#!/usr/bin/env node
/**
 * Forge-Master Studio — MCP Server (Phase-29, Slice 4).
 *
 * Exposes the Forge-Master reasoning loop as a single MCP tool
 * (`forge_master_ask`) over a stdio transport. This is the "second
 * MCP server" that IDE agents can call directly and that
 * `pforge-mcp/server.mjs` proxies to.
 *
 * Usage:
 *   node pforge-master/server.mjs                 # stdio MCP (default)
 *   node pforge-master/server.mjs --mcp-stdio     # explicit stdio flag
 *   node pforge-master/server.mjs --self-test     # run startup self-test and exit 0
 *
 * On startup:
 *   1. Optionally creates the downstream MCP client (pforge-mcp/server.mjs).
 *   2. Registers the forge_master_ask tool.
 *   3. Connects stdio transport and begins serving.
 *
 * The server logs to stderr so stdout is reserved for MCP protocol.
 */

import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
} from "@modelcontextprotocol/sdk/types.js";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";
import { existsSync } from "node:fs";

import { runTurn } from "./src/reasoning.mjs";
import { getForgeMasterConfig } from "./src/config.mjs";
import { resolveAllowlist } from "./src/allowlist.mjs";
import { createMcpClient } from "./src/mcp-client.mjs";
import { startObserver } from "./src/observer-loop.mjs";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const SELF_TEST = process.argv.includes("--self-test");
const MCP_STDIO = process.argv.includes("--mcp-stdio") || !SELF_TEST;

// ─── Tool definition ──────────────────────────────────────────────────

const FORGE_MASTER_ASK_TOOL = {
  name: "forge_master_ask",
  description:
    "Ask Forge-Master a question about your Plan Forge project. " +
    "Forge-Master classifies the intent, retrieves relevant context from memory tiers, " +
    "and calls read-only Plan Forge tools to ground its answer. " +
    "Write tools require an approval card before execution.",
  inputSchema: {
    type: "object",
    properties: {
      message: {
        type: "string",
        description: "Your question or task for Forge-Master.",
      },
      sessionId: {
        type: "string",
        description: "Continue an existing session (optional). Omit to start a new session.",
      },
      maxToolCalls: {
        type: "number",
        description: "Maximum number of tool calls per turn (default: from config, hard ceiling: 10).",
      },
      path: {
        type: "string",
        description: "Project root path override (optional).",
      },
    },
    required: ["message"],
  },
};

const FORGE_MASTER_OBSERVE_TOOL = {
  name: "forge_master_observe",
  description:
    "Control the Forge-Master observer — a background hub subscriber that batches " +
    "live Plan Forge events and (in later slices) narrates notable patterns. " +
    "Observer is mute-by-default; LLM narration is wired in Slice 7. " +
    "Read-only: cannot invoke write tools or modify project files.",
  inputSchema: {
    type: "object",
    properties: {
      action: {
        type: "string",
        enum: ["start", "stop", "status"],
        description: "start — begin observing hub events; stop — halt the observer; status — return current state.",
      },
      sessionId: {
        type: "string",
        description: "Optional session ID for tracing.",
      },
      detach: {
        type: "boolean",
        description: "If true, observer runs as a detached background process (not yet implemented — reserved for Slice 8).",
      },
    },
    required: ["action"],
  },
};

// ─── Active observer (singleton) ─────────────────────────────────────

let _activeObserver = null;
/** Echoed batches (ring-buffer of last 20 batches — for status echo before Slice 7 LLM). */
const _observedBatches = [];
const MAX_OBSERVED_BATCHES = 20;

// ─── Downstream MCP client ────────────────────────────────────────────

let _downstreamClient = null;
const DOWNSTREAM_PATH = resolve(__dirname, "../pforge-mcp/server.mjs");

async function getDownstreamClient() {
  if (_downstreamClient?.ready) return _downstreamClient;
  if (!existsSync(DOWNSTREAM_PATH)) return null;
  try {
    _downstreamClient = await createMcpClient(
      {
        serverPath: DOWNSTREAM_PATH,
        env: { PFORGE_CHILD_MODE: "1", ...process.env },
      },
      { logger: console },
    );
    return _downstreamClient;
  } catch (err) {
    console.error(`forge-master-server: downstream MCP unavailable: ${err.message}`);
    return null;
  }
}

// ─── MCP Server ───────────────────────────────────────────────────────

const server = new Server(
  { name: "forge-master-studio", version: "1.0.0" },
  { capabilities: { tools: {} } },
);

server.setRequestHandler(ListToolsRequestSchema, async () => {
  return { tools: [FORGE_MASTER_ASK_TOOL, FORGE_MASTER_OBSERVE_TOOL] };
});

function _textResult(obj, isError = false) {
  const text = typeof obj === "string" ? obj : JSON.stringify(obj, null, 2);
  return isError ? { content: [{ type: "text", text }], isError: true } : { content: [{ type: "text", text }] };
}

function _handleObserveStart(cwd) {
  const fmConfig = getForgeMasterConfig({ cwd });
  if (!fmConfig.observer.enabled) {
    return { response: _textResult({
      ok: false,
      error: "observer-disabled",
      message: "Observer is disabled. Set forgeMaster.observer.enabled: true in .forge.json to enable.",
    }, true) };
  }

  if (_activeObserver && !_activeObserver.getStatus().stopped) {
    return { response: _textResult({
      ok: true,
      message: "Observer already running.",
      status: _activeObserver.getStatus(),
    }) };
  }
  _observedBatches.length = 0;
  const observer = startObserver({
    cwd,
    onBatch: (batch) => {
      _observedBatches.push({ receivedAt: new Date().toISOString(), events: batch });
      if (_observedBatches.length > MAX_OBSERVED_BATCHES) _observedBatches.shift();
      console.error(`[forge_master_observe] batch: ${batch.length} event(s)`);
      // Slice 7 will call runObserverTurn here
    },
  });
  console.error(`forge-master-server: observer started`);
  return {
    observer,
    response: _textResult({
      ok: true,
      message: "Observer started. Subscribing to hub events.",
      status: observer.getStatus(),
    }),
  };
}

function _handleObserveStop() {
  if (!_activeObserver || _activeObserver.getStatus().stopped) {
    return _textResult({ ok: true, message: "Observer is not running." });
  }
  _activeObserver.stop();
  const finalStatus = _activeObserver.getStatus();
  console.error(`forge-master-server: observer stopped`);
  return _textResult({ ok: true, message: "Observer stopped.", status: finalStatus });
}

function _handleObserveStatus() {
  const status = _activeObserver
    ? _activeObserver.getStatus()
    : { connected: false, stopped: true, message: "Observer has not been started." };
  return _textResult({
    ok: true,
    status,
    recentBatches: _observedBatches.slice(-5),
  });
}

function _handleObserve(args) {
  const { action } = args;
  const cwd = args.path || process.cwd();

  if (!action || !["start", "stop", "status"].includes(action)) {
    return _textResult("forge_master_observe: action must be 'start', 'stop', or 'status'", true);
  }

  if (action === "start") {
    const { observer, response } = _handleObserveStart(cwd);
    if (observer) _activeObserver = observer;
    return response;
  }

  if (action === "stop") {
    return _handleObserveStop();
  }

  return _handleObserveStatus();
}

async function _handleAsk(args) {
  if (!args.message || typeof args.message !== "string") {
    return _textResult("forge_master_ask: message (string) is required", true);
  }

  const t0 = Date.now();
  const cwd = args.path || process.cwd();
  const config = getForgeMasterConfig({ cwd });

  try {
    const downstreamClient = await getDownstreamClient();
    const allowlist = resolveAllowlist({ toolMetadata: {}, discoverExtensionTools: config.discoverExtensionTools });

    const result = await runTurn(
      {
        message: args.message,
        sessionId: args.sessionId || undefined,
        maxToolCalls: args.maxToolCalls || undefined,
        cwd,
      },
      {
        mcpClient: downstreamClient,
        dispatcher: async (toolName, toolArgs, toolCwd) => {
          if (downstreamClient?.ready) {
            return downstreamClient.invoke(toolName, { ...toolArgs, path: toolCwd || cwd });
          }
          return { output: `(tool ${toolName} unavailable — downstream MCP not connected)` };
        },
        hub: null,
        toolMetadata: Object.fromEntries(allowlist.map((n) => [n, { name: n }])),
      },
    );

    const durationMs = Date.now() - t0;
    console.error(`forge-master-server: turn complete in ${durationMs}ms, ${result.toolCalls?.length ?? 0} tool calls`);

    return _textResult(result);
  } catch (err) {
    console.error(`forge-master-server: error: ${err.message}`);
    return _textResult(`Forge-Master error: ${err.message}`, true);
  }
}

server.setRequestHandler(CallToolRequestSchema, async (request) => {
  const { name, arguments: args = {} } = request.params;

  if (name === "forge_master_observe") {
    return _handleObserve(args);
  }

  if (name === "forge_master_ask") {
    return _handleAsk(args);
  }

  return _textResult(`Unknown tool: ${name}`, true);
});

// ─── Self-test ────────────────────────────────────────────────────────

async function runSelfTest() {
  console.error("forge-master-server: --self-test starting");

  // Verify imports resolve
  const { runTurn: _rt } = await import("./src/reasoning.mjs");
  const { BASE_ALLOWLIST } = await import("./src/allowlist.mjs");
  const { startObserver: _so } = await import("./src/observer-loop.mjs");
  if (!_rt || !BASE_ALLOWLIST?.length) throw new Error("core module imports failed");
  if (typeof _so !== "function") throw new Error("observer-loop import failed");

  // Verify tool list (exactly 2 tools)
  const tools = [FORGE_MASTER_ASK_TOOL, FORGE_MASTER_OBSERVE_TOOL];
  if (!tools.find((t) => t.name === "forge_master_ask")) throw new Error("forge_master_ask not registered");
  if (!tools.find((t) => t.name === "forge_master_observe")) throw new Error("forge_master_observe not registered");
  if (tools.length !== 2) throw new Error(`expected 2 tools, got ${tools.length}`);

  console.error(`forge-master-server: --self-test PASS (2 tools: forge_master_ask, forge_master_observe; allowlist size ${BASE_ALLOWLIST.length})`);
  process.exit(0);
}

// ─── Boot ─────────────────────────────────────────────────────────────

async function main() {
  if (SELF_TEST) {
    await runSelfTest();
    return;
  }

  const transport = new StdioServerTransport();
  await server.connect(transport);
  console.error("forge-master-server: stdio MCP ready (1 tool: forge_master_ask)");

  // Graceful shutdown
  process.on("SIGTERM", async () => {
    if (_downstreamClient) await _downstreamClient.close().catch(() => {});
    process.exit(0);
  });
  process.on("SIGINT", async () => {
    if (_downstreamClient) await _downstreamClient.close().catch(() => {});
    process.exit(0);
  });
}

main().catch((err) => {
  console.error(`forge-master-server: fatal: ${err.message}`);
  process.exit(1);
});

/**
 * Plan Forge — MockReasoningClient (Phase-28, Slice 5).
 *
 * Scripted response fixture for testing the reasoning loop without
 * making real API calls. Each call to `sendTurn()` returns the next
 * response from the script; when the script is exhausted, returns a
 * default final reply.
 *
 * Usage:
 *   const client = new MockReasoningClient([
 *     { type: "tool_calls", toolCalls: [{ id: "1", name: "forge_status", args: {} }] },
 *     { type: "reply", content: "Here is your status." },
 *   ]);
 *   const r1 = await client.sendTurn({ messages, tools, model, apiKey });
 *   // r1 → tool_calls
 *   const r2 = await client.sendTurn({ messages, tools, model, apiKey });
 *   // r2 → reply
 *
 * @module forge-master/__fixtures__/MockReasoningClient
 */

export class MockReasoningClient {
  /**
   * @param {Array<{
   *   type: "reply"|"tool_calls",
   *   content?: string,
   *   toolCalls?: Array<{id: string, name: string, args?: object}>,
   *   tokensIn?: number,
   *   tokensOut?: number,
   *   error?: Error,
   * }>} script — ordered list of responses
   */
  constructor(script = []) {
    this._script = [...script];
    this._callIndex = 0;
    this.calls = []; // records every sendTurn invocation for assertions
  }

  /**
   * Simulate a provider sendTurn call.
   * Records the invocation and returns the next scripted response.
   */
  async sendTurn(opts) {
    this.calls.push({
      index: this._callIndex,
      messages: opts.messages,
      tools: opts.tools,
      model: opts.model,
    });

    const entry = this._script[this._callIndex];
    this._callIndex++;

    if (!entry) {
      // Script exhausted — return a default final reply
      return {
        type: "reply",
        content: "[MockReasoningClient] Script exhausted — default reply.",
        tokensIn: 10,
        tokensOut: 20,
      };
    }

    // Simulate an error if the entry requests it
    if (entry.error) {
      throw entry.error;
    }

    return {
      type: entry.type || "reply",
      content: entry.content,
      toolCalls: entry.toolCalls,
      tokensIn: entry.tokensIn ?? 100,
      tokensOut: entry.tokensOut ?? 50,
    };
  }

  /** Number of sendTurn calls recorded. */
  get callCount() {
    return this.calls.length;
  }

  /** Reset call history and script index. */
  reset(newScript) {
    this._script = newScript ? [...newScript] : [...this._script];
    this._callIndex = 0;
    this.calls = [];
  }
}

/**
 * Tests for pforge-master/src/cost.mjs (Phase-38.2).
 *
 * Covers:
 *   (1) getPricing — known models, unknown models fallback
 *   (2) computeTurnCost — zero tokens, positive tokens, mixed-model fallback
 *   (3) All TURN_PRICING entries are positive and finite
 */

import { describe, it, expect } from "vitest";
import { TURN_PRICING, getPricing, computeTurnCost } from "../cost.mjs";

// ─── (1) getPricing ────────────────────────────────────────────────────

describe("getPricing", () => {
  it("returns specific pricing for a known model", () => {
    const p = getPricing("gpt-4o-mini");
    expect(p.input).toBe(0.15 / 1_000_000);
    expect(p.output).toBe(0.6 / 1_000_000);
  });

  it("returns specific pricing for claude-opus models", () => {
    const p = getPricing("claude-opus-4.7");
    expect(p.input).toBe(15 / 1_000_000);
    expect(p.output).toBe(75 / 1_000_000);
  });

  it("falls back to default for an unknown model string", () => {
    const def = getPricing("some-future-model-xyz");
    expect(def).toEqual(TURN_PRICING.default);
  });

  it("falls back to default for null", () => {
    expect(getPricing(null)).toEqual(TURN_PRICING.default);
  });

  it("falls back to default for undefined", () => {
    expect(getPricing(undefined)).toEqual(TURN_PRICING.default);
  });

  it("falls back to default for empty string", () => {
    expect(getPricing("")).toEqual(TURN_PRICING.default);
  });
});

// ─── (2) computeTurnCost ──────────────────────────────────────────────

describe("computeTurnCost", () => {
  it("returns 0 for zero tokens", () => {
    expect(computeTurnCost("gpt-4o-mini", 0, 0)).toBe(0);
  });

  it("computes correct cost for known model", () => {
    // gpt-4o-mini: $0.15/M input, $0.60/M output
    const cost = computeTurnCost("gpt-4o-mini", 1000, 200);
    const expected = (1000 * 0.15 / 1_000_000) + (200 * 0.6 / 1_000_000);
    expect(cost).toBeCloseTo(expected, 10);
  });

  it("computes correct cost for claude-opus (expensive model)", () => {
    // claude-opus-4.7: $15/M input, $75/M output
    const cost = computeTurnCost("claude-opus-4.7", 1000, 500);
    const expected = (1000 * 15 / 1_000_000) + (500 * 75 / 1_000_000);
    expect(cost).toBeCloseTo(expected, 10);
  });

  it("falls back to default pricing for unknown model", () => {
    const defPricing = TURN_PRICING.default;
    const cost = computeTurnCost("unknown-model", 500, 100);
    const expected = (500 * defPricing.input) + (100 * defPricing.output);
    expect(cost).toBeCloseTo(expected, 10);
  });

  it("accumulates correctly across two calls (simulating mixed-model turn)", () => {
    // Simulate: first iteration on high-tier, then fallback to low-tier
    const costHigh = computeTurnCost("claude-opus-4.7", 800, 200);
    const costLow = computeTurnCost("gpt-4o-mini", 400, 100);
    const total = costHigh + costLow;
    expect(total).toBeGreaterThan(costHigh);
    expect(total).toBeGreaterThan(costLow);
    // High tier should dominate
    expect(costHigh).toBeGreaterThan(costLow * 10);
  });

  it("Deep tier is substantially more expensive than Fast for same token count", () => {
    const fastCost = computeTurnCost("gpt-4o-mini", 1000, 500);
    const deepCost = computeTurnCost("claude-opus-4.7", 1000, 500);
    expect(deepCost).toBeGreaterThan(fastCost * 10);
  });
});

// ─── (3) Table integrity ──────────────────────────────────────────────

describe("TURN_PRICING table integrity", () => {
  it("all entries have positive finite input and output rates", () => {
    for (const [model, rates] of Object.entries(TURN_PRICING)) {
      expect(rates.input, `${model}.input`).toBeGreaterThan(0);
      expect(rates.output, `${model}.output`).toBeGreaterThan(0);
      expect(Number.isFinite(rates.input), `${model}.input finite`).toBe(true);
      expect(Number.isFinite(rates.output), `${model}.output finite`).toBe(true);
    }
  });

  it("output rates are always >= input rates (typical LLM pricing pattern)", () => {
    for (const [model, rates] of Object.entries(TURN_PRICING)) {
      expect(rates.output, `${model}: output >= input`).toBeGreaterThanOrEqual(rates.input);
    }
  });

  it("includes the key Forge-Master default models", () => {
    expect(TURN_PRICING["gpt-4o-mini"]).toBeDefined();
    expect(TURN_PRICING["gpt-4o"]).toBeDefined();
    expect(TURN_PRICING["claude-sonnet-4.5"]).toBeDefined();
    expect(TURN_PRICING["grok-3-mini"]).toBeDefined();
    expect(TURN_PRICING.default).toBeDefined();
  });
});

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, rmSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import {
  addEntry,
  query,
  evictLRU,
  save,
  load,
  size,
  cosineSimilarity,
  MAX_ENTRIES,
  __resetCacheForTests,
} from '../embedding/cache.mjs';

/** Deterministic fake embedder — maps text to a unit vector at a fixed slot. */
const DIM = 8;
function fakeEmbed(text) {
  const v = new Float32Array(DIM);
  let slot = 0;
  for (let i = 0; i < text.length; i++) slot = (slot + text.charCodeAt(i)) % DIM;
  v[slot] = 1;
  return Promise.resolve(v);
}

/** Embed that returns a known vector directly. */
function vectorEmbed(vec) {
  return () => Promise.resolve(vec);
}

let tmpDir;

beforeEach(() => {
  __resetCacheForTests();
  tmpDir = mkdtempSync(join(tmpdir(), 'ec-test-'));
});

afterEach(() => {
  __resetCacheForTests();
  rmSync(tmpDir, { recursive: true, force: true });
});

// ── Cosine similarity ────────────────────────────────────────────────

describe('cosineSimilarity', () => {
  it('returns 1.0 for identical unit vectors', () => {
    const v = new Float32Array([0, 1, 0, 0]);
    expect(cosineSimilarity(v, v)).toBeCloseTo(1.0, 6);
  });

  it('returns 0 for orthogonal vectors', () => {
    const a = new Float32Array([1, 0, 0, 0]);
    const b = new Float32Array([0, 1, 0, 0]);
    expect(cosineSimilarity(a, b)).toBeCloseTo(0, 6);
  });

  it('returns -1 for opposite vectors', () => {
    const a = new Float32Array([1, 0]);
    const b = new Float32Array([-1, 0]);
    expect(cosineSimilarity(a, b)).toBeCloseTo(-1.0, 6);
  });

  it('returns 0 for zero-magnitude vector (no NaN)', () => {
    const zero = new Float32Array(4);
    const v = new Float32Array([1, 0, 0, 0]);
    expect(cosineSimilarity(zero, v)).toBe(0);
    expect(Number.isNaN(cosineSimilarity(zero, v))).toBe(false);
  });
});

// ── Threshold filtering ──────────────────────────────────────────────

describe('query — threshold filtering', () => {
  it('returns matches above threshold', async () => {
    // Add entry with a known vector, then query with the same text
    await addEntry({
      text: 'show build status',
      classification: { lane: 'operational' },
      confidence: 0.9,
      _embed: fakeEmbed,
    });

    const results = await query('show build status', {
      threshold: 0.85,
      topK: 5,
      _embed: fakeEmbed,
    });
    expect(results).toHaveLength(1);
    expect(results[0].score).toBeGreaterThanOrEqual(0.85);
    expect(results[0].classification.lane).toBe('operational');
  });

  it('filters out matches below threshold', async () => {
    // a and b produce orthogonal vectors
    const embedA = vectorEmbed(new Float32Array([1, 0, 0, 0]));
    const embedB = vectorEmbed(new Float32Array([0, 1, 0, 0]));

    await addEntry({
      text: 'alpha',
      classification: { lane: 'build' },
      confidence: 0.8,
      _embed: embedA,
    });

    const results = await query('beta', {
      threshold: 0.85,
      topK: 5,
      _embed: embedB,
    });
    expect(results).toHaveLength(0);
  });

  it('sorts results by score descending and respects topK', async () => {
    // Three entries at different similarity levels
    const base = new Float32Array([1, 0, 0, 0]);
    const high = new Float32Array([0.95, 0.31, 0, 0]); // cos ≈ 0.95
    const mid = new Float32Array([0.87, 0.49, 0, 0]);  // cos ≈ 0.87
    const low = new Float32Array([0.5, 0.87, 0, 0]);   // cos ≈ 0.50

    await addEntry({ text: 'mid', classification: { lane: 'b' }, confidence: 0.7, _embed: vectorEmbed(mid) });
    await addEntry({ text: 'high', classification: { lane: 'a' }, confidence: 0.9, _embed: vectorEmbed(high) });
    await addEntry({ text: 'low', classification: { lane: 'c' }, confidence: 0.5, _embed: vectorEmbed(low) });

    const results = await query('q', {
      threshold: 0.80,
      topK: 2,
      _embed: vectorEmbed(base),
    });

    expect(results).toHaveLength(2);
    expect(results[0].score).toBeGreaterThan(results[1].score);
    expect(results[0].classification.lane).toBe('a'); // high
    expect(results[1].classification.lane).toBe('b'); // mid
  });

  it('returns empty array when cache is empty', async () => {
    const results = await query('anything', { _embed: fakeEmbed });
    expect(results).toHaveLength(0);
  });
});

// ── LRU eviction ─────────────────────────────────────────────────────

describe('LRU eviction', () => {
  it('evicts oldest entry when cache reaches MAX_ENTRIES', async () => {
    // Fill cache to MAX_ENTRIES
    for (let i = 0; i < MAX_ENTRIES; i++) {
      await addEntry({
        text: `entry-${i}`,
        classification: { lane: 'test' },
        confidence: 0.9,
        _embed: fakeEmbed,
      });
    }
    expect(size()).toBe(MAX_ENTRIES);

    // Adding one more should evict the oldest
    await addEntry({
      text: 'entry-overflow',
      classification: { lane: 'overflow' },
      confidence: 0.95,
      _embed: fakeEmbed,
    });
    expect(size()).toBe(MAX_ENTRIES);
  });

  it('evicts entry 501 correctly — oldest entry removed', async () => {
    // Add 500 entries; entry-0 is the first (oldest lastUsed)
    for (let i = 0; i < MAX_ENTRIES; i++) {
      await addEntry({
        text: `e-${i}`,
        classification: { lane: 'x', index: i },
        confidence: 0.5,
        _embed: fakeEmbed,
      });
    }

    // The very first entry should be evictable
    const evictedId = evictLRU();
    expect(evictedId).toBe(1); // first entry added
    expect(size()).toBe(MAX_ENTRIES - 1);
  });

  it('evictLRU returns null on empty cache', () => {
    expect(evictLRU()).toBeNull();
  });
});

