/**
 * Plan Forge — Forge-Master Config (Phase-28, Slice 1; Phase-33, Slice 2).
 *
 * Loads the `forgeMaster` block from `.forge.json` and applies the
 * documented fallback chain for reasoningModel / routerModel so callers
 * always receive a fully-resolved config without having to handle missing
 * keys themselves.
 *
 * Fallback chain for reasoningModel:
 *   1. forgeMaster.reasoningModel  (explicit override)
 *   2. model.default               (shared project default)
 *   3. env-detected provider default:
 *        GITHUB_TOKEN      -> "gpt-4o-mini"     (GitHub Models — zero-key default)
 *        ANTHROPIC_API_KEY -> "claude-sonnet-4.5"
 *        OPENAI_API_KEY    -> "gpt-5.3-codex"
 *        XAI_API_KEY       -> "grok-4-fast"
 *        (no key)          -> "gpt-4o-mini"      (caller must handle missing key)
 */

import { existsSync, readFileSync } from "node:fs";
import { resolve } from "node:path";
import { FORGE_MASTER_MODES, MODEL_TIERS } from "../../pforge-mcp/enums.mjs";

export const FORGE_MASTER_DEFAULTS = Object.freeze({
  reasoningModel: null,
  reasoningProvider: null,
  defaultProvider: "githubCopilot",
  providers: Object.freeze({
    githubCopilot: Object.freeze({ model: "gpt-4o-mini" }),
  }),
  routerModel: "grok-3-mini",
  maxToolCalls: 5,
  ceilingToolCalls: 10,
  sessionRetentionDays: 14,
  l3Enabled: false,
  discoverExtensionTools: true,
  reasoningTiers: Object.freeze({ low: null, medium: null, high: null }),
  defaultTier: null,
  autoEscalate: true,
  observer: Object.freeze({
    enabled: false,
    maxUsdPerDay: 1.0,
    maxNarrationsPerHour: 6,
    modelTier: null,
  }),
  auditor: Object.freeze({
    modelTier: null,
  }),
});

const VALID_PROVIDERS = new Set(["githubCopilot", "anthropic", "openai", "xai"]);
const VALID_MODEL_TIERS = new Set(MODEL_TIERS);
const VALID_FORGE_MASTER_MODES = new Set(FORGE_MASTER_MODES);

function formatValidValues(values) {
  return [...values].join(", ");
}

function validateOptionalModelTier(kind, value) {
  if (value == null) return null;
  if (!VALID_MODEL_TIERS.has(value)) {
    throw new RangeError(`Invalid ${kind} '${value}'. Valid: ${formatValidValues(MODEL_TIERS)} or null`);
  }
  return value;
}

function validateOptionalForgeMasterMode(value) {
  if (typeof value !== "string" || value.length === 0) return;
  if (!VALID_FORGE_MASTER_MODES.has(value)) {
    throw new RangeError(`Invalid forgeMaster.mode '${value}'. Valid: ${formatValidValues(FORGE_MASTER_MODES)}`);
  }
}

function resolveReasoningModel(forgeMasterBlock, forgeJson) {
  if (forgeMasterBlock?.reasoningModel && typeof forgeMasterBlock.reasoningModel === "string") {
    return forgeMasterBlock.reasoningModel;
  }
  if (forgeJson?.model?.default && typeof forgeJson.model.default === "string") {
    return forgeJson.model.default;
  }
  if (process.env.GITHUB_TOKEN) return "gpt-4o-mini";
  if (process.env.ANTHROPIC_API_KEY) return "claude-sonnet-4.5";
  if (process.env.OPENAI_API_KEY) return "gpt-5.3-codex";
  if (process.env.XAI_API_KEY) return "grok-4-fast";
  return null; // no key detected — auto-select will handle fallback
}

function resolveReasoningProvider(forgeMasterBlock, resolvedModel) {
  const explicit = forgeMasterBlock?.reasoningProvider;
  // Always pass through the explicit value — selectProvider handles unknown names by returning null.
  if (explicit) return explicit;
  if (!resolvedModel) return null; // no model → auto-select decides
  if (/^claude/i.test(resolvedModel)) return "anthropic";
  if (/^grok/i.test(resolvedModel)) return "xai";
  if (/^gpt-4o/i.test(resolvedModel)) return "githubCopilot";
  if (/^gpt/i.test(resolvedModel)) return "openai";
  return null;
}

const VALID_DEFAULT_TIERS = ["low", "medium", "high"];

function loadForgeMasterBlock(configPath) {
  let forgeJson = null;
  let block = null;

  try {
    if (existsSync(configPath)) {
      forgeJson = JSON.parse(readFileSync(configPath, "utf-8"));
      block = forgeJson?.forgeMaster ?? null;
    }
  } catch { /* fall through to defaults */ }

  return { forgeJson, block };
}

function clampIntegerOption(value, fallback, min, max) {
  if (!Number.isFinite(value)) return fallback;
  return Math.max(min, Math.min(max, Math.trunc(value)));
}

function resolveCeilingToolCalls(value, maxToolCalls) {
  if (!Number.isFinite(value)) return FORGE_MASTER_DEFAULTS.ceilingToolCalls;
  return Math.max(maxToolCalls, Math.min(20, Math.trunc(value)));
}

function resolveBooleanOption(value, fallback) {
  return typeof value === "boolean" ? value : fallback;
}

function resolveDefaultProvider(block) {
  return (typeof block?.defaultProvider === "string" && VALID_PROVIDERS.has(block.defaultProvider))
    ? block.defaultProvider
    : FORGE_MASTER_DEFAULTS.defaultProvider;
}

function resolveReasoningTiers(block) {
  return {
    low: typeof block?.reasoningTiers?.low === "string" ? block.reasoningTiers.low : null,
    medium: typeof block?.reasoningTiers?.medium === "string" ? block.reasoningTiers.medium : null,
    high: typeof block?.reasoningTiers?.high === "string" ? block.reasoningTiers.high : null,
  };
}

function resolveDefaultTier(block) {
  return (typeof block?.defaultTier === "string" && VALID_DEFAULT_TIERS.includes(block.defaultTier))
    ? block.defaultTier
    : FORGE_MASTER_DEFAULTS.defaultTier;
}

function resolveObserverNumber(value, fallback) {
  return (typeof value === "number" && Number.isFinite(value) && value >= 0)
    ? value
    : fallback;
}

function resolveObserverNarrationLimit(value, fallback) {
  return (typeof value === "number" && Number.isFinite(value) && value >= 0)
    ? Math.trunc(value)
    : fallback;
}

function resolveOptionalModelTierValue(kind, value, fallback) {
  return typeof value === "string"
    ? validateOptionalModelTier(kind, value)
    : fallback;
}

function resolveObserverConfig(block) {
  const observerBlock = block?.observer ?? {};
  return {
    enabled: resolveBooleanOption(observerBlock.enabled, FORGE_MASTER_DEFAULTS.observer.enabled),
    maxUsdPerDay: resolveObserverNumber(observerBlock.maxUsdPerDay, FORGE_MASTER_DEFAULTS.observer.maxUsdPerDay),
    maxNarrationsPerHour: resolveObserverNarrationLimit(
      observerBlock.maxNarrationsPerHour,
      FORGE_MASTER_DEFAULTS.observer.maxNarrationsPerHour,
    ),
    modelTier: resolveOptionalModelTierValue(
      "forgeMaster.observer.modelTier",
      observerBlock.modelTier,
      FORGE_MASTER_DEFAULTS.observer.modelTier,
    ),
  };
}

function resolveAuditorConfig(block) {
  const auditorBlock = block?.auditor ?? {};
  return {
    modelTier: resolveOptionalModelTierValue(
      "forgeMaster.auditor.modelTier",
      auditorBlock.modelTier,
      FORGE_MASTER_DEFAULTS.auditor.modelTier,
    ),
  };
}

/**
 * Load and return a fully-resolved Forge-Master config.
 *
 * @param {{ cwd?: string }} [opts]
 * @returns {{
 *   reasoningModel: string,
 *   reasoningProvider: "githubCopilot"|"anthropic"|"openai"|"xai"|null,
 *   defaultProvider: "githubCopilot"|"anthropic"|"openai"|"xai",
 *   routerModel: string,
 *   maxToolCalls: number,
 *   ceilingToolCalls: number,
 *   sessionRetentionDays: number,
 *   l3Enabled: boolean,
 *   discoverExtensionTools: boolean,
 *   reasoningTiers: { low: string|null, medium: string|null, high: string|null },
 *   defaultTier: "low"|"medium"|"high"|null,
 *   autoEscalate: boolean,
 *   observer: { enabled: boolean, maxUsdPerDay: number, maxNarrationsPerHour: number, modelTier: string|null },
 *   auditor: { modelTier: string|null },
 * }}
 */
export function getForgeMasterConfig({ cwd = process.cwd() } = {}) {
  const configPath = resolve(cwd, ".forge.json");
  const { forgeJson, block } = loadForgeMasterBlock(configPath);
  const reasoningModel = resolveReasoningModel(block, forgeJson);
  const reasoningProvider = resolveReasoningProvider(block, reasoningModel);
  const observer = resolveObserverConfig(block);
  const auditor = resolveAuditorConfig(block);

  validateOptionalForgeMasterMode(block?.mode);

  return {
    reasoningModel,
    reasoningProvider,
    defaultProvider: resolveDefaultProvider(block),
    routerModel: (typeof block?.routerModel === "string" && block.routerModel)
      ? block.routerModel
      : FORGE_MASTER_DEFAULTS.routerModel,
    maxToolCalls: clampIntegerOption(block?.maxToolCalls, FORGE_MASTER_DEFAULTS.maxToolCalls, 1, 10),
    ceilingToolCalls: resolveCeilingToolCalls(
      block?.ceilingToolCalls,
      clampIntegerOption(block?.maxToolCalls, FORGE_MASTER_DEFAULTS.maxToolCalls, 1, 10),
    ),
    sessionRetentionDays: clampIntegerOption(
      block?.sessionRetentionDays,
      FORGE_MASTER_DEFAULTS.sessionRetentionDays,
      1,
      365,
    ),
    l3Enabled: resolveBooleanOption(block?.l3Enabled, FORGE_MASTER_DEFAULTS.l3Enabled),
    discoverExtensionTools: resolveBooleanOption(
      block?.discoverExtensionTools,
      FORGE_MASTER_DEFAULTS.discoverExtensionTools,
    ),
    reasoningTiers: resolveReasoningTiers(block),
    defaultTier: resolveDefaultTier(block),
    autoEscalate: resolveBooleanOption(block?.autoEscalate, FORGE_MASTER_DEFAULTS.autoEscalate),
    observer,
    auditor,
  };
}

/**
 * Embedding cache — cosine-similarity query over previously-classified prompts.
 *
 * Entries are keyed by a monotonic counter. The cache enforces a hard cap
 * (MAX_ENTRIES = 500) via LRU eviction. Persistence uses a binary format
 * for vectors (header + packed Float32) plus a JSON metadata sidecar.
 *
 * Binary format (.bin):
 *   [4 bytes: uint32 entry count]
 *   [4 bytes: uint32 vector dimension]
 *   [count × dim × 4 bytes: packed Float32 vectors, row-major]
 *
 * Sidecar (.bin.meta.json):
 *   Array of { id, text, classification, confidence, lastUsed }
 *   Order matches the vector rows in the binary file.
 *
 * @module embedding/cache
 */

import { readFile, writeFile, mkdir } from 'node:fs/promises';
import { dirname } from 'node:path';
import { embed } from './provider.mjs';

export const MAX_ENTRIES = 500;

/** @type {Map<number, CacheEntry>} */
let _entries = new Map();
let _nextId = 1;

/**
 * @typedef {object} CacheEntry
 * @property {number}       id
 * @property {string}       text
 * @property {Float32Array} vector
 * @property {object}       classification - { lane, via, ... }
 * @property {number}       confidence
 * @property {number}       lastUsed - Date.now() timestamp
 */

// ── Cosine similarity ────────────────────────────────────────────────

/**
 * Cosine similarity: dot(a,b) / (|a| × |b|).
 * Returns 0 for zero-magnitude vectors (no NaN).
 *
 * @param {Float32Array} a
 * @param {Float32Array} b
 * @returns {number} Similarity in [-1, 1].
 */
export function cosineSimilarity(a, b) {
  let dot = 0;
  let magA = 0;
  let magB = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    magA += a[i] * a[i];
    magB += b[i] * b[i];
  }
  const denom = Math.sqrt(magA) * Math.sqrt(magB);
  return denom === 0 ? 0 : dot / denom;
}

// ── Public API ───────────────────────────────────────────────────────

/**
 * Add an entry to the cache. If the cache is at capacity, evicts the
 * least-recently-used entry first.
 *
 * @param {object} params
 * @param {string} params.text
 * @param {object} params.classification
 * @param {number} params.confidence
 * @param {((text: string) => Promise<Float32Array>)|undefined} [params._embed]
 *   DI seam for tests.
 * @returns {Promise<number>} The id of the new entry.
 */
export async function addEntry({ text, classification, confidence, _embed }) {
  const embedFn = _embed ?? embed;
  const vector = await embedFn(text);
  if (_entries.size >= MAX_ENTRIES) evictLRU();

  const id = _nextId++;
  _entries.set(id, {
    id,
    text,
    vector,
    classification,
    confidence,
    lastUsed: Date.now(),
  });
  return id;
}

/**
 * @typedef {object} QueryResult
 * @property {number} id
 * @property {string} text
 * @property {object} classification
 * @property {number} confidence
 * @property {number} score - cosine similarity
 */

/**
 * Query the cache: embed `text`, compute cosine against every entry,
 * filter by threshold, sort descending, return top-K.
 *
 * @param {string} text
 * @param {object} [opts]
 * @param {number} [opts.threshold=0.85]
 * @param {number} [opts.topK=1]
 * @param {((text: string) => Promise<Float32Array>)|undefined} [opts._embed]
 * @returns {Promise<QueryResult[]>}
 */
export async function query(text, { threshold = 0.85, topK = 1, _embed } = {}) {
  if (_entries.size === 0) return [];

  const embedFn = _embed ?? embed;
  const qVec = await embedFn(text);

  const hits = [];
  for (const entry of _entries.values()) {
    const score = cosineSimilarity(qVec, entry.vector);
    if (score >= threshold) {
      entry.lastUsed = Date.now();
      hits.push({
        id: entry.id,
        text: entry.text,
        classification: entry.classification,
        confidence: entry.confidence,
        score,
      });
    }
  }

  hits.sort((a, b) => b.score - a.score);
  return hits.slice(0, topK);
}

/**
 * Evict the least-recently-used entry.
 * @returns {number|null} Id of the evicted entry, or null if cache empty.
 */
export function evictLRU() {
  let oldest = null;
  let oldestTime = Infinity;
  for (const entry of _entries.values()) {
    if (entry.lastUsed < oldestTime) {
      oldestTime = entry.lastUsed;
      oldest = entry;
    }
  }
  if (oldest) {
    _entries.delete(oldest.id);
    return oldest.id;
  }
  return null;
}

/**
 * Return current cache size.
 * @returns {number}
 */
export function size() {
  return _entries.size;
}

// ── Persistence ──────────────────────────────────────────────────────

/**
 * Save cache to binary file + JSON sidecar.
 *
 * @param {string} filePath - Path for the .bin file. Sidecar is `${filePath}.meta.json`.
 * @returns {Promise<void>}
 */
export async function save(filePath) {
  const entries = [..._entries.values()];
  const count = entries.length;
  const dim = count > 0 ? entries[0].vector.length : 0;

  // Binary: [uint32 count][uint32 dim][count × dim Float32]
  const headerBytes = 8;
  const vectorBytes = count * dim * 4;
  const buf = Buffer.alloc(headerBytes + vectorBytes);
  const view = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
  view.setUint32(0, count, true);
  view.setUint32(4, dim, true);

  for (let r = 0; r < count; r++) {
    const vec = entries[r].vector;
    const rowOffset = headerBytes + r * dim * 4;
    for (let c = 0; c < dim; c++) {
      view.setFloat32(rowOffset + c * 4, vec[c], true);
    }
  }

  // Metadata sidecar (parallel array, same order)
  const meta = entries.map((e) => ({
    id: e.id,
    text: e.text,
    classification: e.classification,
    confidence: e.confidence,
    lastUsed: e.lastUsed,
  }));

  await mkdir(dirname(filePath), { recursive: true });
  await writeFile(filePath, buf);
  await writeFile(`${filePath}.meta.json`, JSON.stringify(meta));
}

/**
 * Load cache from binary file + JSON sidecar. Replaces current cache
 * contents entirely.
 *
 * @param {string} filePath
 * @returns {Promise<void>}
 */
export async function load(filePath) {
  const [binBuf, metaRaw] = await Promise.all([
    readFile(filePath),
    readFile(`${filePath}.meta.json`, 'utf8'),
  ]);

  const view = new DataView(binBuf.buffer, binBuf.byteOffset, binBuf.byteLength);
  const count = view.getUint32(0, true);
  const dim = view.getUint32(4, true);
  const meta = JSON.parse(metaRaw);

  if (meta.length !== count) {
    throw new Error(
      `Embedding cache corrupt: binary has ${count} entries but sidecar has ${meta.length}`,
    );
  }

  _entries = new Map();
  _nextId = 1;

  for (let r = 0; r < count; r++) {
    const vec = new Float32Array(dim);
    const rowOffset = 8 + r * dim * 4;
    for (let c = 0; c < dim; c++) {
      vec[c] = view.getFloat32(rowOffset + c * 4, true);
    }
    const m = meta[r];
    const id = m.id;
    _entries.set(id, {
      id,
      text: m.text,
      vector: vec,
      classification: m.classification,
      confidence: m.confidence,
      lastUsed: m.lastUsed,
    });
    if (id >= _nextId) _nextId = id + 1;
  }
}

// ── Test helpers ─────────────────────────────────────────────────────

/** @internal Reset cache for test isolation. */
export function __resetCacheForTests() {
  _entries = new Map();
  _nextId = 1;
}

/**
 * Hash-bag embedding provider — deterministic, zero-dependency fallback.
 *
 * Produces a bag-of-words vector using FNV-1a hashing into a fixed-dimension
 * Float32Array, then L2-normalizes. Order-independent (bag semantics).
 *
 * Unicode / non-ASCII characters are stripped by the tokenizer regex.
 * This is acceptable for a lightweight fallback; the transformers provider
 * handles richer text.
 *
 * @module embedding/hash-bag
 */

export const DIM = 512;

/**
 * Tokenize text into lowercase alphanumeric tokens.
 * @param {string} text
 * @returns {string[]}
 */
export function tokenize(text) {
  if (typeof text !== 'string' || text.length === 0) return [];
  return text.toLowerCase().match(/[a-z0-9]+/g) ?? [];
}

/**
 * FNV-1a 32-bit hash.
 * @param {string} str
 * @returns {number} Unsigned 32-bit integer.
 */
export function hash32(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  return h >>> 0;
}

/**
 * Embed text into a Float32Array of length {@link DIM}.
 * Always async for interface uniformity with other providers.
 * @param {string} text
 * @returns {Promise<Float32Array>}
 */
export async function embed(text) {
  const v = new Float32Array(DIM);
  const tokens = tokenize(text);
  for (const tok of tokens) v[hash32(tok) % DIM] += 1;
  let sumSq = 0;
  for (let i = 0; i < DIM; i++) sumSq += v[i] * v[i];
  if (sumSq > 0) {
    const inv = 1 / Math.sqrt(sumSq);
    for (let i = 0; i < DIM; i++) v[i] *= inv;
  }
  return v;
}

/**
 * Create a provider object conforming to the embedding provider interface.
 * @returns {{ name: string, dim: number, embed: (text: string) => Promise<Float32Array> }}
 */
export function createHashBagProvider() {
  return { name: 'hash-bag', dim: DIM, embed };
}

/**
 * Forge-Master HTTP Dispatcher (Phase-37.1, Slice 2; hardened Slice 4).
 *
 * Provides a factory for the allowlist-gated, in-process tool dispatcher
 * used by the `/stream` SSE handler. Separates allowlist enforcement from
 * the HTTP routing layer so both can be tested in isolation.
 *
 * Exports:
 *   - createHttpDispatcher({ allowlist?, mcpCall?, streamEventCap?, streamTimeout? }) → dispatcher fn
 *   - invokeForgeTool(toolName, args) → default no-op (standalone fallback)
 *
 * Design notes:
 *   - The dispatcher awaits the terminal result of every tool call (terminal-await).
 *     When mcpCall returns an async iterable (streaming tool), the dispatcher
 *     collects all non-terminal events into { events: [...], terminal } up to
 *     streamEventCap (default 20) and returns that aggregate.
 *   - Destructive tools (in WRITE_ALLOWLIST) are rejected over HTTP in this
 *     phase; approval is an in-IDE concern only (see Scope Contract, Phase-36).
 *   - mcpCall is injected at creation time so the dispatcher can be unit-tested
 *     without a live MCP server.
 *
 * Failure handling (Phase-37.1 Slice 4):
 *   - mcpCall rejection → returns { error: <message> }
 *   - Stream throw mid-iteration → returns { error: <message> }
 *   - Stream timeout (no terminal within streamTimeout ms) → { error: "stream-timeout" }
 *   - null item yielded from stream → treated as terminal sentinel; terminal = null
 *   - Non-object, non-null primitive yielded → silently skipped (not counted toward cap)
 *
 * @module forge-master/http-dispatcher
 */

import { BASE_ALLOWLIST, WRITE_ALLOWLIST } from "./allowlist.mjs";

// ─── Default fallback ─────────────────────────────────────────────────

/**
 * Default no-op invokeForgeTool — returns an empty object.
 *
 * Used when pforge-master runs standalone (without a live pforge-mcp
 * server available). forge-master-routes.mjs replaces this with the
 * real in-process dispatcher from server.mjs at registration time.
 *
 * @param {string} _toolName
 * @param {object} _args
 * @returns {Promise<{}>}
 */
export async function invokeForgeTool(_toolName, _args) {
  return {};
}

// ─── Dispatcher factory ───────────────────────────────────────────────

/**
 * Create an HTTP dispatcher that enforces the allowlist and rejects
 * destructive (write) tools before forwarding to mcpCall.
 *
 * When mcpCall returns an async iterable, the dispatcher collects
 * non-terminal events into { events: [...], terminal } up to streamEventCap,
 * consuming the remainder of the stream to reach the terminal item.
 *
 * Failure semantics (Phase-37.1 Slice 4):
 *   - mcpCall rejection → { error: <message> }
 *   - Stream throws → { error: <message> }
 *   - No terminal within streamTimeout ms → { error: "stream-timeout" }
 *   - null item in stream → terminal sentinel; returns { events, terminal: null }
 *   - Non-object primitive item → skipped (not counted toward streamEventCap)
 *
 * @param {{
 *   allowlist?: readonly string[],
 *   mcpCall?: (toolName: string, args: object) => Promise<any> | AsyncIterable<any>,
 *   streamEventCap?: number,
 *   streamTimeout?: number,  // ms; 0 = no timeout (default: 10000)
 * }} [opts]
 * @returns {(toolName: string, args: object) => Promise<any>}
 */
export function createHttpDispatcher({
  allowlist = BASE_ALLOWLIST,
  mcpCall = invokeForgeTool,
  streamEventCap = 20,
  streamTimeout = 10000,
} = {}) {
  const writeNames = new Set(WRITE_ALLOWLIST.map((t) => t.name));

  return async (toolName, args = {}) => {
    if (!allowlist.includes(toolName)) {
      return { error: "tool not allowlisted", tool: toolName };
    }
    if (writeNames.has(toolName)) {
      return { error: "destructive tool requires in-IDE confirmation", tool: toolName };
    }

    let rawResult;
    try {
      // Await so that async mcpCall functions are resolved before stream detection.
      rawResult = await mcpCall(toolName, args);
    } catch (err) {
      return { error: err?.message ?? String(err) };
    }

    // Collect async-iterable streams into { events: [...], terminal }.
    if (rawResult != null && typeof rawResult[Symbol.asyncIterator] === "function") {
      const consumeStream = async () => {
        const events = [];
        let terminal = null;
        for await (const item of rawResult) {
          // null item = terminal sentinel with value null; stop collecting.
          if (item === null) {
            return { events, terminal: null };
          }
          // Skip malformed (non-object) primitives — do not count toward cap.
          if (typeof item !== "object") {
            continue;
          }
          if (item.type === "terminal") {
            terminal = item;
            // Consume terminal and stop; remaining items are discarded.
            break;
          } else if (events.length < streamEventCap) {
            events.push(item);
          }
          // Items past streamEventCap are consumed but not stored.
        }
        return { events, terminal };
      };

      if (streamTimeout > 0) {
        let timeoutId;
        const timeoutPromise = new Promise((_, reject) => {
          timeoutId = setTimeout(() => reject(new Error("stream-timeout")), streamTimeout);
        });
        try {
          const result = await Promise.race([consumeStream(), timeoutPromise]);
          clearTimeout(timeoutId);
          return result;
        } catch (err) {
          clearTimeout(timeoutId);
          return { error: err?.message ?? String(err) };
        }
      }

      // streamTimeout === 0 → no timeout; still wrap in try/catch for throws.
      try {
        return await consumeStream();
      } catch (err) {
        return { error: err?.message ?? String(err) };
      }
    }

    return rawResult;
  };
}

/**
 * Forge-Master HTTP Routes (Phase-29, Slice 9).
 *
 * Framework-agnostic route registrar — works with Node's built-in http
 * module as well as any express-compatible app object.
 *
 * Routes:
 *   GET  /api/forge-master/prompts           — prompt catalog
 *   GET  /api/forge-master/sessions          — recent sessions list
 *   GET  /api/forge-master/capabilities      — server capabilities
 *   POST /api/forge-master/chat              — start a chat session
 *   GET  /api/forge-master/chat/:id/stream   — SSE stream
 *   POST /api/forge-master/chat/:id/approve  — resolve approval
 *   GET  /api/forge-master/session/:id       — last 10 turns for a session
 *
 * @module forge-master/http-routes
 */

import { readFileSync, writeFileSync, mkdirSync, existsSync } from "node:fs";
import { join } from "node:path";
import { getPromptCatalog } from "./prompts.mjs";
import { getForgeMasterConfig } from "./config.mjs";
import { runTurn } from "./reasoning.mjs";
import { createSseStream } from "./sse.mjs";
import { BASE_ALLOWLIST, WRITE_ALLOWLIST } from "./allowlist.mjs";
import { createHttpDispatcher, invokeForgeTool } from "./http-dispatcher.mjs";
import { VALID_TIERS } from "./reasoning-tier.mjs";
import { loadSession } from "./session-store.mjs";
import { size as embeddingCacheSize } from "./embedding/cache.mjs";
import { randomUUID } from "node:crypto";

const sessions = new Map();
const pendingApprovals = new Map();
let _embeddingCacheQueries = 0;
let _embeddingCacheHits = 0;

/** Record a cache query (called by reasoning loop or externally). */
export function recordCacheQuery(hit) {
  _embeddingCacheQueries++;
  if (hit) _embeddingCacheHits++;
}

/** Get cache stats for the dashboard tile. */
export function getCacheStats() {
  const sz = embeddingCacheSize();
  const hitRate = _embeddingCacheQueries > 0
    ? _embeddingCacheHits / _embeddingCacheQueries
    : 0;
  return { size: sz, hitRate: Math.round(hitRate * 1000) / 1000, maxSize: 500 };
}

const PREFS_FILE = ".forge/fm-prefs.json";
const VALID_QUORUM_MODES = ["off", "auto", "always"];
const PREFS_DEFAULTS = { tier: null, autoEscalate: false, quorumAdvisory: "off", embeddingFallback: true };

/**
 * Load Forge-Master user prefs from `<cwd>/.forge/fm-prefs.json`.
 * Returns defaults when the file is missing or the stored tier is invalid.
 *
 * @param {string} [cwd] — project root (defaults to process.cwd())
 * @returns {{ tier: string|null, autoEscalate: boolean }}
 */
export function loadPrefs(cwd = process.cwd()) {
  const prefsPath = join(cwd, PREFS_FILE);
  if (!existsSync(prefsPath)) return { ...PREFS_DEFAULTS };
  try {
    const raw = JSON.parse(readFileSync(prefsPath, "utf-8"));
    const tier = raw.tier && VALID_TIERS.includes(raw.tier) ? raw.tier : null;
    const autoEscalate = typeof raw.autoEscalate === "boolean" ? raw.autoEscalate : false;
    const quorumAdvisory = VALID_QUORUM_MODES.includes(raw.quorumAdvisory) ? raw.quorumAdvisory : "off";
    const embeddingFallback = typeof raw.embeddingFallback === "boolean" ? raw.embeddingFallback : true;
    return { tier, autoEscalate, quorumAdvisory, embeddingFallback };
  } catch {
    return { ...PREFS_DEFAULTS };
  }
}

/**
 * Persist Forge-Master user prefs to `<cwd>/.forge/fm-prefs.json`.
 *
 * @param {{ tier: string|null, autoEscalate: boolean }} prefs
 * @param {string} [cwd] — project root (defaults to process.cwd())
 */
export function savePrefs(prefs, cwd = process.cwd()) {
  const forgeDir = join(cwd, ".forge");
  mkdirSync(forgeDir, { recursive: true });
  writeFileSync(join(cwd, PREFS_FILE), JSON.stringify(prefs, null, 2), "utf-8");
}

// ─── Route handler map ───────────────────────────────────────────────

/**
 * Register Forge-Master routes on an express-compatible app or bare
 * Node http IncomingMessage/ServerResponse router.
 *
 * When `app` has `app.get` / `app.post` methods we use them (express mode).
 * Otherwise the function returns a request handler function suitable for
 * `http.createServer(handler)`.
 *
 * @param {object} app — express app or null
 * @param {{ mcpCall?: Function }} [opts] — optional in-process tool invoker
 * @returns {Function|undefined} — request handler when app is null
 */
export function createHttpRoutes(app, { mcpCall = invokeForgeTool } = {}) {
  const dispatcher = createHttpDispatcher({ allowlist: BASE_ALLOWLIST, mcpCall });
  if (app && typeof app.get === "function") {
    // Defensive check: _registerExpress requires get/post/put/use. Detecting
    // an incomplete express-shaped object up front gives a clear error
    // instead of a swallowed `app.put is not a function` mid-registration
    // (which historically left the routes half-registered and produced
    // confusing downstream test failures — see issue #149 Bucket B).
    const missing = ["get", "post", "put", "use"].filter(
      (m) => typeof app[m] !== "function",
    );
    if (missing.length > 0) {
      throw new TypeError(
        `createHttpRoutes: express-shaped app is missing required method(s): ${missing.join(", ")}. ` +
        `If this is a test mock, add stubs for those methods. If it's a real express app, upgrade express to >=4.0.`,
      );
    }
    _registerExpress(app, dispatcher);
  } else {
    return _buildNodeHandler(dispatcher);
  }
}

// ─── Express-mode registration ───────────────────────────────────────

function registerForgeMasterCatalogRoutes(app) {
  app.get("/api/forge-master/prompts", (req, res) => {
    res.json(getPromptCatalog());
  });

  app.get("/api/forge-master/sessions", (req, res) => {
    res.json(Array.from(sessions.entries()).map(([id, session]) => ({ id, ...session })));
  });

  app.get("/api/forge-master/capabilities", (req, res) => {
    const config = getForgeMasterConfig();
    const catalog = getPromptCatalog();
    const promptCount = catalog.categories.reduce((count, category) => count + category.prompts.length, 0);
    res.json({
      reasoningModel: config.reasoningModel,
      routerModel: config.routerModel,
      allowlistedTools: BASE_ALLOWLIST.length,
      writeAllowlist: WRITE_ALLOWLIST.length,
      promptCategories: catalog.categories.length,
      promptCount,
    });
  });

  app.get("/api/forge-master/cache-stats", (req, res) => {
    res.json(getCacheStats());
  });
}

function registerForgeMasterPreferenceRoutes(app) {
  app.get("/api/forge-master/prefs", (req, res) => {
    res.json(loadPrefs(process.cwd()));
  });

  app.put("/api/forge-master/prefs", (req, res) => {
    const { tier, autoEscalate, quorumAdvisory, embeddingFallback } = req.body || {};
    const normalized = {
      tier: tier && VALID_TIERS.includes(tier) ? tier : null,
      autoEscalate: typeof autoEscalate === "boolean" ? autoEscalate : false,
      quorumAdvisory: VALID_QUORUM_MODES.includes(quorumAdvisory) ? quorumAdvisory : "off",
      embeddingFallback: typeof embeddingFallback === "boolean" ? embeddingFallback : true,
    };
    savePrefs(normalized, process.cwd());
    res.json(normalized);
  });
}

function registerForgeMasterChatRoutes(app, dispatcher) {
  app.post("/api/forge-master/chat", (req, res) => {
    const { message, sessionId: reqSessionId } = req.body || {};
    if (!message) return res.status(400).json({ error: "message required" });
    const sessionId = reqSessionId || randomUUID();
    const keywordOnly = req.headers["x-pforge-keyword-only"] === "1";
    const fmSessionId = req.headers["x-pforge-session-id"] || null;
    sessions.set(sessionId, { createdAt: new Date().toISOString(), lastMessage: message, keywordOnly, fmSessionId });
    res.json({
      sessionId,
      streamUrl: `/api/forge-master/chat/${sessionId}/stream?message=${encodeURIComponent(message)}`,
    });
  });

  app.get("/api/forge-master/chat/:sessionId/stream", async (req, res) => {
    const { sessionId } = req.params;
    const message = req.query.message || "";
    const session = sessions.get(sessionId) || {};
    const prefs = loadPrefs(process.cwd());
    const sse = createSseStream(res);
    try {
      sse.send("start", { sessionId });
      const result = await runTurn(
        { message, sessionId },
        {
          dispatcher,
          sessionId: session.fmSessionId || null,
          forceKeywordOnly: session.keywordOnly || false,
          quorumAdvisory: prefs.quorumAdvisory || "off",
          onClassification: (data) => { sse.send("classification", data); },
          onPlan: (data) => { sse.send("plan", data); },
          onQuorumEstimate: (data) => { sse.send("quorum-estimate", data); },
        },
      );
      if (result.error) {
        sse.send("error", { error: result.error, sessionId, tokensIn: result.tokensIn, tokensOut: result.tokensOut, totalCostUSD: result.totalCostUSD || 0 });
      } else {
        sse.send("reply", { content: result.reply, sessionId });
        for (const toolCall of result.toolCalls || []) sse.send("tool-call", toolCall);
        sse.send("done", { sessionId, tokensIn: result.tokensIn, tokensOut: result.tokensOut, totalCostUSD: result.totalCostUSD || 0, resolvedModel: result.resolvedModel || null, relatedTurns: result.relatedTurns || [], quorumResult: result.quorumResult || null });
      }
    } catch (err) {
      sse.send("error", { error: err.message });
    } finally {
      sse.close();
    }
  });

  app.post("/api/forge-master/chat/:sessionId/approve", (req, res) => {
    const { approvalId, decision, editedArgs } = req.body || {};
    const gate = pendingApprovals.get(approvalId);
    if (!gate) return res.status(404).json({ error: "approval not found" });
    gate({ decision, editedArgs });
    pendingApprovals.delete(approvalId);
    res.json({ ok: true, approvalId, decision });
  });
}

function registerForgeMasterSessionRoutes(app) {
  app.get("/api/forge-master/session/:id", async (req, res) => {
    const { id } = req.params;
    try {
      const turns = await loadSession(id, process.cwd());
      res.json({ sessionId: id, turns: turns.slice(-10) });
    } catch {
      res.json({ sessionId: id, turns: [] });
    }
  });

  app.use("/api/forge-master", (req, res) => {
    res.status(404).json({ error: "not found" });
  });
}

function _registerExpress(app, dispatcher) {
  registerForgeMasterCatalogRoutes(app);
  registerForgeMasterPreferenceRoutes(app);
  registerForgeMasterChatRoutes(app, dispatcher);
  registerForgeMasterSessionRoutes(app);
}

// ─── Built-in http handler (no express) ─────────────────────────────

function json(res, code, data) {
  const body = JSON.stringify(data);
  res.writeHead(code, { "Content-Type": "application/json" });
  res.end(body);
}

async function readBody(req) {
  return new Promise((resolve) => {
    let data = "";
    req.on("data", (c) => { data += c; });
    req.on("end", () => {
      try { resolve(JSON.parse(data)); } catch { resolve({}); }
    });
  });
}

function buildCapabilitiesResponse() {
  const config = getForgeMasterConfig();
  const catalog = getPromptCatalog();
  const promptCount = catalog.categories.reduce((n, c) => n + c.prompts.length, 0);
  return {
    reasoningModel: config.reasoningModel,
    routerModel: config.routerModel,
    allowlistedTools: BASE_ALLOWLIST.length,
    writeAllowlist: WRITE_ALLOWLIST.length,
    promptCategories: catalog.categories.length,
    promptCount,
  };
}

function normalizePrefs(body) {
  const { tier, autoEscalate, quorumAdvisory, embeddingFallback } = body;
  return {
    tier: tier && VALID_TIERS.includes(tier) ? tier : null,
    autoEscalate: typeof autoEscalate === "boolean" ? autoEscalate : false,
    quorumAdvisory: VALID_QUORUM_MODES.includes(quorumAdvisory) ? quorumAdvisory : "off",
    embeddingFallback: typeof embeddingFallback === "boolean" ? embeddingFallback : true,
  };
}

function sendStreamResult(sse, result, sessionId) {
  if (result.error) {
    sse.send("error", { error: result.error, sessionId, tokensIn: result.tokensIn, tokensOut: result.tokensOut, totalCostUSD: result.totalCostUSD || 0 });
    return;
  }

  sse.send("reply", { content: result.reply, sessionId });
  for (const tc of result.toolCalls || []) sse.send("tool-call", tc);
  sse.send("done", { sessionId, tokensIn: result.tokensIn, tokensOut: result.tokensOut, totalCostUSD: result.totalCostUSD || 0, resolvedModel: result.resolvedModel || null, relatedTurns: result.relatedTurns || [], quorumResult: result.quorumResult || null });
}

async function handleNodePromptsRoute({ method, path, res }) {
  if (method !== "GET" || path !== "/api/forge-master/prompts") return false;
  json(res, 200, getPromptCatalog());
  return true;
}

async function handleNodeSessionsRoute({ method, path, res }) {
  if (method !== "GET" || path !== "/api/forge-master/sessions") return false;
  json(res, 200, Array.from(sessions.entries()).map(([id, s]) => ({ id, ...s })));
  return true;
}

async function handleNodeCapabilitiesRoute({ method, path, res }) {
  if (method !== "GET" || path !== "/api/forge-master/capabilities") return false;
  json(res, 200, buildCapabilitiesResponse());
  return true;
}

async function handleNodePrefsGetRoute({ method, path, res }) {
  if (method !== "GET" || path !== "/api/forge-master/prefs") return false;
  json(res, 200, loadPrefs(process.cwd()));
  return true;
}

async function handleNodeCacheStatsRoute({ method, path, res }) {
  if (method !== "GET" || path !== "/api/forge-master/cache-stats") return false;
  json(res, 200, getCacheStats());
  return true;
}

async function handleNodePrefsPutRoute({ method, path, req, res }) {
  if (method !== "PUT" || path !== "/api/forge-master/prefs") return false;
  const normalized = normalizePrefs(await readBody(req));
  savePrefs(normalized, process.cwd());
  json(res, 200, normalized);
  return true;
}

async function handleNodeChatRoute({ method, path, req, res }) {
  if (method !== "POST" || path !== "/api/forge-master/chat") return false;

  const { message, sessionId: reqSessionId } = await readBody(req);
  if (!message) {
    json(res, 400, { error: "message required" });
    return true;
  }

  const sessionId = reqSessionId || randomUUID();
  const keywordOnly = req.headers["x-pforge-keyword-only"] === "1";
  const fmSessionId = req.headers["x-pforge-session-id"] || null;
  sessions.set(sessionId, { createdAt: new Date().toISOString(), lastMessage: message, keywordOnly, fmSessionId });
  json(res, 200, {
    sessionId,
    streamUrl: `/api/forge-master/chat/${sessionId}/stream?message=${encodeURIComponent(message)}`,
  });
  return true;
}

async function handleNodeStreamRoute({ method, path, url, res, dispatcher }) {
  const streamMatch = path.match(/^\/api\/forge-master\/chat\/([^/]+)\/stream$/);
  if (method !== "GET" || !streamMatch) return false;

  const sessionId = streamMatch[1];
  const message = url.searchParams.get("message") || "";
  const session = sessions.get(sessionId) || {};
  const prefs = loadPrefs(process.cwd());
  const sse = createSseStream(res);

  try {
    sse.send("start", { sessionId });
    const result = await runTurn(
      { message, sessionId },
      {
        dispatcher,
        sessionId: session.fmSessionId || null,
        forceKeywordOnly: session.keywordOnly || false,
        quorumAdvisory: prefs.quorumAdvisory || "off",
        onClassification: (data) => { sse.send("classification", data); },
        onPlan: (data) => { sse.send("plan", data); },
        onQuorumEstimate: (data) => { sse.send("quorum-estimate", data); },
      },
    );
    sendStreamResult(sse, result, sessionId);
  } catch (err) {
    sse.send("error", { error: err.message });
  } finally {
    sse.close();
  }

  return true;
}

async function handleNodeApproveRoute({ method, path, req, res }) {
  const approveMatch = path.match(/^\/api\/forge-master\/chat\/([^/]+)\/approve$/);
  if (method !== "POST" || !approveMatch) return false;

  const { approvalId, decision, editedArgs } = await readBody(req);
  const gate = pendingApprovals.get(approvalId);
  if (!gate) {
    json(res, 404, { error: "approval not found" });
    return true;
  }

  gate({ decision, editedArgs });
  pendingApprovals.delete(approvalId);
  json(res, 200, { ok: true, approvalId, decision });
  return true;
}

async function handleNodeSessionRoute({ method, path, res }) {
  const sessionMatch = path.match(/^\/api\/forge-master\/session\/([^/]+)$/);
  if (method !== "GET" || !sessionMatch) return false;

  const id = sessionMatch[1];
  try {
    const turns = await loadSession(id, process.cwd());
    json(res, 200, { sessionId: id, turns: turns.slice(-10) });
  } catch {
    json(res, 200, { sessionId: id, turns: [] });
  }

  return true;
}

const NODE_ROUTE_HANDLERS = [
  handleNodePromptsRoute,
  handleNodeSessionsRoute,
  handleNodeCapabilitiesRoute,
  handleNodePrefsGetRoute,
  handleNodeCacheStatsRoute,
  handleNodePrefsPutRoute,
  handleNodeChatRoute,
  handleNodeStreamRoute,
  handleNodeApproveRoute,
  handleNodeSessionRoute,
];

function _buildNodeHandler(dispatcher) {
  return async function handler(req, res) {
    const url = new URL(req.url, `http://${req.headers.host || "localhost"}`);
    const path = url.pathname;

    if (!path.startsWith("/api/forge-master")) return null;

    const context = {
      req,
      res,
      url,
      path,
      method: req.method,
      dispatcher,
    };

    for (const route of NODE_ROUTE_HANDLERS) {
      if (await route(context)) return;
    }

    return json(res, 404, { error: "not found" });
  };
}

/**
 * Plan Forge — Forge-Master Intent Router (Phase-28, Slice 2).
 *
 * Two-stage classifier:
 *   1. Keyword regex table (fast path, zero cost)
 *   2. Router-model call (only when keyword match is ambiguous)
 *
 * Lanes:
 *   - build              — user wants to create/add/change a feature → Crucible
 *   - operational        — status, cost, health, memory, watcher queries
 *   - troubleshoot       — bug, incident, failure investigation
 *   - offtopic           — everything outside Plan Forge's domain
 *   - advisory           — architectural guidance and principled recommendations
 *   - tempering          — tempering gate evaluation and enforcement checks
 *   - principle-judgment — principled architectural decisions and principle reviews
 *   - meta-bug-triage    — triage of meta-bugs, self-repair, plan/orchestrator defects
 *
 * Exports:
 *   classify(message, opts?) → {lane, confidence: "low"|"medium"|"high", reason, suggestedTools}
 *
 * @module forge-master/intent-router
 */

