// ─── Off-Topic Redirect (canned response) ───────────────────────────

export const OFFTOPIC_REDIRECT =
  "I'm scoped to Plan Forge topics. Try asking about:\n" +
  "  \u2022 operational \u2014 \"what's the status of slice 4\", \"cost report for this week\"\n" +
  "  \u2022 troubleshoot \u2014 \"why did the gate fail\", \"diagnose this incident\"\n" +
  "  \u2022 build \u2014 \"I want to add OAuth\" (routes to Crucible)\n" +
  "  \u2022 advisory \u2014 \"should I refactor or ship\", \"architecture advice\"\n" +
  "Outside those lanes I'll redirect you.";

// Internal confidence thresholds (used within deriveFromScores only)
const HIGH_CONFIDENCE = 0.85;
const AMBIGUOUS_THRESHOLD = 0.55;

/**
 * Convert a raw keyword score to a confidence tier string.
 * @param {number} score
 * @returns {"low"|"medium"|"high"}
 */
function scoreToConfidence(score) {
  if (score <= 2) return "low";
  if (score <= 5) return "medium";
  return "high";
}

// ─── Keyword Classification ─────────────────────────────────────────

/**
 * Score a message against the keyword table.
 * @param {string} message
 * @returns {{ scores: Record<string, number>, totalWeight: number }}
 */
function scoreKeywords(message) {
  const scores = {
    [LANES.BUILD]: 0,
    [LANES.OPERATIONAL]: 0,
    [LANES.TROUBLESHOOT]: 0,
    [LANES.OFFTOPIC]: 0,
    [LANES.ADVISORY]: 0,
    [LANES.TEMPERING]: 0,
    [LANES.PRINCIPLE_JUDGMENT]: 0,
    [LANES.META_BUG_TRIAGE]: 0,
  };
  let totalWeight = 0;

  for (const rule of KEYWORD_RULES) {
    if (rule.pattern.test(message)) {
      scores[rule.lane] += rule.weight;
      totalWeight += rule.weight;
    }
  }

  return { scores, totalWeight };
}

/**
 * Derive lane + raw score from keyword scores.
 * @param {{ scores: Record<string, number>, totalWeight: number }} result
 * @returns {{ lane: string, score: number } | null}
 */
function deriveFromScores({ scores, totalWeight }) {
  if (totalWeight === 0) return null;

  const sorted = Object.entries(scores)
    .filter(([, s]) => s > 0)
    .sort((a, b) => b[1] - a[1]);

  if (sorted.length === 0) return null;

  // OFFTOPIC tie-breaker: when offtopic score >= any non-offtopic score, offtopic wins.
  const offtopicScore = scores[LANES.OFFTOPIC] ?? 0;
  const maxNonOfftopicScore = Math.max(
    0,
    ...Object.entries(scores)
      .filter(([lane]) => lane !== LANES.OFFTOPIC)
      .map(([, s]) => s),
  );

  if (offtopicScore > 0 && offtopicScore >= maxNonOfftopicScore) {
    return { lane: LANES.OFFTOPIC, score: offtopicScore };
  }

  const [topLane, topScore] = sorted[0];
  const numericConfidence = topScore / totalWeight;

  // If the top lane has a clear lead, classify with confidence
  if (sorted.length === 1 || numericConfidence >= AMBIGUOUS_THRESHOLD) {
    return { lane: topLane, score: topScore };
  }

  // Multiple lanes scored but no clear winner — ambiguous
  return null;
}

// ─── Router-Model Fallback ──────────────────────────────────────────

const ROUTER_PROMPT = `You are a message classifier for Plan Forge, a software plan orchestration system.

Classify the user's message into exactly ONE lane:
- "build" — the user wants to create, add, implement, or design a new feature, phase, or component
- "operational" — the user asks about status, cost, health, metrics, memory, watchers, extensions, plans, or runs
- "troubleshoot" — the user asks about bugs, failures, errors, incidents, regressions, or root causes
- "advisory" — the user asks for architectural guidance, a recommendation, or a principled decision ("should I", "what's the right approach", "recommend a path")
- "tempering" — the user requests a tempering gate evaluation, enforcement check, or tempering run
- "principle-judgment" — the user asks for a principled architectural decision, principle review, or principle ruling
- "meta-bug-triage" — the user wants to triage a meta-bug, self-repair issue, plan defect, or orchestrator defect
- "offtopic" — the message is unrelated to Plan Forge (weather, personal questions, code generation, etc.)

Respond with ONLY a JSON object: {"lane": "<lane>"}
Do not include any other text.

User message: `;

/**
 * Call the router model for ambiguous classification.
 * @param {string} message
 * @param {{ callApiWorker: Function, routerModel: string, routerProvider: object, priorTurns?: object[] }} deps
 * @returns {Promise<string|null>} lane name or null on failure
 */
async function callRouterModel(message, deps) {
  try {
    let prompt = ROUTER_PROMPT;
    if (deps.priorTurns && deps.priorTurns.length > 0) {
      const contextLines = deps.priorTurns
        .slice(-5)
        .map(t => (t.userMessage || "").trim().slice(0, 100))
        .filter(Boolean)
        .map(m => `- ${JSON.stringify(m)}`)
        .join("\n");
      if (contextLines) {
        prompt = `Recent conversation (last user messages):\n${contextLines}\n\n${ROUTER_PROMPT}`;
      }
    }
    const result = await deps.callApiWorker(
      prompt + JSON.stringify(message),
      deps.routerModel,
      deps.routerProvider,
      { timeout: 15_000, role: "forge-master-router" },
    );

    if (!result?.output) return null;

    const text = result.output.trim();
    // Try JSON parse first
    try {
      const parsed = JSON.parse(text);
      if (parsed.lane && Object.values(LANES).includes(parsed.lane)) {
        return parsed.lane;
      }
    } catch { /* not JSON, try regex extraction */ }

    // Fallback: look for a lane name in the output
    for (const lane of Object.values(LANES)) {
      if (text.toLowerCase().includes(lane)) return lane;
    }

    return null;
  } catch {
    return null; // graceful degradation — keyword-only
  }
}

// ─── Public API ─────────────────────────────────────────────────────

/**
 * Classify a user message into one of four lanes.
 *
 * Stage 1: keyword regex table (fast, zero cost).
 * Stage 2: router-model call (only when keywords are ambiguous).
 * Fallback: if router model unavailable, falls back to keyword-only
 *           with reduced confidence.
 *
 * @param {string} message — the user's input text
 * @param {{
 *   cwd?: string,
 *   callApiWorker?: Function,
 *   detectApiProvider?: Function,
 *   keywordOnly?: boolean,   — when true, skip stage-2 router-model entirely
 *   priorTurns?: object[],   — recent session turns for context-aware routing
 * }} [opts]
 * @returns {Promise<{
 *   lane: string,
 *   confidence: "low"|"medium"|"high",
 *   reason: string,
 *   suggestedTools: string[],
 * }>}
 */
export async function classify(message, opts = {}) {
  if (!message || typeof message !== "string" || !message.trim()) {
    return {
      lane: LANES.OFFTOPIC,
      confidence: "high",
      reason: "empty_message",
      suggestedTools: LANE_TOOLS[LANES.OFFTOPIC],
    };
  }

  const trimmed = message.trim();
  const embedFn = opts._embed; // DI seam for tests

  // Stage 1: keyword scoring
  const kwResult = scoreKeywords(trimmed);
  const kwClassification = deriveFromScores(kwResult);

  if (kwClassification) {
    const result = {
      lane: kwClassification.lane,
      confidence: scoreToConfidence(kwClassification.score),
      reason: "keyword_match",
      suggestedTools: LANE_TOOLS[kwClassification.lane],
    };
    _writeThroughCache(trimmed, result, embedFn);
    return result;
  }

  // Stage 1.5: embedding cache lookup (skipped when embeddingFallback === false)
  if (opts.embeddingFallback !== false) {
    try {
      const cacheHits = await queryCacheRaw(trimmed, {
        threshold: 0.85,
        topK: 1,
        ...(embedFn ? { _embed: embedFn } : {}),
      });
      if (cacheHits.length > 0) {
        const hit = cacheHits[0];
        return {
          lane: hit.classification.lane,
          confidence: hit.classification.confidence || "medium",
          reason: "embedding-cache",
          via: "embedding-cache",
          suggestedTools: LANE_TOOLS[hit.classification.lane],
        };
      }
    } catch (err) {
      console.warn("embedding cache query failed", err?.message || String(err));
    }
  }

  // No keyword match or ambiguous — try router model (skipped when keywordOnly)
  if (!opts.keywordOnly && opts.callApiWorker && opts.detectApiProvider) {
    const config = getForgeMasterConfig({ cwd: opts.cwd });
    const routerProvider = opts.detectApiProvider(config.routerModel);

    if (routerProvider) {
      const modelLane = await callRouterModel(trimmed, {
        callApiWorker: opts.callApiWorker,
        routerModel: config.routerModel,
        routerProvider,
        priorTurns: opts.priorTurns,
      });

      if (modelLane) {
        const result = {
          lane: modelLane,
          confidence: "medium",
          reason: "router_model",
          suggestedTools: LANE_TOOLS[modelLane],
        };
        _writeThroughCache(trimmed, result, embedFn);
        return result;
      }
    }
  }

  // Fallback: if keywords scored anything at all, pick top with low confidence
  if (kwResult.totalWeight > 0) {
    const sorted = Object.entries(kwResult.scores)
      .filter(([, s]) => s > 0)
      .sort((a, b) => b[1] - a[1]);
    const [topLane, topScore] = sorted[0];
    const result = {
      lane: topLane,
      confidence: scoreToConfidence(topScore),
      reason: "keyword_weak",
      suggestedTools: LANE_TOOLS[topLane],
    };
    _writeThroughCache(trimmed, result, embedFn);
    return result;
  }

  // No signals at all — default to offtopic. Meta-bug #98 considered
  // flipping this to operational, but explicit tests guard the "slice
  // me an apple" / "phase of the moon" → offtopic contract. The #98
  // fix lives in the expanded keyword patterns above, not here.
  return {
    lane: LANES.OFFTOPIC,
    confidence: "low",
    reason: "no_signals",
    suggestedTools: LANE_TOOLS[LANES.OFFTOPIC],
  };
}

/**
 * Fire-and-forget: write a successful classification to the embedding cache.
 * Errors are swallowed — cache population must never break the classify path.
 */
function _writeThroughCache(text, classification, embedFn) {
  addCacheEntry({
    text,
    classification: { lane: classification.lane, confidence: classification.confidence },
    confidence: classification.confidence === "high" ? 0.95 : classification.confidence === "medium" ? 0.75 : 0.5,
    ...(embedFn ? { _embed: embedFn } : {}),
  }).catch(() => { /* swallow — cache write is advisory */ });
}

/**
 * Forge-Master Lifecycle Manager (Phase-29, Slice 10).
 *
 * Start/stop/status/logs helpers for the Forge-Master Studio HTTP server.
 * Manages a PID file at .forge/forge-master.pid.
 *
 * Can be run as a CLI script:
 *   node src/lifecycle.mjs start
 *   node src/lifecycle.mjs stop
 *   node src/lifecycle.mjs status [--json]
 *   node src/lifecycle.mjs logs [--n=50]
 *
 * @module forge-master/lifecycle
 */

import { existsSync, readFileSync, writeFileSync, mkdirSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";
import { spawn } from "node:child_process";

const __dirname = dirname(fileURLToPath(import.meta.url));
const SERVER_PATH = resolve(__dirname, "../server.mjs");
const HTTP_PORT = 3102;

function forgePath(cwd, file) {
  const dir = resolve(cwd, ".forge");
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
  return resolve(dir, file);
}

/**
 * Start the Forge-Master HTTP server as a detached background process.
 *
 * @param {{ cwd?: string }} [opts]
 */
export async function start(opts = {}) {
  const cwd = opts.cwd || process.cwd();
  const pidFile = forgePath(cwd, "forge-master.pid");

  const existing = await status({ cwd });
  if (existing.running) {
    console.log(`forge-master already running (PID ${existing.pid})`);
    return;
  }

  const child = spawn(process.execPath, [SERVER_PATH, "--http"], {
    detached: true,
    stdio: ["ignore", "ignore", "ignore"],
    cwd,
  });

  writeFileSync(pidFile, String(child.pid));
  child.unref();
  console.log(`forge-master started on http://127.0.0.1:${HTTP_PORT} (PID ${child.pid})`);
}

/**
 * Stop the running Forge-Master HTTP server.
 *
 * @param {{ cwd?: string }} [opts]
 */
export async function stop(opts = {}) {
  const cwd = opts.cwd || process.cwd();
  const pidFile = forgePath(cwd, "forge-master.pid");
  if (!existsSync(pidFile)) { console.log("forge-master is not running"); return; }
  const pidStr = readFileSync(pidFile, "utf-8").trim();
  if (!pidStr) { console.log("forge-master is not running"); return; }
  const pid = parseInt(pidStr, 10);
  try { process.kill(pid, "SIGTERM"); } catch { /* already dead */ }
  try { writeFileSync(pidFile, ""); } catch { /* non-fatal */ }
  console.log(`forge-master stopped (PID ${pid})`);
}

/**
 * Get the running status of Forge-Master.
 *
 * @param {{ cwd?: string }} [opts]
 * @returns {{ running: boolean, pid?: number, port?: number }}
 */
export async function status(opts = {}) {
  const cwd = opts.cwd || process.cwd();
  const pidFile = forgePath(cwd, "forge-master.pid");
  if (!existsSync(pidFile)) return { running: false };
  const pidStr = readFileSync(pidFile, "utf-8").trim();
  if (!pidStr) return { running: false };
  const pid = parseInt(pidStr, 10);
  if (!Number.isFinite(pid)) return { running: false };
  try {
    process.kill(pid, 0); // 0 = existence check
    return { running: true, pid, port: HTTP_PORT };
  } catch {
    return { running: false };
  }
}

/**
 * Print recent log lines from the Forge-Master stdio log.
 *
 * @param {{ cwd?: string, n?: number }} [opts]
 */
export async function logs(opts = {}) {
  const cwd = opts.cwd || process.cwd();
  const n = opts.n || 50;
  const logFile = forgePath(cwd, "forge-master-stdio.log");
  if (!existsSync(logFile)) { console.log("No log file found"); return; }
  const content = readFileSync(logFile, "utf-8");
  const lines = content.split("\n").filter(Boolean);
  console.log(lines.slice(-n).join("\n"));
}

// ─── CLI entry point ─────────────────────────────────────────────────

const [,, cmd, ...cliArgs] = process.argv;
if (cmd && ["start", "stop", "status", "logs"].includes(cmd)) {
  const jsonFlag = cliArgs.includes("--json");
  const nArg = cliArgs.find(a => a.startsWith("--n="));
  const n = nArg ? parseInt(nArg.split("=")[1], 10) : 50;
  const fn = { start, stop, status, logs }[cmd];
  fn({ json: jsonFlag, n }).then(result => {
    if (result && jsonFlag) console.log(JSON.stringify(result));
  }).catch(err => { console.error(err.message); process.exit(1); });
}

/**
 * Forge-Master Studio — Downstream MCP Client (Phase-29, Slice 3).
 *
 * Spawns `pforge-mcp/server.mjs` as a child process over stdio MCP,
 * performs the MCP handshake, calls `tools/list`, and exposes
 * `invoke(name, args)` that routes through the MCP protocol rather
 * than in-process imports.
 *
 * On startup the client asserts that the discovered tool count is at
 * least BASE_TOOL_COUNT_MIN (the Phase-28 base-allowlist size). A log
 * line confirms readiness:
 *   forge-master: downstream MCP ready (N tools, M allowlisted)
 *
 * Exports:
 *   - createMcpClient(options?, deps?) → McpClient
 *   - BASE_TOOL_COUNT_MIN — minimum expected downstream tool count
 *
 * @module forge-master/mcp-client
 */

import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";
import { existsSync, appendFileSync, mkdirSync } from "node:fs";

import { Client } from "@modelcontextprotocol/sdk/client/index.js";
import { StdioClientTransport } from "@modelcontextprotocol/sdk/client/stdio.js";
import { BASE_ALLOWLIST } from "./allowlist.mjs";

// ─── Constants ──────────────────────────────────────────────────────

/** Minimum downstream tool count — at least the base allowlist size */
export const BASE_TOOL_COUNT_MIN = BASE_ALLOWLIST.length;

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

/** Absolute path to pforge-mcp/server.mjs relative to this file */
const DOWNSTREAM_SERVER_PATH = resolve(__dirname, "../../pforge-mcp/server.mjs");

/** Default stderr log destination inside .forge/ */
const DEFAULT_LOG_PATH = resolve(__dirname, "../../.forge/forge-master-stdio.log");

// ─── McpClient class ─────────────────────────────────────────────────

/**
 * Thin wrapper around the MCP SDK Client + StdioClientTransport.
 * Manages lifecycle, tool discovery, and invocation.
 */
export class McpClient {
  #client = null;
  #transport = null;
  #tools = [];
  #ready = false;
  #logPath = null;
  #logger = null;

  constructor({ logPath = DEFAULT_LOG_PATH, logger = console } = {}) {
    this.#logPath = logPath;
    this.#logger = logger;
  }

  /** True when connected and tools/list has been received */
  get ready() {
    return this.#ready;
  }

  /** Array of discovered tool names */
  get toolNames() {
    return this.#tools.map((t) => t.name);
  }

  /** Number of discovered tools */
  get toolCount() {
    return this.#tools.length;
  }

  /**
   * Connect to the downstream MCP server.
   * Performs handshake + tools/list + assertion.
   *
   * @param {{ serverPath?: string, env?: object }} opts
   * @returns {Promise<void>}
   */
  async connect({ serverPath = DOWNSTREAM_SERVER_PATH, env = process.env } = {}) {
    if (this.#ready) return;

    if (!existsSync(serverPath)) {
      throw new Error(`downstream MCP server not found: ${serverPath}`);
    }

    // Ensure log directory exists
    try {
      const logDir = resolve(this.#logPath, "..");
      if (!existsSync(logDir)) mkdirSync(logDir, { recursive: true });
    } catch {
      // non-fatal
    }

    const stderrHandler = this.#logPath ? "pipe" : "inherit";

    this.#transport = new StdioClientTransport({
      command: process.execPath,
      args: [serverPath, "--port", "0"],
      env: { ...env },
      stderr: stderrHandler,
    });

    // Tee child stderr to log file
    if (stderrHandler === "pipe" && this.#logPath) {
      this.#transport.stderr?.on("data", (chunk) => {
        try {
          appendFileSync(this.#logPath, chunk);
        } catch {
          // non-fatal
        }
      });
    }

    this.#client = new Client(
      { name: "forge-master-studio", version: "1.0.0" },
      { capabilities: {} },
    );

    await this.#client.connect(this.#transport);

    // Discover tools
    const { tools = [] } = await this.#client.listTools();
    this.#tools = tools;

    if (tools.length < BASE_TOOL_COUNT_MIN) {
      this.#logger.warn(
        `forge-master: downstream MCP connected but tool count ${tools.length} < expected ${BASE_TOOL_COUNT_MIN}`,
      );
    }

    this.#ready = true;
    const allowlisted = BASE_ALLOWLIST.filter((n) => tools.some((t) => t.name === n)).length;
    this.#logger.log(
      `forge-master: downstream MCP ready (${tools.length} tools, ${allowlisted} allowlisted)`,
    );
  }

  /**
   * Invoke a tool on the downstream MCP server.
   *
   * @param {string} name
   * @param {object} args
   * @returns {Promise<any>} raw result content
   */
  async invoke(name, args = {}) {
    if (!this.#ready || !this.#client) {
      throw new Error("McpClient not connected — call connect() first");
    }

    const res = await this.#client.callTool({ name, arguments: args });

    // MCP result is { content: [{type, text}], isError? }
    if (res.isError) {
      const msg = res.content?.map((c) => c.text).join("") || "tool error";
      throw new Error(`MCP tool error (${name}): ${msg}`);
    }

    // Return parsed content: if it looks like JSON, parse it; else return text
    const text = res.content?.map((c) => c.text ?? "").join("") ?? "";
    try {
      return JSON.parse(text);
    } catch {
      return text;
    }
  }

  /**
   * Check if a tool is available downstream.
   *
   * @param {string} name
   * @returns {boolean}
   */
  hasTool(name) {
    return this.#tools.some((t) => t.name === name);
  }

  /**
   * Close the client and terminate the child process.
   *
   * @returns {Promise<void>}
   */
  async close() {
    this.#ready = false;
    try {
      await this.#transport?.close();
    } catch {
      // already closed
    }
    this.#client = null;
    this.#transport = null;
    this.#tools = [];
  }

  // ─── Test-only hooks ───────────────────────────────────────────────

  /**
   * Inject mock client/transport for unit testing.
   * @internal test-only
   */
  _injectForTest({ client, transport }) {
    this.#client = client;
    this.#transport = transport;
  }

  /**
   * Run only the post-spawn logic (tools/list + assertion + ready flag)
   * using the already-injected client. For unit testing without spawning.
   * @internal test-only
   */
  async _connectWithInjected() {
    await this.#client.connect(this.#transport);
    const { tools = [] } = await this.#client.listTools();
    this.#tools = tools;

    if (tools.length < BASE_TOOL_COUNT_MIN) {
      this.#logger.warn(
        `forge-master: downstream MCP connected but tool count ${tools.length} < expected ${BASE_TOOL_COUNT_MIN}`,
      );
    }

    this.#ready = true;
    const allowlisted = BASE_ALLOWLIST.filter((n) => tools.some((t) => t.name === n)).length;
    this.#logger.log(
      `forge-master: downstream MCP ready (${tools.length} tools, ${allowlisted} allowlisted)`,
    );
  }
}

// ─── Factory ─────────────────────────────────────────────────────────

/**
 * Create and return a connected McpClient.
 *
 * @param {{ serverPath?: string, logPath?: string, env?: object }} opts
 * @param {{ logger?: { log, warn } }} deps
 * @returns {Promise<McpClient>}
 */
export async function createMcpClient(opts = {}, deps = {}) {
  const { serverPath, logPath, env } = opts;
  const { logger = console } = deps;
  const client = new McpClient({ logPath, logger });
  await client.connect({ serverPath, env });
  return client;
}

/**
 * Observer Budget — daily USD cap + hourly narration cap (Phase-39, Slice 6).
 *
 * Pure functions:
 *   checkBudget(state, caps, [now])  → { ok, reason? }
 *   recordSpend(state, spend)        → updatedState
 *
 * I/O helpers (NOT pure — touch the filesystem):
 *   loadBudgetState([opts])          → state
 *   saveBudgetState(state, [opts])   → void  (atomic: write-to-tmp + rename)
 *
 * State shape (persisted to .forge/forge-master-observer-state.json):
 * {
 *   dailyUsd:          number,  // total USD spent in the current calendar day
 *   dailyDate:         string,  // "YYYY-MM-DD" — day-rollover sentinel
 *   hourlyNarrations:  number,  // narrations emitted in the current clock hour
 *   hourlyHour:        string,  // "YYYY-MM-DDTHH" — hour-rollover sentinel
 * }
 *
 * @module forge-master/observer-budget
 */

import { existsSync, readFileSync, writeFileSync, renameSync, mkdirSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { randomBytes } from "node:crypto";

// ─── Constants ────────────────────────────────────────────────────────

export const BUDGET_STATE_FILE = ".forge/forge-master-observer-state.json";

export const DEFAULT_BUDGET_STATE = Object.freeze({
  dailyUsd: 0,
  dailyDate: "",
  hourlyNarrations: 0,
  hourlyHour: "",
});

// ─── Internal helpers ────────────────────────────────────────────────

/** @param {number} ts */
function isoDay(ts) {
  return new Date(ts).toISOString().slice(0, 10); // "YYYY-MM-DD"
}

/** @param {number} ts */
function isoHour(ts) {
  return new Date(ts).toISOString().slice(0, 13); // "YYYY-MM-DDTHH"
}

/**
 * Apply day and hour rollover to `state` relative to `now`.
 * Returns a new state object; never mutates the input.
 *
 * @param {object} state
 * @param {number} now
 * @returns {object}
 */
function applyRollover(state, now) {
  const day = isoDay(now);
  const hour = isoHour(now);
  let next = { ...state };
  if (next.dailyDate !== day) {
    next = { ...next, dailyUsd: 0, dailyDate: day };
  }
  if (next.hourlyHour !== hour) {
    next = { ...next, hourlyNarrations: 0, hourlyHour: hour };
  }
  return next;
}

// ─── Pure functions ───────────────────────────────────────────────────

/**
 * Check whether a narration is allowed under the configured caps.
 *
 * Applies rollover before checking so stale state is handled transparently.
 * Fail-closed: any cap that is a finite number blocks when met or exceeded.
 *
 * @param {object} state                           Budget state from loadBudgetState().
 * @param {{ maxUsdPerDay?: number, maxNarrationsPerHour?: number }} caps
 * @param {number} [now=Date.now()]                Injection point for tests.
 * @returns {{ ok: boolean, reason?: string }}
 */
export function checkBudget(state, { maxUsdPerDay, maxNarrationsPerHour } = {}, now = Date.now()) {
  const s = applyRollover(state, now);

  if (typeof maxUsdPerDay === "number" && Number.isFinite(maxUsdPerDay) && s.dailyUsd >= maxUsdPerDay) {
    return {
      ok: false,
      reason: `daily USD cap exceeded (spent ${s.dailyUsd.toFixed(6)} >= limit ${maxUsdPerDay})`,
    };
  }

  if (
    typeof maxNarrationsPerHour === "number" &&
    Number.isFinite(maxNarrationsPerHour) &&
    s.hourlyNarrations >= maxNarrationsPerHour
  ) {
    return {
      ok: false,
      reason: `hourly narration cap exceeded (${s.hourlyNarrations} >= limit ${maxNarrationsPerHour})`,
    };
  }

  return { ok: true };
}

/**
 * Record a completed narration spend. Returns the updated state without
 * persisting — caller must call saveBudgetState() when ready to commit.
 *
 * Applies rollover before incrementing so the day/hour sentinels are always
 * current in the returned state.
 *
 * @param {object} state
 * @param {{ usd: number, timestamp?: number }} spend
 * @returns {object} New state with updated dailyUsd and hourlyNarrations.
 */
export function recordSpend(state, { usd, timestamp = Date.now() }) {
  const s = applyRollover(state, timestamp);
  return {
    ...s,
    dailyUsd: s.dailyUsd + (typeof usd === "number" && Number.isFinite(usd) ? usd : 0),
    hourlyNarrations: s.hourlyNarrations + 1,
  };
}

// ─── I/O helpers ──────────────────────────────────────────────────────

/**
 * Load the budget state from disk.
 *
 * If the file is missing or corrupt, returns DEFAULT_BUDGET_STATE with
 * current-day/hour sentinels (so rollover detection starts correctly).
 * Rollover is applied before returning so callers always receive a
 * state that is valid for the current moment.
 *
 * @param {{ cwd?: string, now?: number }} [opts]
 * @returns {object}
 */
export function loadBudgetState({ cwd = process.cwd(), now = Date.now() } = {}) {
  const stateFile = resolve(cwd, BUDGET_STATE_FILE);
  let raw = { ...DEFAULT_BUDGET_STATE };
  try {
    if (existsSync(stateFile)) {
      const parsed = JSON.parse(readFileSync(stateFile, "utf-8"));
      raw = { ...DEFAULT_BUDGET_STATE, ...parsed };
    }
  } catch {
    /* corrupt file — start from defaults */
  }
  return applyRollover(raw, now);
}

/**
 * Atomically persist the budget state to disk.
 *
 * Uses write-to-tmp + rename to avoid partial-write corruption.
 * Creates the containing directory if it does not yet exist.
 *
 * @param {object} state
 * @param {{ cwd?: string }} [opts]
 */
export function saveBudgetState(state, { cwd = process.cwd() } = {}) {
  const stateFile = resolve(cwd, BUDGET_STATE_FILE);
  const dir = dirname(stateFile);
  mkdirSync(dir, { recursive: true });
  const tmp = `${stateFile}.${randomBytes(4).toString("hex")}.tmp`;
  writeFileSync(tmp, JSON.stringify(state, null, 2) + "\n", "utf-8");
  renameSync(tmp, stateFile);
}

/**
 * Observer Loop — hub subscription + event-batch buffer (Phase-39, Slice 5).
 *
 * Connects to the Plan Forge hub WebSocket using `.forge/server-ports.json`
 * discovery (mirrors runWatchLive port-discovery path). Buffers incoming
 * hub events in memory and flushes to an `onBatch` callback every
 * `batchWindowMs` milliseconds.
 *
 * Handles WebSocket disconnect with bounded exponential backoff
 * (MAX_RECONNECT_RETRIES = 3). After all retries are exhausted the observer
 * halts and surfaces the error via `getStatus().lastError`.
 *
 * The `observer:narration` outbound event type is reserved for Slice 7 — no
 * LLM call happens here yet.
 *
 * @module forge-master/observer-loop
 */

import WebSocket from "ws";
import { existsSync, readFileSync, writeFileSync, mkdirSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";
import { spawn } from "node:child_process";

const __filename = fileURLToPath(import.meta.url);

// ─── Constants ────────────────────────────────────────────────────────

export const DEFAULT_BATCH_WINDOW_MS = 60_000;
export const MAX_RECONNECT_RETRIES = 3;
const RECONNECT_BASE_MS = 1_000;

/**
 * Hub event types the observer subscribes to.
 * Extend here when new event types are added to the hub.
 */
export const OBSERVER_SUBSCRIBED_EVENTS = new Set([
  "slice-started",
  "slice-completed",
  "slice-failed",
  "slice-retrying",
  "run-started",
  "run-completed",
  "run-aborted",
  "gate-passed",
  "gate-failed",
  "cost-accrued",
  "ask-telemetry",
]);

/**
 * Reserved outbound event type for Slice 7 narration emission.
 * Defined here so Slice 7 can import the constant without hard-coding the string.
 */
export const OBSERVER_NARRATION_EVENT_TYPE = "observer:narration";

// ─── Observer daemon PID helpers ─────────────────────────────────────

/**
 * The filename used for the observer daemon PID file (relative to .forge/).
 */
export const OBSERVER_PID_FILE = "forge-master-observer.pid";

/**
 * Resolve the full path to the observer PID file.
 *
 * @param {string} cwd  Project root.
 * @returns {string}
 */
export function getObserverPidPath(cwd) {
  return resolve(cwd, ".forge", OBSERVER_PID_FILE);
}

/**
 * Return the running status of the observer daemon by inspecting the PID file.
 *
 * @param {{ cwd?: string }} [opts]
 * @returns {Promise<{ running: boolean, pid?: number }>}
 */
export async function getObserverStatus(opts = {}) {
  const cwd = opts.cwd ?? process.cwd();
  const pidFile = getObserverPidPath(cwd);
  if (!existsSync(pidFile)) return { running: false };
  const pidStr = readFileSync(pidFile, "utf-8").trim();
  if (!pidStr) return { running: false };
  const pid = parseInt(pidStr, 10);
  if (!Number.isFinite(pid)) return { running: false };
  try {
    process.kill(pid, 0); // existence check — throws if process not found
    return { running: true, pid };
  } catch {
    return { running: false };
  }
}

/**
 * Start the observer as a detached background daemon.
 * Writes the daemon PID to `.forge/forge-master-observer.pid`.
 *
 * @param {{ cwd?: string }} [opts]
 */
export async function startObserverDaemon(opts = {}) {
  const cwd = opts.cwd ?? process.cwd();
  const pidFile = getObserverPidPath(cwd);

  const current = await getObserverStatus({ cwd });
  if (current.running) {
    console.log(`forge-master observer already running (PID ${current.pid})`);
    return;
  }

  const forgeDir = resolve(cwd, ".forge");
  if (!existsSync(forgeDir)) mkdirSync(forgeDir, { recursive: true });

  const child = spawn(process.execPath, [__filename, "daemon"], {
    detached: true,
    stdio: ["ignore", "ignore", "ignore"],
    cwd,
  });

  writeFileSync(pidFile, String(child.pid));
  child.unref();
  console.log(`forge-master observer started (PID ${child.pid})`);
}

/**
 * Stop the running observer daemon.
 *
 * @param {{ cwd?: string }} [opts]
 */
export async function stopObserverDaemon(opts = {}) {
  const cwd = opts.cwd ?? process.cwd();
  const pidFile = getObserverPidPath(cwd);
  if (!existsSync(pidFile)) { console.log("forge-master observer is not running"); return; }
  const pidStr = readFileSync(pidFile, "utf-8").trim();
  if (!pidStr) { console.log("forge-master observer is not running"); return; }
  const pid = parseInt(pidStr, 10);
  try { process.kill(pid, "SIGTERM"); } catch { /* already dead */ }
  try { writeFileSync(pidFile, ""); } catch { /* non-fatal */ }
  console.log(`forge-master observer stopped (PID ${pid})`);
}

// ─── Port discovery ──────────────────────────────────────────────────

/**
 * Read the active hub WS port from .forge/server-ports.json.
 * Mirrors the discovery path used by runWatchLive.
 *
 * @param {string} cwd
 * @returns {number|null}
 */
function readHubPort(cwd) {
  const portsPath = resolve(cwd, ".forge", "server-ports.json");
  try {
    if (existsSync(portsPath)) {
      const parsed = JSON.parse(readFileSync(portsPath, "utf-8"));
      return typeof parsed.ws === "number" ? parsed.ws : null;
    }
  } catch { /* best-effort */ }
  return null;
}

// ─── startObserver ───────────────────────────────────────────────────

/**
 * Start the observer: connect to hub, buffer events, flush every `batchWindowMs`.
 *
 * @param {object} opts
 * @param {number}   [opts.batchWindowMs=60000]  Flush interval in ms.
 * @param {Function}  opts.onBatch               async (events: object[]) → void — called on each flush.
 * @param {string}   [opts.cwd=process.cwd()]    Project root for .forge/server-ports.json discovery.
 * @param {number|null} [opts.wsPort=null]        Explicit WS port (overrides .forge/server-ports.json).
 * @param {Function} [opts._wsFactory]            Injectable WebSocket constructor for testing.
 *                                                Signature: (url: string) → WebSocket-like object.
 * @returns {{ stop: Function, getStatus: Function }}
 */
function createObserverState(batchWindowMs) {
  return {
    stopped: false,
    connected: false,
    ws: null,
    retryCount: 0,
    retryTimer: null,
    flushTimer: null,
    buffer: [],
    lastError: null,
    lastFlushAt: null,
    totalEventsReceived: 0,
    totalBatchesFlushed: 0,
    batchWindowMs,
  };
}

function resolveObserverPort({ cwd, wsPort }) {
  if (typeof wsPort === "number") return wsPort;
  return readHubPort(cwd);
}

function createBatchController({ state, onBatch }) {
  function flushBuffer() {
    state.lastFlushAt = new Date().toISOString();
    if (state.buffer.length === 0) return;
    const batch = state.buffer.splice(0);
    state.totalBatchesFlushed++;
    try {
      const result = onBatch(batch);
      if (result && typeof result.catch === "function") {
        result.catch((err) => {
          console.error(`[observer-loop] onBatch error: ${err.message}`);
        });
      }
    } catch (err) {
      console.error(`[observer-loop] onBatch error: ${err.message}`);
    }
  }

  function scheduleFlush() {
    if (state.flushTimer) clearInterval(state.flushTimer);
    state.flushTimer = setInterval(() => {
      if (!state.stopped) flushBuffer();
    }, state.batchWindowMs);
  }

  return { flushBuffer, scheduleFlush };
}

function createConnectionController({ state, cwd, wsPort, wsFactory }) {
  function scheduleReconnect() {
    if (state.stopped) return;
    if (state.retryCount >= MAX_RECONNECT_RETRIES) {
      state.lastError = `max retries (${MAX_RECONNECT_RETRIES}) exceeded — observer halted`;
      console.error(`[observer-loop] ${state.lastError}`);
      return;
    }
    const delay = RECONNECT_BASE_MS * Math.pow(2, state.retryCount);
    state.retryCount++;
    state.retryTimer = setTimeout(() => {
      if (!state.stopped) connect();
    }, delay);
  }

  function connect() {
    if (state.stopped) return;
    const port = resolveObserverPort({ cwd, wsPort });
    if (!port) {
      state.lastError = "hub port not found — hub may not be running";
      console.error(`[observer-loop] ${state.lastError}`);
      scheduleReconnect();
      return;
    }

    const url = `ws://127.0.0.1:${port}`;
    try {
      state.ws = wsFactory(url);
      state.ws.on("open", () => {
        state.connected = true;
        state.retryCount = 0;
        state.lastError = null;
        console.error(`[observer-loop] connected to hub at ${url}`);
      });
      state.ws.on("message", (data) => {
        try {
          const event = JSON.parse(data.toString());
          if (event.type === "connected") return;
          if (OBSERVER_SUBSCRIBED_EVENTS.has(event.type)) {
            state.buffer.push(event);
            state.totalEventsReceived++;
          }
        } catch { /* ignore malformed messages */ }
      });
      state.ws.on("error", (err) => {
        state.connected = false;
        state.lastError = err?.message ?? String(err);
        if (!state.stopped) {
          console.error(`[observer-loop] WS error: ${state.lastError}`);
          scheduleReconnect();
        }
      });
      state.ws.on("close", () => {
        state.connected = false;
        if (!state.stopped) scheduleReconnect();
      });
    } catch (err) {
      state.lastError = err.message;
      console.error(`[observer-loop] connect failed: ${err.message}`);
      scheduleReconnect();
    }
  }

  return { connect };
}

function createObserverApi({ state, flushBuffer }) {
  return {
    stop() {
      state.stopped = true;
      if (state.retryTimer) {
        clearTimeout(state.retryTimer);
        state.retryTimer = null;
      }
      if (state.flushTimer) {
        clearInterval(state.flushTimer);
        state.flushTimer = null;
      }
      flushBuffer();
      if (state.ws) {
        try { state.ws.close(); } catch { /* best-effort */ }
      }
      state.connected = false;
    },
    getStatus() {
      return {
        connected: state.connected,
        stopped: state.stopped,
        retryCount: state.retryCount,
        bufferSize: state.buffer.length,
        lastError: state.lastError,
        lastFlushAt: state.lastFlushAt,
        totalEventsReceived: state.totalEventsReceived,
        totalBatchesFlushed: state.totalBatchesFlushed,
        batchWindowMs: state.batchWindowMs,
      };
    },
  };
}

export function startObserver(opts = {}) {
  const {
    batchWindowMs = DEFAULT_BATCH_WINDOW_MS,
    onBatch,
    cwd = process.cwd(),
    wsPort = null,
    _wsFactory = (url) => new WebSocket(url),
  } = opts;

  if (typeof onBatch !== "function") {
    throw new Error("startObserver: onBatch must be a function");
  }

  const state = createObserverState(batchWindowMs);
  const { flushBuffer, scheduleFlush } = createBatchController({ state, onBatch });
  const { connect } = createConnectionController({
    state,
    cwd,
    wsPort,
    wsFactory: _wsFactory,
  });

  connect();
  scheduleFlush();
  return createObserverApi({ state, flushBuffer });
}

// ─── CLI entry point ─────────────────────────────────────────────────

const isMain = process.argv[1] && resolve(process.argv[1]) === resolve(__filename);

if (isMain) {
  const [,, cliCmd] = process.argv;

  if (cliCmd === "daemon") {
    // Running as the observer daemon — keep process alive until killed.
    // The onBatch callback is intentionally a no-op here: narration is
    // handled by Slice 7's observer-reasoning layer.
    startObserver({
      onBatch: () => {},
    });
    // Keep the event loop alive; the observer's internal timers do this
    // automatically, but guard against empty environments.
    setInterval(() => {}, 60_000);
  } else if (cliCmd && ["start", "stop", "status"].includes(cliCmd)) {
    const cwd = process.cwd();
    if (cliCmd === "start") {
      startObserverDaemon({ cwd }).catch(err => { console.error(err.message); process.exit(1); });
    } else if (cliCmd === "stop") {
      stopObserverDaemon({ cwd }).catch(err => { console.error(err.message); process.exit(1); });
    } else {
      getObserverStatus({ cwd }).then(st => {
        if (st.running) {
          console.log(`forge-master observer running (PID ${st.pid})`);
        } else {
          console.log("forge-master observer is not running");
        }
      }).catch(err => { console.error(err.message); process.exit(1); });
    }
  } else {
    console.error("Usage: node observer-loop.mjs <start|stop|status|daemon>");
    process.exit(1);
  }
}

/**
 * Observer prompt — "narrate notable patterns" (Phase-39, Slice 7).
 *
 * Distinct from runTurn()'s Q&A prompt: shorter, event-batch-aware,
 * narrator-focused. No principles block, no context_block — the hub
 * event batch IS the context.
 *
 * Exports:
 *   OBSERVER_SYSTEM_PROMPT  — static system prompt string
 *   formatBatchMessage(batch) → string
 *   buildObserverPrompt(batch) → { systemPrompt, userMessage }
 *
 * @module forge-master/observer-prompt
 */

export const OBSERVER_SYSTEM_PROMPT = `\
You are the **Plan Forge Observer**, a lightweight narration agent that monitors live pipeline events.

## Your job

You receive a batch of hub events from an active Plan Forge run. Narrate notable patterns in \
2–5 sentences of plain prose, directed at a developer monitoring their pipeline.

Say **"N routine events — nothing notable."** when the batch contains no signal worth surfacing.

## Rules

- Be concise. 200 words maximum.
- Focus on patterns, not individual events. One gate failure in 20 events is noise; five in a row is a pattern.
- Never fabricate data. Only narrate what the event batch shows.
- Do not give advice unless a clear, actionable observation exists \
(e.g., a recurring gate failure on the same slice).
- You may call a tool when you genuinely need external context to interpret an anomaly, \
but prefer narrating from the batch alone.
- You are strictly read-only. Never call write tools.
`;

/**
 * Build a compact, LLM-friendly description of a hub event batch.
 *
 * Each event line includes: timestamp, type, and selected notable fields
 * (sliceId, planId, costUSD, error, retryCount). Unknown fields are omitted
 * to keep the message bounded.
 *
 * @param {object[]} batch
 * @returns {string}
 */
export function formatBatchMessage(batch) {
  if (!Array.isArray(batch) || batch.length === 0) {
    return "Batch: 0 events — nothing to narrate.";
  }

  const lines = batch.map((e, i) => {
    const ts = e.timestamp
      ? `[${String(e.timestamp).slice(0, 24)}]`
      : `[event-${i + 1}]`;
    const type = e.type || "unknown";
    const extras = [];
    if (e.sliceId != null) extras.push(`slice: ${e.sliceId}`);
    if (e.planId != null) extras.push(`plan: ${e.planId}`);
    if (e.costUSD != null) extras.push(`cost: $${Number(e.costUSD).toFixed(6)}`);
    if (e.error) extras.push(`error: ${String(e.error).slice(0, 80)}`);
    if (e.retryCount != null) extras.push(`retry: ${e.retryCount}`);
    return `${ts} ${type}${extras.length ? ` (${extras.join(", ")})` : ""}`;
  });

  return `Batch: ${batch.length} hub event${batch.length === 1 ? "" : "s"}\n\n${lines.join("\n")}`;
}

/**
 * Build the full observer prompt pair for a model narration turn.
 *
 * @param {object[]} batch  Array of hub events from the observer loop.
 * @returns {{ systemPrompt: string, userMessage: string }}
 */
export function buildObserverPrompt(batch) {
  return {
    systemPrompt: OBSERVER_SYSTEM_PROMPT,
    userMessage: formatBatchMessage(batch),
  };
}

/**
 * Plan Forge — Forge-Master Session Persistence (Phase-28, Slice 6).
 *
 * Manages per-session conversation history in brain L1 and auto-summarizes
 * to L2 digests when a session exceeds 20 turns.
 *
 * Key scheme (from plan):
 *   L1:  session.forgemaster.<sessionId>.history
 *   L2:  project.forgemaster.digests.<YYYY-MM-DD>
 *
 * Uses `sessionId` as the brain `runId` for L1 isolation.
 *
 * Exports:
 *   - ensureSessionId(sessionId?) → string
 *   - appendTurn({sessionId, turn}, deps) → {turnCount, sessionId}
 *   - summarizeIfNeeded({sessionId}, deps) → {summarized, ...}
 *   - SUMMARIZE_THRESHOLD, SUMMARIZE_COUNT
 *
 * @module forge-master/persistence
 */

import { randomUUID } from "node:crypto";

// ─── Constants ──────────────────────────────────────────────────────

export const SUMMARIZE_THRESHOLD = 20;
export const SUMMARIZE_COUNT = 10;

// ─── Per-Session Mutex ──────────────────────────────────────────────

const _locks = new Map();

function acquireLock(sessionId) {
  if (!_locks.has(sessionId)) {
    _locks.set(sessionId, Promise.resolve());
  }
  let release;
  const next = new Promise((resolve) => { release = resolve; });
  const prev = _locks.get(sessionId);
  _locks.set(sessionId, next);
  return prev.then(() => release);
}

// For testing: clear all locks
export function _resetLocks() {
  _locks.clear();
}

// ─── Session ID ─────────────────────────────────────────────────────

/**
 * Ensure a valid sessionId exists. Returns the input if it is a
 * non-empty string, otherwise generates a fresh UUID.
 *
 * @param {string|null|undefined} sessionId
 * @returns {string}
 */
export function ensureSessionId(sessionId) {
  if (sessionId && typeof sessionId === "string" && sessionId.trim().length > 0) {
    return sessionId;
  }
  return randomUUID();
}

// ─── Brain Key Helpers ──────────────────────────────────────────────

function historyKey(sessionId) {
  return `session.forgemaster.${sessionId}.history`;
}

function digestKey(dateStr) {
  return `project.forgemaster.digests.${dateStr}`;
}

// ─── Append Turn ────────────────────────────────────────────────────

/**
 * Append a turn record to session history in brain L1.
 *
 * The turn object should contain `{role, content, toolCalls?}`.
 * A timestamp is added automatically if not present.
 *
 * @param {{sessionId: string, turn: object}} input
 * @param {{recall: Function, remember: Function, cwd?: string}} deps
 * @returns {Promise<{turnCount: number, sessionId: string}>}
 */
export async function appendTurn({ sessionId, turn }, deps = {}) {
  if (!sessionId) throw new Error("appendTurn requires a sessionId");
  if (!turn || typeof turn !== "object") throw new Error("appendTurn requires a turn object");

  const key = historyKey(sessionId);
  const release = await acquireLock(sessionId);

  try {
    let history = [];
    try {
      const existing = await deps.recall(key, { runId: sessionId });
      if (Array.isArray(existing)) history = existing;
    } catch { /* empty history on first call */ }

    const record = {
      ...turn,
      timestamp: turn.timestamp || new Date().toISOString(),
    };
    history.push(record);

    deps.remember(key, history, { runId: sessionId });

    return { turnCount: history.length, sessionId };
  } finally {
    release();
  }
}

// ─── Auto-Summarization ─────────────────────────────────────────────

/**
 * If the session history exceeds SUMMARIZE_THRESHOLD turns, move the
 * oldest SUMMARIZE_COUNT turns into an L2 digest and trim L1.
 *
 * Digest key: `project.forgemaster.digests.<YYYY-MM-DD>`
 *
 * @param {{sessionId: string}} input
 * @param {{recall: Function, remember: Function, cwd?: string}} deps
 * @returns {Promise<{summarized: boolean, summarizedCount?: number, remaining?: number, turnCount?: number}>}
 */
export async function summarizeIfNeeded({ sessionId }, deps = {}) {
  if (!sessionId) return { summarized: false };

  const key = historyKey(sessionId);
  const release = await acquireLock(sessionId);

  try {
    let history = [];
    try {
      const existing = await deps.recall(key, { runId: sessionId });
      if (Array.isArray(existing)) history = existing;
    } catch {
      return { summarized: false };
    }

    if (history.length <= SUMMARIZE_THRESHOLD) {
      return { summarized: false, turnCount: history.length };
    }

    const toSummarize = history.slice(0, SUMMARIZE_COUNT);
    const remaining = history.slice(SUMMARIZE_COUNT);

    // Build digest entry and write to L2
    const dateStr = new Date().toISOString().slice(0, 10);
    const dKey = digestKey(dateStr);

    let existingDigests = [];
    try {
      const d = await deps.recall(dKey, { scope: "project" });
      if (Array.isArray(d)) existingDigests = d;
    } catch { /* fresh digest */ }

    existingDigests.push({
      sessionId,
      summarizedAt: new Date().toISOString(),
      turnCount: toSummarize.length,
      turns: toSummarize,
    });

    deps.remember(dKey, existingDigests, { scope: "project" });

    // Update L1 with remaining turns only
    deps.remember(key, remaining, { runId: sessionId });

    return {
      summarized: true,
      summarizedCount: toSummarize.length,
      remaining: remaining.length,
    };
  } finally {
    release();
  }
}

/**
 * Plan Forge — Forge-Master Plan Executor (Phase-38.4, Slice 2).
 *
 * Executes a plan produced by the planner module. Steps are grouped
 * into topological batches — steps with no pending dependencies run
 * in parallel via `Promise.all`; steps with `dependsOn` wait until
 * all named predecessors complete.
 *
 * A hard 30 000 ms timeout cancels remaining steps.
 * A single step failure does NOT abort independent branches — only
 * dependent steps are short-circuited with an error marker.
 *
 * Exports:
 *   - executePlan(plan, deps) → { results, totalDurationMs }
 *   - TIMEOUT_MS — hard timeout constant (30 000)
 *   - topoSort(steps) → string[][] — topological batch grouping
 *
 * @module forge-master/plan-executor
 */

// ─── Constants ──────────────────────────────────────────────────────

/** Hard timeout for the entire plan execution. */
export const TIMEOUT_MS = 30_000;

// ─── Topological sort ───────────────────────────────────────────────

/**
 * Group steps into topological batches using Kahn's algorithm.
 * Each batch is a list of step IDs whose dependencies are satisfied
 * by all preceding batches.
 *
 * @param {import("./planner.mjs").PlanStep[]} steps
 * @returns {string[][]} Ordered batches of step IDs.
 * @throws {Error} If a dependency cycle is detected.
 */
export function topoSort(steps) {
  const ids = new Set(steps.map((s) => s.id));
  const inDegree = new Map();
  const dependents = new Map(); // parent → children

  for (const s of steps) {
    inDegree.set(s.id, 0);
    dependents.set(s.id, []);
  }

  for (const s of steps) {
    if (!s.dependsOn) continue;
    for (const dep of s.dependsOn) {
      if (!ids.has(dep)) continue; // skip unknown refs
      inDegree.set(s.id, (inDegree.get(s.id) ?? 0) + 1);
      dependents.get(dep).push(s.id);
    }
  }

  const batches = [];
  const remaining = new Set(ids);

  while (remaining.size > 0) {
    const batch = [];
    for (const id of remaining) {
      if (inDegree.get(id) === 0) batch.push(id);
    }

    if (batch.length === 0) {
      throw new Error("Dependency cycle detected among steps: " +
        [...remaining].join(", "));
    }

    batches.push(batch);
    for (const id of batch) {
      remaining.delete(id);
      for (const child of dependents.get(id)) {
        inDegree.set(child, inDegree.get(child) - 1);
      }
    }
  }

  return batches;
}

// ─── Executor ───────────────────────────────────────────────────────

/**
 * Execute a plan's steps respecting dependency order, parallelism,
 * error isolation, and a hard timeout.
 *
 * @param {{ steps: import("./planner.mjs").PlanStep[] }} plan
 * @param {{
 *   dispatch: (step: import("./planner.mjs").PlanStep, priorResults: Map<string, any>) => Promise<any>,
 * }} deps
 * @returns {Promise<{
 *   results: Array<{ step: import("./planner.mjs").PlanStep, output: any, error?: string }>,
 *   totalDurationMs: number,
 * }>}
 */
export async function executePlan(plan, deps) {
  const t0 = Date.now();

  if (!plan?.steps?.length) {
    return { results: [], totalDurationMs: Date.now() - t0 };
  }

  const stepMap = new Map(plan.steps.map((s) => [s.id, s]));
  const resultMap = new Map();   // stepId → { step, output, error? }
  const outputMap = new Map();   // stepId → raw output (for injection)

  let batches;
  try {
    batches = topoSort(plan.steps);
  } catch (err) {
    // Cycle → mark all steps as errored
    const results = plan.steps.map((step) => ({
      step,
      output: null,
      error: err.message,
    }));
    return { results, totalDurationMs: Date.now() - t0 };
  }

  let timedOut = false;

  for (const batch of batches) {
    if (timedOut) {
      for (const id of batch) {
        const step = stepMap.get(id);
        resultMap.set(id, { step, output: null, error: "timeout" });
      }
      continue;
    }

    const elapsed = Date.now() - t0;
    const remaining = TIMEOUT_MS - elapsed;

    if (remaining <= 0) {
      timedOut = true;
      for (const id of batch) {
        const step = stepMap.get(id);
        resultMap.set(id, { step, output: null, error: "timeout" });
      }
      continue;
    }

    const batchPromises = batch.map(async (id) => {
      const step = stepMap.get(id);

      // Check if any dependency failed — short-circuit
      if (step.dependsOn) {
        for (const dep of step.dependsOn) {
          const depResult = resultMap.get(dep);
          if (depResult?.error) {
            resultMap.set(id, {
              step,
              output: null,
              error: `dependency-failed: ${dep}`,
            });
            return;
          }
        }
      }

      try {
        const output = await deps.dispatch(step, outputMap);
        resultMap.set(id, { step, output });
        outputMap.set(id, output);
      } catch (err) {
        resultMap.set(id, {
          step,
          output: null,
          error: err.message || String(err),
        });
      }
    });

    // Race the batch against the remaining timeout
    const timeoutSentinel = Symbol("timeout");
    const timer = new Promise((resolve) =>
      setTimeout(() => resolve(timeoutSentinel), remaining),
    );

    const raceResult = await Promise.race([
      Promise.all(batchPromises).then(() => "done"),
      timer,
    ]);

    if (raceResult === timeoutSentinel) {
      timedOut = true;
      // Mark any steps in this batch without results as timed out
      for (const id of batch) {
        if (!resultMap.has(id)) {
          const step = stepMap.get(id);
          resultMap.set(id, { step, output: null, error: "timeout" });
        }
      }
    }
  }

  // Mark any remaining steps (from subsequent batches after timeout)
  for (const step of plan.steps) {
    if (!resultMap.has(step.id)) {
      resultMap.set(step.id, { step, output: null, error: "timeout" });
    }
  }

  // Preserve original step order
  const results = plan.steps.map((s) => resultMap.get(s.id));
  const totalDurationMs = Date.now() - t0;

  return { results, totalDurationMs };
}

/**
 * Plan Forge — Forge-Master Planner (Phase-38.4, Slice 1).
 *
 * Decomposes complex user queries into ordered read-only tool-call
 * steps before execution. Simple queries are short-circuited via
 * skip heuristics (zero-cost, no model call).
 *
 * Exports:
 *   - plan({userMessage, classification, lane, allowedTools, deps}) → PlanResult
 *   - SKIP_REASONS — frozen map of canonical skip-reason strings
 *   - MAX_STEPS — hard cap on planned steps (5)
 *
 * @module forge-master/planner
 */

import { USAGE_HINTS } from "./allowlist.mjs";

// ─── Constants ──────────────────────────────────────────────────────

/** Hard cap: planner never returns more than 5 steps. */
export const MAX_STEPS = 5;

/** Canonical skip-reason strings. */
export const SKIP_REASONS = Object.freeze({
  OFFTOPIC:       "lane=offtopic",
  BUILD:          "lane=build",
  NO_TOOLS:       "no-allowed-tools",
  SINGLE_TOOL:    "single-tool-obvious",
  PLANNER_EMPTY:  "planner-empty",
  PLANNER_ERROR:  "planner-error",
});

/** Lanes where the planner must never be invoked. */
const SKIP_LANES = new Set(["offtopic", "build"]);

// ─── Types (JSDoc) ──────────────────────────────────────────────────

/**
 * A single planned tool-call step.
 *
 * @typedef {Object} PlanStep
 * @property {string}   id         - Canonical step ID (e.g. "step-0").
 * @property {string}   tool       - Tool name (must be in allowedTools).
 * @property {Object}   args       - Arguments to pass to the tool.
 * @property {string}   rationale  - Why this step is needed.
 * @property {string[]} [dependsOn] - IDs of steps that must complete first.
 */

/**
 * Result returned by the planner.
 *
 * @typedef {Object} PlanResult
 * @property {PlanStep[]} steps      - Ordered list of tool-call steps (0–5).
 * @property {string}     [skipReason] - Present when planning was skipped.
 */

// ─── Skip result helper ─────────────────────────────────────────────

/** @returns {PlanResult} */
function skip(reason) {
  return { steps: [], skipReason: reason };
}

// ─── Step validation ────────────────────────────────────────────────

/**
 * Validate and normalize a raw step object from the model.
 * Returns null if the step is malformed or references a disallowed tool.
 *
 * @param {*} raw
 * @param {Set<string>} allowedSet
 * @returns {Omit<PlanStep, "id"> | null}
 */
function validateStep(raw, allowedSet) {
  if (!raw || typeof raw !== "object") return null;
  if (typeof raw.tool !== "string" || !raw.tool.trim()) return null;

  const tool = raw.tool.trim();
  if (!allowedSet.has(tool)) return null;

  const args = raw.args && typeof raw.args === "object" && !Array.isArray(raw.args)
    ? raw.args
    : {};

  const rationale = typeof raw.rationale === "string" ? raw.rationale : "";

  // dependsOn: accept string array only; will be re-mapped after ID assignment
  let dependsOn;
  if (Array.isArray(raw.dependsOn)) {
    dependsOn = raw.dependsOn.filter((d) => typeof d === "string");
    if (dependsOn.length === 0) dependsOn = undefined;
  }

  return { tool, args, rationale, dependsOn };
}

/**
 * Assign canonical step IDs and remap/prune dependsOn references.
 *
 * @param {Array<Omit<PlanStep, "id"> & { dependsOn?: string[] }>} validSteps
 * @param {string[]} originalIds - The raw IDs the model used (positional)
 * @returns {PlanStep[]}
 */
function assignIds(validSteps, originalIds) {
  // Build a mapping from original (model-supplied) ID → new canonical ID
  const idMap = new Map();
  for (let i = 0; i < validSteps.length; i++) {
    const origId = originalIds[i];
    const canonId = `step-${i}`;
    if (origId != null) idMap.set(String(origId), canonId);
    // Also map positional index strings
    idMap.set(String(i), canonId);
  }

  const canonicalIdSet = new Set(
    validSteps.map((_, i) => `step-${i}`),
  );

  return validSteps.map((s, i) => {
    const id = `step-${i}`;

    let dependsOn;
    if (s.dependsOn) {
      dependsOn = s.dependsOn
        .map((ref) => idMap.get(String(ref)) ?? ref)
        .filter((ref) => canonicalIdSet.has(ref) && ref !== id); // drop self-refs
      if (dependsOn.length === 0) dependsOn = undefined;
    }

    return { id, tool: s.tool, args: s.args, rationale: s.rationale, ...(dependsOn ? { dependsOn } : {}) };
  });
}

// ─── Planner system prompt ──────────────────────────────────────────

/**
 * Build the system prompt for the planning model.
 *
 * @param {string[]} allowedTools
 * @returns {string}
 */
function buildPlannerPrompt(allowedTools) {
  const toolDescriptions = allowedTools.map((t) => {
    const hint = USAGE_HINTS[t] || `Plan Forge tool: ${t}`;
    return `- ${t}: ${hint}`;
  }).join("\n");

  return `You are a query planner for Plan Forge's Forge-Master assistant.
Your job is to decompose a user query into an ordered list of tool calls.

Rules:
- Return a JSON array of step objects. Each step: {"tool": "<name>", "args": {}, "rationale": "<why>", "dependsOn": []}
- Use ONLY tools from the allowed list below.
- Maximum 5 steps.
- dependsOn is optional: list step indices (0-based) that must complete before this step.
- If the query is simple and needs only 1 tool, return a single-step plan.
- Return an empty array [] if no tools are relevant.

Allowed tools:
${toolDescriptions}

Respond with ONLY valid JSON — no markdown, no explanation.`;
}

// ─── Main planner function ──────────────────────────────────────────

/**
 * Plan tool-call steps for a user query.
 *
 * Skip heuristics (zero-cost, no model call):
 *   1. lane is "offtopic" or "build" → skip
 *   2. allowedTools is empty → skip
 *   3. allowedTools has exactly 1 tool → single-tool-obvious
 *
 * Otherwise, calls `deps.callPlannerModel` to decompose the query.
 *
 * @param {{
 *   userMessage: string,
 *   classification: { lane: string, confidence: string, suggestedTools?: string[] },
 *   lane: string,
 *   allowedTools: string[],
 *   deps: {
 *     callPlannerModel: (opts: { systemPrompt: string, userMessage: string }) => Promise<string>,
 *   },
 * }} opts
 * @returns {Promise<PlanResult>}
 */
export async function plan({ userMessage, classification, lane, allowedTools, deps }) {
  // ── Skip heuristics ───────────────────────────────────────────────

  // 1. Disallowed lanes
  if (SKIP_LANES.has(lane)) {
    return skip(lane === "offtopic" ? SKIP_REASONS.OFFTOPIC : SKIP_REASONS.BUILD);
  }

  // 2. No tools available
  if (!Array.isArray(allowedTools) || allowedTools.length === 0) {
    return skip(SKIP_REASONS.NO_TOOLS);
  }

  // 3. Single allowed tool — no need for decomposition
  const uniqueTools = [...new Set(allowedTools.filter((t) => typeof t === "string" && t.trim()))];
  if (uniqueTools.length <= 1) {
    return skip(SKIP_REASONS.SINGLE_TOOL);
  }

  // ── Model call ────────────────────────────────────────────────────

  if (!deps?.callPlannerModel || typeof deps.callPlannerModel !== "function") {
    return skip(SKIP_REASONS.PLANNER_ERROR);
  }

  let rawResponse;
  try {
    const systemPrompt = buildPlannerPrompt(uniqueTools);
    rawResponse = await deps.callPlannerModel({ systemPrompt, userMessage });
  } catch {
    return skip(SKIP_REASONS.PLANNER_ERROR);
  }

  // ── Parse response ────────────────────────────────────────────────

  let parsed;
  try {
    if (typeof rawResponse !== "string") {
      return skip(SKIP_REASONS.PLANNER_ERROR);
    }
    // Strip markdown fences if present
    const cleaned = rawResponse.replace(/^```(?:json)?\s*/i, "").replace(/\s*```\s*$/, "").trim();
    parsed = JSON.parse(cleaned);
  } catch {
    return skip(SKIP_REASONS.PLANNER_ERROR);
  }

  if (!Array.isArray(parsed)) {
    return skip(SKIP_REASONS.PLANNER_ERROR);
  }

  // ── Validate, filter, cap ─────────────────────────────────────────

  const allowedSet = new Set(uniqueTools);
  const originalIds = [];
  const validSteps = [];

  for (const raw of parsed) {
    // Capture original ID for dep remapping (index-based or explicit)
    originalIds.push(raw?.id ?? String(originalIds.length));
    const step = validateStep(raw, allowedSet);
    if (step) validSteps.push(step);
  }

  // Cap to MAX_STEPS after filtering
  const capped = validSteps.slice(0, MAX_STEPS);

  if (capped.length === 0) {
    return skip(SKIP_REASONS.PLANNER_EMPTY);
  }

  // Build original ID list for just the capped steps (positional)
  const cappedOriginalIds = originalIds.slice(0, originalIds.length).slice(0, capped.length);
  const steps = assignIds(capped, cappedOriginalIds);

  return { steps };
}

/**
 * Tests for github-copilot-tools.mjs (Phase-33, Slice 1).
 *
 * Uses vi.stubGlobal("fetch", ...) with fixture-backed responses.
 * Mocks node:child_process to prevent real `gh` subprocess invocations.
