    expect(result.type).toBe("rate_limited");
    expect(result.retryAfter).toBe("60");
    expect(typeof result.raw).toBe("string");
  });

  it("≥500 → throws an error", async () => {
    vi.stubGlobal("fetch", makeFetch(500, { error: "internal" }));
    await expect(
      sendTurn({ messages: [{ role: "user", content: "hi" }], tools: [], model: "gpt-4o" }),
    ).rejects.toThrow("GitHub Copilot API error 500");
  });
});

/**
 * Plan Forge — Forge-Master Anthropic Tool-Use Adapter (Phase-28, Slice 5).
 *
 * Translates between the reasoning loop's generic interface and the
 * Anthropic Messages API tool-use format.
 *
 * Anthropic specifics:
 *   - POST /v1/messages
 *   - Header: x-api-key, anthropic-version
 *   - Tools use `input_schema` (JSON Schema)
 *   - Response content blocks: {type:"text"} or {type:"tool_use"}
 *   - Tool results: {role:"user", content:[{type:"tool_result", ...}]}
 *
 * @module forge-master/providers/anthropic-tools
 */

const ANTHROPIC_VERSION = "2023-06-01";
const DEFAULT_BASE_URL = "https://api.anthropic.com/v1";
const DEFAULT_MAX_TOKENS = 4096;

/**
 * Build Anthropic-format tool definitions from generic tool schemas.
 * @param {Array<{name, description, parameters?}>} tools
 * @returns {Array<object>}
 */
export function buildAnthropicTools(tools) {
  return tools.map((t) => ({
    name: t.name,
    description: t.description || "",
    input_schema: t.parameters || { type: "object", properties: {} },
  }));
}

/**
 * Convert generic messages to Anthropic format.
 * Separates out system messages (Anthropic uses a top-level `system` param).
 *
 * @param {Array<{role, content, toolCalls?, toolCallId?}>} messages
 * @returns {{ system: string, messages: Array<object> }}
 */
export function formatMessages(messages) {
  let system = "";
  const formatted = [];

  for (const msg of messages) {
    if (msg.role === "system") {
      system += (system ? "\n\n" : "") + msg.content;
      continue;
    }

    if (msg.role === "tool_result") {
      formatted.push({
        role: "user",
        content: [
          {
            type: "tool_result",
            tool_use_id: msg.toolCallId,
            content: typeof msg.content === "string" ? msg.content : JSON.stringify(msg.content),
          },
        ],
      });
      continue;
    }

    if (msg.role === "assistant" && msg.toolCalls) {
      const content = [];
      if (msg.content) content.push({ type: "text", text: msg.content });
      for (const tc of msg.toolCalls) {
        content.push({
          type: "tool_use",
          id: tc.id,
          name: tc.name,
          input: tc.args || {},
        });
      }
      formatted.push({ role: "assistant", content });
      continue;
    }

    formatted.push({
      role: msg.role === "user" ? "user" : "assistant",
      content: msg.content || "",
    });
  }

  return { system, messages: formatted };
}

/**
 * Parse Anthropic response into the generic format.
 *
 * Phase-COST-TOKEN-COVERAGE Slice 5: Extracts prompt-cache + cache-creation
 * fields. Anthropic's `input_tokens` is uncached input only (post-cache-breakpoint);
 * cache_read and cache_creation are reported separately. Both ephemeral_5m and
 * ephemeral_1h sub-buckets are exposed when the 1-hour TTL is used. The
 * `vendor: "anthropic"` field signals to priceSlice() to apply the
 * cached-EXCLUDED billing math (mirror-opposite of OpenAI/xAI).
 *
 * @param {object} data - Anthropic API response
 * @returns {{
 *   type: "reply"|"tool_calls", content?: string, toolCalls?: Array,
 *   tokensIn: number, tokensOut: number,
 *   cacheReadTokens: number,
 *   cacheCreationInputTokens: number,
 *   cacheCreation5mTokens: number,
 *   cacheCreation1hTokens: number,
 *   vendor: "anthropic",
 * }}
 */
export function parseResponse(data) {
  const usage = data.usage || {};
  const tokensIn = usage.input_tokens || 0;
  const tokensOut = usage.output_tokens || 0;
  // Phase-COST-TOKEN-COVERAGE Slice 5: cache + creation token extraction
  const cacheReadTokens = usage.cache_read_input_tokens || 0;
  const cacheCreationInputTokens = usage.cache_creation_input_tokens || 0;
  const creation = usage.cache_creation || {};
  const cacheCreation5mTokens = creation.ephemeral_5m_input_tokens || 0;
  const cacheCreation1hTokens = creation.ephemeral_1h_input_tokens || 0;

  const contentBlocks = data.content || [];
  const toolUseBlocks = contentBlocks.filter((b) => b.type === "tool_use");
  const textBlocks = contentBlocks.filter((b) => b.type === "text");
  const textContent = textBlocks.map((b) => b.text).join("\n").trim();

  if (toolUseBlocks.length > 0) {
    return {
      type: "tool_calls",
      content: textContent || undefined,
      toolCalls: toolUseBlocks.map((b) => ({
        id: b.id,
        name: b.name,
        args: b.input || {},
      })),
      tokensIn,
      tokensOut,
      cacheReadTokens,
      cacheCreationInputTokens,
      cacheCreation5mTokens,
      cacheCreation1hTokens,
      vendor: "anthropic",
    };
  }

  return {
    type: "reply",
    content: textContent || data.content?.[0]?.text || "",
    tokensIn,
    tokensOut,
    cacheReadTokens,
    cacheCreationInputTokens,
    cacheCreation5mTokens,
    cacheCreation1hTokens,
    vendor: "anthropic",
  };
}

/**
 * Send a turn to the Anthropic Messages API with tool-use support.
 *
 * @param {{
 *   messages: Array<{role, content, toolCalls?, toolCallId?}>,
 *   tools: Array<{name, description, parameters?}>,
 *   model: string,
 *   apiKey: string,
 *   baseUrl?: string,
 *   signal?: AbortSignal,
 *   maxTokens?: number,
 * }} opts
 * @returns {Promise<{ type: "reply"|"tool_calls", content?: string, toolCalls?: Array, tokensIn: number, tokensOut: number }>}
 */
export async function sendTurn(opts) {
  const {
    messages,
    tools,
    model,
    apiKey,
    baseUrl = DEFAULT_BASE_URL,
    signal,
    maxTokens = DEFAULT_MAX_TOKENS,
  } = opts;

  const { system, messages: formatted } = formatMessages(messages);
  const anthropicTools = buildAnthropicTools(tools);

  const body = {
    model,
    max_tokens: maxTokens,
    messages: formatted,
  };
  if (system) body.system = system;
  if (anthropicTools.length > 0) body.tools = anthropicTools;

  const response = await fetch(`${baseUrl}/v1/messages`, {
    method: "POST",
    headers: {
      "x-api-key": apiKey,
      "anthropic-version": ANTHROPIC_VERSION,
      "content-type": "application/json",
    },
    body: JSON.stringify(body),
    signal,
  });

  if (!response.ok) {
    const errBody = await response.text();
    throw new Error(`Anthropic API error ${response.status}: ${errBody}`);
  }

  const data = await response.json();
  return parseResponse(data);
}

export const PROVIDER_NAME = "anthropic";

/**
 * Plan Forge — Forge-Master GitHub Copilot Provider Adapter (Phase-33, Slice 1).
 *
 * Connects the reasoning loop to the GitHub Models inference endpoint,
 * which exposes an OpenAI-compatible Chat Completions API.
 *
 * GitHub Models specifics:
 *   - POST /chat/completions (base: https://models.github.ai/inference)
 *   - Header: Authorization: Bearer <github-token>
 *   - Token resolution: passed → GITHUB_TOKEN env → .forge/secrets.json → `gh auth token`
 *   - Models: gpt-4o, gpt-4o-mini, claude-sonnet-4, claude-opus-4 (fallback: gpt-4o-mini)
 *   - 429 → structured rate_limited return; ≥500 → throw; 2xx → parse OpenAI format
 *
 * @module forge-master/providers/github-copilot-tools
 */

import { execFileSync } from "node:child_process";
import { existsSync, readFileSync } from "node:fs";
import { resolve } from "node:path";

import {
  buildOpenAITools,
  formatMessages,
  parseResponse,
} from "./openai-tools.mjs";

const DEFAULT_BASE_URL = "https://models.github.ai/inference";

export const KNOWN_MODELS = ["gpt-4o", "gpt-4o-mini", "claude-sonnet-4", "claude-opus-4"];

const _warnedModels = new Set();

// Module-scope subprocess cache: undefined = not yet attempted; null = attempted, no token; string = token
let _ghSubprocessAttempted = false;
let _ghTokenCache = null;

/** Reset subprocess token cache — for testing only. */
export function _resetTokenCache() {
  _ghSubprocessAttempted = false;
  _ghTokenCache = null;
  _warnedModels.clear();
}

/**
 * Resolve a GitHub token from four ordered tiers:
 *   1. `token` argument passed directly
 *   2. `GITHUB_TOKEN` environment variable
 *   3. `.forge/secrets.json` — key `GITHUB_TOKEN` or `github.token`
 *   4. `gh auth token` subprocess (result cached at module scope)
 *
 * @param {{ token?: string, useSubprocess?: boolean }} [opts]
 * @returns {string | null}
 */
export function resolveGitHubToken({ token, useSubprocess = true } = {}) {
  // Tier 1: directly passed
  if (token) return token;

  // Tier 2: environment variable
  const envToken = process.env.GITHUB_TOKEN;
  if (envToken) return envToken;

  // Tier 3: .forge/secrets.json
  try {
    const secretsPath = resolve(process.cwd(), ".forge", "secrets.json");
    if (existsSync(secretsPath)) {
      const secrets = JSON.parse(readFileSync(secretsPath, "utf-8"));
      const secretToken = secrets?.GITHUB_TOKEN || secrets?.github?.token;
      if (secretToken) return secretToken;
    }
  } catch { /* malformed JSON or unreadable — skip */ }

  // Tier 4: gh auth token subprocess (cache result at module scope)
  if (useSubprocess) {
    if (_ghSubprocessAttempted) return _ghTokenCache;
    _ghSubprocessAttempted = true;
    try {
      const tok = execFileSync("gh", ["auth", "token"], {
        encoding: "utf8",
        stdio: ["ignore", "pipe", "ignore"],
      }).trim();
      if (tok) {
        _ghTokenCache = tok;
        return tok;
      }
    } catch { /* gh not installed or not authenticated */ }
  }

  return null;
}

/**
 * Returns true if a GitHub token is available from any resolution tier.
 * Allowed to spawn `gh` once for the initial cache warm-up; subsequent
 * calls are cache-only and never hit the network.
 *
 * @returns {boolean}
 */
export function isAvailable() {
  return Boolean(resolveGitHubToken({ useSubprocess: true }));
}

function normalizeModel(model) {
  if (KNOWN_MODELS.includes(model)) return model;
  if (!_warnedModels.has(model)) {
    console.warn(
      `[github-copilot] Unknown model "${model}", falling back to "gpt-4o-mini"`,
    );
    _warnedModels.add(model);
  }
  return "gpt-4o-mini";
}

/**
 * Send a turn to the GitHub Models Chat Completions endpoint.
 *
 * @param {{
 *   messages: Array<{role, content, toolCalls?, toolCallId?}>,
 *   tools?: Array<{name, description, parameters?}>,
 *   model: string,
 *   token?: string,
 *   apiKey?: string,
 *   baseUrl?: string,
 *   signal?: AbortSignal,
 * }} opts
 * @returns {Promise<
 *   | { type: "reply"|"tool_calls", content?: string, toolCalls?: Array, tokensIn: number, tokensOut: number }
 *   | { type: "rate_limited", retryAfter: string|null, raw: string }
 * >}
 */
export async function sendTurn(opts) {
  const {
    messages,
    tools = [],
    model,
    token,
    apiKey,
    baseUrl = DEFAULT_BASE_URL,
    signal,
  } = opts;

  // Accept both `token` and `apiKey` for caller compatibility
  const resolvedToken = resolveGitHubToken({ token: token ?? apiKey });
  if (!resolvedToken) {
    throw new Error(
      "GitHub Copilot: no token available. " +
      "Set GITHUB_TOKEN env var, add to .forge/secrets.json, or run `gh auth login`.",
    );
  }

  const normalizedModel = normalizeModel(model);
  const formatted = formatMessages(messages);
  const body = { model: normalizedModel, messages: formatted };

  const builtTools = buildOpenAITools(tools);
  if (builtTools.length > 0) body.tools = builtTools;

  const response = await fetch(`${baseUrl}/chat/completions`, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${resolvedToken}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify(body),
    signal,
  });

  if (response.status === 429) {
    const raw = await response.text();
    return {
      type: "rate_limited",
      retryAfter: response.headers.get("retry-after") ?? null,
      raw,
    };
  }

  if (response.status >= 500) {
    const errBody = await response.text();
    throw new Error(`GitHub Copilot API error ${response.status}: ${errBody}`);
  }

  if (!response.ok) {
    const errBody = await response.text();
    throw new Error(`GitHub Copilot API error ${response.status}: ${errBody}`);
  }

  const data = await response.json();
  return parseResponse(data);
}

export const PROVIDER_NAME = "github-copilot";

/**
 * Plan Forge — Forge-Master OpenAI Function-Calling Adapter (Phase-28, Slice 5).
 *
 * Translates between the reasoning loop's generic interface and the
 * OpenAI Chat Completions API function-calling format.
 *
 * OpenAI specifics:
 *   - POST /v1/chat/completions
 *   - Header: Authorization: Bearer
 *   - Tools: {type:"function", function:{name, description, parameters}}
 *   - Response: choices[0].message.tool_calls[{id, function:{name, arguments}}]
 *   - Tool results: {role:"tool", tool_call_id, content}
 *
 * @module forge-master/providers/openai-tools
 */

const DEFAULT_BASE_URL = "https://api.openai.com/v1";

/**
 * Build OpenAI-format tool definitions from generic tool schemas.
 * @param {Array<{name, description, parameters?}>} tools
 * @returns {Array<object>}
 */
export function buildOpenAITools(tools) {
  return tools.map((t) => ({
    type: "function",
    function: {
      name: t.name,
      description: t.description || "",
      parameters: t.parameters || { type: "object", properties: {} },
    },
  }));
}

/**
 * Convert generic messages to OpenAI format.
 *
 * @param {Array<{role, content, toolCalls?, toolCallId?}>} messages
 * @returns {Array<object>}
 */
export function formatMessages(messages) {
  const formatted = [];

  for (const msg of messages) {
    if (msg.role === "tool_result") {
      formatted.push({
        role: "tool",
        tool_call_id: msg.toolCallId,
        content: typeof msg.content === "string" ? msg.content : JSON.stringify(msg.content),
      });
      continue;
    }

    if (msg.role === "assistant" && msg.toolCalls) {
      const entry = {
        role: "assistant",
        content: msg.content || null,
        tool_calls: msg.toolCalls.map((tc) => ({
          id: tc.id,
          type: "function",
          function: {
            name: tc.name,
            arguments: JSON.stringify(tc.args || {}),
          },
        })),
      };
      formatted.push(entry);
      continue;
    }

    formatted.push({
      role: msg.role,
      content: msg.content || "",
    });
  }

  return formatted;
}

function parseUsage(data) {
  const usage = data.usage || {};
  return {
    tokensIn: usage.prompt_tokens ?? usage.input_tokens ?? 0,
    tokensOut: usage.completion_tokens ?? usage.output_tokens ?? 0,
    cacheReadTokens: usage.prompt_tokens_details?.cached_tokens ?? usage.input_tokens_details?.cached_tokens ?? 0,
    reasoningTokens: usage.completion_tokens_details?.reasoning_tokens ?? usage.output_tokens_details?.reasoning_tokens ?? 0,
    serviceTier: data.service_tier ?? null,
    vendor: "openai",
  };
}

function buildReplyResponse(content, usage) {
  return {
    type: "reply",
    content,
    ...usage,
  };
}

function buildToolCallsResponse(message, usage) {
  return {
    type: "tool_calls",
    content: message.content || undefined,
    toolCalls: message.tool_calls.map((tc) => ({
      id: tc.id,
      name: tc.function.name,
      args: safeParseArgs(tc.function.arguments),
    })),
    ...usage,
  };
}

/**
 * Parse OpenAI response into the generic format.
 *
 * Phase-COST-TOKEN-COVERAGE Slice 6: Extracts cached_tokens, reasoning_tokens,
 * and service_tier. Handles BOTH the Chat Completions API shape
 * (`prompt_tokens` + `prompt_tokens_details.cached_tokens`) and the
 * Responses API shape (`input_tokens` + `input_tokens_details.cached_tokens`).
 * The `vendor: "openai"` field signals to priceSlice() to apply the
 * cached-INCLUDED billing math (mirror-opposite of Anthropic).
 *
 * @param {object} data - OpenAI API response
 * @returns {{
 *   type: "reply"|"tool_calls", content?: string, toolCalls?: Array,
 *   tokensIn: number, tokensOut: number,
 *   cacheReadTokens: number, reasoningTokens: number,
 *   serviceTier: string|null, vendor: "openai",
 * }}
 */
export function parseResponse(data) {
  const usage = parseUsage(data);
  const message = data.choices?.[0]?.message;

  if (!message) {
    return buildReplyResponse("", usage);
  }

  if (message.tool_calls?.length > 0) {
    return buildToolCallsResponse(message, usage);
  }

  return buildReplyResponse(message.content || "", usage);
}

function safeParseArgs(str) {
  try {
    return JSON.parse(str || "{}");
  } catch {
    return {};
  }
}

/**
 * Send a turn to the OpenAI Chat Completions API with function-calling support.
 *
 * @param {{
 *   messages: Array<{role, content, toolCalls?, toolCallId?}>,
 *   tools: Array<{name, description, parameters?}>,
 *   model: string,
 *   apiKey: string,
 *   baseUrl?: string,
 *   signal?: AbortSignal,
 * }} opts
 * @returns {Promise<{ type: "reply"|"tool_calls", content?: string, toolCalls?: Array, tokensIn: number, tokensOut: number }>}
 */
export async function sendTurn(opts) {
  const {
    messages,
    tools,
    model,
    apiKey,
    baseUrl = DEFAULT_BASE_URL,
    signal,
  } = opts;

  const formatted = formatMessages(messages);
  const body = {
    model,
    messages: formatted,
  };

  const openAITools = buildOpenAITools(tools);
  if (openAITools.length > 0) body.tools = openAITools;

  const response = await fetch(`${baseUrl}/chat/completions`, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${apiKey}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify(body),
    signal,
  });

  if (!response.ok) {
    const errBody = await response.text();
    throw new Error(`OpenAI API error ${response.status}: ${errBody}`);
  }

  const data = await response.json();
  return parseResponse(data);
}

export const PROVIDER_NAME = "openai";

/**
 * Plan Forge — Forge-Master XAI (Grok) Tool-Use Adapter (Phase-28, Slice 5).
 *
 * XAI Grok uses an OpenAI-compatible endpoint. This adapter attempts
 * tool-use via the OpenAI format and falls back to reply-only mode
 * if tool-use is not supported (HTTP 400/422 on tools param).
 *
 * Exports:
 *   - sendTurn(opts) — try tool-use, fallback to reply-only
 *   - sendReplyOnly(opts) — no tool schemas, reply-only
 *   - PROVIDER_NAME — "xai"
 *
 * @module forge-master/providers/xai-tools
 */

import {
  buildOpenAITools,
  formatMessages,
  parseResponse as parseOpenAIResponse,
} from "./openai-tools.mjs";

const DEFAULT_BASE_URL = "https://api.x.ai/v1";

/**
 * Parse xAI response into the generic format.
 *
 * Phase-COST-TOKEN-COVERAGE Slice 7: xAI is OpenAI-compatible at the wire,
 * so we delegate to the OpenAI parser then overlay xAI-specific fields:
 *   - vendor: "xai" (overrides the "openai" the base parser sets)
 *   - costInUsdTicks: authoritative billed amount per response
 *     (1 tick = 1e-10 USD). When present, priceSlice() uses it directly
 *     and skips computed multiplier math. See xAI cost-tracking docs.
 *
 * @param {object} data - xAI API response (OpenAI-compatible shape)
 * @returns {object} same shape as openai parseResponse plus costInUsdTicks + vendor: "xai"
 */
export function parseResponse(data) {
  const base = parseOpenAIResponse(data);
  const usage = data.usage || {};
  const costInUsdTicks = typeof usage.cost_in_usd_ticks === "number" ? usage.cost_in_usd_ticks : null;
  return {
    ...base,
    costInUsdTicks,
    vendor: "xai",
  };
}

/**
 * Send a reply-only request (no tool schemas).
 * Used as fallback when tool-use is unsupported by XAI.
 */
export async function sendReplyOnly(opts) {
  const {
    messages,
    model,
    apiKey,
    baseUrl = DEFAULT_BASE_URL,
    signal,
  } = opts;

  const formatted = formatMessages(messages);

  const response = await fetch(`${baseUrl}/chat/completions`, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${apiKey}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ model, messages: formatted }),
    signal,
  });

  if (!response.ok) {
    const errBody = await response.text();
    throw new Error(`XAI API error ${response.status}: ${errBody}`);
  }

  const data = await response.json();
  const parsed = parseResponse(data);
  // Force reply type — no tool calls in reply-only mode
  return { ...parsed, type: "reply", toolCalls: undefined };
}

/**
 * Send a turn to the XAI (Grok) API with tool-use support.
 * Falls back to reply-only if the API rejects the tools parameter.
 *
 * @param {{
 *   messages: Array<{role, content, toolCalls?, toolCallId?}>,
 *   tools: Array<{name, description, parameters?}>,
 *   model: string,
 *   apiKey: string,
 *   baseUrl?: string,
 *   signal?: AbortSignal,
 * }} opts
 * @returns {Promise<{ type: "reply"|"tool_calls", content?: string, toolCalls?: Array, tokensIn: number, tokensOut: number }>}
 */
export async function sendTurn(opts) {
  const {
    messages,
    tools,
    model,
    apiKey,
    baseUrl = DEFAULT_BASE_URL,
    signal,
  } = opts;

  const formatted = formatMessages(messages);
  const body = { model, messages: formatted };

  const openAITools = buildOpenAITools(tools);
  if (openAITools.length > 0) body.tools = openAITools;

  try {
    const response = await fetch(`${baseUrl}/chat/completions`, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${apiKey}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify(body),
      signal,
    });

    if (!response.ok) {
      const status = response.status;
      // 400 or 422 with tools may mean tool-use unsupported — fallback
      if ((status === 400 || status === 422) && openAITools.length > 0) {
        return sendReplyOnly(opts);
      }
      const errBody = await response.text();
      throw new Error(`XAI API error ${status}: ${errBody}`);
    }

    const data = await response.json();
    return parseResponse(data);
  } catch (err) {
    // If the error is about tools, try reply-only fallback
    if (err.message && /tool/i.test(err.message) && openAITools.length > 0) {
      return sendReplyOnly(opts);
    }
    throw err;
  }
}

export const PROVIDER_NAME = "xai";

/**
 * Plan Forge — Forge-Master Quorum Dispatcher (Phase-38.7, Slice 1).
 *
 * Dispatches a single prompt to multiple models in parallel and collects
 * replies with a dissent summary.  Used by the advisory quorum path in
 * reasoning.mjs when the user enables quorum advisory mode.
 *
 * Exports:
 *   - dispatchQuorum({ prompt, models, deps }) → QuorumResult
 *   - extractDissent(replies)                  → { topic, axis }
 *   - MAX_MODELS                               — hard cap (3)
 *   - TIMEOUT_MS                               — per-call timeout (60 000 ms)
 *
 * @module forge-master/quorum-dispatcher
 */

import { computeTurnCost } from "./cost.mjs";

// ─── Constants ──────────────────────────────────────────────────────

export const MAX_MODELS = 3;
export const TIMEOUT_MS = 60_000;

// ─── Stopwords for dissent extraction ───────────────────────────────

const STOPWORDS = new Set([
  "a", "an", "the", "is", "are", "was", "were", "be", "been", "being",
  "have", "has", "had", "do", "does", "did", "will", "would", "could",
  "should", "may", "might", "shall", "can", "need", "dare", "ought",
  "to", "of", "in", "for", "on", "with", "at", "by", "from", "as",
  "into", "through", "during", "before", "after", "above", "below",
  "between", "out", "off", "over", "under", "again", "further", "then",
  "once", "and", "but", "or", "nor", "not", "so", "yet", "both",
  "either", "neither", "each", "every", "all", "any", "few", "more",
  "most", "other", "some", "such", "no", "only", "own", "same", "than",
  "too", "very", "just", "because", "if", "when", "while", "that",
  "which", "who", "whom", "this", "these", "those", "i", "you", "he",
  "she", "it", "we", "they", "me", "him", "her", "us", "them", "my",
  "your", "his", "its", "our", "their", "what", "how", "about",
]);

// ─── Dissent Extraction ─────────────────────────────────────────────

/**
 * Extract first N words from text, normalized (lowercase, no punctuation).
 * @param {string} text
 * @param {number} [n=50]
 * @returns {string[]}
 */
function extractWords(text, n = 50) {
  if (!text || typeof text !== "string") return [];
  return text
    .toLowerCase()
    .replace(/[^\w\s]/g, "")
    .split(/\s+/)
    .filter((w) => w.length > 0 && !STOPWORDS.has(w))
    .slice(0, n);
}

/**
 * Compute dissent summary from an array of reply objects.
 *
 * Uses a simple keyword-diff approach on the first 50 meaningful words
 * of each reply.  If the word-set Jaccard distance exceeds 0.5, reports
 * the most divergent terms.
 *
 * @param {Array<{ model: string, text: string }>} replies
 * @returns {{ topic: string, axis: string }}
 */
export function extractDissent(replies) {
  if (!replies || replies.length < 2) {
    return { topic: "", axis: "" };
  }

  const wordSets = replies.map((r) => new Set(extractWords(r.text)));

  // Pairwise Jaccard distance — find the most divergent pair
  let maxDistance = 0;
  let pairA = 0;
  let pairB = 1;

  for (let i = 0; i < wordSets.length; i++) {
    for (let j = i + 1; j < wordSets.length; j++) {
      const union = new Set([...wordSets[i], ...wordSets[j]]);
      const intersection = [...wordSets[i]].filter((w) => wordSets[j].has(w));
      const distance = union.size === 0 ? 0 : 1 - intersection.length / union.size;
      if (distance > maxDistance) {
        maxDistance = distance;
        pairA = i;
        pairB = j;
      }
    }
  }

  if (maxDistance <= 0.5) {
    return { topic: "", axis: "" };
  }

  // Find words unique to each side of the most divergent pair
  const uniqueA = [...wordSets[pairA]].filter((w) => !wordSets[pairB].has(w)).slice(0, 5);
  const uniqueB = [...wordSets[pairB]].filter((w) => !wordSets[pairA].has(w)).slice(0, 5);

  return {
    topic: "recommendation",
    axis: `${replies[pairA].model} emphasizes [${uniqueA.join(", ")}] vs ${replies[pairB].model} emphasizes [${uniqueB.join(", ")}]`,
  };
}

// ─── Quorum Dispatcher ─────────────────────────────────────────────

/**
 * Dispatch a prompt to multiple models in parallel and collect replies.
 *
 * @param {{
 *   prompt: string,
 *   models: Array<{ model: string, provider: string, apiKey?: string }>,
 *   deps: {
 *     selectProvider: (name: string) => Promise<{ sendTurn: Function } | null>,
 *     systemPrompt?: string,
 *     timeoutMs?: number,
 *   }
 * }} opts
 * @returns {Promise<{
 *   replies: Array<{ model: string, text: string, durationMs: number, costUSD: number }>,
 *   dissent: { topic: string, axis: string }
 * }>}
 */
export async function dispatchQuorum({ prompt, models, deps }) {
  const effectiveModels = (models || []).slice(0, MAX_MODELS);
  const timeoutMs = deps?.timeoutMs ?? TIMEOUT_MS;
  const systemPrompt = deps?.systemPrompt ?? "You are a helpful assistant.";

  if (effectiveModels.length === 0) {
    return { replies: [], dissent: { topic: "all-failed", axis: "" } };
  }

  const messages = [
    { role: "system", content: systemPrompt },
    { role: "user", content: prompt },
  ];

  // Dispatch each model call in parallel with individual timeouts
  const tasks = effectiveModels.map(async (entry) => {
    const start = Date.now();
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), timeoutMs);

    try {
      const provider = await deps.selectProvider(entry.provider);
      if (!provider) {
        throw new Error(`provider "${entry.provider}" not available`);
      }

      const response = await Promise.race([
        provider.sendTurn({
          messages,
          tools: [],
          model: entry.model,
          apiKey: entry.apiKey || "",
          signal: controller.signal,
        }),
        new Promise((_, reject) => {
          controller.signal.addEventListener("abort", () =>
            reject(new Error("quorum_timeout")),
          );
        }),
      ]);

      // Only accept actual reply responses — rate_limited, tool_calls, etc. are failures
      if (!response || response.type !== "reply" || typeof response.content !== "string") {
        throw new Error(`unexpected response type: ${response?.type ?? "null"}`);
      }

      const durationMs = Date.now() - start;
      const costUSD = computeTurnCost(entry.model, response.tokensIn || 0, response.tokensOut || 0);

      return {
        model: entry.model,
        text: response.content,
        durationMs,
        costUSD,
      };
    } catch {
      return null; // Mark as failed
    } finally {
      clearTimeout(timer);
    }
  });

  const results = await Promise.allSettled(tasks);

  const replies = results
    .filter((r) => r.status === "fulfilled" && r.value !== null)
    .map((r) => r.value);

  if (replies.length === 0) {
    return { replies: [], dissent: { topic: "all-failed", axis: "" } };
  }

  const dissent = extractDissent(replies);

  return { replies, dissent };
}

/**
 * Plan Forge — Forge-Master Reasoning Loop (Phase-28, Slice 5; Phase-33, Slice 2).
 *
 * Implements the tool-use reasoning loop:
 *   1. Classify intent via intent-router.
 *   2. Fetch context from brain tiers via retrieval.
 *   3. Load + interpolate system prompt.
 *   4. Invoke frontier model via provider adapter with tool schemas.
 *   5. Execute tool calls through tool-bridge.
 *   6. Iterate until final reply or budget exceeded.
 *
 * Exports:
 *   - runTurn({message, sessionId, maxToolCalls, cwd}, deps) → result
 *   - buildToolSchemas(allowlist, usageHints) → schema array
 *   - selectProvider(providerName) → adapter module  (explicit by-name selection)
 *   - autoSelectProvider(config, env, _providers) → adapter module (availability-order selection)
 *   - ABSOLUTE_CEILING — hard ceiling for tool calls (10)
 *
 * @module forge-master/reasoning
 */

import { readFileSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";

import { classify, LANES, LANE_DESCRIPTORS, OFFTOPIC_REDIRECT } from "./intent-router.mjs";
import { fetchContext } from "./retrieval.mjs";
import { getForgeMasterConfig } from "./config.mjs";
import { resolveAllowlist, USAGE_HINTS } from "./allowlist.mjs";
import { invokeMany, invokeAllowlisted } from "./tool-bridge.mjs";
import { plan as runPlanner } from "./planner.mjs";
import { executePlan } from "./plan-executor.mjs";
import { ensureSessionId, appendTurn, summarizeIfNeeded } from "./persistence.mjs";
import { appendTurn as storeAppendTurn, loadSession, hashReply } from "./session-store.mjs";
import { loadIndex, queryIndex } from "./recall-index.mjs";
import { loadPrinciples, UNIVERSAL_BASELINE } from "./principles.mjs";
import { resolveModel, VALID_TIERS } from "./reasoning-tier.mjs";
import { computeTurnCost } from "./cost.mjs";
import { dispatchQuorum } from "./quorum-dispatcher.mjs";
import * as githubCopilotProvider from "./providers/github-copilot-tools.mjs";
import { checkBudget, recordSpend, loadBudgetState, saveBudgetState } from "./observer-budget.mjs";
import { buildObserverPrompt } from "./observer-prompt.mjs";
import { OBSERVER_NARRATION_EVENT_TYPE } from "./observer-loop.mjs";

// ─── Recall-eligible lanes ────────────────────────────────────────────

const RECALL_LANES = new Set([LANES.OPERATIONAL, LANES.TROUBLESHOOT, LANES.ADVISORY]);

// ─── Quorum advisory — model set for multi-model fan-out ────────────

const QUORUM_MODELS = [
  { model: "claude-sonnet-4-20250514", provider: "anthropic" },
  { model: "gpt-5.2", provider: "openai" },
  { model: "grok-4.20", provider: "xai" },
];

// Lanes where quorum must NEVER engage (hard guard)
const QUORUM_BLOCKED_LANES = new Set([
  LANES.BUILD,
  LANES.OPERATIONAL,
  LANES.TROUBLESHOOT,
  LANES.OFFTOPIC,
  LANES.TEMPERING,
  LANES.PRINCIPLE_JUDGMENT,
  LANES.META_BUG_TRIAGE,
]);

// ─── Constants ──────────────────────────────────────────────────────

export const ABSOLUTE_CEILING = 10;

/**
 * Observer tool allowlist (RD #11) — exactly four read-only tools.
 * Any model-requested tool call outside this list is rejected by the bridge filter.
 */
export const OBSERVER_TOOL_ALLOWLIST = [
  "brain_recall",
  "forge_search",
  "forge_plan_status",
  "forge_watch",
];

const __dirname = dirname(fileURLToPath(import.meta.url));
const SYSTEM_PROMPT_PATH = resolve(__dirname, "system-prompt.md");

// Ordered from highest to lowest for tier fallback traversal
const TIER_ORDER = ["high", "medium", "low"];
function nextTier(tier) {
  const idx = TIER_ORDER.indexOf(tier);
  return idx >= 0 && idx < TIER_ORDER.length - 1 ? TIER_ORDER[idx + 1] : null;
}
/** Escalate to the next higher tier (toward "high"). Returns null if already at top. */
function escalateTier(tier) {
  const idx = TIER_ORDER.indexOf(tier);
  return idx > 0 ? TIER_ORDER[idx - 1] : null;
}

// ─── Provider Selection ─────────────────────────────────────────────

const NO_PROVIDER_SUGGESTION =
  "Install GitHub CLI and run 'gh auth login', or set GITHUB_TOKEN, OPENAI_API_KEY, ANTHROPIC_API_KEY, or XAI_API_KEY";

const AUTO_SELECT_ORDER = ["githubCopilot", "anthropic", "openai", "xai"];

/**
 * Select the appropriate provider adapter by explicit name.
 * Returns a module with `sendTurn(opts)`, or null for unknown names.
 * Maintained for backward compatibility — prefer `autoSelectProvider` for new code.
 *
 * @param {"githubCopilot"|"anthropic"|"openai"|"xai"|string|null} providerName
 * @returns {Promise<{ sendTurn: Function, PROVIDER_NAME: string }|null>}
 */
export async function selectProvider(providerName) {
  switch (providerName) {
    case "githubCopilot":
      return githubCopilotProvider;
    case "anthropic":
      return import("./providers/anthropic-tools.mjs");
    case "openai":
      return import("./providers/openai-tools.mjs");
    case "xai":
      return import("./providers/xai-tools.mjs");
    default:
      return null;
  }
}

/**
 * Auto-select the first available provider adapter by checking `isAvailable()`.
 * Iterates `["githubCopilot", "anthropic", "openai", "xai"]` unless
 * `config.defaultProvider` overrides the starting position.
 *
 * @param {{ defaultProvider?: string }} config
 * @param {NodeJS.ProcessEnv} [env]
 * @param {Record<string, { module: object, isAvailable: () => boolean }>|null} [_providers]
 *   — injectable for testing; null = use real providers
 * @returns {Promise<{ sendTurn: Function, PROVIDER_NAME: string }|null>}
 */
export async function autoSelectProvider(config, env = process.env, _providers = null) {
  const providerDefs = _providers || {
    githubCopilot: {
      module: githubCopilotProvider,
      isAvailable: () => githubCopilotProvider.isAvailable(),
    },
    anthropic: {
      module: null,
      isAvailable: () => Boolean(env.ANTHROPIC_API_KEY),
      load: () => import("./providers/anthropic-tools.mjs"),
    },
    openai: {
      module: null,
      isAvailable: () => Boolean(env.OPENAI_API_KEY),
      load: () => import("./providers/openai-tools.mjs"),
    },
    xai: {
      module: null,
      isAvailable: () => Boolean(env.XAI_API_KEY),
      load: () => import("./providers/xai-tools.mjs"),
    },
  };

  let order = [...AUTO_SELECT_ORDER];
  const preferred = config?.defaultProvider;
  if (preferred && order.includes(preferred)) {
    order = [preferred, ...order.filter((p) => p !== preferred)];
  }

  for (const name of order) {
    const entry = providerDefs[name];
    if (!entry) continue;
    if (entry.isAvailable()) {
      return entry.module ?? (await entry.load());
    }
  }
  return null;
}

// ─── Tool Schema Builder ────────────────────────────────────────────

/**
 * Build simplified tool schemas for the reasoning model from the
 * allowlist and usage hints.
 *
 * @param {string[]} allowlist — resolved allowlist of tool names
 * @param {Record<string, string>} [hints=USAGE_HINTS]
 * @returns {Array<{name: string, description: string, parameters: object}>}
 */
export function buildToolSchemas(allowlist, hints = USAGE_HINTS) {
  return allowlist.map((name) => ({
    name,
    description: hints[name] || `Plan Forge tool: ${name}`,
    parameters: {
      type: "object",
      properties: {},
      additionalProperties: true,
    },
  }));
}

// ─── System Prompt Loader ───────────────────────────────────────────

/**
 * Load and interpolate the system prompt.
 * Substitutes {principles_block} first (non-negotiable, never truncated),
 * then {context_block} (may have been pre-trimmed by retrieval.mjs).
 *
 * @param {string} contextBlock   — pre-fetched and truncated memory context
 * @param {string} principlesBlock — active principles (from loadPrinciples or UNIVERSAL_BASELINE)
 * @returns {string}
 */
function loadSystemPrompt(contextBlock, principlesBlock) {
  try {
    const raw = readFileSync(SYSTEM_PROMPT_PATH, "utf-8");
    return raw
      .replace("{principles_block}", principlesBlock || UNIVERSAL_BASELINE)
      .replace("{context_block}", contextBlock || "(no context available)");
  } catch {
    return `You are Forge-Master, a Plan Forge reasoning assistant.\n\n## Philosophy & Guardrails\n\n${principlesBlock || UNIVERSAL_BASELINE}\n\n## Current Context\n\n${contextBlock || "(no context available)"}`;
  }
}

// ─── Private helpers for runTurn ────────────────────────────────────

async function _loadPriorTurns(effectiveSessionId, isEphemeral, cwd) {
  if (isEphemeral) return [];
  try {
    const all = await loadSession(effectiveSessionId, cwd);
    return all.slice(-10);
  } catch { return []; }
}

function _resolveTierState(input, config) {
  const inputModel = typeof input.model === "string" ? input.model : null;
  const rawInputTier = input.tier ?? null;
  const requestedTier = !inputModel && rawInputTier && VALID_TIERS.includes(rawInputTier)
    ? rawInputTier
    : (!inputModel && config.defaultTier ? config.defaultTier : null);
  return {
    inputModel,
    requestedTier,
    currentTier: requestedTier,
    currentModel: inputModel ?? resolveModel(requestedTier, config),
  };
}

function _applyAutoEscalation({ inputModel, currentTier, currentModel, config, classification }) {
  if (inputModel || !currentTier || !config.autoEscalate) {
    return { applied: false, autoEscalated: false, autoFromTier: null, autoToTier: null, autoEscalationReason: null, currentTier, currentModel };
  }
  if (!(LANE_DESCRIPTORS[classification.lane]?.recommendedTierBump > 0)) {
    return { applied: false, autoEscalated: false, autoFromTier: null, autoToTier: null, autoEscalationReason: null, currentTier, currentModel };
  }
  const escalated = escalateTier(currentTier);
  if (!escalated) {
    return { applied: false, autoEscalated: false, autoFromTier: null, autoToTier: null, autoEscalationReason: null, currentTier, currentModel };
  }
  return {
    applied: true,
    autoEscalated: true,
    autoFromTier: currentTier,
    autoToTier: escalated,
    autoEscalationReason: `high-stakes lane: ${classification.lane}`,
    currentTier: escalated,
    currentModel: resolveModel(escalated, config),
  };
}

async function _buildContextBlock({ effectiveSessionId, isEphemeral, classification, message, cwd, priorTurns, deps }) {
  let contextBlock = "";
  try {
    const ctx = await fetchContext({ sessionId: effectiveSessionId, lane: classification.lane, cwd }, deps);
    contextBlock = ctx.contextBlock;
  } catch { /* non-fatal */ }

  let relatedTurns = [];
  if (!isEphemeral && RECALL_LANES.has(classification.lane)) {
    try {
      await loadIndex(cwd);
      relatedTurns = await queryIndex(message, { topK: 3, projectDir: cwd });
    } catch (err) {
      console.warn("[forge-master] recall-index query failed (non-fatal):", err?.message);
    }
    if (relatedTurns.length > 0) {
      const recallLines = relatedTurns.map((r) => {
        const ts = r.timestamp ? r.timestamp.slice(0, 10) : "unknown";
        return `- [${ts} · ${r.lane}] "${r.userMessage}"`;
      });
      contextBlock = `${contextBlock}\n\n> **Recall (advisory):**\n${recallLines.join("\n")}`.trimStart();
    }
  }

  if (classification.lane === LANES.TROUBLESHOOT) {
    try {
      const detectPatterns = deps.detectPatterns || null;
      const surfacedPatterns = typeof detectPatterns === "function" ? await detectPatterns({ cwd }) : [];
      if (surfacedPatterns.length > 0) {
        const patternLines = surfacedPatterns.slice(0, 3).map(
          (p) => `> **Recurring pattern observed:** ${p.title || p.summary || p.id}`,
        );
        contextBlock = `${contextBlock}\n\n${patternLines.join("\n")}`.trimStart();
      }
    } catch { /* non-fatal */ }
  }

  if (priorTurns.length > 0) {
    const priorBlock = priorTurns.map((t) => `Turn ${t.turn}: User: "${t.userMessage}"`).join("\n");
    contextBlock = `## Prior conversation turns (oldest first)\n\n${priorBlock}\n\n${contextBlock}`;
  }

  return { contextBlock, relatedTurns };
}

function _loadPrinciplesBlock(cwd) {
  try {
    const { block } = loadPrinciples({ cwd });
    return block;
  } catch (err) {
    console.warn("[forge-master] principles loader failed, using universal baseline:", err?.message);
    return UNIVERSAL_BASELINE;
  }
}

async function _resolveProvider(config, deps) {
  let provider = deps.provider || null;
  if (!provider) {
    provider = config.reasoningProvider
      ? await selectProvider(config.reasoningProvider)
      : await autoSelectProvider(config, process.env, deps._providers || null);
  }
  return provider;
}

function _resolveApiKey(config, deps) {
  if (deps.resolveApiKey) return deps.resolveApiKey(config.reasoningProvider);
  if (deps.detectApiProvider) return deps.detectApiProvider(config.reasoningModel)?.apiKey || null;
  return null;
}

async function _runPlannerPhase({ provider, currentModel, apiKey, message, classification, allowlist, cwd, deps, systemPrompt }) {
  if (deps.skipPlanner) return { plannerSynthesis: null, plannerToolCalls: [], tokensIn: 0, tokensOut: 0, costUSD: 0 };
  let tokensIn = 0, tokensOut = 0, costUSD = 0;
  try {
    const callPlannerModel = async ({ systemPrompt: sp, userMessage: um }) => {
      const planResp = await provider.sendTurn({
        messages: [{ role: "system", content: sp }, { role: "user", content: um }],
        tools: [],
        model: currentModel,
        apiKey: apiKey || "",
        signal: undefined,
      });
      tokensIn += planResp.tokensIn || 0;
      tokensOut += planResp.tokensOut || 0;
      costUSD += computeTurnCost(currentModel, planResp.tokensIn || 0, planResp.tokensOut || 0);
      return planResp.content || "";
    };
    const planResult = await runPlanner({ userMessage: message, classification, lane: classification.lane, allowedTools: allowlist, deps: { callPlannerModel } });
    try { if (typeof deps.onPlan === "function") deps.onPlan(planResult); } catch { /* observer */ }
    if (!planResult.steps || planResult.steps.length === 0) return { plannerSynthesis: null, plannerToolCalls: [], tokensIn, tokensOut, costUSD };

    const planDispatch = async (step) => invokeAllowlisted(
      { tool: step.tool, args: step.args || {}, cwd },
      { resolvedAllowlist: allowlist, dispatcher: deps.dispatcher || (async () => ({})), hub: deps.hub || null },
    );
    const execResult = await executePlan({ steps: planResult.steps }, { dispatch: planDispatch });

    // Issue #153 — record planner-executed steps as tool-call records (source: "planner")
    const plannerToolCalls = execResult.results.map((r) => {
      const outputStr = r.error ? `ERROR: ${r.error}` : (typeof r.output === "string" ? r.output : JSON.stringify(r.output ?? null));
      const summary = outputStr.length > 800 ? outputStr.slice(0, 800) + "…" : outputStr;
      return { name: r.step.tool, args: r.step.args || {}, resultSummary: summary, costUSD: 0, source: "planner", stepId: r.step.id, ...(r.error && { error: r.error }) };
    });
    const lines = execResult.results.map((r) => {
      const status = r.error ? `ERROR: ${r.error}` : "OK";
      const output = r.error ? "(no output)" : (typeof r.output === "string" ? r.output : JSON.stringify(r.output ?? null));
      const trunc = output.length > 800 ? output.slice(0, 800) + "…" : output;
      return `[${r.step.id}] ${r.step.tool} → ${status}\n${trunc}`;
    });
    return { plannerSynthesis: lines.join("\n\n"), plannerToolCalls, tokensIn, tokensOut, costUSD };
  } catch {
    return { plannerSynthesis: null, plannerToolCalls: [], tokensIn, tokensOut, costUSD };
  }
}

async function _runQuorumAdvisory({ deps, classification, message, systemPrompt, autoEscalated, autoToTier }) {
  const quorumAdvisoryMode = deps.quorumAdvisory || "off";
  if (quorumAdvisoryMode === "off" || QUORUM_BLOCKED_LANES.has(classification.lane)) return { quorumResult: null, costUSD: 0 };
  const shouldEngage =
    quorumAdvisoryMode === "always" ||
    (quorumAdvisoryMode === "auto" && classification.lane === LANES.ADVISORY && autoEscalated &&
      autoToTier === "high" && (classification.confidence === "medium" || classification.confidence === "high"));
  if (!shouldEngage) return { quorumResult: null, costUSD: 0 };

  const estimatedCostUSD = QUORUM_MODELS.reduce((sum, m) => sum + computeTurnCost(m.model, 500, 500), 0);
  try { if (typeof deps.onQuorumEstimate === "function") deps.onQuorumEstimate({ type: "quorum-estimate", models: QUORUM_MODELS.map((m) => m.model), estimatedCostUSD, canCancel: true }); } catch { /* observer */ }

  try {
    const quorumResult = await dispatchQuorum({ prompt: message, models: QUORUM_MODELS, deps: { selectProvider, systemPrompt, timeoutMs: undefined } });
    const costUSD = quorumResult?.replies ? quorumResult.replies.reduce((s, r) => s + (r.costUSD || 0), 0) : 0;
    return { quorumResult, costUSD };
  } catch {
    return { quorumResult: null, costUSD: 0 };
  }
}

// Returns { ok: true, response, currentTier, currentModel, fallbackFromTier }
//      or { ok: false, earlyError, currentTier, currentModel, fallbackFromTier, finalReply }
async function _callWithTierFallback({ provider, messages, toolSchemas, currentTier, currentModel, config, apiKey, fallbackFromTier, partialReply }) {
  for (;;) {
    let response;
    try {
      response = await provider.sendTurn({ messages, tools: toolSchemas, model: currentModel, apiKey: apiKey || "", signal: undefined });
    } catch {
      return { ok: false, earlyError: "reasoning_model_unavailable", currentTier, currentModel, fallbackFromTier, finalReply: partialReply };
    }
    if (response.type === "rate_limited") {
      const next = nextTier(currentTier);
      if (next) {
        if (!fallbackFromTier) fallbackFromTier = currentTier;
        currentTier = next;
        currentModel = resolveModel(currentTier, config);
        continue;
      }
      return { ok: false, earlyError: "rate_limited", currentTier, currentModel, fallbackFromTier, finalReply: "" };
    }
    return { ok: true, response, currentTier, currentModel, fallbackFromTier };
  }
}

// Returns { done: false } to continue the loop, or { done: true, truncated, finalReply } on budget-exceeded.
// Mutates conversationMessages and allToolCalls in-place.
async function _dispatchToolCalls({ response, conversationMessages, allToolCalls, allowlist, cwd, deps, effectiveMaxToolCalls }) {
  const reactiveCount = allToolCalls.reduce((n, tc) => (tc.source === "planner" ? n : n + 1), 0);
  if (reactiveCount + response.toolCalls.length > effectiveMaxToolCalls) {
    return { done: true, truncated: true, finalReply: response.content || "(tool budget exceeded — partial response)" };
  }
  const bridgeCalls = response.toolCalls.map((tc) => ({ tool: tc.name, args: tc.args || {}, cwd }));
  const results = await invokeMany(bridgeCalls, { resolvedAllowlist: allowlist, dispatcher: deps.dispatcher || (async () => ({})), hub: deps.hub || null });
  conversationMessages.push({ role: "assistant", content: response.content || null, toolCalls: response.toolCalls });
  for (let i = 0; i < response.toolCalls.length; i++) {
    const tc = response.toolCalls[i];
    const result = results[i];
    allToolCalls.push({ name: tc.name, args: tc.args || {}, resultSummary: result?.summary || result?.error || "", costUSD: result?.costUSD || 0 });
    conversationMessages.push({ role: "tool_result", toolCallId: tc.id, content: result?.summary || result?.error || "no result" });
  }
  return { done: false };
}

async function _executeToolUseLoop({ provider, conversationMessages, toolSchemas, maxIterations, effectiveMaxToolCalls, allowlist, cwd, deps, config, currentTier, currentModel, apiKey, fallbackFromTier, allToolCalls, totalTokensIn, totalTokensOut, totalCostUSD }) {
  let finalReply = "", truncated = false, iterationCount = 0;
  let _currentTier = currentTier, _currentModel = currentModel, _fallbackFromTier = fallbackFromTier;

  while (iterationCount < maxIterations) {
    iterationCount++;
    const callResult = await _callWithTierFallback({ provider, messages: conversationMessages, toolSchemas, currentTier: _currentTier, currentModel: _currentModel, config, apiKey, fallbackFromTier: _fallbackFromTier, partialReply: finalReply });
    if (!callResult.ok) {
      return { earlyError: callResult.earlyError, currentTier: callResult.currentTier, currentModel: callResult.currentModel, fallbackFromTier: callResult.fallbackFromTier, allToolCalls, totalTokensIn, totalTokensOut, totalCostUSD, finalReply: callResult.finalReply };
    }
    _currentTier = callResult.currentTier;
    _currentModel = callResult.currentModel;
    _fallbackFromTier = callResult.fallbackFromTier;
    const { response } = callResult;
    totalTokensIn += response.tokensIn || 0;
    totalTokensOut += response.tokensOut || 0;
    totalCostUSD += computeTurnCost(_currentModel, response.tokensIn || 0, response.tokensOut || 0);

    if (response.type === "reply") { finalReply = response.content || ""; break; }

    if (response.type === "tool_calls" && response.toolCalls) {
      const toolResult = await _dispatchToolCalls({ response, conversationMessages, allToolCalls, allowlist, cwd, deps, effectiveMaxToolCalls });
      if (toolResult.done) { truncated = toolResult.truncated; finalReply = toolResult.finalReply; break; }
      continue;
    }
    finalReply = response.content || "";
    break;
  }

  if (!finalReply && iterationCount >= maxIterations) { truncated = true; finalReply = "(tool budget exceeded — partial response)"; }
  return { allToolCalls, totalTokensIn, totalTokensOut, totalCostUSD, finalReply, truncated, currentTier: _currentTier, currentModel: _currentModel, fallbackFromTier: _fallbackFromTier };
}

async function _persistTurnToStores({ isEphemeral, effectiveSessionId, message, classification, finalReply, allToolCalls, totalTokensIn, totalTokensOut, truncated, cwd, deps }) {
  const brainDeps = { recall: deps.recall || (async () => null), remember: deps.remember || (() => ({ ok: true })), cwd };
  try {
    await appendTurn({ sessionId: effectiveSessionId, turn: { role: "turn", userMessage: message, assistantReply: finalReply, toolCalls: allToolCalls, tokensIn: totalTokensIn, tokensOut: totalTokensOut, truncated } }, brainDeps);
    await summarizeIfNeeded({ sessionId: effectiveSessionId }, brainDeps);
  } catch { /* non-fatal */ }
  if (!isEphemeral) {
    try { await storeAppendTurn(effectiveSessionId, { userMessage: message, classification, replyHash: hashReply(finalReply), toolCalls: allToolCalls }, cwd); } catch { /* non-fatal */ }
  }
}

function _notifyClassification(deps, classification) {
  try { if (typeof deps.onClassification === "function") deps.onClassification(classification); } catch { /* observer */ }
}

async function _handleOfftopicTurn({ isEphemeral, effectiveSessionId, message, classification, requestedTier, currentModel, cwd }) {
  if (!isEphemeral) {
    try { await storeAppendTurn(effectiveSessionId, { userMessage: message, classification, replyHash: hashReply(OFFTOPIC_REDIRECT), toolCalls: [] }, cwd); } catch { /* non-fatal */ }
  }
  return { reply: OFFTOPIC_REDIRECT, toolCalls: [], tokensIn: 0, tokensOut: 0, totalCostUSD: 0, truncated: false, sessionId: effectiveSessionId, requestedTier, resolvedModel: currentModel, fallbackFromTier: null, escalated: false, autoEscalated: false, fromTier: null, toTier: null, reason: null, classification: classification ?? null, relatedTurns: [] };
}

function _formatCrossRunSnap(snap) {
  if (!snap || snap.ok === false || snap.mode !== "cross-run") return;
  const cr = snap.crossRun || snap.snapshot?.crossRun || {};
  const hasAnomalies = Array.isArray(snap.anomalies) && snap.anomalies.length > 0;
  const anomalyLines = hasAnomalies
    ? snap.anomalies.slice(0, 4).map((a) => `  - ${a.code}: ${a.message || ""}`)
    : ["  (none in window)"];
  const retryFlag = cr.retryRateSpike ? " — ⚠" : "";
  const costFlag = cr.costTrend === "up" ? " — ⚠ cost" : "";
  // Build the string for parity; not injected into systemPrompt (already frozen above).
  void (`${snap.totalRuns ?? 0} runs — ${snap.failedRuns ?? 0} failed${retryFlag}${costFlag}\n${anomalyLines.join("\n")}`);
}

function _shouldPreFetchCrossRunContext(classification, message, deps) {
  return classification.lane === LANES.OPERATIONAL
    && /\b(health|audit|failure|retry|gate|slice|plan.health|watcher)\b/i.test(message)
    && !!deps.dispatcher;
}

async function _warmCrossRunContextCache({ cwd, allowlist, deps }) {
  const watchResult = await invokeAllowlisted(
    { tool: "forge_watch", args: { targetPath: cwd || ".", mode: "cross-run" }, cwd },
    { resolvedAllowlist: allowlist, dispatcher: deps.dispatcher, hub: deps.hub || null },
  );
  _formatCrossRunSnap(watchResult?.result ?? watchResult);
}

async function _preFetchCrossRunContext({ classification, message, cwd, allowlist, deps }) {
  if (!_shouldPreFetchCrossRunContext(classification, message, deps)) return;
  // Behavioral parity: original code fetched cross-run context here but systemPrompt was already built.
  // The fetch is preserved for side-effects (watcher cache warm-up); result is not injected.
  try {
    await _warmCrossRunContextCache({ cwd, allowlist, deps });
  } catch { /* non-fatal */ }
}

function _emitTurnComplete(hub, payload) {
  if (hub && typeof hub.broadcast === "function") hub.broadcast({ type: "forge-master.turn-complete", source: "forge-master", worker: "forge-master-reasoning", ...payload });
}

// ─── Main Reasoning Loop ────────────────────────────────────────────

/**
 * Run a single reasoning turn: classify → retrieve → loop → reply.
 *
 * @param {{
 *   message: string,
 *   sessionId?: string,
 *   maxToolCalls?: number,
 *   cwd?: string,
 *   tier?: "low"|"medium"|"high",
 *   model?: string,
 * }} input
 * @param {{
 *   provider?: { sendTurn: Function },
 *   dispatcher?: Function,
 *   hub?: { broadcast: Function } | null,
 *   toolMetadata?: Record<string, object>,
 *   callApiWorker?: Function,
 *   detectApiProvider?: Function,
 *   resolveApiKey?: (provider: string) => string | null,
 *   forceKeywordOnly?: boolean, — when true, skip stage-2 router-model in classify()
 *   resolvedAllowlist?: string[], — override computed allowlist (test injection)
 *   sessionId?: string, — file-based session store ID; "ephemeral" suppresses disk writes
 * }} [deps] — injected dependencies for testability
 * @returns {Promise<{
 *   reply: string,
 *   toolCalls: Array<{name: string, args: object, resultSummary: string, costUSD: number}>,
 *   tokensIn: number,
 *   tokensOut: number,
 *   totalCostUSD: number,
 *   truncated: boolean,
 *   error?: string,
 *   requestedTier: string|null,
 *   resolvedModel: string|null,
 *   fallbackFromTier: string|null,
 *   escalated: boolean,
 *   autoEscalated: boolean,
 *   fromTier: string|null,
 *   toTier: string|null,
 *   reason: string|null,
 *   relatedTurns: Array<{turnId:string,sessionId:string,timestamp:string,userMessage:string,lane:string,replyHash:string,score:number}>,
 * }>}
 */
export async function runTurn(input, deps = {}) {
  const { message, cwd } = input;
  const config = getForgeMasterConfig({ cwd });
  const effectiveSessionId = ensureSessionId(deps.sessionId ?? input.sessionId);
  const isEphemeral = !effectiveSessionId || effectiveSessionId === "ephemeral";

  const priorTurns = await _loadPriorTurns(effectiveSessionId, isEphemeral, cwd);
  const tierState = _resolveTierState(input, config);
  const { inputModel, requestedTier } = tierState;
  let { currentTier, currentModel } = tierState;

  // ── 1. Intent classification ──────────────────────────────────────
  const classification = await classify(message, { cwd, keywordOnly: deps.forceKeywordOnly || false, callApiWorker: deps.callApiWorker, detectApiProvider: deps.detectApiProvider, priorTurns });
  _notifyClassification(deps, classification);

  if (classification.lane === LANES.OFFTOPIC) {
    return _handleOfftopicTurn({ isEphemeral, effectiveSessionId, message, classification, requestedTier, currentModel, cwd });
  }

  // ── Auto-escalation ───────────────────────────────────────────────
  const esc = _applyAutoEscalation({ inputModel: inputModel, currentTier: currentTier, currentModel: currentModel, config: config, classification: classification });
  currentTier = esc.currentTier;
  currentModel = esc.currentModel;
  const { autoEscalated, autoFromTier, autoToTier, autoEscalationReason } = esc;

  // ── 2. Build context block (memory, recall, patterns, prior turns) ─
  const { contextBlock, relatedTurns } = await _buildContextBlock({ effectiveSessionId, isEphemeral, classification, message, cwd, priorTurns, deps });

  // ── 3. Load system prompt ─────────────────────────────────────────
  const systemPrompt = loadSystemPrompt(contextBlock, _loadPrinciplesBlock(cwd));

  // ── 4. Resolve allowlist + tool schemas ───────────────────────────
  const allowlist = deps.resolvedAllowlist ?? resolveAllowlist({ toolMetadata: deps.toolMetadata || {}, discoverExtensionTools: config.discoverExtensionTools });
  const toolSchemas = buildToolSchemas(allowlist);

  // ── 4a. Cross-run watcher pre-fetch (operational lane parity) ─────
  await _preFetchCrossRunContext({ classification, message, cwd, allowlist, deps });

  // ── 5. Resolve provider + API key ─────────────────────────────────
  const provider = await _resolveProvider(config, deps);
  if (!provider) {
    return { reply: "", toolCalls: [], tokensIn: 0, tokensOut: 0, totalCostUSD: 0, truncated: false, error: "no provider available", suggestion: NO_PROVIDER_SUGGESTION, sessionId: effectiveSessionId, requestedTier, resolvedModel: currentModel, fallbackFromTier: null, escalated: false, autoEscalated, fromTier: autoFromTier, toTier: autoToTier, reason: autoEscalationReason, classification: classification ?? null, relatedTurns };
  }
  const apiKey = _resolveApiKey(config, deps);

  // ── 6a. Proactive planner + executor ──────────────────────────────
  const plannerOut = await _runPlannerPhase({ provider, currentModel, apiKey, message, classification, allowlist, cwd, deps, systemPrompt });
  const allToolCalls = [...plannerOut.plannerToolCalls];
  const effectiveMaxToolCalls = Math.min(input.maxToolCalls ?? config.maxToolCalls, ABSOLUTE_CEILING);

  // ── 6b. Quorum advisory fan-out ───────────────────────────────────
  const quorumOut = await _runQuorumAdvisory({ deps, classification, message, systemPrompt, autoEscalated, autoToTier });

  // ── 7. Tool-use loop ──────────────────────────────────────────────
  const conversationMessages = [{ role: "system", content: systemPrompt }, { role: "user", content: message }];
  if (plannerOut.plannerSynthesis) {
    conversationMessages.push({ role: "user", content: `The following tool results were pre-fetched to help answer the query:\n\n${plannerOut.plannerSynthesis}\n\nUse these results to formulate your response. You may call additional tools if needed.` });
  }

  const loopResult = await _executeToolUseLoop({ provider, conversationMessages, toolSchemas, maxIterations: effectiveMaxToolCalls + 1, effectiveMaxToolCalls, allowlist, cwd, deps, config, currentTier, currentModel, apiKey, fallbackFromTier: null, allToolCalls, totalTokensIn: plannerOut.tokensIn, totalTokensOut: plannerOut.tokensOut, totalCostUSD: plannerOut.costUSD + quorumOut.costUSD });

  if (loopResult.earlyError) {
    return { reply: loopResult.finalReply || "", toolCalls: loopResult.allToolCalls, tokensIn: loopResult.totalTokensIn, tokensOut: loopResult.totalTokensOut, totalCostUSD: loopResult.totalCostUSD, truncated: false, error: loopResult.earlyError, sessionId: effectiveSessionId, requestedTier, resolvedModel: loopResult.currentModel, fallbackFromTier: loopResult.fallbackFromTier, escalated: false, autoEscalated, fromTier: autoFromTier, toTier: autoToTier, reason: autoEscalationReason, classification: classification ?? null, relatedTurns };
  }

  // ── 8. Persist + emit ─────────────────────────────────────────────
  await _persistTurnToStores({ isEphemeral, effectiveSessionId, message, classification, finalReply: loopResult.finalReply, allToolCalls: loopResult.allToolCalls, totalTokensIn: loopResult.totalTokensIn, totalTokensOut: loopResult.totalTokensOut, truncated: loopResult.truncated, cwd, deps });
  _emitTurnComplete(deps.hub, { tokensIn: loopResult.totalTokensIn, tokensOut: loopResult.totalTokensOut, toolCallCount: loopResult.allToolCalls.length, truncated: loopResult.truncated, sessionId: effectiveSessionId, timestamp: new Date().toISOString() });

  return {
    reply: loopResult.finalReply,
    toolCalls: loopResult.allToolCalls,
    tokensIn: loopResult.totalTokensIn,
    tokensOut: loopResult.totalTokensOut,
    totalCostUSD: loopResult.totalCostUSD,
    truncated: loopResult.truncated,
    sessionId: effectiveSessionId,
    requestedTier,
    resolvedModel: loopResult.currentModel,
    fallbackFromTier: loopResult.fallbackFromTier,
    escalated: false,
    autoEscalated,
    fromTier: autoFromTier,
    toTier: autoToTier,
    reason: autoEscalationReason,
    classification: classification ?? null,
    relatedTurns,
    quorumResult: quorumOut.quorumResult,
  };
}

// ─── Observer Reasoning Turn ────────────────────────────────────────

function getObserverBudgetFns(opts) {
  return {
    checkBudgetFn: opts._checkBudget ?? checkBudget,
    recordSpendFn: opts._recordSpend ?? recordSpend,
    loadBudgetStateFn: opts._loadBudgetState ?? loadBudgetState,
    saveBudgetStateFn: opts._saveBudgetState ?? saveBudgetState,
  };
}

function resolveObserverConfigBlock(config) {
  return config?.observer && typeof config.observer === "object"
    ? config.observer
    : config;
}

function buildObserverCaps(observerConfig) {
  return {
    maxUsdPerDay: observerConfig.maxUsdPerDay ?? 1.0,
    maxNarrationsPerHour: observerConfig.maxNarrationsPerHour ?? 6,
  };
}

function blockObserverBudget(hub, budgetCheck) {
  console.error(`[observer] budget block: ${budgetCheck.reason}`);
  if (hub && typeof hub.broadcast === "function") {
    hub.broadcast({
      type: "observer:budget-blocked",
      reason: budgetCheck.reason,
      timestamp: new Date().toISOString(),
    });
  }
  return { ok: false, skipped: true, reason: budgetCheck.reason, narration: null };
}

function checkObserverBudgetGate({ opts, cwd, loadBudgetStateFn, checkBudgetFn, caps, hub }) {
  const state = opts.budgetState ?? loadBudgetStateFn({ cwd });
  const budgetCheck = checkBudgetFn(state, caps);
  if (!budgetCheck.ok) {
    return { state: null, blocked: blockObserverBudget(hub, budgetCheck) };
  }
  return { state, blocked: null };
}

async function resolveObserverProvider(opts, config) {
  return opts.provider ?? autoSelectProvider(config, process.env, opts._providers ?? null);
}

function resolveObserverModel(config, observerConfig) {
  const modelTier = observerConfig.modelTier ?? null;
  return (modelTier ? resolveModel(modelTier, config) : null)
    ?? config?.reasoningModel
    ?? null;
}

async function callObserverModel(provider, resolvedModel, batch) {
  const { systemPrompt, userMessage } = buildObserverPrompt(batch);
  return provider.sendTurn({
    messages: [
      { role: "system", content: systemPrompt },
      { role: "user", content: userMessage },
    ],
    tools: buildToolSchemas(OBSERVER_TOOL_ALLOWLIST),
    model: resolvedModel,
    apiKey: "",
  });
}

function saveObserverBudgetState(saveBudgetStateFn, updatedState, cwd) {
  try {
    saveBudgetStateFn(updatedState, { cwd });
  } catch (err) {
    console.error(`[observer] budget state save failed (non-fatal): ${err?.message ?? err}`);
  }
}

function captureObserverNarration({ observerConfig, rememberFn, batch, narration, usd }) {
  if (observerConfig.brainCapture === false || typeof rememberFn !== "function") return;

  try {
    const captureKey = `project.observer.narration-${Date.now()}`;
    rememberFn(captureKey, {
      timestamp: new Date().toISOString(),
      narration,
      batchEventCount: Array.isArray(batch) ? batch.length : 0,
      usd,
    });
  } catch (err) {
    console.error(`[observer] brain capture failed (non-fatal): ${err?.message ?? err}`);
  }
}

function emitObserverNarration({ hub, batch, narration, usd, observerConfig }) {
  if (!hub || typeof hub.broadcast !== "function") return;

  hub.broadcast({
    type: OBSERVER_NARRATION_EVENT_TYPE,
    timestamp: new Date().toISOString(),
    batchEventCount: Array.isArray(batch) ? batch.length : 0,
    narration,
    usd,
    modelTier: observerConfig.modelTier ?? null,
  });
}

/**
 * Run a single observer narration turn: check budget → call model → capture → emit.
 *
 * Called by the observer loop's `onBatch` callback once per batch flush.
 * The function is strictly fail-closed on budget: it MUST NOT make any LLM call
 * when `checkBudget()` returns `{ ok: false }`.
 *
 * @param {object[]} batch  Hub events from observer-loop's batch flush.
 * @param {{
 *   config?: object,            Forge-Master config (getForgeMasterConfig() result).
 *                               Reads: config.observer.{maxUsdPerDay, maxNarrationsPerHour,
 *                                      modelTier, brainCapture}, config.reasoningModel.
 *   provider?: object,          Pre-resolved provider adapter with sendTurn(). Auto-selected if absent.
 *   hub?: object|null,          Hub for broadcasting observer:narration + observer:budget-blocked.
 *   cwd?: string,               Working directory (for budget state I/O and provider auto-select).
 *   remember?: Function,        brain.remember-compatible fn for L2 narration capture (optional).
 *   budgetState?: object,       Pre-loaded budget state (test injection — skips loadBudgetState).
 *   _checkBudget?: Function,    checkBudget override for testing.
 *   _recordSpend?: Function,    recordSpend override for testing.
 *   _loadBudgetState?: Function loadBudgetState override for testing.
 *   _saveBudgetState?: Function saveBudgetState override for testing.
 * }} [opts]
 * @returns {Promise<{
 *   ok: boolean,
 *   skipped?: boolean,    true when budget blocked (no LLM call occurred)
 *   reason?: string,      human-readable block/error reason
 *   narration?: string|null,
 *   tokensIn?: number,
 *   tokensOut?: number,
 *   usd?: number,
 * }>}
 */
export async function runObserverTurn(batch, opts = {}) {
  const {
    config = {},
    hub = null,
    cwd = process.cwd(),
    remember: _remember = null,
  } = opts;
  const { checkBudgetFn, recordSpendFn, loadBudgetStateFn, saveBudgetStateFn } = getObserverBudgetFns(opts);
  const observerConfig = resolveObserverConfigBlock(config);
  const budgetGate = checkObserverBudgetGate(
    { opts: opts, cwd: cwd, loadBudgetStateFn: loadBudgetStateFn, checkBudgetFn: checkBudgetFn, caps: buildObserverCaps(observerConfig), hub: hub },
  );

  if (budgetGate.blocked) {
    return budgetGate.blocked;
  }

  const provider = await resolveObserverProvider(opts, config);
  if (!provider) {
    return { ok: false, skipped: false, reason: "no provider available", narration: null };
  }

  const resolvedModel = resolveObserverModel(config, observerConfig);

  let response;
  try {
    response = await callObserverModel(provider, resolvedModel, batch);
  } catch (err) {
    return {
      ok: false,
      skipped: false,
      reason: `model error: ${err?.message ?? String(err)}`,
      narration: null,
    };
  }

  const narration = response.content || "";
  const tokensIn = response.tokensIn || 0;
  const tokensOut = response.tokensOut || 0;
  const usd = computeTurnCost(resolvedModel, tokensIn, tokensOut);
  const updatedState = recordSpendFn(budgetGate.state, { usd, timestamp: Date.now() });

  saveObserverBudgetState(saveBudgetStateFn, updatedState, cwd);
  captureObserverNarration({ observerConfig: observerConfig, rememberFn: _remember, batch: batch, narration: narration, usd: usd });
  emitObserverNarration({ hub: hub, batch: batch, narration: narration, usd: usd, observerConfig: observerConfig });

  return { ok: true, narration, tokensIn, tokensOut, usd };
}

/**
 * Plan Forge — Forge-Master Cross-Session Recall Index (Phase-38.2).
 *
 * Builds and queries a BM25 index over past fm-session JSONL files so
 * `runTurn` can surface related prior interactions for operational,
 * troubleshoot, and advisory lanes.
 *
 * Index file: `.forge/fm-sessions/recall-index.json`
 *   { version, projectDir, lastBuiltAt, docs: [...], idf: {...} }
 *
 * Turn doc shape in index:
 *   { turnId, sessionId, timestamp, userMessage, lane, replyHash }
 *
 * BM25 parameters: k1 = 1.5, b = 0.75 (standard TREC defaults)
 *
 * Exports:
 *   buildIndex(projectDir) → Promise<void>
 *   loadIndex(projectDir)  → Promise<void>   (lazy refresh by staleness)
 *   queryIndex(text, opts) → Promise<Array<RecallHit>>
 *
 * @module forge-master/recall-index
 */

import { mkdir, readFile, writeFile, readdir, stat } from "node:fs/promises";
import { join } from "node:path";

// ─── BM25 constants ──────────────────────────────────────────────────

const K1 = 1.5;
const B = 0.75;
const INDEX_VERSION = 1;
const MIN_QUERY_TOKENS = 3;

// ─── Path helpers ────────────────────────────────────────────────────

function sessionsDir(projectDir) {
  return join(projectDir || process.cwd(), ".forge", "fm-sessions");
}

function indexPath(projectDir) {
  return join(sessionsDir(projectDir), "recall-index.json");
}

// ─── Tokenizer ───────────────────────────────────────────────────────

/**
 * Tokenize a string into lowercase terms.
 * Splits on whitespace and punctuation, but also expands hyphenated/dotted
 * Plan Forge terms (e.g. "meta-bug-triage" → ["meta", "bug", "triage", "meta-bug-triage"]).
 *
 * @param {string} text
 * @returns {string[]}
 */
function tokenize(text) {
  if (!text || typeof text !== "string") return [];
  const lower = text.toLowerCase();
  // Split on whitespace and common delimiters
  const parts = lower.split(/[\s/\\,;|]+/).filter(Boolean);
  const tokens = new Set();
  for (const part of parts) {
    // Add the whole part (may include hyphens/dots — Plan Forge IDs)
    if (part.length > 0) tokens.add(part);
    // Also split on hyphens and dots for sub-term matching
    const sub = part.split(/[-.]/).filter((s) => s.length > 1);
    for (const s of sub) tokens.add(s);
  }
  return [...tokens];
}

// ─── Per-projectDir build mutex ──────────────────────────────────────

const _buildInFlight = new Map();

// ─── JSONL reader ────────────────────────────────────────────────────

async function readJsonlFile(filePath) {
  try {
    const text = await readFile(filePath, "utf-8");
    const lines = [];
    for (const line of text.split("\n")) {
      const trimmed = line.trim();
      if (!trimmed) continue;
      try { lines.push(JSON.parse(trimmed)); } catch { /* skip malformed */ }
    }
    return lines;
  } catch {
    return [];
  }
}

// ─── Module-level index cache (by projectDir) ───────────────────────

const _indexCache = new Map(); // projectDir → { index, mtime }

// ─── Build ───────────────────────────────────────────────────────────

/**
 * Build (or rebuild) the BM25 recall index from all active + archive
 * JSONL files in `.forge/fm-sessions/`, excluding OFFTOPIC turns.
 * Writes result to `.forge/fm-sessions/recall-index.json`.
 * Concurrent calls for the same projectDir are serialized.
 *
 * @param {string} [projectDir] — defaults to process.cwd()
 */
export async function buildIndex(projectDir = process.cwd()) {
  // Serialize concurrent builds for the same project
  const prev = _buildInFlight.get(projectDir) || Promise.resolve();
  let resolveBuild;
  const thisBuild = new Promise((res) => { resolveBuild = res; });
  _buildInFlight.set(projectDir, thisBuild);

  try {
    await prev;
    await _doBuild(projectDir);
  } finally {
    resolveBuild();
    if (_buildInFlight.get(projectDir) === thisBuild) {
      _buildInFlight.delete(projectDir);
    }
  }
}

async function _doBuild(projectDir) {
  const dir = sessionsDir(projectDir);
  await mkdir(dir, { recursive: true });

  // Enumerate session files (active + archive, not the index itself)
  let files = [];
  try {
    const entries = await readdir(dir);
    files = entries
      .filter((f) => f.endsWith(".jsonl") && f !== "recall-index.json")
      .map((f) => join(dir, f));
  } catch {
    files = [];
  }

  // Parse all turns
  const docs = [];
  for (const file of files) {
    const sessionId = _sessionIdFromFile(file);
    if (!sessionId) continue;
    const turns = await readJsonlFile(file);
    for (const turn of turns) {
      // Skip OFFTOPIC turns — they are noise
      if (turn.classification?.lane === "offtopic") continue;
      if (!turn.userMessage) continue;
      const turnId = `${sessionId}:${turn.turn ?? docs.length}`;
      docs.push({
        turnId,
        sessionId,
        timestamp: turn.timestamp || "",
        userMessage: turn.userMessage,
        lane: turn.classification?.lane || "unknown",
        replyHash: turn.replyHash || "",
        _tokens: tokenize(turn.userMessage),
      });
    }
  }

  // Build IDF table
  const df = {};
  for (const doc of docs) {
    const seen = new Set(doc._tokens);
    for (const t of seen) {
      df[t] = (df[t] || 0) + 1;
    }
  }
  const N = docs.length;
  const idf = {};
  for (const [t, freq] of Object.entries(df)) {
    idf[t] = Math.log((N - freq + 0.5) / (freq + 0.5) + 1);
  }

  // Compute average doc length
  const avgdl = docs.length > 0
    ? docs.reduce((s, d) => s + d._tokens.length, 0) / docs.length
    : 1;

  const index = {
    version: INDEX_VERSION,
    projectDir,
    lastBuiltAt: new Date().toISOString(),
    avgdl,
    idf,
    docs: docs.map(({ _tokens, ...rest }) => ({ ...rest, dl: _tokens.length, termFreq: _termFreq(_tokens) })),
  };

  // Atomic write via tmp file + rename
  const target = indexPath(projectDir);
  const tmp = target + ".tmp";
  await writeFile(tmp, JSON.stringify(index), "utf-8");
  await writeFile(target, JSON.stringify(index), "utf-8"); // direct write (Windows lacks atomic rename to existing)

  // Update in-memory cache
  _indexCache.set(projectDir, { index, mtime: Date.now() });
}

function _termFreq(tokens) {
  const tf = {};
  for (const t of tokens) tf[t] = (tf[t] || 0) + 1;
  return tf;
}

function _sessionIdFromFile(filePath) {
  const base = filePath.replace(/\\/g, "/").split("/").pop() || "";
  if (base.endsWith(".archive.jsonl")) return base.slice(0, -".archive.jsonl".length);
  if (base.endsWith(".jsonl")) return base.slice(0, -".jsonl".length);
  return null;
}

// ─── Load (lazy refresh) ─────────────────────────────────────────────

/**
 * Load the recall index from disk, rebuilding if absent or stale.
 * Staleness = any session JSONL file is newer than the index, OR
 * the index was built on a prior calendar day, OR the index file is absent.
 *
 * @param {string} [projectDir]
 */
export async function loadIndex(projectDir = process.cwd()) {
  const path = indexPath(projectDir);

  // Check in-memory cache freshness first
  const cached = _indexCache.get(projectDir);

  let indexStat = null;
  try { indexStat = await stat(path); } catch { /* absent */ }

  if (!indexStat) {
    // Index absent — build it
    await buildIndex(projectDir);
    return;
  }

  // Stale if last-built is a prior calendar day
  let existingIndex = null;
  try {
    const raw = await readFile(path, "utf-8");
    existingIndex = JSON.parse(raw);
  } catch {
    await buildIndex(projectDir);
    return;
  }

  const builtDate = existingIndex.lastBuiltAt
    ? existingIndex.lastBuiltAt.slice(0, 10)
    : "";
  const today = new Date().toISOString().slice(0, 10);
  if (builtDate !== today) {
    await buildIndex(projectDir);
    return;
  }

  // Stale if any session file is newer than the index
  const dir = sessionsDir(projectDir);
  let sessionFiles = [];
  try {
    const entries = await readdir(dir);
    sessionFiles = entries
      .filter((f) => f.endsWith(".jsonl") && f !== "recall-index.json")
      .map((f) => join(dir, f));
  } catch { /* no sessions */ }

  for (const f of sessionFiles) {
    try {
      const s = await stat(f);
      if (s.mtimeMs > indexStat.mtimeMs) {
        await buildIndex(projectDir);
        return;
      }
    } catch { /* skip */ }
  }

  // Index is fresh — load into cache if not already there
  if (!cached) {
    _indexCache.set(projectDir, { index: existingIndex, mtime: indexStat.mtimeMs });
  }
}

// ─── Query ───────────────────────────────────────────────────────────

/**
 * Query the recall index with BM25 ranking.
 * Returns up to `topK` results sorted by descending score.
 * Returns [] when the query is too short (< 3 tokens) or the index is empty.
 *
 * @param {string} text
 * @param {{ topK?: number, projectDir?: string }} [opts]
 * @returns {Promise<Array<{turnId,sessionId,timestamp,userMessage,lane,replyHash,score}>>}
 */
export async function queryIndex(text, opts = {}) {
  const { topK = 3, projectDir = process.cwd() } = opts;

  const queryTokens = tokenize(text);
  if (queryTokens.length < MIN_QUERY_TOKENS) return [];

  // Ensure cache is populated
  await loadIndex(projectDir);
  const cached = _indexCache.get(projectDir);
  if (!cached) return [];

  const { index } = cached;
  if (!index || !index.docs || index.docs.length === 0) return [];

  const { docs, idf, avgdl } = index;

  const scores = docs.map((doc) => {
    let score = 0;
    for (const qt of queryTokens) {
      const idfScore = idf[qt] || 0;
      if (idfScore === 0) continue;
      const tf = doc.termFreq?.[qt] || 0;
      if (tf === 0) continue;
      const dl = doc.dl || 1;
      const norm = tf * (K1 + 1) / (tf + K1 * (1 - B + B * dl / (avgdl || 1)));
      score += idfScore * norm;
    }
    return { doc, score };
  });

  return scores
    .filter((s) => s.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, topK)
    .map(({ doc, score }) => ({
      turnId: doc.turnId,
      sessionId: doc.sessionId,
      timestamp: doc.timestamp,
      userMessage: doc.userMessage,
      lane: doc.lane,
      replyHash: doc.replyHash,
      score,
    }));
}

/** For testing only — clears the in-memory index cache. */
export function _resetIndexCache() {
  _indexCache.clear();
}

/**
 * Plan Forge — Forge-Master Memory Retrieval (Phase-28, Slice 3).
 *
 * Reads L1 session history, L2 project digests, L3 cross-project topics;
 * formats into a markdown block capped at 4000 tokens; truncates by
 * dropping sections in order L3 → L2 → L1 (least-specific first).
 *
 * The returned `contextBlock` is the *body* only — the system prompt
 * already contains the `## Current Context` heading and `{context_block}`
 * placeholder.
 *
 * @module forge-master/retrieval
 */

import { recall } from "../../pforge-mcp/brain.mjs";
import { getForgeMasterConfig } from "./config.mjs";

// ─── Constants ──────────────────────────────────────────────────────

const TOKEN_CAP = 4000;
const CHARS_PER_TOKEN = 4;
const CHAR_CAP = TOKEN_CAP * CHARS_PER_TOKEN;

// L1 keys — session-scoped, need runId
const L1_KEYS = Object.freeze([
  "session.history",
  "session.context",
]);

// L2 keys per lane — only fetch what's relevant
const L2_KEYS_BY_LANE = Object.freeze({
  build:        ["project.run.latest", "project.crucible"],
  operational:  ["project.run.latest", "project.tempering.state"],
  troubleshoot: ["project.run.latest", "project.tempering.state", "project.liveguard.incidents"],
  offtopic:     ["project.run.latest"],
  advisory:     ["project.run.latest", "project.tempering.state"],
});
const L2_KEYS_DEFAULT = Object.freeze(["project.run.latest", "project.tempering.state"]);

// L3 keys — cross-project, only when l3Enabled
const L3_KEYS = Object.freeze([
  "cross.pattern.recent",
  "cross.convention.recent",
]);

// ─── Summarizers ────────────────────────────────────────────────────

function summarizeValue(key, value) {
  if (value == null) return null;
  if (typeof value === "string") return value;
  if (Array.isArray(value)) {
    if (value.length === 0) return null;
    const items = value.slice(-5); // keep most recent entries
    return items.map((v) => (typeof v === "string" ? v : JSON.stringify(v))).join("\n");
  }
  // Objects — extract summary fields if available, else compact JSON
  if (typeof value === "object") {
    if (value.summary) return String(value.summary);
    if (value.status && value.plan) {
      return `Plan: ${value.plan} | Status: ${value.status}`;
    }
    const json = JSON.stringify(value, null, 0);
    return json.length > 500 ? json.slice(0, 497) + "..." : json;
  }
  return String(value);
}

// ─── Token Estimation ───────────────────────────────────────────────

function estimateTokens(text) {
  return Math.ceil(text.length / CHARS_PER_TOKEN);
}

// ─── Section Builder ────────────────────────────────────────────────

function buildSection(tier, entries) {
  const filtered = entries.filter((e) => e.text != null);
  if (filtered.length === 0) return null;
  const label = tier === "l1" ? "Session" : tier === "l2" ? "Project" : "Cross-Project";
  const lines = [`### ${label}`, ""];
  for (const { key, text } of filtered) {
    lines.push(`**${key}**: ${text}`);
  }
  return lines.join("\n");
}

// ─── Truncation ─────────────────────────────────────────────────────

/**
 * Truncate sections to fit within CHAR_CAP.
 * Drops sections in order: L3 → L2 → L1 (least-specific first).
 * Within a section, drops oldest entries first.
 */
function truncateSections(l1Section, l2Section, l3Section) {
  const sections = [];
  if (l3Section) sections.push({ tier: "l3", text: l3Section });
  if (l2Section) sections.push({ tier: "l2", text: l2Section });
  if (l1Section) sections.push({ tier: "l1", text: l1Section });

  let total = sections.reduce((sum, s) => sum + s.text.length, 0);

  // Drop whole sections from the front (L3 first, then L2) until we fit
  while (total > CHAR_CAP && sections.length > 1) {
    const dropped = sections.shift();
    total -= dropped.text.length;
  }

  // If still over cap, hard-truncate the remaining section
  if (total > CHAR_CAP && sections.length === 1) {
    sections[0].text = sections[0].text.slice(0, CHAR_CAP - 20) + "\n\n*(truncated)*";
  }

  // Rebuild in display order: L1 → L2 → L3
  const ordered = [];
  for (const tier of ["l1", "l2", "l3"]) {
    const found = sections.find((s) => s.tier === tier);
    if (found) ordered.push(found.text);
  }
  return ordered.join("\n\n");
}

// ─── Public API ─────────────────────────────────────────────────────

async function collectContextEntries({ keys, doRecall, recallArgs, cwd, sourceBucket }) {
  const entries = [];

  for (const key of keys) {
    try {
      const value = await doRecall(key, recallArgs(key), { cwd });
      const text = summarizeValue(key, value);
      if (text) {
        entries.push({ key, text });
        sourceBucket.push(key);
      }
    } catch { /* non-fatal — best-effort retrieval */ }
  }

  return entries;
}

function buildHubEventsSection(hubSubscriber) {
  if (!hubSubscriber) return null;

  const events = hubSubscriber.getRecentEvents(10);
  if (events.length === 0) return null;

  const lines = ["### Recent Operational Events", ""];
  for (const ev of events) {
    const ts = ev.timestamp ? ` (${ev.timestamp})` : "";
    const detail = ev.sliceId
      ? ` — ${ev.sliceId}`
      : ev.runId ? ` — run:${ev.runId}` : "";
    lines.push(`- **${ev.type}**${detail}${ts}`);
  }
  return lines.join("\n");
}

/**
 * Fetch context from all brain tiers and format as a markdown block.
 *
 * @param {{ sessionId?: string, lane?: string, cwd?: string }} opts
 * @param {{ recall?: Function, getForgeMasterConfig?: Function }} [deps] — DI overrides
 * @returns {Promise<{ contextBlock: string, sources: { l1: string[], l2: string[], l3: string[] } }>}
 */
export async function fetchContext(opts = {}, deps = {}) {
  const { sessionId, lane, cwd } = opts;
  const doRecall = deps.recall || recall;
  const getConfig = deps.getForgeMasterConfig || getForgeMasterConfig;
  const config = getConfig({ cwd });
  const sources = { l1: [], l2: [], l3: [] };

  const l1Entries = await collectContextEntries(
    { keys: L1_KEYS, doRecall: doRecall, recallArgs: () => ({ runId: sessionId }), cwd: cwd, sourceBucket: sources.l1 },
  );
  const l2Entries = await collectContextEntries(
    { keys: L2_KEYS_BY_LANE[lane] || L2_KEYS_DEFAULT, doRecall: doRecall, recallArgs: () => ({}), cwd: cwd, sourceBucket: sources.l2 },
  );
  const l3Entries = config.l3Enabled
    ? await collectContextEntries({ keys: L3_KEYS, doRecall: doRecall, recallArgs: () => ({ scope: "cross" }), cwd: cwd, sourceBucket: sources.l3 })
    : [];

  let contextBlock = truncateSections(
    buildSection("l1", l1Entries),
    buildSection("l2", l2Entries),
    buildSection("l3", l3Entries),
  );
  const hubSection = buildHubEventsSection(deps.hubSubscriber);

  if (hubSection) {
    contextBlock = contextBlock ? `${contextBlock}\n\n${hubSection}` : hubSection;
  }

  return { contextBlock, sources };
}

// Exported for testing
export { TOKEN_CAP, CHARS_PER_TOKEN, L1_KEYS, L2_KEYS_BY_LANE, L3_KEYS, estimateTokens, summarizeValue };

/**
 * Plan Forge — Forge-Master Session Store (Phase-38.1).
 *
 * Persists per-session conversation turns as JSONL files under
 * `.forge/fm-sessions/` in the project directory.
 *
 * Turn record schema:
 *   { turn, timestamp, userMessage, classification, replyHash, toolCalls }
 *
 * Storage behaviour:
 *   - Active file:  `.forge/fm-sessions/<sessionId>.jsonl`
 *   - Archive file: `.forge/fm-sessions/<sessionId>.archive.jsonl`
 *   - When active turn count ≥ 200, oldest 100 turns are moved to archive.
 *   - Session files are never committed — `.forge/` is gitignored.
 *
 * Exports:
 *   - appendTurn(sessionId, record, cwd?)  → void
 *   - loadSession(sessionId, cwd?)         → TurnRecord[]
 *   - purgeSession(sessionId, cwd?)        → void
 *   - rotateIfNeeded(sessionId, cwd?)      → void
 *
 * @module forge-master/session-store
 */

import { createHash } from "node:crypto";
import { mkdir, readFile, appendFile, writeFile, unlink } from "node:fs/promises";
import { join } from "node:path";

// ─── Validation ──────────────────────────────────────────────────────

/** Allowed characters in a session ID to prevent path traversal. */
const VALID_SESSION_ID_RE = /^[A-Za-z0-9._-]+$/;

function assertSessionId(sessionId) {
  if (!sessionId || typeof sessionId !== "string") {
    throw new Error(`session-store: sessionId must be a non-empty string`);
  }
  if (!VALID_SESSION_ID_RE.test(sessionId)) {
    throw new Error(`session-store: invalid sessionId "${sessionId}" — only [A-Za-z0-9._-] allowed`);
  }
}

// ─── Path helpers ────────────────────────────────────────────────────

function sessionsDir(cwd) {
  return join(cwd || process.cwd(), ".forge", "fm-sessions");
}

function activePath(sessionId, cwd) {
  assertSessionId(sessionId);
  return join(sessionsDir(cwd), `${sessionId}.jsonl`);
}

function archivePath(sessionId, cwd) {
  assertSessionId(sessionId);
  return join(sessionsDir(cwd), `${sessionId}.archive.jsonl`);
}

// ─── Per-session mutex ───────────────────────────────────────────────

const _locks = new Map();

function acquireLock(key) {
  if (!_locks.has(key)) _locks.set(key, Promise.resolve());
  let release;
  const next = new Promise((res) => { release = res; });
  const prev = _locks.get(key);
  _locks.set(key, next);
  return prev.then(() => release);
}

/** For testing only — clears all active locks. */
export function _resetLocks() {
  _locks.clear();
}

// ─── JSONL helpers ───────────────────────────────────────────────────

async function readLines(filePath) {
  try {
    const text = await readFile(filePath, "utf-8");
    const lines = [];
    for (const line of text.split("\n")) {
      const trimmed = line.trim();
      if (!trimmed) continue;
      try {
        lines.push(JSON.parse(trimmed));
      } catch { /* skip malformed lines */ }
    }
    return lines;
  } catch {
    return [];
  }
}

// ─── Internal rotate (must be called within lock) ───────────────────

async function _rotate(sessionId, cwd) {
  const active = activePath(sessionId, cwd);
  const archive = archivePath(sessionId, cwd);
  const lines = await readLines(active);
  if (lines.length < 200) return;

  const toArchive = lines.slice(0, 100);
  const toKeep = lines.slice(100);

  // Append oldest 100 to archive
  const archiveChunk = toArchive.map((r) => JSON.stringify(r)).join("\n") + "\n";
  await appendFile(archive, archiveChunk, "utf-8");

  // Rewrite active file with newest 100
  const keepContent = toKeep.map((r) => JSON.stringify(r)).join("\n") + "\n";
  await writeFile(active, keepContent, "utf-8");
}

// ─── Public API ──────────────────────────────────────────────────────

/**
 * Append a turn record to the session's JSONL file.
 * Assigns `turn` (1-based, monotonically increasing) and `timestamp` automatically.
 * Automatically rotates when the active file reaches 200 turns.
 *
 * @param {string} sessionId   — Must match [A-Za-z0-9._-]+
 * @param {object} record      — { userMessage, classification, replyHash, toolCalls }
 * @param {string} [cwd]       — project root (defaults to process.cwd())
 */
export async function appendTurn(sessionId, record, cwd = process.cwd()) {
  const path = activePath(sessionId, cwd);
  const dir = sessionsDir(cwd);
  const release = await acquireLock(sessionId);
  try {
    await mkdir(dir, { recursive: true });

    // Determine monotonic turn number from last active line
    const existing = await readLines(path);
    const lastTurn = existing.length > 0 ? (existing[existing.length - 1].turn ?? existing.length) : 0;
    const nextTurn = lastTurn + 1;

    const entry = {
      turn: nextTurn,
      timestamp: new Date().toISOString(),
      ...record,
    };

    await appendFile(path, JSON.stringify(entry) + "\n", "utf-8");

    // Auto-rotate under the same lock
    await _rotate(sessionId, cwd);
  } finally {
    release();
  }
}

/**
 * Load all turns for a session.
 * Returns `[]` when the file does not exist — never throws on missing file.
 *
 * @param {string} sessionId
 * @param {string} [cwd]
 * @returns {Promise<object[]>}
 */
export async function loadSession(sessionId, cwd = process.cwd()) {
  return readLines(activePath(sessionId, cwd));
}

/**
 * Delete the active and archive session files.
 * No-op (no error) when files do not exist.
 *
 * @param {string} sessionId
 * @param {string} [cwd]
 */
export async function purgeSession(sessionId, cwd = process.cwd()) {
  const release = await acquireLock(sessionId);
  try {
    await Promise.all([
      unlink(activePath(sessionId, cwd)).catch(() => {}),
      unlink(archivePath(sessionId, cwd)).catch(() => {}),
    ]);
  } finally {
    release();
  }
}

/**
 * Rotate the session file if it has ≥ 200 active turns.
 * Exported for external callers; `appendTurn` calls this automatically.
 *
 * @param {string} sessionId
 * @param {string} [cwd]
 */
export async function rotateIfNeeded(sessionId, cwd = process.cwd()) {
  const release = await acquireLock(sessionId);
  try {
    await _rotate(sessionId, cwd);
  } finally {
    release();
  }
}

/**
 * Compute a truncated sha256 hex hash suitable for `replyHash`.
 *
 * @param {string} text
 * @returns {string} — first 16 hex characters
 */
export function hashReply(text) {
  return createHash("sha256").update(text || "").digest("hex").slice(0, 16);
}

/**
 * Forge-Master SSE Stream Helper (Phase-29, Slice 8).
 *
 * Wraps a Node.js http.ServerResponse in a thin SSE emitter.
 *
 * @module forge-master/sse
 */

/**
 * Create an SSE stream over a Node.js http.ServerResponse.
 *
 * @param {import("node:http").ServerResponse} res
 * @returns {{ send(event: string, data: any): void, close(): void }}
 */
export function createSseStream(res) {
  res.writeHead(200, {
    "Content-Type": "text/event-stream",
    "Cache-Control": "no-cache",
    "Connection": "keep-alive",
    "Access-Control-Allow-Origin": "*",
  });

  if (typeof res.flushHeaders === "function") res.flushHeaders();

  return {
    send(event, data) {
      const payload = typeof data === "string" ? data : JSON.stringify(data);
      res.write(`event: ${event}\ndata: ${payload}\n\n`);
    },
    close() { res.end(); },
  };
}

/**
 * Plan Forge — Forge-Master Tool Bridge (Phase-28, Slice 4).
 *
 * Single choke point between the reasoning loop and the main MCP
 * dispatcher. Every tool call the frontier model requests passes
 * through here. The bridge:
 *
 *   1. Checks the resolved allowlist — rejects blocked tools.
 *   2. Invokes the tool handler via the injected dispatcher.
 *   3. Truncates the raw result to ≤2000 chars for context efficiency.
 *   4. Emits a hub event with `source: "forge-master"` for cost tagging.
 *   5. Returns `{ok, result, summary, resultFull, error?, costUSD}`.
 *
 * For multi-tool turns the caller should use `invokeMany()` which
 * runs allowlisted calls in parallel via `Promise.allSettled`.
 *
 * Exports:
 *   - invokeAllowlisted({tool, args, cwd}, deps) → result object
 *   - invokeMany(calls, deps) → result object[]
 *   - summarize(text, limit?) → string
 *   - SUMMARY_LIMIT — default truncation limit (2000)
 *
 * @module forge-master/tool-bridge
 */

import { isAllowlisted } from "./allowlist.mjs";

// ─── Constants ──────────────────────────────────────────────────────

export const SUMMARY_LIMIT = 2000;

// ─── Helpers ────────────────────────────────────────────────────────

/**
 * Truncate text to `limit` characters with an ellipsis marker when
 * the original exceeds the limit.
 *
 * @param {string} text
 * @param {number} [limit=SUMMARY_LIMIT]
 * @returns {string}
 */
export function summarize(text, limit = SUMMARY_LIMIT) {
  if (typeof text !== "string") {
    text = text == null ? "" : JSON.stringify(text);
  }
  if (text.length <= limit) return text;
  return text.slice(0, limit - 13) + " …[truncated]";
}

// ─── Single-tool invocation ─────────────────────────────────────────

/**
 * Invoke a single tool through the allowlist gate.
 *
 * @param {{ tool: string, args?: object, cwd?: string }} call
 * @param {{
 *   resolvedAllowlist: string[],
 *   dispatcher: (name: string, args: object, cwd?: string) => Promise<any>,
 *   hub?: { broadcast: (event: object) => void } | null,
 * }} deps — injected dependencies (DI for testability)
 * @returns {Promise<{
 *   ok: boolean,
 *   tool: string,
 *   result?: any,
 *   summary?: string,
 *   resultFull?: any,
 *   error?: string,
 *   costUSD?: number,
 *   source: "forge-master",
 * }>}
 */
export async function invokeAllowlisted({ tool, args = {}, cwd }, deps) {
  const { resolvedAllowlist, dispatcher, hub = null, mcpClient = null } = deps;

  // ── Allowlist gate ──
  const check = isAllowlisted(tool, resolvedAllowlist);
  if (!check.allowed) {
    const errorPayload = {
      ok: false,
      tool,
      error: "tool_not_allowlisted",
      reason: check.reason,
      source: "forge-master",
    };
    emitEvent(hub, "forge-master.tool-rejected", { tool, reason: check.reason });
    return errorPayload;
  }

  // ── Dispatch — MCP transport when client is ready, in-process otherwise ──
  const transport = mcpClient?.ready ? "mcp" : "inprocess";
  const t0 = Date.now();
  let raw;
  try {
    if (transport === "mcp") {
      raw = await mcpClient.invoke(tool, cwd ? { ...args, path: cwd } : args);
    } else {
      raw = await dispatcher(tool, args, cwd);
    }
  } catch (err) {
    const elapsed = Date.now() - t0;
    const errorPayload = {
      ok: false,
      tool,
      error: `dispatcher_error: ${err.message}`,
      transport,
      source: "forge-master",
    };
    emitEvent(hub, "forge-master.tool-error", {
      tool,
      error: err.message,
      durationMs: elapsed,
      transport,
      source: "forge-master",
    });
    return errorPayload;
  }

  const elapsed = Date.now() - t0;

  // ── Serialise raw result for summarisation ──
  const fullText = typeof raw === "string" ? raw : JSON.stringify(raw ?? "");
  const summary = summarize(fullText);

  const result = {
    ok: true,
    tool,
    result: raw,
    summary,
    resultFull: raw,
    costUSD: 0,
    transport,
    source: "forge-master",
  };

  emitEvent(hub, "forge-master.tool-complete", {
    tool,
    durationMs: elapsed,
    summaryLength: summary.length,
    truncated: fullText.length > SUMMARY_LIMIT,
    transport,
    source: "forge-master",
  });

  return result;
}

// ─── Multi-tool (parallel) invocation ───────────────────────────────

/**
 * Invoke multiple tools in parallel. Each call goes through the
 * allowlist gate individually.
 *
 * @param {Array<{ tool: string, args?: object, cwd?: string }>} calls
 * @param {object} deps — same as `invokeAllowlisted`
 * @returns {Promise<Array<object>>}
 */
export async function invokeMany(calls, deps) {
  if (!Array.isArray(calls) || calls.length === 0) return [];

  const settled = await Promise.allSettled(
    calls.map((c) => invokeAllowlisted(c, deps)),
  );

  return settled.map((s) =>
    s.status === "fulfilled"
      ? s.value
      : {
          ok: false,
          tool: "unknown",
          error: `promise_rejected: ${s.reason?.message ?? String(s.reason)}`,
          source: "forge-master",
        },
  );
}

// ─── Transport-aware dispatcher factory ─────────────────────────────

/**
 * Create a dispatcher function that routes tool calls through the MCP
 * protocol or falls back to in-process invocation.
 *
 * @param {{
 *   transport: "mcp" | "inprocess",
 *   mcpClient?: { ready: boolean, hasTool: (n: string) => boolean, invoke: (n: string, a: object) => Promise<any> } | null,
 *   fallbackDispatcher?: (name: string, args: object, cwd?: string) => Promise<any>,
 * }} opts
 * @returns {(name: string, args: object, cwd?: string) => Promise<any>}
 */
export function createDispatcher({ transport, mcpClient = null, fallbackDispatcher = null } = {}) {
  if (!transport) {
    throw new Error("createDispatcher: transport is required ('mcp' or 'inprocess')");
  }

  return async (name, args = {}, cwd) => {
    if (transport === "mcp" && mcpClient?.ready) {
      // When MCP transport is selected but the tool isn't available
      // downstream, fall back to in-process if available.
      if (!mcpClient.hasTool(name)) {
        if (fallbackDispatcher) return fallbackDispatcher(name, args, cwd);
        throw new Error(`tool '${name}' not found on downstream MCP and no fallback dispatcher`);
      }
      return mcpClient.invoke(name, args);
    }

    // transport === "inprocess", or MCP requested but client not ready
    if (fallbackDispatcher) return fallbackDispatcher(name, args, cwd);
    throw new Error(`no dispatcher available (transport=${transport}, mcpReady=${!!mcpClient?.ready})`);
  };
}

// ─── Hub event helper ───────────────────────────────────────────────

function emitEvent(hub, type, data) {
  if (!hub || typeof hub.broadcast !== "function") return;
  hub.broadcast({
    type,
    ...data,
    source: "forge-master",
    timestamp: new Date().toISOString(),
  });
}

