/**
 * Plan Forge — Anvil (Δ-only Memoization Cache)
 *
 * Provides a pure memoization wrapper (`withAnvil`) for read-only tools,
 * plus stat/clear/rebuild surface for operator visibility. Slice 1 covers
 * the core cache only — DLQ is added in Slice 2.
 *
 * On-disk layout:
 *   .forge/anvil/<toolName>/<sha256>.json   — cached payload
 *   .forge/anvil/stats.json                 — per-tool hit/miss counters
 *
 * Cache key: sha256(toolName + ":" + sha256(JSON.stringify(inputs, sortedReplacer)) + ":" + sha256(codeHashSeed))
 *
 * @module anvil
 */

import {
  existsSync, mkdirSync, readFileSync, writeFileSync,
  readdirSync, rmSync, statSync,
} from "node:fs";
import { resolve, join } from "node:path";
import { createHash, randomUUID } from "node:crypto";
import { execSync } from "node:child_process";

// ─── Helpers ─────────────────────────────────────────────────────────────────

/**
 * SHA-256 hex of a string.
 * @param {string} data
 * @returns {string}
 */
function sha256(data) {
  return createHash("sha256").update(data, "utf-8").digest("hex");
}

/**
 * JSON.stringify replacer that sorts object keys for canonical output.
 * @param {string} _key
 * @param {*} value
 * @returns {*}
 */
function sortedReplacer(_key, value) {
  if (value !== null && typeof value === "object" && !Array.isArray(value)) {
    const sorted = {};
    for (const k of Object.keys(value).sort()) {
      sorted[k] = value[k];
    }
    return sorted;
  }
  return value;
}

/**
 * Resolve the root directory for all anvil entries.
 * @param {{ cwd?: string }} deps
 * @returns {string}
 */
function anvilRoot(deps = {}) {
  const cwd = deps.cwd || process.cwd();
  return resolve(cwd, ".forge", "anvil");
}

/**
 * Path to the stats file.
 * @param {{ cwd?: string }} deps
 * @returns {string}
 */
function statsPath(deps = {}) {
  return join(anvilRoot(deps), "stats.json");
}

// ─── Stats I/O ───────────────────────────────────────────────────────────────

/**
 * Read the stats file, returning a default structure if absent.
 * @param {{ cwd?: string }} deps
 * @returns {{ perTool: Record<string, { hits: number, misses: number }> }}
 */
function readStats(deps = {}) {
  const p = statsPath(deps);
  if (!existsSync(p)) return { perTool: {} };
  try {
    return JSON.parse(readFileSync(p, "utf-8"));
  } catch {
    return { perTool: {} };
  }
}

/**
 * Persist the stats object atomically.
 * @param {{ perTool: Record<string, { hits: number, misses: number }> }} stats
 * @param {{ cwd?: string }} deps
 */
function writeStats(stats, deps = {}) {
  const p = statsPath(deps);
  mkdirSync(resolve(p, ".."), { recursive: true });
  writeFileSync(p, JSON.stringify(stats, null, 2), "utf-8");
}

/**
 * Increment a hit or miss counter for a tool.
 * @param {string} toolName
 * @param {"hit"|"miss"} kind
 * @param {{ cwd?: string }} deps
 */
function recordStat(toolName, kind, deps = {}) {
  try {
    const stats = readStats(deps);
    if (!stats.perTool[toolName]) stats.perTool[toolName] = { hits: 0, misses: 0 };
    if (kind === "hit") stats.perTool[toolName].hits++;
    else stats.perTool[toolName].misses++;
    writeStats(stats, deps);
  } catch {
    // Stats are best-effort — never block the caller
  }
}

// ─── Cache Key ───────────────────────────────────────────────────────────────

/**
 * Compute the canonical cache key.
 * @param {string} toolName
 * @param {*} inputs
 * @param {string} codeHashSeed
 * @returns {string}
 */
function computeCacheKey(toolName, inputs, codeHashSeed) {
  const inputsHash = sha256(JSON.stringify(inputs, sortedReplacer));
  const seedHash = sha256(String(codeHashSeed));
  return sha256(`${toolName}:${inputsHash}:${seedHash}`);
}

// ─── Entry I/O ───────────────────────────────────────────────────────────────

/**
 * Resolve the path for a given toolName + key.
 * @param {string} toolName
 * @param {string} key
 * @param {{ cwd?: string }} deps
 * @returns {string}
 */
function entryPath(toolName, key, deps = {}) {
  return join(anvilRoot(deps), toolName, `${key}.json`);
}

/**
 * Read a cached entry, returning null on any error.
 * @param {string} toolName
 * @param {string} key
 * @param {{ cwd?: string }} deps
 * @returns {{ payload: *, storedAt: string, codeHashSeed: string } | null}
 */
function readEntry(toolName, key, deps = {}) {
  const p = entryPath(toolName, key, deps);
  if (!existsSync(p)) return null;
  try {
    return JSON.parse(readFileSync(p, "utf-8"));
  } catch {
    return null;
  }
}

/**
 * Write a cache entry to disk.
 * @param {string} toolName
 * @param {string} key
 * @param {*} payload
 * @param {string} codeHashSeed
 * @param {{ cwd?: string }} deps
 */
function writeEntry({ toolName, key, payload, codeHashSeed, deps = {} }) {
  const p = entryPath(toolName, key, deps);
  mkdirSync(resolve(p, ".."), { recursive: true });
  const record = {
    toolName,
    cacheKey: key,
    codeHashSeed: String(codeHashSeed),
    storedAt: new Date().toISOString(),
    payload,
  };
  writeFileSync(p, JSON.stringify(record, null, 2), "utf-8");
}

// ─── Public API ──────────────────────────────────────────────────────────────

/**
 * Memoization wrapper for a pure tool function.
 *
 * On cache hit: returns `{ ...payload, anvil: { hit: true, key, ageMs } }`
 * On cache miss: runs `toolFn`, stores result, returns `{ ...payload, anvil: { hit: false, key } }`
 *
 * Supports both synchronous and asynchronous `toolFn`.
 *
 * @param {Function} toolFn
 * @param {{ toolName: string, inputs: *, codeHashSeed: string }} opts
 * @param {{ cwd?: string }} [deps]
 * @returns {Promise<*>}
 */
export async function withAnvil(toolFn, opts = {}, deps = {}) {
  const { toolName, inputs, codeHashSeed } = opts;
  const key = computeCacheKey(toolName, inputs, codeHashSeed);

  const cached = readEntry(toolName, key, deps);
  if (cached !== null) {
    const ageMs = Date.now() - new Date(cached.storedAt).getTime();
    recordStat(toolName, "hit", deps);
    return { ...cached.payload, anvil: { hit: true, key, ageMs: Math.max(0, ageMs) } };
  }

  const result = await toolFn();

  writeEntry({ toolName: toolName, key: key, payload: result, codeHashSeed: codeHashSeed, deps: deps });
  recordStat(toolName, "miss", deps);

  return { ...result, anvil: { hit: false, key } };
}

/**
 * Read-only summary of the anvil cache.
 *
 * Returns: `{ entries, totalBytes, oldestMtime, perTool: { [tool]: { hits, misses, count } } }`
 *
 * @param {{ cwd?: string }} [deps]
 * @returns {{ entries: number, totalBytes: number, oldestMtime: number|null, perTool: Record<string, { hits: number, misses: number, count: number }> }}
 */
export function anvilStat(deps = {}) {
  const root = anvilRoot(deps);
  const stats = readStats(deps);

  let entries = 0;
  let totalBytes = 0;
  let oldestMtime = null;

  // Per-tool entry counts from disk
  const diskCounts = {};
  if (existsSync(root)) {
    for (const toolDir of readdirSync(root)) {
      if (toolDir === "stats.json" || toolDir === "dlq") continue;
      const toolPath = join(root, toolDir);
      let st;
      try { st = statSync(toolPath); } catch { continue; }
      if (!st.isDirectory()) continue;

      let count = 0;
      for (const file of readdirSync(toolPath)) {
        if (!file.endsWith(".json")) continue;
        const filePath = join(toolPath, file);
        try {
          const fst = statSync(filePath);
          count++;
          entries++;
          totalBytes += fst.size;
          const mtimeMs = fst.mtimeMs;
          if (oldestMtime === null || mtimeMs < oldestMtime) oldestMtime = mtimeMs;
        } catch {
          // skip unreadable files
        }
      }
      diskCounts[toolDir] = count;
    }
  }

  // Merge disk counts with stats.json counters
  const perTool = {};
  const allTools = new Set([...Object.keys(diskCounts), ...Object.keys(stats.perTool)]);
  for (const tool of allTools) {
    const s = stats.perTool[tool] || { hits: 0, misses: 0 };
    perTool[tool] = { hits: s.hits, misses: s.misses, count: diskCounts[tool] || 0 };
  }

  return { entries, totalBytes, oldestMtime, perTool };
}

/**
 * Bounded cache deletion. Requires at least one of `tool` or `olderThanMs`.
 * Calling with no filters throws `ERR_ANVIL_NO_FILTER`.
 *
 * @param {{ tool?: string, olderThanMs?: number }} [opts]
 * @param {{ cwd?: string }} [deps]
 * @returns {{ deleted: number }}
 */
export function anvilClear(opts = {}, deps = {}) {
  const { tool, olderThanMs } = opts;

  if (!tool && olderThanMs == null) {
    const err = new Error(
      "anvilClear requires at least one filter (tool or olderThanMs) to prevent accidental full-cache nuke"
    );
    err.code = "ERR_ANVIL_NO_FILTER";
    throw err;
  }

  const root = anvilRoot(deps);
  if (!existsSync(root)) return { deleted: 0 };

  let deleted = 0;
  const nowMs = Date.now();

  const toolDirs = tool
    ? [tool]
    : readdirSync(root).filter(d => d !== "stats.json" && d !== "dlq");

  for (const toolDir of toolDirs) {
    const toolPath = join(root, toolDir);
    if (!existsSync(toolPath)) continue;
    let st;
    try { st = statSync(toolPath); } catch { continue; }
    if (!st.isDirectory()) continue;

    if (olderThanMs == null) {
      // Delete the entire tool directory
      rmSync(toolPath, { recursive: true, force: true });
      deleted++;
      continue;
    }

    // Delete individual files at least olderThanMs old (inclusive,
    // so olderThanMs:0 deletes everything regardless of mtime).
    for (const file of readdirSync(toolPath)) {
      if (!file.endsWith(".json")) continue;
      const filePath = join(toolPath, file);
      try {
        const fst = statSync(filePath);
        if (Math.max(0, nowMs - fst.mtimeMs) >= olderThanMs) {
          rmSync(filePath, { force: true });
          deleted++;
        }
      } catch {
        // skip
      }
    }
  }

  return { deleted };
}

/**
 * Selectively invalidates cache entries whose `codeHashSeed` references a
 * file that changed since `since` (a git SHA). Uses `git diff --name-only`.
 *
 * Does NOT re-run the tool — the next caller gets a clean miss.
 *
 * @param {{ since: string }} opts
 * @param {{ cwd?: string, exec?: Function }} [deps]
 * @returns {{ invalidated: number, changedFiles: string[] }}
 */
export function anvilRebuild(opts = {}, deps = {}) {
  const { since } = opts;
  if (!since) {
    throw new Error("anvilRebuild requires { since: '<sha>' }");
  }

  const cwd = deps.cwd || process.cwd();
  const exec = deps.exec || ((cmd, o) => execSync(cmd, o).toString());

  let diffOutput = "";
  try {
    diffOutput = exec(`git diff --name-only ${since} HEAD`, {
      cwd,
      encoding: "utf-8",
      timeout: 10_000,
      stdio: "pipe",
    });
  } catch {
    return { invalidated: 0, changedFiles: [] };
  }

  const changedFiles = diffOutput
    .split("\n")
    .map(l => l.trim())
    .filter(Boolean);

  if (changedFiles.length === 0) {
    return { invalidated: 0, changedFiles: [] };
  }

  const root = anvilRoot(deps);
  if (!existsSync(root)) return { invalidated: 0, changedFiles };

  let invalidated = 0;

  for (const toolDir of readdirSync(root)) {
    if (toolDir === "stats.json" || toolDir === "dlq") continue;
    const toolPath = join(root, toolDir);
    let st;
    try { st = statSync(toolPath); } catch { continue; }
    if (!st.isDirectory()) continue;

    for (const file of readdirSync(toolPath)) {
      if (!file.endsWith(".json")) continue;
      const filePath = join(toolPath, file);
      try {
        const entry = JSON.parse(readFileSync(filePath, "utf-8"));
        const seed = String(entry.codeHashSeed || "");
        // An entry "references" a changed file if its codeHashSeed ends with
        // or contains the changed file path (handles absolute vs. relative)
        const references = changedFiles.some(
          f => seed === f || seed.endsWith(`/${f}`) || seed.endsWith(`\\${f}`) || seed.includes(f)
        );
        if (references) {
          rmSync(filePath, { force: true });
          invalidated++;
        }
      } catch {
        // skip unreadable entries
      }
    }
  }

  return { invalidated, changedFiles };
}

// ─── DLQ Helpers ─────────────────────────────────────────────────────────────

/**
 * Resolve the DLQ directory path.
 * @param {{ cwd?: string }} deps
 * @returns {string}
 */
function dlqDir(deps = {}) {
  return join(anvilRoot(deps), "dlq");
}

/**
 * Resolve the path for a specific DLQ entry.
 * @param {string} id
 * @param {{ cwd?: string }} deps
 * @returns {string}
 */
function dlqEntryPath(id, deps = {}) {
  return join(dlqDir(deps), `${id}.json`);
}

// ─── DLQ Public API ──────────────────────────────────────────────────────────

/**
 * Append a failure record to the Dead Letter Queue.
 *
 * The caller supplies whatever fields are known (`toolName`, `inputs`,
 * `error`). The function assigns a UUID `id` and a `failedAt` ISO timestamp.
 *
 * @param {{ toolName?: string, inputs?: *, error?: string, [key: string]: * }} [entry]
 * @param {{ cwd?: string }} [deps]
 * @returns {{ id: string }}
 */
export function anvilDlqAppend(entry = {}, deps = {}) {
  const id = randomUUID();
  const dir = dlqDir(deps);
  mkdirSync(dir, { recursive: true });
  const record = {
    ...entry,
    id,
    toolName: entry.toolName ?? null,
    inputs: entry.inputs ?? null,
    error: entry.error ?? null,
    failedAt: new Date().toISOString(),
  };
  writeFileSync(dlqEntryPath(id, deps), JSON.stringify(record, null, 2), "utf-8");
  return { id };
}

/**
 * List DLQ entries, optionally filtered by tool name and/or capped by limit.
 *
 * Returns all matching entries ordered by `failedAt` ascending (oldest first).
 * `total` reflects the count of matching entries before `limit` is applied.
 *
 * @param {{ tool?: string, limit?: number }} [opts]
 * @param {{ cwd?: string }} [deps]
 * @returns {{ items: Array<{ id: string, toolName: string|null, failedAt: string, [key: string]: * }>, total: number }}
 */
export function anvilDlqList(opts = {}, deps = {}) {
  const { tool, limit } = opts;
  const dir = dlqDir(deps);
  if (!existsSync(dir)) return { items: [], total: 0 };

  const items = [];
  for (const file of readdirSync(dir)) {
    if (!file.endsWith(".json")) continue;
    try {
      const rec = JSON.parse(readFileSync(join(dir, file), "utf-8"));
      if (tool != null && rec.toolName !== tool) continue;
      items.push(rec);
    } catch {
      // skip unreadable entries
    }
  }

  items.sort((a, b) => {
    const ta = a.failedAt ? new Date(a.failedAt).getTime() : 0;
    const tb = b.failedAt ? new Date(b.failedAt).getTime() : 0;
    return ta - tb;
  });

  const total = items.length;
  return { items: limit != null ? items.slice(0, limit) : items, total };
}

/**
 * Remove DLQ entries — by specific `id`, by `tool`, or all entries when no
 * filter is provided.
 *
 * Unlike `anvilClear`, a full drain (no opts) is intentional and permitted.
 *
 * **Callback form** (Phase-ANVIL Slice 4):
 * When the first argument is an async function, the drain iterates every
 * DLQ record oldest-first and calls `callback(record)`. A record is deleted
 * only when the callback returns `{ ok: true }`. Records whose callback
 * returns `{ ok: false }` (or throws) remain on the heap.
 *
 * The callback form returns a Promise of `{ drained: number, remaining: number }`.
 *
 * **Opts form** (backward-compatible, synchronous):
 * When the first argument is an opts object `{ id?, tool? }`, the function
 * behaves as before and returns `{ drained: number }` synchronously.
 *
 * @overload
 * @param {(rec: object) => Promise<{ ok: boolean }>} callback
 * @param {{ cwd?: string }} [deps]
 * @returns {Promise<{ drained: number, remaining: number }>}
 *
 * @overload
 * @param {{ id?: string, tool?: string }} [opts]
 * @param {{ cwd?: string }} [deps]
 * @returns {{ drained: number }}
 */
export function anvilDlqDrain(callbackOrOpts = {}, deps = {}) {
  // ── Callback-based async drain ──────────────────────────────────────────────
  if (typeof callbackOrOpts === "function") {
    const callback = callbackOrOpts;
    const dir = dlqDir(deps);
    if (!existsSync(dir)) return Promise.resolve({ drained: 0, remaining: 0 });

    return (async () => {
      const { items } = anvilDlqList({}, deps);
      let drained = 0;
      let remaining = 0;
      for (const rec of items) {
        let result;
        try {
          result = await callback(rec);
        } catch {
          result = { ok: false };
        }
        if (result && result.ok === true) {
          try { rmSync(dlqEntryPath(rec.id, deps), { force: true }); } catch { /* skip */ }
          drained++;
        } else {
          remaining++;
        }
      }
      return { drained, remaining };
    })();
  }

  // ── Legacy opts-based synchronous drain ─────────────────────────────────────
  const { id, tool } = callbackOrOpts;
  const dir = dlqDir(deps);
  if (!existsSync(dir)) return { drained: 0 };

  if (id != null) {
    const p = dlqEntryPath(id, deps);
    if (existsSync(p)) {
      rmSync(p, { force: true });
      return { drained: 1 };
    }
    return { drained: 0 };
  }

  let drained = 0;
  for (const file of readdirSync(dir)) {
    if (!file.endsWith(".json")) continue;
    const filePath = join(dir, file);
    try {
      if (tool != null) {
        const rec = JSON.parse(readFileSync(filePath, "utf-8"));
        if (rec.toolName !== tool) continue;
      }
      rmSync(filePath, { force: true });
      drained++;
    } catch {
      // skip unreadable entries
    }
  }
  return { drained };
}

/**
 * Audit export — streaming reader for `.forge/runs/<id>/events.log` files.
 * Yields filtered JSON or CSV records without loading all events into memory.
 *
 * Phase-OTEL-AUDIT-EXPORT Slice 8.
 *
 * Design constraints:
 *   - Streaming: uses readline on each events.log — no bulk readFileSync
 *   - Never throws — graceful on missing/empty .forge/runs/
 *   - Decoupled from OTel — reads the same files telemetry already writes
 *   - Filters: --since, --until, --type (repeatable), --run
 *   - Formats: json (JSONL) and csv (flat with header)
 *
 * @module audit-export
 */

import { existsSync, readdirSync, readFileSync, createReadStream } from "node:fs";
import { resolve } from "node:path";
import { createInterface } from "node:readline";

// ─── Event line parser (mirrors orchestrator.mjs parseEventLine) ─────

const EVENT_LINE_RE = /^\[([^\]]+)\]\s+([a-z-]+):\s*(.*)$/;

/**
 * Parse a single events.log line.
 * @param {string} line
 * @returns {{ ts: string, type: string, data: object } | null}
 */
function parseLine(line) {
  const m = line.match(EVENT_LINE_RE);
  if (!m) return null;
  let data = {};
  try { data = JSON.parse(m[3] || "{}"); } catch { /* keep empty */ }
  return { ts: m[1], type: m[2], data };
}

// ─── CSV helpers ─────────────────────────────────────────────────────

const CSV_COLUMNS = [
  "timestamp",
  "run_id",
  "plan",
  "slice_id",
  "event_type",
  "source",
  "security_risk",
  "gate_result",
  "cost_usd",
  "tokens_in",
  "tokens_out",
  "model",
  "worker",
];

function csvEscape(value) {
  if (value == null) return "";
  const s = String(value);
  if (s.includes(",") || s.includes('"') || s.includes("\n")) {
    return `"${s.replace(/"/g, '""')}"`;
  }
  return s;
}

function toCsvRow(record) {
  return CSV_COLUMNS.map((col) => csvEscape(record[col])).join(",");
}

function firstDefined(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null) return value;
  }
  return null;
}

// ─── Record builder ──────────────────────────────────────────────────

/**
 * Build a flat record from a parsed event line + run metadata.
 */
function buildRecord(parsed, runId, plan) {
  const d = parsed.data;
  return {
    timestamp: parsed.ts,
    run_id: runId,
    plan: firstDefined(plan, d.plan),
    slice_id: firstDefined(d.sliceId, d.slice, d.sliceNumber),
    event_type: parsed.type,
    source: firstDefined(d.source),
    security_risk: firstDefined(d.security_risk),
    gate_result: firstDefined(d.gateResult, d.gate_result),
    cost_usd: firstDefined(d.cost, d.costUsd, d.cost_usd),
    tokens_in: firstDefined(d.tokensIn, d.tokens_in, d.inputTokens),
    tokens_out: firstDefined(d.tokensOut, d.tokens_out, d.outputTokens),
    model: firstDefined(d.model),
    worker: firstDefined(d.worker),
  };
}

// ─── Run directory discovery ─────────────────────────────────────────

/**
 * List run directories under `.forge/runs/`, sorted oldest-first.
 * @param {string} cwd
 * @returns {string[]} sorted directory names
 */
function listRunDirs(cwd) {
  const runsDir = resolve(cwd, ".forge", "runs");
  if (!existsSync(runsDir)) return [];
  try {
    return readdirSync(runsDir, { withFileTypes: true })
      .filter((d) => d.isDirectory())
      .map((d) => d.name)
      .sort();
  } catch {
    return [];
  }
}


// ─── Filter logic ────────────────────────────────────────────────────

/**
 * Check if an event timestamp passes the --since / --until filters.
 */
function passesDateFilter(ts, since, until) {
  if (!ts) return false;
  if (since && ts < since) return false;
  if (until && ts > until) return false;
  return true;
}

/**
 * Check if an event type passes the --type filter.
 */
function passesTypeFilter(type, typeFilter) {
  if (!typeFilter || typeFilter.length === 0) return true;
  return typeFilter.includes(type);
}

// ─── Core streaming export ───────────────────────────────────────────

/**
 * Streaming audit export. Async generator that yields records from
 * `.forge/runs/<id>/events.log` files, applying filters.
 *
 * @param {object} opts
 * @param {string} [opts.cwd=process.cwd()]  - Working directory
 * @param {string} [opts.since]              - ISO date lower bound (inclusive)
 * @param {string} [opts.until]              - ISO date upper bound (inclusive)
 * @param {string[]} [opts.type]             - Event types to include
 * @param {string} [opts.run]                - Single run ID to scope to
 * @param {"json"|"csv"} [opts.format="json"] - Output format
 * @yields {string} One line per record (JSONL or CSV row)
 */
export async function* exportAudit(opts = {}) {
  const {
    cwd = process.cwd(),
    since,
    until,
    type: typeFilter,
    run: runFilter,
    format = "json",
  } = opts;

  const dirs = listRunDirs(cwd);
  if (dirs.length === 0) return;

  // Filter to a single run if --run specified
  const targetDirs = runFilter
    ? dirs.filter((d) => d === runFilter)
    : dirs;

  if (targetDirs.length === 0) return;

  // Emit CSV header if format is csv
  if (format === "csv") {
    yield CSV_COLUMNS.join(",");
  }

  for (const dirName of targetDirs) {
    const runDirPath = resolve(cwd, ".forge", "runs", dirName);
    const logPath = resolve(runDirPath, "events.log");
    if (!existsSync(logPath)) continue;

    // Read minimal manifest metadata for plan name
    let plan = null;
    try {
      const manifestPath = resolve(runDirPath, "manifest.json");
      if (existsSync(manifestPath)) {
        const manifest = JSON.parse(readFileSync(manifestPath, "utf-8"));
        plan = manifest.plan ?? null;
      }
    } catch { /* skip */ }

    // Stream events.log line by line
    const rl = createInterface({
      input: createReadStream(logPath, { encoding: "utf-8" }),
      crlfDelay: Infinity,
    });

    for await (const line of rl) {
      if (!line.trim()) continue;

      const parsed = parseLine(line);
      if (!parsed) continue;

      if (!passesDateFilter(parsed.ts, since, until)) continue;
      if (!passesTypeFilter(parsed.type, typeFilter)) continue;

      const record = buildRecord(parsed, dirName, plan);

      if (format === "csv") {
        yield toCsvRow(record);
      } else {
        yield JSON.stringify(record);
      }
    }
  }
}

/**
 * HTTP middleware factory for Plan Forge MCP authentication + authorization.
 *
 * `withAuth` wraps a Node.js-style `(req, res)` handler and enforces:
 *   1. Authentication  — delegates to `authenticate()` (bearer, sso, or none)
 *   2. Authorization   — optional RBAC scope check via `resolveRoles` / `hasScope`
 *
 * On failure the wrapper writes a JSON error body and calls `res.end()` so the
 * original handler is never invoked. On success the request context is enriched
 * with `req.auth` before the handler is called.
 *
 * @module auth/middleware
 */

import { authenticate } from "./index.mjs";
import { resolveRoles, hasScope } from "./rbac.mjs";

/**
 * @typedef {Object} WithAuthOptions
 * @property {"bearer"|"sso"|"none"} [provider="bearer"] - Auth provider
 * @property {string}  [token]   - Expected bearer token (bearer provider only)
 * @property {string}  [scope]   - Required RBAC scope (e.g. "plans:read")
 * @property {import("./rbac.mjs").RbacConfig} [rbac] - RBAC config (required when scope is set)
 */

/**
 * Wrap a `(req, res)` handler with authentication and optional authorization.
 *
 * @param {Function}        handler - The route handler to protect
 * @param {WithAuthOptions} [opts]
 * @returns {Function} A new handler that enforces auth before calling `handler`
 */
export function withAuth(handler, opts = {}) {
  return async function authGuard(req, res, ...rest) {
    // ── Step 1: Authentication ──────────────────────────────────────────
    const authResult = authenticate(req, opts);

    if (!authResult.ok) {
      return sendAuthError(res, 401, authResult.error ?? "Unauthorized");
    }

    // ── Step 2: Authorization (RBAC scope check, if requested) ──────────
    if (opts.scope) {
      const rbac = opts.rbac;
      if (!rbac) {
        return sendAuthError(
          res,
          500,
          "Server configuration error: RBAC config required when scope is set"
        );
      }

      // Use the token as the principal key for role lookup
      const principal = authResult.token;
      const roles = resolveRoles(principal, rbac);

      if (!hasScope(roles, opts.scope, rbac)) {
        return sendAuthError(
          res,
          403,
          `Forbidden: scope "${opts.scope}" is required`
        );
      }
    }

    // ── Step 3: Enrich request context and invoke handler ───────────────
    req.auth = authResult;
    return handler(req, res, ...rest);
  };
}

/**
 * Write a JSON error response and end the response.
 *
 * @param {Object} res     - Node.js ServerResponse
 * @param {number} status  - HTTP status code (401, 403, 500, …)
 * @param {string} message - Human-readable error description
 */
function sendAuthError(res, status, message) {
  const body = JSON.stringify({ ok: false, error: message });
  if (res.headersSent) return;
  res.writeHead(status, {
    "Content-Type": "application/json",
    "Content-Length": Buffer.byteLength(body),
  });
  res.end(body);
}

/**
 * Bearer token authentication provider for Plan Forge MCP.
 *
 * Extracts and validates a bearer token from the Authorization header
 * (preferred) or the PFORGE_AUTH_TOKEN environment variable (fallback).
 *
 * @module auth/providers/bearer
 */

const AUTH_HEADER = "authorization";
const ENV_TOKEN_KEY = "PFORGE_AUTH_TOKEN";

/**
 * @typedef {Object} AuthResult
 * @property {boolean} ok       - Whether authentication succeeded
 * @property {string}  token    - The validated token (empty string on failure)
 * @property {string}  [error]  - Human-readable reason for failure
 */

/**
 * Authenticate a request using a bearer token.
 *
 * Accepts tokens via:
 *   - `Authorization: Bearer <token>` header (headers map or object)
 *   - `PFORGE_AUTH_TOKEN` environment variable (when no header is present)
 *
 * When `opts.token` is provided (pre-configured secret) the extracted
 * token must match exactly. If no configured token is set, any non-empty
 * token is accepted (permissive mode — useful in local / dev environments).
 *
 * @param {Object} req                        - Incoming request context
 * @param {Record<string,string>} [req.headers] - HTTP-style headers map
 * @param {Object} [opts]                     - Provider options
 * @param {string} [opts.token]               - Expected token for validation
 * @returns {AuthResult}
 */
export function authenticateBearer(req, opts = {}) {
  const headers = req?.headers ?? {};

  // Normalise header lookup — keys may be lower- or mixed-case
  const authHeader =
    headers[AUTH_HEADER] ??
    headers["Authorization"] ??
    headers["AUTHORIZATION"] ??
    "";

  let extracted = "";
  if (authHeader) {
    const match = /^Bearer\s+(\S+)$/i.exec(authHeader.trim());
    if (match) {
      extracted = match[1];
    }
  }

  // Fallback to environment variable when no header was supplied
  if (!extracted) {
    extracted = process.env[ENV_TOKEN_KEY] ?? "";
  }

  if (!extracted) {
    return { ok: false, token: "", error: "No bearer token provided" };
  }

  // When a configured token is set, require an exact match
  if (opts.token && extracted !== opts.token) {
    return { ok: false, token: "", error: "Bearer token mismatch" };
  }

  return { ok: true, token: extracted };
}

/**
 * Plan Forge — Brain Facade (v1.0)
 *
 * Unified recall/remember/forget API routing to L1 (session), L2 (durable),
 * and L3 (semantic/OpenBrain) tiers. This is a **dumb router** — no caching,
 * no intelligence. Smarts live in agents and skills.
 *
 * Backwards-compatible: existing direct readers continue to work unchanged.
 * The facade wraps, does not replace.
 *
 * @module brain
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync, unlinkSync, renameSync, readdirSync, statSync } from "node:fs";
import { resolve, basename, dirname } from "node:path";
import { randomUUID } from "node:crypto";
import { tmpdir } from "node:os";
import { startSpan, endSpan, addEvent, Severity } from "./telemetry.mjs";
// Phase-ANVIL Slice 4 — DLQ fallback for L3 boundary writes
import { anvilDlqAppend as _anvilDlqAppend } from "./anvil.mjs";

// ─── Key Validation ──────────────────────────────────────────────────────────

const VALID_SCOPES = ["session", "project", "cross"];
const KEY_PATTERN = /^(session|project|cross)\.[a-zA-Z0-9][a-zA-Z0-9._-]*$/;

/**
 * Typed error for invalid brain keys.
 */
export class BrainKeyError extends Error {
  constructor(key, reason) {
    super(`Invalid brain key "${key}": ${reason}`);
    this.name = "BrainKeyError";
    this.key = key;
    this.reason = reason;
  }
}

/**
 * Validate a dotted-path brain key.
 * @param {string} key
 * @returns {void}
 * @throws {BrainKeyError}
 */
export function validateKey(key) {
  if (!key || typeof key !== "string") {
    throw new BrainKeyError(String(key), "key must be a non-empty string");
  }
  if (key.includes("..")) {
    throw new BrainKeyError(key, "path traversal (..) is forbidden");
  }
  if (/\s/.test(key)) {
    throw new BrainKeyError(key, "spaces are not allowed in keys");
  }
  if (!KEY_PATTERN.test(key)) {
    const scope = key.split(".")[0];
    if (!VALID_SCOPES.includes(scope)) {
      throw new BrainKeyError(key, `unknown scope prefix "${scope}" — expected one of: ${VALID_SCOPES.join(", ")}`);
    }
    throw new BrainKeyError(key, "invalid key format — use dotted path like scope.entity.id");
  }
}

/**
 * Parse a key into its components.
 * @param {string} key
 * @returns {{ scope: string, segments: string[], entity: string, id: string|null }}
 */
function parseKey(key) {
  const parts = key.split(".");
  const scope = parts[0];
  const segments = parts.slice(1);
  const entity = segments[0] || null;
  const id = segments.length > 1 ? segments.slice(1).join(".") : null;
  return { scope, segments, entity, id };
}

// ─── Tier Routing ────────────────────────────────────────────────────────────

/**
 * Resolve which tiers to read/write for a given scope.
 * @param {string} scope
 * @param {{ fallback?: string }} opts
 * @returns {{ readTiers: string[], writeTier: string }}
 */
function resolveTier(scope, opts = {}) {
  const fallback = opts.fallback || "none";
  switch (scope) {
    case "session":
      return { readTiers: ["l1"], writeTier: "l1" };
    case "project":
      return {
        readTiers: fallback === "l3" ? ["l2", "l3"] : ["l2"],
        writeTier: "l2",
      };
    case "project-durable":
      return { readTiers: ["l2", "l3"], writeTier: "l2+l3" };
    case "cross":
    case "cross-project":
      return { readTiers: ["l3"], writeTier: "l3" };
    default:
      return { readTiers: ["l2"], writeTier: "l2" };
  }
}

// ─── L1 Backend (Session / In-Process) ───────────────────────────────────────

const l1Store = new Map(); // Map<runId, Map<key, { value, mtime }>>

function l1Recall(key, runId) {
  if (!runId) return null;
  const runMap = l1Store.get(runId);
  if (!runMap) return null;
  const entry = runMap.get(key);
  return entry ? entry.value : null;
}

function l1Remember(key, value, runId, cwd) {
  if (!runId) {
    throw new Error("Cannot write to L1 without an active runId");
  }
  if (!l1Store.has(runId)) l1Store.set(runId, new Map());
  l1Store.get(runId).set(key, { value, mtime: Date.now() });

  // Mirror to disk
  try {
    const mirrorDir = resolve(cwd, ".forge", "runs", runId);
    mkdirSync(mirrorDir, { recursive: true });
    const mirrorPath = resolve(mirrorDir, "brain-state.json");
    const tmpPath = mirrorPath + ".tmp." + randomUUID().slice(0, 8);
    const state = {};
    for (const [k, v] of l1Store.get(runId)) {
      state[k] = v;
    }
    writeFileSync(tmpPath, JSON.stringify(state, null, 2));
    renameSync(tmpPath, mirrorPath);
  } catch { /* mirror write failure is non-fatal */ }

  return { ok: true, tier: "l1", ref: `memory://l1/${runId}/${key}` };
}

function l1Forget(key, runId, cwd) {
  if (!runId) return { ok: true, removed: [] };
  const runMap = l1Store.get(runId);
  if (!runMap || !runMap.has(key)) return { ok: true, removed: [] };
  runMap.delete(key);

  // Update mirror
  try {
    const mirrorDir = resolve(cwd, ".forge", "runs", runId);
    const mirrorPath = resolve(mirrorDir, "brain-state.json");
    const tmpPath = mirrorPath + ".tmp." + randomUUID().slice(0, 8);
    const state = {};
    for (const [k, v] of runMap) {
      state[k] = v;
    }
    writeFileSync(tmpPath, JSON.stringify(state, null, 2));
    renameSync(tmpPath, mirrorPath);
  } catch { /* mirror update failure is non-fatal */ }

  return { ok: true, removed: ["l1"] };
}

// For testing: clear L1 store
export function _resetL1() {
  l1Store.clear();
}

// ─── L2 Backend (Durable / File-Based) ──────────────────────────────────────

/**
 * L2 routing table — maps key entity prefixes to existing reader functions.
 * The facade delegates to these readers; it does NOT re-implement file I/O.
 */
const L2_ROUTES = {
  bug: (deps, id) => deps.loadBug(deps.cwd, id),
  review: (deps, id) => {
    // Synthetic key: project.review.counts → aggregate counts from readReviewQueueState
    if (id === "counts" || id?.startsWith("counts.")) {
      if (deps.readReviewQueueState) return deps.readReviewQueueState(deps.cwd);
      return null;
    }
    return deps.readReviewItem(deps.cwd, id);
  },
  tempering: (deps, id) => {
    // project.tempering.perf-history → delegate to readPerfHistory
    if (id === "perf-history") {
      if (deps.readPerfHistory) return deps.readPerfHistory(deps.cwd);
      return null;
    }
    return deps.readTemperingState(deps.cwd);
  },
  run: (deps, id) => deps.findLatestRun(deps.cwd, id === "latest" ? null : id),
  "hub-events": (deps) => deps.readHubEvents(deps.cwd, {}),
  crucible: (deps) => {
    if (deps.readCrucibleState) return deps.readCrucibleState(deps.cwd);
    return null;
  },
  liveguard: (deps, id) => {
    // project.liveguard.drift → drift-history.jsonl
    // project.liveguard.incidents → incidents.jsonl
    // project.liveguard.fix-proposals → fix-proposals.jsonl
    // project.liveguard.state → all three combined
    if (deps.readForgeJsonl) {
      if (id === "drift") return deps.readForgeJsonl("drift-history.jsonl", [], deps.cwd);
      if (id === "incidents") return deps.readForgeJsonl("incidents.jsonl", [], deps.cwd);
      if (id === "fix-proposals") return deps.readForgeJsonl("fix-proposals.jsonl", [], deps.cwd);
      if (id === "state" || !id) {
        return {
          drift: deps.readForgeJsonl("drift-history.jsonl", [], deps.cwd),
          incidents: deps.readForgeJsonl("incidents.jsonl", [], deps.cwd),
          fixProposals: deps.readForgeJsonl("fix-proposals.jsonl", [], deps.cwd),
        };
      }
    }
    return null;
  },
};

function l2Recall(key, deps) {
  const { entity, id } = parseKey(key);
  const route = L2_ROUTES[entity];
  if (!route) return null;
  try {
    return route(deps, id);
  } catch {
    return null;
  }
}

function l2Remember(key, value, deps) {
  const { entity, id } = parseKey(key);
  try {
    const forgeDir = resolve(deps.cwd, ".forge");
    mkdirSync(forgeDir, { recursive: true });

    // Route writes to appropriate storage
    if (entity === "review" && id) {
      const reviewDir = resolve(forgeDir, "review-queue");
      mkdirSync(reviewDir, { recursive: true });
      const filePath = resolve(reviewDir, `${basename(id)}.json`);
      const tmpPath = filePath + ".tmp." + randomUUID().slice(0, 8);
      writeFileSync(tmpPath, JSON.stringify(value, null, 2));
      renameSync(tmpPath, filePath);
      return { ok: true, tier: "l2", ref: filePath };
    }

    // Generic L2 write — store under .forge/brain/<entity>/<id>.json
    const brainDir = resolve(forgeDir, "brain", entity || "_default");
    mkdirSync(brainDir, { recursive: true });
    const fileName = id ? `${basename(id)}.json` : "state.json";
    const filePath = resolve(brainDir, fileName);
    const tmpPath = filePath + ".tmp." + randomUUID().slice(0, 8);
    writeFileSync(tmpPath, JSON.stringify(value, null, 2));
    renameSync(tmpPath, filePath);
    return { ok: true, tier: "l2", ref: filePath };
  } catch (err) {
    return { ok: false, tier: "l2", error: err.message };
  }
}

function l2Forget(key, deps) {
  const { entity, id } = parseKey(key);
  try {
    const forgeDir = resolve(deps.cwd, ".forge");

    if (entity === "review" && id) {
      const filePath = resolve(forgeDir, "review-queue", `${basename(id)}.json`);
      if (existsSync(filePath)) {
        unlinkSync(filePath);
        return { ok: true, removed: ["l2"] };
      }
      return { ok: true, removed: [] };
    }

    // Generic brain storage
    const fileName = id ? `${basename(id)}.json` : "state.json";
    const filePath = resolve(forgeDir, "brain", entity || "_default", fileName);
    if (existsSync(filePath)) {
      unlinkSync(filePath);
      return { ok: true, removed: ["l2"] };
    }
    return { ok: true, removed: [] };
  } catch {
    return { ok: true, removed: [] };
  }
}

// ─── Phase-25 Slice 6: Cross-project memory federation (L4-lite) ────────────

/**
 * Validate a federation repo entry. Per Phase-25 D9:
 *   - Must be an absolute path (POSIX `/...` or Windows `X:\...`)
 *   - URLs (http / https / ssh / git) are rejected
 *   - Must not contain `..` segments (path traversal)
 */
export function validateFederationRepo(repo) {
  if (typeof repo !== "string" || repo.length === 0) {
    return { ok: false, reason: "repo must be a non-empty string" };
  }
  if (/^(https?|ssh|git|ftp):/i.test(repo)) {
    return { ok: false, reason: "URL-style repos are rejected (absolute local paths only per D9)" };
  }
  if (repo.includes("..")) {
    return { ok: false, reason: "path traversal ('..') is forbidden" };
  }
  const isPosixAbs = repo.startsWith("/");
  const isWinAbs = /^[A-Za-z]:[\\/]/.test(repo);
  if (!isPosixAbs && !isWinAbs) {
    return { ok: false, reason: "repo path must be absolute" };
  }
  return { ok: true };
}

/**
 * Load `.forge.json → brain.federation` from `cwd`.
 * Schema: { enabled?: boolean, repos: string[] }
 * Default: { enabled: false, repos: [] }  (opt-in per project)
 */
export function loadFederationConfig(cwd = process.cwd()) {
  const configPath = resolve(cwd, ".forge.json");
  const defaults = { enabled: false, repos: [] };
  try {
    if (existsSync(configPath)) {
      const cfg = JSON.parse(readFileSync(configPath, "utf-8"));
      const block = cfg?.brain?.federation;
      if (block && typeof block === "object") {
        const enabled = block.enabled === true;
        const repos = Array.isArray(block.repos) ? block.repos.filter((r) => typeof r === "string") : [];
        return { enabled, repos };
      }
    }
  } catch { /* fall through */ }
  return { ...defaults };
}

/**
 * Phase-25 MUST #10 — Read a brain key across federated projects.
 *
 * Iterates `brain.federation.repos[]` (absolute local paths only per D9) and
 * attempts to read `<repo>/.forge/brain/<entity>/<id>.json` for each entry
 * that passes validation. Returns an array of `{ repo, value }` hits, or `[]`
 * when federation is disabled, mis-configured, or no repo holds the key.
 * READ-ONLY — never writes to federated repos.
 */
export function federationRead(key, opts = {}) {
  validateKey(key);
  const { scope, entity, id } = parseKey(key);
  if (scope !== "cross" && scope !== "cross-project") return [];
  if (!entity) return [];

  const cwd = opts.cwd || process.cwd();
  const cfg = opts.config || loadFederationConfig(cwd);
  if (!cfg.enabled) return [];
  if (!Array.isArray(cfg.repos) || cfg.repos.length === 0) return [];

  const hits = [];
  for (const repo of cfg.repos) {
    const v = validateFederationRepo(repo);
    if (!v.ok) continue; // silently skip — config errors surfaced via validateFederationConfig()
    const fileName = id ? `${basename(id)}.json` : "state.json";
    const filePath = resolve(repo, ".forge", "brain", entity, fileName);
    const repoRoot = resolve(repo);
    if (!filePath.startsWith(repoRoot)) continue;
    if (!existsSync(filePath)) continue;
    try {
      const parsed = JSON.parse(readFileSync(filePath, "utf-8"));
      hits.push({ repo, value: parsed });
    } catch { /* skip unreadable/malformed */ }
  }
  return hits;
}

/**
 * Report federation config issues without throwing. Returns an array of
 * { repo, reason } for each invalid entry; empty when the config is clean
 * or federation is disabled.
 */
export function validateFederationConfig(cwd = process.cwd()) {
  const cfg = loadFederationConfig(cwd);
  if (!cfg.enabled) return [];
  const errors = [];
  for (const repo of cfg.repos) {
    const v = validateFederationRepo(repo);
    if (!v.ok) errors.push({ repo, reason: v.reason });
  }
  return errors;
}

// ─── Phase-26 Slice 11: Trajectory federation (extension of L4-lite) ────────

/** Hard ceiling on trajectory files returned per federationReadTrajectories call. */
export const TRAJECTORY_FEDERATION_LIMIT = 100;

function listTrajectoryFiles(planDir) {
  try {
    return readdirSync(planDir);
  } catch {
    return [];
  }
}

function listPlanDirectories(trajRoot) {
  try {
    return readdirSync(trajRoot, { withFileTypes: true });
  } catch {
    return [];
  }
}

function readTrajectoryFile(repo, planBasename, planDir, fileName) {
  const match = /^slice-(.+)\.md$/.exec(fileName);
  if (!match) return null;
  const filePath = resolve(planDir, fileName);
  if (!filePath.startsWith(planDir)) return null;

  let stats;
  try {
    stats = statSync(filePath);
  } catch {
    return null;
  }
  if (!stats.isFile()) return null;

  try {
    return {
      repo,
      planBasename,
      sliceId: match[1],
      path: filePath,
      mtimeMs: stats.mtimeMs,
      content: readFileSync(filePath, "utf-8"),
    };
  } catch {
    return null;
  }
}

function collectRepoTrajectoryEntries(repo) {
  const entries = [];
  const trajRoot = resolve(repo, ".forge", "trajectories");
  if (!existsSync(trajRoot)) return entries;

  for (const planDirEntry of listPlanDirectories(trajRoot)) {
    if (!planDirEntry.isDirectory()) continue;
    const planBasename = planDirEntry.name;
    const planDir = resolve(trajRoot, planBasename);
    if (!planDir.startsWith(trajRoot)) continue;

    for (const fileName of listTrajectoryFiles(planDir)) {
      const trajectoryEntry = readTrajectoryFile(repo, planBasename, planDir, fileName);
      if (trajectoryEntry) entries.push(trajectoryEntry);
    }
  }
  return entries;
}

/**
 * Read trajectory notes (`.forge/trajectories/<plan>/slice-<id>.md`) across
 * allowlisted sibling repos. READ-ONLY — never writes to federated repos.
 *
 * Behaviour (Phase-26 MUST §Slice 11):
 *   - Enumerate each repo passing `validateFederationRepo()`
 *   - For each repo: walk `.forge/trajectories/*\/slice-*.md` (depth 2)
 *   - Cap at `limit` files total across all repos (default 100)
 *   - Sort by `mtimeMs` descending — newest wins
 *   - Tag each entry with source repo path
 *
 * @param {object} [opts]
 * @param {string} [opts.cwd=process.cwd()] — project root whose `.forge.json` holds the allowlist
 * @param {number} [opts.limit=100] — max files returned
 * @param {object} [opts.config] — pre-loaded federation config (test injection)
 * @returns {Array<{ repo, planBasename, sliceId, path, mtimeMs, content }>}
 */
export function federationReadTrajectories(opts = {}) {
  const cwd = opts.cwd || process.cwd();
  const cfg = opts.config || loadFederationConfig(cwd);
  if (!cfg.enabled) return [];
  if (!Array.isArray(cfg.repos) || cfg.repos.length === 0) return [];

  const rawLimit = opts.limit;
  const limit = Number.isFinite(rawLimit) && rawLimit > 0
    ? Math.min(Math.floor(rawLimit), TRAJECTORY_FEDERATION_LIMIT)
    : TRAJECTORY_FEDERATION_LIMIT;

  const collected = [];
  for (const repo of cfg.repos) {
    const v = validateFederationRepo(repo);
    if (!v.ok) continue;
    collected.push(...collectRepoTrajectoryEntries(repo));
  }

  // Sort by mtime desc, cap at limit.
  collected.sort((a, b) => b.mtimeMs - a.mtimeMs);
  return collected.slice(0, limit);
}

// ─── Phase-25 Slice 7: Reviewer-agent in-loop (L4) ───────────────────────────

/**
 * Default reviewer configuration. Opt-in per Phase-25 MUST #7.
 * `blockOnCritical` is advisory-only in v2.57 (D6): the reviewer surfaces
 * verdicts but never blocks the next slice. Blocking enters Phase-26 after
 * calibration data exists.
 */
export const REVIEWER_DEFAULTS = Object.freeze({
  enabled: false,
  quorumPreset: "speed",
  blockOnCritical: false,
  timeoutMs: 30000,
  calibrationThreshold: 50,
});

/**
 * Load `.forge.json → runtime.reviewer` with defaults. Unknown fields are
 * ignored; malformed quorumPreset falls back to "speed".
 */
export function loadReviewerConfig(cwd = process.cwd()) {
  const out = { ...REVIEWER_DEFAULTS };
  const configPath = resolve(cwd, ".forge.json");
  if (!existsSync(configPath)) return out;
  try {
    const raw = JSON.parse(readFileSync(configPath, "utf-8"));
    const block = raw?.runtime?.reviewer;
    if (block && typeof block === "object") {
      if (typeof block.enabled === "boolean") out.enabled = block.enabled;
      if (typeof block.quorumPreset === "string" && ["speed", "power"].includes(block.quorumPreset)) {
        out.quorumPreset = block.quorumPreset;
      }
      if (typeof block.blockOnCritical === "boolean") out.blockOnCritical = block.blockOnCritical;
      if (typeof block.timeoutMs === "number" && block.timeoutMs > 0) out.timeoutMs = Math.floor(block.timeoutMs);
      if (typeof block.calibrationThreshold === "number" && block.calibrationThreshold > 0) {
        out.calibrationThreshold = Math.floor(block.calibrationThreshold);
      }
    }
  } catch { /* malformed — keep defaults */ }
  return out;
}

// ─── Phase-26 Slice 6: Reviewer calibration (C2) ─────────────────────────────

/**
 * Derive reviewer calibration at read-time from `.forge/reviews/*.json`.
 *
 * Phase-26 MUST #C2 / D5: the review count is NEVER stored as a mutable scalar.
 * It is always derived at read-time by counting `.json` files in the directory.
 * This guarantees the counter cannot drift from the on-disk reality.
 *
 * Returns `{ count, threshold, eligible }` where `eligible` is true when the
 * accumulated review count has met the `calibrationThreshold` (default 50,
 * overridable via `runtime.reviewer.calibrationThreshold` in `.forge.json`).
 *
 * Used by the `blockOnCritical` activation path: blocking stays advisory-only
 * until `eligible === true`.
 *
 * @param {string} [cwd] - Project working directory (default `process.cwd()`)
 * @returns {{ count: number, threshold: number, eligible: boolean }}
 */
export function getReviewerCalibration(cwd = process.cwd()) {
  const config = loadReviewerConfig(cwd);
  const threshold = config.calibrationThreshold;
  const reviewsDir = resolve(cwd, ".forge", "reviews");
  let count = 0;
  if (existsSync(reviewsDir)) {
    try {
      const entries = readdirSync(reviewsDir, { withFileTypes: true });
      for (const entry of entries) {
        if (entry.isFile() && entry.name.endsWith(".json")) count += 1;
      }
    } catch { /* unreadable — count stays 0 */ }
  }
  return { count, threshold, eligible: count >= threshold };
}

/**
 * Parse a reviewer response into a structured verdict. Tolerant of partial
 * JSON, markdown fences, or prose wrappers. Unknown shapes yield
 * `{ ok: false, error }` so callers can treat the reviewer as skipped.
 *
 * Expected shape (flexible): `{ score: 0-100, critical: boolean, summary: string }`
 */
export function parseReviewerResponse(raw) {
  if (raw == null) return { ok: false, error: "empty response" };
  if (typeof raw === "object" && !Array.isArray(raw)) {
    const score = Number(raw.score);
    const critical = raw.critical === true;
    const summary = typeof raw.summary === "string" ? raw.summary : "";
    if (Number.isFinite(score)) {
      return { ok: true, score: Math.max(0, Math.min(100, score)), critical, summary };
    }
    return { ok: false, error: "missing numeric score" };
  }
  if (typeof raw === "string") {
    // Try to extract a JSON object — prefer the first `{...}` balanced block.
    const fencedMatch = raw.match(/```(?:json)?\s*(\{[\s\S]*?\})\s*```/);
    const bareMatch = fencedMatch ? null : raw.match(/\{[\s\S]*\}/);
    const candidate = fencedMatch ? fencedMatch[1] : (bareMatch ? bareMatch[0] : null);
    if (!candidate) return { ok: false, error: "no JSON object found in string" };
    try {
      return parseReviewerResponse(JSON.parse(candidate));
    } catch (err) {
      return { ok: false, error: `invalid JSON: ${err.message}` };
    }
  }
  return { ok: false, error: `unsupported type: ${typeof raw}` };
}

/**
 * Phase-25 MUST #8 — Invoke the speed-quorum reviewer on a slice diff.
 *
 * Pure DI — the actual quorum LLM call is injected via `deps.quorumInvoke`
 * so tests can mock it deterministically. When `quorumInvoke` is absent, the
 * helper returns a skipped verdict rather than throwing.
 *
 * Timeboxed via `Promise.race`; on timeout returns `{ ok: false, error, timedOut: true }`.
 *
 * @param {{
 *   sliceNumber?: (number|string),
 *   sliceTitle?: string,
 *   diffSummary?: string,
 *   config?: object,
 *   cwd?: string,
 * }} args
 * @param {{ quorumInvoke?: Function, now?: Function }} [deps]
 * @returns {Promise<{
 *   ok: boolean,
 *   skipped?: boolean,
 *   timedOut?: boolean,
 *   error?: string,
 *   score?: number,
 *   critical?: boolean,
 *   summary?: string,
 *   quorumPreset?: string,
 *   durationMs?: number,
 * }>}
 */
export async function invokeReviewer(args = {}, deps = {}) {
  const cwd = args.cwd || process.cwd();
  const config = args.config || loadReviewerConfig(cwd);
  if (!config.enabled) {
    return { ok: false, skipped: true, error: "reviewer disabled" };
  }
  const quorumInvoke = typeof deps.quorumInvoke === "function" ? deps.quorumInvoke : null;
  if (!quorumInvoke) {
    return { ok: false, skipped: true, error: "no quorumInvoke handler" };
  }

  const prompt = [
    `You are a code reviewer. Score the following slice diff from 0-100 and flag if there are any critical issues.`,
    ``,
    `Slice: ${args.sliceNumber ?? "?"} — ${args.sliceTitle || ""}`,
    ``,
    `Diff summary:`,
    (args.diffSummary || "(no diff provided)").slice(0, 4000),
    ``,
    `Respond with JSON only: {"score": <0-100>, "critical": <true|false>, "summary": "<one-line verdict>"}`,
  ].join("\n");

  const now = typeof deps.now === "function" ? deps.now : Date.now;
  const t0 = now();
  let timer;
  const timeoutPromise = new Promise((resolve) => {
    timer = setTimeout(() => resolve({ __timedOut: true }), config.timeoutMs);
  });

  try {
    const raced = await Promise.race([
      Promise.resolve().then(() => quorumInvoke(prompt, { preset: config.quorumPreset })),
      timeoutPromise,
    ]);
    if (raced && raced.__timedOut) {
      return { ok: false, timedOut: true, error: "reviewer timeout", quorumPreset: config.quorumPreset, durationMs: now() - t0 };
    }
    const parsed = parseReviewerResponse(raced);
    if (!parsed.ok) {
      return { ok: false, error: parsed.error, quorumPreset: config.quorumPreset, durationMs: now() - t0 };
    }
    return {
      ok: true,
      score: parsed.score,
      critical: parsed.critical,
      summary: parsed.summary,
      quorumPreset: config.quorumPreset,
      durationMs: now() - t0,
    };
  } catch (err) {
    return { ok: false, error: err?.message || String(err), quorumPreset: config.quorumPreset, durationMs: now() - t0 };
  } finally {
    if (timer) clearTimeout(timer);
  }
}

// ─── L3 Backend (Semantic / OpenBrain) ──────────────────────────────────────

async function l3Recall(key, deps) {
  if (!deps.searchMemory) return null;
  try {
    return await deps.searchMemory(key);
  } catch {
    return null;
  }
}

function l3Remember(key, value, opts, deps) {
  try {
    const record = {
      content: typeof value === "string" ? value : JSON.stringify(value),
      type: opts.type || "decision",
      source: opts.source || "brain.remember",
      project: opts.project || basename(deps.cwd),
      captured_at: new Date().toISOString(),
      key,
      _status: "pending",
      _attempts: 0,
      _enqueuedAt: new Date().toISOString(),
      _nextAttemptAt: new Date().toISOString(),
      _v: 1,
    };
    if (opts.tags) record.tags = opts.tags;
    if (opts.ttlMs) record.expiresAt = new Date(Date.now() + opts.ttlMs).toISOString();

    deps.appendForgeJsonl("openbrain-queue.jsonl", record, deps.cwd);
    return { ok: true, tier: "l3", ref: `openbrain://queue/${key}`, queued: true };
  } catch {
    return { ok: true, tier: "l3", ref: `openbrain://queue/${key}`, queued: true };
  }
}

function l3Forget(key, deps) {
  try {
    const record = {
      _action: "delete",
      key,
      _status: "pending",
      _attempts: 0,
      _enqueuedAt: new Date().toISOString(),
      _nextAttemptAt: new Date().toISOString(),
      _v: 1,
    };
    deps.appendForgeJsonl("openbrain-queue.jsonl", record, deps.cwd);
    return { ok: true, removed: ["l3-queued"] };
  } catch {
    return { ok: true, removed: [] };
  }
}

// ─── Default Dependencies ────────────────────────────────────────────────────

function buildDefaultDeps(overrides = {}) {
  const defaults = {
    cwd: overrides.cwd || process.cwd(),
    loadBug: () => null,
    readReviewItem: () => null,
    readReviewQueueState: () => null,
    readTemperingState: () => null,
    readPerfHistory: null,
    findLatestRun: () => null,
    readHubEvents: () => [],
    readCrucibleState: null,
    readForgeJsonl: null,
    searchMemory: null,
    appendForgeJsonl: () => {},
  };
  return { ...defaults, ...overrides };
}

async function recallFromTiers(key, opts, deps, readTiers) {
  for (const tier of readTiers) {
    if (tier === "l1") {
      const value = l1Recall(key, opts.runId);
      if (value != null) return { result: value, servedFrom: "l1" };
      continue;
    }

    if (tier === "l2") {
      const value = l2Recall(key, deps);
      if (value != null) return { result: value, servedFrom: "l2" };
      continue;
    }

    if (tier === "l3") {
      const value = await l3Recall(key, deps);
      if (value != null) return { result: value, servedFrom: "l3" };
    }
  }
  return { result: null, servedFrom: "miss" };
}

function shouldAttemptFederatedRecall(scope, result) {
  return result == null && (scope === "cross" || scope === "cross-project");
}

function recallFromFederation(key, cwd) {
  try {
    const hits = federationRead(key, { cwd });
    if (hits.length > 0) {
      return { result: hits[0].value, servedFrom: "federation" };
    }
  } catch { /* federation read never fails the call */ }
  return { result: null, servedFrom: "miss" };
}

// ─── Public API ──────────────────────────────────────────────────────────────

/**
 * Recall a value from the brain.
 *
 * @param {string} key — dotted-path with scope prefix (e.g., "project.bug.BUG-001")
 * @param {object} [opts] — { scope?, freshnessMs?, fallback?, runId? }
 * @param {object} [deps] — DI overrides for testing
 * @returns {Promise<any|null>}
 */
export async function recall(key, opts = {}, deps = {}) {
  validateKey(key);
  const d = buildDefaultDeps(deps);
  const { scope } = parseKey(key);
  const effectiveScope = opts.scope || scope;
  const { readTiers } = resolveTier(effectiveScope, opts);

  const trace = d.trace || null;
  const t0 = Date.now();
  let span = null;
  if (trace) {
    span = startSpan({ trace, name: "brain.recall", parentSpanId: trace.spans[0]?.spanId || null, kind: "INTERNAL", attributes: {
      key,
      "tier-attempted": readTiers.join(","),
    } });
  }

  let { result, servedFrom } = await recallFromTiers(key, opts, d, readTiers);

  // Phase-25 Slice 6 (MUST #10): for cross.* keys that still missed, attempt
  // a read-only fan-out across federated repos. Opt-in via .forge.json →
  // brain.federation.enabled; silent no-op when disabled. Returns the first
  // hit; ties broken by repo array order (deterministic).
  if (shouldAttemptFederatedRecall(effectiveScope, result)) {
    ({ result, servedFrom } = recallFromFederation(key, d.cwd));
  }

  if (span) {
    span.attributes["tier-served"] = servedFrom;
    span.attributes["cache-hit"] = false;
    span.attributes.durationMs = Date.now() - t0;
    endSpan(span, result != null ? "OK" : "UNSET");
  }

  return result;
}

/**
 * Store a value in the brain.
 *
 * @param {string} key
 * @param {any} value
 * @param {object} [opts] — { scope?, tags?, ttlMs?, runId?, type?, source?, project? }
 * @param {object} [deps] — DI overrides
 * @returns {{ ok: boolean, tier: string, ref: string, queued?: boolean }}
 */
export function remember(key, value, opts = {}, deps = {}) {
  validateKey(key);
  if (value === undefined) {
    throw new BrainKeyError(key, "value must not be undefined (use null for explicit clear)");
  }
  const d = buildDefaultDeps(deps);
  const { scope } = parseKey(key);
  const effectiveScope = opts.scope || scope;
  const { writeTier } = resolveTier(effectiveScope, opts);

  const trace = d.trace || null;
  const t0 = Date.now();
  let span = null;
  if (trace) {
    span = startSpan({ trace, name: "brain.remember", parentSpanId: trace.spans[0]?.spanId || null, kind: "INTERNAL", attributes: {
      key,
      "tier-attempted": writeTier,
    } });
  }

  let result;

  if (writeTier === "l1") {
    result = l1Remember(key, value, opts.runId, d.cwd);
  } else if (writeTier === "l2") {
    result = l2Remember(key, value, d);
  } else if (writeTier === "l3") {
    result = l3Remember(key, value, opts, d);
  } else if (writeTier === "l2+l3") {
    // Dual-write: L2 first (synchronous), then queue L3 (async, never blocks)
    const l2Result = l2Remember(key, value, d);
    let l3Queued = false;
    try {
      l3Remember(key, value, opts, d);
      l3Queued = true;
    } catch { /* L3 queue failure is non-fatal */ }

    if (span && l3Queued) {
      addEvent(span, "brain.l3.dual_write_queued", Severity.WARN, { key });
    }
    result = { ...l2Result, queued: l3Queued };
  } else {
    result = { ok: false, tier: writeTier, ref: null };
  }

  if (span) {
    span.attributes["tier-served"] = result.tier || writeTier;
    span.attributes.durationMs = Date.now() - t0;
    endSpan(span, result.ok ? "OK" : "ERROR");
  }

  return result;
}

/**
 * Remove a value from the brain.
 *
 * @param {string} key
 * @param {object} [opts] — { scope?, runId? }
 * @param {object} [deps] — DI overrides
 * @returns {{ ok: boolean, removed: string[] }}
 */
export function forget(key, opts = {}, deps = {}) {
  validateKey(key);
  const d = buildDefaultDeps(deps);
  const { scope } = parseKey(key);
  const effectiveScope = opts.scope || scope;
  const { readTiers, writeTier } = resolveTier(effectiveScope, opts);

  const trace = d.trace || null;
  const t0 = Date.now();
  let span = null;
  if (trace) {
    span = startSpan({ trace, name: "brain.forget", parentSpanId: trace.spans[0]?.spanId || null, kind: "INTERNAL", attributes: {
      key,
    } });
  }

  const allRemoved = [];

  if (writeTier === "l1" || readTiers.includes("l1")) {
    const r = l1Forget(key, opts.runId, d.cwd);
    allRemoved.push(...r.removed);
  }
  if (writeTier === "l2" || writeTier === "l2+l3" || readTiers.includes("l2")) {
    const r = l2Forget(key, d);
    allRemoved.push(...r.removed);
  }
  if (writeTier === "l3" || writeTier === "l2+l3" || readTiers.includes("l3")) {
    const r = l3Forget(key, d);
    allRemoved.push(...r.removed);
  }

  if (span) {
    span.attributes.removed = allRemoved.join(",");
    span.attributes.durationMs = Date.now() - t0;
    endSpan(span, "OK");
  }

  return { ok: true, removed: allRemoved };
}

// ─── Phase-ANVIL Slice 3: Hallmark Writer ────────────────────────────────────

const HALLMARK_ID_PATTERN = /^[a-zA-Z0-9][a-zA-Z0-9._-]*$/;

/**
 * Typed error for invalid hallmark IDs.
 */
export class HallmarkError extends Error {
  constructor(id, reason) {
    super(`Invalid hallmark id "${id}": ${reason}`);
    this.name = "HallmarkError";
    this.id = id;
    this.reason = reason;
  }
}

/**
 * Validate a hallmark ID. Rejects path traversal and non-alphanumeric patterns.
 * @param {string} id
 * @throws {HallmarkError}
 */
export function validateHallmarkId(id) {
  if (!id || typeof id !== "string") {
    throw new HallmarkError(String(id), "id must be a non-empty string");
  }
  if (id.includes("..")) {
    throw new HallmarkError(id, "path traversal ('..') is forbidden");
  }
  if (!HALLMARK_ID_PATTERN.test(id)) {
    throw new HallmarkError(id, "id must start with alphanumeric and contain only [a-zA-Z0-9._-]");
  }
}

/**
 * Write a hallmark record to `.forge/hallmarks/<id>.json`. Idempotent — last
 * write wins. The hallmark records a slice milestone, achievement, or marker.
 *
 * @param {string} id — stable identifier for the hallmark
 * @param {any} payload — arbitrary JSON-serialisable value
 * @param {{ source?: string, tags?: string[] }} [opts]
 * @param {{ cwd?: string, now?: () => string }} [deps]
 * @returns {{ ok: boolean, ref?: string, error?: string }}
 */
export function writeHallmark(id, payload, opts = {}, deps = {}) {
  validateHallmarkId(id);
  if (payload === undefined) {
    throw new HallmarkError(id, "payload must not be undefined");
  }
  const cwd = deps.cwd || process.cwd();
  const hallmarksDir = resolve(cwd, ".forge", "hallmarks");
  try {
    mkdirSync(hallmarksDir, { recursive: true });
    const filePath = resolve(hallmarksDir, `${id}.json`);
    if (!filePath.startsWith(hallmarksDir)) {
      throw new HallmarkError(id, "path confinement violation");
    }
    const record = {
      id,
      payload,
      writtenAt: typeof deps.now === "function" ? deps.now() : new Date().toISOString(),
    };
    if (opts.source) record.source = opts.source;
    if (opts.tags) record.tags = opts.tags;
    const tmpPath = filePath + ".tmp." + randomUUID().slice(0, 8);
    writeFileSync(tmpPath, JSON.stringify(record, null, 2));
    renameSync(tmpPath, filePath);
    return { ok: true, ref: filePath };
  } catch (err) {
    if (err instanceof HallmarkError) throw err;
    return { ok: false, error: err.message };
  }
}

/**
 * Read a hallmark by ID from `.forge/hallmarks/<id>.json`.
 * Returns the stored record, or `null` if absent.
 *
 * @param {string} id
 * @param {{ cwd?: string }} [deps]
 * @returns {{ id, payload, writtenAt, source?, tags? } | null}
 */
export function readHallmark(id, deps = {}) {
  validateHallmarkId(id);
  const cwd = deps.cwd || process.cwd();
  const hallmarksDir = resolve(cwd, ".forge", "hallmarks");
  const filePath = resolve(hallmarksDir, `${id}.json`);
  if (!filePath.startsWith(hallmarksDir)) return null;
  if (!existsSync(filePath)) return null;
  try {
    return JSON.parse(readFileSync(filePath, "utf-8"));
  } catch {
    return null;
  }
}

/**
 * List all hallmarks in `.forge/hallmarks/`, sorted by `writtenAt` ascending.
 * Returns an empty array when the directory is absent or unreadable.
 *
 * @param {{ sort?: boolean }} [opts] — set `sort: false` to skip chronological sort
 * @param {{ cwd?: string }} [deps]
 * @returns {Array<{ id, payload, writtenAt, source?, tags? }>}
 */
export function listHallmarks(opts = {}, deps = {}) {
  const cwd = deps.cwd || process.cwd();
  const hallmarksDir = resolve(cwd, ".forge", "hallmarks");
  if (!existsSync(hallmarksDir)) return [];
  try {
    const entries = readdirSync(hallmarksDir, { withFileTypes: true });
    const hallmarks = [];
    for (const entry of entries) {
      if (!entry.isFile() || !entry.name.endsWith(".json")) continue;
      const filePath = resolve(hallmarksDir, entry.name);
      if (!filePath.startsWith(hallmarksDir)) continue;
      try {
        const record = JSON.parse(readFileSync(filePath, "utf-8"));
        hallmarks.push(record);
      } catch { /* skip malformed files */ }
    }
    if (opts.sort !== false) {
      hallmarks.sort((a, b) => (a.writtenAt || "").localeCompare(b.writtenAt || ""));
    }
    return hallmarks;
  } catch {
    return [];
  }
}

// ─── Phase-ANVIL Slice 3: Capability-Negotiating L3 Client ───────────────────

/**
 * L3 capability identifiers. Each key maps to a feature the L3 backend may
 * or may not support depending on the injected deps.
 */
export const L3_CAPABILITY = Object.freeze({
  SEARCH: "search",
  WRITE: "write",
  DELETE: "delete",
  TAGS: "tags",
  TTL: "ttl",
});

/**
 * Negotiate which L3 capabilities are available given the current deps.
 *
 * Resolution rules:
 * - `SEARCH`: `deps.searchMemory` is a function
 * - `WRITE`, `DELETE`, `TAGS`, `TTL`: `deps.appendForgeJsonl` is a function
 *   (write capability implies tagging, TTL, and delete support via the queue)
 *
 * @param {object} [deps]
 * @returns {{ has: (cap: string) => boolean, list: () => string[], canSearch: boolean, canWrite: boolean, canDelete: boolean, canTags: boolean, canTTL: boolean }}
 */
export function negotiateL3Capabilities(deps = {}) {
  const capabilities = new Set();
  if (typeof deps.searchMemory === "function") capabilities.add(L3_CAPABILITY.SEARCH);
  if (typeof deps.appendForgeJsonl === "function") {
    capabilities.add(L3_CAPABILITY.WRITE);
    capabilities.add(L3_CAPABILITY.DELETE);
    capabilities.add(L3_CAPABILITY.TAGS);
    capabilities.add(L3_CAPABILITY.TTL);
  }
  return {
    has: (cap) => capabilities.has(cap),
    list: () => [...capabilities],
    canSearch: capabilities.has(L3_CAPABILITY.SEARCH),
    canWrite: capabilities.has(L3_CAPABILITY.WRITE),
    canDelete: capabilities.has(L3_CAPABILITY.DELETE),
    canTags: capabilities.has(L3_CAPABILITY.TAGS),
    canTTL: capabilities.has(L3_CAPABILITY.TTL),
  };
}

/**
 * Create a capability-aware L3 client. The client probes `deps` at creation
 * time and routes each operation only when the required capability is present.
 * All operations are safe no-ops when the capability is absent.
 *
 * @param {object} [deps] — DI bundle: { searchMemory?, appendForgeJsonl?, cwd? }
 * @returns {{
 *   capabilities: ReturnType<typeof negotiateL3Capabilities>,
 *   recall: (key: string) => Promise<any|null>,
 *   remember: (key: string, value: any, opts?: object) => { ok: boolean, queued?: boolean, skipped?: boolean, reason?: string },
 *   forget: (key: string) => { ok: boolean, queued?: boolean, skipped?: boolean, reason?: string },
 * }}
 */
export function createL3Client(deps = {}) {
  const caps = negotiateL3Capabilities(deps);

  return {
    capabilities: caps,

    async recall(key) {
      if (!caps.canSearch) return null;
      try {
        return await deps.searchMemory(key);
      } catch {
        return null;
      }
    },

    remember(key, value, opts = {}) {
      if (!caps.canWrite) {
        return { ok: false, skipped: true, reason: "write capability unavailable" };
      }
      const record = {
        content: typeof value === "string" ? value : JSON.stringify(value),
        type: opts.type || "decision",
        source: opts.source || "brain.l3",
        key,
        _status: "pending",
        _attempts: 0,
        _enqueuedAt: new Date().toISOString(),
        _nextAttemptAt: new Date().toISOString(),
        _v: 1,
      };
      if (caps.canTags && opts.tags) record.tags = opts.tags;
      if (caps.canTTL && opts.ttlMs) record.expiresAt = new Date(Date.now() + opts.ttlMs).toISOString();
      try {
        deps.appendForgeJsonl("openbrain-queue.jsonl", record, deps.cwd);
        return { ok: true, queued: true };
      } catch (err) {
        return { ok: false, error: err.message };
      }
    },

    forget(key) {
      if (!caps.canDelete) {
        return { ok: false, skipped: true, reason: "delete capability unavailable" };
      }
      const record = {
        _action: "delete",
        key,
        _status: "pending",
        _attempts: 0,
        _enqueuedAt: new Date().toISOString(),
        _nextAttemptAt: new Date().toISOString(),
        _v: 1,
      };
      try {
        deps.appendForgeJsonl("openbrain-queue.jsonl", record, deps.cwd);
        return { ok: true, queued: true };
      } catch (err) {
        return { ok: false, error: err.message };
      }
    },
  };
}

// ─── Public API ──────────────────────────────────────────────────────────────

/**
 * Introspection helper — describe what a key resolves to.
 *
 * @param {string} key
 * @returns {{ layout: { scope: string, segments: string[], entity: string|null, id: string|null }, examples: string[] }}
 */
export function describeKey(key) {
  validateKey(key);
  const parsed = parseKey(key);
  const examples = [];

  if (parsed.scope === "session") {
    examples.push("session.run.abc123.slice.1", "session.run.abc123.context");
  } else if (parsed.scope === "project") {
    examples.push("project.bug.BUG-001", "project.review.REV-001", "project.tempering.state", "project.run.latest");
  } else if (parsed.scope === "cross") {
    examples.push("cross.pattern.auth-flow", "cross.convention.naming");
  }

  return { layout: parsed, examples };
}

// ─── Phase-ANVIL Slice 4: L3 Boundary with DLQ Fallback ─────────────────────

/**
 * Wrap an L3 write with Slag-heap DLQ fallback.
 *
 * Attempts `writeFn()`. On throw, the record is appended to the Anvil DLQ
 * via `deps.dlqAppend` (or `anvilDlqAppend` by default), then the original
 * error is re-thrown so the caller still sees the failure.
 *
 * Both outcomes are guaranteed:
 *   1. The error propagates back to the caller.
 *   2. The record lands on the DLQ for later re-drive.
 * DLQ append failure is non-fatal — it never swallows the original error.
 *
 * @param {Function} writeFn — async or sync function that performs the L3 write
 * @param {object} [record] — DLQ record fields (toolName, inputs, key, etc.)
 * @param {{ dlqAppend?: Function, cwd?: string }} [deps]
 * @returns {Promise<*>} — resolves with writeFn result on success, or throws on failure
 */
export async function withL3Boundary(writeFn, record = {}, deps = {}) {
  try {
    return await writeFn();
  } catch (err) {
    const dlqAppend = typeof deps.dlqAppend === "function" ? deps.dlqAppend : _anvilDlqAppend;
    try {
      dlqAppend(
        { ...record, error: err?.message || String(err) },
        { cwd: deps.cwd }
      );
    } catch {
      // DLQ append failure is non-fatal — never swallow the original error
    }
    throw err;
  }
}

/**
 * Plan Forge Bridge — External Notifications & Webhook Dispatcher
 *
 * Subscribes to WebSocket hub events and dispatches formatted notifications
 * to external platforms: Telegram, Slack, Discord, and generic webhooks.
 *
 * Phase 16: OpenClaw Bridge
 *
 * Architecture:
 *   - BridgeManager connects to the hub as a WebSocket CLIENT (read-only subscriber)
 *   - Hub is NOT modified — bridge observes events via standard ws:// connection
 *   - Notification level filtering: all | important | critical
 *   - Rate limiter: max 1 notification per 5s per channel (anti-spam)
 *   - Config: .forge.json `bridge` section
 *   - HTTP client: Node.js built-in fetch (no new dependencies)
 *
 * @module bridge
 */

import { WebSocket } from "ws";
import { readFileSync, existsSync } from "node:fs";
import { resolve, basename } from "node:path";
import { appendEvent, SECURITY_RISK } from "./orchestrator.mjs";
import { authenticate } from "./auth/index.mjs";

// ─── Constants ────────────────────────────────────────────────────────

const RATE_LIMIT_MS = 5_000;
const RECONNECT_DELAY_MS = 5_000;

/**
 * Which event types belong to each notification level.
 * Levels are hierarchical: critical ⊆ important ⊆ all.
 */
const LEVEL_EVENTS = {
  all: new Set([
    "run-started", "slice-started", "slice-completed",
    "slice-failed", "run-completed", "run-aborted",
  ]),
  important: new Set([
    "run-started", "slice-failed", "run-completed", "run-aborted",
  ]),
  critical: new Set([
    "slice-failed", "run-aborted",
    // run-completed only if there were failures
  ]),
};

// ─── Config ───────────────────────────────────────────────────────────

/**
 * Load bridge configuration from .forge.json in the project directory.
 *
 * Expected shape:
 * ```json
 * {
 *   "bridge": {
 *     "enabled": true,
 *     "channels": [
 *       { "type": "telegram", "url": "...", "chatId": "...", "level": "important" },
 *       { "type": "slack",    "url": "...", "level": "all" },
 *       { "type": "discord",  "url": "...", "level": "critical" },
 *       { "type": "generic",  "url": "...", "level": "all" }
 *     ]
 *   }
 * }
 * ```
 *
 * @param {string} cwd - Project directory
 * @returns {{ enabled: boolean, channels: Array } | null}
 */
function loadBridgeConfig(cwd) {
  const configPath = resolve(cwd, ".forge.json");
  if (!existsSync(configPath)) return null;
  try {
    const config = JSON.parse(readFileSync(configPath, "utf-8"));
    return config.bridge ?? null;
  } catch {
    return null;
  }
}

// ─── Event Text Helpers ───────────────────────────────────────────────

/**
 * Get a short title for a hub event (used by Discord embeds and logging).
 * @param {object} event
 * @returns {string}
 */
function getEventTitle(event) {
  switch (event.type) {
    case "run-started":     return "🚀 Plan Forge — Execution Started";
    case "slice-started":   return `▶️ Slice ${event.sliceId} Started`;
    case "slice-completed": return `✅ Slice ${event.sliceId} Passed`;
    case "slice-failed":    return `❌ Slice ${event.sliceId} Failed`;
    case "run-completed":   return (event.results?.failed ?? 0) === 0
                              ? "🏁 Plan Forge — Execution Complete"
                              : "⚠️ Plan Forge — Execution Finished with Failures";
    case "run-aborted":     return "🛑 Plan Forge — Execution Aborted";
    default:                return `Plan Forge — ${event.type}`;
  }
}

/**
 * Get a Discord embed color for a hub event.
 * @param {object} event
 * @returns {number} RGB integer
 */
function getEventColor(event) {
  switch (event.type) {
    case "run-started":
    case "slice-started":   return 0x3498db;  // blue
    case "slice-completed": return 0x2ecc71;  // green
    case "slice-failed":
    case "run-aborted":     return 0xe74c3c;  // red
    case "run-completed":   return (event.results?.failed ?? 0) === 0 ? 0x2ecc71 : 0xe74c3c;
    default:                return 0x95a5a6;  // grey
  }
}

/**
 * Format a hub event as a human-readable text string.
 *
 * @param {object} event - Hub event payload
 * @param {"plain"|"markdown"} style - Text style
 * @returns {string}
 */
function _fmtRunStarted(event, fmt) {
  const plan = event.plan ? fmt.code(basename(event.plan)) : "plan";
  const count = event.sliceCount ?? "?";
  const mode = event.mode ?? "auto";
  return `🚀 ${fmt.bold("Plan Forge")} — Executing ${plan} (${count} slices, ${mode} mode)`;
}

function _fmtSliceStarted(event) {
  return `▶️ Slice ${event.sliceId} started${event.title ? `: ${event.title}` : ""}`;
}

function _fmtSliceCompleted(event) {
  const dur = event.duration != null ? `${Math.round(event.duration / 1000)}s` : null;
  const cost = event.cost_usd != null ? `$${event.cost_usd.toFixed(2)}` : null;
  const detail = [dur, cost].filter(Boolean).join(", ");
  return `✅ Slice ${event.sliceId} passed${detail ? ` (${detail})` : ""}`;
}

function _fmtSliceFailed(event, fmt) {
  const cmd = event.failedCommand ? fmt.code(event.failedCommand) : null;
  const err = !cmd && event.error ? event.error.slice(0, 120) : null;
  const detail = cmd ?? err ?? "";
  return `❌ Slice ${event.sliceId} FAILED${detail ? ` — ${detail}` : ""}`;
}

function _fmtRunCompleted(event, fmt) {
  const r = event.results ?? {};
  const passed = r.passed ?? 0;
  const failed = r.failed ?? 0;
  const total = passed + failed;
  const plan = event.plan ? fmt.code(basename(event.plan)) : null;
  const score = event.analyze?.score != null ? ` Score: ${event.analyze.score}.` : "";
  const cost = event.cost?.total_cost_usd != null
    ? ` Cost: $${Number(event.cost.total_cost_usd).toFixed(2)}.`
    : "";
  const summary = total > 0 ? `${passed}/${total} passed.` : "Complete.";
  return `🏁 ${fmt.bold("Plan Forge")}${plan ? ` — ${plan}` : ""} ${summary}${score}${cost}`;
}

function _fmtRunAborted(event) {
  return `🛑 Execution aborted at slice ${event.sliceId ?? "?"}${event.reason ? `: ${event.reason}` : ""}`;
}

const _FORMAT_EVENT_HANDLERS = {
  "run-started": _fmtRunStarted,
  "slice-started": _fmtSliceStarted,
  "slice-completed": _fmtSliceCompleted,
  "slice-failed": _fmtSliceFailed,
  "run-completed": _fmtRunCompleted,
  "run-aborted": _fmtRunAborted,
};

function formatEventText(event, style = "plain") {
  const fmt = {
    bold: (s) => style === "markdown" ? `*${s}*` : s,
    code: (s) => style === "markdown" ? `\`${s}\`` : s,
  };
  const fn = _FORMAT_EVENT_HANDLERS[event.type];
  return fn ? fn(event, fmt) : `${event.type}: ${JSON.stringify(event)}`;
}

// ─── Telegram MarkdownV2 Helpers ─────────────────────────────────────

/**
 * Escape text for Telegram MarkdownV2.
 * All reserved characters outside formatting entities must be preceded by `\`.
 * Reserved: _ * [ ] ( ) ~ ` > # + - = | { } . !
 * @param {string|number} text
 * @returns {string}
 */
function escapeMdV2(text) {
  return String(text).replace(/[_*[\]()~`>#+=|{}.!-]/g, "\\$&");
}

/** Telegram MarkdownV2 bold — content is auto-escaped. */
function tgBold(text) { return `*${escapeMdV2(text)}*`; }

/** Telegram MarkdownV2 inline code — no escaping needed inside backticks. */
function tgCode(text) { return `\`${text}\``; }

/**
 * Build a Telegram MarkdownV2 message string for a hub event.
 * @param {object} event
 * @param {{ sliceCount?: number, plan?: string, model?: string }} [context] - Cached run context
 * @returns {string}
 */
function _tgRunStarted(event) {
  const plan = event.plan ? tgCode(basename(event.plan)) : escapeMdV2("plan");
  const count = escapeMdV2(event.sliceCount ?? "?");
  const mode = escapeMdV2(event.mode ?? "auto");
  return `🚀 ${tgBold("Plan Forge")} — Executing ${plan} \\(${count} slices, ${mode} mode\\)`;
}

function _tgSliceStarted(event, sliceRef) {
  const id = sliceRef(event.sliceId);
  const title = event.title ? ` \\— ${escapeMdV2(event.title)}` : "";
  return `▶️ Slice ${id} started${title}`;
}

function _tgSliceCompleted(event, sliceRef) {
  const id = sliceRef(event.sliceId);
  const dur = event.duration != null ? escapeMdV2(`${Math.round(event.duration / 1000)}s`) : null;
  const cost = event.cost_usd != null ? escapeMdV2(`$${event.cost_usd.toFixed(2)}`) : null;
  const detail = [dur, cost].filter(Boolean).join(", ");
  return `✅ Slice ${id} passed${detail ? ` \\(${detail}\\)` : ""}`;
}

function _tgSliceFailed(event, sliceRef) {
  const id = sliceRef(event.sliceId);
  const cmd = event.failedCommand ? tgCode(event.failedCommand) : null;
  const err = !cmd && event.error ? escapeMdV2(event.error.slice(0, 120)) : null;
  const detail = cmd ?? err ?? "";
  return `❌ Slice ${id} FAILED${detail ? ` — ${detail}` : ""}`;
}

function _tgRunCompleted(event) {
  const r = event.results ?? {};
  const passed = r.passed ?? 0;
  const failed = r.failed ?? 0;
  const total = passed + failed;
  const plan = event.plan ? ` — ${tgCode(basename(event.plan))}` : "";
  const summary = escapeMdV2(total > 0 ? `${passed}/${total} passed` : "Complete");
  const score = event.analyze?.score != null
    ? ` Score: ${escapeMdV2(String(event.analyze.score))}\\.`
    : "";
  const cost = event.cost?.total_cost_usd != null
    ? ` Cost: ${escapeMdV2(`$${Number(event.cost.total_cost_usd).toFixed(2)}`)}\\.`
    : "";
  const icon = failed === 0 ? "🏁" : "⚠️";
  return `${icon} ${tgBold("Plan Forge")}${plan} ${summary}\\.${score}${cost}`;
}

function _tgRunAborted(event) {
  const id = escapeMdV2(event.sliceId ?? "?");
  const reason = event.reason ? `: ${escapeMdV2(event.reason)}` : "";
  return `🛑 Execution aborted at slice ${id}${reason}`;
}

const _TELEGRAM_HANDLERS = {
  "run-started": _tgRunStarted,
  "slice-started": _tgSliceStarted,
  "slice-completed": _tgSliceCompleted,
  "slice-failed": _tgSliceFailed,
  "run-completed": _tgRunCompleted,
  "run-aborted": _tgRunAborted,
};

function buildTelegramText(event, context) {
  const sliceRef = (id) => {
    const total = context?.sliceCount;
    return total != null
      ? `${escapeMdV2(id ?? "?")}/${escapeMdV2(total)}`
      : escapeMdV2(id ?? "?");
  };
  const fn = _TELEGRAM_HANDLERS[event.type];
  return fn ? fn(event, sliceRef) : escapeMdV2(`${event.type}: ${JSON.stringify(event)}`);
}

// ─── Slack Block Kit Helpers ──────────────────────────────────────────

/**
 * Render a text-based progress bar for use in Slack context blocks.
 * Example: "▓▓▓▒▒▒▒▒ 3/8 (37%)"
 *
 * @param {string|number} current - Current slice index (1-based)
 * @param {string|number} total   - Total slice count
 * @returns {string}
 */
function slackProgressBar(current, total) {
  const BAR_LEN = 8;
  const n = typeof current === "string" ? parseInt(current, 10) : current;
  const t = typeof total === "string" ? parseInt(total, 10) : total;
  if (isNaN(n) || isNaN(t) || t <= 0) return `${current}/${total}`;
  const filled = Math.round((n / t) * BAR_LEN);
  const bar = "▓".repeat(Math.max(0, filled)) + "▒".repeat(Math.max(0, BAR_LEN - filled));
  const pct = Math.round((n / t) * 100);
  return `${bar} ${n}/${t} (${pct}%)`;
}

/**
 * Build Slack Block Kit blocks for a hub event.
 * Includes context blocks for metadata (plan, cost, model), an optional
 * progress bar when sliceCount is known, and approval action buttons
 * when `channel.approvalRequired` is true.
 *
 * @param {object} event
 * @param {object} [channel] - Channel config (for approvalRequired + serverUrl)
 * @param {{ sliceCount?: number, plan?: string, model?: string }} [context] - Cached run context
 * @returns {Array}
 */
function _slackSliceLabel(event, context) {
  return context?.sliceCount
    ? `*Slice ${event.sliceId ?? "?"}/${context.sliceCount}*`
    : `*Slice ${event.sliceId ?? "?"}*`;
}

function _slackProgressContext(event, context) {
  if (!context?.sliceCount) return null;
  return {
    type: "context",
    elements: [{ type: "mrkdwn", text: slackProgressBar(event.sliceId ?? 0, context.sliceCount) }],
  };
}

function _slackRunStarted(event) {
  const blocks = [];
  const planName = event.plan ? basename(event.plan) : null;
  const header = planName
    ? `🚀 *Plan Forge* — Executing \`${planName}\``
    : "🚀 *Plan Forge* — Execution Started";
  blocks.push({ type: "section", text: { type: "mrkdwn", text: header } });
  const ctx = [
    event.sliceCount != null && `${event.sliceCount} slices`,
    event.mode && `${event.mode} mode`,
    event.model,
  ].filter(Boolean);
  if (ctx.length) {
    blocks.push({ type: "context", elements: [{ type: "mrkdwn", text: ctx.join(" · ") }] });
  }
  return blocks;
}

function _slackSliceStarted(event, context) {
  const blocks = [];
  const title = event.title ? `: ${event.title}` : "";
  const sliceLabel = _slackSliceLabel(event, context);
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: `▶️ ${sliceLabel} started${title}` },
  });
  const progress = _slackProgressContext(event, context);
  if (progress) blocks.push(progress);
  return blocks;
}

function _slackSliceCompleted(event, context) {
  const blocks = [];
  const sliceLabel = _slackSliceLabel(event, context);
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: `✅ ${sliceLabel} passed` },
  });
  const ctx = [
    context?.sliceCount && slackProgressBar(event.sliceId ?? 0, context.sliceCount),
    event.duration != null && `${Math.round(event.duration / 1000)}s`,
    event.cost_usd != null && `$${event.cost_usd.toFixed(2)}`,
    event.tokens?.model,
  ].filter(Boolean);
  if (ctx.length) {
    blocks.push({ type: "context", elements: [{ type: "mrkdwn", text: ctx.join(" · ") }] });
  }
  return blocks;
}

function _slackSliceFailed(event, context) {
  const blocks = [];
  const sliceLabel = _slackSliceLabel(event, context);
  const cmd = event.failedCommand ? ` — \`${event.failedCommand}\`` : "";
  const err = !event.failedCommand && event.error ? ` — ${event.error.slice(0, 200)}` : "";
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: `❌ ${sliceLabel} FAILED${cmd || err}` },
  });
  const progress = _slackProgressContext(event, context);
  if (progress) blocks.push(progress);
  return blocks;
}

function _slackApprovalActions(event, channel) {
  const serverUrl = (channel.serverUrl ?? "").replace(/\/$/, "");
  return [
    { type: "divider" },
    {
      type: "actions",
      elements: [
        {
          type: "button",
          text: { type: "plain_text", text: "✅ Approve", emoji: true },
          style: "primary",
          ...(serverUrl && { url: `${serverUrl}/api/bridge/approve/${event.runId}?action=approve` }),
          value: `approve:${event.runId}`,
        },
        {
          type: "button",
          text: { type: "plain_text", text: "❌ Reject", emoji: true },
          style: "danger",
          ...(serverUrl && { url: `${serverUrl}/api/bridge/approve/${event.runId}?action=reject` }),
          value: `reject:${event.runId}`,
        },
      ],
    },
  ];
}

function _slackRunCompleted(event, _context, channel) {
  const blocks = [];
  const r = event.results ?? {};
  const passed = r.passed ?? 0;
  const failed = r.failed ?? 0;
  const total = passed + failed;
  const planName = event.plan ? basename(event.plan) : null;
  const icon = failed === 0 ? "🏁" : "⚠️";
  const summary = total > 0 ? `${passed}/${total} passed` : "Complete";
  const header = planName
    ? `${icon} *${planName}* — ${summary}`
    : `${icon} *Plan Forge* — ${summary}`;
  blocks.push({ type: "section", text: { type: "mrkdwn", text: header } });
  const ctx = [
    event.analyze?.score != null && `Score: ${event.analyze.score}/100`,
    event.cost?.total_cost_usd != null && `$${Number(event.cost.total_cost_usd).toFixed(2)}`,
    event.model,
  ].filter(Boolean);
  if (ctx.length) {
    blocks.push({ type: "context", elements: [{ type: "mrkdwn", text: ctx.join(" · ") }] });
  }
  if (channel?.approvalRequired && failed === 0 && event.runId) {
    blocks.push(..._slackApprovalActions(event, channel));
  }
  return blocks;
}

function _slackRunAborted(event) {
  const reason = event.reason ? `: ${event.reason}` : "";
  return [{
    type: "section",
    text: {
      type: "mrkdwn",
      text: `🛑 *Plan Forge* — Aborted at Slice ${event.sliceId ?? "?"}${reason}`,
    },
  }];
}

const _SLACK_BLOCK_HANDLERS = {
  "run-started": _slackRunStarted,
  "slice-started": _slackSliceStarted,
  "slice-completed": _slackSliceCompleted,
  "slice-failed": _slackSliceFailed,
  "run-completed": _slackRunCompleted,
  "run-aborted": _slackRunAborted,
};

function buildSlackBlocks(event, channel, context) {
  const fn = _SLACK_BLOCK_HANDLERS[event.type];
  const blocks = fn
    ? fn(event, context, channel)
    : [{ type: "section", text: { type: "mrkdwn", text: `Plan Forge — \`${event.type}\`` } }];
  blocks.push({ type: "divider" });
  return blocks;
}

// ─── Discord Embed Field Helpers ──────────────────────────────────────

/**
 * Build Discord embed fields for a hub event.
 * Returns per-event fields: Plan, Slice, Status, Duration, Cost, Model.
 *
 * @param {object} event
 * @param {{ sliceCount?: number, plan?: string, model?: string }} [context] - Cached run context
 * @returns {Array<{ name: string, value: string, inline: boolean }>}
 */
function _discordRunStarted(event) {
  const fields = [];
  if (event.plan) fields.push({ name: "Plan", value: basename(event.plan), inline: true });
  if (event.mode) fields.push({ name: "Mode", value: event.mode, inline: true });
  if (event.sliceCount != null) fields.push({ name: "Slices", value: String(event.sliceCount), inline: true });
  if (event.model) fields.push({ name: "Model", value: event.model, inline: true });
  return fields;
}

function _discordSliceStarted(event, sliceRef) {
  const fields = [{ name: "Slice", value: sliceRef(event.sliceId), inline: true }];
  if (event.title) fields.push({ name: "Title", value: event.title, inline: true });
  return fields;
}

function _discordSliceCompleted(event, sliceRef) {
  const fields = [
    { name: "Slice", value: sliceRef(event.sliceId), inline: true },
    { name: "Status", value: "✅ Passed", inline: true },
  ];
  if (event.duration != null) fields.push({ name: "Duration", value: `${Math.round(event.duration / 1000)}s`, inline: true });
  if (event.cost_usd != null) fields.push({ name: "Cost", value: `$${event.cost_usd.toFixed(2)}`, inline: true });
  if (event.tokens?.model) fields.push({ name: "Model", value: event.tokens.model, inline: true });
  return fields;
}

function _discordSliceFailed(event, sliceRef) {
  const fields = [
    { name: "Slice", value: sliceRef(event.sliceId), inline: true },
    { name: "Status", value: "❌ Failed", inline: true },
  ];
  if (event.failedCommand) fields.push({ name: "Failed Command", value: `\`${event.failedCommand}\``, inline: false });
  else if (event.error) fields.push({ name: "Error", value: event.error.slice(0, 1024), inline: false });
  return fields;
}

function _discordRunCompleted(event) {
  const fields = [];
  const r = event.results ?? {};
  const passed = r.passed ?? 0;
  const failed = r.failed ?? 0;
  const total = passed + failed;
  if (event.plan) fields.push({ name: "Plan", value: basename(event.plan), inline: true });
  if (total > 0) fields.push({ name: "Results", value: `${passed}/${total} passed`, inline: true });
  if (event.analyze?.score != null) fields.push({ name: "Score", value: `${event.analyze.score}/100`, inline: true });
  if (event.cost?.total_cost_usd != null) fields.push({ name: "Cost", value: `$${Number(event.cost.total_cost_usd).toFixed(2)}`, inline: true });
  if (event.totalDuration != null) fields.push({ name: "Duration", value: `${Math.round(event.totalDuration / 60000)}m`, inline: true });
  return fields;
}

function _discordRunAborted(event, sliceRef) {
  const fields = [];
  if (event.sliceId) fields.push({ name: "Aborted at Slice", value: sliceRef(event.sliceId), inline: true });
  if (event.reason) fields.push({ name: "Reason", value: event.reason, inline: false });
  return fields;
}

const _DISCORD_FIELD_HANDLERS = {
  "run-started": _discordRunStarted,
  "slice-started": _discordSliceStarted,
  "slice-completed": _discordSliceCompleted,
  "slice-failed": _discordSliceFailed,
  "run-completed": _discordRunCompleted,
  "run-aborted": _discordRunAborted,
};

function buildDiscordFields(event, context) {
  const sliceRef = (id) =>
    context?.sliceCount != null ? `${id ?? "?"}/${context.sliceCount}` : String(id ?? "?");
  const fn = _DISCORD_FIELD_HANDLERS[event.type];
  return fn ? fn(event, sliceRef) : [];
}

// ─── Platform Formatters ──────────────────────────────────────────────

/**
 * Format a hub event for the Telegram Bot API (sendMessage) using MarkdownV2.
 * Emoji status indicators per event type with proper character escaping.
 *
 * @param {object} event - Hub event
 * @param {object} channel - Channel config (must include `chatId`)
 * @param {{ sliceCount?: number, plan?: string, model?: string }} [context] - Cached run context
 * @returns {{ chat_id: string, text: string, parse_mode: string, reply_markup?: object }}
 */
export function formatTelegram(event, channel, context) {
  const payload = {
    chat_id: channel.chatId ?? "",
    text: buildTelegramText(event, context),
    parse_mode: "MarkdownV2",
  };

  // Add inline keyboard approval buttons for approval-required channels
  if (channel.approvalRequired && event.runId && event.type === "run-completed") {
    const serverUrl = (channel.serverUrl ?? "").replace(/\/$/, "");
    if (serverUrl) {
      payload.reply_markup = {
        inline_keyboard: [[
          { text: "✅ Approve", url: `${serverUrl}/api/bridge/approve/${event.runId}?action=approve` },
          { text: "❌ Reject",  url: `${serverUrl}/api/bridge/approve/${event.runId}?action=reject` },
        ]],
      };
    }
  }

  return payload;
}

/**
 * Format a hub event for Slack Incoming Webhooks using Block Kit.
 * Rich blocks with plan name, progress bar, cost, model info, and optional
 * approval action buttons when `channel.approvalRequired` is true.
 *
 * @param {object} event - Hub event
 * @param {object} [channel] - Channel config (for approvalRequired + serverUrl)
 * @param {{ sliceCount?: number, plan?: string, model?: string }} [context] - Cached run context
 * @returns {{ text: string, blocks: Array }}
 */
export function formatSlack(event, channel, context) {
  return {
    text: formatEventText(event, "plain"),
    blocks: buildSlackBlocks(event, channel, context),
  };
}

/**
 * Format a hub event for Discord Webhooks using Embeds.
 * Color-coded sidebar (green=pass, red=fail, blue=info) with per-event
 * fields: Plan, Slice, Status, Duration, Cost. Footer includes model + timestamp.
 *
 * @param {object} event - Hub event
 * @param {{ sliceCount?: number, plan?: string, model?: string }} [context] - Cached run context
 * @returns {{ embeds: Array }}
 */
export function formatDiscord(event, context) {
  const fields = buildDiscordFields(event, context);
  const model = event.model ?? event.tokens?.model ?? context?.model ?? null;
  const footerParts = ["Plan Forge", model, event.timestamp ?? new Date().toISOString()].filter(Boolean);
  return {
    embeds: [
      {
        title: getEventTitle(event),
        description: formatEventText(event, "plain"),
        color: getEventColor(event),
        ...(fields.length > 0 && { fields }),
        footer: { text: footerParts.join(" • ") },
      },
    ],
  };
}

/**
 * Format a hub event for a generic webhook.
 * Clean JSON envelope with event type, payload, and metadata.
 *
 * @param {object} event - Hub event
 * @returns {{ source: string, schemaVersion: string, timestamp: string, event: object }}
 */
export function formatGeneric(event) {
  return {
    source: "plan-forge",
    schemaVersion: "1.0",
    timestamp: new Date().toISOString(),
    event,
  };
}

// ─── Tool Deny Filter ─────────────────────────────────────────────────

/**
 * Determine whether a tool-call event should be blocked based on the plan's
 * `tools.deny` list parsed from frontmatter.
 *
 * Phase-WORKER-GUARDRAILS Slice 6 (A8): MCP bridge filter for `tools.deny`.
 * The orchestrator extracts `meta.toolsDeny` from plan frontmatter and passes it
 * here; the bridge drops any `tool-call` / `tool-invoked` event whose `toolName`
 * appears in the denied list before forwarding to external notification channels.
 *
 * @param {string}          toolName    - The MCP tool name being invoked
 * @param {string[] | null} deniedTools - List from plan frontmatter `tools.deny`
 * @returns {boolean} true when the tool is denied and must be blocked
 */
export function isDeniedTool(toolName, deniedTools) {
  if (!deniedTools || !Array.isArray(deniedTools) || deniedTools.length === 0) return false;
  return deniedTools.includes(toolName);
}



class RateLimiter {
  /**
   * @param {number} windowMs - Minimum milliseconds between notifications per key
   */
  constructor(windowMs = RATE_LIMIT_MS) {
    this.windowMs = windowMs;
    this._lastSent = new Map(); // channelKey → timestamp (ms)
  }

  /** @param {string} key @returns {boolean} */
  isAllowed(key) {
    const last = this._lastSent.get(key) ?? 0;
    return Date.now() - last >= this.windowMs;
  }

  /** @param {string} key */
  record(key) {
    this._lastSent.set(key, Date.now());
  }
}

// ─── BridgeManager ────────────────────────────────────────────────────

/**
 * BridgeManager connects to the Plan Forge WebSocket hub as a subscriber
 * and dispatches notifications to configured external channels.
 *
 * Usage:
 * ```js
 * const bridge = new BridgeManager({ cwd: '/path/to/project' });
 * bridge.connect(); // reads port from .forge/server-ports.json
 * // ...
 * bridge.stop();
 * ```
 */
export class BridgeManager {
  /**
   * @param {object} options
   * @param {string} [options.cwd]         - Project directory (for .forge.json + server-ports.json)
   * @param {object} [options.config]      - Bridge config override (skips .forge.json lookup)
   * @param {string} [options.logDir]      - Run log directory for bridge-edit-* event recording
   * @param {string[]} [options.deniedTools] - Tool names denied by plan frontmatter `tools.deny`
   */
  constructor(options = {}) {
    this.cwd = options.cwd ?? process.cwd();
    this.config = options.config ?? loadBridgeConfig(this.cwd);
    this._logDir = options.logDir ?? null;
    /** Phase-WORKER-GUARDRAILS Slice 6 (A8): MCP tool names blocked by plan frontmatter `tools.deny`. */
    this._deniedTools = options.deniedTools ?? null;
    this._ws = null;
    this._rateLimiter = new RateLimiter();
    this._reconnectTimer = null;
    this._stopped = false;
    /** Cached context from the most recent run-started event. */
    this._runContext = null;
    /** Lazily initialised ApprovalGate — created on first requestApproval call. */
    this._approvalGate = null;
  }

  /**
   * Returns true if bridge is enabled and has at least one channel configured.
   * @returns {boolean}
   */
  get isEnabled() {
    return !!(this.config?.enabled !== false && this.config?.channels?.length);
  }

  /**
   * Returns true if any configured channel has `approvalRequired: true`.
   * @returns {boolean}
   */
  get hasApprovalChannels() {
    return (this.config?.channels ?? []).some((c) => c.approvalRequired === true);
  }

  /**
   * Request approval for a run. Dispatches approval notifications to channels
   * with `approvalRequired: true` and awaits human decision or timeout.
   *
   * @param {string} runId
   * @param {object} event - Typically a run-completed event payload
   * @returns {Promise<{ approved: boolean, approver?: string, timedOut?: boolean }>}
   */
  requestApproval(runId, event) {
    if (!this._approvalGate) {
      const channels = ApprovalGate.getApprovalChannels(this.config);
      const serverUrl = this.config?.serverUrl ?? "";
      const timeoutMinutes = this.config?.approvalTimeoutMinutes ?? 30;
      this._approvalGate = new ApprovalGate({ channels, serverUrl, timeoutMinutes, logDir: this._logDir });
    }
    return this._approvalGate.requestApproval(runId, event);
  }

  /**
   * Receive an external approval decision — called by the server's REST endpoint.
   *
   * @param {string} runId
   * @param {boolean} approved
   * @param {string} [approver]
   * @returns {{ ok: boolean, message: string }}
   */
  receiveApproval(runId, approved, approver = "unknown") {
    if (!this._approvalGate) {
      return { ok: false, message: "No approval gate initialised" };
    }
    return this._approvalGate.receiveApproval(runId, approved, approver);
  }

  /**
   * Return pending approvals from the internal gate (for the status endpoint).
   * @returns {Array<{ runId: string, status: string, requestedAt: string }>}
   */
  getPendingApprovals() {
    return this._approvalGate?.getPendingApprovals() ?? [];
  }

  /**
   * Authenticate an incoming approval request against the configured
   * `bridge.approvalSecret`. Returns `{ ok: true }` when no secret is
   * configured (permissive / local mode).
   *
   * Accepts the token via:
   *   - `Authorization: Bearer <secret>` header, OR
   *   - `?token=<secret>` query parameter (browser-friendly Telegram links)
   *
   * @param {Object} req - Incoming request context with `headers` map and
   *   optional `query` object (Express-style).
   * @returns {{ ok: boolean, error?: string }}
   */
  authenticateApproval(req) {
    const secret = this.config?.approvalSecret;
    if (!secret) return { ok: true };

    // Prefer header-based bearer auth via the shared auth module
    const headerResult = authenticate(req, { provider: "bearer", token: secret });
    if (headerResult.ok) return { ok: true };

    // Fallback: query-parameter token for browser-friendly approval links
    const queryToken = req?.query?.token ?? null;
    if (queryToken && queryToken === secret) return { ok: true };

    return { ok: false, error: "Unauthorized — invalid or missing approval secret" };
  }

  /**
   * Connect to the hub WebSocket and start processing events.
   * Auto-reconnects on disconnect unless `stop()` has been called.
   *
   * @param {number} [port] - Hub WS port. Reads .forge/server-ports.json if omitted.
   */
  connect(port) {
    if (!this.isEnabled) return;

    const hubPort = port ?? this._readHubPort();
    if (!hubPort) {
      console.error("[bridge] No hub port found — bridge will not connect");
      return;
    }

    const url = `ws://127.0.0.1:${hubPort}?label=bridge`;
    this._ws = new WebSocket(url);

    this._ws.on("open", () => {
      console.error(`[bridge] Connected to hub at ws://127.0.0.1:${hubPort}`);
    });

    this._ws.on("message", (data) => {
      try {
        const event = JSON.parse(data.toString());
        // Skip the 'connected' ack and replayed history ack
        if (event.type && event.type !== "connected") {
          this._onEvent(event);
        }
      } catch {
        // Ignore malformed messages
      }
    });

    this._ws.on("close", () => {
      if (!this._stopped) {
        console.error(`[bridge] Hub connection closed — reconnecting in ${RECONNECT_DELAY_MS / 1000}s`);
        this._reconnectTimer = setTimeout(() => this.connect(port), RECONNECT_DELAY_MS);
      }
    });

    this._ws.on("error", (err) => {
      // 'close' fires after error, which triggers reconnect — just log here
      console.error(`[bridge] WebSocket error: ${err.message}`);
    });
  }

  /**
   * Disconnect from the hub and stop all reconnect attempts.
   */
  stop() {
    this._stopped = true;
    if (this._reconnectTimer) {
      clearTimeout(this._reconnectTimer);
      this._reconnectTimer = null;
    }
    if (this._ws) {
      this._ws.close();
      this._ws = null;
    }
  }

  /**
   * Handle an incoming hub event — apply level filter and dispatch to each channel.
   * Caches run-started context for use in per-slice message formatting.
   * Drops `tool-call`/`tool-invoked` events whose `toolName` appears in
   * `_deniedTools` (populated from plan frontmatter `tools.deny`).
   * @param {object} event
   */
  _onEvent(event) {
    // Phase-WORKER-GUARDRAILS Slice 6 (A8): drop denied tool-call events before forwarding
    if (
      (event.type === "tool-call" || event.type === "tool-invoked") &&
      isDeniedTool(event.toolName, this._deniedTools)
    ) {
      console.error(`[bridge] Blocked denied tool event: ${event.toolName}`);
      return;
    }

    // Cache run context so slice formatters can show "Slice N/Total"
    if (event.type === "run-started") {
      this._runContext = {
        sliceCount: event.sliceCount ?? null,
        plan: event.plan ?? null,
        model: event.model ?? null,
      };
    } else if (event.type === "run-completed" || event.type === "run-aborted") {
      this._runContext = null;
    }

    const channels = this.config?.channels;
    if (!channels?.length) return;

    for (const channel of channels) {
      if (this._shouldSend(channel, event)) {
        // Fire-and-forget; errors are caught inside dispatchToChannel
        this.dispatchToChannel(channel, event).catch(() => {});
      }
    }
  }

  /**
   * Decide whether a channel should receive the given event.
   * For `critical` level, run-completed is only sent when there are failures.
   *
   * @param {object} channel
   * @param {object} event
   * @returns {boolean}
   */
  _shouldSend(channel, event) {
    const level = channel.level ?? "important";
    const allowed = LEVEL_EVENTS[level] ?? LEVEL_EVENTS.important;

    if (!allowed.has(event.type)) return false;

    // For critical level, run-completed only fires on failure
    if (level === "critical" && event.type === "run-completed") {
      return (event.results?.failed ?? 0) > 0;
    }

    return true;
  }

  /**
   * Format and POST a notification to a single channel with rate limiting.
   * Never throws — logs errors and continues.
   *
   * @param {object} channel - Channel config ({ type, url, chatId?, level? })
   * @param {object} event - Hub event payload
   */
  async dispatchToChannel(channel, event) {
    const key = `${channel.type}:${channel.url}`;

    if (!this._rateLimiter.isAllowed(key)) {
      console.error(`[bridge] Rate limited — skipping ${channel.type} for ${event.type}`);
      return;
    }

    this._rateLimiter.record(key);

    const ctx = this._runContext;
    let payload;
    switch (channel.type) {
      case "telegram": payload = formatTelegram(event, channel, ctx); break;
      case "slack":    payload = formatSlack(event, channel, ctx); break;
      case "discord":  payload = formatDiscord(event, ctx); break;
      default:         payload = formatGeneric(event); break;
    }

    try {
      const response = await fetch(channel.url, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (!response.ok) {
        const body = await response.text().catch(() => "");
        // Mask URL to avoid leaking tokens in logs
        const maskedUrl = channel.url.replace(/\/bot[^/]+\//, "/bot[REDACTED]/");
        console.error(`[bridge] Webhook ${channel.type} HTTP ${response.status} (${maskedUrl}): ${body.slice(0, 200)}`);
      }
    } catch (err) {
      console.error(`[bridge] Webhook error (${channel.type}): ${err.message}`);
    }
  }

  /**
   * Read the active hub port from .forge/server-ports.json.
   * @returns {number | null}
   */
  _readHubPort() {
    const portsPath = resolve(this.cwd, ".forge", "server-ports.json");
    try {
      if (existsSync(portsPath)) {
        const info = JSON.parse(readFileSync(portsPath, "utf-8"));
        return info.ws ?? null;
      }
    } catch {
      // Stale or corrupt
    }
    return null;
  }
}

// ─── Approval Gate ────────────────────────────────────────────────────

const DEFAULT_APPROVAL_TIMEOUT_MINUTES = 30;

/**
 * Build a Telegram sendMessage payload with an inline keyboard for approval.
 * Adds reply_markup with Approve/Reject buttons when serverUrl is configured.
 *
 * @param {string} runId
 * @param {object} event - run-completed event
 * @param {object} channel - Channel config (chatId, serverUrl)
 * @returns {object} Telegram sendMessage payload
 */
function buildTelegramApprovalPayload(runId, event, channel) {
  const serverUrl = (channel.serverUrl ?? "").replace(/\/$/, "");
  const text = buildTelegramText(event) + "\n\n_Waiting for approval\\.\\.\\._";
  const payload = {
    chat_id: channel.chatId ?? "",
    text,
    parse_mode: "MarkdownV2",
  };

  if (serverUrl) {
    payload.reply_markup = {
      inline_keyboard: [[
        { text: "✅ Approve", url: `${serverUrl}/api/bridge/approve/${runId}?action=approve` },
        { text: "❌ Reject",  url: `${serverUrl}/api/bridge/approve/${runId}?action=reject`  },
      ]],
    };
  }

  return payload;
}

/**
 * Approval Gate — pause-on-completion state machine.
 *
 * Tracks pending approvals for runs that require external sign-off before the
 * orchestrator writes the final summary and manifest.
 *
 * Usage:
 * ```js
 * const gate = new ApprovalGate({ channels: approvalChannels, serverUrl });
 * const result = await gate.requestApproval(runId, runCompletedEvent);
 * if (!result.approved) { ... }
 * ```
 */
export class ApprovalGate {
  /**
   * @param {object} [options]
   * @param {Array}  [options.channels]                - Channels with approvalRequired: true
   * @param {string} [options.serverUrl]               - Base URL for callback links (e.g. "http://localhost:3100")
   * @param {number} [options.timeoutMinutes=30]       - Auto-reject after N minutes
   * @param {string} [options.logDir]                  - Run log directory for bridge-edit-* event recording
   */
  constructor(options = {}) {
    /** @type {Map<string, { status: string, requestedAt: string, event: object, timer: any, _resolve: Function }>} */
    this._pending = new Map();
    this._timeoutMs = (options.timeoutMinutes ?? DEFAULT_APPROVAL_TIMEOUT_MINUTES) * 60_000;
    this._channels = options.channels ?? [];
    this._serverUrl = options.serverUrl ?? "";
    this._logDir = options.logDir ?? null;
  }

  /**
   * Filter an array of bridge channels to only those with approvalRequired: true.
   * @param {object} bridgeConfig - Bridge config from .forge.json
   * @returns {Array}
   */
  static getApprovalChannels(bridgeConfig) {
    return (bridgeConfig?.channels ?? []).filter((c) => c.approvalRequired === true);
  }

  /**
   * Send an approval request to all configured approval channels and return a
   * Promise that resolves when `receiveApproval` is called or the timeout elapses.
   *
   * @param {string} runId
   * @param {object} event - Hub event triggering the approval (typically run-completed)
   * @returns {Promise<{ approved: boolean, approver?: string, timedOut?: boolean }>}
   */
  requestApproval(runId, event) {
    if (this._pending.has(runId)) {
      const entry = this._pending.get(runId);
      return new Promise((resolve) => {
        const origResolve = entry._resolve;
        entry._resolve = (result) => { origResolve(result); resolve(result); };
      });
    }

    let resolveApproval;
    const promise = new Promise((resolve) => { resolveApproval = resolve; });

    const timer = setTimeout(() => {
      if (this._pending.has(runId)) {
        this._pending.delete(runId);
        resolveApproval({ approved: false, timedOut: true });
        // Call site 1: bridge-edit-blocked — approval timed out
        appendEvent("bridge-edit-blocked", {
          runId,
          reason: "timeout",
          source: "bridge",
          security_risk: SECURITY_RISK.HIGH,
        }, this._logDir);
      }
    }, this._timeoutMs);

    this._pending.set(runId, {
      status: "pending",
      requestedAt: new Date().toISOString(),
      event,
      timer,
      _resolve: resolveApproval,
    });

    // Dispatch approval notifications fire-and-forget
    this._dispatchApprovalRequests(runId, event).catch((err) => {
      console.error(`[bridge] ApprovalGate dispatch error: ${err.message}`);
    });

    return promise;
  }

  /**
   * Receive an approval decision and resolve the pending gate.
   *
   * @param {string} runId
   * @param {boolean} approved
   * @param {string} [approver]
   * @returns {{ ok: boolean, message: string }}
   */
  receiveApproval(runId, approved, approver = "unknown") {
    const entry = this._pending.get(runId);
    if (!entry) {
      return { ok: false, message: `No pending approval for runId: ${runId}` };
    }

    clearTimeout(entry.timer);
    this._pending.delete(runId);
    entry._resolve({ approved, approver, timedOut: false });

    // Call site 2: bridge-edit-approved or bridge-edit-blocked — explicit decision
    const eventType = approved ? "bridge-edit-approved" : "bridge-edit-blocked";
    appendEvent(eventType, {
      runId,
      approver,
      source: "bridge",
      security_risk: approved
        ? (entry.event?.security_risk ?? SECURITY_RISK.NONE)
        : SECURITY_RISK.HIGH,
    }, this._logDir);

    return { ok: true, message: approved ? "Approved" : "Rejected" };
  }

  /**
   * Check if a runId has a pending approval.
   * @param {string} runId
   * @returns {boolean}
   */
  hasPending(runId) {
    return this._pending.has(runId);
  }

  /**
   * Return all pending approvals (for status endpoint).
   * @returns {Array<{ runId: string, status: string, requestedAt: string }>}
   */
  getPendingApprovals() {
    return Array.from(this._pending.entries()).map(([runId, entry]) => ({
      runId,
      status: entry.status,
      requestedAt: entry.requestedAt,
    }));
  }

  /**
   * Dispatch approval-request notifications to all approval channels.
   * Telegram gets an inline keyboard; Slack gets action buttons (already
   * handled by buildSlackBlocks when approvalRequired + runId are present);
   * Discord and generic get standard event formatting.
   *
   * @param {string} runId
   * @param {object} event
   */
  async _dispatchApprovalRequests(runId, event) {
    const eventWithRunId = { ...event, runId };

    for (const channel of this._channels) {
      const channelWithServer = {
        ...channel,
        serverUrl: channel.serverUrl ?? this._serverUrl,
      };

      let payload;
      switch (channel.type) {
        case "telegram":
          payload = buildTelegramApprovalPayload(runId, eventWithRunId, channelWithServer);
          break;
        case "slack":
          payload = formatSlack(eventWithRunId, channelWithServer);
          break;
        case "discord":
          payload = formatDiscord(eventWithRunId);
          break;
        default:
          payload = formatGeneric(eventWithRunId);
          break;
      }

      try {
        const response = await fetch(channel.url, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(payload),
        });
        if (!response.ok) {
          const body = await response.text().catch(() => "");
          const maskedUrl = channel.url.replace(/\/bot[^/]+\//, "/bot[REDACTED]/");
          console.error(`[bridge] ApprovalGate ${channel.type} HTTP ${response.status} (${maskedUrl}): ${body.slice(0, 200)}`);
        }
      } catch (err) {
        console.error(`[bridge] ApprovalGate dispatch error (${channel.type}): ${err.message}`);
      }
    }
  }
}

