    cache_read_multiplier: 0.25,
    _source: "https://docs.x.ai/developers/models (2026-05-06)" },
  "grok-4-0709":                       { input: 1.25 / 1_000_000, output: 2.50 / 1_000_000,
    cache_read_multiplier: 0.25, _retiredAfter: "2026-05-15",
    _source: "https://docs.x.ai/developers/migration/may-15-retirement (2026-05-06)" },
  "grok-3":                            { input: 3 / 1_000_000,    output: 15 / 1_000_000,
    cache_read_multiplier: 0.25, _retiredAfter: "2026-05-15",
    _source: "https://docs.x.ai/developers/migration/may-15-retirement (2026-05-06)" },
  "grok-3-mini":                       { input: 0.30 / 1_000_000, output: 0.50 / 1_000_000,
    cache_read_multiplier: 0.25,
    _source: "https://docs.x.ai/developers/advanced-api-usage/prompt-caching (2026-05-06)" },

  // ─── Fallback ─────────────────────────────────────────────────────
  // Conservative default: kept at $3/$15 (Sonnet-class) so unknown models
  // don't dramatically under-estimate cost. No cache multipliers applied
  // (defaults to 1.0 — no benefit assumed for unrecognised models).
  default:                  { input: 3 / 1_000_000,    output: 15 / 1_000_000,
    _source: "https://www.anthropic.com/pricing (2026-05-06)" },
};

/**
 * Default multiplier values applied to every pricing entry that doesn't override them.
 * Phase-COST-TOKEN-COVERAGE Slice 1: enables additive vendor-aware math in priceSlice()
 * without breaking entries that only carry { input, output }. Anthropic-only fields
 * (cache_write_5m_multiplier, cache_write_1h_multiplier) and OpenAI-only fields
 * (flex_*, priority_*) all default to 1.0 so unknown/legacy entries cost as before.
 */
const PRICING_MULTIPLIER_DEFAULTS = Object.freeze({
  cache_read_multiplier: 1.0,
  cache_write_5m_multiplier: 1.0,
  cache_write_1h_multiplier: 1.0,
  flex_input_multiplier: 1.0,
  flex_output_multiplier: 1.0,
  priority_input_multiplier: 1.0,
  priority_output_multiplier: 1.0,
});

/**
 * Look up per-token pricing for a model. Unknown models fall through to the
 * default rate so callers never hit an undefined.
 *
 * Returns the full pricing object with all multiplier defaults applied (1.0 for any
 * cache_read / cache_write / flex / priority multiplier the entry doesn't override).
 * Callers can rely on every multiplier field being a number — no need to handle
 * missing keys downstream.
 *
 * @param {string} model
 * @returns {{
 *   input: number, output: number,
 *   cache_read_multiplier: number,
 *   cache_write_5m_multiplier: number, cache_write_1h_multiplier: number,
 *   flex_input_multiplier: number, flex_output_multiplier: number,
 *   priority_input_multiplier: number, priority_output_multiplier: number,
 *   _retiredAfter?: string, _source?: string,
 * }}
 */
export function getPricing(model) {
  const entry = MODEL_PRICING[model] || MODEL_PRICING.default;
  return { ...PRICING_MULTIPLIER_DEFAULTS, ...entry };
}

// ─── Provider Awareness ───────────────────────────────────────────────
// Subscription CLI providers bill by premium-request count, not per-token.
export const SUBSCRIPTION_PROVIDERS = new Set(["gh-copilot", "claude-cli", "codex-cli"]);

// ─── Microsoft Foundry: deployment-name → model-key resolution ────────
// Reads `.forge/foundry-deployments.json` (operator-editable) once per cwd;
// falls back to the raw deployment name when the map is absent or the
// deployment is not listed.  Shape: `{ "my-deployment": "gpt-5.4-mini" }`.
let _foundryDeploymentMap = null;
let _foundryMapCwd = null;

function loadFoundryDeployments() {
  const cwd = process.cwd();
  if (_foundryDeploymentMap !== null && _foundryMapCwd === cwd) {
    return _foundryDeploymentMap;
  }
  const mapPath = resolve(cwd, ".forge", "foundry-deployments.json");
  try {
    _foundryDeploymentMap = existsSync(mapPath)
      ? JSON.parse(readFileSync(mapPath, "utf-8"))
      : {};
  } catch {
    _foundryDeploymentMap = {};
  }
  _foundryMapCwd = cwd;
  return _foundryDeploymentMap;
}

/**
 * Resolve a Microsoft Foundry deployment name to a canonical MODEL_PRICING key.
 * Reads `.forge/foundry-deployments.json`; falls back to the deployment name itself.
 * @param {string} deployment
 * @returns {string}
 */
function resolveFoundryModel(deployment) {
  const map = loadFoundryDeployments();
  return (deployment && map[deployment]) || deployment || "unknown";
}

const CLI_PER_REQUEST_USD = 0.01;

/**
 * Expected wall-clock minutes for one Copilot Coding Agent slice.
 * Based on DEFAULT_TIMEOUT_MS (30 min) in copilot-coding-agent.mjs.
 * Used by estimatePlan to project elapsed time for --estimate output.
 */
export const COPILOT_AGENT_MINUTES_PER_SLICE = 30;

/**
 * Determine cost model for the active execution environment.
 *
 * Precedence (highest to lowest):
 *   1. env.PFORGE_COST_MODEL — explicit override
 *   2. forgeConfig.cost?.model — project-level config in .forge.json
 *   3. Model-name heuristic:
 *      - gpt-*       → openai-api
 *      - grok-*      → xai-api
 *      - claude-* + ANTHROPIC_API_KEY → anthropic-api
 *      - claude-* (no key)            → claude-cli
 *      - "gh-copilot" / *copilot*     → gh-copilot
 *      - else                         → unknown
 *   4. default → unknown
 *
 * @param {{ env?: Record<string,string>, forgeConfig?: object, model?: string }} opts
 * @returns {{ provider: string, perRequestUsd: number|null, source: string }}
 */
function _detectProviderFromModelPrefix(m, env) {
  if (m.startsWith("gpt-") || m.startsWith("chatgpt-")) {
    return {
      provider: Boolean(env.OPENAI_API_KEY) ? "openai-api" : "gh-copilot",
      source: "model-prefix",
    };
  }
  if (m.startsWith("grok-")) {
    return { provider: "xai-api", source: "model-prefix" };
  }
  if (m.startsWith("claude-")) {
    return {
      provider: Boolean(env.ANTHROPIC_API_KEY) ? "anthropic-api" : "claude-cli",
      source: "model-prefix",
    };
  }
  if (m === "gh-copilot" || m.includes("copilot")) {
    return { provider: "gh-copilot", source: "model-prefix" };
  }
  if (m === "codex-cli" || m.startsWith("codex-")) {
    return { provider: "codex-cli", source: "model-prefix" };
  }
  return null;
}

export function detectCostModel({ env = {}, forgeConfig = {}, model = "" } = {}) {
  const knownProviders = new Set([
    "gh-copilot", "claude-cli", "codex-cli",
    "anthropic-api", "openai-api", "xai-api", "unknown",
  ]);

  function toResult(provider, source) {
    let perRequestUsd;
    if (SUBSCRIPTION_PROVIDERS.has(provider)) {
      perRequestUsd = CLI_PER_REQUEST_USD;
    } else if (provider === "unknown") {
      perRequestUsd = 0;
    } else {
      perRequestUsd = null; // API provider — use token-based pricing
    }
    return { provider, perRequestUsd, source };
  }

  // 1. Explicit env override
  const envOverride = env.PFORGE_COST_MODEL;
  if (envOverride && knownProviders.has(envOverride)) {
    return toResult(envOverride, "env:PFORGE_COST_MODEL");
  }

  // 2. forge.json cost.model
  const cfgModel = forgeConfig?.cost?.model;
  if (cfgModel && knownProviders.has(cfgModel)) {
    return toResult(cfgModel, "forge.json:cost.model");
  }

  // 3. Model-name heuristic
  // Issue #120: previously gpt-* always routed to openai-api (token pricing),
  // which produced ~250x overestimates for users running gh-copilot. Align
  // with probeQuorumModelAvailability's host detection: when no API key is
  // present, prefer the local CLI (gh-copilot for gpt-*, claude-cli for
  // claude-*) which is subscription-priced.
  const m = typeof model === "string" ? model : "";
  const prefixResult = _detectProviderFromModelPrefix(m, env);
  if (prefixResult) {
    return toResult(prefixResult.provider, prefixResult.source);
  }

  // 4. Default
  return toResult("unknown", "default");
}

/**
 * Round a USD cost to 6 decimal places (matches existing convention; ~$0.000001 precision).
 */
function roundUsd(n) {
  return Math.round(n * 1_000_000) / 1_000_000;
}

/**
 * Build a zero-filled `cost_breakdown` object. Every priceSlice() return populates
 * the same shape so downstream consumers can rely on the keys existing.
 */
function emptyBreakdown() {
  return {
    input_uncached: 0,
    input_cache_read: 0,
    input_cache_write_5m: 0,
    input_cache_write_1h: 0,
    output_total: 0,
    reasoning_tokens: 0,
    tier_adjustment: 0,
    subscription_cost: 0,
  };
}

/**
 * Resolve OpenAI / xAI service-tier multipliers from a pricing entry.
 * Returns `{ input: 1.0, output: 1.0 }` for unknown/missing tiers (no adjustment).
 */
function resolveTierMultipliers(pricing, serviceTier) {
  switch (serviceTier) {
    case "flex":
      return { input: pricing.flex_input_multiplier, output: pricing.flex_output_multiplier };
    case "priority":
      return { input: pricing.priority_input_multiplier, output: pricing.priority_output_multiplier };
    case "standard":
    case "default":
    case null:
    case undefined:
    default:
      return { input: 1.0, output: 1.0 };
  }
}

function debugCostLog(message) {
  if (process.env.PFORGE_LOG_LEVEL === "debug") {
    console.error(`[cost-service] ${message}`);
  }
}

/**
 * Calculate cost for a single slice from its token data.
 *
 * Phase-COST-TOKEN-COVERAGE Slice 3: vendor-aware billing math with per-class
 * `cost_breakdown`. Five execution paths, picked from `tokens.vendor`:
 *
 *  - **Subscription CLI** (`worker` is set and not `api-*`): unchanged path —
 *    `premiumRequests × $0.01`. v2.83.0 Forbidden Action #1 protected.
 *  - **Anthropic** (`vendor === 'anthropic'`): `tokens_in` is uncached input
 *    (after last cache breakpoint). Bill `tokens_in`, cache_read, 5m write,
 *    1h write each independently with their multipliers.
 *  - **OpenAI** (`vendor === 'openai'`): `tokens_in` INCLUDES `cache_read_tokens`.
 *    Subtract cached from input before billing uncached portion. Apply tier
 *    multipliers (flex/priority).
 *  - **xAI** (`vendor === 'xai'`): if `cost_in_usd_ticks` present, use it directly
 *    (1 tick = 1e-10 USD); skip computed math. Otherwise mirror OpenAI math.
 *  - **Unknown / legacy** (`vendor` absent or unrecognized): backward-compatible
 *    math. `tokens_in × input + tokens_out × output`. Existing callers that
 *    construct `{ tokens_in, tokens_out, model }` see identical cost as before.
 *
 * @param {{
 *   tokens_in?: number|null, tokens_out?: number|null, model?: string,
 *   premiumRequests?: number,
 *   cache_read_tokens?: number,
 *   cache_creation_5m_tokens?: number, cache_creation_1h_tokens?: number,
 *   cache_creation_input_tokens?: number,
 *   reasoning_tokens?: number,
 *   service_tier?: 'standard'|'flex'|'priority'|'default'|null,
 *   cost_in_usd_ticks?: number,
 *   vendor?: 'anthropic'|'openai'|'xai'|'azure-openai'|'microsoft-foundry'|'unknown',
 *   provider?: string,
 *   deployment?: string,
 * }} tokens
 * @param {string} [worker] - Worker type: "gh-copilot", "claude", "codex", "api-xai", etc.
 * @returns {{
 *   cost_usd: number, model: string, tokens_in: number, tokens_out: number,
 *   cost_breakdown: object,
 * }}
 */
function _priceSliceSubscription({ tokens, model, tokensIn, tokensOut, breakdown }) {
  const premiumRequests = tokens?.premiumRequests || 0;
  const cost = premiumRequests * CLI_PER_REQUEST_USD;
  breakdown.subscription_cost = roundUsd(cost);
  return {
    cost_usd: roundUsd(cost),
    model,
    tokens_in: tokensIn,
    tokens_out: tokensOut,
    cost_breakdown: breakdown,
  };
}

function _priceSliceXaiTicks({ tokens, model, tokensIn, tokensOut, breakdown }) {
  const costFromTicks = tokens.cost_in_usd_ticks * 1e-10;
  const reasoning = tokens?.reasoning_tokens || 0;
  breakdown.input_uncached = roundUsd(costFromTicks);
  breakdown.reasoning_tokens = reasoning;
  breakdown.authoritative_source = "cost_in_usd_ticks";
  return {
    cost_usd: roundUsd(costFromTicks),
    model,
    tokens_in: tokensIn,
    tokens_out: tokensOut,
    cost_breakdown: breakdown,
  };
}

function _priceSliceAnthropic({ tokens, model, tokensIn, tokensOut, pricing, breakdown }) {
  const cacheRead = tokens?.cache_read_tokens || 0;
  let cache5m = tokens?.cache_creation_5m_tokens || 0;
  let cache1h = tokens?.cache_creation_1h_tokens || 0;
  const cacheCombined = tokens?.cache_creation_input_tokens || 0;

  if (cacheCombined > 0 && cache5m === 0 && cache1h === 0) {
    cache5m = cacheCombined;
    debugCostLog(`Anthropic cache_creation_input_tokens lacked 5m/1h split for ${model}; defaulted ${cacheCombined} tokens to 5m pricing.`);
  }

  breakdown.input_uncached = roundUsd(tokensIn * pricing.input);
  breakdown.input_cache_read = roundUsd(cacheRead * pricing.input * pricing.cache_read_multiplier);
  breakdown.input_cache_write_5m = roundUsd(cache5m * pricing.input * pricing.cache_write_5m_multiplier);
  breakdown.input_cache_write_1h = roundUsd(cache1h * pricing.input * pricing.cache_write_1h_multiplier);
  breakdown.output_total = roundUsd(tokensOut * pricing.output);
  breakdown.tier_adjustment = 0;

  const cost = breakdown.input_uncached + breakdown.input_cache_read +
               breakdown.input_cache_write_5m + breakdown.input_cache_write_1h +
               breakdown.output_total;
  return {
    cost_usd: roundUsd(cost),
    model,
    tokens_in: tokensIn,
    tokens_out: tokensOut,
    cost_breakdown: breakdown,
  };
}

function _priceSliceOpenAiXai({ tokens, model, tokensIn, tokensOut, pricing, breakdown }) {
  const cacheRead = tokens?.cache_read_tokens || 0;
  const uncachedIn = Math.max(0, tokensIn - cacheRead);
  const tier = resolveTierMultipliers(pricing, tokens?.service_tier);
  const inputUncachedCost = uncachedIn * pricing.input * tier.input;
  const inputCacheReadCost = cacheRead * pricing.input * pricing.cache_read_multiplier * tier.input;
  const outputCost = tokensOut * pricing.output * tier.output;
  const standardCost = (uncachedIn * pricing.input) +
                       (cacheRead * pricing.input * pricing.cache_read_multiplier) +
                       (tokensOut * pricing.output);
  const activeCost = inputUncachedCost + inputCacheReadCost + outputCost;
  breakdown.input_uncached = roundUsd(inputUncachedCost);
  breakdown.input_cache_read = roundUsd(inputCacheReadCost);
  breakdown.output_total = roundUsd(outputCost);
  breakdown.tier_adjustment = roundUsd(activeCost - standardCost);
  return {
    cost_usd: roundUsd(activeCost),
    model,
    tokens_in: tokensIn,
    tokens_out: tokensOut,
    cost_breakdown: breakdown,
  };
}

function _priceSliceDefault({ tokensIn, tokensOut, model, pricing, breakdown, isFoundry }) {
  const baseCost = (tokensIn * pricing.input) + (tokensOut * pricing.output);
  let foundryMultiplier = 1.0;
  if (isFoundry && pricing.aoai_deployment_type_multiplier) {
    const deploymentType = process.env.AZURE_OPENAI_DEPLOYMENT_TYPE || "global";
    foundryMultiplier = pricing.aoai_deployment_type_multiplier[deploymentType] ?? 1.0;
  }
  const cost = baseCost * foundryMultiplier;
  breakdown.input_uncached = roundUsd(tokensIn * pricing.input * foundryMultiplier);
  breakdown.output_total = roundUsd(tokensOut * pricing.output * foundryMultiplier);
  if (isFoundry && foundryMultiplier !== 1.0) {
    breakdown.tier_adjustment = roundUsd(cost - baseCost);
  }
  return {
    cost_usd: roundUsd(cost),
    model,
    tokens_in: tokensIn,
    tokens_out: tokensOut,
    cost_breakdown: breakdown,
  };
}

function _priceSliceIsFoundry(tokens, worker) {
  return tokens?.provider === "microsoft-foundry" || worker === "api-microsoft-foundry";
}

function _priceSliceNumber(value) {
  return typeof value === "number" ? value : 0;
}

function _priceSliceContext(tokens, worker) {
  const rawModel = tokens?.model || "unknown";
  const isFoundry = _priceSliceIsFoundry(tokens, worker);
  return {
    model: isFoundry ? resolveFoundryModel(tokens?.deployment || rawModel) : rawModel,
    tokensIn: _priceSliceNumber(tokens?.tokens_in),
    tokensOut: _priceSliceNumber(tokens?.tokens_out),
    breakdown: emptyBreakdown(),
    isFoundry,
  };
}

function _priceSliceUsesSubscriptionPricing(worker) {
  return Boolean(worker) && !worker.startsWith("api-");
}

function _priceSliceUsesXaiTicks(tokens) {
  return tokens?.vendor === "xai" && typeof tokens?.cost_in_usd_ticks === "number";
}

function _priceSliceUsesComputedVendorPricing(tokens) {
  return tokens?.vendor === "openai" || tokens?.vendor === "xai";
}

export function priceSlice(tokens, worker) {
  const { model, tokensIn, tokensOut, breakdown, isFoundry } = _priceSliceContext(tokens, worker);

  if (_priceSliceUsesSubscriptionPricing(worker)) {
    return _priceSliceSubscription({ tokens: tokens, model: model, tokensIn: tokensIn, tokensOut: tokensOut, breakdown: breakdown });
  }
  if (_priceSliceUsesXaiTicks(tokens)) {
    return _priceSliceXaiTicks({ tokens: tokens, model: model, tokensIn: tokensIn, tokensOut: tokensOut, breakdown: breakdown });
  }

  const pricing = getPricing(model);
  breakdown.reasoning_tokens = tokens?.reasoning_tokens || 0;

  if (tokens?.vendor === "anthropic") {
    return _priceSliceAnthropic({ tokens: tokens, model: model, tokensIn: tokensIn, tokensOut: tokensOut, pricing: pricing, breakdown: breakdown });
  }
  if (_priceSliceUsesComputedVendorPricing(tokens)) {
    return _priceSliceOpenAiXai({ tokens: tokens, model: model, tokensIn: tokensIn, tokensOut: tokensOut, pricing: pricing, breakdown: breakdown });
  }

  return _priceSliceDefault({ tokensIn: tokensIn, tokensOut: tokensOut, model: model, pricing: pricing, breakdown: breakdown, isFoundry: isFoundry });
}

/**
 * Build cost breakdown from all slice results.
 * Drop-in replacement for orchestrator.buildCostBreakdown.
 * @param {Array} sliceResults
 * @returns {{ total_cost_usd, by_model, by_slice }}
 */
function _apportionReviewerCostToModels({ byModel, reviewerModels, reviewerCost, reviewerTokensIn, reviewerTokensOut }) {
  if (reviewerModels.length === 0) return;
  if (reviewerCost <= 0 && reviewerTokensIn <= 0 && reviewerTokensOut <= 0) return;

  const share = 1 / reviewerModels.length;
  for (const rm of reviewerModels) {
    if (!byModel[rm]) {
      byModel[rm] = { tokens_in: 0, tokens_out: 0, cost_usd: 0, slices: 0, role: "reviewer" };
    } else if (!byModel[rm].role) {
      byModel[rm].role = byModel[rm].cost_usd > 0 ? "mixed" : "reviewer";
    }
    byModel[rm].tokens_in += reviewerTokensIn * share;
    byModel[rm].tokens_out += reviewerTokensOut * share;
    byModel[rm].cost_usd += reviewerCost * share;
    byModel[rm].slices += 1;
  }
}

function _priceRunContextLabel(sliceResult) {
  return `slice ${sliceResult?.number || sliceResult?.sliceId || "?"}`;
}

function _priceRunReviewerTelemetry(sliceResult) {
  return {
    reviewerCost: Number(sliceResult.quorum?.reviewerCost) || 0,
    reviewerModels: Array.isArray(sliceResult.quorum?.models) ? sliceResult.quorum.models : [],
    reviewerTokensIn: Number(sliceResult.quorum?.dryRunTokens?.tokens_in) || 0,
    reviewerTokensOut: Number(sliceResult.quorum?.dryRunTokens?.tokens_out) || 0,
  };
}

function _priceRunAccumulateModel(byModel, cost) {
  if (!byModel[cost.model]) {
    byModel[cost.model] = { tokens_in: 0, tokens_out: 0, cost_usd: 0, slices: 0 };
  }
  byModel[cost.model].tokens_in += cost.tokens_in;
  byModel[cost.model].tokens_out += cost.tokens_out;
  byModel[cost.model].cost_usd += cost.cost_usd;
  byModel[cost.model].slices += 1;
}

export function priceRun(sliceResults) {
  const byModel = {};
  const bySlice = [];
  let totalCost = 0;
  let totalReviewerCost = 0;
  let totalIn = 0;
  let totalOut = 0;

  for (const sr of sliceResults) {
    warnOnUnknownCostSourceLabel(sr?.source ?? null, _priceRunContextLabel(sr));
    if (!sr.tokens || sr.status === "skipped") continue;

    const cost = priceSlice(sr.tokens, sr.worker);
    const { reviewerCost, reviewerModels, reviewerTokensIn, reviewerTokensOut } = _priceRunReviewerTelemetry(sr);
    totalCost += cost.cost_usd;
    totalReviewerCost += reviewerCost;
    totalIn += cost.tokens_in + reviewerTokensIn;
    totalOut += cost.tokens_out + reviewerTokensOut;

    bySlice.push({
      slice: sr.number || sr.sliceId,
      ...cost,
      reviewer_cost_usd: Math.round(reviewerCost * 1_000_000) / 1_000_000,
      reviewer_models: reviewerModels,
    });

    _priceRunAccumulateModel(byModel, cost);
    _apportionReviewerCostToModels({ byModel: byModel, reviewerModels: reviewerModels, reviewerCost: reviewerCost, reviewerTokensIn: reviewerTokensIn, reviewerTokensOut: reviewerTokensOut });
  }

  for (const m of Object.values(byModel)) {
    m.cost_usd = Math.round(m.cost_usd * 1_000_000) / 1_000_000;
    m.tokens_in = Math.round(m.tokens_in);
    m.tokens_out = Math.round(m.tokens_out);
  }

  return {
    total_cost_usd: Math.round((totalCost + totalReviewerCost) * 100) / 100,
    total_executor_cost_usd: Math.round(totalCost * 100) / 100,
    total_reviewer_cost_usd: Math.round(totalReviewerCost * 100) / 100,
    total_tokens_in: totalIn,
    total_tokens_out: totalOut,
    by_model: byModel,
    by_slice: bySlice,
  };
}

/**
 * Build a cost estimate for an entire plan.
 * Drop-in replacement for orchestrator.buildEstimate — same signature, same output shape.
 *
 * Historical calibration: reads .forge/cost-history.json when available; clamps
 * correction factor to [0.5, 3.0]. Quorum overhead computed when quorumConfig.enabled.
 * Per-plan model recommendation from .forge/model-performance.json.
 */
function _readJsonIfExists(path, fallback = null) {
  try {
    if (path && existsSync(path)) {
      return JSON.parse(readFileSync(path, "utf-8"));
    }
  } catch {
    return fallback;
  }
  return fallback;
}

function _loadForgeConfig(cwd) {
  const forgeConfig = _readJsonIfExists(cwd ? resolve(cwd, ".forge.json") : null, {});
  return forgeConfig && typeof forgeConfig === "object" ? forgeConfig : {};
}

function _loadCostHistory(cwd) {
  const history = _readJsonIfExists(cwd ? resolve(cwd, ".forge", "cost-history.json") : null, []);
  return Array.isArray(history) ? history : [];
}

function _computeAverageTokensPerSlice(history, source = null) {
  if (!Array.isArray(history) || history.length === 0) return null;

  const totalIn = history.reduce((sum, entry) => sum + (entry.total_tokens_in || 0), 0);
  const totalOut = history.reduce((sum, entry) => sum + (entry.total_tokens_out || 0), 0);
  const totalSlices = history.reduce((sum, entry) => sum + (entry.sliceCount || 1), 0);
  if (totalSlices <= 0) return null;

  return {
    input: Math.round(totalIn / totalSlices),
    output: Math.round(totalOut / totalSlices),
    ...(source && { source }),
  };
}

function _computeAveragePremiumPerSlice(history) {
  if (!Array.isArray(history) || history.length === 0) return null;

  const valid = history.filter(
    (entry) => typeof entry.total_premium_requests === "number" && (entry.sliceCount || 1) > 0
  );
  if (valid.length === 0) return null;

  const sum = valid.reduce(
    (total, entry) => total + entry.total_premium_requests / (entry.sliceCount || 1),
    0
  );
  return Math.max(0.5, Math.min(5.0, sum / valid.length));
}

function _resolveEffectiveSlices(plan, resumeFrom) {
  let effectiveSlices = plan.slices;
  let effectiveOrder = plan.dag.order;
  if (resumeFrom !== null && resumeFrom !== undefined) {
    const target = String(resumeFrom);
    const startIdx = plan.dag.order.findIndex((id) => id === target);
    if (startIdx >= 0) {
      effectiveOrder = plan.dag.order.slice(startIdx);
      const includeIds = new Set(effectiveOrder);
      effectiveSlices = plan.slices.filter((slice) => includeIds.has(String(slice.number)));
    }
  }
  return { effectiveSlices, effectiveOrder };
}

function _calibrateCorrectionFactor(modelKey, cwd) {
  const history = _loadCostHistory(cwd);
  const withEstimates = history.filter((entry) => entry.estimated_cost_usd > 0 && entry.total_cost_usd > 0);
  if (withEstimates.length < 3) return null;

  const ratios = withEstimates.slice(-10).map((entry) => entry.total_cost_usd / entry.estimated_cost_usd);
  const avgRatio = ratios.reduce((sum, ratio) => sum + ratio, 0) / ratios.length;
  const correctionFactor = Math.max(0.5, Math.min(3.0, avgRatio));
  return {
    correctionFactor,
    samplesUsed: withEstimates.length,
    source: "historical",
    model: modelKey,
  };
}

function _computeQuorumOverhead(quorumConfig, _modelKey, sliceEstimates) {
  if (!(quorumConfig && quorumConfig.enabled)) return null;

  const { effectiveSlices, sliceCount, tokensPerSlice, cwd, costForLeg } = sliceEstimates;
  const quorumSlices = quorumConfig.auto
    ? effectiveSlices.filter((slice) => scoreSliceComplexity(slice, cwd).score >= quorumConfig.threshold)
    : effectiveSlices;
  const modelCount = quorumConfig.models.length;
  const dryRunInputPerLeg = tokensPerSlice.input * 1.5;
  const dryRunOutputPerLeg = tokensPerSlice.output * 0.8;
  const reviewerInput = dryRunOutputPerLeg * modelCount + tokensPerSlice.input;
  const reviewerOutput = tokensPerSlice.output * 0.6;
  const dryRunCostPerSlice = quorumConfig.models.reduce(
    (sum, legModel) => sum + costForLeg(legModel, dryRunInputPerLeg, dryRunOutputPerLeg),
    0
  );
  const reviewerCostPerSlice = costForLeg(quorumConfig.reviewerModel, reviewerInput, reviewerOutput);

  return {
    quorumSliceCount: quorumSlices.length,
    totalSliceCount: sliceCount,
    dryRunCostPerSlice: Math.round(dryRunCostPerSlice * 100) / 100,
    reviewerCostPerSlice: Math.round(reviewerCostPerSlice * 100) / 100,
    totalOverheadUSD: Math.round((dryRunCostPerSlice + reviewerCostPerSlice) * quorumSlices.length * 100) / 100,
    models: quorumConfig.models,
    reviewerModel: quorumConfig.reviewerModel,
    slices: quorumSlices.map((slice) => ({
      number: slice.number,
      title: slice.title,
      complexityScore: scoreSliceComplexity(slice, cwd).score,
    })),
  };
}

function _loadModelRecommendation(modelKey, cwd) {
  if (!cwd) return null;

  try {
    const perfRecords = loadModelPerformance(cwd);
    if (perfRecords.length === 0) return null;

    const stats = aggregateModelStats(perfRecords);
    const MIN_SAMPLE = 3;
    const qualified = Object.entries(stats)
      .filter(([candidate, stat]) => !isApiOnlyModel(candidate) && stat.total_slices >= MIN_SAMPLE && stat.success_rate > 0.8)
      .map(([candidate, stat]) => ({
        model: candidate,
        success_rate: stat.success_rate,
        total_slices: stat.total_slices,
        avg_cost_usd: stat.avg_cost_usd,
      }))
      .sort((a, b) => a.avg_cost_usd - b.avg_cost_usd);
    if (qualified.length === 0) return null;

    const best = qualified[0];
    return {
      model: best.model,
      reason: `Cheapest model with >${(0.8 * 100).toFixed(0)}% success rate`,
      success_rate: best.success_rate,
      avg_cost_usd_per_slice: best.avg_cost_usd,
      based_on_slices: best.total_slices,
      all_qualified: qualified,
    };
  } catch {
    return null;
  }
}

function _loadSplitAdvisories(effectiveSlices, cwd) {
  try {
    const perfRecords = loadModelPerformance(cwd);
    return effectiveSlices.reduce((items, slice) => {
      const priorFailures = perfRecords.filter((record) =>
        record.sliceTitle && slice.title && record.sliceTitle.toLowerCase() === slice.title.toLowerCase() && record.status !== "passed"
      );
      const taskCount = slice.tasks?.length || 0;
      const scopeCount = slice.scope?.length || 0;
      if (priorFailures.length >= 2 || (taskCount > 6 && scopeCount > 4)) {
        items.push({
          sliceNumber: slice.number,
          sliceTitle: slice.title,
          reason: priorFailures.length >= 2
            ? `Failed ${priorFailures.length} time(s) historically — consider splitting`
            : `${taskCount} tasks + ${scopeCount} scope files — may be too large`,
          tasks: taskCount,
          scope: scopeCount,
          priorFailures: priorFailures.length,
        });
      }
      return items;
    }, []);
  } catch {
    return [];
  }
}

function _estimatePlanResumeFields(plan, resumeFrom) {
  return resumeFrom !== null && resumeFrom !== undefined
    ? { resumeFrom: String(resumeFrom), fullSliceCount: plan.slices.length }
    : {};
}

function _buildCopilotCodingAgentEstimate({ plan, effectiveSlices, effectiveOrder, resumeFrom, model, tokensPerSlice }) {
  const sliceCount = effectiveSlices.length;
  const totalInputTokens = sliceCount * tokensPerSlice.input;
  const totalOutputTokens = sliceCount * tokensPerSlice.output;
  return {
    status: "estimate",
    sliceCount,
    executionOrder: effectiveOrder,
    ..._estimatePlanResumeFields(plan, resumeFrom),
    worker: "copilot-coding-agent",
    model: model || "copilot-coding-agent",
    tokens: {
      estimatedInput: totalInputTokens,
      estimatedOutput: totalOutputTokens,
      source: tokensPerSlice.source,
    },
    estimatedCostUSD: 0,
    estimated_cost_usd: 0,
    provider: "copilot-coding-agent",
    pricingMode: "subscription",
    wallClockEstimateMinutes: sliceCount * COPILOT_AGENT_MINUTES_PER_SLICE,
    confidence: "heuristic",
    slices: effectiveSlices.map((slice) => ({
      number: slice.number,
      title: slice.title,
      depends: slice.depends,
      parallel: slice.parallel,
      scope: slice.scope,
    })),
  };
}

function _buildEstimatePlanSlices(effectiveSlices, cwd, quorumConfig) {
  return effectiveSlices.map((slice) => {
    const sliceType = inferSliceType(slice);
    const recommendation = cwd ? recommendModel(cwd, sliceType) : null;
    const complexityScore = quorumConfig && quorumConfig.enabled
      ? scoreSliceComplexity(slice, cwd).score
      : null;
    return {
      number: slice.number,
      title: slice.title,
      depends: slice.depends,
      parallel: slice.parallel,
      scope: slice.scope,
      sliceType,
      ...(recommendation && {
        recommendedModel: {
          model: recommendation.model,
          success_rate: recommendation.success_rate,
          based_on_slices: recommendation.total_slices,
        },
      }),
      ...(quorumConfig && quorumConfig.enabled && {
        complexityScore,
        quorumEligible: quorumConfig.auto
          ? complexityScore >= quorumConfig.threshold
          : true,
      }),
    };
  });
}

function _estimatePlanHistoryContext(cwd, pricingMode) {
  const history = _loadCostHistory(cwd);
  return {
    avgTokensPerSlice: _computeAverageTokensPerSlice(
      history,
      history.length > 0 ? `${history.length} prior run(s)` : null
    ),
    avgPremiumPerSlice: pricingMode === "subscription"
      ? _computeAveragePremiumPerSlice(history)
      : null,
  };
}

function _estimatePlanBaseCost({ pricingMode, sliceCount, avgPremiumPerSlice, costModel, totalInputTokens, totalOutputTokens, pricing }) {
  if (pricingMode === "subscription") {
    const reqPerSlice = avgPremiumPerSlice !== null ? avgPremiumPerSlice : 1.5;
    return sliceCount * reqPerSlice * costModel.perRequestUsd;
  }
  return (totalInputTokens * pricing.input) + (totalOutputTokens * pricing.output);
}

function _estimatePlanCostCalibration(pricingMode, model, cwd) {
  if (pricingMode !== "token") return null;

  const correction = _calibrateCorrectionFactor(model, cwd);
  if (!correction) return null;

  return {
    appliedFactor: correction.correctionFactor,
    output: {
      correctionFactor: Math.round(correction.correctionFactor * 100) / 100,
      samplesUsed: correction.samplesUsed,
      source: correction.source,
    },
  };
}

function _estimatePlanQuorumViability(quorumConfig) {
  if (!(quorumConfig && quorumConfig.enabled)) return null;

  const presetName = quorumConfig.preset || null;
  if (!(presetName && QUORUM_PRESETS[presetName])) return null;
  return assessQuorumViability(presetName);
}

function _estimatePlanFoundryQuota(totalInputTokens, totalOutputTokens, provider, cwd) {
  return _computeFoundryQuota({
    estimatedTokensIn: totalInputTokens,
    estimatedTokensOut: totalOutputTokens,
    provider,
    cwd,
  });
}

function _buildEstimatePlanResult({
  plan,
  resumeFrom,
  model,
  costModel,
  pricingMode,
  avgTokensPerSlice,
  splitAdvisories,
  modelRecommendation,
  estimatedCost,
  totalInputTokens,
  totalOutputTokens,
  tokensPerSlice,
  effectiveOrder,
  effectiveSlices,
  sliceCount,
  quorumOverhead,
  quorumViability,
  costCalibration,
  cwd,
  quorumConfig,
}) {
  const foundryQuota = _estimatePlanFoundryQuota(totalInputTokens, totalOutputTokens, costModel.provider, cwd);
  return {
    status: "estimate",
    sliceCount,
    executionOrder: effectiveOrder,
    ..._estimatePlanResumeFields(plan, resumeFrom),
    model: model || "auto",
    ...(modelRecommendation && { modelRecommendation }),
    ...(splitAdvisories.length > 0 && { splitAdvisories }),
    tokens: {
      estimatedInput: totalInputTokens,
      estimatedOutput: totalOutputTokens,
      source: tokensPerSlice.source,
    },
    estimatedCostUSD: Math.round(estimatedCost * 100) / 100,
    estimated_cost_usd: Math.round(estimatedCost * 100) / 100,
    provider: costModel.provider,
    pricingMode,
    ...(costCalibration && { costCalibration }),
    ...(quorumOverhead && {
      quorumOverhead,
      totalCostWithQuorumUSD: Math.round((estimatedCost + quorumOverhead.totalOverheadUSD) * 100) / 100,
    }),
    ...(quorumViability && { quorumViability }),
    confidence: avgTokensPerSlice ? "historical" : "heuristic",
    ...(foundryQuota && { foundryQuota }),
    slices: _buildEstimatePlanSlices(effectiveSlices, cwd, quorumConfig),
  };
}

export function estimatePlan({ plan, model, cwd, quorumConfig = null, resumeFrom = null, worker = null }) {
  const { effectiveSlices, effectiveOrder } = _resolveEffectiveSlices(plan, resumeFrom);
  const forgeConfig = _loadForgeConfig(cwd);
  const costModel = detectCostModel({ env: process.env, forgeConfig, model });
  const pricingMode = SUBSCRIPTION_PROVIDERS.has(costModel.provider) ? "subscription" : "token";
  const { avgTokensPerSlice, avgPremiumPerSlice } = _estimatePlanHistoryContext(cwd, pricingMode);
  const tokensPerSlice = avgTokensPerSlice || { input: 2000, output: 5000, source: "heuristic" };
  const pricing = getPricing(model);
  const sliceCount = effectiveSlices.length;
  const totalInputTokens = sliceCount * tokensPerSlice.input;
  const totalOutputTokens = sliceCount * tokensPerSlice.output;

  if (worker === "copilot-coding-agent") {
    return _buildCopilotCodingAgentEstimate({ plan: plan, effectiveSlices: effectiveSlices, effectiveOrder: effectiveOrder, resumeFrom: resumeFrom, model: model, tokensPerSlice: tokensPerSlice });
  }

  let estimatedCost = _estimatePlanBaseCost({
    pricingMode,
    sliceCount,
    avgPremiumPerSlice,
    costModel,
    totalInputTokens,
    totalOutputTokens,
    pricing,
  });
  const calibration = _estimatePlanCostCalibration(pricingMode, model, cwd);
  const costCalibration = calibration?.output || null;
  if (calibration) {
    estimatedCost *= calibration.appliedFactor;
  }

  const costForLeg = (legModel, inTokens, outTokens) => {
    const legCost = detectCostModel({ env: process.env, forgeConfig, model: legModel });
    if (SUBSCRIPTION_PROVIDERS.has(legCost.provider)) {
      // Subscription provider — flat per-request charge regardless of token volume.
      return legCost.perRequestUsd;
    }
    const mPricing = getPricing(legModel);
    return (inTokens * mPricing.input) + (outTokens * mPricing.output);
  };

  return _buildEstimatePlanResult({
    plan,
    resumeFrom,
    model,
    costModel,
    pricingMode,
    avgTokensPerSlice,
    splitAdvisories: _loadSplitAdvisories(effectiveSlices, cwd),
    modelRecommendation: _loadModelRecommendation(model, cwd),
    estimatedCost,
    totalInputTokens,
    totalOutputTokens,
    tokensPerSlice,
    effectiveOrder,
    effectiveSlices,
    sliceCount,
    quorumOverhead: _computeQuorumOverhead(quorumConfig, model, {
      effectiveSlices,
      sliceCount,
      tokensPerSlice,
      cwd,
      costForLeg,
    }),
    quorumViability: _estimatePlanQuorumViability(quorumConfig),
    costCalibration,
    cwd,
    quorumConfig,
  });
}

/**
 * Build a quorum configuration object for a given mode name.
 * Shared by estimateQuorum and estimateSlice so the two always agree
 * on which models, thresholds, and auto flags each mode implies.
 *
 * @param {"auto"|"power"|"speed"|"false"} mode
 * @returns {object|null} quorumConfig for estimatePlan, or null for mode "false".
 */
function _buildQuorumAutoConfig() {
  return {
    enabled: true,
    auto: true,
    threshold: 5,
    models: QUORUM_PRESETS.speed?.models || ["claude-sonnet-4.6"],
    reviewerModel: QUORUM_PRESETS.speed?.reviewerModel || "claude-sonnet-4.6",
    preset: "speed",
  };
}

function _buildQuorumPresetConfig(presetName, fallbackThreshold, fallbackReviewerModel) {
  return {
    enabled: true,
    auto: false,
    threshold: QUORUM_PRESETS[presetName]?.threshold ?? fallbackThreshold,
    models: QUORUM_PRESETS[presetName]?.models || [],
    reviewerModel: QUORUM_PRESETS[presetName]?.reviewerModel || fallbackReviewerModel,
    preset: presetName,
  };
}

export function buildQuorumConfigForMode(mode) {
  if (mode === "false" || mode === false) return null;

  const builders = {
    auto: _buildQuorumAutoConfig,
    power: () => _buildQuorumPresetConfig("power", 5, "claude-opus-4.7"),
    speed: () => _buildQuorumPresetConfig("speed", 7, "claude-sonnet-4.6"),
  };
  const builder = builders[mode];
  if (builder) {
    return builder();
  }
  throw new Error(`buildQuorumConfigForMode: unknown mode "${mode}" — expected auto | power | speed | false`);
}

/**
 * Project cost for a single slice under a given quorum mode.
 *
 * Per-slice projections are un-calibrated base × rate numbers. Run-level
 * historical calibration (correction factor from cost-history.json) is
 * applied only in `estimatePlan` / `estimateQuorum`. This is intentional:
 * a single slice does not provide enough context to re-derive the factor.
 *
 * @param {object} options
 * @param {object} options.plan - Parsed plan object with slices and dag
 * @param {string|number} options.sliceNumber - Slice identifier (may be alphanumeric, e.g. "2A")
 * @param {"auto"|"power"|"speed"|"false"} [options.mode="auto"] - Quorum mode
 * @param {string} [options.model="claude-sonnet-4.5"] - Base model for pricing
 * @param {string} [options.cwd] - Project root for history + complexity scoring
 * @returns {{
 *   estimatedCostUSD: number,
 *   baseCostUSD: number,
 *   overheadUSD: number,
 *   complexityScore: number,
 *   model: string,
 *   quorumEligible: boolean,
 *   rationale: string,
 *   generatedAt: string
 * }}
 */
const VALID_ESTIMATE_SLICE_MODES = new Set(["auto", "power", "speed", "false"]);

function _estimateSliceTokensPerSlice(resolvedCwd) {
  return _computeAverageTokensPerSlice(_loadCostHistory(resolvedCwd)) || { input: 2000, output: 5000 };
}

function _estimateSliceQuorumDecision(quorumConfig, complexityScore, mode) {
  if (!quorumConfig) {
    return { quorumEligible: false, rationale: "mode false: quorum disabled" };
  }
  if (quorumConfig.auto) {
    const quorumEligible = complexityScore >= quorumConfig.threshold;
    return {
      quorumEligible,
      rationale: quorumEligible
        ? `threshold ${quorumConfig.threshold} met: complexity ${complexityScore}`
        : `threshold ${quorumConfig.threshold} not met: complexity ${complexityScore}`,
    };
  }
  return {
    quorumEligible: true,
    rationale: `mode ${mode}: all slices quorum-eligible`,
  };
}

function _estimateSliceOverhead(quorumEligible, quorumConfig, tokensPerSlice, costForLeg) {
  if (!(quorumEligible && quorumConfig)) return 0;

  const dryRunInput = tokensPerSlice.input * 1.5;
  const dryRunOutput = tokensPerSlice.output * 0.8;
  const dryRunCost = quorumConfig.models.reduce(
    (sum, legModel) => sum + costForLeg(legModel, dryRunInput, dryRunOutput),
    0
  );
  const reviewerInput = dryRunOutput * quorumConfig.models.length + tokensPerSlice.input;
  const reviewerOutput = tokensPerSlice.output * 0.6;
  const reviewerCost = costForLeg(quorumConfig.reviewerModel, reviewerInput, reviewerOutput);
  return dryRunCost + reviewerCost;
}

export function estimateSlice({ plan, sliceNumber, mode = "auto", model = "claude-sonnet-4.5", cwd, env = process.env } = {}) {
  if (!plan || !plan.slices) {
    throw new Error("estimateSlice: plan object with slices is required");
  }
  const target = String(sliceNumber);
  const slice = plan.slices.find((s) => String(s.number) === target);
  if (!slice) {
    throw new Error(`estimateSlice: sliceNumber "${target}" not found in plan (available: ${plan.slices.map((s) => s.number).join(", ")})`);
  }
  if (!VALID_ESTIMATE_SLICE_MODES.has(mode)) {
    throw new Error(`estimateSlice: unknown mode "${mode}" — expected auto | power | speed | false`);
  }

  const resolvedCwd = cwd === null ? null : (cwd || process.cwd());
  const tokensPerSlice = _estimateSliceTokensPerSlice(resolvedCwd);
  const forgeConfig = _loadForgeConfig(resolvedCwd);
  const costForLeg = (legModel, inTokens, outTokens) => {
    const legCost = detectCostModel({ env, forgeConfig, model: legModel });
    if (SUBSCRIPTION_PROVIDERS.has(legCost.provider)) {
      return legCost.perRequestUsd;
    }
    const mPricing = getPricing(legModel);
    return (inTokens * mPricing.input) + (outTokens * mPricing.output);
  };

  const baseCostUSD = costForLeg(model, tokensPerSlice.input, tokensPerSlice.output);
  const { score: complexityScore } = scoreSliceComplexity(slice, resolvedCwd);
  const quorumConfig = buildQuorumConfigForMode(mode);
  const { quorumEligible, rationale } = _estimateSliceQuorumDecision(quorumConfig, complexityScore, mode);
  const overheadUSD = _estimateSliceOverhead(quorumEligible, quorumConfig, tokensPerSlice, costForLeg);
  const estimatedCostUSD = baseCostUSD + overheadUSD;
  const _sliceProvider = detectCostModel({ env, forgeConfig, model }).provider;
  const _sliceFq = _computeFoundryQuota({
    estimatedTokensIn: tokensPerSlice.input,
    estimatedTokensOut: tokensPerSlice.output,
    provider: _sliceProvider,
    env,
    cwd: resolvedCwd,
  });

  return {
    estimatedCostUSD: Math.round(estimatedCostUSD * 1_000_000) / 1_000_000,
    baseCostUSD: Math.round(baseCostUSD * 1_000_000) / 1_000_000,
    overheadUSD: Math.round(overheadUSD * 1_000_000) / 1_000_000,
    complexityScore,
    model,
    quorumEligible,
    rationale,
    generatedAt: new Date().toISOString(),
    ...(_sliceFq && { foundryQuota: _sliceFq }),
  };
}

/**
 * Build a cost estimate for all four quorum modes in a single call.
 * This is the canonical "show me the picker" entry point — agents must call
 * this tool instead of hand-computing quorum costs in chat.
 *
 * @param {object} options
 * @param {object} options.plan - Parsed plan object (same shape estimatePlan expects)
 * @param {string} [options.cwd] - Project root for history lookup
 * @param {string|number} [options.resumeFrom] - Optional resume point
 * @param {string} [options.defaultModel] - Base model when quorum disabled (default: "claude-sonnet-4.5")
 * @returns {{
 *   auto: object, power: object, speed: object, "false": object,
 *   recommended: "auto"|"power"|"speed"|"false",
 *   generatedAt: string
 * }}
 *   Each mode summary contains: mode, estimatedCostUSD, baseCostUSD,
 *   overheadUSD, quorumSliceCount, totalSliceCount, confidence, and
 *   slices[] — an additive per-slice breakdown with sliceNumber,
 *   projectedCostUSD, complexityScore, quorumEligible.
 */
export function estimateQuorum({ plan, cwd, resumeFrom = null, defaultModel = "claude-sonnet-4.5" } = {}) {
  if (!plan || !plan.slices || !plan.dag) {
    throw new Error("estimateQuorum: plan object with slices and dag is required");
  }

  // Meta-bug #97: distinguish `cwd === null` (caller opts out of history lookup —
  // fresh heuristic estimate) from `cwd === undefined` (fall back to process.cwd()).
  // Previously both collapsed to process.cwd(), which on a pforge checkout silently
  // pulled the plan-forge repo's own .forge/cost-history.json and produced
  // "historical" confidence + inflated cost (calibration factor × large-run token
  // averages) on caller-supplied heuristic plans.
  const resolvedCwd = cwd === null ? null : (cwd || process.cwd());

  const autoConfig = buildQuorumConfigForMode("auto");
  const powerConfig = buildQuorumConfigForMode("power");
  const speedConfig = buildQuorumConfigForMode("speed");

  const estAuto = estimatePlan({ plan, model: defaultModel, cwd: resolvedCwd, quorumConfig: autoConfig, resumeFrom });
  const estPower = estimatePlan({ plan, model: defaultModel, cwd: resolvedCwd, quorumConfig: powerConfig, resumeFrom });
  const estSpeed = estimatePlan({ plan, model: defaultModel, cwd: resolvedCwd, quorumConfig: speedConfig, resumeFrom });
  const estNone = estimatePlan({ plan, model: defaultModel, cwd: resolvedCwd, resumeFrom });

  // Per-mode, per-slice breakdown (additive — does not alter existing keys).
  // Uses estimateSlice for parity with the single-slice MCP tool. Un-calibrated
  // (no run-level historical correction factor); summed values may differ from
  // the run-level estimate's calibrated totalCostWithQuorumUSD.
  const buildSliceBreakdown = (mode) =>
    plan.slices.map((s) => {
      const sliceEst = estimateSlice({ plan, sliceNumber: s.number, mode, model: defaultModel, cwd: resolvedCwd });
      return {
        sliceNumber: s.number,
        projectedCostUSD: sliceEst.estimatedCostUSD,
        complexityScore: sliceEst.complexityScore,
        quorumEligible: sliceEst.quorumEligible,
      };
    });

  const toSummary = (est, mode) => ({
    mode,
    estimatedCostUSD: est.totalCostWithQuorumUSD ?? est.estimatedCostUSD,
    baseCostUSD: est.estimatedCostUSD,
    overheadUSD: est.quorumOverhead?.totalOverheadUSD ?? 0,
    quorumSliceCount: est.quorumOverhead?.quorumSliceCount ?? 0,
    totalSliceCount: est.sliceCount,
    confidence: est.confidence,
    slices: buildSliceBreakdown(mode),
  });

  const summaries = {
    auto: toSummary(estAuto, "auto"),
    power: toSummary(estPower, "power"),
    speed: toSummary(estSpeed, "speed"),
    "false": toSummary(estNone, "false"),
  };

  // Recommendation: cheapest mode under optional runtime.cost.budget, else auto.
  let budgetCap = null;
  if (cwd) {
    try {
      const cfgPath = resolve(cwd, ".forge.json");
      if (existsSync(cfgPath)) {
        const cfg = JSON.parse(readFileSync(cfgPath, "utf-8"));
        if (cfg?.runtime?.cost?.budget && Number.isFinite(cfg.runtime.cost.budget)) {
          budgetCap = cfg.runtime.cost.budget;
        }
      }
    } catch { /* budget cap optional */ }
  }

  let recommended = "auto";
  if (budgetCap !== null) {
    const affordable = Object.entries(summaries)
      .filter(([, s]) => s.estimatedCostUSD <= budgetCap)
      .sort((a, b) => a[1].estimatedCostUSD - b[1].estimatedCostUSD);
    if (affordable.length > 0) recommended = affordable[0][0];
  }

  return {
    ...summaries,
    recommended,
    ...(budgetCap !== null && { budgetCapUSD: budgetCap }),
    generatedAt: new Date().toISOString(),
    ...(() => {
      const _qFq = _computeFoundryQuota({
        estimatedTokensIn: estAuto.tokens?.estimatedInput ?? 0,
        estimatedTokensOut: estAuto.tokens?.estimatedOutput ?? 0,
        provider: estAuto.provider ?? "unknown",
        cwd: resolvedCwd,
      });
      return _qFq ? { foundryQuota: _qFq } : {};
    })(),
  };
}

/**
 * Plan Forge — Crucible Config (Slice 01.6).
 *
 * Persists dashboard Config-tab settings for the Crucible subsystem
 * to `.forge/crucible/config.json`. Tiny surface — load / save / merge
 * with validation so bad UI input can't corrupt the file.
 *
 * Fields:
 *   - defaultLane: "tweak" | "feature" | "full"
 *   - recursionDepth: 0..3   (self-referral cap on child smelts)
 *   - autoApproveAgent: boolean  (auto-finalize agent smelts)
 *   - sourceWeights: { memory, principles, plans }  (sum ~= 100)
 *   - staleDefaultsHours: 1..168  (warning threshold)
 *   - quorumPreset: "speed" | "power" | "power-gov" | "false"  (Phase-FOUNDRY-PROVIDER)
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { resolve } from "node:path";

export const DEFAULT_CRUCIBLE_CONFIG = Object.freeze({
  defaultLane: "feature",
  recursionDepth: 1,
  autoApproveAgent: false,
  sourceWeights: { memory: 34, principles: 33, plans: 33 },
  staleDefaultsHours: 24,
  quorumPreset: "speed",
});

const VALID_LANES = new Set(["tweak", "feature", "full"]);

/** All quorum presets accepted by the Crucible dashboard config (Phase-FOUNDRY-PROVIDER Slice 6). */
export const VALID_QUORUM_PRESETS = new Set(["speed", "power", "power-gov", "false"]);

export function configPath(projectDir) {
  return resolve(projectDir, ".forge", "crucible", "config.json");
}

/**
 * Load + sanitize the config. Missing file -> defaults. Malformed file
 * -> defaults (never throws, never corrupts caller).
 */
export function loadCrucibleConfig(projectDir) {
  const path = configPath(projectDir);
  if (!existsSync(path)) return { ...DEFAULT_CRUCIBLE_CONFIG, sourceWeights: { ...DEFAULT_CRUCIBLE_CONFIG.sourceWeights } };
  let raw;
  try { raw = JSON.parse(readFileSync(path, "utf-8")); }
  catch { return { ...DEFAULT_CRUCIBLE_CONFIG, sourceWeights: { ...DEFAULT_CRUCIBLE_CONFIG.sourceWeights } }; }
  return sanitize(raw);
}

/**
 * Merge + validate + persist. Returns the sanitized config that was
 * written so the caller can echo it back to the UI.
 */
export function saveCrucibleConfig(projectDir, patch) {
  const current = loadCrucibleConfig(projectDir);
  const merged = sanitize({ ...current, ...patch, sourceWeights: { ...current.sourceWeights, ...(patch?.sourceWeights || {}) } });
  const path = configPath(projectDir);
  mkdirSync(resolve(projectDir, ".forge", "crucible"), { recursive: true });
  writeFileSync(path, JSON.stringify(merged, null, 2), "utf-8");
  return merged;
}

/**
 * Coerce caller-supplied values to the canonical shape. Unknown fields
 * are dropped. Out-of-range numbers snap to the nearest valid bound.
 * Weights are normalized to sum 100.
 */
export function sanitize(input) {
  const out = { ...DEFAULT_CRUCIBLE_CONFIG, sourceWeights: { ...DEFAULT_CRUCIBLE_CONFIG.sourceWeights } };
  if (!input || typeof input !== "object") return out;

  if (typeof input.defaultLane === "string" && VALID_LANES.has(input.defaultLane)) {
    out.defaultLane = input.defaultLane;
  }
  if (Number.isFinite(input.recursionDepth)) {
    out.recursionDepth = Math.max(0, Math.min(3, Math.trunc(input.recursionDepth)));
  }
  if (typeof input.autoApproveAgent === "boolean") {
    out.autoApproveAgent = input.autoApproveAgent;
  }
  if (typeof input.quorumPreset === "string" && VALID_QUORUM_PRESETS.has(input.quorumPreset)) {
    out.quorumPreset = input.quorumPreset;
  }
  if (Number.isFinite(input.staleDefaultsHours)) {
    out.staleDefaultsHours = Math.max(1, Math.min(168, Math.trunc(input.staleDefaultsHours)));
  }

  const w = input.sourceWeights;
  if (w && typeof w === "object") {
    const m = Number(w.memory);
    const p = Number(w.principles);
    const pl = Number(w.plans);
    if (Number.isFinite(m) && Number.isFinite(p) && Number.isFinite(pl)) {
      const raw = { memory: Math.max(0, m), principles: Math.max(0, p), plans: Math.max(0, pl) };
      const sum = raw.memory + raw.principles + raw.plans;
      if (sum > 0) {
        // Normalize to sum 100 while keeping integer values
        const scaled = {
          memory: Math.round((raw.memory / sum) * 100),
          principles: Math.round((raw.principles / sum) * 100),
          plans: Math.round((raw.plans / sum) * 100),
        };
        // Fix rounding drift so the sum is exactly 100
        const drift = 100 - (scaled.memory + scaled.principles + scaled.plans);
        scaled.plans += drift;
        out.sourceWeights = scaled;
      }
    }
  }

  return out;
}

/**
 * Plan Forge — Crucible Draft Renderer (Phase-35 Slice 2).
 *
 * Assembles a phase-doc markdown body from a smelt's raw idea + answers.
 * Emits the six mandatory blocks every hardened plan must carry:
 *
 *   1. Slices              — from scope-files / scope-in answers
 *   2. Validation Gates    — from validation / validation-gates answer
 *   3. Stop Conditions     — boilerplate we WILL NOT auto-fill as "answered"
 *   4. Rollback            — from rollback / rollback-plan answer
 *   5. Anti-patterns       — from forbidden-actions answer
 *   6. Change Manifest     — file list derived from scope answers
 *
 * Any field that has no answer yet renders as `{{TBD: <question-id>}}`
 * so `extractUnresolvedFields()` can surface it in the preview.
 *
 * Hard rule: this renderer must NEVER inject plausible-sounding filler
 * in place of a `{{TBD:}}` marker. Slice 01.3 Stop Condition.
 */

import { inferRepoCommands } from "./crucible-infer.mjs";

const TBD_REGEX = /\{\{TBD:\s*([a-z0-9-]+)\s*\}\}/gi;

/**
 * Return a { questionId -> answer } lookup from a smelt.
 */
function indexAnswers(smelt) {
  const out = {};
  for (const a of (smelt && smelt.answers) || []) {
    if (a && typeof a.questionId === "string") out[a.questionId] = a.answer;
  }
  return out;
}

function firstAnswer(answers, ...keys) {
  for (const k of keys) {
    const v = answers[k];
    if (typeof v === "string" && v.trim()) return v.trim();
  }
  return null;
}

/**
 * Expand an answer into a markdown bullet list. Input may be comma- or
 * newline-separated. If already formatted as a list, return as-is.
 */
function asBulletList(value) {
  if (!value) return null;
  if (/^\s*[-*]\s+/m.test(value)) return value.trim();
  const parts = value
    .split(/\r?\n|,/)
    .map((s) => s.trim())
    .filter(Boolean);
  if (parts.length === 0) return null;
  return parts.map((p) => `- ${p}`).join("\n");
}

/**
 * Synthesize a concrete Slice 1 markdown block from interview answers and
 * inferred repo commands. Returns `null` when any required prerequisite is
 * missing, so the caller falls back to the generic `> Slice template:` block.
 *
 * Prerequisites:
 *   - `smelt.answers` must contain a non-empty `scope-files` / `scope-in` answer
 *   - `smelt.answers` must contain a non-empty `validation-gates` / `validation` answer
 *   - `repoCommands.buildCommand` and `repoCommands.testCommand` must both be non-null
 *
 * @param {{ smelt: object, repoCommands: object }} params
 * @returns {string|null}
 */
export function synthesizeSliceBlock({ smelt, repoCommands }) {
  if (!smelt || !repoCommands) return null;
  if (!repoCommands.buildCommand || !repoCommands.testCommand) return null;

  const ans = indexAnswers(smelt);

  const scopeRaw = firstAnswer(ans, "scope-files", "scope-file", "scope-in");
  if (!scopeRaw) return null;
  const filesBullet = asBulletList(scopeRaw);
  if (!filesBullet) return null;

  const gatesRaw = firstAnswer(ans, "validation-gates", "validation");
  if (!gatesRaw) return null;
  const gatesLines = gatesRaw
    .split(/\r?\n/)
    .map((s) => s.trim())
    .filter(Boolean)
    .map((s) => {
      if (/^-\s*\[/.test(s)) return s;
      if (/^[-*]\s+/.test(s)) return `- [ ] ${s.replace(/^[-*]\s+/, "")}`;
      return `- [ ] ${s}`;
    });
  if (gatesLines.length === 0) return null;

  const rawIdea = (smelt.rawIdea || "").trim();
  const titleBase =
    firstAnswer(ans, "feature-name") || rawIdea.split(/\r?\n/)[0] || "Untitled";
  const title = titleBase.slice(0, 60);

  return [
    `### Slice 1 — ${title}`,
    "",
    `Build command: ${repoCommands.buildCommand}`,
    `Test command:  ${repoCommands.testCommand}`,
    "",
    "**Files**:",
    filesBullet,
    "",
    "**Acceptance Criteria**:",
    gatesLines.join("\n"),
  ].join("\n");
}

/**
 * Render the phase-doc body for a smelt. Caller prepends the crucibleId
 * frontmatter.
 *
 * @param {{
 *   rawIdea?: string,
 *   lane?: string,
 *   source?: string,
 *   status?: string,
 *   answers?: Array<{questionId:string, answer:string}>,
 *   phaseName?: string|null,
 * }} smelt
 * @param {{ cwd?: string }} [options]
 * @returns {string} markdown body (trailing newline included)
 */
function fallbackField(value, tbdId) {
  return value || `{{TBD: ${tbdId}}}`;
}

function buildDraftContent(ans, lane) {
  const scopeInRaw = firstAnswer(ans, "scope-in", "scope-files", "scope-file", "goal");
  return {
    scopeIn: fallbackField(asBulletList(scopeInRaw), lane === "full" ? "scope-in" : "scope-files"),
    outOfScope: fallbackField(asBulletList(firstAnswer(ans, "scope-out", "out-of-scope")), lane === "full" ? "scope-out" : "out-of-scope"),
    validationGates: fallbackField(firstAnswer(ans, "validation-gates", "validation"), lane === "tweak" ? "validation" : "validation-gates"),
    rollback: fallbackField(firstAnswer(ans, "rollback-plan", "rollback"), lane === "full" ? "rollback-plan" : "rollback"),
    forbidden: fallbackField(asBulletList(firstAnswer(ans, "forbidden-actions")), "forbidden-actions"),
    tests: fallbackField(firstAnswer(ans, "tests"), "tests"),
    changeManifest: fallbackField(asBulletList(firstAnswer(ans, "scope-files", "scope-file", "scope-in")), "change-manifest"),
    sliceCount: firstAnswer(ans, "slice-count"),
  };
}

function appendDraftPreamble(lines, { smelt, lane, title, rawIdea }) {
  lines.push(`# ${smelt.phaseName ? `${smelt.phaseName}: ` : ""}${title}`);
  lines.push("");
  lines.push(`> **Lane**: ${lane}  `);
  lines.push(`> **Source**: ${smelt.source || "human"}  `);
  lines.push(`> **Status**: ${smelt.status || "in-progress"}`);
  lines.push("");
  lines.push("## Raw Idea");
  lines.push("");
  lines.push(rawIdea || `{{TBD: ${lane === "full" ? "user-problem" : "goal"}}}`);
  lines.push("");
}

function appendFullLaneSections(lines, ans) {
  const problem = fallbackField(firstAnswer(ans, "user-problem"), "user-problem");
  const metric = fallbackField(firstAnswer(ans, "success-metric"), "success-metric");
  const stack = fallbackField(firstAnswer(ans, "stack-boundary"), "stack-boundary");
  const dataModel = fallbackField(firstAnswer(ans, "data-model"), "data-model");
  const apiSurface = fallbackField(firstAnswer(ans, "api-surface"), "api-surface");
  const security = fallbackField(firstAnswer(ans, "security-posture"), "security-posture");

  lines.push("## Problem & Success Metric");
  lines.push("");
  lines.push(`**Problem**: ${problem}`);
  lines.push("");
  lines.push(`**Success metric**: ${metric}`);
  lines.push("");
  lines.push("## Stack Boundary");
  lines.push("");
  lines.push(stack);
  lines.push("");
  lines.push("## Data Model");
  lines.push("");
  lines.push(dataModel);
  lines.push("");
  lines.push("## API Surface");
  lines.push("");
  lines.push(apiSurface);
  lines.push("");
  lines.push("## Security Posture");
  lines.push("");
  lines.push(security);
  lines.push("");
}

function appendScopeContract(lines, content) {
  lines.push("## Scope Contract");
  lines.push("");
  lines.push("**In scope**:");
  lines.push("");
  lines.push(content.scopeIn);
  lines.push("");
  lines.push("**Out of scope**:");
  lines.push("");
  lines.push(content.outOfScope);
  lines.push("");
}

function appendSliceTemplate(lines) {
  lines.push("> Slice template:");
  lines.push(">");
  lines.push("> ```");
  lines.push("> ### Slice N — <name>");
  lines.push("> Build command: <cmd>");
  lines.push("> Test command:  <cmd>");
  lines.push("> Tasks:         <list>");
  lines.push("> Files:         <manifest>");
  lines.push("> ```");
}

function appendSlicesSection(lines, sliceCount, synthesized) {
  lines.push("## Slices");
  lines.push("");
  lines.push(
    sliceCount
      ? `_Estimated: ${sliceCount} slices. Expand each below during Plan Hardener step._`
      : "_Slice breakdown is authored during the Plan Hardener step (Session 1, Step 2)._"
  );
  lines.push("");
  if (synthesized) lines.push(synthesized);
  else appendSliceTemplate(lines);
  lines.push("");
}

function appendStandardBlocks(lines, content) {
  lines.push("## Validation Gates");
  lines.push("");
  lines.push(content.validationGates);
  lines.push("");
  lines.push(`**Tests**: ${content.tests}`);
  lines.push("");
  lines.push("## Stop Conditions");
  lines.push("");
  lines.push("- Validation gate fails and root cause is not identified within 30 minutes");
  lines.push("- A slice drifts past its declared Scope Contract");
  lines.push("- A forbidden action (see Anti-patterns) is about to be introduced");
  lines.push("- Token budget for this phase is exceeded by more than 25%");
  lines.push("");
  lines.push("## Rollback");
  lines.push("");
  lines.push(content.rollback);
  lines.push("");
  lines.push("## Anti-patterns & Forbidden Actions");
  lines.push("");
  lines.push(content.forbidden);
  lines.push("");
  lines.push("## Change Manifest");
  lines.push("");
  lines.push(content.changeManifest);
  lines.push("");
}

function appendInterviewLog(lines, answers) {
  if (!Array.isArray(answers) || answers.length === 0) return;
  lines.push("## Interview Log");
  lines.push("");
  answers.forEach((answer, i) => {
    lines.push(`${i + 1}. **${answer.questionId}** — ${answer.answer}`);
  });
  lines.push("");
}

export function renderDraft(smelt, options = {}) {
  if (!smelt) throw new Error("smelt required");
  const cwd = options && options.cwd;
  const ans = indexAnswers(smelt);
  const lane = smelt.lane || "feature";
  const rawIdea = (smelt.rawIdea || "").trim();
  const firstLine = rawIdea.split(/\r?\n/)[0].slice(0, 80).trim();
  const title = firstAnswer(ans, "feature-name") || firstLine || "Untitled smelt";
  const content = buildDraftContent(ans, lane);
  const synthesized = cwd ? synthesizeSliceBlock({ smelt, repoCommands: inferRepoCommands(cwd) }) : null;
  const lines = [];

  appendDraftPreamble(lines, { smelt, lane, title, rawIdea });
  if (lane === "full") appendFullLaneSections(lines, ans);
  appendScopeContract(lines, content);
  appendSlicesSection(lines, content.sliceCount, synthesized);
  appendStandardBlocks(lines, content);
  appendInterviewLog(lines, smelt.answers);

  return lines.join("\n");
}

/**
 * Extract the set of unresolved `{{TBD: question-id}}` markers from a
 * rendered markdown body. Returns an ordered, de-duplicated array of
 * question ids.
 *
 * @param {string} markdown
 * @returns {string[]}
 */
export function extractUnresolvedFields(markdown) {
  if (typeof markdown !== "string") return [];
  const seen = new Set();
  const out = [];
  let m;
  TBD_REGEX.lastIndex = 0;
  while ((m = TBD_REGEX.exec(markdown)) !== null) {
    const id = m[1].trim();
    if (!seen.has(id)) {
      seen.add(id);
      out.push(id);
    }
  }
  return out;
}

/**
 * Six block headings that renderDraft must emit for every lane. Exposed
 * for tests so the contract is declarative.
 */
export const MANDATORY_BLOCKS = Object.freeze([
  "## Scope Contract",
  "## Slices",
  "## Validation Gates",
  "## Stop Conditions",
  "## Rollback",
  "## Anti-patterns & Forbidden Actions",
  "## Change Manifest",
]);

/**
 * Plan Forge — Spec Kit Importer (Phase CRUCIBLE-IMPORT-CLI).
 *
 * Deterministic, LLM-free importer that maps the four canonical Spec Kit
 * artifacts (`spec.md`, `plan.md`, `tasks.md`, `constitution.md`) into a
 * Plan Forge Crucible smelt and emits a Phase Plan whose YAML frontmatter
 * already satisfies `crucible-enforce.mjs`.
 *
 * Field mapping is documented in [docs/manual/spec-kit-interop.html].
 *
 * Separation of concerns:
 *   - This module: filesystem read, markdown parse, smelt write, plan emit,
 *     audit-log append. Pure data transforms — no network, no LLM, no shell.
 *   - CLI rendering (table output, ANSI, exit codes): the `main()` entry at
 *     the bottom of this file, invoked when run as a script.
 *   - MCP tool wrapping: server.mjs (Slice 4).
 *
 * @module crucible-import
 */

import {
  appendFileSync,
  existsSync,
  mkdirSync,
  readFileSync,
  readdirSync,
  statSync,
  writeFileSync,
} from "node:fs";
import { dirname, join, resolve, basename } from "node:path";
import { randomUUID } from "node:crypto";
import { ERROR_CODES } from "./enums.mjs";

// ─── Public API ─────────────────────────────────────────────────────────────

/**
 * @typedef {Object} MappedField
 * @property {string} source    Source file + heading, e.g. "spec.md#title"
 * @property {string} target    Smelt target field, e.g. "plan-title"
 * @property {*}      value     The mapped value (string | string[] | object[])
 *
 * @typedef {Object} MissingField
 * @property {string} file      Which source file was missing the field
 * @property {string} field     Which field
 * @property {"error"|"warn"} severity
 *
 * @typedef {Object} ImportResult
 * @property {boolean}        ok
 * @property {string|null}    smeltId
 * @property {string|null}    planPath
 * @property {string|null}    smeltPath
 * @property {MappedField[]}  mappedFields
 * @property {MissingField[]} missingFields
 * @property {string[]}       warnings
 * @property {string}         [error]    Error code when `ok: false`
 * @property {boolean}        dryRun
 */

/**
 * Default candidate directories Spec Kit artifacts may live under, relative
 * to a project root. First match wins.
 */
const DEFAULT_SCAN_DIRS = [
  "specs",
  "memory",
  ".speckit",
  ".",
];

/**
 * Import a Spec Kit artifact set into a Crucible smelt + Phase Plan.
 *
 * @param {Object}  opts
 * @param {string}  opts.projectRoot      Absolute path to the Plan Forge project
 * @param {string}  [opts.dir]            Override directory to scan (relative or absolute)
 * @param {boolean} [opts.dryRun=false]   Validate + map without writing files
 * @param {boolean} [opts.syncPrinciples=false]  Also write PROJECT-PRINCIPLES.md from constitution.md
 * @param {string}  [opts.name]           Override the slugified plan name
 * @returns {ImportResult}
 */
function _validateSpeckitArtifacts({ spec, plan, tasks, constitution, result }) {
  if (!spec || !plan) {
    if (!spec)
      result.missingFields.push({ file: "spec.md", field: "<file>", severity: "error" });
    if (!plan)
      result.missingFields.push({ file: "plan.md", field: "<file>", severity: "error" });
    result.error = ERROR_CODES.SPECKIT_IMPORT_MISSING_REQUIRED.code;
    result.warnings.push(
      "Both spec.md and plan.md are required. Re-run after creating them."
    );
    return false;
  }
  if (!spec.title) {
    result.missingFields.push({ file: "spec.md", field: "title", severity: "error" });
    result.error = ERROR_CODES.SPECKIT_IMPORT_MISSING_FIELD.code;
    result.warnings.push(
      "spec.md is missing a top-level `# Title` heading; import blocked."
    );
    return false;
  }
  if (!plan.scope) {
    result.missingFields.push({ file: "plan.md", field: "scope", severity: "error" });
    result.error = ERROR_CODES.SPECKIT_IMPORT_MISSING_FIELD.code;
    result.warnings.push(
      "plan.md is missing a `## Scope` section; import blocked."
    );
    return false;
  }
  if (!tasks)
    result.missingFields.push({ file: "tasks.md", field: "<file>", severity: "warn" });
  if (!constitution)
    result.missingFields.push({ file: "constitution.md", field: "<file>", severity: "warn" });
  return true;
}

function _checkSyncPrinciplesGuard({ syncPrinciples, constitution, principlesPath, result }) {
  if (!syncPrinciples) return true;
  if (!constitution) {
    result.error = ERROR_CODES.PROJECT_PRINCIPLES_NO_SOURCE.code;
    result.warnings.push(
      "--sync-principles requested but constitution.md is absent."
    );
    return false;
  }
  if (existsSync(principlesPath)) {
    result.error = ERROR_CODES.PROJECT_PRINCIPLES_EXISTS.code;
    result.warnings.push(
      `${principlesPath} already exists; refusing to overwrite. Remove it first or omit --sync-principles.`
    );
    return false;
  }
  return true;
}

function _writeSpeckitOutputs(ctx) {
  const {
    smeltDir, planFilePath, smeltPath, smelt, projectRoot, phaseName, planMarkdown,
    syncPrinciples, constitution, principlesPath, auditPath, crucibleId, mapped, result,
  } = ctx;
  mkdirSync(smeltDir, { recursive: true });
  mkdirSync(dirname(planFilePath), { recursive: true });
  writeFileSync(smeltPath, JSON.stringify(smelt, null, 2));

  let finalPlanPath = planFilePath;
  let n = 2;
  while (existsSync(finalPlanPath)) {
    finalPlanPath = join(projectRoot, "docs", "plans", `${phaseName}-${n}-PLAN.md`);
    n++;
  }
  writeFileSync(finalPlanPath, planMarkdown);
  result.planPath = finalPlanPath;

  if (syncPrinciples && constitution) {
    writeFileSync(principlesPath, renderPrinciples(constitution));
  }

  appendFileSync(
    auditPath,
    JSON.stringify({
      timestamp: new Date().toISOString(),
      planPath: finalPlanPath,
      source: "speckit",
      reason: "auto-import via pforge crucible import",
      crucibleId,
      mappedFieldCount: mapped.length,
      missingFieldCount: result.missingFields.length,
    }) + "\n"
  );
}

function createImportResult(dryRun) {
  return {
    ok: false,
    smeltId: null,
    planPath: null,
    smeltPath: null,
    mappedFields: [],
    missingFields: [],
    warnings: [],
    dryRun,
  };
}

function parseSpeckitArtifacts({ specPath, planPath, tasksPath, constitutionPath }) {
  return {
    spec: specPath ? parseSpec(readFileSync(specPath, "utf-8")) : null,
    plan: planPath ? parsePlan(readFileSync(planPath, "utf-8")) : null,
    tasks: tasksPath ? parseTasks(readFileSync(tasksPath, "utf-8")) : null,
    constitution: constitutionPath
      ? parseConstitution(readFileSync(constitutionPath, "utf-8"))
      : null,
  };
}

function buildSpeckitMappedFields({ spec, plan, slicesMerged, constitution }) {
  const mapped = [
    { source: "spec.md#title", target: "plan-title", value: spec.title },
    { source: "spec.md#goals", target: "objectives[]", value: spec.goals },
    { source: "plan.md#scope", target: "scope", value: plan.scope },
    { source: "plan.md#slices", target: "slices[]", value: slicesMerged },
    {
      source: "plan.md#forbidden-actions",
      target: "forbidden-actions",
      value: plan.forbiddenActions,
    },
  ];
  if (constitution) {
    mapped.push({
      source: "constitution.md#rules",
      target: "agent-constraints",
      value: constitution.rules,
    });
  }
  return mapped;
}

function prepareSpeckitImportArtifacts({ opts, projectRoot, result, scanResult, parsed }) {
  const smeltId = randomUUID();
  const crucibleId = `imported-speckit-${smeltId}`;
  const slices = mergeSlicesWithTasks(parsed.plan.slices || [], parsed.tasks ? parsed.tasks.rows : []);
  for (const warning of slices.warnings) result.warnings.push(warning);

  const mapped = buildSpeckitMappedFields({
    spec: parsed.spec,
    plan: parsed.plan,
    slicesMerged: slices.merged,
    constitution: parsed.constitution,
  });
  result.mappedFields = mapped;

  const slug = opts.name || slugify(parsed.spec.title) || `speckit-import-${smeltId.slice(0, 8)}`;
  const phaseName = `Phase-${slug.toUpperCase()}`;
  const smeltDir = join(projectRoot, ".forge", "crucible");
  const smeltPath = join(smeltDir, `${smeltId}.json`);
  const planFilePath = join(projectRoot, "docs", "plans", `${phaseName}-PLAN.md`);
  const auditPath = join(smeltDir, "manual-imports.jsonl");
  const principlesPath = join(projectRoot, "docs", "plans", "PROJECT-PRINCIPLES.md");

  const smelt = {
    id: smeltId,
    crucibleId,
    source: "speckit",
    sourceDir: scanResult.sourceDir,
    status: "imported",
    createdAt: new Date().toISOString(),
    "plan-title": parsed.spec.title,
    objectives: parsed.spec.goals,
    scope: parsed.plan.scope,
    slices: slices.merged,
    "forbidden-actions": parsed.plan.forbiddenActions,
    "agent-constraints": parsed.constitution ? parsed.constitution.rules : [],
    "agent-commitments": parsed.constitution ? parsed.constitution.commitments : [],
    "agent-boundaries": parsed.constitution ? parsed.constitution.boundaries : [],
    sourceFiles: {
      spec: scanResult.specPath,
      plan: scanResult.planPath,
      tasks: scanResult.tasksPath,
      constitution: scanResult.constitutionPath,
    },
  };

  const planMarkdown = renderPhasePlan({
    crucibleId,
    phaseName,
    spec: parsed.spec,
    plan: parsed.plan,
    slicesMerged: slices.merged,
    constitution: parsed.constitution,
  });

  result.smeltId = smeltId;
  result.smeltPath = smeltPath;
  result.planPath = planFilePath;

  return {
    smelt,
    smeltDir,
    smeltId,
    smeltPath,
    planFilePath,
    auditPath,
    principlesPath,
    mapped,
    planMarkdown,
    phaseName,
    crucibleId,
  };
}

export function importSpeckit(opts) {
  const projectRoot = resolve(opts.projectRoot || process.cwd());
  const dryRun = !!opts.dryRun;
  const syncPrinciples = !!opts.syncPrinciples;
  const result = createImportResult(dryRun);

  const scanResult = locateArtifacts(projectRoot, opts.dir);
  if (!scanResult.ok) {
    result.error = scanResult.error;
    result.warnings.push(scanResult.message);
    return result;
  }

  const parsed = parseSpeckitArtifacts(scanResult);
  if (!_validateSpeckitArtifacts({ ...parsed, result })) {
    return result;
  }

  const artifacts = prepareSpeckitImportArtifacts({
    opts,
    projectRoot,
    result,
    scanResult,
    parsed,
  });

  if (!_checkSyncPrinciplesGuard({
    syncPrinciples,
    constitution: parsed.constitution,
    principlesPath: artifacts.principlesPath,
    result,
  })) {
    return result;
  }

  if (dryRun) {
    result.ok = true;
    return result;
  }

  _writeSpeckitOutputs({
    smeltDir: artifacts.smeltDir,
    planFilePath: artifacts.planFilePath,
    smeltPath: artifacts.smeltPath,
    smelt: artifacts.smelt,
    projectRoot,
    phaseName: artifacts.phaseName,
    planMarkdown: artifacts.planMarkdown,
    syncPrinciples,
    constitution: parsed.constitution,
    principlesPath: artifacts.principlesPath,
    auditPath: artifacts.auditPath,
    crucibleId: artifacts.crucibleId,
    mapped: artifacts.mapped,
    result,
  });

  result.ok = true;
  return result;
}

// ─── Locator ────────────────────────────────────────────────────────────────

function locateArtifacts(projectRoot, overrideDir) {
  const candidates = [];
  if (overrideDir) {
    const abs = resolve(projectRoot, overrideDir);
    if (!existsSync(abs)) {
      return {
        ok: false,
        error: ERROR_CODES.SPECKIT_IMPORT_DIR_NOT_FOUND.code,
        message: `Directory not found: ${abs}`,
      };
    }
    candidates.push(abs);
  } else {
    for (const d of DEFAULT_SCAN_DIRS) {
      const abs = resolve(projectRoot, d);
      if (!existsSync(abs)) continue;
      candidates.push(abs);
      // For specs/, also descend one level (Spec Kit puts feature dirs there)
      if (d === "specs") {
        try {
          for (const child of readdirSync(abs)) {
            const childAbs = join(abs, child);
            if (statSync(childAbs).isDirectory()) candidates.push(childAbs);
          }
        } catch { /* ignore */ }
      }
    }
  }

  // Pick the first candidate that has at least spec.md OR plan.md
  for (const c of candidates) {
    const specPath = pickFirst(c, ["spec.md", "SPEC.md"]);
    const planPath = pickFirst(c, ["plan.md", "PLAN.md"]);
    if (specPath || planPath) {
      // constitution.md often lives one level up (under memory/ in Spec Kit's default layout)
      let constitutionPath = pickFirst(c, ["constitution.md"]);
      if (!constitutionPath) {
        constitutionPath = pickFirst(join(projectRoot, "memory"), ["constitution.md"]);
      }
      return {
        ok: true,
        sourceDir: c,
        specPath,
        planPath,
        tasksPath: pickFirst(c, ["tasks.md", "TASKS.md"]),
        constitutionPath,
      };
    }
  }

  return {
    ok: false,
    error: ERROR_CODES.SPECKIT_IMPORT_NOT_FOUND.code,
    message:
      "No Spec Kit artifacts found. Tried: " +
      DEFAULT_SCAN_DIRS.map((d) => `${d}/`).join(", ") +
      ". Pass --dir <path> to point at a specific feature directory.",
  };
}

function pickFirst(dir, names) {
  for (const n of names) {
    const p = join(dir, n);
    if (existsSync(p)) return p;
  }
  return null;
}

// ─── Parsers ────────────────────────────────────────────────────────────────

/**
 * Parse spec.md. Recognises:
 *   - First `# heading`            → title (strips "Feature Specification: " prefix if present)
 *   - `## Goals` bullet list       → goals[] (alias: `## Requirements`)
 *   - `## Acceptance Criteria` list → acceptance[] (alias: `## Success Criteria`)
 *   - `## Out of Scope` list       → outOfScope[] (alias: `## Assumptions`)
 *   - `## User Scenarios` list     (informational)
 *
 * Aliases support both the hand-crafted Plan Forge convention and the actual
 * heading names emitted by the real github/spec-kit CLI templates.
 */
export function parseSpec(content) {
  const title = extractFirstH1(content);
  const goals = extractBulletsWithAliases(content, ["Goals", "Requirements"]);
  const acceptance = extractBulletsWithAliases(content, ["Acceptance Criteria", "Success Criteria"]);
  const outOfScope = extractBulletsWithAliases(content, ["Out of Scope", "Assumptions"]);
  return { title, goals, acceptance, outOfScope };
}

/**
 * Parse plan.md. Recognises:
 *   - `## Scope`              → scope (raw paragraph text; alias: `## Summary`)
 *   - `## Slices` numbered list → slices[]
 *   - `## Forbidden Actions` list → forbiddenActions[]
 *
 * The `## Summary` alias supports the heading name used by the real
 * github/spec-kit `plan-template.md`.
 */
export function parsePlan(content) {
  const scope = extractParagraphUnderHeading(content, "Scope") ??
                extractParagraphUnderHeading(content, "Summary");
  const sliceLines = extractBulletsUnderHeading(content, "Slices");
  const slices = sliceLines.map((line, i) => {
    // Handle "**Title** — body" pattern
    const m = line.match(/^\*\*(.+?)\*\*\s*[—–-]\s*(.*)$/);
    return {
      id: i + 1,
      title: m ? m[1].trim() : line.split(/[—–-]/)[0].trim(),
      description: m ? m[2].trim() : line,
    };
  });
  const forbiddenActions = extractBulletsUnderHeading(content, "Forbidden Actions");
  return { scope, slices, forbiddenActions };
}

/**
 * Parse tasks.md. Recognises a markdown table with columns:
 *   Task ID | Slice | Description | Status
 *
 * Returns `{ rows: [{ taskId, slice, description, status }] }`.
 * Unknown status values are normalised to `pending` with a warning attached.
 */
export function parseTasks(content) {
  const lines = content.split(/\r?\n/);
  const rows = [];
  let inTable = false;
  let headerSeen = false;
  for (const line of lines) {
    if (line.trim().startsWith("|")) {
      const cells = line.split("|").map((c) => c.trim()).filter((_, i, a) => i > 0 && i < a.length - 1);
      if (!headerSeen) {
        headerSeen = true;
        inTable = true;
        continue;
      }
      // Skip the separator row (---|---|---)
      if (cells.every((c) => /^:?-+:?$/.test(c))) continue;
      if (cells.length >= 4) {
        rows.push({
          taskId: cells[0],
          slice: cells[1],
          description: cells[2],
          status: normaliseTaskStatus(cells[3]),
        });
      }
    } else if (inTable && line.trim() === "") {
      // table ended
      inTable = false;
    }
  }
  return { rows };
}

function normaliseTaskStatus(raw) {
  const r = raw.toLowerCase().trim();
  if (r === "done" || r === "complete" || r === "completed") return "done";
  if (r === "in-progress" || r === "in progress" || r === "wip") return "in_progress";
  return "pending";
}

/**
 * Parse constitution.md. Recognises three optional sections:
 *   ## Rules        → rules[] (alias: `## Core Principles`)
 *   ## Commitments  → commitments[]
 *   ## Boundaries   → boundaries[]
 *
 * The `## Core Principles` alias supports the heading name used by the real
 * github/spec-kit `constitution-template.md`.
 */
export function parseConstitution(content) {
  return {
    rules: extractBulletsWithAliases(content, ["Rules", "Core Principles"]),
    commitments: extractBulletsUnderHeading(content, "Commitments"),
    boundaries: extractBulletsUnderHeading(content, "Boundaries"),
  };
}

// ─── Markdown helpers (no external deps, deterministic) ─────────────────────

function extractFirstH1(content) {
  const lines = content.split(/\r?\n/);
  for (const line of lines) {
    const m = line.match(/^#\s+(.+?)\s*$/);
    if (m) {
      // Strip the "Feature Specification: " prefix emitted by the real spec-kit CLI
      return m[1].trim().replace(/^Feature Specification:\s+/i, "");
    }
  }
  return null;
}

/**
 * Try each alias heading in order; return the first non-empty bullet list found.
 * Falls back to [] when none of the aliases match.
 */
function extractBulletsWithAliases(content, aliases) {
  for (const alias of aliases) {
    const items = extractBulletsUnderHeading(content, alias);
    if (items.length > 0) return items;
  }
  return [];
}

/**
 * Extract bullet items under a `## Heading` until the next heading or EOF.
 * Recognises `-`, `*`, and `1.` style bullets. Strips checkbox prefixes.
 */
function extractBulletsUnderHeading(content, heading) {
  const lines = content.split(/\r?\n/);
  const headingRe = new RegExp(`^##+\\s+${escapeRe(heading)}\\s*$`, "i");
  const nextHeadingRe = /^##+\s+/;
  const bulletRe = /^\s*(?:[-*]|\d+\.)\s+(.+?)\s*$/;
  const items = [];
  let inSection = false;
  for (const line of lines) {
    if (headingRe.test(line)) {
      inSection = true;
      continue;
    }
    if (inSection && nextHeadingRe.test(line)) break;
    if (inSection) {
      const m = line.match(bulletRe);
      if (m) {
        let item = m[1].trim();
        // Strip leading `[ ]` / `[x]` checkbox markers
        item = item.replace(/^\[\s*[xX ]?\s*\]\s+/, "");
        items.push(item);
      }
    }
  }
  return items;
}

/**
 * Extract the prose paragraph(s) directly under a `## Heading` until the
 * next heading. Bullet lines are excluded — use `extractBulletsUnderHeading`
 * for those.
 */
function extractParagraphUnderHeading(content, heading) {
  const lines = content.split(/\r?\n/);
  const headingRe = new RegExp(`^##+\\s+${escapeRe(heading)}\\s*$`, "i");
  const nextHeadingRe = /^##+\s+/;
  const collected = [];
  let inSection = false;
  for (const line of lines) {
    if (headingRe.test(line)) {
      inSection = true;
      continue;
    }
    if (inSection && nextHeadingRe.test(line)) break;
    if (inSection) collected.push(line);
  }
  return collected.join("\n").trim() || null;
}

function escapeRe(s) {
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function slugify(s) {
  if (!s) return null;
  return s
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 60);
}

// ─── Slice-task merge ───────────────────────────────────────────────────────

function mergeSlicesWithTasks(slices, taskRows) {
  const warnings = [];
  if (!slices.length) {
    if (taskRows.length) {
      warnings.push(
        "tasks.md has rows but plan.md has no Slices section; tasks dropped."
      );
    }
    return { merged: [], warnings };
  }
  const merged = slices.map((s) => ({ ...s, tasks: [] }));
  for (const row of taskRows) {
    // Slice cell can be "1", "Slice 1", or the slice title
    const idx = matchSliceIndex(row.slice, merged);
    if (idx < 0) {
      warnings.push(
        `tasks.md row ${row.taskId} references unknown slice "${row.slice}"; task skipped.`
      );
      continue;
    }
    merged[idx].tasks.push({
      taskId: row.taskId,
      description: row.description,
      status: row.status,
    });
  }
  return { merged, warnings };
}

function matchSliceIndex(sliceCell, slices) {
  const raw = String(sliceCell).trim();
  // Numeric match
  const numMatch = raw.match(/(\d+)/);
  if (numMatch) {
    const n = parseInt(numMatch[1], 10);
    if (n >= 1 && n <= slices.length) return n - 1;
  }
  // Title match (case-insensitive substring)
  const lower = raw.toLowerCase();
  for (let i = 0; i < slices.length; i++) {
    if (slices[i].title.toLowerCase().includes(lower)) return i;
  }
  return -1;
}

// ─── Renderers ──────────────────────────────────────────────────────────────

function _renderBulletList(lines, items) {
  for (const item of items) lines.push(`- ${item}`);
}

function _renderSpecSections(lines, spec) {
  if (spec.goals && spec.goals.length) {
    lines.push("## Goals");
    lines.push("");
    _renderBulletList(lines, spec.goals);
    lines.push("");
  }
  if (spec.acceptance && spec.acceptance.length) {
    lines.push("## Acceptance Criteria");
    lines.push("");
    _renderBulletList(lines, spec.acceptance);
    lines.push("");
  }
  if (spec.outOfScope && spec.outOfScope.length) {
    lines.push("## Out of Scope");
    lines.push("");
    _renderBulletList(lines, spec.outOfScope);
    lines.push("");
  }
}

function _renderSliceBlock(lines, s) {
  lines.push(`### Slice ${s.id} — ${s.title}`);
  if (s.description && s.description !== s.title) {
    lines.push("");
    lines.push(s.description);
  }
  if (s.tasks && s.tasks.length) {
    lines.push("");
    lines.push("**Tasks**:");
    lines.push("");
    for (const t of s.tasks) {
      const mark = t.status === "done" ? "[x]" : t.status === "in_progress" ? "[~]" : "[ ]";
      lines.push(`- ${mark} \`${t.taskId}\` ${t.description}`);
    }
  }
  lines.push("");
  lines.push("**Validation gate** (placeholder — Hardener must replace):");
  lines.push("");
  lines.push("```bash");
  lines.push(`bash -c "echo 'TODO: gate for slice ${s.id}'"`);
  lines.push("```");
  lines.push("");
}

function _renderSlicePlan(lines, slicesMerged) {
  lines.push("## Slice Plan");
  lines.push("");
  lines.push("> **Note for Hardener**: Each slice below was imported from a Spec Kit `plan.md` entry. Validation gates are placeholders — Step 2 must replace them with real gates that match Plan Forge gate-portability rules.");
  lines.push("");
  if (!slicesMerged.length) {
    lines.push("_(no slices in source plan.md — Hardener must define them)_");
    lines.push("");
    return;
  }
  for (const s of slicesMerged) _renderSliceBlock(lines, s);
}

function _renderConstitutionSection(lines, constitution) {
  if (!constitution) return;
  if (!(constitution.rules.length || constitution.commitments.length || constitution.boundaries.length)) return;
  lines.push("## Imported Agent Constraints (from constitution.md)");
  lines.push("");
  if (constitution.rules.length) {
    lines.push("### Rules");
    lines.push("");
    _renderBulletList(lines, constitution.rules);
    lines.push("");
  }
  if (constitution.commitments.length) {
    lines.push("### Commitments");
    lines.push("");
    _renderBulletList(lines, constitution.commitments);
    lines.push("");
  }
  if (constitution.boundaries.length) {
    lines.push("### Boundaries");
    lines.push("");
    _renderBulletList(lines, constitution.boundaries);
    lines.push("");
  }
  lines.push("> If you also have `docs/plans/PROJECT-PRINCIPLES.md`, the rules above are advisory and PROJECT-PRINCIPLES wins on conflict.");
  lines.push("");
}

function renderPhasePlan({ crucibleId, phaseName, spec, plan, slicesMerged, constitution }) {
  const lines = [];
  lines.push("---");
  lines.push(`crucibleId: ${crucibleId}`);
  lines.push("lane: full");
  lines.push("source: speckit");
  lines.push("---");
  lines.push("");
  lines.push(`# ${phaseName}: ${spec.title}`);
  lines.push("");
  lines.push("> **Source**: Imported from Spec Kit via `pforge crucible import --from=spec-kit`.");
  lines.push("> **Status**: Drafted (Step 0 equivalent), awaiting Pre-flight (Step 1) + Hardening (Step 2).");
  lines.push("");
  lines.push("## Specification Source");
  lines.push("");
  lines.push("- Imported from: Spec Kit");
  if (spec.title) lines.push(`- Spec title: ${spec.title}`);
  lines.push(`- Importer: pforge crucible import (Phase CRUCIBLE-IMPORT-CLI)`);
  lines.push("");

  _renderSpecSections(lines, spec);

  lines.push("## Scope Contract");
  lines.push("");
  lines.push(plan.scope || "_(scope not provided in source plan.md)_");
  lines.push("");

  if (plan.forbiddenActions && plan.forbiddenActions.length) {
    lines.push("### Forbidden Actions");
    lines.push("");
    for (const f of plan.forbiddenActions) lines.push(`- ❌ ${f}`);
    lines.push("");
  }

  _renderSlicePlan(lines, slicesMerged);
  _renderConstitutionSection(lines, constitution);

  return lines.join("\n");
}

function renderPrinciples(constitution) {
  const lines = [];
  lines.push("# Project Principles");
  lines.push("");
  lines.push("> Imported from Spec Kit `constitution.md` via `pforge crucible import --sync-principles`.");
  lines.push("");
  if (constitution.rules.length) {
    lines.push("## Rules (Non-Negotiable)");
    lines.push("");
    for (const r of constitution.rules) lines.push(`- ${r}`);
    lines.push("");
  }
  if (constitution.commitments.length) {
    lines.push("## Commitments");
    lines.push("");
    for (const c of constitution.commitments) lines.push(`- ${c}`);
    lines.push("");
  }
  if (constitution.boundaries.length) {
    lines.push("## Boundaries");
    lines.push("");
    for (const b of constitution.boundaries) lines.push(`- ${b}`);
    lines.push("");
  }
  return lines.join("\n");
}

// ─── Smelt browser (used by `pforge crucible status`) ───────────────────────

/**
 * List smelts under `.forge/crucible/`. Returns a thin summary array.
 *
 * @param {string} projectRoot
 * @returns {{ smelts: Array<{id:string, source:string, status:string, createdAt:string, planTitle?:string}> }}
 */
export function listSmelts(projectRoot) {
  const dir = join(resolve(projectRoot), ".forge", "crucible");
  if (!existsSync(dir)) return { smelts: [] };
  const out = [];
  for (const f of readdirSync(dir)) {
    if (!f.endsWith(".json") || f === "config.json" || f === "phase-claims.json") continue;
    try {
      const obj = JSON.parse(readFileSync(join(dir, f), "utf-8"));
      out.push({
        id: obj.id || basename(f, ".json"),
        source: obj.source || "unknown",
        status: obj.status || "unknown",
        createdAt: obj.createdAt || null,
        planTitle: obj["plan-title"] || obj.rawIdea || null,
      });
    } catch {
      // Skip malformed
    }
  }
  out.sort((a, b) => String(b.createdAt).localeCompare(String(a.createdAt)));
  return { smelts: out };
}

/**
 * Return the full smelt JSON for a given id, or `null` if not found.
 *
 * @param {string} projectRoot
 * @param {string} smeltId
 */
export function getSmelt(projectRoot, smeltId) {
  const dir = join(resolve(projectRoot), ".forge", "crucible");
  const path = join(dir, `${smeltId}.json`);
  if (!existsSync(path)) return null;
  try {
    return JSON.parse(readFileSync(path, "utf-8"));
  } catch {
    return null;
  }
}

// ─── CLI entrypoint ─────────────────────────────────────────────────────────

/**
 * CLI entrypoint. Invoked by pforge.ps1 / pforge.sh as:
 *   node pforge-mcp/crucible-import.mjs <subcommand> [options]
 *
 * Subcommands:
 *   import   --from=spec-kit [--dir <path>] [--dry-run] [--sync-principles] [--name <slug>] [--json] [--project <root>]
 *   status   [<smeltId>] [--json] [--project <root>]
 *
 * Exit codes:
 *   0   success
 *   1   import returned ok:false, smelt not found, or unexpected error
 *   2   invalid arguments
 */
function main(argv) {
  const sub = argv[0];
  const rest = argv.slice(1);

  if (!sub || sub === "--help" || sub === "-h" || sub === "help") {
    printHelp();
    return 0;
  }

  if (sub === "import") return cliImport(rest);
  if (sub === "status") return cliStatus(rest);

  process.stderr.write(`pforge crucible: unknown subcommand '${sub}'\n`);
  printHelp(process.stderr);
  return 2;
}

function cliImport(argv) {
  const args = parseImportArgs(argv);
  if (args.error) {
    process.stderr.write(`pforge crucible import: ${args.error}\n`);
    return 2;
  }
  if (args.from !== "spec-kit") {
    process.stderr.write(
      `pforge crucible import: --from=${args.from} not supported. Currently supported: spec-kit.\n`
    );
    return 2;
  }
  const result = importSpeckit({
    projectRoot: args.project,
    dir: args.dir,
    dryRun: args.dryRun,
    syncPrinciples: args.syncPrinciples,
    name: args.name,
  });
  if (args.json) {
    process.stdout.write(JSON.stringify(result, null, 2) + "\n");
  } else {
    renderImportHuman(result);
  }
  return result.ok ? 0 : 1;
}

function cliStatus(argv) {
  const args = parseStatusArgs(argv);
  if (args.error) {
    process.stderr.write(`pforge crucible status: ${args.error}\n`);
    return 2;
  }
  if (args.smeltId) {
    const smelt = getSmelt(args.project, args.smeltId);
    if (!smelt) {
      if (args.json) process.stdout.write(JSON.stringify({ ok: false, error: ERROR_CODES.SMELT_NOT_FOUND.code, smeltId: args.smeltId }) + "\n");
      else process.stderr.write(`pforge crucible status: smelt not found: ${args.smeltId}\n`);
      return 1;
    }
    if (args.json) process.stdout.write(JSON.stringify(smelt, null, 2) + "\n");
    else renderSmeltDetail(smelt);
    return 0;
  }
  const list = listSmelts(args.project);
  if (args.json) process.stdout.write(JSON.stringify(list, null, 2) + "\n");
  else renderSmeltList(list);
  return 0;
}

function parseImportArgs(argv) {
  const out = {
    project: process.cwd(),
    from: null,
    dir: null,
    dryRun: false,
    syncPrinciples: false,
    name: null,
    json: false,
    error: null,
  };
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a === "--from") out.from = argv[++i];
    else if (a.startsWith("--from=")) out.from = a.slice("--from=".length);
    else if (a === "--dir") out.dir = argv[++i];
    else if (a.startsWith("--dir=")) out.dir = a.slice("--dir=".length);
    else if (a === "--name") out.name = argv[++i];
    else if (a.startsWith("--name=")) out.name = a.slice("--name=".length);
    else if (a === "--project") out.project = argv[++i];
    else if (a.startsWith("--project=")) out.project = a.slice("--project=".length);
    else if (a === "--dry-run") out.dryRun = true;
    else if (a === "--sync-principles") out.syncPrinciples = true;
    else if (a === "--json") out.json = true;
    else if (a === "--help" || a === "-h") { out.error = "see `pforge crucible --help`"; return out; }
    else { out.error = `unknown argument: ${a}`; return out; }
  }
  if (!out.from) { out.error = "missing required --from=<source> (e.g. --from=spec-kit)"; }
  return out;
}

function parseStatusArgs(argv) {
  const out = { project: process.cwd(), smeltId: null, json: false, error: null };
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a === "--project") out.project = argv[++i];
    else if (a.startsWith("--project=")) out.project = a.slice("--project=".length);
    else if (a === "--json") out.json = true;
    else if (a === "--help" || a === "-h") { out.error = "see `pforge crucible --help`"; return out; }
    else if (a.startsWith("--")) { out.error = `unknown argument: ${a}`; return out; }
    else if (!out.smeltId) out.smeltId = a;
    else { out.error = `unexpected argument: ${a}`; return out; }
  }
  return out;
}

function renderImportHuman(r) {
  const out = [];
  out.push("");
  out.push("Spec Kit → Crucible import");
  out.push("─".repeat(72));
  if (!r.ok) {
    out.push(`  ✗ FAILED — ${r.error || "unknown error"}`);
    for (const w of r.warnings) out.push(`    • ${w}`);
    if (r.missingFields.length) {
      out.push("");
      out.push("  Missing fields:");
      for (const m of r.missingFields) {
        const sev = m.severity === "error" ? "✗" : "⚠";
        out.push(`    ${sev} ${m.file} :: ${m.field}`);
      }
    }
  } else if (r.dryRun) {
    out.push("  ✓ DRY RUN — would write the following:");
    out.push(`    smelt:   ${r.smeltPath}`);
    out.push(`    plan:    ${r.planPath}`);
    out.push(`    audit:   .forge/crucible/manual-imports.jsonl (append)`);
    out.push("");
    out.push(`  Mapped fields: ${r.mappedFields.length}`);
    for (const m of r.mappedFields) {
      const v = Array.isArray(m.value) ? `[${m.value.length} items]` : truncate(String(m.value), 60);
      out.push(`    • ${m.source.padEnd(36)} → ${m.target.padEnd(20)} ${v}`);
    }
    if (r.missingFields.length) {
      out.push("");
      out.push("  Warnings:");
      for (const m of r.missingFields) out.push(`    ⚠ ${m.file} :: ${m.field} (${m.severity})`);
    }
  } else {
    out.push(`  ✓ Imported smelt ${r.smeltId}`);
    out.push(`    smelt:   ${r.smeltPath}`);
    out.push(`    plan:    ${r.planPath}`);
    out.push(`    fields:  ${r.mappedFields.length} mapped`);
    if (r.warnings.length) {
      out.push("");
      out.push("  Warnings:");
      for (const w of r.warnings) out.push(`    • ${w}`);
    }
    out.push("");
    out.push(`  Next: pforge run-plan "${r.planPath}"`);
  }
  out.push("");
  process.stdout.write(out.join("\n") + "\n");
}

function renderSmeltList(list) {
  const out = [];
  out.push("");
  out.push(`Crucible smelts (${list.smelts.length})`);
  out.push("─".repeat(72));
  if (!list.smelts.length) {
    out.push("  (none)");
    out.push("");
    out.push("  Hint: `pforge crucible import --from=spec-kit` to import Spec Kit artifacts.");
  } else {
    out.push(`  ${"ID".padEnd(36)}  ${"SOURCE".padEnd(10)}  ${"STATUS".padEnd(12)}  CREATED`);
    for (const s of list.smelts) {
      out.push(
        `  ${s.id.padEnd(36)}  ${String(s.source).padEnd(10)}  ${String(s.status).padEnd(12)}  ${s.createdAt || ""}`
      );
    }
  }
  out.push("");
  process.stdout.write(out.join("\n") + "\n");
}

function renderSmeltDetail(smelt) {
  const out = [];
  out.push("");
  out.push(`Smelt ${smelt.id}`);
  out.push("─".repeat(72));
  out.push(`  source:    ${smelt.source || "unknown"}`);
  out.push(`  status:    ${smelt.status || "unknown"}`);
  out.push(`  created:   ${smelt.createdAt || ""}`);
  if (smelt["plan-title"]) out.push(`  title:     ${smelt["plan-title"]}`);
  if (Array.isArray(smelt.objectives) && smelt.objectives.length) {
    out.push(`  objectives (${smelt.objectives.length}):`);
    for (const o of smelt.objectives) out.push(`    • ${o}`);
  }
  if (Array.isArray(smelt.slices) && smelt.slices.length) {
    out.push(`  slices (${smelt.slices.length}):`);
    for (const s of smelt.slices) out.push(`    ${s.id}. ${s.title}`);
  }
  out.push("");
  process.stdout.write(out.join("\n") + "\n");
}

function truncate(s, n) {
  if (s.length <= n) return s;
  return s.slice(0, n - 1) + "…";
}

function printHelp(stream = process.stdout) {
  stream.write(
`Usage: node crucible-import.mjs <subcommand> [options]

Subcommands:
  import --from=spec-kit [options]   Import Spec Kit artifacts into a Crucible smelt
  status [<smeltId>] [options]       List smelts, or show one in detail

Import options:
  --from=<source>      Required. Currently supported: spec-kit
  --dir <path>         Override scan directory (default: scan specs/, memory/, .speckit/, .)
  --dry-run            Validate and map without writing files
  --sync-principles    Also write docs/plans/PROJECT-PRINCIPLES.md from constitution.md
  --name <slug>        Override the slugified plan name
  --project <dir>      Project root (default: cwd)
  --json               Emit structured JSON to stdout

Status options:
  <smeltId>            Optional smelt id to show in detail
  --project <dir>      Project root (default: cwd)
  --json               Emit structured JSON to stdout

Exit codes:
  0   success
  1   import returned ok:false, smelt not found, or unexpected error
  2   invalid arguments
`
  );
}

// Run CLI when invoked directly (not when imported).
const entryPath = typeof process.argv[1] === "string" ? process.argv[1] : "";
const invokedDirectly =
  entryPath.length > 0 &&
  (import.meta.url === `file://${entryPath.replace(/\\/g, "/")}` ||
    import.meta.url.endsWith(entryPath.replace(/\\/g, "/")));
if (invokedDirectly) {
  process.exit(main(process.argv.slice(2)));
}

/**
 * Plan Forge — Crucible Interview Engine (Slice 01.3).
 *
 * Lane-scoped question banks plus a strict recommended-default resolver
 * that refuses to fabricate answers when memory yields nothing.
 *
 * Sources consulted (in order) for recommended defaults:
 *   1. `docs/plans/PROJECT-PRINCIPLES.md` — project-specific commitments
 *   2. `docs/plans/Phase-*.md`             — conventions from prior phases
 *   3. `null`                              — explicit "no default" sentinel
 *
 * Design Commitment #3 of Phase-CRUCIBLE-01:
 *   "No defaults = no question (leave blank, don't fabricate)."
 *
 * Callers MUST treat `recommendedDefault === null` as "unknown — ask the
 * human" and MUST NOT substitute boilerplate.
 */

import { existsSync, readFileSync, readdirSync, statSync } from "node:fs";
import { resolve, join } from "node:path";

// ─── Question banks ──────────────────────────────────────────────────
// Shape of each question:
//   { id, prompt, required, defaultSource? }
// defaultSource is a hint for buildRecommendedDefault — the resolver
// maps source keys to lookup strategies.

export const TWEAK_QUESTIONS = Object.freeze([
  Object.freeze({
    id: "scope-file",
    prompt: "Which file(s) will this change touch? List paths.",
    required: true,
    defaultSource: null,
  }),
  Object.freeze({
    id: "validation",
    prompt: "How will we verify the fix works? Give the exact build/test command.",
    required: true,
    defaultSource: "validation-gate",
  }),
  // Issue #135 — same blocker as feature lane: `forbidden-actions` is in
  // CRITICAL_FIELDS so even tweak smelts must answer this to finalize.
  Object.freeze({
    id: "forbidden-actions",
    prompt: "What MUST this tweak not do? (e.g., 'no schema changes', 'no edits outside scope-file')",
    required: true,
    defaultSource: null,
  }),
  Object.freeze({
    id: "rollback",
    prompt: "How do we roll back if this breaks something?",
    required: true,
    defaultSource: null,
  }),
]);

export const FEATURE_QUESTIONS = Object.freeze([
  Object.freeze({
    id: "goal",
    prompt: "What user-visible outcome does this feature produce?",
    required: true,
    defaultSource: null,
  }),
  Object.freeze({
    id: "scope-files",
    prompt: "Which files/modules are in scope?",
    required: true,
    defaultSource: null,
  }),
  Object.freeze({
    id: "out-of-scope",
    prompt: "What is explicitly out of scope for this phase?",
    required: true,
    defaultSource: null,
  }),
  Object.freeze({
    id: "tests",
    prompt: "What tests prove the feature works? Name the test files or suites.",
    required: true,
    defaultSource: "test-framework",
  }),
  Object.freeze({
    id: "validation-gates",
    prompt: "Which build/test commands gate completion of each slice?",
    required: true,
    defaultSource: "validation-gate",
  }),
  // Issue #135 — `forbidden-actions` is in CRITICAL_FIELDS (crucible-server.mjs)
  // so finalize refuses any feature smelt that lacks it. Without this question
  // the interview completes but finalize is unrunnable without manual JSON edit.
  Object.freeze({
    id: "forbidden-actions",
    prompt: "What MUST this slice not do? (e.g., 'no destructive migrations', 'no API contract changes', 'no edits outside scope-files')",
    required: true,
    defaultSource: null,
  }),
  Object.freeze({
    id: "rollback",
    prompt: "How do we roll this feature back cleanly if issues surface post-ship?",
