/**
 * Return the frozen question bank for a given lane.
 * @param {"tweak"|"feature"|"full"} lane
 * @returns {ReadonlyArray<{id:string,prompt:string,required:boolean,defaultSource:string|null}>}
 */
export function getQuestionBank(lane) {
  if (lane === "tweak") return TWEAK_QUESTIONS;
  if (lane === "full") return FULL_QUESTIONS;
  return FEATURE_QUESTIONS; // default + explicit "feature"
}

/**
 * Total number of questions for a lane (used by the hub updated event).
 * @param {string} lane
 * @returns {number}
 */
export function totalQuestions(lane) {
  return getQuestionBank(lane).length;
}

// ─── Next question ───────────────────────────────────────────────────

/**
 * Return the next unanswered question for a smelt, or null if the
 * interview is complete.
 *
 * Pure on the smelt; reads the filesystem only to resolve recommended
 * defaults (via buildRecommendedDefault).
 *
 * @param {{lane:string, answers:Array<{questionId:string}>}} smelt
 * @param {{projectDir?: string}} [context]
 * @returns {{id:string,prompt:string,required:boolean,recommendedDefault:string|null,questionIndex:number,totalQuestions:number}|null}
 */
export function getNextQuestion(smelt, context = {}) {
  if (!smelt || smelt.status && smelt.status !== "in-progress") return null;
  const bank = getQuestionBank(smelt.lane);
  const answered = new Set((smelt.answers || []).map((a) => a.questionId));
  const idx = bank.findIndex((q) => !answered.has(q.id));
  if (idx === -1) return null;
  const q = bank[idx];
  const recommendedDefault = buildRecommendedDefault(q.id, {
    ...context,
    defaultSource: q.defaultSource,
  });
  return {
    id: q.id,
    prompt: q.prompt,
    required: q.required,
    recommendedDefault, // null = ask human, do NOT fabricate
    questionIndex: idx + 1,
    totalQuestions: bank.length,
  };
}

/**
 * Return a new smelt object with the answer appended. Does not persist.
 * Caller persists via crucible-store's updateSmelt.
 *
 * @param {{answers?:Array}} smelt
 * @param {string} questionId
 * @param {string} answer
 * @returns {object} patched smelt
 */
export function recordAnswer(smelt, questionId, answer) {
  if (!smelt) throw new Error("smelt required");
  if (typeof questionId !== "string" || !questionId) {
    throw new Error("questionId required");
  }
  if (typeof answer !== "string") {
    throw new Error("answer must be a string");
  }
  const entry = {
    questionId,
    answer,
    recordedAt: new Date().toISOString(),
  };
  return { ...smelt, answers: [...(smelt.answers || []), entry] };
}

// ─── Recommended default resolver ────────────────────────────────────

/**
 * Strict resolver — returns a string when a source yields a value,
 * otherwise null. NEVER fabricates.
 *
 * @param {string} questionId
 * @param {{projectDir?:string, defaultSource?:string|null}} context
 * @returns {string|null}
 */
export function buildRecommendedDefault(questionId, context = {}) {
  const { projectDir, defaultSource } = context;
  if (!projectDir || !defaultSource) return null;

  // 1) PROJECT-PRINCIPLES.md (primary source)
  const fromPrinciples = readFromPrinciples(projectDir, defaultSource);
  if (fromPrinciples) return fromPrinciples;

  // 2) Existing plan conventions (secondary)
  const fromPlans = readFromPlans(projectDir, defaultSource);
  if (fromPlans) return fromPlans;

  // 3) Nothing found — explicit null (no fabrication)
  return null;
}

function readFromPrinciples(projectDir, defaultSource) {
  const candidates = [
    resolve(projectDir, "docs", "plans", "PROJECT-PRINCIPLES.md"),
    resolve(projectDir, "PROJECT-PRINCIPLES.md"),
  ];
  for (const path of candidates) {
    if (!existsSync(path)) continue;
    let text;
    try { text = readFileSync(path, "utf-8"); } catch { continue; }
    const value = extractPrincipleValue(text, defaultSource);
    if (value) return value;
  }
  return null;
}

/**
 * Extract a value matching defaultSource from a PROJECT-PRINCIPLES.md body.
 * Conservative — only returns a value when the principles file is
 * unambiguous. Returns null for anything uncertain.
 */
function extractPrincipleValue(text, defaultSource) {
  if (defaultSource === "validation-gate") {
    // Look for a fenced code block preceded by a "validation" / "build" / "test" heading
    const m = text.match(/(?:^|\n)#{1,6}\s*(?:validation|build|test)[^\n]*\n+```[\w-]*\n([^\n`]+)\n```/i);
    if (m && m[1]) return m[1].trim();
  }
  if (defaultSource === "test-framework") {
    const m = text.match(/\btest(?:ing)?\s*(?:framework|runner)\s*[:=]\s*([A-Za-z0-9_+\-./ ]+)/i);
    if (m && m[1]) return m[1].trim();
  }
  if (defaultSource === "stack") {
    const m = text.match(/(?:^|\n)#{1,6}\s*(?:stack|technology)[^\n]*\n+([^\n#]+)/i);
    if (m && m[1]) {
      const v = m[1].trim();
      if (v.length > 0 && v.length <= 200) return v;
    }
  }
  if (defaultSource === "slice-count") {
    const m = text.match(/\bmax(?:imum)?\s*slices?\s*[:=]\s*(\d{1,2})\b/i);
    if (m && m[1]) return m[1];
  }
  return null;
}

function readFromPlans(projectDir, defaultSource) {
  const plansDir = resolve(projectDir, "docs", "plans");
  if (!existsSync(plansDir)) return null;
  let files;
  try { files = readdirSync(plansDir); } catch { return null; }
  // Most-recent first by mtime
  const phaseFiles = files
    .filter((f) => /^Phase-.+\.md$/.test(f))
    .map((f) => {
      const p = join(plansDir, f);
      let mtime = 0;
      try { mtime = statSync(p).mtimeMs; } catch { /* ignore */ }
      return { path: p, mtime };
    })
    .sort((a, b) => b.mtime - a.mtime)
    .slice(0, 5);

  for (const { path } of phaseFiles) {
    let text;
    try { text = readFileSync(path, "utf-8"); } catch { continue; }
    const value = extractPlanValue(text, defaultSource);
    if (value) return value;
  }
  return null;
}

function extractPlanValue(text, defaultSource) {
  if (defaultSource === "validation-gate") {
    // Pick the first **Validation Gate** / **Test command** code block content
    const m = text.match(/\*\*(?:Validation Gate|Test command|Build command)\*\*[^\n]*\n+```[\w-]*\n([^\n`]+)\n```/i);
    if (m && m[1]) return m[1].trim();
    // Fallback: inline backticks after "Test command:"
    const m2 = text.match(/\*\*Test command\*\*[^`\n]*`([^`\n]+)`/i);
    if (m2 && m2[1]) return m2[1].trim();
  }
  if (defaultSource === "slice-count") {
    // Count "### Slice N" headers in the recent plan
    const matches = text.match(/^###\s+Slice\s+\d/gim);
    if (matches && matches.length > 0) return String(matches.length);
  }
  return null;
}

/**
 * Plan Forge — Crucible Grandfather Migration (Slice 01.4).
 *
 * Legacy projects that existed before v2.37 have `docs/plans/Phase-*.md`
 * files without a `crucibleId:` frontmatter. Enforcement would break
 * them instantly. This module stamps each such plan with a stable
 * synthetic id so the enforcement gate lets them through while keeping
 * them clearly distinguishable from plans that were actually smelted.
 *
 * Stamp format: `crucibleId: grandfathered-<uuid>`
 * (NOT a real smelt id — tooling can tell the difference.)
 *
 * Design guarantees:
 *   - Idempotent: re-running never changes an already-stamped file
 *   - Scope-safe: only touches `docs/plans/Phase-*.md`
 *   - Body-safe: only inserts frontmatter; body bytes are preserved
 *   - Auditable: writes a `.forge/crucible/manual-imports.jsonl`
 *                entry per stamped file with source="grandfather"
 */

import {
  existsSync,
  readFileSync,
  readdirSync,
  writeFileSync,
} from "node:fs";
import { join, resolve } from "node:path";
import { randomUUID } from "node:crypto";

import {
  parseFrontmatter,
  upsertFrontmatter,
  logManualImport,
} from "./crucible-enforce.mjs";

const PHASE_FILE_RE = /^Phase-.+\.md$/i;

/**
 * Stamp every legacy Phase plan lacking `crucibleId:` with a
 * `grandfathered-<uuid>` value. Returns a per-file report.
 *
 * @param {string} projectDir
 * @param {{ dryRun?: boolean }} [opts]
 * @returns {{
 *   scanned: number,
 *   stamped: Array<{ path: string, crucibleId: string }>,
 *   skipped: Array<{ path: string, reason: string }>,
 * }}
 */
export function grandfatherExistingPlans(projectDir, opts = {}) {
  const { dryRun = false } = opts;
  const plansDir = resolve(projectDir, "docs", "plans");
  const report = { scanned: 0, stamped: [], skipped: [] };

  if (!existsSync(plansDir)) return report;

  let entries;
  try { entries = readdirSync(plansDir, { withFileTypes: true }); }
  catch { return report; }

  for (const entry of entries) {
    if (!entry.isFile()) continue;
    if (!PHASE_FILE_RE.test(entry.name)) continue;

    const path = join(plansDir, entry.name);
    report.scanned += 1;

    let original;
    try { original = readFileSync(path, "utf-8"); }
    catch (err) {
      report.skipped.push({ path, reason: `read-failed:${err.code || "unknown"}` });
      continue;
    }

    const { frontmatter } = parseFrontmatter(original);
    if (frontmatter.crucibleId) {
      report.skipped.push({ path, reason: "already-stamped" });
      continue;
    }

    const crucibleId = `grandfathered-${randomUUID()}`;
    const { changed, content } = upsertFrontmatter(original, { crucibleId });
    if (!changed) {
      // Defensive — upsert should always change when the field is missing
      report.skipped.push({ path, reason: "no-change" });
      continue;
    }

    if (!dryRun) {
      try { writeFileSync(path, content, "utf-8"); }
      catch (err) {
        report.skipped.push({ path, reason: `write-failed:${err.code || "unknown"}` });
        continue;
      }
      logManualImport(projectDir, {
        timestamp: new Date().toISOString(),
        planPath: path,
        source: "grandfather",
        reason: "legacy plan predated v2.37 Crucible",
        crucibleId,
      });
    }

    report.stamped.push({ path, crucibleId });
  }

  return report;
}

/**
 * Plan Forge — Crucible MCP handlers + lane inference.
 *
 * Pure module used by server.mjs to dispatch the six crucible tools.
 * Keeps server.mjs slim and makes handlers unit-testable without MCP plumbing.
 *
 * Slice 01.2 added: lane inference, submit/ask/preview/finalize/list/abandon,
 *                   three hub events (crucible-smelt-started/updated/finalized).
 * Slice 01.3 added: real interview engine (crucible-interview.mjs) and
 *                   six-block draft renderer (crucible-draft.mjs). The
 *                   Slice-2 stubs `getNextQuestion`/`renderDraftStub` are
 *                   replaced with real implementations re-exported here
 *                   for backwards-compatible imports in tests.
 */

import { existsSync, mkdirSync, readdirSync, statSync, writeFileSync } from "node:fs";
import { resolve, join } from "node:path";

import { loadCrucibleConfig } from "./crucible-config.mjs";
import { ERROR_CODES } from "./enums.mjs";
import { inferRepoCommands } from "./crucible-infer.mjs";

import {
  claimPhaseNumber,
  isValidPhaseName,
  listClaims,
  nextPhaseNumber,
} from "./crucible.mjs";
import {
  abandonSmelt,
  createSmelt,
  listSmelts,
  loadSmelt,
  updateSmelt,
} from "./crucible-store.mjs";
import {
  getNextQuestion as interviewGetNextQuestion,
  totalQuestions as interviewTotalQuestions,
} from "./crucible-interview.mjs";
import {
  renderDraft,
  extractUnresolvedFields,
} from "./crucible-draft.mjs";

/**
 * Compute "stale defaults" warnings for a smelt. Fires when the files
 * the recommendation engine reads (Project Principles, project profile)
 * are newer than the smelt's own updatedAt by more than the configured
 * threshold — which means the smelt's pre-filled defaults may reflect
 * out-of-date project state.
 *
 * @param {object} smelt
 * @param {string} projectDir
 * @returns {Array<{code: string, message: string, file: string, mtime: string}>}
 */
export function computeStaleDefaultsWarnings(smelt, projectDir) {
  if (!smelt || !smelt.updatedAt) return [];
  const cfg = loadCrucibleConfig(projectDir);
  const thresholdMs = Math.max(1, cfg.staleDefaultsHours) * 60 * 60 * 1000;
  const smeltTs = Date.parse(smelt.updatedAt);
  if (!Number.isFinite(smeltTs)) return [];

  const candidates = [
    { path: "docs/plans/PROJECT-PRINCIPLES.md", code: "STALE_PRINCIPLES" },
    { path: ".github/instructions/project-profile.instructions.md", code: "STALE_PROFILE" },
  ];
  const warnings = [];
  for (const c of candidates) {
    const abs = resolve(projectDir, c.path);
    if (!existsSync(abs)) continue;
    let stat;
    try { stat = statSync(abs); } catch { continue; }
    const fileTs = stat.mtime.getTime();
    if (fileTs - smeltTs <= thresholdMs) continue;
    const hoursAhead = Math.round((fileTs - smeltTs) / (60 * 60 * 1000));
    warnings.push({
      code: c.code,
      message: `${c.path} was updated ${hoursAhead}h after this smelt started — recommended defaults may be out of date.`,
      file: c.path,
      mtime: stat.mtime.toISOString(),
    });
  }
  return warnings;
}

// ─── Finalize refusal ────────────────────────────────────────────────

/**
 * Thrown by handleFinalize when the rendered draft still contains unresolved
 * markers for fields that are required before a plan can be executed.
 *
 * `payload.criticalGaps` lists the question IDs that must be answered.
 */
export class CrucibleFinalizeRefusedError extends Error {
  constructor(payload) {
    super(payload.hint || "finalize refused");
    this.name = "CrucibleFinalizeRefusedError";
    this.payload = payload;
  }
}

/**
 * Issue #137 — thrown by handleFinalize when `docs/plans/Phase-NN.md` already
 * exists and the caller did not pass `overwrite: true`. Carries the existing
 * path plus the side-by-side draft path that was written instead.
 */
export class CruciblePlanExistsError extends Error {
  constructor({ phaseName, planPath, draftPath }) {
    super(`Plan already exists at ${planPath}. Pass overwrite:true to replace, or use the side-by-side draft at ${draftPath}.`);
    this.name = "CruciblePlanExistsError";
    this.code = ERROR_CODES.PLAN_ALREADY_EXISTS.code;
    this.phaseName = phaseName;
    this.planPath = planPath;
    this.draftPath = draftPath;
  }
}

/**
 * Issue #138 — thrown by handleAsk when the client supplies an explicit `id`
 * that does not match the question the server has pending. Prevents silent
 * answer corruption when client and server fall out of sync.
 */
export class CrucibleAskMismatchError extends Error {
  constructor({ expected, got }) {
    super(`Question id mismatch: server expected '${expected}' but client sent '${got}'. Re-fetch the next question and retry.`);
    this.name = "CrucibleAskMismatchError";
    this.code = ERROR_CODES.ASK_QUESTION_MISMATCH.code;
    this.expected = expected;
    this.got = got;
  }
}

/**
 * Fields whose absence blocks finalization entirely. A plan that still has
 * {{TBD: <any of these>}} cannot be executed by the orchestrator.
 */
const CRITICAL_FIELDS = new Set([
  "scope-in",
  "scope-files",
  "validation-gates",
  "validation",
  "forbidden-actions",
  // Issue #118: build/test commands are required to make a slice executable.
  // Without them the orchestrator hits the "no executable gates → rubber-stamp"
  // path and the slice passes without doing anything.
  "build-command",
  "test-command",
]);

// ─── Lane inference ──────────────────────────────────────────────────

// Keyword order: FULL wins over FEATURE wins over TWEAK so that a phrase
// like "add new phase" (contains both "add" and "new phase") routes to
// "full" instead of "feature".
const FULL_PATTERNS = /\b(new phase|major (rewrite|overhaul|redesign)|redesign|overhaul|rearchitect|migrate (to|from))\b/i;
const FEATURE_PATTERNS = /\b(add|implement|support|enable|introduce)\b/i;
const TWEAK_PATTERNS = /\b(typo|rename|bump|config|hotfix|tweak|adjust|patch)\b/i;

/**
 * Infer the recommended lane for a raw idea.
 * @param {string} rawIdea
 * @returns {"tweak"|"feature"|"full"}
 */
export function inferLane(rawIdea) {
  if (typeof rawIdea !== "string") return "feature";
  const s = rawIdea.trim();
  if (!s) return "feature";
  if (FULL_PATTERNS.test(s)) return "full";
  if (FEATURE_PATTERNS.test(s)) return "feature";
  if (TWEAK_PATTERNS.test(s)) return "tweak";
  return "feature";
}

// ─── Interview (Slice 01.3 — real engine) ────────────────────────────

/**
 * Return the next unanswered question for a smelt, or null if done.
 * Thin wrapper so existing callers keep importing from crucible-server.
 * @param {object} smelt
 * @param {{projectDir?: string}} [context]
 */
export function getNextQuestion(smelt, context = {}) {
  return interviewGetNextQuestion(smelt, context);
}

/**
 * Slice-01.2 compatibility alias — was the stub draft renderer, now
 * just delegates to renderDraft. Kept for legacy imports until callers
 * are migrated.
 * @deprecated use renderDraft from crucible-draft.mjs
 */
export function renderDraftStub(smelt) {
  return renderDraft(smelt);
}

// Re-export the real renderer for convenience.
export { renderDraft, extractUnresolvedFields };

// ─── Hub event helper ────────────────────────────────────────────────

function emit(hub, type, data) {
  if (!hub || typeof hub.broadcast !== "function") return;
  try {
    hub.broadcast({ type, data, timestamp: new Date().toISOString() });
  } catch { /* best-effort */ }
}

// ─── Phase-number discovery ──────────────────────────────────────────

/**
 * Collect existing decimal-style phase names from:
 *   - active phase-claims.json (in-progress finalizations)
 *   - docs/plans/Phase-*.md file names (already-finalized phases)
 * Non-decimal names (e.g. Phase-CRUCIBLE-01) are ignored — they get
 * grandfathered in Slice 4.
 * @returns {string[]}
 */
export function collectExistingPhaseNames(projectDir) {
  const names = new Set();
  for (const c of listClaims(projectDir)) {
    if (isValidPhaseName(c.phaseName)) names.add(c.phaseName);
  }
  const plansDir = resolve(projectDir, "docs", "plans");
  try {
    for (const entry of readdirSync(plansDir, { withFileTypes: true })) {
      if (!entry.isFile()) continue;
      if (!entry.name.endsWith(".md")) continue;
      const base = entry.name.replace(/\.md$/, "");
      if (isValidPhaseName(base)) names.add(base);
    }
  } catch { /* plans dir may not exist yet */ }
  return [...names];
}

// ─── Handlers ────────────────────────────────────────────────────────

/**
 * forge_crucible_submit
 */
export function handleSubmit({ rawIdea, lane, source, parentSmeltId, projectDir, hub }) {
  if (typeof rawIdea !== "string" || !rawIdea.trim()) {
    throw new Error("rawIdea is required");
  }
  const recommendedLane = inferLane(rawIdea);
  const smelt = createSmelt({
    lane: lane || recommendedLane,
    rawIdea,
    source: source || "human",
    parentSmeltId: parentSmeltId || null,
    projectDir,
  });
  emit(hub, "crucible-smelt-started", {
    id: smelt.id,
    lane: smelt.lane,
    source: smelt.source,
    totalQuestions: interviewTotalQuestions(smelt.lane),
  });
  return {
    id: smelt.id,
    recommendedLane,
    firstQuestion: interviewGetNextQuestion(smelt, { projectDir }),
  };
}

/**
 * forge_crucible_ask
 *
 * The caller sends the answer to whatever question was last returned by
 * getNextQuestion. We look up that "pending" question on the server so
 * the questionId recorded in the smelt matches the bank id exactly —
 * not a client-supplied string — and so the interview cannot record
 * answers for nonexistent questions.
 */
export function handleAsk({ id, answer, questionId, projectDir, hub }) {
  const smelt = loadSmelt(id, projectDir);
  if (!smelt) throw new Error(`smelt not found: ${id}`);
  if (smelt.status !== "in-progress") {
    throw new Error(`smelt is ${smelt.status}, cannot continue interview`);
  }

  let current = smelt;
  const pending = interviewGetNextQuestion(smelt, { projectDir });

  // Issue #138 — if the caller supplied a `questionId` (the schema field
  // formerly mistaken for the smelt `id`), validate it matches the pending
  // question. Refuse mismatched answers so a confused client can't silently
  // record the wrong answer against the wrong question.
  if (typeof questionId === "string" && questionId.length > 0 && pending && questionId !== pending.id) {
    throw new CrucibleAskMismatchError({ expected: pending.id, got: questionId });
  }

  if (answer !== undefined && answer !== null && `${answer}`.length > 0 && pending) {
    const patch = {
      answers: [
        ...smelt.answers,
        { questionId: pending.id, answer: String(answer), recordedAt: new Date().toISOString() },
      ],
    };
    current = updateSmelt(id, patch, projectDir);
    emit(hub, "crucible-smelt-updated", {
      id: current.id,
      questionIndex: current.answers.length,
      totalQuestions: interviewTotalQuestions(current.lane),
    });
  }

  const nextQuestion = interviewGetNextQuestion(current, { projectDir });
  const markdown = renderDraft(current);
  return {
    done: nextQuestion === null,
    nextQuestion,
    draftPreview: markdown,
    warnings: computeStaleDefaultsWarnings(current, projectDir),
  };
}

/**
 * forge_crucible_preview
 */
export function handlePreview({ id, projectDir }) {
  const smelt = loadSmelt(id, projectDir);
  if (!smelt) throw new Error(`smelt not found: ${id}`);
  const markdown = renderDraft(smelt);
  return {
    markdown,
    phaseName: smelt.phaseName,
    unresolvedFields: extractUnresolvedFields(markdown),
  };
}

/**
 * forge_crucible_finalize
 *
 * @param {object} params
 * @param {string} params.id
 * @param {string} params.projectDir
 * @param {object} [params.hub]
 * @param {boolean} [params.overwrite=false] — Issue #137: when false (default),
 *   refuses to overwrite an existing `docs/plans/Phase-NN.md` and instead
 *   writes a side-by-side `Phase-NN.crucible-draft.md` plus throws a
 *   `CruciblePlanExistsError` so the caller can decide.
 */
export function handleFinalize({ id, projectDir, hub, overwrite = false }) {
  const smelt = loadSmelt(id, projectDir);
  if (!smelt) throw new Error(`smelt not found: ${id}`);
  if (smelt.status !== "in-progress") {
    throw new Error(`smelt is ${smelt.status}, cannot finalize`);
  }

  // Render a preview draft (no phaseName yet) to detect critical TBD gaps
  // before committing to a phase number or writing any file.
  const previewBody = renderDraft(smelt, { cwd: projectDir });
  const allUnresolved = extractUnresolvedFields(previewBody);
  const criticalGaps = allUnresolved.filter((f) => CRITICAL_FIELDS.has(f));

  if (criticalGaps.length > 0) {
    throw new CrucibleFinalizeRefusedError({
      id,
      criticalGaps,
      hint: "Run forge_crucible_ask with these question IDs to fill the gaps before finalizing.",
    });
  }

  const existing = collectExistingPhaseNames(projectDir);
  const phaseName = nextPhaseNumber(existing);

  const planDir = resolve(projectDir, "docs", "plans");
  mkdirSync(planDir, { recursive: true });
  const planPath = join(planDir, `${phaseName}.md`);

  const frontmatter =
    `---\n` +
    `crucibleId: ${id}\n` +
    `lane: ${smelt.lane}\n` +
    `source: ${smelt.source}\n` +
    `---\n\n`;
  const bodySmelt = { ...smelt, phaseName };
  const body = renderDraft(bodySmelt, { cwd: projectDir });
  const markdown = frontmatter + body;

  // Issue #137 — don't overwrite a hand-authored plan. If the path already
  // exists and is non-empty, write a side-by-side `.crucible-draft.md` and
  // refuse with a CruciblePlanExistsError that surfaces both paths.
  const planExists = existsSync(planPath);
  let planFileExistedAndNonEmpty = false;
  if (planExists) {
    try {
      const stat = statSync(planPath);
      planFileExistedAndNonEmpty = stat.size > 0;
    } catch { /* treat unreadable as non-existent */ }
  }

  if (planFileExistedAndNonEmpty && !overwrite) {
    const draftPath = join(planDir, `${phaseName}.crucible-draft.md`);
    writeFileSync(draftPath, markdown, "utf-8");
    // Do NOT claim the phase number, do NOT mutate the smelt status — the
    // caller has to re-finalize with overwrite:true (or pick a new phase).
    throw new CruciblePlanExistsError({ phaseName, planPath, draftPath });
  }

  claimPhaseNumber(projectDir, phaseName, id);
  writeFileSync(planPath, markdown, "utf-8");

  updateSmelt(id, {
    phaseName,
    status: "finalized",
    draftMarkdown: markdown,
  }, projectDir);

  emit(hub, "crucible-smelt-finalized", {
    id,
    phaseName,
    planPath,
  });

  // v2.37 Slice 01.6 — emit the Hardener handoff event. The dashboard
  // listens for this and shows a "Hardener ready" action; the MCP
  // agent can subscribe and auto-invoke `step2-harden-plan.prompt.md`.
  // We do not block finalize on hardening — the plan is already on
  // disk and enforcement-compatible by virtue of the frontmatter
  // written above.
  emit(hub, "crucible-handoff-to-hardener", {
    id,
    phaseName,
    planPath,
    nextStep: "step2-harden-plan.prompt.md",
  });

  const inferred = inferRepoCommands(projectDir);
  const unresolvedFields = allUnresolved.filter((f) => !CRITICAL_FIELDS.has(f));

  return {
    phaseName,
    planPath,
    unresolvedFields,
    inferred,
    hardenerInvoked: false, // Slice 6 wires the Plan Hardener handoff
    hardenerHandoff: {
      event: "crucible-handoff-to-hardener",
      nextStep: "step2-harden-plan.prompt.md",
      hint: "Run `/step2-harden-plan` against this plan, or attach it to the Plan Hardener agent.",
    },
  };
}

/**
 * forge_crucible_list
 */
export function handleList({ status, projectDir }) {
  return { smelts: listSmelts(projectDir, status ? { status } : {}) };
}

/**
 * forge_crucible_abandon
 */
export function handleAbandon({ id, projectDir }) {
  return abandonSmelt(id, projectDir);
}

/**
 * Plan Forge — Crucible: Smelt Persistence
 *
 * A "smelt" is an in-progress conversion of a raw idea into a hardened
 * phase spec. Each smelt is persisted as `.forge/crucible/<id>.json` and
 * survives across dashboard refreshes and CLI sessions.
 *
 * Record schema:
 *   {
 *     id: string,            // UUID
 *     lane: "tweak" | "feature" | "full",
 *     rawIdea: string,       // original prompt that started the smelt
 *     answers: Array<{questionId, answer, answeredAt}>,
 *     draftMarkdown: string, // rendered via crucible-draft.renderDraft()
 *     phaseName: string|null,// assigned on finalize
 *     createdAt: string,     // ISO
 *     updatedAt: string,     // ISO
 *     status: "in-progress" | "finalized" | "abandoned",
 *     source: "human" | "agent",
 *     parentSmeltId: string|null, // for agent self-referrals
 *   }
 *
 * @module crucible-store
 */

import {
  existsSync,
  mkdirSync,
  readFileSync,
  readdirSync,
  renameSync,
  writeFileSync,
  unlinkSync,
} from "node:fs";
import { resolve, join } from "node:path";
import { randomUUID } from "node:crypto";

import { releaseClaim } from "./crucible.mjs";

const VALID_LANES = new Set(["tweak", "feature", "full"]);
const VALID_SOURCES = new Set(["human", "agent"]);
const VALID_STATUSES = new Set(["in-progress", "finalized", "abandoned"]);

function crucibleDir(projectDir) {
  return resolve(projectDir, ".forge", "crucible");
}

function smeltPath(projectDir, id) {
  return join(crucibleDir(projectDir), `${id}.json`);
}

function ensureCrucibleDir(projectDir) {
  const dir = crucibleDir(projectDir);
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
}

/**
 * Atomic write via rename-on-write.
 * @private
 */
function atomicWrite(path, content) {
  const tmp = `${path}.tmp.${process.pid}.${randomUUID().slice(0, 8)}`;
  writeFileSync(tmp, content, "utf-8");
  renameSync(tmp, path);
}

/**
 * Create a new smelt record.
 *
 * @param {object} opts
 * @param {string} opts.lane - "tweak" | "feature" | "full"
 * @param {string} opts.rawIdea - original prompt
 * @param {string} opts.projectDir
 * @param {string} [opts.source="human"]
 * @param {string|null} [opts.parentSmeltId=null] - for agent self-referrals
 * @returns {object} the created smelt record
 */
export function createSmelt({ lane, rawIdea, projectDir, source = "human", parentSmeltId = null }) {
  if (!VALID_LANES.has(lane)) {
    throw new Error(`createSmelt: invalid lane '${lane}' (must be tweak|feature|full)`);
  }
  if (typeof rawIdea !== "string" || !rawIdea.trim()) {
    throw new Error("createSmelt: rawIdea is required");
  }
  if (!VALID_SOURCES.has(source)) {
    throw new Error(`createSmelt: invalid source '${source}'`);
  }
  ensureCrucibleDir(projectDir);
  const now = new Date().toISOString();
  const record = {
    id: randomUUID(),
    lane,
    rawIdea: rawIdea.trim(),
    answers: [],
    draftMarkdown: "",
    phaseName: null,
    createdAt: now,
    updatedAt: now,
    status: "in-progress",
    source,
    parentSmeltId,
  };
  atomicWrite(smeltPath(projectDir, record.id), JSON.stringify(record, null, 2));
  return record;
}

/**
 * Load a smelt by id. Returns null if not found.
 *
 * @param {string} id
 * @param {string} projectDir
 * @returns {object|null}
 */
export function loadSmelt(id, projectDir) {
  if (!id || typeof id !== "string") return null;
  const path = smeltPath(projectDir, id);
  if (!existsSync(path)) return null;
  try {
    const raw = readFileSync(path, "utf-8");
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

/**
 * Update a smelt with a patch object. Always refreshes `updatedAt`.
 *
 * Rejects changes to immutable fields: id, createdAt, source, parentSmeltId.
 * Validates `lane` and `status` if present in the patch.
 *
 * @param {string} id
 * @param {object} patch
 * @param {string} projectDir
 * @returns {object} updated record
 */
export function updateSmelt(id, patch, projectDir) {
  const existing = loadSmelt(id, projectDir);
  if (!existing) throw new Error(`updateSmelt: smelt '${id}' not found`);
  if (patch.lane !== undefined && !VALID_LANES.has(patch.lane)) {
    throw new Error(`updateSmelt: invalid lane '${patch.lane}'`);
  }
  if (patch.status !== undefined && !VALID_STATUSES.has(patch.status)) {
    throw new Error(`updateSmelt: invalid status '${patch.status}'`);
  }
  const immutable = ["id", "createdAt", "source", "parentSmeltId"];
  const next = { ...existing };
  for (const [k, v] of Object.entries(patch)) {
    if (immutable.includes(k)) continue;
    next[k] = v;
  }
  next.updatedAt = new Date().toISOString();
  atomicWrite(smeltPath(projectDir, id), JSON.stringify(next, null, 2));
  return next;
}

/**
 * List all smelts in the project, optionally filtered by status.
 *
 * @param {string} projectDir
 * @param {object} [opts]
 * @param {string} [opts.status] - filter: "in-progress" | "finalized" | "abandoned"
 * @returns {object[]} list of smelt records (most recent first)
 */
export function listSmelts(projectDir, { status } = {}) {
  const dir = crucibleDir(projectDir);
  if (!existsSync(dir)) return [];
  let entries;
  try {
    entries = readdirSync(dir, { withFileTypes: true });
  } catch {
    return [];
  }
  const smelts = [];
  for (const entry of entries) {
    if (!entry.isFile() || !entry.name.endsWith(".json")) continue;
    if (entry.name === "phase-claims.json" || entry.name === "config.json") continue;
    if (entry.name === "manual-imports.jsonl") continue;
    const id = entry.name.slice(0, -".json".length);
    const rec = loadSmelt(id, projectDir);
    if (!rec) continue;
    if (status && rec.status !== status) continue;
    smelts.push(rec);
  }
  smelts.sort((a, b) => (a.updatedAt < b.updatedAt ? 1 : -1));
  return smelts;
}

/**
 * Abandon a smelt. Marks status and releases any held phase claim.
 *
 * @param {string} id
 * @param {string} projectDir
 * @returns {{abandoned: boolean}}
 */
export function abandonSmelt(id, projectDir) {
  const existing = loadSmelt(id, projectDir);
  if (!existing) return { abandoned: false };
  if (existing.status === "abandoned") return { abandoned: true };
  if (existing.phaseName) {
    releaseClaim(projectDir, existing.phaseName, id);
  }
  updateSmelt(id, { status: "abandoned" }, projectDir);
  return { abandoned: true };
}

/**
 * Test helper — delete a smelt file outright. Not part of the public API.
 * @private
 */
export function _deleteSmeltForTest(id, projectDir) {
  const path = smeltPath(projectDir, id);
  if (existsSync(path)) {
    try { unlinkSync(path); } catch { /* ignore */ }
  }
}

/**
 * Plan Forge — Crucible: Phase Naming & Atomic Claims
 *
 * Phase naming rules (non-negotiable per Phase-CRUCIBLE-01 design commitment #1):
 *   - Decimal-only, semver-style: "Phase-01", "Phase-01.1", "Phase-01.1.1"
 *   - No letters. No mixed styles.
 *   - A new phase at depth N means "granular refinement of parent N-1"
 *
 * Atomic phase-number claim prevents two concurrent smelts from picking the
 * same number. Uses a rename-on-write pattern on `.forge/crucible/phase-claims.json`.
 *
 * @module crucible
 */

import { existsSync, mkdirSync, readFileSync, renameSync, writeFileSync, unlinkSync } from "node:fs";
import { resolve, join, dirname } from "node:path";
import { randomUUID } from "node:crypto";

/**
 * Regex for valid phase names. Matches:
 *   Phase-01
 *   Phase-01.1
 *   Phase-01.1.1
 *   Phase-12.34.56
 *
 * Rejects:
 *   Phase-1       (must be zero-padded to at least 2 digits at top level)
 *   Phase-01D     (no letters)
 *   Phase-1.C.2   (no letters in decimal parts)
 *   Phase-CRUCIBLE-01  (the literal string "CRUCIBLE" is a letter block)
 *
 * Note: for backward-compat with existing repo plans like Phase-CRUCIBLE-01.md,
 * validation only runs on NEW smelts. Grandfathered plans keep their names.
 */
const PHASE_NAME_RE = /^Phase-(\d{2,})(\.\d+)*$/;

/**
 * Validate a phase name against the decimal-only semver rule.
 *
 * @param {string} name - e.g. "Phase-01" or "Phase-01.1.1"
 * @returns {boolean}
 */
export function isValidPhaseName(name) {
  if (typeof name !== "string" || !name) return false;
  return PHASE_NAME_RE.test(name);
}

/**
 * Parse a phase name into its numeric segments.
 *
 * @param {string} name - e.g. "Phase-01.1.2"
 * @returns {number[]|null} [01, 1, 2] or null if invalid
 */
export function parsePhaseName(name) {
  if (!isValidPhaseName(name)) return null;
  const body = name.slice("Phase-".length);
  return body.split(".").map((s) => parseInt(s, 10));
}

/**
 * Compare two phase names for sort order. `01 < 01.1 < 01.2 < 02`.
 * Returns -1, 0, or +1. Invalid names sort last.
 *
 * @param {string} a
 * @param {string} b
 * @returns {number}
 */
export function comparePhaseNames(a, b) {
  const pa = parsePhaseName(a);
  const pb = parsePhaseName(b);
  if (!pa && !pb) return 0;
  if (!pa) return 1;
  if (!pb) return -1;
  const len = Math.max(pa.length, pb.length);
  for (let i = 0; i < len; i++) {
    const av = pa[i] ?? -1;
    const bv = pb[i] ?? -1;
    if (av !== bv) return av < bv ? -1 : 1;
  }
  return 0;
}

/**
 * Compute the next available phase number given a list of existing names.
 *
 * When `parent` is null: returns the next top-level phase (e.g. existing
 * ["Phase-01","Phase-02"] → "Phase-03").
 *
 * When `parent` is a valid phase name: returns the next child
 * (e.g. parent="Phase-02", existing ["Phase-02.1","Phase-02.2"] → "Phase-02.3").
 *
 * @param {string[]} existingNames - Names already claimed
 * @param {string|null} [parent=null] - Parent phase for nested naming
 * @returns {string} Next available phase name
 */
export function nextPhaseNumber(existingNames, parent = null) {
  const valid = existingNames.filter(isValidPhaseName);

  if (parent === null) {
    // Top-level: find max first segment
    let max = 0;
    for (const n of valid) {
      const segs = parsePhaseName(n);
      if (segs && segs.length === 1 && segs[0] > max) max = segs[0];
    }
    const next = max + 1;
    return `Phase-${String(next).padStart(2, "0")}`;
  }

  if (!isValidPhaseName(parent)) {
    throw new Error(`nextPhaseNumber: invalid parent name '${parent}'`);
  }
  const parentSegs = parsePhaseName(parent);
  const depth = parentSegs.length + 1;
  let max = 0;
  for (const n of valid) {
    const segs = parsePhaseName(n);
    if (!segs || segs.length !== depth) continue;
    // Must share parent prefix
    let prefixMatch = true;
    for (let i = 0; i < parentSegs.length; i++) {
      if (segs[i] !== parentSegs[i]) { prefixMatch = false; break; }
    }
    if (!prefixMatch) continue;
    if (segs[depth - 1] > max) max = segs[depth - 1];
  }
  return `${parent}.${max + 1}`;
}

// ───────────────────────────────────────────────────────────────────────
// Atomic phase-number claims
// ───────────────────────────────────────────────────────────────────────

function crucibleDir(projectDir) {
  return resolve(projectDir, ".forge", "crucible");
}

function claimsPath(projectDir) {
  return join(crucibleDir(projectDir), "phase-claims.json");
}

function ensureCrucibleDir(projectDir) {
  const dir = crucibleDir(projectDir);
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
}

/**
 * Read the current claims table. Missing file → empty object.
 *
 * @param {string} projectDir
 * @returns {{[phaseName: string]: {id: string, claimedAt: string}}}
 */
function readClaims(projectDir) {
  const path = claimsPath(projectDir);
  if (!existsSync(path)) return {};
  try {
    const raw = readFileSync(path, "utf-8");
    if (!raw.trim()) return {};
    return JSON.parse(raw);
  } catch {
    return {};
  }
}

/**
 * Atomically write the claims table. Uses rename-on-write so concurrent
 * readers never see a partial file.
 *
 * @param {string} projectDir
 * @param {object} claims
 */
function writeClaims(projectDir, claims) {
  ensureCrucibleDir(projectDir);
  const path = claimsPath(projectDir);
  // Unique temp name per call so parallel writers don't collide on the tmp path.
  const tmp = `${path}.tmp.${process.pid}.${randomUUID().slice(0, 8)}`;
  writeFileSync(tmp, JSON.stringify(claims, null, 2), "utf-8");
  renameSync(tmp, path);
}

/**
 * Claim a phase number for a smelt. Fails if already claimed.
 *
 * Caller is expected to have already checked `nextPhaseNumber()` or chosen
 * an explicit name. This function is the point of serialization: if two
 * concurrent callers race on the same name, exactly one succeeds.
 *
 * @param {string} projectDir
 * @param {string} phaseName - must pass `isValidPhaseName`
 * @param {string} smeltId
 * @returns {{claimed: true}}
 * @throws If phaseName is invalid or already claimed
 */
export function claimPhaseNumber(projectDir, phaseName, smeltId) {
  if (!isValidPhaseName(phaseName)) {
    throw new Error(`claimPhaseNumber: invalid phase name '${phaseName}'`);
  }
  if (!smeltId || typeof smeltId !== "string") {
    throw new Error("claimPhaseNumber: smeltId is required");
  }
  // Re-read under the rename boundary. The rename itself is atomic on POSIX
  // and Windows (same-volume), so read→mutate→write is safe for single-process
  // scenarios and correct-but-optimistic for multi-process: losers of the race
  // observe the claim during their read-before-write and raise the "already
  // claimed" error.
  const claims = readClaims(projectDir);
  if (claims[phaseName]) {
    throw new Error(
      `claimPhaseNumber: '${phaseName}' already claimed by smelt '${claims[phaseName].id}'`,
    );
  }
  claims[phaseName] = { id: smeltId, claimedAt: new Date().toISOString() };
  writeClaims(projectDir, claims);
  // Verify the claim landed (defensive against cross-process races on the rare
  // case of a concurrent writer overwriting between our read and write).
  const verify = readClaims(projectDir);
  if (!verify[phaseName] || verify[phaseName].id !== smeltId) {
    throw new Error(
      `claimPhaseNumber: '${phaseName}' was claimed by another smelt during write`,
    );
  }
  return { claimed: true };
}

/**
 * Release a phase claim. Safe to call even if the claim doesn't exist.
 *
 * @param {string} projectDir
 * @param {string} phaseName
 * @param {string} smeltId - must match the claimer to release
 * @returns {{released: boolean}}
 */
export function releaseClaim(projectDir, phaseName, smeltId) {
  const claims = readClaims(projectDir);
  if (!claims[phaseName]) return { released: false };
  if (claims[phaseName].id !== smeltId) {
    // Not our claim — refuse to release someone else's.
    return { released: false };
  }
  delete claims[phaseName];
  writeClaims(projectDir, claims);
  return { released: true };
}

/**
 * List all currently claimed phase names.
 *
 * @param {string} projectDir
 * @returns {Array<{phaseName: string, id: string, claimedAt: string}>}
 */
export function listClaims(projectDir) {
  const claims = readClaims(projectDir);
  return Object.entries(claims).map(([phaseName, v]) => ({
    phaseName,
    id: v.id,
    claimedAt: v.claimedAt,
  }));
}

/**
 * Internal helper exposed for tests — reset the claims file for a project.
 * Not part of the public API.
 *
 * @param {string} projectDir
 * @private
 */
export function _resetClaimsForTest(projectDir) {
  const path = claimsPath(projectDir);
  if (existsSync(path)) {
    try { unlinkSync(path); } catch { /* ignore */ }
  }
}

/**
 * Plan Forge — Anvil & Lattice Dashboard Tab (Phase-LATTICE Slice 9).
 *
 * Exports render helpers for the "Anvil & Lattice" tab:
 *   - `renderAnvilCard(stat)` — Anvil cache summary: entries, bytes, top-5 tools by hit count, DLQ count.
 *   - `renderLatticeCard(stat)` — Lattice index summary: chunks, edges, languages, last index age, chunker impl.
 *
 * `stat` for `renderAnvilCard` is the merged result of `forge_anvil_stat` + `dlqCount` from `forge_anvil_dlq_list`.
 * `stat` for `renderLatticeCard` is the result of `forge_lattice_stat`.
 *
 * The browser interop section at the bottom wires `loadAnvilLattice()` and exposes it as `window.loadAnvilLattice`.
 */

// ─── Anvil Card ───────────────────────────────────────────────────────────────

/**
 * Render the Anvil cache summary card.
 *
 * @param {{ entries: number, totalBytes: number, oldestMtime: number|null,
 *           perTool: Record<string, { hits: number, misses: number, count: number }>,
 *           dlqCount?: number } | null} stat
 * @returns {string} HTML fragment
 */
export function renderAnvilCard(stat) {
  if (!stat || stat.entries === 0) {
    return `<div class="al-card al-card--anvil" data-card="anvil">
  <h3 class="al-card__title">🔨 Anvil Cache</h3>
  <p class="al-card__empty">No cached entries yet. Run a plan to warm the cache.</p>
</div>`;
  }

  const { entries, totalBytes = 0, perTool = {}, dlqCount = 0 } = stat;

  const toolRows = Object.entries(perTool)
    .map(([tool, s]) => {
      const total = (s.hits ?? 0) + (s.misses ?? 0);
      const rate = total > 0 ? s.hits / total : 0;
      return { tool, hits: s.hits ?? 0, count: s.count ?? 0, rate };
    })
    .sort((a, b) => b.hits - a.hits)
    .slice(0, 5);

  const rowsHtml =
    toolRows.length > 0
      ? toolRows
          .map(
            (r) => `    <tr class="al-table__row">
      <td class="al-table__cell">${escapeHtml(r.tool)}</td>
      <td class="al-table__cell al-table__cell--num">${r.count}</td>
      <td class="al-table__cell al-table__cell--num">${formatPercent(r.rate)}</td>
    </tr>`
          )
          .join('\n')
      : `    <tr><td colspan="3" class="al-table__cell al-card__empty--inline">No tool stats yet.</td></tr>`;

  return `<div class="al-card al-card--anvil" data-card="anvil">
  <h3 class="al-card__title">🔨 Anvil Cache</h3>
  <div class="al-card__stats">
    <div class="al-stat" data-stat="entries">
      <span class="al-stat__label">Entries</span>
      <span class="al-stat__value">${entries}</span>
    </div>
    <div class="al-stat" data-stat="bytes">
      <span class="al-stat__label">Cache size</span>
      <span class="al-stat__value">${formatBytes(totalBytes)}</span>
    </div>
    <div class="al-stat" data-stat="dlq">
      <span class="al-stat__label">DLQ</span>
      <span class="al-stat__value${dlqCount > 0 ? ' al-stat__value--warn' : ''}">${dlqCount}</span>
    </div>
  </div>
  <h4 class="al-card__subtitle">Top tools by hit count</h4>
  <table class="al-table" aria-label="Anvil tool stats">
    <thead>
      <tr>
        <th class="al-table__th">Tool</th>
        <th class="al-table__th al-table__th--num">Entries</th>
        <th class="al-table__th al-table__th--num">Hit rate</th>
      </tr>
    </thead>
    <tbody>
${rowsHtml}
    </tbody>
  </table>
</div>`;
}

// ─── Lattice Card ─────────────────────────────────────────────────────────────

/**
 * Render the Lattice index summary card.
 *
 * @param {{ chunks: number, edges: number, languages: Record<string, number>,
 *           lastIndexedAt: string|null, chunkerImpl: string|null,
 *           chunkerVersion: string|null, anvilHitRate: number,
 *           indexBytes: number } | null} stat
 * @returns {string} HTML fragment
 */
export function renderLatticeCard(stat) {
  if (!stat || stat.chunks === 0) {
    return `<div class="al-card al-card--lattice" data-card="lattice">
  <h3 class="al-card__title">🕸 Lattice Index</h3>
  <p class="al-card__empty">No index found. Run <code>forge_lattice_index</code> to populate.</p>
</div>`;
  }

  const {
    chunks,
    edges,
    languages = {},
    lastIndexedAt,
    chunkerImpl,
    chunkerVersion,
    anvilHitRate,
    indexBytes = 0,
  } = stat;

  const ageStr = lastIndexedAt ? formatAge(lastIndexedAt) : 'never';
  const hitRateStr =
    typeof anvilHitRate === 'number' ? formatPercent(anvilHitRate) : 'n/a';

  const totalLangChunks =
    Object.values(languages).reduce((s, n) => s + n, 0) || 1;

  const langBarsHtml = Object.entries(languages)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 6)
    .map(([lang, count]) => {
      const pct = Math.round((count / totalLangChunks) * 100);
      return `    <div class="al-lang-bar" data-lang="${escapeHtml(lang)}">
      <span class="al-lang-bar__label">${escapeHtml(lang)}</span>
      <div class="al-lang-bar__track"><div class="al-lang-bar__fill" style="width:${pct}%"></div></div>
      <span class="al-lang-bar__count">${count}</span>
    </div>`;
    })
    .join('\n');

  const implLabel = escapeHtml(chunkerImpl ?? 'unknown');
  const implVersion = chunkerVersion ? ` v${escapeHtml(chunkerVersion)}` : '';

  return `<div class="al-card al-card--lattice" data-card="lattice">
  <h3 class="al-card__title">🕸 Lattice Index</h3>
  <div class="al-card__stats">
    <div class="al-stat" data-stat="chunks">
      <span class="al-stat__label">Chunks</span>
      <span class="al-stat__value">${chunks}</span>
    </div>
    <div class="al-stat" data-stat="edges">
      <span class="al-stat__label">Edges</span>
      <span class="al-stat__value">${edges}</span>
    </div>
    <div class="al-stat" data-stat="index-bytes">
      <span class="al-stat__label">Index size</span>
      <span class="al-stat__value">${formatBytes(indexBytes)}</span>
    </div>
    <div class="al-stat" data-stat="anvil-hit-rate">
      <span class="al-stat__label">Anvil hit rate</span>
      <span class="al-stat__value">${hitRateStr}</span>
    </div>
  </div>
  <div class="al-card__meta">
    <span class="al-meta__item">Indexed <strong>${ageStr}</strong></span>
    <span class="al-meta__sep">·</span>
    <span class="al-meta__item">Chunker: <code>${implLabel}${implVersion}</code></span>
  </div>
${langBarsHtml
    ? `  <h4 class="al-card__subtitle">Language distribution</h4>
  <div class="al-lang-bars">
${langBarsHtml}
  </div>`
    : ''}
</div>`;
}

// ─── Internal helpers ─────────────────────────────────────────────────────────

function escapeHtml(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function formatPercent(val) {
  if (typeof val !== 'number') return '0%';
  return `${Math.round(val * 100)}%`;
}

function formatBytes(bytes) {
  const n = typeof bytes === 'number' ? bytes : 0;
  if (n < 1024) return `${n} B`;
  if (n < 1024 * 1024) return `${(n / 1024).toFixed(1)} KB`;
  return `${(n / (1024 * 1024)).toFixed(1)} MB`;
}

function formatAge(iso) {
  try {
    const ms = Date.now() - new Date(iso).getTime();
    if (ms < 60_000) return 'just now';
    if (ms < 3_600_000) return `${Math.floor(ms / 60_000)}m ago`;
    if (ms < 86_400_000) return `${Math.floor(ms / 3_600_000)}h ago`;
    return `${Math.floor(ms / 86_400_000)}d ago`;
  } catch {
    return 'unknown';
  }
}

// ─── Browser interop ──────────────────────────────────────────────────────────
// Exposes loadAnvilLattice() and render helpers to non-module scripts via window.
if (typeof window !== 'undefined') {
  const API_BASE = `${window.location.protocol}//${window.location.host}`;

  async function loadAnvilLattice() {
    const errEl = document.getElementById('al-error');
    if (errEl) errEl.classList.add('hidden');

    try {
      const [anvilRes, dlqRes, latticeRes] = await Promise.allSettled([
        fetch(`${API_BASE}/api/tool/forge_anvil_stat`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: '{}',
        }).then((r) => r.json()),
        fetch(`${API_BASE}/api/tool/forge_anvil_dlq_list`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: '{}',
        }).then((r) => r.json()),
        fetch(`${API_BASE}/api/tool/forge_lattice_stat`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: '{}',
        }).then((r) => r.json()),
      ]);

      const anvilStat =
        anvilRes.status === 'fulfilled' ? anvilRes.value : null;
      const dlqData =
        dlqRes.status === 'fulfilled' ? dlqRes.value : null;
      const latticeStat =
        latticeRes.status === 'fulfilled' ? latticeRes.value : null;

      const mergedAnvil = anvilStat
        ? { ...anvilStat, dlqCount: dlqData?.total ?? 0 }
        : null;

      const anvilEl = document.getElementById('al-anvil-card');
      if (anvilEl) anvilEl.innerHTML = renderAnvilCard(mergedAnvil);

      const latticeEl = document.getElementById('al-lattice-card');
      if (latticeEl) latticeEl.innerHTML = renderLatticeCard(latticeStat);
    } catch (err) {
      if (errEl) {
        errEl.textContent = `Failed to load Anvil & Lattice stats: ${err.message}`;
        errEl.classList.remove('hidden');
      }
    }
  }

  window.loadAnvilLattice = loadAnvilLattice;
  window.anvilLatticeRenderAnvilCard = renderAnvilCard;
  window.anvilLatticeRenderLatticeCard = renderLatticeCard;
}

export function renderTeamActivityPanel(activities) {
  if (!activities || activities.length === 0) {
    return `<div class="team-activity-empty text-slate-500 text-sm p-4">
      No team activity yet. Activity is recorded after each plan run.<br/>
      <code class="text-amber-400">pforge team activity</code> to check.
    </div>`;
  }
  const rows = activities.slice(0, 10).map((a) => {
    const ago = formatRelativeTime(a.timestamp);
    const status = a.status === "completed" ? "✅" : a.status === "aborted" ? "⚠️" : "❌";
    return `<tr class="border-b border-slate-700">
      <td class="py-1 pr-4 text-slate-400 text-xs whitespace-nowrap">${ago}</td>
      <td class="py-1 pr-4">${status}</td>
      <td class="py-1 pr-4 text-slate-300 text-sm truncate max-w-xs">${a.plan ?? "—"}</td>
      <td class="py-1 pr-4 text-slate-400 text-xs">${a.operator?.split("<")[0].trim() ?? "—"}</td>
      <td class="py-1 text-amber-400 text-xs">${a.cost_usd != null ? "$" + Number(a.cost_usd).toFixed(2) : "—"}</td>
    </tr>`;
  }).join("");
  return `<div class="team-activity-panel">
    <table class="w-full text-left"><tbody>${rows}</tbody></table>
  </div>`;
}

function formatRelativeTime(ts) {
  const diff = Date.now() - new Date(ts).getTime();
  if (diff < 60000) return "just now";
  if (diff < 3600000) return Math.floor(diff / 60000) + "m ago";
  if (diff < 86400000) return Math.floor(diff / 3600000) + "h ago";
  return Math.floor(diff / 86400000) + "d ago";
}

/**
 * Plan Forge — Team Dashboard (Phase-TEAM-DASHBOARD, v3.4.0)
 *
 * Server-side aggregation for the multi-developer plan coordination dashboard.
 * Reads team-activity.jsonl, groups by operator, computes per-developer stats,
 * and detects coordination risk when multiple developers are concurrently active.
 *
 * Exports:
 *   aggregateTeamActivity(activities)             → per-operator stats array
 *   detectConflictRisk(operators)                 → { level, active_count, message }
 *   buildTeamDashboard({ storeDir, limit, since }) → full dashboard payload
 */

import { loadActivity } from "../team-activity.mjs";

const RECENT_WINDOW_MS = 8 * 60 * 60 * 1000; // 8 hours for conflict detection

/**
 * Group a flat activity array by operator and compute per-developer stats.
 * @param {Array} activities  — from loadActivity(), newest-first
 * @returns {Array} operators sorted by last_active descending
 */
export function aggregateTeamActivity(activities) {
  const todayStart = new Date();
  todayStart.setHours(0, 0, 0, 0);

  const byOp = new Map();

  for (const a of activities) {
    const key = a.operator || "unknown";
    if (!byOp.has(key)) {
      byOp.set(key, {
        operator: key,
        last_active: null,
        runs_total: 0,
        runs_today: 0,
        runs_completed: 0,
        runs_failed: 0,
        total_cost_usd: 0,
        recent_plans: [],
      });
    }

    const entry = byOp.get(key);
    const ts = new Date(a.timestamp);

    entry.runs_total++;

    if (!entry.last_active || ts > new Date(entry.last_active)) {
      entry.last_active = a.timestamp;
    }

    if (ts >= todayStart) entry.runs_today++;

    if (a.status === "completed") entry.runs_completed++;
    else if (a.status === "failed" || a.status === "aborted") entry.runs_failed++;

    if (a.cost_usd) entry.total_cost_usd += Number(a.cost_usd);

    if (a.plan && !entry.recent_plans.includes(a.plan) && entry.recent_plans.length < 3) {
      entry.recent_plans.push(a.plan);
    }
  }

  return Array.from(byOp.values())
    .sort((a, b) => {
      const aMs = a.last_active ? Date.parse(a.last_active) : 0;
      const bMs = b.last_active ? Date.parse(b.last_active) : 0;
      return bMs - aMs;
    })
    .map((e) => ({
      ...e,
      total_cost_usd: Math.round(e.total_cost_usd * 100) / 100,
    }));
}

/**
 * Compute coordination risk level based on how many operators have been
 * active within the RECENT_WINDOW_MS window.
 * @param {Array} operators — output of aggregateTeamActivity()
 * @returns {{ level: string, active_count: number, message: string }}
 */
export function detectConflictRisk(operators) {
  const now = Date.now();
  const recentlyActive = operators.filter(
    (op) => op.last_active && now - Date.parse(op.last_active) < RECENT_WINDOW_MS
  );
  const count = recentlyActive.length;

  if (count >= 3) {
    return {
      level: "high",
      active_count: count,
      message: `${count} developers active in the last 8 h — high coordination risk. Sync before starting new plan runs.`,
    };
  }
  if (count === 2) {
    return {
      level: "medium",
      active_count: count,
      message: `${count} developers active in the last 8 h — coordinate before overlapping plan runs.`,
    };
  }
  if (count === 1) {
    return {
      level: "low",
      active_count: count,
      message: "Single developer active — no coordination needed.",
    };
  }
  return {
    level: "none",
    active_count: 0,
    message: "No recent activity in the last 8 h.",
  };
}

/**
 * Build the full team-dashboard payload.
 * @param {{ storeDir?: string, limit?: number, since?: string }} opts
 * @returns {{ ok, operators, conflict_risk, summary, message }}
 */
export function buildTeamDashboard({ storeDir, limit = 50, since } = {}) {
  const activities = loadActivity({ storeDir, limit, since });
  const operators = aggregateTeamActivity(activities);
  const conflict_risk = detectConflictRisk(operators);

  const todayStart = new Date();
  todayStart.setHours(0, 0, 0, 0);
  const todayActivities = activities.filter((a) => new Date(a.timestamp) >= todayStart);
  const completedToday = todayActivities.filter((a) => a.status === "completed").length;
  const active24h = operators.filter(
    (op) => op.last_active && Date.now() - Date.parse(op.last_active) < 24 * 60 * 60 * 1000
  ).length;
  const totalCost = Math.round(operators.reduce((s, op) => s + op.total_cost_usd, 0) * 100) / 100;

  return {
    ok: true,
    operators,
    conflict_risk,
    summary: {
      total_runs_today: todayActivities.length,
      active_operators: active24h,
      total_cost_usd: totalCost,
      success_rate:
        todayActivities.length > 0
          ? Math.round((completedToday / todayActivities.length) * 100)
          : null,
    },
    message:
      operators.length > 0
        ? `${operators.length} developer(s) tracked. ${conflict_risk.message}`
        : "No team activity recorded yet. Activity appears after the first plan run.",
  };
}

export const CATEGORIES = [
  "leaked-secret",
  "prompt-injection-echo",
  "license-incompatible-paste",
  "eval-exec-introduced",
  "unexpected-network-call",
  "large-binary-dump",
];

export const SEVERITY_ORDER = ["none", "low", "medium", "high", "critical"];

const CATEGORY_SEVERITY = {
  "leaked-secret": "critical",
  "prompt-injection-echo": "high",
  "license-incompatible-paste": "high",
  "eval-exec-introduced": "medium",
  "unexpected-network-call": "low",
  "large-binary-dump": "medium",
};

const SECRET_PATTERNS = [
  { regex: /-----BEGIN[^\n]*PRIVATE KEY-----/, detail: "Private key block detected" },
  { regex: /AKIA[0-9A-Z]{16}/, detail: "AWS access key pattern detected" },
  { regex: /ghp_[A-Za-z0-9]{36}/, detail: "GitHub PAT pattern detected" },
  {
    regex: /(password|secret|api_key|access_token|private_key)\s*[=:]\s*['"][^'"]{16,}['"]/i,
    detail: "Credential assignment detected",
  },
];

const PROMPT_PATTERNS = [
  /ignore (previous|prior|all) instructions/i,
  /\[SYSTEM\]/,
  /\[INST\]/,
  /<\|system\|>/,
  /act as .{0,30}(DAN|jailbreak|without restrictions)/i,
];

const EXEC_PATTERNS = [
  { regex: /\beval\s*\(/, detail: "eval() introduced" },
  { regex: /\bnew Function\s*\(/, detail: "new Function() introduced" },
  { regex: /\bexec\s*\(.*['"`]/, detail: "exec() with string literal detected" },
  { regex: /__import__\s*\(/, detail: "__import__() introduced" },
  { regex: /getattr\s*\(.*__/, detail: "getattr(..., __*) pattern detected" },
];

const NETWORK_PATTERN = /(fetch|axios)\s*\(\s*['"`]https?:\/\/(?!localhost|127\.0\.0\.1|api\.openai|api\.anthropic|api\.github|githubusercontent)/i;
const URL_PATTERN = /new URL\s*\(\s*['"`]https?:\/\/(?!localhost|127\.0\.0\.1|api\.openai|api\.anthropic|api\.github|githubusercontent)/i;
const GPL_MARKER = /(GPL|GNU General Public License|AGPL|LGPL)/i;
const GPL_LICENSE_TEXT = /(This (file|program|software|library) is free software|under the terms of the GNU)/i;

export function maxSeverity(a, b) {
  return SEVERITY_ORDER.indexOf(a) >= SEVERITY_ORDER.indexOf(b) ? a : b;
}

function pushFinding(findings, category, detail) {
  findings.push({ category, severity: CATEGORY_SEVERITY[category], detail });
}

function getAddedLines(lines) {
  return lines.filter((line) => line.startsWith("+") && !line.startsWith("+++")).map((line) => line.slice(1));
}

function isLargeBase64Line(line) {
  if (line.length < 500) return false;
  let base64Count = 0;
  for (const ch of line) {
    if ((ch >= "A" && ch <= "Z") || (ch >= "a" && ch <= "z") || (ch >= "0" && ch <= "9") || ch === "+" || ch === "/" || ch === "=") {
      base64Count += 1;
    }
  }
  return base64Count / line.length >= 0.8;
}

export function classifyDiff(diff, options = {}) {
  const maxLines = Number.isFinite(options.maxLines) ? Math.max(0, Math.floor(options.maxLines)) : 3000;
  const lines = typeof diff === "string" && diff.length > 0 ? diff.split(/\r?\n/) : [];
  const truncated = lines.length > maxLines;
  const limitedLines = truncated ? lines.slice(0, maxLines) : lines;
  const addedLines = getAddedLines(limitedLines);
  const findings = [];
  let severity = "none";
  let sawGplMarker = false;
  let sawGplLicenseText = false;

  for (const line of addedLines) {
    for (const pattern of SECRET_PATTERNS) {
      if (pattern.regex.test(line)) {
        pushFinding(findings, "leaked-secret", pattern.detail);
        severity = maxSeverity(severity, CATEGORY_SEVERITY["leaked-secret"]);
      }
    }

    if (PROMPT_PATTERNS.some((pattern) => pattern.test(line))) {
      pushFinding(findings, "prompt-injection-echo", "Prompt-injection echo pattern detected");
      severity = maxSeverity(severity, CATEGORY_SEVERITY["prompt-injection-echo"]);
    }

    for (const pattern of EXEC_PATTERNS) {
      if (pattern.regex.test(line)) {
        pushFinding(findings, "eval-exec-introduced", pattern.detail);
        severity = maxSeverity(severity, CATEGORY_SEVERITY["eval-exec-introduced"]);
      }
    }

    if (GPL_MARKER.test(line)) sawGplMarker = true;
    if (GPL_LICENSE_TEXT.test(line)) sawGplLicenseText = true;

    if (NETWORK_PATTERN.test(line) || URL_PATTERN.test(line)) {
      pushFinding(findings, "unexpected-network-call", "Hardcoded external network call detected");
      severity = maxSeverity(severity, CATEGORY_SEVERITY["unexpected-network-call"]);
    }

    if (isLargeBase64Line(line)) {
      pushFinding(findings, "large-binary-dump", "Large base64-like added line detected");
      severity = maxSeverity(severity, CATEGORY_SEVERITY["large-binary-dump"]);
    }
  }

  if (sawGplMarker && sawGplLicenseText) {
    pushFinding(findings, "license-incompatible-paste", "GPL-family license header detected in added lines");
    severity = maxSeverity(severity, CATEGORY_SEVERITY["license-incompatible-paste"]);
  }

  return {
    severity,
    findings,
    totalAdded: addedLines.length,
    truncated,
  };
}

/**
 * Plan Forge — Daily Digest Aggregator (Phase-38.5 Slice 1)
 *
 * Builds a structured digest covering five sections:
 *   1. probe-deltas   — lane-match regressions between two probe result sets
 *   2. aging-bugs     — meta-bugs open > 7 days
 *   3. stalled-phases — roadmap phases in-progress > 14 days
 *   4. drift-trend    — drift score drops below threshold
 *   5. cost-anomaly   — cost spikes > 2× the 7-day moving average
 *
 * Pure reader — never modifies any artifact.
 *
 * @module digest/aggregator
 */

import { existsSync, readFileSync, readdirSync, statSync } from "node:fs";
import { resolve, basename } from "node:path";

// ─── Helpers ──────────────────────────────────────────────────────────

function safeReadJson(filePath) {
  try {
    return JSON.parse(readFileSync(filePath, "utf-8"));
  } catch {
    return null;
  }
}

function safeReadJsonl(filePath) {
  try {
    const raw = readFileSync(filePath, "utf-8").trim();
    if (!raw) return [];
    return raw.split("\n").map((line) => {
      try { return JSON.parse(line); } catch { return null; }
    }).filter(Boolean);
  } catch {
    return [];
  }
}

function listJsonFiles(dirPath) {
  try {
    if (!existsSync(dirPath)) return [];
    return readdirSync(dirPath)
      .filter((f) => f.endsWith(".json"))
      .map((f) => resolve(dirPath, f));
  } catch {
    return [];
  }
}

function daysBetween(a, b) {
  return Math.abs(a - b) / (1000 * 60 * 60 * 24);
}

function isoDate(d) {
  return d instanceof Date ? d.toISOString().slice(0, 10) : String(d).slice(0, 10);
}

// ─── Section: probe-deltas ────────────────────────────────────────────

function findProbeResultByDate(validationDir, dateStr) {
  if (!existsSync(validationDir)) return null;
  const files = readdirSync(validationDir)
    .filter((f) => f.startsWith("results-") && f.endsWith(".json"))
    .sort();

  // Find the latest result file whose timestamp matches dateStr
  const matching = files.filter((f) => f.includes(dateStr));
  if (matching.length > 0) {
    return safeReadJson(resolve(validationDir, matching[matching.length - 1]));
  }

  // Fallback: find the latest result file on or before dateStr
  const beforeOrOn = files.filter((f) => {
    const ts = f.replace("results-", "").replace(".json", "").slice(0, 10);
    return ts <= dateStr;
  });
  if (beforeOrOn.length > 0) {
    return safeReadJson(resolve(validationDir, beforeOrOn[beforeOrOn.length - 1]));
  }
  return null;
}

function computeLaneMatch(probeResults) {
  if (!Array.isArray(probeResults)) return {};
  const counts = {};
  for (const r of probeResults) {
    const expected = r.probe?.lane;
    const actual = r.classification?.lane;
    if (!expected) continue;
    if (!counts[expected]) counts[expected] = { matched: 0, total: 0 };
    counts[expected].total++;
    if (actual === expected) counts[expected].matched++;
  }
  return counts;
}

function buildProbeDeltas(projectDir, dateStr, baselineDateStr) {
  const section = { id: "probe-deltas", title: "Probe Lane-Match Deltas", severity: "info", items: [] };
  const validationDir = resolve(projectDir, ".forge", "validation");

  const current = findProbeResultByDate(validationDir, dateStr);
  const baseline = findProbeResultByDate(validationDir, baselineDateStr);

  if (!current || !baseline) return section;

  const currentCounts = computeLaneMatch(current);
  const baselineCounts = computeLaneMatch(baseline);

  const allLanes = new Set([...Object.keys(currentCounts), ...Object.keys(baselineCounts)]);
  for (const lane of allLanes) {
    const cur = currentCounts[lane] || { matched: 0, total: 0 };
    const base = baselineCounts[lane] || { matched: 0, total: 0 };
    const curRate = cur.total > 0 ? cur.matched / cur.total : 0;
    const baseRate = base.total > 0 ? base.matched / base.total : 0;
    const delta = curRate - baseRate;

    if (delta < 0) {
      section.items.push({
        lane,
        currentRate: Math.round(curRate * 100),
        baselineRate: Math.round(baseRate * 100),
        delta: Math.round(delta * 100),
      });
      section.severity = "warn";
    }
  }

  if (section.items.length === 0) section.severity = "info";
  return section;
}

// ─── Section: aging-bugs ──────────────────────────────────────────────

function buildAgingBugs(projectDir, dateStr) {
  const section = { id: "aging-bugs", title: "Aging Meta-Bugs", severity: "info", items: [] };
  const bugsDir = resolve(projectDir, ".forge", "bugs");
  const files = listJsonFiles(bugsDir);
  const now = new Date(dateStr + "T00:00:00Z");

  for (const f of files) {
    const bug = safeReadJson(f);
    if (!bug) continue;
    if (bug.status !== "open") continue;

    const created = bug.createdAt || bug.created_at || bug.timestamp;
    if (!created) continue;

    const age = daysBetween(now, new Date(created));
    if (age >= 7) {
      section.items.push({
        id: bug.id || basename(f, ".json"),
        title: bug.title || bug.summary || basename(f, ".json"),
        ageDays: Math.floor(age),
        severity: bug.severity || "medium",
      });
    }
  }

  if (section.items.length > 0) {
    section.severity = section.items.some((i) => i.ageDays > 30) ? "alert" : "warn";
  }
  return section;
}

// ─── Section: stalled-phases ──────────────────────────────────────────

function parseRoadmapPhases(projectDir) {
  const candidates = [
    resolve(projectDir, "docs", "plans", "DEPLOYMENT-ROADMAP.md"),
    resolve(projectDir, "ROADMAP.md"),
  ];

  for (const roadmapPath of candidates) {
    if (!existsSync(roadmapPath)) continue;
    try {
      const content = readFileSync(roadmapPath, "utf-8");
      return extractInProgressPhases(content);
    } catch {
      continue;
    }
  }
  return [];
}

function extractInProgressPhases(content) {
  const phases = [];
  // Match patterns like "Phase-NN" or "v2.XX.X" with "in-progress" or "In flight" or similar markers
  const lines = content.split("\n");
  for (const line of lines) {
    const lower = line.toLowerCase();
    if (lower.includes("in-progress") || lower.includes("in flight") || lower.includes("in progress")) {
      // Try to extract phase reference and date
      const phaseMatch = line.match(/Phase[- ]?([\d.]+\S*)/i);
      const dateMatch = line.match(/\b(20\d{2}-\d{2}-\d{2})\b/);
      const versionMatch = line.match(/v(\d+\.\d+(?:\.\d+)?)/);

      phases.push({
        name: phaseMatch ? `Phase-${phaseMatch[1]}` : (versionMatch ? `v${versionMatch[1]}` : line.trim().slice(0, 80)),
        startDate: dateMatch ? dateMatch[1] : null,
        raw: line.trim(),
      });
    }
  }
  return phases;
}

function buildStalledPhases(projectDir, dateStr) {
  const section = { id: "stalled-phases", title: "Stalled Phases", severity: "info", items: [] };
  const now = new Date(dateStr + "T00:00:00Z");
  const phases = parseRoadmapPhases(projectDir);

  for (const phase of phases) {
    if (!phase.startDate) continue;
    const start = new Date(phase.startDate + "T00:00:00Z");
    const age = daysBetween(now, start);

    if (age >= 14) {
      section.items.push({
        name: phase.name,
        startDate: phase.startDate,
        ageDays: Math.floor(age),
      });
    }
  }

  if (section.items.length > 0) {
    section.severity = section.items.some((i) => i.ageDays > 30) ? "alert" : "warn";
  }
  return section;
}

// ─── Section: drift-trend ─────────────────────────────────────────────

function buildDriftTrend(projectDir, dateStr, opts = {}) {
  const threshold = opts.driftThreshold ?? 15;
  const section = { id: "drift-trend", title: "Drift Trend", severity: "info", items: [] };
  const driftPath = resolve(projectDir, ".forge", "drift-history.json");
  const entries = safeReadJsonl(driftPath);
  if (entries.length === 0) return section;

  // Find entries on or before dateStr
  const relevant = entries.filter((e) => {
    const ts = (e.timestamp || "").slice(0, 10);
    return ts <= dateStr;
  });

  if (relevant.length === 0) return section;

  const latest = relevant[relevant.length - 1];
  if (typeof latest.score === "number" && latest.score > threshold) {
    section.items.push({
      score: latest.score,
      threshold,
      trend: latest.trend || "unknown",
      timestamp: latest.timestamp,
      violationCount: Array.isArray(latest.violations) ? latest.violations.length : 0,
    });
    section.severity = latest.score > threshold * 2 ? "alert" : "warn";
  }

  return section;
}

// ─── Section: cost-anomaly ────────────────────────────────────────────

function buildCostAnomaly(projectDir, dateStr) {
  const section = { id: "cost-anomaly", title: "Cost Anomaly", severity: "info", items: [] };
  const costPath = resolve(projectDir, ".forge", "cost-history.json");
  const entries = safeReadJson(costPath);
  if (!Array.isArray(entries) || entries.length === 0) return section;

  // Sort by date ascending
  const sorted = [...entries]
    .filter((e) => e.date)
    .sort((a, b) => a.date.localeCompare(b.date));

  // Filter entries on or before dateStr
  const relevant = sorted.filter((e) => (e.date || "").slice(0, 10) <= dateStr);
  if (relevant.length === 0) return section;

  const latest = relevant[relevant.length - 1];
  const latestDate = (latest.date || "").slice(0, 10);

  // Compute 7-day moving average (entries before latest)
  const sevenDayAgo = new Date(latestDate + "T00:00:00Z");
  sevenDayAgo.setDate(sevenDayAgo.getDate() - 7);
  const sevenDayStr = isoDate(sevenDayAgo);

  const windowEntries = relevant.filter((e) => {
    const d = (e.date || "").slice(0, 10);
    return d >= sevenDayStr && d < latestDate;
  });

  if (windowEntries.length === 0) return section;

  const avgCost = windowEntries.reduce((sum, e) => sum + (e.total_cost_usd || 0), 0) / windowEntries.length;
  const latestCost = latest.total_cost_usd || 0;

  if (avgCost > 0 && latestCost > avgCost * 2) {
    section.items.push({
      latestCost: Math.round(latestCost * 100) / 100,
      averageCost: Math.round(avgCost * 100) / 100,
      multiplier: Math.round((latestCost / avgCost) * 10) / 10,
      plan: latest.plan || "unknown",
      date: latestDate,
    });
    section.severity = latestCost > avgCost * 5 ? "alert" : "warn";
  }

  return section;
}

// ─── Public API ───────────────────────────────────────────────────────

/**
 * Build the daily digest for a project.
 *
 * @param {object} opts
 * @param {string} opts.projectDir - Project root directory
 * @param {string} opts.date       - ISO date string (YYYY-MM-DD) for the digest
 * @param {string} opts.baselineDate - ISO date string for probe comparison baseline
 * @param {object} [opts.thresholds] - Optional thresholds override
 * @returns {{ sections: Array<{id: string, title: string, severity: string, items: any[]}>, generatedAt: string }}
 */
export function buildDigest({ projectDir, date, baselineDate, thresholds = {} }) {
  const dateStr = isoDate(date);
  const baselineDateStr = baselineDate ? isoDate(baselineDate) : dateStr;

  const sections = [
    buildProbeDeltas(projectDir, dateStr, baselineDateStr),
    buildAgingBugs(projectDir, dateStr),
    buildStalledPhases(projectDir, dateStr),
    buildDriftTrend(projectDir, dateStr, { driftThreshold: thresholds.drift }),
    buildCostAnomaly(projectDir, dateStr),
  ];

  return {
    sections,
    generatedAt: new Date().toISOString(),
  };
}

/**
 * Plan Forge — Daily Digest Renderer (Phase-38.5 Slice 2)
 *
 * Converts a digest object (from aggregator.mjs) into human-readable
 * Markdown or a stable machine-readable JSON format.
 *
 * @module digest/render
 */

// ─── Severity badges ─────────────────────────────────────────────────

const SEVERITY_BADGE = {
  info:  "🟢 info",
  warn:  "🟡 warn",
  alert: "🔴 alert",
};

function badge(severity) {
  return SEVERITY_BADGE[severity] || severity;
}

// ─── Markdown item renderers (per section id) ────────────────────────

const ITEM_RENDERERS = {
  "probe-deltas"(item) {
    return `- **${item.lane}**: ${item.currentRate}% → was ${item.baselineRate}% (Δ ${item.delta}%)`;
  },
  "aging-bugs"(item) {
    return `- **${item.id}** — ${item.title} (${item.ageDays} days, severity: ${item.severity})`;
  },
  "stalled-phases"(item) {
    return `- **${item.name}** — started ${item.startDate}, stalled ${item.ageDays} days`;
  },
  "drift-trend"(item) {
    return `- Score **${item.score}** (threshold ${item.threshold}) — trend: ${item.trend}, violations: ${item.violationCount}`;
  },
  "cost-anomaly"(item) {
    return `- **$${item.latestCost}** on ${item.date} — ${item.multiplier}× the 7-day avg ($${item.averageCost}), plan: ${item.plan}`;
  },
};

function renderItem(sectionId, item) {
  const renderer = ITEM_RENDERERS[sectionId];
  return renderer ? renderer(item) : `- ${JSON.stringify(item)}`;
}

// ─── Public API ───────────────────────────────────────────────────────

/**
 * Render a digest as human-readable Markdown.
 *
 * @param {{ sections: Array<{id: string, title: string, severity: string, items: any[]}>, generatedAt: string }} digest
 * @returns {string} Markdown string
 */
export function renderMarkdown(digest) {
  const lines = ["# Daily Digest", ""];

  let allGreen = true;

  for (const section of digest.sections) {
    lines.push(`## ${section.title}  ${badge(section.severity)}`);
    lines.push("");

    if (section.items.length === 0) {
      lines.push("No issues detected.");
    } else {
      allGreen = false;
      for (const item of section.items) {
        lines.push(renderItem(section.id, item));
      }
    }
    lines.push("");
  }

  if (allGreen) {
    lines.push("## Summary");
    lines.push("");
    lines.push("✅ All green — no significant deltas detected.");
    lines.push("");
  }

  lines.push("---");
  lines.push(`*Generated at ${digest.generatedAt} (UTC)*`);
  lines.push("");

  return lines.join("\n");
}

/**
 * Render a digest as a stable machine-readable JSON object.
 *
 * @param {{ sections: Array<{id: string, title: string, severity: string, items: any[]}>, generatedAt: string }} digest
 * @returns {{ version: string, date: string, sections: Array<{id: string, title: string, severity: string, items: any[]}> }}
 */
export function renderJson(digest) {
  const date = digest.generatedAt
    ? digest.generatedAt.slice(0, 10)
    : new Date().toISOString().slice(0, 10);

  return {
    version: "1",
    date,
    sections: digest.sections.map((s) => ({
      id: s.id,
      title: s.title,
      severity: s.severity,
      items: s.items,
    })),
  };
}

/**
 * Plan Forge — Export Plan
 *
 * Converts a loose plan (e.g., from a Copilot cloud agent session) into a
 * hardened Plan Forge `Phase-X-PLAN.md` document.
 *
 * Input: Markdown text with a title (# heading) and steps (numbered or
 *   bulleted list).
 * Output: A fully-scaffolded Plan Forge plan with scope contract, forbidden
 *   actions template, per-step slices, validation gates, and a files table.
 *
 * @module export-plan
 */

import { existsSync, readFileSync, writeFileSync, mkdirSync } from "node:fs";
import { resolve, dirname, extname, basename } from "node:path";

// ─── Path Extraction ──────────────────────────────────────────────────────────

/**
 * Regex patterns for file path extraction.
 * Order matters — more-specific patterns first.
 */
const PATH_PATTERNS = [
  // Backtick-quoted paths: `src/foo.ts`
  /`([a-zA-Z0-9_./\\-]+\.[a-zA-Z0-9]{1,10})`/g,
  // Straight-quoted paths: "src/foo.ts" or 'src/foo.ts'
  /["']([a-zA-Z0-9_./\\-]+\.[a-zA-Z0-9]{1,10})["']/g,
  // Bare paths that start with known root segments: src/, lib/, test/, docs/, pforge-mcp/, .github/
  /\b((?:src|lib|tests?|spec|docs|scripts|pforge-mcp|pforge-sdk|\.github|\.forge|templates)\/[a-zA-Z0-9_./-]+\.[a-zA-Z0-9]{1,10})\b/g,
];

const IGNORED_EXTENSIONS = new Set([".md", ".txt", ".html", ".svg", ".png", ".jpg", ".gif", ".ico"]);
const TEST_EXTENSIONS_RE = /\.(test|spec)\.[a-z]+$/;
const DOC_EXTENSIONS_RE = /\.(md|html|txt|svg|png|jpg|gif|ico)$/;

/**
 * Extract file paths mentioned in a piece of text.
 *
 * @param {string} text
 * @returns {string[]} Deduplicated file paths (order of first appearance)
 */
export function extractPaths(text) {
  const seen = new Set();
  const paths = [];

  for (const pattern of PATH_PATTERNS) {
    pattern.lastIndex = 0;
    let m;
    while ((m = pattern.exec(text)) !== null) {
      const p = m[1].replace(/\\/g, "/").replace(/^\/+/, "");
      if (!seen.has(p)) {
        seen.add(p);
        paths.push(p);
      }
    }
  }

  return paths;
}

// ─── Step Parsing ─────────────────────────────────────────────────────────────

/**
 * Parse steps from a loose plan text. Recognises:
 *   - Numbered lists  (1. / 2. / 3.)
 *   - Checkbox items  (- [ ] / - [x])
 *   - Bulleted items  (- / * / •)
 *   - Sub-headings    (## / ###) when no list items are found
 *
 * @param {string} text
 * @returns {string[]} Ordered list of step strings (trimmed, no list prefix)
 */
export function parseSteps(text) {
  const lines = text.split(/\r?\n/);
  const steps = [];

  for (const line of lines) {
    const trimmed = line.trim();
    // Numbered: "1. ...", "10. ..."
    const numbered = /^\d+\.\s+(.+)/.exec(trimmed);
    if (numbered) { steps.push(numbered[1].trim()); continue; }

    // Checkbox: "- [ ] ..." or "- [x] ..."
    const checkbox = /^[-*]\s+\[[ xX]\]\s+(.+)/.exec(trimmed);
    if (checkbox) { steps.push(checkbox[1].trim()); continue; }

    // Bulleted: "- ..." or "* ..." or "• ..."
    const bulleted = /^[-*•]\s+(.+)/.exec(trimmed);
    if (bulleted) {
      const txt = bulleted[1].trim();
      if (txt) { steps.push(txt); }
      continue;
    }
  }

  // Fallback: treat sub-headings (## / ###) as steps if no list was found
  if (steps.length === 0) {
    for (const line of lines) {
      const heading = /^#{2,3}\s+(.+)/.exec(line.trim());
      if (heading) {
        const txt = heading[1].trim();
        if (txt && !["plan", "steps", "tasks", "implementation", "overview"].includes(txt.toLowerCase())) {
          steps.push(txt);
        }
      }
    }
  }

  return steps;
}

/**
 * Parse the title from the first `#` heading in the text.
 *
 * @param {string} text
 * @returns {string} Title or "Untitled Feature"
 */
export function parseTitle(text) {
  for (const line of text.split(/\r?\n/)) {
    const m = /^#\s+(.+)/.exec(line.trim());
    if (m) return m[1].trim();
  }
  // Fallback: first non-empty non-heading line
  for (const line of text.split(/\r?\n/)) {
    const t = line.trim();
    if (t && !t.startsWith("#")) return t.slice(0, 80);
  }
  return "Untitled Feature";
}

// ─── Phase Name Derivation ───────────────────────────────────────────────────

const STOP_WORDS = new Set([
  "a", "an", "the", "and", "or", "but", "in", "on", "at", "to", "for",
  "of", "with", "by", "from", "up", "about", "into", "through", "during",
  "add", "adding", "update", "updating", "implement", "implementing",
  "create", "creating", "build", "building", "fix", "fixing", "refactor",
  "new", "support", "enable", "use", "using",
]);

/**
 * Derive a Plan Forge phase name slug from a title.
 * "Add rate limiting to the REST API" → "RATE-LIMIT-REST-API"
 *
 * @param {string} title
 * @returns {string} Uppercase hyphenated slug (max 4 words)
 */
export function derivePhaseSlug(title) {
  const words = title
    .replace(/[^a-zA-Z0-9\s]/g, " ")
    .split(/\s+/)
    .map((w) => w.toLowerCase())
    .filter((w) => w.length > 2 && !STOP_WORDS.has(w));

  return words
    .slice(0, 4)
    .map((w) => w.toUpperCase())
    .join("-") || "FEATURE";
}

// ─── Validation Gate Generation ──────────────────────────────────────────────

/**
 * Generate a validation gate for a slice based on its files.
 *
 * @param {string[]} files Paths mentioned in this slice
 * @param {string}   stepText Original step text
 * @returns {string} Shell command block (bash-compatible)
 */
export function buildGate(files, stepText) {
  const testFiles = files.filter((f) => TEST_EXTENSIONS_RE.test(f));
  const codeFiles = files.filter((f) => !DOC_EXTENSIONS_RE.test(f) && !TEST_EXTENSIONS_RE.test(f));

  // Test file → run vitest
  if (testFiles.length > 0) {
    const testArg = testFiles.map((f) => f.replace(/^pforge-mcp\//, "")).join(" ");
    return `cd pforge-mcp && npx vitest run ${testArg} --reporter=dot 2>&1 | tail -5 | grep -qE 'Test Files.*passed' && echo ok`;
  }

  // Code files → existence check
  if (codeFiles.length > 0) {
    const checks = codeFiles.map((f) => `test -f ${f}`).join(" && ");
    return `${checks} && echo ok`;
  }

  // Default placeholder gate
  return `node -e "console.log('ok')" # TODO: replace with a real validation command`;
}

// ─── Slice Builder ───────────────────────────────────────────────────────────

/**
 * @typedef {Object} Slice
 * @property {number}   number    Slice ordinal (1-based)
 * @property {string}   goal      Human description (the raw step text)
 * @property {string[]} files     File paths extracted from the step
 * @property {string}   gate      Shell command for the validation gate
 * @property {boolean}  isNew     True for any file marked new (no indicator → assume new)
 */

/**
 * Build a Slice descriptor from a step string.
 *
 * @param {string} step Step text
 * @param {number} n    Slice ordinal (1-based)
 * @returns {Slice}
 */
export function buildSlice(step, n) {
  const files = extractPaths(step);
  const gate = buildGate(files, step);
  const isNew = /\bnew\b|create|add|introduce/i.test(step);

  return { number: n, goal: step, files, gate, isNew };
}

// ─── Document Renderer ───────────────────────────────────────────────────────

const TODAY = new Date().toISOString().slice(0, 10);

/**
 * Format a single slice section in Plan Forge style.
 *
 * @param {Slice}  slice
 * @param {Slice|null} prevSlice  Preceding slice (for Depends On chain)
 * @returns {string}
 */
function renderSlice(slice, prevSlice) {
  const filesBlock =
    slice.files.length > 0
      ? slice.files.map((f) => `- \`${f}\`${slice.isNew ? " (new)" : ""}`).join("\n")
      : "- <!-- TODO: list affected files -->";

  const dependsOn = prevSlice ? `\n**Depends On**: Slice ${prevSlice.number}\n` : "";

  return `### Slice ${slice.number}: ${slice.goal} [sequential]

**Goal**: ${slice.goal}.

**Files**:
${filesBlock}
${dependsOn}
**Validation Gate**:
\`\`\`bash
${slice.gate}
\`\`\`

---`;
}

/**
 * Render a full hardened Plan Forge plan document.
 *
 * @param {Object} params
 * @param {string}   params.title       Feature title
 * @param {string}   params.phaseSlug   UPPERCASE-SLUG for phase name
 * @param {string}   params.description Optional description text from input
 * @param {Slice[]}  params.slices
 * @param {string[]} params.allFiles    Union of files across all slices (deduplicated)
 * @param {string}   [params.sourceNote] Attribution note (e.g. "Exported from Copilot cloud agent session plan")
 * @returns {string}
 */
function renderPlan({ title, phaseSlug, description, slices, allFiles, sourceNote }) {
  const codeFiles = allFiles.filter((f) => !DOC_EXTENSIONS_RE.test(f));
  const docFiles = allFiles.filter((f) => DOC_EXTENSIONS_RE.test(f));

  const inScopeLines =
    codeFiles.length > 0
      ? codeFiles.map((f) => `- \`${f}\``).join("\n")
      : "- <!-- TODO: list files in scope -->";

  const filesTable =
    allFiles.length > 0
      ? allFiles.map((f, i) => `| \`${f}\` | ${i + 1} |`).join("\n")
      : "| <!-- TODO --> | 1 |";

  const sliceSections = slices
    .map((s, i) => renderSlice(s, i > 0 ? slices[i - 1] : null))
    .join("\n\n");

  const descriptionNote = description ? `\n${description}\n` : "";
  const sourceAttr = sourceNote ? `\n> **Source**: ${sourceNote}` : "";

  return `# Phase-${phaseSlug}: ${title} (HARDENED)

> **Status**: Hardened, ready for execution (Step 3)
> **Tracks**: Code + Tests + Docs
> **Estimated cost**: TBD (${slices.length} slices)
> **Pipeline**: Specify ✅ → Pre-flight ✅ → **Harden ✅** → Execute → Sweep → Review → Ship
> **Exported**: ${TODAY}${sourceAttr}

---
${descriptionNote}
## Scope Contract

### In Scope

${inScopeLines}

### Out of Scope

- <!-- TODO: list what is explicitly NOT in scope -->

### Forbidden Actions

- **Do NOT break existing tests.** All existing tests must pass after each slice.
- **Do NOT add dependencies** without documenting the reason here.
- **Do NOT skip validation gates.** Each slice gate must pass before the next slice begins.
- <!-- TODO: add project-specific forbidden actions -->

---

## Required Decisions

| # | Decision | Status | Resolution |
|---|---|---|---|
| 1 | <!-- Decision topic --> | OPEN | <!-- Decide before executing --> |

---

## Acceptance Criteria

${slices.map((s, i) => `- [ ] **Slice ${i + 1}**: ${s.goal}`).join("\n")}

---

## Execution Slices

${sliceSections}

---

## Files Modified (Exhaustive)

| File | Slice(s) |
|---|---|
${filesTable}

---

## Risks and Mitigations

| Risk | Mitigation |
|---|---|
| <!-- Risk --> | <!-- Mitigation --> |
`;
}

// ─── Public API ───────────────────────────────────────────────────────────────

/**
 * @typedef {Object} ExportPlanOptions
 * @property {string}  [phaseName]   Override the derived phase slug (UPPERCASE-SLUG)
 * @property {string}  [outputPath]  If given, write the plan to this file path
 * @property {string}  [cwd]         Working directory for resolving outputPath
 * @property {string}  [sourceNote]  Attribution text in the plan header
 */

/**
 * @typedef {Object} ExportPlanResult
 * @property {boolean}  ok
 * @property {string}   plan        The rendered Plan Forge Markdown
 * @property {string}   title       Parsed title
 * @property {string}   phaseSlug   Derived or overridden phase slug
 * @property {number}   sliceCount  Number of slices generated
 * @property {string[]} files       All file paths extracted across all slices
 * @property {string}   [outputPath] Path written to (when opts.outputPath is set)
 * @property {string}   [error]
 */

/**
 * Convert a loose plan document into a hardened Plan Forge plan.
 *
 * @param {string}            input  Markdown text
 * @param {ExportPlanOptions} [opts]
 * @returns {ExportPlanResult}
 */
export function exportPlan(input, opts = {}) {
  if (typeof input !== "string" || !input.trim()) {
    return { ok: false, error: "Input must be a non-empty string" };
  }

  const title = parseTitle(input);
  const steps = parseSteps(input);
  const phaseSlug = opts.phaseName
    ? opts.phaseName.toUpperCase().replace(/\s+/g, "-")
    : derivePhaseSlug(title);

  if (steps.length === 0) {
    return {
      ok: false,
      error:
        "No steps found in the input. Provide a numbered list (1. 2. 3.) or bulleted list (- / * / •).",
    };
  }

  const slices = steps.map((step, i) => buildSlice(step, i + 1));

  const allFiles = deduplicate(slices.flatMap((s) => s.files));

  // Extract a description paragraph (first prose paragraph after the title)
  const description = extractDescription(input);

  const plan = renderPlan({
    title,
    phaseSlug,
    description,
    slices,
    allFiles,
    sourceNote: opts.sourceNote ?? "Exported from loose plan via forge_export_plan",
  });

  const result = {
    ok: true,
    plan,
    title,
    phaseSlug,
    sliceCount: slices.length,
    files: allFiles,
    message: `Exported ${slices.length}-slice plan for "${title}" (Phase-${phaseSlug})`,
  };

  if (opts.outputPath) {
    const cwd = opts.cwd ?? process.cwd();
    const outAbs = resolve(cwd, opts.outputPath);
    mkdirSync(dirname(outAbs), { recursive: true });
    writeFileSync(outAbs, plan, "utf-8");
    result.outputPath = outAbs;
    result.message += `. Written to ${outAbs}`;
  }

  return result;
}

/**
 * Read a loose plan from a file and export it.
 *
 * @param {string}            inputPath  Path to the loose plan Markdown file
 * @param {ExportPlanOptions} [opts]
 * @returns {ExportPlanResult}
 */
export function exportPlanFromFile(inputPath, opts = {}) {
  const cwd = opts.cwd ?? process.cwd();
  const absPath = resolve(cwd, inputPath);
  if (!existsSync(absPath)) {
    return { ok: false, error: `Input file not found: ${absPath}` };
  }
  const input = readFileSync(absPath, "utf-8");
  return exportPlan(input, opts);
}

// ─── Utilities ────────────────────────────────────────────────────────────────

function deduplicate(arr) {
  return [...new Set(arr)];
}

/**
 * Extract a short description paragraph from the loose plan text.
 * Looks for the first prose paragraph after the first heading.
 *
 * @param {string} text
 * @returns {string}
 */
function extractDescription(text) {
  const lines = text.split(/\r?\n/);
  let pastTitle = false;

  for (const line of lines) {
    const t = line.trim();
    if (!t) continue;

    if (t.startsWith("#")) {
      pastTitle = true;
      continue;
    }

    if (!pastTitle) continue;

    // Skip list items — those become steps
    if (/^(\d+\.|[-*•]|\[[ xX]\])/.test(t)) continue;

    // First non-empty non-heading non-list line after the title is the description
    return t.slice(0, 300);
  }

  return "";
}

/**
 * forge-tools/hotspot.mjs — Lattice augmentation for forge_hotspot.
 *
 * Adds { callerCount, calleeCount, inBlastOf } to each hotspot entry when a
 * Lattice index exists.  When the index is absent, input is returned unchanged
 * (additive-only contract — Scope Contract §MUST-1).
 */

import { existsSync, readFileSync } from 'node:fs';
import { resolve, join } from 'node:path';

const LATTICE_SUBDIR = join('.forge', 'lattice');

function latticeDir(deps = {}) {
  return resolve(deps.cwd ?? process.cwd(), LATTICE_SUBDIR);
}

function readJsonl(filePath) {
  if (!existsSync(filePath)) return [];
  return readFileSync(filePath, 'utf8')
    .split('\n')
    .filter(Boolean)
    .map((line) => { try { return JSON.parse(line); } catch { return null; } })
    .filter(Boolean);
}

/**
 * Augment an array of hotspot entries with Lattice call-graph metrics.
 *
 * Each augmented entry gains:
 *   - `callerCount`  {number}   Distinct external files that call into this file.
 *   - `calleeCount`  {number}   Distinct external files this file calls into.
 *   - `inBlastOf`    {string[]} Files whose change would put this file in their blast radius
 *                               (i.e., files that this file calls into).
 *
 * @param {Array<{ file: string, commits: number }>} hotspots
 * @param {{ deps?: { cwd?: string } }} [opts]
 * @returns {Array<object>}  Original entries + optional Lattice fields.
 */
export function augmentHotspots(hotspots, { deps = {} } = {}) {
  if (!Array.isArray(hotspots) || hotspots.length === 0) return hotspots ?? [];

  const dir = latticeDir(deps);
  const chunksPath = join(dir, 'chunks.jsonl');

  // Additive-only: if index absent, return hotspots unchanged.
  if (!existsSync(chunksPath)) return hotspots;

  const allChunks = readJsonl(chunksPath);
  const allEdges = readJsonl(join(dir, 'edges.jsonl'));

  // chunk id → filePath
  const chunkIdToFile = new Map(allChunks.map((c) => [c.id, c.filePath]));

  // callee name → Set of filePaths that declare a chunk with that name
  const nameToFiles = new Map();
  for (const c of allChunks) {
    if (c.name) {
      if (!nameToFiles.has(c.name)) nameToFiles.set(c.name, new Set());
      nameToFiles.get(c.name).add(c.filePath);
    }
  }

  // Per-file call-graph sets (cross-file edges only)
  // callerFiles[file]  = Set of files that call INTO this file
  // calleeFiles[file]  = Set of files that this file calls INTO
  const callerFiles = new Map(); // file → Set<file>
  const calleeFiles = new Map(); // file → Set<file>

  for (const edge of allEdges) {
    const callerFile = chunkIdToFile.get(edge.callerChunkId);
    const targetFiles = nameToFiles.get(edge.calleeName) ?? new Set();

    for (const targetFile of targetFiles) {
      if (!callerFile || callerFile === targetFile) continue;

      // outgoing: callerFile → targetFile
      if (!calleeFiles.has(callerFile)) calleeFiles.set(callerFile, new Set());
      calleeFiles.get(callerFile).add(targetFile);

      // incoming: targetFile ← callerFile
      if (!callerFiles.has(targetFile)) callerFiles.set(targetFile, new Set());
      callerFiles.get(targetFile).add(callerFile);
    }
  }

  return hotspots.map((hs) => {
    const callers = callerFiles.get(hs.file) ?? new Set();
    const callees = calleeFiles.get(hs.file) ?? new Set();
    return {
      ...hs,
      callerCount: callers.size,
      calleeCount: callees.size,
      // Files whose change would cascade to affect this file (this file calls into them).
      inBlastOf: [...callees],
    };
  });
}

/**
 * forge-tools/regression-guard.mjs — Lattice blast-radius augmentation for forge_regression_guard.
 *
 * Computes blastRadius for a set of changed files using the Lattice call graph.
 * When the index is absent, returns null so the caller omits the field entirely
 * (additive-only contract — Scope Contract §MUST-2).
 */

import { existsSync, readFileSync } from 'node:fs';
import { resolve, join } from 'node:path';
import { latticeBlast } from '../lattice.mjs';

const LATTICE_SUBDIR = join('.forge', 'lattice');

function readJsonl(filePath) {
  if (!existsSync(filePath)) return [];
  return readFileSync(filePath, 'utf8')
    .split('\n')
    .filter(Boolean)
    .map((line) => { try { return JSON.parse(line); } catch { return null; } })
    .filter(Boolean);
}

/** Heuristic: is this file a test file? */
function isTestFile(filePath) {
  return /\.(test|spec)\.[^.]+$/.test(filePath) ||
    /(^|[/\\])(tests?|__tests?__)[/\\]/.test(filePath);
}

/**
 * Compute the blast radius for a set of changed files using the Lattice call graph.
 *
 * Starting from the chunks belonging to each changed file, a BFS traversal in
 * the `callers` direction is run: files that call into a changed file could be
 * broken by that change and therefore appear in its blast radius.
 *
 * @param {string[]} changedFiles  Relative (or absolute) file paths that changed.
 * @param {{ depth?: number, limit?: number, deps?: { cwd?: string } }} [opts]
 * @returns {{
 *   files:     string[],   Non-test files in blast radius (changed files excluded).
 *   tests:     string[],   Test files in blast radius (changed files excluded).
 *   depth:     number,     BFS depth used.
 *   truncated: boolean,    True if any traversal hit the limit.
 * } | null}  null when no Lattice index is present.
 */
export function computeBlastRadius(changedFiles = [], { depth = 3, limit = 50, deps = {} } = {}) {
  const root = deps.cwd ?? process.cwd();
  const chunksPath = resolve(root, LATTICE_SUBDIR, 'chunks.jsonl');

  // Additive-only: if index absent, return null so callers omit the field.
  if (!existsSync(chunksPath)) return null;

  if (changedFiles.length === 0) {
    return { files: [], tests: [], depth, truncated: false };
  }

  // Resolve chunk IDs for the changed files.
  const allChunks = readJsonl(chunksPath);
  const changedFileSet = new Set(changedFiles);
  const seedChunkIds = allChunks
    .filter((c) => changedFileSet.has(c.filePath))
    .map((c) => c.id);

  if (seedChunkIds.length === 0) {
    return { files: [], tests: [], depth, truncated: false };
  }

  // BFS from each seed chunk in the caller direction.
  const affectedFileSet = new Set();
  let truncated = false;

  for (const chunkId of seedChunkIds) {
    const result = latticeBlast({ chunkId, direction: 'callers', depth, limit, deps });
    for (const node of result.nodes) {
      affectedFileSet.add(node.filePath);
    }
    if (result.truncated) truncated = true;
  }

  // The changed files themselves are the source of the blast, not victims.
  for (const f of changedFiles) affectedFileSet.delete(f);

  const allAffected = [...affectedFileSet];
  const tests = allAffected.filter(isTestFile);
  const files = allAffected.filter((f) => !isTestFile(f));

  return { files, tests, depth, truncated };
}

/**
 * Azure AI Foundry quota management for Plan Forge.
 * Phase-FOUNDRY-QUOTA-PREFLIGHT Slice 1.
 *
 * Exports:
 *   getDeploymentQuota  — async REST call to AOAI control-plane; fail-open.
 *   quotaCacheGet / quotaCacheSet — 5-minute in-memory TTL cache.
 *   compareSliceEstimate — synchronous comparator (status/headroomPct/message).
 *
 * @module foundry-quota
 */

// ─── In-memory TTL cache ──────────────────────────────────────────────────────
// Keyed by "${subscriptionId}/${resourceGroup}/${accountName}/${deploymentName}"
// TTL: 5 minutes (operators may resize deployments; stale quota = wrong warnings).

const _cache = new Map();

/**
 * Retrieve a cached quota entry, or null if absent/expired.
 * @param {string} key
 * @returns {object|null}
 */
export function quotaCacheGet(key) {
  const entry = _cache.get(key);
  if (!entry) return null;
  if (Date.now() > entry.expiresAt) {
    _cache.delete(key);
    return null;
  }
  return entry.value;
}

/**
 * Store a quota entry with a TTL.
 * @param {string} key
 * @param {object} value
 * @param {number} [ttlMs=300000] - 5 minutes by default
 */
export function quotaCacheSet(key, value, ttlMs = 5 * 60 * 1_000) {
  _cache.set(key, { value, expiresAt: Date.now() + ttlMs });
}

function buildQuotaCacheKey(subscriptionId, resourceGroup, accountName, deploymentName) {
  return `${subscriptionId}/${resourceGroup}/${accountName}/${deploymentName}`;
}

function missingQuotaParams(subscriptionId, resourceGroup, accountName, deploymentName) {
  return !subscriptionId || !resourceGroup || !accountName || !deploymentName;
}

async function resolveQuotaToken(credential) {
  try {
    if (!credential) return { ok: false, reason: "no_credential" };
    const tokenResult = await credential.getToken("https://management.azure.com/.default");
    const token = tokenResult?.token;
    return token ? { ok: true, token } : { ok: false, reason: "no_token" };
  } catch {
    return { ok: false, reason: "token_error" };
  }
}

function buildQuotaUrl(subscriptionId, resourceGroup, accountName, deploymentName) {
  return (
    `https://management.azure.com/subscriptions/${subscriptionId}` +
    `/resourceGroups/${resourceGroup}` +
    `/providers/Microsoft.CognitiveServices/accounts/${accountName}` +
    `/deployments/${deploymentName}?api-version=2023-05-01`
  );
}

function quotaHttpErrorReason(status) {
  if (status === 429) return "rate_limited";
  if (status === 401 || status === 403) return "forbidden";
  if (status === 503) return "service_unavailable";
  if (status >= 200 && status < 300) return null;
  return status ? `http_${status}` : null;
}

function buildQuotaResult(data, deploymentName) {
  const props = data.properties || {};
  const cap = props.capacity || {};
  return {
    ok: true,
    deploymentName: data.name || deploymentName,
    model: props.model?.name ?? "unknown",
    tpmCapacity: typeof cap.deploymentCapacity === "number" ? cap.deploymentCapacity : null,
    tpmUsage: null,
    ptuCapacity: null,
    ptuUsage: null,
    sku: data.sku?.name ?? null,
    fetchedAt: new Date().toISOString(),
  };
}

function isQuotaTimeout(err) {
  return err?.name === "TimeoutError" || err?.code === "ABORT_ERR";
}

// ─── REST quota fetch ──────────────────────────────────────────────────────────

/**
 * Fetch deployment quota from the Azure Cognitive Services control-plane API.
 * Fail-open: returns { ok: false, reason } on any error so callers can proceed.
 *
 * Cache key: `${subscriptionId}/${resourceGroup}/${accountName}/${deploymentName}`
 * Cache TTL: 5 minutes (configurable via ttlMs param).
 *
 * @param {object} opts
 * @param {string} opts.subscriptionId
 * @param {string} opts.resourceGroup
 * @param {string} opts.accountName
 * @param {string} opts.deploymentName
 * @param {object} [opts.credential]  - Token provider with getToken(scope). Optional when cached.
 * @param {number} [opts.ttlMs=300000]
 * @returns {Promise<{ok:true, deploymentName:string, model:string, tpmCapacity:number|null,
 *                    tpmUsage:number|null, ptuCapacity:number|null, ptuUsage:number|null,
 *                    sku:string|null, fetchedAt:string}
 *                  | {ok:false, reason:string}>}
 */
export async function getDeploymentQuota({
  subscriptionId,
  resourceGroup,
  accountName,
  deploymentName,
  credential,
  ttlMs = 5 * 60 * 1_000,
  _fetchFn = globalThis.fetch,
} = {}) {
  if (missingQuotaParams(subscriptionId, resourceGroup, accountName, deploymentName)) {
    return { ok: false, reason: "missing_required_params" };
  }

  const cacheKey = buildQuotaCacheKey(subscriptionId, resourceGroup, accountName, deploymentName);
  const cached = quotaCacheGet(cacheKey);
  if (cached) return cached;

  const tokenResult = await resolveQuotaToken(credential);
  if (!tokenResult.ok) return tokenResult;

  try {
    const res = await _fetchFn(buildQuotaUrl(subscriptionId, resourceGroup, accountName, deploymentName), {
      headers: { Authorization: `Bearer ${tokenResult.token}` },
      signal: AbortSignal.timeout(10_000),
    });

    const reason = quotaHttpErrorReason(res.status);
    if (reason) return { ok: false, reason };
    if (!res.ok) return { ok: false, reason: `http_${res.status}` };

    const result = buildQuotaResult(await res.json(), deploymentName);
    quotaCacheSet(cacheKey, result, ttlMs);
    return result;
  } catch (err) {
    return { ok: false, reason: isQuotaTimeout(err) ? "timeout" : "network_error" };
  }
}

// ─── Slice estimate comparator ────────────────────────────────────────────────

/**
 * Compare a slice token estimate against deployment quota.
 *
 * Status thresholds (headroom = remaining TPM after current usage + slice):
 *   safe     ≥ 30% headroom
 *   warning  10–30%
 *   critical < 10%
 *   unknown  quota unavailable or no tpmCapacity
 *
 * @param {object} quota - Output of getDeploymentQuota() (or cached value)
 * @param {object} sliceEstimate - { tokens_in: number, tokens_out: number }
 * @returns {{ status: "safe"|"warning"|"critical"|"unknown", headroomPct: number|null, message: string }}
 */
export function compareSliceEstimate(quota, sliceEstimate) {
  if (!quota || quota.ok === false) {
    const reason = quota?.reason ?? "quota unavailable";
    return { status: "unknown", headroomPct: null, message: `Quota unavailable: ${reason}` };
  }

  const tpmCapacity = quota.tpmCapacity;
  if (!tpmCapacity || tpmCapacity <= 0) {
    return { status: "unknown", headroomPct: null, message: "TPM capacity not reported by control-plane" };
  }

  const tpmUsed = quota.tpmUsage ?? 0;
  const sliceTokens = (sliceEstimate?.tokens_in ?? 0) + (sliceEstimate?.tokens_out ?? 0);
  const headroomTokens = tpmCapacity - tpmUsed - sliceTokens;
  const headroomPct = (headroomTokens / tpmCapacity) * 100;

  let status;
  if (headroomPct >= 30) status = "safe";
  else if (headroomPct >= 10) status = "warning";
  else status = "critical";

  const deployment = quota.deploymentName || "unknown";
  const message =
    `[foundry-quota] ${status} — ${headroomPct.toFixed(1)}% headroom ` +
    `(${deployment}). ` +
    `Cap=${tpmCapacity.toLocaleString()} tpm, ` +
    `used=${tpmUsed.toLocaleString()} tpm, ` +
    `slice est=${sliceTokens.toLocaleString()} tokens.`;

  return { status, headroomPct: Math.round(headroomPct * 10) / 10, message };
}

/**
 * Plan Forge — GitHub Stack Introspection (Phase GITHUB-A).
 *
 * Inspects a project directory for the GitHub-native AI surface Plan-Forge
 * integrates with: .github/copilot-instructions.md, AGENTS.md,
 * .github/instructions/*, .github/prompts/*, .vscode/mcp.json, GitHub Actions,
 * a github.com remote, and the gh CLI.
 *
 * Strictly read-only and offline by default. Network-backed checks are gated
 * behind an explicit `ghToken` opt-in.
 *
 * Separation of concerns:
 *   - This module does filesystem checks + structured reporting only.
 *   - CLI rendering (✓ / ⚠ / ✗ / ⊘ glyphs, colors, exit codes) lives in the
 *     CLI dispatcher invocation at the bottom of this file.
 *   - MCP tool wrapping lives in server.mjs (added in Slice 4).
 *
 * @module github-introspect
 */
import { existsSync, readdirSync, readFileSync, statSync } from "node:fs";
import { resolve, join } from "node:path";
import { execSync } from "node:child_process";

/**
 * @typedef {Object} CheckResult
 * @property {string} id - Stable check identifier (e.g. "copilot-instructions")
 * @property {string} label - Human-readable short label
 * @property {"pass"|"warn"|"fail"|"na"} status - Check outcome
 * @property {string} detail - One-line detail about the finding
 * @property {string} [fixHint] - One-line actionable hint when warn/fail
 */

/**
 * @typedef {Object} InspectionResult
 * @property {string} projectRoot - The absolute path that was inspected
 * @property {CheckResult[]} checks - Ordered check results
 * @property {{ pass: number, warn: number, fail: number, na: number, total: number }} summary
 */

/**
 * Order matters — this is the order the CLI prints rows.
 * Keep stable for downstream JSON consumers.
 */
const CHECK_ORDER = [
  "copilot-instructions",
  "agents-md",
  "instructions-dir",
  "prompts-dir",
  "vscode-mcp",
  "actions-workflows",
  "github-remote",
  "gh-cli",
  "copilot-coding-agent-assignable",
  "cloud-agent-validation",
];

/**
 * Inspect a project directory's GitHub-native AI surface.
 *
 * @param {string} projectRoot - Absolute path to the project root to inspect
 * @param {{ ghToken?: string|null, extra?: boolean }} [opts]
 *   - `ghToken`: Reserved for Phase GITHUB-B network-backed checks (currently unused).
 *   - `extra`: When true, also runs the SHOULD-tier checks (instruction depth, applyTo usage).
 * @returns {InspectionResult}
 */
export function inspectGithubStack(projectRoot, opts = {}) {
  const root = resolve(projectRoot);
  const checks = [];

  checks.push(checkCopilotInstructions(root));
  checks.push(checkAgentsMd(root));
  checks.push(checkInstructionsDir(root));
  checks.push(checkPromptsDir(root));
  checks.push(checkVscodeMcp(root));
  checks.push(checkActionsWorkflows(root));
  checks.push(checkGithubRemote(root));
  checks.push(checkGhCli());
  checks.push(checkCopilotCodingAgentAssignable(root, opts));
  checks.push(checkCloudAgentValidation(root));

  if (opts.extra) {
    checks.push(checkCopilotInstructionsDepth(root));
    checks.push(checkInstructionsApplyTo(root));
  }

  const summary = checks.reduce(
    (acc, c) => {
      acc[c.status]++;
      acc.total++;
      return acc;
    },
    { pass: 0, warn: 0, fail: 0, na: 0, total: 0 }
  );

  return { projectRoot: root, checks, summary };
}

// ─── individual checks ──────────────────────────────────────────────────────

/** @returns {CheckResult} */
function checkCopilotInstructions(root) {
  const p = join(root, ".github", "copilot-instructions.md");
  if (existsSync(p)) {
    return {
      id: "copilot-instructions",
      label: ".github/copilot-instructions.md",
      status: "pass",
      detail: "present",
    };
  }
  return {
    id: "copilot-instructions",
    label: ".github/copilot-instructions.md",
    status: "fail",
    detail: "file missing",
    fixHint: "Run setup.ps1 / setup.sh to scaffold the GitHub-native surface.",
  };
}

/** @returns {CheckResult} */
function checkAgentsMd(root) {
  const p = join(root, "AGENTS.md");
  if (existsSync(p)) {
    return { id: "agents-md", label: "AGENTS.md", status: "pass", detail: "present at repo root" };
  }
  return {
    id: "agents-md",
    label: "AGENTS.md",
    status: "warn",
    detail: "missing — open agent standard not adopted",
    fixHint: "Run setup.ps1 / setup.sh, or copy templates/AGENTS.md to the repo root.",
  };
}

/** @returns {CheckResult} */
function checkInstructionsDir(root) {
  const dir = join(root, ".github", "instructions");
  if (!existsSync(dir) || !isDir(dir)) {
    return {
      id: "instructions-dir",
      label: ".github/instructions/*.instructions.md",
      status: "fail",
      detail: "directory missing",
      fixHint: "Run setup.ps1 / setup.sh to scaffold path-scoped instruction files.",
    };
  }
  const files = safeReaddir(dir).filter((f) => f.endsWith(".instructions.md"));
  if (files.length === 0) {
    return {
      id: "instructions-dir",
      label: ".github/instructions/*.instructions.md",
      status: "warn",
      detail: "directory exists but contains no *.instructions.md files",
      fixHint: "Add at least one *.instructions.md (see /manual/instructions-agents.html).",
    };
  }
  return {
    id: "instructions-dir",
    label: ".github/instructions/*.instructions.md",
    status: "pass",
    detail: `${files.length} instruction file${files.length === 1 ? "" : "s"} found`,
  };
}

/** @returns {CheckResult} */
function checkPromptsDir(root) {
  const dir = join(root, ".github", "prompts");
  if (!existsSync(dir) || !isDir(dir)) {
    return {
      id: "prompts-dir",
      label: ".github/prompts/*.prompt.md",
      status: "warn",
      detail: "directory missing",
      fixHint: "Run setup.ps1 / setup.sh to scaffold the pipeline prompt files.",
    };
  }
  const files = safeReaddir(dir).filter((f) => f.endsWith(".prompt.md"));
  if (files.length === 0) {
    return {
      id: "prompts-dir",
      label: ".github/prompts/*.prompt.md",
      status: "warn",
      detail: "directory exists but contains no *.prompt.md files",
      fixHint: "Add at least one *.prompt.md (see /manual/your-first-plan.html).",
    };
  }
  return {
    id: "prompts-dir",
    label: ".github/prompts/*.prompt.md",
    status: "pass",
    detail: `${files.length} prompt file${files.length === 1 ? "" : "s"} found`,
  };
}

/** @returns {CheckResult} */
function checkVscodeMcp(root) {
  const p = join(root, ".vscode", "mcp.json");
  if (!existsSync(p)) {
    return {
      id: "vscode-mcp",
      label: ".vscode/mcp.json",
      status: "warn",
      detail: "missing — MCP server not registered for VS Code",
      fixHint: "Run setup.ps1 / setup.sh, or see /manual/mcp-server-quickstart.html.",
    };
  }
  let raw;
  try {
    raw = readFileSync(p, "utf-8");
  } catch {
    return {
      id: "vscode-mcp",
      label: ".vscode/mcp.json",
      status: "warn",
      detail: "file present but unreadable",
      fixHint: "Verify file permissions and JSON syntax.",
    };
  }
  // Loose match — Plan-Forge MCP entries reference plan-forge or pforge-mcp
  const hasPlanForgeEntry = /plan[-_ ]?forge|pforge[-_ ]?mcp/i.test(raw);
  if (!hasPlanForgeEntry) {
    return {
      id: "vscode-mcp",
      label: ".vscode/mcp.json",
      status: "warn",
      detail: "present but no Plan-Forge MCP server entry detected",
      fixHint: "Add a Plan-Forge MCP server entry; see /manual/mcp-server-quickstart.html.",
    };
  }
  return {
    id: "vscode-mcp",
    label: ".vscode/mcp.json",
    status: "pass",
    detail: "Plan-Forge MCP server registered",
  };
}

/** @returns {CheckResult} */
function checkActionsWorkflows(root) {
  const dir = join(root, ".github", "workflows");
  if (!existsSync(dir) || !isDir(dir)) {
    return {
      id: "actions-workflows",
      label: ".github/workflows/",
      status: "warn",
      detail: "no GitHub Actions workflows present",
      fixHint: "Add a workflow under .github/workflows/ to enable CI on this repo.",
    };
  }
  const files = safeReaddir(dir).filter((f) => f.endsWith(".yml") || f.endsWith(".yaml"));
  if (files.length === 0) {
    return {
      id: "actions-workflows",
      label: ".github/workflows/",
      status: "warn",
      detail: "directory exists but contains no .yml workflows",
      fixHint: "Add a workflow under .github/workflows/ to enable CI on this repo.",
    };
  }
  return {
    id: "actions-workflows",
    label: ".github/workflows/",
    status: "pass",
    detail: `${files.length} workflow file${files.length === 1 ? "" : "s"} found`,
  };
}

/** @returns {CheckResult} */
function checkGithubRemote(root) {
  const cfg = join(root, ".git", "config");
  if (!existsSync(cfg)) {
    return {
      id: "github-remote",
      label: "git remote → github.com",
      status: "na",
      detail: "no .git directory found (not a clone)",
    };
  }
  let txt;
  try {
    txt = readFileSync(cfg, "utf-8");
  } catch {
    return {
      id: "github-remote",
      label: "git remote → github.com",
      status: "warn",
      detail: ".git/config unreadable",
      fixHint: "Check filesystem permissions on .git/config.",
    };
  }
  if (/github\.com/i.test(txt)) {
    return {
      id: "github-remote",
      label: "git remote → github.com",
      status: "pass",
      detail: "github.com remote configured",
    };
  }
  return {
    id: "github-remote",
    label: "git remote → github.com",
    status: "warn",
    detail: "no github.com remote in .git/config",
    fixHint: "Add a github.com remote: git remote add origin https://github.com/<owner>/<repo>.git",
  };
}

/** @returns {CheckResult} */
function checkGhCli() {
  try {
    // Cross-platform "is command available?" — use `--version` so output is bounded.
    execSync("gh --version", {
      stdio: ["ignore", "pipe", "pipe"],
      timeout: 3000,
    });
    return {
      id: "gh-cli",
      label: "gh CLI on PATH",
      status: "pass",
      detail: "gh CLI available",
    };
  } catch {
    return {
      id: "gh-cli",
      label: "gh CLI on PATH",
      status: "warn",
      detail: "gh CLI not found on PATH",
      fixHint: "Install GitHub CLI: https://cli.github.com — unlocks issue / PR / GHAS workflows.",
    };
  }
}

