// ─── extra (SHOULD) checks ──────────────────────────────────────────────────

/** @returns {CheckResult} */
function checkCopilotInstructionsDepth(root) {
  const p = join(root, ".github", "copilot-instructions.md");
  if (!existsSync(p)) {
    return {
      id: "copilot-instructions-depth",
      label: "copilot-instructions.md depth",
      status: "na",
      detail: "file not present (see prior check)",
    };
  }
  let lines;
  try {
    lines = readFileSync(p, "utf-8").split(/\r?\n/).length;
  } catch {
    return {
      id: "copilot-instructions-depth",
      label: "copilot-instructions.md depth",
      status: "warn",
      detail: "file unreadable",
      fixHint: "Check file permissions.",
    };
  }
  if (lines < 50) {
    return {
      id: "copilot-instructions-depth",
      label: "copilot-instructions.md depth",
      status: "warn",
      detail: `only ${lines} lines — likely a stub`,
      fixHint: "Expand with project-specific architecture, conventions, and quick commands.",
    };
  }
  return {
    id: "copilot-instructions-depth",
    label: "copilot-instructions.md depth",
    status: "pass",
    detail: `${lines} lines of context`,
  };
}

/** @returns {CheckResult} */
function checkInstructionsApplyTo(root) {
  const dir = join(root, ".github", "instructions");
  if (!existsSync(dir) || !isDir(dir)) {
    return {
      id: "instructions-applyto",
      label: "instructions use applyTo path-scoping",
      status: "na",
      detail: "instructions directory missing (see prior check)",
    };
  }
  const files = safeReaddir(dir).filter((f) => f.endsWith(".instructions.md"));
  if (files.length === 0) {
    return {
      id: "instructions-applyto",
      label: "instructions use applyTo path-scoping",
      status: "na",
      detail: "no instruction files (see prior check)",
    };
  }
  let withApplyTo = 0;
  for (const f of files) {
    try {
      const txt = readFileSync(join(dir, f), "utf-8");
      if (/^\s*applyTo\s*:/m.test(txt)) withApplyTo++;
    } catch { /* skip unreadable */ }
  }
  if (withApplyTo === 0) {
    return {
      id: "instructions-applyto",
      label: "instructions use applyTo path-scoping",
      status: "warn",
      detail: `0 of ${files.length} files use applyTo: frontmatter`,
      fixHint: "Add 'applyTo: \"src/**/*.ts\"' (or similar) to scope instructions to file paths.",
    };
  }
  return {
    id: "instructions-applyto",
    label: "instructions use applyTo path-scoping",
    status: "pass",
    detail: `${withApplyTo} of ${files.length} files use applyTo:`,
  };
}

// ─── helpers ────────────────────────────────────────────────────────────────

/**
 * Read the optional `cloudAgentValidation` block from `.forge.json`.
 * Returns null if the file is absent, unreadable, or the key is missing.
 *
 * @param {string} root
 * @returns {Record<string,boolean>|null}
 */
function readCloudAgentValidationConfig(root) {
  try {
    const cfgPath = join(root, ".forge.json");
    if (!existsSync(cfgPath)) return null;
    const raw = JSON.parse(readFileSync(cfgPath, "utf-8"));
    const val = raw?.cloudAgentValidation;
    if (!val || typeof val !== "object" || Array.isArray(val)) return null;
    return val;
  } catch {
    return null;
  }
}

/** @returns {CheckResult} */
function checkCloudAgentValidation(root) {
  const cfg = readCloudAgentValidationConfig(root);
  if (!cfg) {
    return {
      id: "cloud-agent-validation",
      label: "cloudAgentValidation (.forge.json)",
      status: "na",
      detail:
        "not configured — add cloudAgentValidation to .forge.json to declare your GitHub scanning stack",
    };
  }
  const KNOWN_TOOLS = ["codeql", "secretScanning", "dependencyReview", "copilotCodeReview"];
  const enabled = KNOWN_TOOLS.filter((k) => cfg[k] === true);
  const disabled = KNOWN_TOOLS.filter((k) => cfg[k] === false);
  const parts = [];
  if (enabled.length > 0) parts.push(`enabled: ${enabled.join(", ")}`);
  if (disabled.length > 0) parts.push(`disabled: ${disabled.join(", ")}`);
  return {
    id: "cloud-agent-validation",
    label: "cloudAgentValidation (.forge.json)",
    status: "pass",
    detail: parts.length > 0 ? parts.join(" | ") : "configured (no standard tools declared)",
  };
}

function isDir(p) {
  try {
    return statSync(p).isDirectory();
  } catch {
    return false;
  }
}

function safeReaddir(p) {
  try {
    return readdirSync(p);
  } catch {
    return [];
  }
}

// ─── CLI entrypoint ─────────────────────────────────────────────────────────

/**
 * CLI entrypoint. Invoked by pforge.ps1 / pforge.sh as:
 *   node pforge-mcp/github-introspect.mjs --project <root> [--json] [--doctor] [--extra]
 *
 * Exit codes:
 *   0 — no failures (warns and N/A allowed)
 *   1 — at least one failure, OR --help printed nothing actionable
 *   2 — invalid arguments
 */
function main(argv) {
  const args = parseArgs(argv);
  if (args.help) {
    printHelp();
    return 0;
  }
  if (args.error) {
    process.stderr.write(`pforge github: ${args.error}\n`);
    printHelp(process.stderr);
    return 2;
  }

  const result = inspectGithubStack(args.project, { extra: args.extra });

  if (args.json) {
    process.stdout.write(JSON.stringify(result, null, 2) + "\n");
  } else {
    renderHuman(result, { doctor: args.doctor });
  }
  return result.summary.fail > 0 ? 1 : 0;
}

function parseArgs(argv) {
  const out = {
    project: process.cwd(),
    json: false,
    doctor: false,
    extra: false,
    help: false,
    error: null,
  };
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a === "--help" || a === "-h") {
      out.help = true;
    } else if (a === "--json") {
      out.json = true;
    } else if (a === "--doctor") {
      out.doctor = true;
    } else if (a === "--extra") {
      out.extra = true;
    } else if (a === "--project") {
      const v = argv[++i];
      if (!v) {
        out.error = "--project requires a path argument";
        return out;
      }
      out.project = v;
    } else if (a.startsWith("--project=")) {
      out.project = a.slice("--project=".length);
    } else {
      out.error = `unknown argument: ${a}`;
      return out;
    }
  }
  return out;
}

function printHelp(stream = process.stdout) {
  stream.write(
`Usage: node github-introspect.mjs [options]

Inspect a project's GitHub-native AI surface (Copilot, AGENTS.md, MCP, GHAS).

Options:
  --project <dir>   Project root to inspect (default: cwd)
  --json            Emit structured JSON to stdout
  --doctor          Include one-line fix hints for warn/fail rows
  --extra           Run optional depth checks (instruction-file applyTo, etc.)
  --help, -h        Show this help

Exit codes:
  0   no failures
  1   at least one fail
  2   invalid arguments
`
  );
}

function renderHuman(result, { doctor }) {
  const glyph = { pass: "✓", warn: "⚠", fail: "✗", na: "⊘" };
  const out = [];
  out.push("");
  out.push(`GitHub stack readiness — ${result.projectRoot}`);
  out.push("─".repeat(72));
  for (const c of result.checks) {
    out.push(`  ${glyph[c.status]} ${c.label}`);
    out.push(`      ${c.detail}`);
    if (doctor && c.fixHint && (c.status === "warn" || c.status === "fail")) {
      out.push(`      → ${c.fixHint}`);
    }
  }
  out.push("─".repeat(72));
  const s = result.summary;
  out.push(
    `  ${s.pass} pass · ${s.warn} warn · ${s.fail} fail · ${s.na} n/a  (${s.total} checks)`
  );
  if (s.fail > 0 && !doctor) {
    out.push("");
    out.push("  Hint: re-run with `pforge github doctor` for one-line fix suggestions.");
  } else if (s.fail === 0 && s.warn === 0) {
    out.push("");
    out.push("  All checks pass — GitHub-native surface is fully wired up.");
  }
  out.push("");
  process.stdout.write(out.join("\n") + "\n");
}

// Run CLI when invoked directly (not when imported).
const entryPath = typeof process.argv[1] === "string" ? process.argv[1] : "";
const invokedDirectly =
  entryPath.length > 0 &&
  (import.meta.url === `file://${entryPath.replace(/\\/g, "/")}` ||
    import.meta.url.endsWith(entryPath.replace(/\\/g, "/")));
if (invokedDirectly) {
  process.exit(main(process.argv.slice(2)));
}

/**
 * Plan Forge — GitHub Copilot Metrics Ingestion (Phase GITHUB-D Slice 1).
 *
 * Provides three operations:
 *   - `pullMetrics`  — fetch from GitHub Copilot Metrics API via `gh api`
 *   - `writeMetrics` — persist normalized records to JSONL under storeDir
 *   - `loadMetrics`  — read merged, sorted time series back from disk
 *
 * All API calls are made through the user's existing `gh` CLI auth — no new
 * secret management needed.  Tests mock `gh` via the createMockGh helper;
 * no real Copilot Metrics API calls are made during tests.
 *
 * JSONL on-disk layout:
 *   <storeDir>/<org>/<YYYY-MM-DD>.jsonl   (one normalized record per line)
 *
 * @module github-metrics
 */

import { existsSync, mkdirSync, readdirSync, readFileSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { spawnSync } from "node:child_process";

// ─── Error classes ──────────────────────────────────────────────────────────

export class MetricsError extends Error {
  constructor(message) {
    super(message);
    this.name = "MetricsError";
  }
}

export class MetricsAuthError extends MetricsError {
  constructor(message) {
    super(message);
    this.name = "MetricsAuthError";
  }
}

export class MetricsNotFoundError extends MetricsError {
  constructor(message) {
    super(message);
    this.name = "MetricsNotFoundError";
  }
}

export class MetricsRateLimitError extends MetricsError {
  constructor(message) {
    super(message);
    this.name = "MetricsRateLimitError";
  }
}

// ─── Public API ─────────────────────────────────────────────────────────────

/**
 * Fetch Copilot metrics for an org from the GitHub Copilot Metrics API.
 *
 * @param {Object} opts
 * @param {string}  opts.org      - GitHub org slug (required)
 * @param {string}  [opts.since]  - ISO date or shorthand like "30d" (default: "30d")
 * @param {string}  [opts.until]  - ISO date or shorthand (default: today)
 * @param {string}  [opts.ghCmd]  - Path to `gh` binary (default: "gh")
 * @param {Object}  [opts.env]    - Process environment override (used in tests)
 * @returns {NormalizedRecord[]} Normalized daily records, sorted by date ascending
 * @throws {MetricsAuthError}       on 403 / missing copilot:read scope
 * @throws {MetricsNotFoundError}   on 404 / org not found
 * @throws {MetricsRateLimitError}  on 429 / API rate limit
 * @throws {MetricsError}           on other failures
 */
export function pullMetrics({ org, since, until, ghCmd = "gh", env } = {}) {
  if (!org) throw new MetricsError("org is required");

  const sinceDate = parseDateArg(since ?? "30d");
  const params = [`since=${sinceDate}`];
  if (until) params.push(`until=${parseDateArg(until)}`);

  const url = `/orgs/${encodeURIComponent(org)}/copilot/metrics?${params.join("&")}`;

  // Bug #192 (v2.99.1): avoid DEP0190 — on Windows route through cmd.exe
  // instead of shell:true + array args.
  const isWin    = process.platform === "win32";
  const spawnBin = isWin ? "cmd" : ghCmd;
  const spawnArg = isWin ? ["/d", "/s", "/c", ghCmd, "api", url] : ["api", url];
  const result = spawnSync(spawnBin, spawnArg, {
    encoding: "utf-8",
    env: env ?? process.env,
    windowsHide: isWin,
  });

  if (result.error) {
    throw new MetricsError(`Failed to spawn gh: ${result.error.message}`);
  }

  if (result.status !== 0) {
    raiseGhError(result, org);
  }

  let data;
  try {
    data = JSON.parse(result.stdout || "[]");
  } catch {
    throw new MetricsError(`gh api returned non-JSON output: ${result.stdout?.slice(0, 200)}`);
  }

  if (!Array.isArray(data)) {
    if (data?.message) raiseErrorBody(data, org);
    return [];
  }

  return data
    .map((raw) => normalizeRecord(raw, org))
    .sort((a, b) => a.date.localeCompare(b.date));
}

/**
 * Write normalized records to per-date JSONL files under storeDir.
 * Idempotent: existing date files are skipped (not overwritten).
 *
 * @param {NormalizedRecord[]} records
 * @param {{ storeDir: string }} opts
 * @returns {{ written: string[], skipped: string[] }}
 */
export function writeMetrics(records, { storeDir }) {
  if (!storeDir) throw new MetricsError("storeDir is required");

  const grouped = new Map();
  for (const rec of records) {
    if (!rec?.date || !rec?.org) continue;
    const key = `${rec.org}\x00${rec.date}`;
    if (!grouped.has(key)) grouped.set(key, []);
    grouped.get(key).push(rec);
  }

  const written = [];
  const skipped = [];

  for (const [key, recs] of grouped) {
    const [org, date] = key.split("\x00");
    const dir = join(storeDir, org);
    mkdirSync(dir, { recursive: true });
    const file = join(dir, `${date}.jsonl`);

    if (existsSync(file)) {
      skipped.push(date);
      continue;
    }

    const content = recs.map((r) => JSON.stringify(r)).join("\n") + "\n";
    writeFileSync(file, content, "utf-8");
    written.push(date);
  }

  return { written, skipped };
}

/**
 * Load normalized records from disk, merged across dates and sorted ascending.
 *
 * @param {Object} opts
 * @param {string}  opts.storeDir - Root directory for the JSONL store
 * @param {string}  opts.org      - Org slug to read
 * @param {string}  [opts.since]  - ISO date or shorthand for lower bound (inclusive)
 * @param {string}  [opts.until]  - ISO date or shorthand for upper bound (inclusive)
 * @returns {NormalizedRecord[]}
 */
export function loadMetrics({ storeDir, org, since, until } = {}) {
  if (!storeDir) throw new MetricsError("storeDir is required");
  if (!org) throw new MetricsError("org is required");

  const orgDir = join(storeDir, org);
  if (!existsSync(orgDir)) return [];

  const sinceDate = since ? parseDateArg(since) : null;
  const untilDate = until ? parseDateArg(until) : null;

  let files;
  try {
    files = readdirSync(orgDir);
  } catch {
    return [];
  }

  const filtered = files
    .filter((f) => f.endsWith(".jsonl"))
    .filter((f) => {
      const date = f.slice(0, -".jsonl".length);
      if (sinceDate && date < sinceDate) return false;
      if (untilDate && date > untilDate) return false;
      return true;
    })
    .sort();

  const records = [];
  for (const file of filtered) {
    let content;
    try {
      content = readFileSync(join(orgDir, file), "utf-8").trim();
    } catch {
      continue;
    }
    if (!content) continue;
    for (const line of content.split("\n")) {
      try {
        records.push(JSON.parse(line));
      } catch { /* skip malformed lines */ }
    }
  }

  return records.sort((a, b) => a.date.localeCompare(b.date));
}

// ─── Normalization ──────────────────────────────────────────────────────────

/**
 * @typedef {Object} NormalizedRecord
 * @property {"1.0"} schema
 * @property {string} date  - ISO date string (YYYY-MM-DD)
 * @property {string} org
 * @property {number} totalActiveUsers
 * @property {number} totalEngagedUsers
 * @property {Object} codeCompletions
 * @property {number} ideChatEngagedUsers
 * @property {number} dotcomChatEngagedUsers
 * @property {number} prEngagedUsers
 */

function normalizeRecord(raw, org) {
  const completions = raw.copilot_ide_code_completions ?? {};
  const languages = (completions.languages ?? []).map((l) => ({
    name: l.name,
    engagedUsers: l.total_engaged_users ?? 0,
    suggestions: l.total_code_suggestions ?? 0,
    acceptances: l.total_code_acceptances ?? 0,
    linesSuggested: l.total_code_lines_suggested ?? 0,
    linesAccepted: l.total_code_lines_accepted ?? 0,
  }));

  const totalSuggestions = languages.reduce((s, l) => s + l.suggestions, 0);
  const totalAcceptances = languages.reduce((s, l) => s + l.acceptances, 0);

  return {
    schema: "1.0",
    date: raw.date,
    org,
    totalActiveUsers: raw.total_active_users ?? 0,
    totalEngagedUsers: raw.total_engaged_users ?? 0,
    codeCompletions: {
      totalEngagedUsers: completions.total_engaged_users ?? 0,
      totalSuggestions,
      totalAcceptances,
      acceptanceRate:
        totalSuggestions > 0
          ? Math.round((totalAcceptances / totalSuggestions) * 10000) / 10000
          : 0,
      languages,
    },
    ideChatEngagedUsers: raw.copilot_ide_chat?.total_engaged_users ?? 0,
    dotcomChatEngagedUsers: raw.copilot_dotcom_chat?.total_engaged_users ?? 0,
    prEngagedUsers: raw.copilot_dotcom_pull_requests?.total_engaged_users ?? 0,
  };
}

// ─── Date helpers ────────────────────────────────────────────────────────────

/**
 * Parse a date argument into ISO YYYY-MM-DD format.
 * Supports "Nd" shorthand (e.g. "30d") and ISO date strings.
 *
 * @param {string|Date} value
 * @returns {string} ISO date string
 */
export function parseDateArg(value) {
  if (!value) return null;
  if (value instanceof Date) return value.toISOString().slice(0, 10);
  const shorthand = String(value).match(/^(\d+)d$/i);
  if (shorthand) {
    const days = parseInt(shorthand[1], 10);
    const d = new Date();
    d.setUTCDate(d.getUTCDate() - days);
    return d.toISOString().slice(0, 10);
  }
  return String(value).slice(0, 10);
}

// ─── Error dispatch ─────────────────────────────────────────────────────────

function raiseGhError(result, org) {
  let body = null;
  try {
    body = JSON.parse(result.stdout || "{}");
  } catch { /* ignore */ }

  const message = body?.message ?? "";
  const status = body?.status ?? "";
  const combined = `${message} ${status} ${result.stderr ?? ""}`;

  if (/403|forbidden|copilot.*scope|scope.*copilot|required scope/i.test(combined)) {
    throw new MetricsAuthError(
      "Token lacks `copilot:read` scope. Run `gh auth refresh -s copilot:read --hostname github.com`"
    );
  }

  if (/404|not found/i.test(combined)) {
    throw new MetricsNotFoundError(`Org not found or access denied: ${org}`);
  }

  if (/429|rate.?limit/i.test(combined)) {
    const m = (result.stderr ?? "").match(/retry.?after[:\s]+(\d+)/i);
    const hint = m ? ` --retry-after ${m[1]}` : "";
    throw new MetricsRateLimitError(`Rate limit hit.${hint}`);
  }

  throw new MetricsError(
    `gh api failed (exit ${result.status}): ${message || result.stderr?.trim() || "unknown error"}`
  );
}

function raiseErrorBody(body, org) {
  raiseGhError({ status: 1, stdout: JSON.stringify(body), stderr: "" }, org);
}

/**
 * Plan Forge — GitHub Personal Metrics (Phase-54 Slice 0).
 *
 * Provides three operations against the personal/individual GitHub API surface:
 *   - `fetchUserProfile`      — authenticated user's profile via `gh api user`
 *   - `fetchRepoSummary`      — repository metadata via `gh api repos/{owner}/{repo}`
 *   - `scanCopilotCoauthors`  — scan commit history for Copilot co-author signatures
 *
 * All API calls go through the user's existing `gh` CLI auth — no additional
 * secret management required. Tests mock `gh` via the createMockGh helper;
