}

// ─── Public API ───────────────────────────────────────────────────────────────

/**
 * @typedef {Object} UserProfile
 * @property {string} login
 * @property {number} id
 * @property {string|null} name
 * @property {string|null} email
 * @property {string|null} bio
 * @property {number} publicRepos
 * @property {number} followers
 * @property {number} following
 * @property {string} createdAt  - ISO datetime
 */

/**
 * Fetch the authenticated user's GitHub profile.
 *
 * @param {Object}  [opts]
 * @param {string}  [opts.ghCmd] - Path to `gh` binary (default: "gh")
 * @param {Object}  [opts.env]   - Process environment override (used in tests)
 * @returns {UserProfile}
 * @throws {PersonalAuthError}      on 401/403
 * @throws {PersonalRateLimitError} on 429
 * @throws {PersonalError}          on other failures
 */
export function fetchUserProfile({ ghCmd = "gh", env } = {}) {
  const raw = callGhApi("user", { ghCmd, env });
  return normalizeUserProfile(raw);
}

/**
 * @typedef {Object} RepoSummary
 * @property {number} id
 * @property {string} name
 * @property {string} fullName
 * @property {boolean} private
 * @property {string|null} description
 * @property {boolean} fork
 * @property {number} stars
 * @property {number} forks
 * @property {number} openIssues
 * @property {string} defaultBranch
 * @property {string|null} language
 * @property {string} createdAt
 * @property {string} updatedAt
 * @property {string} pushedAt
 */

/**
 * Fetch a repository summary from the GitHub API.
 *
 * @param {Object}  opts
 * @param {string}  opts.owner   - Repository owner (user or org slug)
 * @param {string}  opts.repo    - Repository name
 * @param {string}  [opts.ghCmd] - Path to `gh` binary (default: "gh")
 * @param {Object}  [opts.env]   - Process environment override (used in tests)
 * @returns {RepoSummary}
 * @throws {PersonalAuthError}      on 401/403
 * @throws {PersonalNotFoundError}  on 404
 * @throws {PersonalRateLimitError} on 429
 * @throws {PersonalError}          on other failures
 */
export function fetchRepoSummary({ owner, repo, ghCmd = "gh", env } = {}) {
  if (!owner) throw new PersonalError("owner is required");
  if (!repo) throw new PersonalError("repo is required");

  const endpoint = `repos/${encodeURIComponent(owner)}/${encodeURIComponent(repo)}`;
  const raw = callGhApi(endpoint, { ghCmd, env, context: `${owner}/${repo}` });
  return normalizeRepoSummary(raw);
}

/**
 * @typedef {Object} CommitScanResult
 * @property {number} total           - Total commits scanned
 * @property {number} withCopilot     - Commits with a Copilot co-author signature
 * @property {CommitEntry[]} commits  - Per-commit detail
 */

/**
 * @typedef {Object} CommitEntry
 * @property {string}  sha
 * @property {string}  date        - ISO datetime of the commit
 * @property {string}  message     - Full commit message
 * @property {boolean} hasCopilot  - Whether Copilot co-authorship was detected
 */

/**
 * Scan a repository's commit history for GitHub Copilot co-author signatures.
 *
 * Detects lines matching (case-insensitive):
 *   Co-authored-by: GitHub Copilot <...>
 *   Co-authored-by: Copilot <copilot@github.com>
 *
 * @param {Object}  opts
 * @param {string}  opts.owner       - Repository owner
 * @param {string}  opts.repo        - Repository name
 * @param {string}  [opts.since]     - ISO date lower bound (passed to GitHub API)
 * @param {string}  [opts.until]     - ISO date upper bound (passed to GitHub API)
 * @param {number}  [opts.perPage]   - Commits per page (default: 100, max: 100)
 * @param {string}  [opts.ghCmd]     - Path to `gh` binary (default: "gh")
 * @param {Object}  [opts.env]       - Process environment override (used in tests)
 * @returns {CommitScanResult}
 * @throws {PersonalAuthError}      on 401/403
 * @throws {PersonalNotFoundError}  on 404
 * @throws {PersonalRateLimitError} on 429
 * @throws {PersonalError}          on other failures
 */
export function scanCopilotCoauthors({
  owner,
  repo,
  since,
  until,
  perPage = 100,
  ghCmd = "gh",
  env,
} = {}) {
  if (!owner) throw new PersonalError("owner is required");
  if (!repo) throw new PersonalError("repo is required");

  const params = [`per_page=${Math.min(perPage, 100)}`];
  if (since) params.push(`since=${since}`);
  if (until) params.push(`until=${until}`);

  const endpoint =
    `repos/${encodeURIComponent(owner)}/${encodeURIComponent(repo)}/commits` +
    `?${params.join("&")}`;

  const raw = callGhApi(endpoint, { ghCmd, env, context: `${owner}/${repo}` });
  const items = Array.isArray(raw) ? raw : [];

  const commits = items.map((item) => {
    const message = item?.commit?.message ?? "";
    const hasCopilot = COPILOT_COAUTHOR_RE.test(message);
    return {
      sha: item?.sha ?? "",
      date: item?.commit?.author?.date ?? "",
      message,
      hasCopilot,
    };
  });

  return {
    total: commits.length,
    withCopilot: commits.filter((c) => c.hasCopilot).length,
    commits,
  };
}

// ─── Copilot co-author detection ──────────────────────────────────────────────

const COPILOT_COAUTHOR_RE =
  /co-authored-by:\s*(github\s+)?copilot\s*</i;

// ─── Normalization helpers ────────────────────────────────────────────────────

function normalizeUserProfile(raw) {
  return {
    login: raw.login ?? "",
    id: raw.id ?? 0,
    name: raw.name ?? null,
    email: raw.email ?? null,
    bio: raw.bio ?? null,
    publicRepos: raw.public_repos ?? 0,
    followers: raw.followers ?? 0,
    following: raw.following ?? 0,
    createdAt: raw.created_at ?? "",
  };
}

function normalizeRepoSummary(raw) {
  return {
    id: raw.id ?? 0,
    name: raw.name ?? "",
    fullName: raw.full_name ?? "",
    private: raw.private ?? false,
    description: raw.description ?? null,
    fork: raw.fork ?? false,
    stars: raw.stargazers_count ?? 0,
    forks: raw.forks_count ?? 0,
    openIssues: raw.open_issues_count ?? 0,
    defaultBranch: raw.default_branch ?? "main",
    language: raw.language ?? null,
    createdAt: raw.created_at ?? "",
    updatedAt: raw.updated_at ?? "",
    pushedAt: raw.pushed_at ?? "",
  };
}

// ─── `gh` invocation helpers ─────────────────────────────────────────────────

/**
 * Call `gh api <endpoint>` and return the parsed JSON body.
 * Throws a typed PersonalError on any non-zero exit or HTTP error response.
 *
 * @param {string} endpoint   - API path (e.g. "user" or "repos/owner/repo")
 * @param {Object} opts
 * @param {string} opts.ghCmd
 * @param {Object} [opts.env]
 * @param {string} [opts.context] - Context hint for error messages (e.g. "owner/repo")
 * @returns {*} Parsed JSON response
 */
function callGhApi(endpoint, { ghCmd, env, context } = {}) {
  // Bug #192 (v2.99.1): avoid DEP0190 on Windows — route through cmd.exe
  const isWin = process.platform === "win32";
  const spawnBin = isWin ? "cmd" : ghCmd;
  const spawnArg = isWin
    ? ["/d", "/s", "/c", ghCmd, "api", endpoint]
    : ["api", endpoint];

  const result = spawnSync(spawnBin, spawnArg, {
    encoding: "utf-8",
    env: env ?? process.env,
    windowsHide: isWin,
  });

  if (result.error) {
    throw new PersonalError(`Failed to spawn gh: ${result.error.message}`);
  }

  if (result.status !== 0) {
    raiseGhError(result, context);
  }

  let data;
  try {
    data = JSON.parse(result.stdout || "null");
  } catch {
    throw new PersonalError(
      `gh api returned non-JSON output: ${result.stdout?.slice(0, 200)}`
    );
  }

  if (data && typeof data === "object" && !Array.isArray(data) && data.message) {
    raiseErrorBody(data, context);
  }

  return data;
}

// ─── Error dispatch ───────────────────────────────────────────────────────────

function raiseGhError(result, context) {
  let body = null;
  try {
    body = JSON.parse(result.stdout || "{}");
  } catch { /* ignore */ }

  const message = body?.message ?? "";
  const status = body?.status ?? "";
  const combined = `${message} ${status} ${result.stderr ?? ""}`;

  if (/401|403|forbidden|unauthorized|required scope|bad.?credentials/i.test(combined)) {
    throw new PersonalAuthError(
      "GitHub auth failure. Run `gh auth login` or `gh auth refresh` to re-authenticate."
    );
  }

  if (/404|not.?found/i.test(combined)) {
    const ctx = context ? `: ${context}` : "";
    throw new PersonalNotFoundError(`Resource not found${ctx}`);
  }

  if (/429|rate.?limit/i.test(combined)) {
    const m = (result.stderr ?? "").match(/retry.?after[:\s]+(\d+)/i);
    const hint = m ? ` --retry-after ${m[1]}` : "";
    throw new PersonalRateLimitError(`GitHub API rate limit hit.${hint}`);
  }

  throw new PersonalError(
    `gh api failed (exit ${result.status}): ${message || result.stderr?.trim() || "unknown error"}`
  );
}

function raiseErrorBody(body, context) {
  raiseGhError({ status: 1, stdout: JSON.stringify(body), stderr: "" }, context);
}

/**
 * Plan Forge Knowledge Graph — Builder (Phase-38.3).
 * @module graph/builder
 */
import { execSync } from "node:child_process";
import { readdirSync, readFileSync, writeFileSync, renameSync, mkdirSync, existsSync } from "node:fs";
import { resolve, join } from "node:path";
import { NODE_TYPES, EDGE_TYPES } from "./schema.mjs";

function parsePlanFiles(plansDir) {
  const nodes = [];
  const edges = [];
  if (!existsSync(plansDir)) return { nodes, edges };
  let files;
  try {
    files = readdirSync(plansDir).filter(f => f.endsWith(".md"));
  } catch {
    return { nodes, edges };
  }
  for (const file of files) {
    try {
      const content = readFileSync(join(plansDir, file), "utf8");
      const lines = content.split("\n");
      let phaseId = null;
      let phaseName = null;
      // Try frontmatter crucibleId
      if (lines[0]?.trim() === "---") {
        const fmEnd = lines.indexOf("---", 1);
        if (fmEnd > 0) {
          for (let i = 1; i < fmEnd; i++) {
            const m = lines[i].match(/^crucibleId:\s*(.+)/);
            if (m) { phaseId = m[1].trim(); phaseName = phaseId; }
          }
        }
      }
      // Try # Phase-XX.X heading
      for (const line of lines) {
        const m = line.match(/^#\s+(Phase-[\d.]+.*)/);
        if (m) {
          if (!phaseId) phaseId = m[1].trim().replace(/\s+/g, "-");
          phaseName = m[1].trim();
          break;
        }
      }
      if (!phaseId) {
        phaseId = file.replace(/\.md$/, "");
        phaseName = phaseId;
      }
      const phaseNode = { id: `phase-${phaseId}`, type: NODE_TYPES.PHASE, name: phaseName, metadata: { file } };
      nodes.push(phaseNode);
      // Extract Slice nodes from ### Slice N — headings
      for (const line of lines) {
        const sm = line.match(/^###\s+(Slice\s+\d+\s*[—-].+)/i);
        if (sm) {
          const sliceName = sm[1].trim();
          const sliceId = `slice-${phaseId}-${sliceName.replace(/\s+/g, "-").replace(/[^a-zA-Z0-9\-]/g, "").toLowerCase()}`;
          nodes.push({ id: sliceId, type: NODE_TYPES.SLICE, name: sliceName, metadata: { phase: phaseId } });
          edges.push({ from: phaseNode.id, to: sliceId, type: EDGE_TYPES.PHASE_TO_SLICE });
        }
      }
    } catch {
      // skip malformed files
    }
  }
  return { nodes, edges };
}

function parseCommits(projectDir, since, execSyncFn) {
  const nodes = [];
  const sincePart = since || "90 days ago";
  try {
    const fn = execSyncFn || execSync;
    const output = fn(`git log --format="%H %s" --since="${sincePart}"`, { cwd: projectDir, encoding: "utf8" });
    const lines = (output || "").split("\n").filter(Boolean);
    for (const line of lines) {
      const spaceIdx = line.indexOf(" ");
      if (spaceIdx < 0) continue;
      const hash = line.slice(0, spaceIdx);
      const subject = line.slice(spaceIdx + 1);
      nodes.push({
        id: `commit-${hash}`,
        type: NODE_TYPES.COMMIT,
        name: subject,
        metadata: { hash, subject },
      });
    }
  } catch {
    // no git or no commits — return empty
  }
  return nodes;
}

function inferSliceCommitEdges(sliceNodes, commitNodes) {
  const edges = [];
  for (const commit of commitNodes) {
    const subject = (commit.metadata?.subject || commit.name || "").toLowerCase();
    for (const slice of sliceNodes) {
      // Extract keywords from slice name
      const sliceWords = slice.name.toLowerCase().split(/[\s\-—]+/).filter(w => w.length > 3);
      for (const word of sliceWords) {
        if (subject.includes(word)) {
          edges.push({ from: slice.id, to: commit.id, type: EDGE_TYPES.SLICE_TO_COMMIT });
          break;
        }
      }
    }
  }
  return edges;
}

function parseRuns(forgeDir) {
  const nodes = [];
  const runsDir = join(forgeDir, "runs");
  if (!existsSync(runsDir)) return nodes;
  // Glob runs/**/*.json — walk dirs
  const phaseCounters = {};
  function walkDir(dir) {
    let entries;
    try { entries = readdirSync(dir, { withFileTypes: true }); } catch { return; }
    for (const entry of entries) {
      const full = join(dir, entry.name);
      if (entry.isDirectory()) {
        walkDir(full);
      } else if (entry.name.endsWith(".json")) {
        try {
          const data = JSON.parse(readFileSync(full, "utf8"));
          const phaseKey = data.phase || "unknown";
          phaseCounters[phaseKey] = (phaseCounters[phaseKey] || 0) + 1;
          if (phaseCounters[phaseKey] > 10) continue; // last 10 runs per phase
          nodes.push({
            id: `run-${data.id || entry.name.replace(".json", "")}`,
            type: NODE_TYPES.RUN,
            name: data.id || entry.name.replace(".json", ""),
            metadata: { phase: data.phase, startedAt: data.startedAt },
          });
        } catch { /* skip malformed */ }
      }
    }
  }
  walkDir(runsDir);
  return nodes;
}

function parseBugs(forgeDir) {
  const nodes = [];
  const bugsDir = join(forgeDir, "bugs");
  if (!existsSync(bugsDir)) return nodes;
  function walkDir(dir) {
    let entries;
    try { entries = readdirSync(dir, { withFileTypes: true }); } catch { return; }
    for (const entry of entries) {
      const full = join(dir, entry.name);
      if (entry.isDirectory()) {
        walkDir(full);
      } else if (entry.name.endsWith(".json")) {
        if (nodes.length >= 200) return; // bound at 200 bugs
        try {
          const data = JSON.parse(readFileSync(full, "utf8"));
          nodes.push({
            id: `bug-${data.id || entry.name.replace(".json", "")}`,
            type: NODE_TYPES.BUG,
            name: data.title || data.id || entry.name.replace(".json", ""),
            metadata: { severity: data.severity, id: data.id },
          });
        } catch { /* skip malformed */ }
      }
    }
  }
  walkDir(bugsDir);
  return nodes;
}

function writeSnapshot(forgeDir, graph) {
  try {
    const graphDir = join(forgeDir, "graph");
    mkdirSync(graphDir, { recursive: true });
    const snapshotPath = join(graphDir, "snapshot.json");
    const tmpPath = snapshotPath + ".tmp";
    writeFileSync(tmpPath, JSON.stringify(graph, null, 2), "utf8");
    renameSync(tmpPath, snapshotPath);
  } catch { /* non-fatal */ }
}

/**
 * Build the knowledge graph from project artifacts.
 * @param {string} projectDir
 * @param {{ since?: string, execSyncFn?: Function }} [opts]
 * @returns {{ nodes: Array, edges: Array }}
 */
export function buildGraph(projectDir, opts = {}) {
  const { since, execSyncFn } = opts;
  try {
    const plansDir = join(projectDir, "docs", "plans");
    const forgeDir = join(projectDir, ".forge");
    const { nodes: planNodes, edges: planEdges } = parsePlanFiles(plansDir);
    const sliceNodes = planNodes.filter(n => n.type === NODE_TYPES.SLICE);
    const commitNodes = parseCommits(projectDir, since, execSyncFn);
    const sliceCommitEdges = inferSliceCommitEdges(sliceNodes, commitNodes);
    const runNodes = parseRuns(forgeDir);
    const bugNodes = parseBugs(forgeDir);
    const nodes = [...planNodes, ...commitNodes, ...runNodes, ...bugNodes];
    const edges = [...planEdges, ...sliceCommitEdges];
    const graph = { nodes, edges };
    writeSnapshot(forgeDir, graph);
    return graph;
  } catch {
    return { nodes: [], edges: [] };
  }
}

/**
 * Plan Forge Knowledge Graph — Query API (Phase-38.3).
 * @module graph/query
 */
import { readFileSync, existsSync } from "node:fs";
import { join } from "node:path";
import { buildGraph } from "./builder.mjs";

let _cachedGraph = null;
let _cachedProjectDir = null;

function loadGraph(projectDir) {
  if (_cachedGraph && _cachedProjectDir === projectDir) return _cachedGraph;
  const snapshotPath = join(projectDir, ".forge", "graph", "snapshot.json");
  if (existsSync(snapshotPath)) {
    try {
      _cachedGraph = JSON.parse(readFileSync(snapshotPath, "utf8"));
      _cachedProjectDir = projectDir;
      return _cachedGraph;
    } catch { /* fall through to rebuild */ }
  }
  _cachedGraph = buildGraph(projectDir);
  _cachedProjectDir = projectDir;
  return _cachedGraph;
}

export function _resetGraphCache() {
  _cachedGraph = null;
  _cachedProjectDir = null;
}

function formatResult(nodes, edges) {
  return { nodes, edges, nodeCount: nodes.length, edgeCount: edges.length };
}

/**
 * Filter graph to Phase node with matching name + connected subgraph.
 */
export function queryByPhase(name, opts = {}) {
  const projectDir = opts.projectDir || process.cwd();
  const { nodes, edges } = loadGraph(projectDir);
  const phaseNode = nodes.find(n => n.type === "Phase" && (n.name?.toLowerCase().includes(name.toLowerCase()) || n.id?.toLowerCase().includes(name.toLowerCase())));
  if (!phaseNode) return formatResult([], []);
  const visited = new Set([phaseNode.id]);
  const resultEdges = [];
  const queue = [phaseNode.id];
  while (queue.length) {
    const nodeId = queue.shift();
    for (const edge of edges) {
      if (edge.from === nodeId || edge.to === nodeId) {
        const otherId = edge.from === nodeId ? edge.to : edge.from;
        resultEdges.push(edge);
        if (!visited.has(otherId)) {
          visited.add(otherId);
          queue.push(otherId);
        }
      }
    }
  }
  const resultNodes = nodes.filter(n => visited.has(n.id));
  return formatResult(resultNodes, resultEdges);
}

/**
 * Find File nodes matching path + connected commits and tests.
 */
export function queryByFile(path, opts = {}) {
  const projectDir = opts.projectDir || process.cwd();
  const { nodes, edges } = loadGraph(projectDir);
  const fileNodes = nodes.filter(n => n.type === "File" && (n.name?.includes(path) || n.id?.includes(path)));
  if (!fileNodes.length) return formatResult([], []);
  const visited = new Set(fileNodes.map(n => n.id));
  const resultEdges = [];
  for (const fileNode of fileNodes) {
    for (const edge of edges) {
      if (edge.from === fileNode.id || edge.to === fileNode.id) {
        const otherId = edge.from === fileNode.id ? edge.to : edge.from;
        resultEdges.push(edge);
        visited.add(otherId);
      }
    }
  }
  const resultNodes = nodes.filter(n => visited.has(n.id));
  return formatResult(resultNodes, resultEdges);
}

function parseSinceDate(since) {
  if (!since) return null;
  const relMatch = since.match(/^(\d+)d$/);
  if (relMatch) {
    const days = parseInt(relMatch[1], 10);
    return new Date(Date.now() - days * 24 * 60 * 60 * 1000);
  }
  const d = new Date(since);
  return isNaN(d.getTime()) ? null : d;
}

/**
 * Filter Commit/Slice/Run nodes by since date and optional type.
 */
export function queryRecentChanges({ since, type } = {}, opts = {}) {
  const projectDir = opts.projectDir || process.cwd();
  const { nodes, edges } = loadGraph(projectDir);
  const sinceDate = parseSinceDate(since);
  const RECENT_TYPES = ["Commit", "Slice", "Run"];
  let filtered = nodes.filter(n => RECENT_TYPES.includes(n.type));
  if (type) {
    filtered = filtered.filter(n => n.type?.toLowerCase() === type.toLowerCase());
  }
  if (sinceDate) {
    filtered = filtered.filter(n => {
      const ts = n.metadata?.startedAt || n.metadata?.committedAt;
      if (!ts) return true; // include if no date
      return new Date(ts) >= sinceDate;
    });
  }
  const filteredIds = new Set(filtered.map(n => n.id));
  const filteredEdges = edges.filter(e => filteredIds.has(e.from) && filteredIds.has(e.to));
  return formatResult(filtered, filteredEdges);
}

/**
 * 1-hop BFS from nodeId; optional edgeType filter.
 */
export function neighbors(nodeId, opts = {}) {
  const projectDir = opts.projectDir || process.cwd();
  const { nodes, edges } = loadGraph(projectDir);
  const startNode = nodes.find(n => n.id === nodeId);
  if (!startNode) return formatResult([], []);
  const visited = new Set([nodeId]);
  const resultEdges = [];
  for (const edge of edges) {
    if (opts.edgeType && edge.type !== opts.edgeType) continue;
    if (edge.from === nodeId || edge.to === nodeId) {
      const otherId = edge.from === nodeId ? edge.to : edge.from;
      resultEdges.push(edge);
      visited.add(otherId);
    }
  }
  const resultNodes = nodes.filter(n => visited.has(n.id));
  return formatResult(resultNodes, resultEdges);
}

/**
 * lattice-chunker-treesitter.mjs — High-fidelity code chunker using tree-sitter.
 *
 * Lazy-loads `tree-sitter` and per-language grammars only when first needed. If
 * the packages are not installed the module transparently falls back to the
 * pure-JS chunker and emits a single one-time warning to stderr so the caller
 * always receives valid CodeChunker-compatible records.
 *
 * Scope: pforge-mcp/lattice-chunker-treesitter.mjs (Slice 3 of Phase-LATTICE)
 */

import { createHash } from 'node:crypto';

// ─── Capability metadata ──────────────────────────────────────────────────────

/** Languages supported when tree-sitter grammars are present. */
export const languages = ['js', 'ts', 'mjs', 'py'];

/** Chunk kinds produced (superset of the pure-JS chunker — adds "method"). */
export const kinds = ['file', 'function', 'class', 'method'];

export const version = '1.0.0';

// ─── Lazy-loading state ───────────────────────────────────────────────────────

/** @type {null | false | Map<string, object>} */
let _parsers = null;
let _warnedFallback = false;

/**
 * Attempt to load tree-sitter and grammars on first use. Returns a parser Map
 * on success, or `false` if any package is absent.
 */
async function ensureParsers() {
  if (_parsers !== null) return _parsers;

  try {
    const { default: Parser } = await import('tree-sitter');
    const { default: JavaScript } = await import('tree-sitter-javascript');
    const tsModule = await import('tree-sitter-typescript');
    // tree-sitter-typescript exports { typescript, tsx } or a default with those props
    const TypeScriptGrammars = tsModule.default ?? tsModule;
    const { default: Python } = await import('tree-sitter-python');

    const jsParser = new Parser();
    jsParser.setLanguage(JavaScript);

    const tsParser = new Parser();
    tsParser.setLanguage(TypeScriptGrammars.typescript);

    const pyParser = new Parser();
    pyParser.setLanguage(Python);

    _parsers = new Map([
      ['js', jsParser],
      ['mjs', jsParser],
      ['ts', tsParser],
      ['py', pyParser],
    ]);
    return _parsers;
  } catch {
    if (!_warnedFallback) {
      process.stderr.write(
        '[lattice-chunker-treesitter] tree-sitter or grammar packages not installed; ' +
          'falling back to pure-JS chunker. ' +
          'Install with: npm install tree-sitter tree-sitter-javascript ' +
          'tree-sitter-typescript tree-sitter-python\n',
      );
      _warnedFallback = true;
    }
    _parsers = false;
    return false;
  }
}

// ─── Internal helpers ─────────────────────────────────────────────────────────

function sha256(text) {
  return 'sha256:' + createHash('sha256').update(text, 'utf8').digest('hex');
}

/** Map a file-path extension to the language key used by the parser map. */
function detectLanguage(filePath) {
  const ext = filePath.split('.').pop()?.toLowerCase() ?? '';
  const map = { js: 'js', mjs: 'mjs', ts: 'ts', tsx: 'ts', py: 'py' };
  return map[ext] ?? 'unknown';
}

/**
 * Walk a tree-sitter SyntaxNode recursively and collect names of called
 * functions / methods into a Set.
 */
function collectCallRefs(node, refs = new Set()) {
  if (node.type === 'call_expression') {
    const fn = node.childForFieldName('function');
    if (fn) {
      const name =
        fn.type === 'member_expression'
          ? fn.childForFieldName('property')?.text
          : fn.text;
      if (name && /^\w/.test(name)) refs.add(name);
    }
  }
  for (const child of node.namedChildren) {
    collectCallRefs(child, refs);
  }
  return refs;
}

/**
 * Build a CodeChunker record from a tree-sitter SyntaxNode.
 *
 * NOTE: tree-sitter indices are character-position–based when parsing a plain
 * string. For ASCII-only content (all current fixtures) these equal UTF-8 byte
 * offsets. Full multi-byte support can be added by pre-converting the source
 * to a Buffer before parsing.
 */
function makeChunk({ filePath, language, kind, name, node, content }) {
  const startByte = node.startIndex;
  const endByte = node.endIndex;
  const text = content.slice(startByte, endByte);
  const startLine = node.startPosition.row + 1; // convert 0-based row → 1-indexed
  const endLine = node.endPosition.row + 1;

  return {
    filePath,
    language,
    kind,
    name,
    startByte,
    endByte,
    startLine,
    endLine,
    contentHash: sha256(text),
    declares: name ? [name] : [],
    references: [...collectCallRefs(node)],
  };
}

// ─── Language-specific AST walkers ───────────────────────────────────────────

/**
 * Extract function, class, and method chunks from the root of a JS/TS/MJS
 * parse tree. Only top-level declarations and class body methods are walked;
 * nested functions inside function bodies are intentionally not emitted (they
 * would cause overlapping byte ranges).
 */
function jsFunctionChunk(filePath, language, node, content) {
  const name = node.childForFieldName('name')?.text ?? '';
  return makeChunk({ filePath, language, kind: 'function', name, node, content });
}

function jsClassChunks(filePath, language, node, content) {
  const className = node.childForFieldName('name')?.text ?? '';
  const chunks = [makeChunk({ filePath, language, kind: 'class', name: className, node, content })];
  const body = node.childForFieldName('body');
  if (!body) return chunks;
  for (const member of body.namedChildren) {
    if (member.type !== 'method_definition') continue;
    const methodName = member.childForFieldName('name')?.text ?? '';
    chunks.push(makeChunk({ filePath, language, kind: 'method', name: methodName, node: member, content }));
  }
  return chunks;
}

function isJsFunctionValue(node) {
  return ["arrow_function", "function_expression", "generator_function"].includes(node?.type);
}

function jsVariableChunks(filePath, language, node, content) {
  const chunks = [];
  for (const declarator of node.namedChildren) {
    if (declarator.type !== 'variable_declarator') continue;
    const nameNode = declarator.childForFieldName('name');
    const valueNode = declarator.childForFieldName('value');
    if (!nameNode || !isJsFunctionValue(valueNode)) continue;
    chunks.push(makeChunk({ filePath, language, kind: 'function', name: nameNode.text, node: declarator, content }));
  }
  return chunks;
}

function extractJsChunks(filePath, language, rootNode, content) {
  const chunks = [];

  for (const node of rootNode.namedChildren) {
    if (node.type === 'function_declaration') {
      chunks.push(jsFunctionChunk(filePath, language, node, content));
      continue;
    }
    if (node.type === 'class_declaration') {
      chunks.push(...jsClassChunks(filePath, language, node, content));
      continue;
    }
    if (node.type === 'lexical_declaration' || node.type === 'variable_declaration') {
      chunks.push(...jsVariableChunks(filePath, language, node, content));
    }
  }

  return chunks;
}

/**
 * Extract function and class chunks from the root of a Python parse tree.
 * Methods inside classes are emitted with kind "method".
 */
function extractPyChunks(filePath, rootNode, content) {
  const chunks = [];

  for (const node of rootNode.namedChildren) {
    if (node.type === 'function_definition') {
      const name = node.childForFieldName('name')?.text ?? '';
      chunks.push(makeChunk({ filePath, language: 'py', kind: 'function', name, node, content }));

    } else if (node.type === 'class_definition') {
      const className = node.childForFieldName('name')?.text ?? '';
      chunks.push(makeChunk({ filePath, language: 'py', kind: 'class', name: className, node, content }));

      const body = node.childForFieldName('body');
      if (body) {
        for (const child of body.namedChildren) {
          if (child.type === 'function_definition') {
            const methodName = child.childForFieldName('name')?.text ?? '';
            chunks.push(
              makeChunk({ filePath, language: 'py', kind: 'method', name: methodName, node: child, content }),
            );
          }
        }
      }
    }
  }

  return chunks;
}

// ─── Public API ───────────────────────────────────────────────────────────────

/**
 * Chunk a source file into CodeChunker-compatible records using tree-sitter.
 *
 * When tree-sitter or required grammar packages are absent the function falls
 * back to the pure-JS chunker (which always produces valid records) and emits
 * a one-time warning to stderr.
 *
 * @param {{ filePath: string, content: string, language?: string }} options
 * @returns {Promise<Array<object>>} Chunk records conforming to the CodeChunker contract.
 */
export async function chunkFile({ filePath, content, language }) {
  const lang = language ?? detectLanguage(filePath);
  const contentBuf = Buffer.from(content, 'utf8');

  // Build the file-level chunk — always present regardless of impl.
  const rawLines = content.split('\n');
  const lineCount = content.endsWith('\n') ? rawLines.length - 1 : rawLines.length;
  const fileChunk = {
    filePath,
    language: lang,
    kind: 'file',
    name: '',
    startByte: 0,
    endByte: contentBuf.length,
    startLine: 1,
    endLine: Math.max(lineCount, 1),
    contentHash: sha256(content),
    declares: [],
    references: [],
  };

  const parsers = await ensureParsers();

  if (!parsers) {
    // tree-sitter unavailable — delegate entirely to pure-JS chunker.
    const { chunkFile: pureJsChunkFile } = await import('../pforge-sdk/src/chunker-pureJs.mjs');
    return pureJsChunkFile({ filePath, content, language });
  }

  const parser = parsers.get(lang);
  if (!parser) {
    // Language not supported by the loaded grammars — return file chunk only.
    return [fileChunk];
  }

  const tree = parser.parse(content);
  let subChunks = [];

  if (lang === 'js' || lang === 'mjs' || lang === 'ts') {
    subChunks = extractJsChunks(filePath, lang, tree.rootNode, content);
  } else if (lang === 'py') {
    subChunks = extractPyChunks(filePath, tree.rootNode, content);
  }

  return [fileChunk, ...subChunks];
}

// ─── Test backdoor ────────────────────────────────────────────────────────────

/**
 * Reset lazy-loading state. Exported for use by test files only — do not call
 * in production code.
 */
export function _resetForTesting() {
  _parsers = null;
  _warnedFallback = false;
}

