function readMeta(deps = {}) {
  const p = join(latticeDir(deps), META_FILE);
  if (!existsSync(p)) return { lastIndexedAt: null, chunkerImpl: null, chunkerVersion: null };
  try {
    return JSON.parse(readFileSync(p, 'utf8'));
  } catch {
    return { lastIndexedAt: null, chunkerImpl: null, chunkerVersion: null };
  }
}

function writeMeta(meta, deps = {}) {
  const dir = latticeDir(deps);
  mkdirSync(dir, { recursive: true });
  writeFileSync(join(dir, META_FILE), JSON.stringify(meta, null, 2), 'utf8');
}

// ─── Chunker resolution ───────────────────────────────────────────────────────

/** @type {{ chunkFile: Function, name: string, version: string } | null} */
let _cachedChunker = null;

/**
 * Resolve the best available chunker implementation.
 *
 * Priority:
 *  1. deps.chunker  (test injection)
 *  2. tree-sitter   (when `tree-sitter` package is importable)
 *  3. pure-JS       (always available; last resort)
 *
 * Result is cached after the first resolution to avoid repeated dynamic imports.
 */
async function resolveChunker(deps = {}) {
  if (deps.chunker) {
    return {
      chunkFile: deps.chunker,
      name: deps.chunkerName ?? 'injected',
      version: deps.chunkerVersion ?? '0.0.0',
    };
  }

  if (_cachedChunker) return _cachedChunker;

  // Probe for tree-sitter availability (optional dep)
  let treeSitterAvailable = false;
  try {
    await import('tree-sitter');
    treeSitterAvailable = true;
  } catch { /* not installed — expected in stock CI */ }

  if (treeSitterAvailable) {
    const mod = await import('./lattice-chunker-treesitter.mjs');
    _cachedChunker = { chunkFile: mod.chunkFile, name: 'treesitter', version: mod.version };
  } else {
    const mod = await import('../pforge-sdk/src/chunker-pureJs.mjs');
    _cachedChunker = { chunkFile: mod.chunkFile, name: 'pureJs', version: mod.version };
    // Emit the one-time warning mandated by the forbidden-actions contract
    process.stderr.write(
      '[lattice] tree-sitter packages not installed; using pure-JS chunker. ' +
        'Install with: npm install tree-sitter tree-sitter-javascript ' +
        'tree-sitter-typescript tree-sitter-python\n',
    );
  }

  return _cachedChunker;
}

/**
 * Reset the cached chunker impl. Exported for test isolation only — do not
 * call in production code.
 */
export function _resetChunkerForTesting() {
  _cachedChunker = null;
}

// ─── Public API ───────────────────────────────────────────────────────────────

/**
 * Walk the given `paths`, chunk each file, persist JSONL, and return a summary.
 *
 * Per-file chunking is wrapped in `withAnvil` so repeated `latticeIndex` calls
 * on an unchanged tree yield ≥ 95 % Anvil hit rate with zero re-chunking work.
 *
 * @param {{
 *   paths?:  string[],
 *   since?:  string,
 *   deps?:   { cwd?: string, exec?: Function, chunker?: Function, chunkerName?: string, chunkerVersion?: string }
 * }} opts
 * @returns {Promise<{
 *   filesIndexed: number,
 *   chunks:       number,
 *   edges:        number,
 *   anvilHits:    number,
 *   anvilMisses:  number,
 * }>}
 */
export async function latticeIndex({ paths = ['.'], since, deps = {} } = {}) {
  const root = workspaceRoot(deps);

  // 1. Resolve and validate paths
  const resolvedPaths = paths.map((p) => (isAbsolute(p) ? p : resolve(root, p)));
  assertPathsInsideRepo(root, resolvedPaths);

  // 2. Get the full tracked-file list from git
  const candidateFiles = listRepoFiles(root, deps);

  // 3. Filter to files under the requested paths
  let files = candidateFiles.filter((absFile) =>
    resolvedPaths.some((rp) => {
      const rel = relative(rp, absFile);
      return !rel.startsWith('..') && !isAbsolute(rel);
    }),
  );

  // 4. Optionally restrict to files changed since a revision
  if (since) {
    const changedSet = new Set(listChangedFiles(root, since, deps));
    files = files.filter((f) => changedSet.has(f));
  }

  // 5. Filter to chunkable extensions
  files = files.filter((f) => CHUNKABLE_EXTS.has(fileExt(f)));

  // 6. Resolve the chunker impl
  const chunker = await resolveChunker(deps);

  // 7. Chunk each file with per-file Anvil caching
  const allChunks = [];
  const allEdges = [];
  let anvilHits = 0;
  let anvilMisses = 0;

  for (const absPath of files) {
    let content;
    try {
      content = readFileSync(absPath, 'utf8');
    } catch {
      continue; // skip unreadable files
    }

    const relPath = relative(root, absPath).replace(/\\/g, '/');
    const contentHash = sha256hex(content);
    const codeHashSeed = `${relPath}:${contentHash}:${chunker.name}:${chunker.version}`;

    const result = await withAnvil(
      async () => {
        const chunks = await chunker.chunkFile({ filePath: relPath, content });
        return { chunks };
      },
      {
        toolName: 'lattice_file_chunk',
        inputs: {
          filePath: relPath,
          contentHash,
          chunkerName: chunker.name,
          chunkerVersion: chunker.version,
        },
        codeHashSeed,
      },
      deps,
    );

    if (result.anvil?.hit) anvilHits++;
    else anvilMisses++;

    for (const chunk of result.chunks ?? []) {
      const cId = makeChunkId(chunk);
      allChunks.push({ ...chunk, id: cId });
      for (const ref of chunk.references ?? []) {
        allEdges.push({ callerChunkId: cId, calleeName: ref });
      }
    }
  }

  // 8. Persist JSONL files
  const dir = latticeDir(deps);
  mkdirSync(dir, { recursive: true });

  writeFileSync(
    join(dir, CHUNKS_FILE),
    allChunks.map((c) => JSON.stringify(c)).join('\n') +
      (allChunks.length > 0 ? '\n' : ''),
    'utf8',
  );
  writeFileSync(
    join(dir, EDGES_FILE),
    allEdges.map((e) => JSON.stringify(e)).join('\n') +
      (allEdges.length > 0 ? '\n' : ''),
    'utf8',
  );

  // 9. Persist meta for latticeStat
  writeMeta(
    {
      lastIndexedAt: new Date().toISOString(),
      chunkerImpl: chunker.name,
      chunkerVersion: chunker.version,
      filesIndexed: files.length,
    },
    deps,
  );

  return { filesIndexed: files.length, chunks: allChunks.length, edges: allEdges.length, anvilHits, anvilMisses };
}

/**
 * Return a bounded summary of the current Lattice index state.
 *
 * @param {{ deps?: object }} [opts]
 * @returns {{
 *   chunks:        number,
 *   edges:         number,
 *   languages:     Record<string, number>,
 *   lastIndexedAt: string | null,
 *   chunkerImpl:   string | null,
 *   chunkerVersion:string | null,
 *   anvilHitRate:  number,
 *   indexBytes:    number,
 * }}
 */
function readChunkLanguageStats(dir) {
  const chunksPath = join(dir, CHUNKS_FILE);
  const languages = {};
  if (!existsSync(chunksPath)) return { chunks: 0, languages };

  const lines = readFileSync(chunksPath, 'utf8').split('\n').filter(Boolean);
  for (const line of lines) {
    try {
      const rec = JSON.parse(line);
      const lang = rec.language ?? 'unknown';
      languages[lang] = (languages[lang] ?? 0) + 1;
    } catch { /* skip malformed lines */ }
  }
  return { chunks: lines.length, languages };
}

function countJsonlRecords(filePath) {
  if (!existsSync(filePath)) return 0;
  return readFileSync(filePath, 'utf8').split('\n').filter(Boolean).length;
}

function computeIndexBytes(dir) {
  let indexBytes = 0;
  for (const fname of [CHUNKS_FILE, EDGES_FILE, META_FILE]) {
    const p = join(dir, fname);
    if (!existsSync(p)) continue;
    try {
      indexBytes += statSync(p).size;
    } catch { /* best-effort */ }
  }
  return indexBytes;
}

function readLatticeAnvilHitRate(deps) {
  try {
    const statsFile = resolve(workspaceRoot(deps), '.forge', 'anvil', 'stats.json');
    if (!existsSync(statsFile)) return 0;
    const stats = JSON.parse(readFileSync(statsFile, 'utf8'));
    const ts = stats.perTool?.lattice_file_chunk;
    if (!ts) return 0;
    const total = (ts.hits ?? 0) + (ts.misses ?? 0);
    return total > 0 ? ts.hits / total : 0;
  } catch {
    return 0;
  }
}

export function latticeStat({ deps = {} } = {}) {
  const dir = latticeDir(deps);
  const meta = readMeta(deps);
  const { chunks, languages } = readChunkLanguageStats(dir);
  const edges = countJsonlRecords(join(dir, EDGES_FILE));

  return {
    chunks,
    edges,
    languages,
    lastIndexedAt: meta.lastIndexedAt ?? null,
    chunkerImpl: meta.chunkerImpl ?? null,
    chunkerVersion: meta.chunkerVersion ?? null,
    anvilHitRate: readLatticeAnvilHitRate(deps),
    indexBytes: computeIndexBytes(dir),
  };
}

// ─── Internal read helpers (Slice 5) ─────────────────────────────────────────

function readAllChunks(deps = {}) {
  const p = join(latticeDir(deps), CHUNKS_FILE);
  if (!existsSync(p)) return [];
  return readFileSync(p, 'utf8')
    .split('\n')
    .filter(Boolean)
    .map((line) => { try { return JSON.parse(line); } catch { return null; } })
    .filter(Boolean);
}

function readAllEdges(deps = {}) {
  const p = join(latticeDir(deps), EDGES_FILE);
  if (!existsSync(p)) return [];
  return readFileSync(p, 'utf8')
    .split('\n')
    .filter(Boolean)
    .map((line) => { try { return JSON.parse(line); } catch { return null; } })
    .filter(Boolean);
}

// ─── Scoring helpers ──────────────────────────────────────────────────────────

/**
 * Tokenize text for relevance scoring.
 * Splits on whitespace/punctuation AND camelCase/PascalCase boundaries so that
 * a query for "user" matches chunks named "getUserById" or "UserService".
 *
 * @param {string} text
 * @returns {Map<string, number>} token → count (lowercase)
 */
export function tokenizeForSearch(text) {
  if (!text || typeof text !== 'string') return new Map();
  const split = text
    .replace(/([a-z])([A-Z])/g, '$1 $2')
    .replace(/([A-Z]+)([A-Z][a-z])/g, '$1 $2');
  const tokens = split.toLowerCase().match(/[a-z0-9]+/g) ?? [];
  const out = new Map();
  for (const t of tokens) out.set(t, (out.get(t) || 0) + 1);
  return out;
}

/**
 * Compute a relevance score for a chunk against a query string.
 *
 * Score = (nameOverlap × 2 + pathOverlap) / 3, where overlap is
 * |query_tokens ∩ field_tokens| / |query_tokens|.
 *
 * Returns a value in [0, 1].  Returns 0 when query is empty.
 *
 * @param {string} queryText
 * @param {{ name?: string, filePath?: string }} chunk
 * @returns {number}
 */
export function scoreChunk(queryText, chunk) {
  if (!queryText || typeof queryText !== 'string') return 0;
  const qTokens = tokenizeForSearch(queryText);
  if (qTokens.size === 0) return 0;

  const nameTokens = tokenizeForSearch(chunk.name ?? '');
  const pathTokens = tokenizeForSearch(chunk.filePath ?? '');

  let nameHits = 0;
  let pathHits = 0;
  for (const q of qTokens.keys()) {
    if (nameTokens.has(q)) nameHits++;
    if (pathTokens.has(q)) pathHits++;
  }

  const qSize = qTokens.size;
  return (nameHits / qSize * 2 + pathHits / qSize) / 3;
}

// ─── latticeQuery ─────────────────────────────────────────────────────────────

/**
 * Search the chunk index for records matching the given criteria.
 *
 * All filters are ANDed. An empty/omitted `query` matches all chunks.
 * When a query is provided, results are ranked by relevance (name-token overlap
 * weighted 2× over filePath-token overlap, both camelCase-aware).  Each
 * returned chunk gains a `score` field (0–1, three decimal places).
 *
 * @param {{
 *   query?:    string,            token + substring match against chunk.name / filePath
 *   language?: string,            exact match against chunk.language
 *   kind?:     string,            exact match against chunk.kind
 *   filePath?: string,            substring match against chunk.filePath
 *   limit?:    number,            max results returned (default 25)
 *   deps?:     object
 * }} [opts]
 * @returns {{
 *   chunks:    object[],
 *   total:     number,
 *   truncated: boolean,
 *   message:   string,
 * }}
 */
export function latticeQuery({
  query = '',
  language,
  kind,
  filePath: filePathFilter,
  limit = 25,
  deps = {},
} = {}) {
  const allChunks = readAllChunks(deps);
  const q = query.toLowerCase();

  const filtered = allChunks.filter((c) => {
    if (q && !c.name?.toLowerCase().includes(q) && !c.filePath?.toLowerCase().includes(q)) return false;
    if (language !== undefined && c.language !== language) return false;
    if (kind !== undefined && c.kind !== kind) return false;
    if (filePathFilter && !c.filePath?.toLowerCase().includes(filePathFilter.toLowerCase())) return false;
    return true;
  });

  let ranked;
  if (q) {
    ranked = filtered
      .map((c) => ({ ...c, score: Math.round(scoreChunk(query, c) * 1000) / 1000 }))
      .sort((a, b) => b.score - a.score);
  } else {
    ranked = filtered;
  }

  const total = ranked.length;
  const truncated = total > limit;
  const results = ranked.slice(0, limit);

  const filters = [
    query ? `query "${query}"` : null,
    language ? `language "${language}"` : null,
    kind ? `kind "${kind}"` : null,
    filePathFilter ? `filePath "${filePathFilter}"` : null,
  ].filter(Boolean).join(', ');

  const message = total === 0
    ? `No chunks matched${filters ? ` ${filters}` : ''}. Broaden your query or run latticeIndex first.`
    : `Found ${total} chunk${total !== 1 ? 's' : ''}${filters ? ` matching ${filters}` : ''}${truncated ? `; returning first ${limit}` : ''}.`;

  return { chunks: results, total, truncated, message };
}

// ─── latticeCallers ───────────────────────────────────────────────────────────

/**
 * Find all chunks that reference (call) the given symbol name.
 *
 * @param {{
 *   name:   string,   the callee symbol name to search for
 *   limit?: number,   max results (default 25)
 *   deps?:  object
 * }} opts
 * @returns {{
 *   chunks:    object[],
 *   total:     number,
 *   truncated: boolean,
 *   message:   string,
 * }}
 */
export function latticeCallers({ name, limit = 25, deps = {} } = {}) {
  if (!name) {
    return { chunks: [], total: 0, truncated: false, message: '"name" is required.' };
  }

  const edges = readAllEdges(deps);
  const callerIds = new Set(
    edges.filter((e) => e.calleeName === name).map((e) => e.callerChunkId),
  );

  const allChunks = readAllChunks(deps);
  const callers = allChunks.filter((c) => callerIds.has(c.id));

  const total = callers.length;
  const truncated = total > limit;
  const results = callers.slice(0, limit);

  const message = total === 0
    ? `No callers found for "${name}". Ensure the index is up to date.`
    : `Found ${total} caller${total !== 1 ? 's' : ''} of "${name}"${truncated ? `; returning first ${limit}` : ''}.`;

  return { chunks: results, total, truncated, message };
}

// ─── latticeBlast ─────────────────────────────────────────────────────────────

/**
 * BFS traversal of the call graph starting from a seed chunk.
 *
 * Traverses outgoing callee edges, incoming caller edges, or both, up to
 * `depth` hops from the seed.  Callee names that do not resolve to a known
 * chunk are captured in `unresolvedNames` but are not enqueued for further
 * traversal (they have no outgoing/incoming edges of their own).
 *
 * @param {{
 *   chunkId?:   string,   exact seed chunk id (takes priority over name)
 *   name?:      string,   seed chunk name (all matching chunks are enqueued)
 *   direction?: 'callees' | 'callers' | 'both'   default: 'both'
 *   depth?:     number,   BFS hop limit (default 3)
 *   limit?:     number,   max nodes returned (default 50)
 *   deps?:      object
 * }} [opts]
 * @returns {{
 *   nodes:           Array<object & { distance: number }>,
 *   edges:           Array<{ from: string, to: string }>,
 *   unresolvedNames: string[],
 *   total:           number,
 *   truncated:       boolean,
 *   message:         string,
 * }}
 */
function buildChunksByName(allChunks) {
  const chunksByName = new Map();
  for (const chunk of allChunks) {
    if (!chunk.name) continue;
    if (!chunksByName.has(chunk.name)) chunksByName.set(chunk.name, []);
    chunksByName.get(chunk.name).push(chunk);
  }
  return chunksByName;
}

function buildBlastEdgeMaps(allEdges) {
  const outEdges = new Map();
  const inEdges = new Map();
  for (const edge of allEdges) {
    if (!outEdges.has(edge.callerChunkId)) outEdges.set(edge.callerChunkId, []);
    outEdges.get(edge.callerChunkId).push(edge.calleeName);
    if (!inEdges.has(edge.calleeName)) inEdges.set(edge.calleeName, []);
    inEdges.get(edge.calleeName).push(edge.callerChunkId);
  }
  return { outEdges, inEdges };
}

function resolveBlastSeedIds(chunkId, name, chunkById, chunksByName) {
  if (chunkId) return chunkById.has(chunkId) ? [chunkId] : [];
  return (chunksByName.get(name) ?? []).map((chunk) => chunk.id);
}

function enqueueBlastNode(queue, visited, id, dist) {
  if (visited.has(id)) return;
  visited.set(id, dist);
  queue.push({ id, dist });
}

function expandBlastCallees({ curId, dist, outEdges, chunksByName, traversedEdges, unresolvedNames, queue, visited }) {
  for (const calleeName of outEdges.get(curId) ?? []) {
    const calleeChunks = chunksByName.get(calleeName) ?? [];
    if (calleeChunks.length === 0) {
      unresolvedNames.add(calleeName);
      continue;
    }
    for (const calleeChunk of calleeChunks) {
      traversedEdges.push({ from: curId, to: calleeChunk.id });
      enqueueBlastNode(queue, visited, calleeChunk.id, dist + 1);
    }
  }
}

function expandBlastCallers({ curId, dist, chunkById, inEdges, traversedEdges, queue, visited }) {
  const curChunk = chunkById.get(curId);
  if (!curChunk?.name) return;
  for (const callerChunkId of inEdges.get(curChunk.name) ?? []) {
    traversedEdges.push({ from: callerChunkId, to: curId });
    enqueueBlastNode(queue, visited, callerChunkId, dist + 1);
  }
}

function traverseBlastGraph({ seedIds, depth, direction, chunkById, chunksByName, outEdges, inEdges }) {
  const visited = new Map();
  const traversedEdges = [];
  const unresolvedNames = new Set();
  const queue = [];

  for (const id of seedIds) enqueueBlastNode(queue, visited, id, 0);

  let head = 0;
  while (head < queue.length) {
    const { id: curId, dist } = queue[head++];
    if (dist >= depth) continue;
    if (direction === 'callees' || direction === 'both') {
      expandBlastCallees({ curId, dist, outEdges, chunksByName, traversedEdges, unresolvedNames, queue, visited });
    }
    if (direction === 'callers' || direction === 'both') {
      expandBlastCallers({ curId, dist, chunkById, inEdges, traversedEdges, queue, visited });
    }
  }

  return { visited, traversedEdges, unresolvedNames };
}

function buildBlastNodes(visited, chunkById) {
  const allNodes = [];
  for (const [id, distance] of visited) {
    const chunk = chunkById.get(id);
    if (chunk) allNodes.push({ ...chunk, distance });
  }
  allNodes.sort((a, b) => a.distance - b.distance || a.id.localeCompare(b.id));
  return allNodes;
}

function dedupeBlastEdges(traversedEdges) {
  const seenEdges = new Set();
  return traversedEdges.filter((edge) => {
    const key = `${edge.from}→${edge.to}`;
    if (seenEdges.has(key)) return false;
    seenEdges.add(key);
    return true;
  });
}

export function latticeBlast({
  chunkId,
  name,
  direction = 'both',
  depth = 3,
  limit = 50,
  deps = {},
} = {}) {
  if (!chunkId && !name) {
    return {
      nodes: [],
      edges: [],
      unresolvedNames: [],
      total: 0,
      truncated: false,
      message: '"chunkId" or "name" is required.',
    };
  }

  const allChunks = readAllChunks(deps);
  const chunkById = new Map(allChunks.map((chunk) => [chunk.id, chunk]));
  const chunksByName = buildChunksByName(allChunks);
  const { outEdges, inEdges } = buildBlastEdgeMaps(readAllEdges(deps));
  const seedIds = resolveBlastSeedIds(chunkId, name, chunkById, chunksByName);
  const desc = chunkId ? `chunk "${chunkId}"` : `"${name}"`;

  if (seedIds.length === 0) {
    return {
      nodes: [],
      edges: [],
      unresolvedNames: [],
      total: 0,
      truncated: false,
      message: `No chunk found for ${desc}.`,
    };
  }

  const { visited, traversedEdges, unresolvedNames } = traverseBlastGraph({
    seedIds,
    depth,
    direction,
    chunkById,
    chunksByName,
    outEdges,
    inEdges,
  });
  const allNodes = buildBlastNodes(visited, chunkById);
  const total = allNodes.length;
  const truncated = total > limit;
  const dirLabel = direction === 'callees' ? 'callee' : direction === 'callers' ? 'caller' : 'call-graph';
  const message = total === 0
    ? `No ${dirLabel} neighbors found for ${desc} within depth ${depth}.`
    : `Traversed ${total} node${total !== 1 ? 's' : ''} from ${desc} (direction: ${direction}, depth: ${depth})${truncated ? `; returning first ${limit}` : ''}.`;

  return {
    nodes: allNodes.slice(0, limit),
    edges: dedupeBlastEdges(traversedEdges),
    unresolvedNames: [...unresolvedNames],
    total,
    truncated,
    message,
  };
}

// ─── latticeCallees ───────────────────────────────────────────────────────────

/**
 * Find all symbols called by a given chunk (identified by chunkId or name).
 *
 * Callee names are resolved to chunk records where possible. Names that do
 * not match any known chunk are returned in `unresolvedNames`.
 *
 * @param {{
 *   chunkId?: string,  exact chunk id (takes priority over name)
 *   name?:    string,  chunk.name to look up the source chunk
 *   limit?:   number,  max resolved chunks returned (default 25)
 *   deps?:    object
 * }} [opts]
 * @returns {{
 *   chunks:          object[],   resolved callee chunks
 *   unresolvedNames: string[],   callee names with no matching chunk
 *   total:           number,     resolved + unresolved count
 *   truncated:       boolean,
 *   message:         string,
 * }}
 */
export function latticeCallees({ chunkId, name, limit = 25, deps = {} } = {}) {
  if (!chunkId && !name) {
    return { chunks: [], unresolvedNames: [], total: 0, truncated: false, message: '"chunkId" or "name" is required.' };
  }

  const allChunks = readAllChunks(deps);
  const edges = readAllEdges(deps);

  // Resolve source chunk id(s)
  let sourceIds;
  if (chunkId) {
    sourceIds = new Set([chunkId]);
  } else {
    sourceIds = new Set(allChunks.filter((c) => c.name === name).map((c) => c.id));
  }

  const desc = chunkId ? `chunk "${chunkId}"` : `"${name}"`;

  if (sourceIds.size === 0) {
    return { chunks: [], unresolvedNames: [], total: 0, truncated: false, message: `No chunk found for ${desc}.` };
  }

  // Unique callee names from outgoing edges
  const calleeNames = [
    ...new Set(edges.filter((e) => sourceIds.has(e.callerChunkId)).map((e) => e.calleeName)),
  ];

  // Build a name → first-chunk map for resolution
  const chunksByName = new Map();
  for (const c of allChunks) {
    if (c.name && !chunksByName.has(c.name)) chunksByName.set(c.name, c);
  }

  const resolvedChunks = [];
  const unresolvedNames = [];
  for (const cn of calleeNames) {
    const resolved = chunksByName.get(cn);
    if (resolved) resolvedChunks.push(resolved);
    else unresolvedNames.push(cn);
  }

  const total = resolvedChunks.length + unresolvedNames.length;
  const truncated = resolvedChunks.length > limit;
  const resultChunks = resolvedChunks.slice(0, limit);

  const message = total === 0
    ? `No callees found for ${desc}.`
    : `Found ${total} callee${total !== 1 ? 's' : ''} for ${desc} (${resolvedChunks.length} resolved, ${unresolvedNames.length} unresolved)${truncated ? `; returning first ${limit} resolved` : ''}.`;

  return { chunks: resultChunks, unresolvedNames, total, truncated, message };
}

/**
 * Plan Forge — Local Semantic Recall (Phase 55 + 56)
 *
 * Phase 55: TF-IDF + IDF-weighted cosine-similarity search over local .forge/
 * thought stores. Zero-dependency semantic-search fallback when OpenBrain
 * (L3 Postgres + pgvector) is not configured.
 *
 * Phase 56: Persistent TF-IDF index cache. The corpus index (token maps + IDF
 * weights) is serialised to `.forge/local-recall-index.json` after the first
 * search and reloaded on subsequent calls. Staleness is detected by comparing
 * the mtime of each source JSONL file against the index's `builtAt` timestamp;
 * any newer source file triggers a full rebuild.
 *
 * Optional upgrade: if @xenova/transformers is installed, neural embeddings
 * (all-MiniLM-L6-v2, 384-dim) replace TF-IDF for substantially better recall.
 * The upgrade is fully transparent — same inputs, same output shape.
 *
 * Output shape (ACI-compliant):
 *   { hits, total, backend, query, truncated, message }
 *
 * @module local-recall
 */

import { existsSync, readFileSync, writeFileSync, statSync, unlinkSync } from "node:fs";
import { resolve, join } from "node:path";
import { tokenize } from "./memory.mjs";

// ─── Constants ────────────────────────────────────────────────────────────────

/** Local .forge/ JSONL files that hold thoughts/memories. */
const THOUGHT_SOURCES = Object.freeze([
  "openbrain-queue.jsonl",
  "openbrain-queue.archive.jsonl",
  "openbrain-dlq.jsonl",
  "liveguard-memories.jsonl",
]);

const MAX_CORPUS = 500;      // max thoughts indexed
const DEFAULT_LIMIT = 5;     // default hits returned
const DEFAULT_THRESHOLD = 0.02; // min similarity score
const SNIPPET_CHARS = 120;   // chars per hit snippet

/** Filename for the persisted TF-IDF index (Phase 56). */
const INDEX_CACHE_FILE = "local-recall-index.json";
/** Current schema version — bump when the index format changes. */
const INDEX_VERSION = 1;

// ─── Thought loading ─────────────────────────────────────────────────────────

/**
 * Read a single JSONL file and return parsed records. Non-fatal on error.
 * @param {string} filePath
 * @returns {Array<object>}
 */
function readJsonl(filePath) {
  try {
    const raw = readFileSync(filePath, "utf-8");
    const records = [];
    for (const line of raw.split("\n")) {
      const trimmed = line.trim();
      if (!trimmed) continue;
      try { records.push(JSON.parse(trimmed)); } catch { /* skip malformed */ }
    }
    return records;
  } catch {
    return [];
  }
}

/**
 * Load thoughts from local .forge/ JSONL stores.
 * Returns at most MAX_CORPUS records (newest-first within each file).
 *
 * @param {string} [cwd=process.cwd()]
 * @param {{ sources?: string[], max?: number }} [opts]
 * @returns {Array<object>}
 */
export function readLocalThoughts(cwd = process.cwd(), opts = {}) {
  const forgeDir = resolve(cwd, ".forge");
  if (!existsSync(forgeDir)) return [];

  const sources = Array.isArray(opts.sources) ? opts.sources : THOUGHT_SOURCES;
  const max = typeof opts.max === "number" ? opts.max : MAX_CORPUS;
  const all = [];

  for (const src of sources) {
    if (all.length >= max) break;
    const records = readJsonl(join(forgeDir, src));
    const remaining = max - all.length;
    // Take from the end (newest records)
    all.push(...records.slice(-remaining));
  }

  return all;
}

// ─── TF-IDF engine ───────────────────────────────────────────────────────────

/**
 * Compute IDF weights from a corpus of token maps.
 * IDF(t) = log((N + 1) / (df(t) + 1)) + 1  (smooth)
 *
 * @param {Array<Map<string,number>>} tokenMaps
 * @returns {Map<string, number>} token → idf weight
 */
export function buildIdf(tokenMaps) {
  const N = tokenMaps.length;
  const df = new Map(); // document frequency
  for (const tMap of tokenMaps) {
    for (const token of tMap.keys()) {
      df.set(token, (df.get(token) || 0) + 1);
    }
  }
  const idf = new Map();
  for (const [token, freq] of df) {
    idf.set(token, Math.log((N + 1) / (freq + 1)) + 1);
  }
  return idf;
}

/**
 * Compute a TF-IDF weighted vector (as Map<token, weight>) for `text`.
 *
 * @param {string} text
 * @param {Map<string, number>} idf
 * @returns {Map<string, number>}
 */
export function tfIdfVector(text, idf) {
  const tf = tokenize(text);
  const vec = new Map();
  const len = tf.size || 1;
  for (const [token, count] of tf) {
    const w = (count / len) * (idf.get(token) ?? 1);
    vec.set(token, w);
  }
  return vec;
}

/**
 * Cosine similarity between two Map<string, number> vectors.
 *
 * @param {Map<string, number>} a
 * @param {Map<string, number>} b
 * @returns {number} [0, 1]
 */
export function vecCosineSimilarity(a, b) {
  if (!a.size || !b.size) return 0;
  let dot = 0;
  let magA = 0;
  let magB = 0;
  for (const v of a.values()) magA += v * v;
  for (const v of b.values()) magB += v * v;
  // Iterate the smaller map
  const [smaller, larger] = a.size <= b.size ? [a, b] : [b, a];
  for (const [token, v] of smaller) {
    const w = larger.get(token);
    if (w) dot += v * w;
  }
  const denom = Math.sqrt(magA) * Math.sqrt(magB);
  return denom === 0 ? 0 : dot / denom;
}

// ─── Persistent index cache (Phase 56) ───────────────────────────────────────

/**
 * Build a corpus index from an array of thought records.
 *
 * @param {Array<object>} thoughts
 * @returns {{ tokenMaps: Array<Array<[string,number]>>, idf: Array<[string,number]> }}
 *   Serialisable index — Maps converted to arrays for JSON round-trip.
 */
export function buildCorpusIndex(thoughts) {
  const contents = thoughts.map((t) => t.content || t.message || t.text || "");
  const tokenMaps = contents.map(tokenize);
  const idf = buildIdf(tokenMaps);
  return {
    tokenMaps: tokenMaps.map((m) => [...m]),
    idf: [...idf],
  };
}

/**
 * Return the mtime (ms since epoch) for each THOUGHT_SOURCE JSONL file that
 * exists inside `forgeDir`, or 0 when absent.
 *
 * @param {string} forgeDir  Absolute path to `.forge/`
 * @param {string[]} sources  Filenames to stat
 * @returns {Record<string, number>} fileName → mtime
 */
function _sourceMtimes(forgeDir, sources) {
  const mtimes = {};
  for (const src of sources) {
    const p = join(forgeDir, src);
    try {
      mtimes[src] = statSync(p).mtimeMs;
    } catch {
      mtimes[src] = 0;
    }
  }
  return mtimes;
}

/**
 * Persist the corpus index to `.forge/local-recall-index.json`.
 * Non-fatal on I/O error.
 *
 * @param {string} cwd
 * @param {object} index  Output of `buildCorpusIndex`.
 * @param {{ sources?: string[], corpusSize?: number }} [meta]
 */
export function persistIndex(cwd, index, meta = {}) {
  const forgeDir = resolve(cwd, ".forge");
  if (!existsSync(forgeDir)) return;
  const sources = Array.isArray(meta.sources) ? meta.sources : [...THOUGHT_SOURCES];
  const record = {
    version: INDEX_VERSION,
    builtAt: Date.now(),
    corpusSize: meta.corpusSize ?? (index.tokenMaps?.length ?? 0),
    sourceMtimes: _sourceMtimes(forgeDir, sources),
    index,
  };
  try {
    writeFileSync(join(forgeDir, INDEX_CACHE_FILE), JSON.stringify(record), "utf-8");
  } catch { /* non-fatal */ }
}

/**
 * Load the cached corpus index if it exists and is not stale.
 *
 * Staleness: any source JSONL file with an mtime newer than `builtAt` causes
 * a cache miss. A missing source counts as mtime 0 (never newer).
 *
 * @param {string} cwd
 * @param {{ sources?: string[] }} [opts]
 * @returns {{ tokenMaps: Map<string,number>[], idf: Map<string,number> } | null}
 *   Hydrated Maps, or null on cache miss / stale / version mismatch.
 */
export function loadCachedIndex(cwd, opts = {}) {
  const forgeDir = resolve(cwd, ".forge");
  const cachePath = join(forgeDir, INDEX_CACHE_FILE);
  if (!existsSync(cachePath)) return null;

  let record;
  try {
    record = JSON.parse(readFileSync(cachePath, "utf-8"));
  } catch { return null; }

  if (record.version !== INDEX_VERSION) return null;
  if (!record.builtAt || !record.index) return null;

  const sources = Array.isArray(opts.sources) ? opts.sources : [...THOUGHT_SOURCES];
  const currentMtimes = _sourceMtimes(forgeDir, sources);
  for (const src of sources) {
    const stored = record.sourceMtimes?.[src] ?? 0;
    const current = currentMtimes[src] ?? 0;
    if (current !== stored) return null; // added, modified, or removed
  }

  try {
    const tokenMaps = record.index.tokenMaps.map((arr) => new Map(arr));
    const idf = new Map(record.index.idf);
    return { tokenMaps, idf };
  } catch { return null; }
}

/**
 * Delete the persisted index file, if it exists.
 * Non-fatal on I/O error.
 *
 * @param {string} [cwd=process.cwd()]
 */
export function clearPersistedIndex(cwd = process.cwd()) {
  const cachePath = join(resolve(cwd, ".forge"), INDEX_CACHE_FILE);
  try {
    if (existsSync(cachePath)) unlinkSync(cachePath);
  } catch { /* non-fatal */ }
}

/**
 * Return diagnostic information about the persisted index.
 *
 * @param {string} [cwd=process.cwd()]
 * @returns {{
 *   exists: boolean,
 *   version: number|null,
 *   builtAt: string|null,
 *   corpusSize: number|null,
 *   stale: boolean|null,
 *   cacheFile: string
 * }}
 */
export function getIndexStatus(cwd = process.cwd()) {
  const forgeDir = resolve(cwd, ".forge");
  const cachePath = join(forgeDir, INDEX_CACHE_FILE);

  if (!existsSync(cachePath)) {
    return { exists: false, version: null, builtAt: null, corpusSize: null, stale: null, cacheFile: cachePath };
  }

  let record;
  try { record = JSON.parse(readFileSync(cachePath, "utf-8")); }
  catch { return { exists: true, version: null, builtAt: null, corpusSize: null, stale: null, cacheFile: cachePath }; }

  const sources = [...THOUGHT_SOURCES];
  const currentMtimes = _sourceMtimes(forgeDir, sources);
  const stale = record.sourceMtimes
    ? sources.some((s) => (currentMtimes[s] ?? 0) !== (record.sourceMtimes[s] ?? 0))
    : null;

  return {
    exists: true,
    version: record.version ?? null,
    builtAt: record.builtAt ? new Date(record.builtAt).toISOString() : null,
    corpusSize: record.corpusSize ?? null,
    stale,
    cacheFile: cachePath,
  };
}

// ─── Neural embedding probe ──────────────────────────────────────────────────

let _neuralProbeCache = null; // null = unchecked, false = unavailable, true = available

/**
 * Check whether @xenova/transformers is importable. Result is cached after
 * the first check to avoid repeated dynamic-import overhead.
 *
 * @returns {Promise<boolean>}
 */
export async function isNeuralEmbeddingAvailable() {
  if (_neuralProbeCache !== null) return _neuralProbeCache;
  try {
    await import("@xenova/transformers");
    _neuralProbeCache = true;
  } catch {
    _neuralProbeCache = false;
  }
  return _neuralProbeCache;
}

/** Reset the neural probe cache (for tests). */
export function _resetNeuralProbeCache() {
  _neuralProbeCache = null;
}

/**
 * Embed a list of texts using @xenova/transformers (all-MiniLM-L6-v2).
 * Returns Float32Array per text, or null on failure.
 *
 * @param {string[]} texts
 * @returns {Promise<Float32Array[]|null>}
 */
async function _neuralEmbed(texts) {
  try {
    const { pipeline } = await import("@xenova/transformers");
    const embedder = await pipeline("feature-extraction", "Xenova/all-MiniLM-L6-v2", { quantized: true });
    const results = [];
    for (const text of texts) {
      const output = await embedder(text, { pooling: "mean", normalize: true });
      results.push(output.data);
    }
    return results;
  } catch {
    return null;
  }
}

/**
 * Cosine similarity between two Float32Arrays.
 */
function float32Cosine(a, b) {
  let dot = 0;
  let magA = 0;
  let magB = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    magA += a[i] * a[i];
    magB += b[i] * b[i];
  }
  const denom = Math.sqrt(magA) * Math.sqrt(magB);
  return denom === 0 ? 0 : dot / denom;
}

// ─── Search ───────────────────────────────────────────────────────────────────

/**
 * Extract a displayable snippet from a thought record.
 * @param {object} thought
 * @returns {string}
 */
function thoughtSnippet(thought) {
  const raw = thought.content || thought.message || thought.text || "";
  return raw.length > SNIPPET_CHARS ? raw.slice(0, SNIPPET_CHARS) + "…" : raw;
}

/**
 * Normalize and default the raw opts bag for searchLocalThoughts.
 *
 * @param {object} opts
 * @returns {{ cwd: string, limit: number, threshold: number, sources: string[]|undefined, forceBackend: string|undefined, noCache: boolean }}
 */
function _buildSearchOptions(opts) {
  return {
    cwd: opts.cwd ?? process.cwd(),
    limit: opts.limit ?? DEFAULT_LIMIT,
    threshold: opts.threshold ?? DEFAULT_THRESHOLD,
    sources: opts.sources,
    forceBackend: opts.forceBackend,
    noCache: opts.noCache ?? false,
  };
}

/**
 * Determine which search backend to use.
 * Returns 'neural' when @xenova/transformers is available (and not overridden),
 * otherwise 'tfidf'.
 *
 * @param {string|undefined} forceBackend
 * @returns {Promise<'neural'|'tfidf'>}
 */
async function _chooseBackend(forceBackend) {
  if (forceBackend === "neural") return "neural";
  if (forceBackend === "tfidf") return "tfidf";
  return (await isNeuralEmbeddingAvailable()) ? "neural" : "tfidf";
}

/**
 * Run the TF-IDF search path, using and updating the persisted index cache.
 *
 * @param {string} query
 * @param {Array<object>} thoughts
 * @param {string} cwd
 * @param {{ sources?: string[], noCache?: boolean, limit: number, threshold: number }} tfidfOpts
 * @returns {Array<object>}
 */
function _runTfidfPath(query, thoughts, cwd, tfidfOpts) {
  const { sources, noCache, limit, threshold } = tfidfOpts;
  const resolvedSources = sources ?? [...THOUGHT_SOURCES];
  const cachedIdx = noCache ? null : loadCachedIndex(cwd, { sources: resolvedSources });
  if (cachedIdx) {
    return _tfidfSearchWithIndex(query, thoughts, cachedIdx.tokenMaps, cachedIdx.idf, limit, threshold);
  }
  const hits = _tfidfSearch(query, thoughts, limit, threshold);
  if (!noCache) {
    const built = buildCorpusIndex(thoughts);
    persistIndex(cwd, built, { sources: resolvedSources, corpusSize: thoughts.length });
  }
  return hits;
}

/**
 * Search local .forge/ thoughts by semantic similarity.
 *
 * TF-IDF path uses a disk-persisted corpus index (Phase 56). On the first call
 * the index is built and saved to `.forge/local-recall-index.json`; subsequent
 * calls reload the cached index unless any source JSONL has been modified.
 * Neural path always rebuilds embeddings (the WASM model is already fast).
 *
 * @param {string} query
 * @param {{
 *   cwd?: string,
 *   limit?: number,
 *   threshold?: number,
 *   sources?: string[],
 *   forceBackend?: 'tfidf'|'neural',
 *   noCache?: boolean
 * }} [opts]
 * @returns {Promise<{
 *   hits: Array, total: number, backend: string,
 *   query: string, truncated: boolean, message: string
 * }>}
 */
export async function searchLocalThoughts(query, opts = {}) {
  if (!query || typeof query !== "string" || !query.trim()) {
    return _emptyResult(query || "", "Query must be a non-empty string.");
  }

  const { cwd, limit, threshold, sources, forceBackend, noCache } = _buildSearchOptions(opts);

  const thoughts = readLocalThoughts(cwd, { sources });
  if (thoughts.length === 0) {
    return _emptyResult(query, "No local thoughts found in .forge/ — capture some with forge_capture_thought or run a plan to build memory.");
  }

  const backend = await _chooseBackend(forceBackend);
  const hits = backend === "neural"
    ? await _neuralSearch(query, thoughts, limit, threshold)
    : _runTfidfPath(query, thoughts, cwd, { sources, noCache, limit, threshold });

  const truncated = thoughts.length >= MAX_CORPUS;

  return {
    hits,
    total: hits.length,
    corpusSize: thoughts.length,
    backend,
    query,
    truncated,
    message: hits.length > 0
      ? `Found ${hits.length} matching thought${hits.length === 1 ? "" : "s"} (${backend} backend, corpus: ${thoughts.length}).`
      : `No thoughts matched query "${query}" above threshold ${threshold} (${backend} backend, corpus: ${thoughts.length}). Try a broader query or lower threshold.`,
  };
}

/**
 * TF-IDF path: rank all thoughts by cosine similarity to query.
 * Builds the corpus index internally (no cache).
 */
function _tfidfSearch(query, thoughts, limit, threshold) {
  const contents = thoughts.map((t) => t.content || t.message || t.text || "");
  const tokenMaps = contents.map(tokenize);
  const idf = buildIdf(tokenMaps);
  return _tfidfSearchWithIndex(query, thoughts, tokenMaps, idf, limit, threshold);
}

/**
 * TF-IDF path with pre-built index (cache hit path).
 *
 * @param {string} query
 * @param {Array<object>} thoughts
 * @param {Map<string,number>[]} tokenMaps  Pre-computed raw token-count maps
 * @param {Map<string,number>} idf          Pre-computed IDF weights
 * @param {number} limit
 * @param {number} threshold
 */
function _tfidfSearchWithIndex(query, thoughts, tokenMaps, idf, limit, threshold) {
  const queryVec = tfIdfVector(query, idf);
  const scored = thoughts.map((thought, i) => {
    const rawTf = tokenMaps[i];        // Map<string, count> from tokenize()
    const len = rawTf.size || 1;
    const docVec = new Map();
    for (const [token, count] of rawTf) {
      docVec.set(token, (count / len) * (idf.get(token) ?? 1));
    }
    const score = vecCosineSimilarity(queryVec, docVec);
    return { thought, score };
  });
  return _topHits(scored, limit, threshold);
}

/**
 * Neural path: embed query + all thought contents, rank by cosine.
 * Falls back to TF-IDF if embedding fails.
 */
async function _neuralSearch(query, thoughts, limit, threshold) {
  const contents = thoughts.map((t) => t.content || t.message || t.text || "");
  const allTexts = [query, ...contents];
  const vectors = await _neuralEmbed(allTexts);

  if (!vectors || vectors.length !== allTexts.length) {
    return _tfidfSearch(query, thoughts, limit, threshold);
  }

  const queryVec = vectors[0];
  const scored = thoughts.map((thought, i) => ({
    thought,
    score: float32Cosine(queryVec, vectors[i + 1]),
  }));

  return _topHits(scored, limit, threshold);
}

/**
 * Filter, sort, and format the top scored hits.
 */
function _topHits(scored, limit, threshold) {
  return scored
    .filter(({ score }) => score >= threshold)
    .sort((a, b) => b.score - a.score)
    .slice(0, limit)
    .map(({ thought, score }) => ({
      source: thought.source || thought._source || "local",
      project: thought.project || thought._project || null,
      type: thought.type || thought._type || null,
      snippet: thoughtSnippet(thought),
      score: Math.round(score * 10000) / 10000,
      createdAt: thought._enqueuedAt || thought.created_at || thought.timestamp || null,
    }));
}

function _emptyResult(query, message) {
  return { hits: [], total: 0, corpusSize: 0, backend: "none", query, truncated: false, message };
}

/**
 * Plan Forge — OpenBrain Memory Integration
 *
 * Integrates persistent semantic memory into the orchestrator pipeline.
 * When OpenBrain is configured, the orchestrator:
 *   - Injects memory search results into worker prompts (before each slice)
 *   - Instructs workers to capture decisions (after each slice)
 *   - Captures run summaries as thoughts (after completion)
 *
 * All integration is opt-in: if OpenBrain is not configured, all functions
 * return empty strings / no-ops. Zero impact on non-OpenBrain users.
 *
 * @module memory
 */

import { readFileSync, writeFileSync, appendFileSync, mkdirSync, existsSync, statSync, readdirSync, unlinkSync, renameSync } from "node:fs";
import { resolve, join } from "node:path";
import { createHash } from "node:crypto";

/**
 * Default keyword patterns mapped to targeted search queries for `search_thoughts`.
 * Matched against slice titles to generate domain-specific context requests.
 * G3.4 (v2.36): projects can override via `.forge.json` → `openbrain.keywordMap`
 * using the same shape — see `loadKeywordSearchMap()`.
 */
const DEFAULT_KEYWORD_SEARCH_MAP = [
  { pattern: /\b(database|migration|schema|alter|seed|index|ef\s+core|dbcontext|repository)\b/i, query: "database migration patterns" },
  { pattern: /\b(auth|token|rbac|jwt|oauth|password|credential|permission|role)\b/i, query: "authentication authorization patterns" },
  { pattern: /\b(api|endpoint|route|controller|http|rest|graphql)\b/i, query: "API endpoint design patterns" },
  { pattern: /\b(test|spec|jest|xunit|mocha|vitest|coverage)\b/i, query: "testing patterns conventions" },
  { pattern: /\b(deploy|ci|cd|pipeline|docker|kubernetes|container)\b/i, query: "deployment pipeline patterns" },
  { pattern: /\b(ui|component|react|vue|angular|frontend|css)\b/i, query: "UI component patterns" },
  { pattern: /\b(cache|redis|memcache|invalidat)\b/i, query: "caching invalidation patterns" },
  { pattern: /\b(error|exception|logging|monitor|alert)\b/i, query: "error handling logging patterns" },
  { pattern: /\b(memory|openbrain|context|semantic)\b/i, query: "memory context integration patterns" },
];

// Back-compat alias — some downstream code / tests imported this symbol.
const KEYWORD_SEARCH_MAP = DEFAULT_KEYWORD_SEARCH_MAP;

/**
 * G3.4 (v2.36): load the active keyword-search map. Order of precedence:
 *   1. `.forge.json` → `openbrain.keywordMap: [{ pattern: "regex", flags?: "i", query: "..." }, ...]`
 *   2. Built-in `DEFAULT_KEYWORD_SEARCH_MAP`
 *
 * Invalid entries (missing pattern/query, malformed regex) are skipped with
 * a console warning — never throws. Returns an array of `{pattern: RegExp, query: string}`.
 *
 * @param {string} [cwd=process.cwd()]
 * @returns {Array<{pattern: RegExp, query: string}>}
 */
export function loadKeywordSearchMap(cwd = process.cwd()) {
  try {
    const cfgPath = resolve(cwd, ".forge.json");
    if (!existsSync(cfgPath)) return DEFAULT_KEYWORD_SEARCH_MAP;
    const cfg = JSON.parse(readFileSync(cfgPath, "utf-8"));
    const custom = cfg?.openbrain?.keywordMap;
    if (!Array.isArray(custom) || custom.length === 0) return DEFAULT_KEYWORD_SEARCH_MAP;

    const compiled = [];
    for (const entry of custom) {
      if (!entry || typeof entry.pattern !== "string" || typeof entry.query !== "string") continue;
      try {
        const flags = typeof entry.flags === "string" ? entry.flags : "i";
        compiled.push({ pattern: new RegExp(entry.pattern, flags), query: entry.query });
      } catch (err) {
        console.error(`[memory] skipping invalid keywordMap entry (${entry.pattern}): ${err.message}`);
      }
    }
    return compiled.length > 0 ? compiled : DEFAULT_KEYWORD_SEARCH_MAP;
  } catch {
    return DEFAULT_KEYWORD_SEARCH_MAP;
  }
}

/**
 * Load project-level context to prepend to slice prompts.
 *
 * Reads key project files (README, architecture docs) and generates
 * slice-specific `search_thoughts` instructions based on keywords in the
 * slice title.  Returns an empty string when cwd is falsy or nothing
 * useful can be found — callers can concatenate unconditionally.
 *
 * @param {string} cwd - Working directory
 * @param {string} projectName - Project name for scoping OpenBrain searches
 * @param {string} sliceTitle - Title of the current slice (keyword matching)
 * @returns {string} Context block to prepend to the slice prompt, or ""
 */
export function loadProjectContext(cwd, projectName, sliceTitle) {
  if (!cwd) return "";

  const parts = [];

  // ── Project file snippets ──────────────────────────────────────────────
  const candidates = [
    { path: resolve(cwd, "README.md"),                   label: "Project README",  maxLines: 50 },
    { path: resolve(cwd, "ARCHITECTURE.md"),             label: "Architecture",    maxLines: 80 },
    { path: resolve(cwd, "docs", "ARCHITECTURE.md"),     label: "Architecture",    maxLines: 80 },
    { path: resolve(cwd, ".github", "CONTRIBUTING.md"),  label: "Contributing",    maxLines: 30 },
    { path: resolve(cwd, "CONTRIBUTING.md"),             label: "Contributing",    maxLines: 30 },
  ];

  const seen = new Set();
  for (const { path: filePath, label, maxLines } of candidates) {
    if (seen.has(label)) continue; // only first match per label
    try {
      if (existsSync(filePath)) {
        const content = readFileSync(filePath, "utf-8");
        const snippet = content.split("\n").slice(0, maxLines).join("\n");
        parts.push(`### ${label}\n${snippet}`);
        seen.add(label);
      }
    } catch { /* skip unreadable files */ }
  }

  if (parts.length > 0) {
    parts.unshift("--- PROJECT CONTEXT ---");
    parts.push("--- END PROJECT CONTEXT ---");
  }

  // ── Slice-specific deep-context searches ──────────────────────────────
  if (sliceTitle && projectName) {
    // G3.4 (v2.36): use the configurable map instead of the frozen default.
    const keywordMap = loadKeywordSearchMap(cwd);
    const matchedQueries = keywordMap
      .filter(({ pattern }) => pattern.test(sliceTitle))
      .map(({ query }) => query);

    if (matchedQueries.length > 0) {
      parts.push("");
      parts.push("--- DEEP CONTEXT (OpenBrain) ---");
      parts.push("Search for domain-specific prior decisions before starting:");
      for (const query of matchedQueries) {
        parts.push(`  Use search_thoughts tool with query: "${query}", project: "${projectName}", limit: 5`);
      }
      parts.push("Apply findings to avoid repeating known patterns and mistakes.");
      parts.push("--- END DEEP CONTEXT ---");
    }
  }

  return parts.length > 0 ? parts.join("\n") + "\n" : "";
}

/**
 * Check if OpenBrain is configured in .vscode/mcp.json.
 */
export function isOpenBrainConfigured(cwd) {
  const mcpConfigPaths = [
    resolve(cwd, ".vscode", "mcp.json"),
    resolve(cwd, ".claude", "mcp.json"),
  ];

  for (const configPath of mcpConfigPaths) {
    try {
      if (existsSync(configPath)) {
        const config = readFileSync(configPath, "utf-8");
        if (config.includes("openbrain") || config.includes("open-brain")) {
          return true;
        }
      }
    } catch { /* ignore */ }
  }
  return false;
}

/**
 * Build memory search instructions to prepend to a worker prompt.
 * The worker (gh copilot) will execute the search_thoughts call.
 *
 * @param {string} projectName - Project name for scoping
 * @param {object} slice - Slice metadata
 * @returns {string} Memory context block to prepend to prompt
 */
export function buildMemorySearchBlock(projectName, slice) {
  return `
--- MEMORY CONTEXT (OpenBrain) ---
Before starting work, search for relevant prior decisions:

1. Search for project conventions:
   Use the search_thoughts tool with query: "conventions patterns ${slice.title}"
   project: "${projectName}", type: "convention", limit: 5

2. Search for prior lessons on similar work:
   Use the search_thoughts tool with query: "${slice.title} ${slice.tasks?.[0] || ''}"
   project: "${projectName}", limit: 5

Apply any relevant findings. Do NOT repeat mistakes documented in prior thoughts.
--- END MEMORY CONTEXT ---
`;
}

/**
 * Build memory capture instructions to append to a worker prompt.
 * The worker will capture key decisions after completing work.
 *
 * @param {string} projectName - Project name
 * @param {object} slice - Slice metadata
 * @param {string} planName - Plan file name
 * @returns {string} Capture instructions block
 */
export function buildMemoryCaptureBlock(projectName, slice, planName) {
  return `
--- MEMORY CAPTURE (OpenBrain) ---
After completing all tasks and passing validation gates, capture key decisions:

Use the capture_thought tool for each significant decision:
- content: "Decision: <what you decided and why>"
- project: "${projectName}"
- source: "plan-forge-orchestrator/${planName}/slice-${slice.number}"
- created_by: "gh-copilot-worker"

Capture:
1. Architecture decisions made during this slice
2. Patterns chosen (and why alternatives were rejected)
3. Any gotchas or constraints discovered
4. Conventions established that future slices should follow

Do NOT capture trivial facts. Focus on decisions that would save time in future phases.
--- END MEMORY CAPTURE ---
`;
}

/**
 * Build a Reflexion-style "previous attempt summary" prompt block for retries.
 *
 * Phase-25 Slice 1 (L1 — Reflexion). On retry attempt N ≥ 2, `executeSlice`
 * prepends this Markdown block to the worker prompt so the worker can learn
 * from the previous failure instead of repeating it.
 *
 * Contract (Phase-25 MUST #1):
 *   - Header: `## Previous attempt (N-1) summary`
 *   - Contains: gate name, chosen model, duration, stderr tail (≤2KB)
 *   - Markdown prose format (D1) — workers consume prose well
 *
 * Pure function: no fs, no network, deterministic. Safe to test in isolation.
 *
 * @param {object} ctx
 * @param {number} ctx.previousAttempt - The 1-based attempt number that failed (the one being summarized).
 * @param {string} [ctx.gateName] - Gate command that failed (e.g. "npx vitest run"). Defaults to "unknown".
 * @param {string} [ctx.model] - Model used for the failed attempt (e.g. "claude-sonnet-4.5"). Defaults to "auto".
 * @param {number} [ctx.durationMs] - Duration of the failed attempt in milliseconds. Defaults to 0.
 * @param {string} [ctx.stderrTail] - Stderr / gate-error text from the failed attempt. Truncated to last 2KB.
 * @returns {string} Markdown block ready to prepend to the worker prompt.
 */
export function buildReflexionBlock(ctx = {}) {
  const MAX_STDERR_BYTES = 2048;
  const previousAttempt = Number.isFinite(ctx.previousAttempt) && ctx.previousAttempt > 0
    ? ctx.previousAttempt
    : 1;
  const gateName = typeof ctx.gateName === "string" && ctx.gateName.length > 0
    ? ctx.gateName
    : "unknown";
  const model = typeof ctx.model === "string" && ctx.model.length > 0
    ? ctx.model
    : "auto";
  const durationMs = Number.isFinite(ctx.durationMs) && ctx.durationMs >= 0
    ? Math.round(ctx.durationMs)
    : 0;

  const rawStderr = typeof ctx.stderrTail === "string" ? ctx.stderrTail : "";
  let stderrTail = rawStderr;
  let truncated = false;
  if (rawStderr.length > MAX_STDERR_BYTES) {
    stderrTail = rawStderr.slice(-MAX_STDERR_BYTES);
    truncated = true;
  }

  const tailBody = stderrTail.length > 0 ? stderrTail : "(no stderr captured)";

  return [
    `## Previous attempt (${previousAttempt}) summary`,
    "",
    `- **Gate that failed**: \`${gateName}\``,
    `- **Model used**: \`${model}\``,
    `- **Duration**: ${durationMs}ms`,
    "",
    truncated
      ? `**Failure output (stderr tail, truncated to last ${MAX_STDERR_BYTES} bytes):**`
      : "**Failure output (stderr tail, ≤2KB):**",
    "",
    "```",
    tailBody,
    "```",
    "",
    "Use this summary to avoid repeating the same mistake. Address the specific error above before the next gate run.",
    "",
  ].join("\n");
}

// ─── Phase-25 Slice 2: Trajectory notes (L8) ──────────────────────────

/**
 * Sentinels used by `buildTrajectorySuffix` / `extractTrajectory` to bracket
 * the worker's trajectory note in its stdout.
 */
export const TRAJECTORY_BEGIN_SENTINEL = "<!-- PFORGE_TRAJECTORY:BEGIN -->";
export const TRAJECTORY_END_SENTINEL = "<!-- PFORGE_TRAJECTORY:END -->";

/**
 * Phase-25 D2: maximum words retained in a persisted trajectory note.
 * Overage truncated with a `[truncated]` marker.
 */
export const TRAJECTORY_MAX_WORDS = 500;

/**
 * Build the trajectory-note prompt suffix appended to a slice worker prompt.
 * Asks the worker to emit a first-person prose note wrapped in sentinels so
 * later slices in the same plan can learn from the approach (Phase-25 L8,
 * scenario 5 — "Operator verbalizes intent for the next slice").
 *
 * Pure function: deterministic, no fs, no network.
 *
 * @returns {string} Prompt suffix (newline-prefixed + suffixed for clean concat).
 */
export function buildTrajectorySuffix() {
  return `
--- TRAJECTORY NOTE (Phase-25 L8) ---
After your work is complete and the validation gate has been run, emit a
brief first-person prose note (≤${TRAJECTORY_MAX_WORDS} words) wrapped in
sentinels so later slices in the same plan can learn from your approach.

Format — exactly these three lines, in order:
${TRAJECTORY_BEGIN_SENTINEL}
<your prose note — a few short paragraphs>
${TRAJECTORY_END_SENTINEL}

Cover, in plain prose:
- The approach you chose and why.
- Any dead-ends you ruled out.
- Gotchas a future slice should watch for.
- Key file or function names a later slice may need to touch.

This is NOT a summary of the plan. Do not include commands, code blocks,
bullet lists of commits, or machine-readable structures — prose only.
--- END TRAJECTORY NOTE ---
`;
}

/**
 * Extract the trajectory sentinel block from worker stdout.
 * Returns the trimmed content between sentinels, or null when not present.
 *
 * @param {string} output
 * @returns {string|null}
 */
export function extractTrajectory(output) {
  if (typeof output !== "string") return null;
  const beginIdx = output.indexOf(TRAJECTORY_BEGIN_SENTINEL);
  if (beginIdx < 0) return null;
  const endIdx = output.indexOf(TRAJECTORY_END_SENTINEL, beginIdx + TRAJECTORY_BEGIN_SENTINEL.length);
  if (endIdx < 0) return null;
  const body = output.slice(beginIdx + TRAJECTORY_BEGIN_SENTINEL.length, endIdx).trim();
  return body.length > 0 ? body : null;
}

/**
 * Cap a trajectory note at `maxWords` words. When capped, append "\n\n[truncated]"
 * per Phase-25 D2. Whitespace is normalized to single spaces in the word count
 * but the original prose layout is preserved up to the cut.
 *
 * @param {string} content
 * @param {number} [maxWords=TRAJECTORY_MAX_WORDS]
 * @returns {string}
 */
export function capTrajectoryWords(content, maxWords = TRAJECTORY_MAX_WORDS) {
  if (typeof content !== "string") return "";
  const trimmed = content.trim();
  if (trimmed.length === 0) return "";
  const tokens = trimmed.split(/\s+/);
  if (tokens.length <= maxWords) return trimmed;
  // Preserve original layout up to the nth word. Walk the raw string and stop
  // once we've consumed `maxWords` whitespace-separated runs.
  let count = 0;
  let cutAt = trimmed.length;
  let inWord = false;
  for (let i = 0; i < trimmed.length; i++) {
    const isWs = /\s/.test(trimmed[i]);
    if (!isWs && !inWord) {
      count++;
      inWord = true;
      if (count > maxWords) {
        cutAt = i;
        break;
      }
    } else if (isWs) {
      inWord = false;
    }
  }
  return trimmed.slice(0, cutAt).trimEnd() + "\n\n[truncated]";
}

/**
 * Sanitize an untrusted string for safe use as a filesystem path component.
 * Keeps `[A-Za-z0-9._-]` only, collapses everything else to `_`, strips any
 * remaining `..` sequences (to prevent path traversal), and caps length.
 */
function sanitizePathComponent(s) {
  let cleaned = String(s ?? "").replace(/[^A-Za-z0-9._-]/g, "_");
  // Collapse any `..` sequences (even the trailing ones left after other
  // chars were replaced) to prevent escaping the intended directory root.
  while (cleaned.includes("..")) {
    cleaned = cleaned.replace(/\.\./g, "_");
  }
  cleaned = cleaned.slice(0, 128);
  return cleaned.length > 0 ? cleaned : "_";
}

/**
 * Persist a trajectory note to `.forge/trajectories/<plan>/slice-<id>.md`.
 * Word-capped to `TRAJECTORY_MAX_WORDS` (Phase-25 MUST #2 + D2).
 *
 * @param {object} opts
 * @param {string} [opts.cwd=process.cwd()]
 * @param {string} opts.planBasename - Plan file name without extension.
 * @param {(string|number)} opts.sliceId
 * @param {string} opts.content - Raw trajectory prose.
 * @returns {string} Absolute path of the written file.
 */
export function writeTrajectory({ cwd = process.cwd(), planBasename, sliceId, content }) {
  if (!planBasename || typeof planBasename !== "string") {
    throw new Error("writeTrajectory: planBasename is required");
  }
  if (sliceId === undefined || sliceId === null || sliceId === "") {
    throw new Error("writeTrajectory: sliceId is required");
  }
  const safePlan = sanitizePathComponent(planBasename);
  const safeSlice = sanitizePathComponent(String(sliceId));
  const dir = resolve(cwd, ".forge", "trajectories", safePlan);
  mkdirSync(dir, { recursive: true });
  const path = resolve(dir, `slice-${safeSlice}.md`);
  const capped = capTrajectoryWords(content);
  writeFileSync(path, capped, "utf-8");
  return path;
}

/**
 * Read a single trajectory note. Returns `null` when the file does not exist.
 */
export function readTrajectory({ cwd = process.cwd(), planBasename, sliceId }) {
  if (!planBasename || sliceId === undefined || sliceId === null || sliceId === "") return null;
  const safePlan = sanitizePathComponent(planBasename);
  const safeSlice = sanitizePathComponent(String(sliceId));
  const path = resolve(cwd, ".forge", "trajectories", safePlan, `slice-${safeSlice}.md`);
  if (!existsSync(path)) return null;
  try {
    return readFileSync(path, "utf-8");
  } catch {
    return null;
  }
}

/**
 * List every trajectory note for a plan, sorted numerically by slice id when
 * possible. Returns `[]` when the directory does not exist.
 */
export function listTrajectories({ cwd = process.cwd(), planBasename }) {
  if (!planBasename) return [];
  const safePlan = sanitizePathComponent(planBasename);
  const dir = resolve(cwd, ".forge", "trajectories", safePlan);
  if (!existsSync(dir)) return [];
  let files;
  try {
    files = readdirSync(dir);
  } catch {
    return [];
  }
  const entries = [];
  for (const f of files) {
    const m = /^slice-(.+)\.md$/.exec(f);
    if (!m) continue;
    const sliceId = m[1];
    const fullPath = resolve(dir, f);
    let content = "";
    try { content = readFileSync(fullPath, "utf-8"); } catch { /* skip unreadable */ }
    entries.push({ sliceId, path: fullPath, content });
  }
  entries.sort((a, b) => {
    const an = Number(a.sliceId);
    const bn = Number(b.sliceId);
    if (Number.isFinite(an) && Number.isFinite(bn)) return an - bn;
    return a.sliceId.localeCompare(b.sliceId);
  });
  return entries;
}

// ─── Phase-25 Slice 3: Auto-skill library (L2 — Voyager) ──────────────

/** Subdirectory under `.forge/` where auto-skill candidates are stored. */
const AUTOSKILL_DIR = "skills-auto";

/** SHA-256 prefix length used in auto-skill file names (Phase-25 D4). */
export const AUTOSKILL_SHA_PREFIX_LEN = 12;

/** Default promotion threshold for auto-skill reuses (Phase-25 D3). */
export const AUTOSKILL_DEFAULT_THRESHOLD = 3;

/**
 * Derive domain keywords for a slice by matching its title (and, if present,
 * its file list) against the keyword search map. Returns canonical query
 * strings (e.g. "database migration patterns") — the same vocabulary used by
 * `buildMemorySearchBlock`, so auto-skills and memory search share indexing.
 *
 * @param {object} slice
 * @param {string} [cwd=process.cwd()]
 * @returns {string[]} Unique list of matched domain query strings.
 */
export function extractDomainKeywords(slice, cwd = process.cwd()) {
  if (!slice) return [];
  const fileList = Array.isArray(slice.files) ? slice.files : [];
  const haystack = [slice.title || "", ...fileList].join(" ").toLowerCase();
  const map = loadKeywordSearchMap(cwd);
  const hits = [];
  for (const entry of map) {
    if (entry.pattern.test(haystack) && !hits.includes(entry.query)) {
      hits.push(entry.query);
    }
  }
  return hits;
}

function inferAutoSkillSliceType(slice) {
  const t = String(slice?.title || "").toLowerCase();
  if (/\btest|spec\b/.test(t)) return "test";
  if (/\bdoc|readme|changelog|manual\b/.test(t)) return "doc";
  if (/\bdeploy|ship|release\b/.test(t)) return "deploy";
  if (/\bfix|bug|hotfix\b/.test(t)) return "fix";
  return "execute";
}

function autoSkillPrefix(summary, commands) {
  const h = createHash("sha256");
  h.update(String(summary || ""));
  h.update("\n");
  h.update((Array.isArray(commands) ? commands : []).join("\n"));
  return h.digest("hex").slice(0, AUTOSKILL_SHA_PREFIX_LEN);
}

/**
 * Parse a slice's validationGate (string or string[]) into an array of
 * runnable shell commands, dropping blank lines and `#` comments.
 */
function parseGateCommands(rawGate) {
  let lines = [];
  if (Array.isArray(rawGate)) {
    lines = rawGate;
  } else if (typeof rawGate === "string") {
    lines = rawGate.split("\n");
  } else {
    return [];
  }
  return lines
    .map((s) => (typeof s === "string" ? s.trim() : ""))
    .filter((s) => s.length > 0 && !s.startsWith("#"));
}

/**
 * Build an auto-skill record from a passing slice. Pure function — no fs.
 * Returns `null` when the slice has no validation-gate commands to capture.
 *
 * MUST #3 schema: { sha256Prefix, summary, commands[], contextSignature,
 *                   reuseCount: 0, createdAt }.
 *
 * @param {object} args
 * @param {object} args.slice
 * @param {string} [args.planBasename]
 * @param {string} [args.cwd]
 * @param {string} [args.now] ISO timestamp override (for deterministic tests).
 * @returns {object|null}
 */
export function extractAutoSkill({ slice, planBasename = "", cwd = process.cwd(), now } = {}) {
  if (!slice || typeof slice !== "object") return null;
  const commands = parseGateCommands(slice.validationGate);
  if (commands.length === 0) return null;

  const domainKeywords = extractDomainKeywords(slice, cwd);
  const titleHash = createHash("sha256")
    .update(String(slice.title || ""))
    .digest("hex")
    .slice(0, 8);
  const summary = String(slice.title || `slice-${slice.number ?? "unknown"}`).slice(0, 200);
  const sha256Prefix = autoSkillPrefix(summary, commands);
  const createdAt = typeof now === "string" && now.length > 0 ? now : new Date().toISOString();

  return {
    sha256Prefix,
    summary,
    commands,
    contextSignature: {
      sliceType: inferAutoSkillSliceType(slice),
      domainKeywords,
      titleHash,
      planBasename: typeof planBasename === "string" ? planBasename : "",
    },
    reuseCount: 0,
    createdAt,
  };
}

/**
 * Serialize an auto-skill record to its Markdown-on-disk form. Frontmatter
 * uses JSON-encoded scalars where quoting matters, so the parser round-trips
 * exotic characters in commands and summaries.
 */
export function renderAutoSkillMarkdown(record) {
  if (!record) throw new Error("renderAutoSkillMarkdown: record required");
  const cs = record.contextSignature || {};
  const domainKeywords = Array.isArray(cs.domainKeywords) ? cs.domainKeywords : [];
  const lines = [
    "---",
    `sha256Prefix: ${record.sha256Prefix}`,
    `summary: ${JSON.stringify(String(record.summary || ""))}`,
    `createdAt: ${record.createdAt}`,
    `reuseCount: ${Number(record.reuseCount || 0)}`,
    "contextSignature:",
    `  sliceType: ${cs.sliceType || "execute"}`,
    `  titleHash: ${cs.titleHash || ""}`,
    `  planBasename: ${cs.planBasename || ""}`,
    `  domainKeywords: [${domainKeywords.map((k) => JSON.stringify(k)).join(", ")}]`,
    "commands:",
    ...record.commands.map((c) => `  - ${JSON.stringify(String(c))}`),
    "---",
    "",
    `# Auto-skill: ${record.summary}`,
    "",
    "Captured by Plan-Forge Phase-25 auto-skill library (L2).",
    "Reuse this recipe when a future slice matches the domain keywords above.",
    "",
    "## Commands that worked",
    "",
    ...record.commands.flatMap((c) => ["```", c, "```", ""]),
  ];
  return lines.join("\n");
}

/**
 * Parse an auto-skill record from its Markdown-on-disk form. Tolerant of
 * hand-edits — returns `null` on clearly malformed files.
 */
function _parseAutoSkillContextSignature(fm) {
  const cs = {
    sliceType: (/^\s*sliceType:\s*(\S+)$/m.exec(fm) || [])[1] || "execute",
    titleHash: (/^\s*titleHash:\s*(\S+)$/m.exec(fm) || [])[1] || "",
    planBasename: (/^\s*planBasename:\s*(\S+)$/m.exec(fm) || [])[1] || "",
    domainKeywords: [],
  };
  const kwMatch = /^\s*domainKeywords:\s*\[([^\]]*)\]$/m.exec(fm);
  if (kwMatch) {
    try {
      const parsed = JSON.parse("[" + kwMatch[1] + "]");
      if (Array.isArray(parsed)) cs.domainKeywords = parsed.filter((s) => typeof s === "string");
    } catch { /* leave empty */ }
  }
  return cs;
}

function _parseAutoSkillCommands(fm) {
  const commands = [];
  const cmdSectionMatch = /\ncommands:\n([\s\S]*)$/.exec(fm);
  if (!cmdSectionMatch) return commands;
  for (const raw of cmdSectionMatch[1].split("\n")) {
    const m = /^\s*-\s*(.+)$/.exec(raw);
    if (!m) continue;
    let v = m[1].trim();
    try { v = JSON.parse(v); } catch { /* keep raw */ }
    if (typeof v === "string" && v.length > 0) commands.push(v);
  }
  return commands;
}

export function parseAutoSkillMarkdown(text) {
  if (typeof text !== "string") return null;
  const fmMatch = /^---\n([\s\S]*?)\n---/.exec(text);
  if (!fmMatch) return null;
  const fm = fmMatch[1];

  const sha256Prefix = (/^sha256Prefix:\s*(\S+)$/m.exec(fm) || [])[1];
  if (!sha256Prefix) return null;

  const summaryLine = (/^summary:\s*(.+)$/m.exec(fm) || [])[1] || "";
  let summary = summaryLine;
  try { summary = JSON.parse(summaryLine); } catch { /* keep raw */ }

  const createdAt = (/^createdAt:\s*(\S+)$/m.exec(fm) || [])[1] || "";
  const reuseCount = Number((/^reuseCount:\s*(\S+)$/m.exec(fm) || [])[1] || 0) || 0;

  const contextSignature = _parseAutoSkillContextSignature(fm);
  const commands = _parseAutoSkillCommands(fm);

  return { sha256Prefix, summary, commands, contextSignature, reuseCount, createdAt };
}

/**
 * Persist an auto-skill record to `.forge/skills-auto/<sha256Prefix>.md`.
 * Idempotent by prefix — overwrites an existing file to support reuseCount updates.
 *
 * @returns {string} Absolute path of the written file.
 */
export function writeAutoSkill({ cwd = process.cwd(), record }) {
  if (!record || !record.sha256Prefix) {
    throw new Error("writeAutoSkill: record.sha256Prefix required");
  }
  const dir = resolve(cwd, ".forge", AUTOSKILL_DIR);
  mkdirSync(dir, { recursive: true });
  const path = resolve(dir, `${record.sha256Prefix}.md`);
  writeFileSync(path, renderAutoSkillMarkdown(record), "utf-8");
  return path;
}

/** Read a single auto-skill by prefix. Returns `null` when missing or malformed. */
export function readAutoSkill({ cwd = process.cwd(), sha256Prefix }) {
  if (!sha256Prefix) return null;
  const path = resolve(cwd, ".forge", AUTOSKILL_DIR, `${sha256Prefix}.md`);
  if (!existsSync(path)) return null;
  try {
    return parseAutoSkillMarkdown(readFileSync(path, "utf-8"));
  } catch {
    return null;
  }
}

/** List every auto-skill candidate. Returns `[]` when the directory does not exist. */
export function listAutoSkills({ cwd = process.cwd() } = {}) {
  const dir = resolve(cwd, ".forge", AUTOSKILL_DIR);
  if (!existsSync(dir)) return [];
  let files;
  try { files = readdirSync(dir); } catch { return []; }
  const out = [];
  for (const f of files) {
    if (!f.endsWith(".md")) continue;
    const rec = readAutoSkill({ cwd, sha256Prefix: f.slice(0, -3) });
    if (rec) out.push(rec);
  }
  return out;
}

/**
 * Retrieve auto-skills whose `contextSignature.domainKeywords` overlap the
 * given slice's domain keywords. Ranked by `reuseCount` desc, then `createdAt`
 * desc. Returns up to `limit` records (default 3).
 */
export function retrieveAutoSkills({ cwd = process.cwd(), slice, limit = 3 } = {}) {
  if (!slice) return [];
  const keywords = extractDomainKeywords(slice, cwd);
  if (keywords.length === 0) return [];
  const all = listAutoSkills({ cwd });
  const matches = all.filter((s) => {
    const kw = s.contextSignature?.domainKeywords || [];
    return kw.some((k) => keywords.includes(k));
  });
  matches.sort((a, b) => {
    const dr = (b.reuseCount || 0) - (a.reuseCount || 0);
    if (dr !== 0) return dr;
    return String(b.createdAt || "").localeCompare(String(a.createdAt || ""));
  });
  const cap = Number.isFinite(limit) && limit > 0 ? limit : 3;
  return matches.slice(0, cap);
}

/**
 * Atomically bump `reuseCount` for a given skill. Returns the new count, or
 * `null` when the skill is missing.
 */
export function incrementAutoSkillReuse({ cwd = process.cwd(), sha256Prefix }) {
  const rec = readAutoSkill({ cwd, sha256Prefix });
  if (!rec) return null;
  rec.reuseCount = (Number(rec.reuseCount) || 0) + 1;
  writeAutoSkill({ cwd, record: rec });
  return rec.reuseCount;
}

/**
 * MUST #4 promotion gate. Returns `true` when a skill is eligible for
 * promotion to `.github/skills/auto-<name>/SKILL.md`. Default threshold = 3
 * (Phase-25 D3); callers override via `runtime.autoSkill.promoteThreshold`.
 */
export function shouldPromoteAutoSkill(skill, threshold = AUTOSKILL_DEFAULT_THRESHOLD) {
  if (!skill) return false;
  const n = Number(skill.reuseCount || 0);
  const t = Number.isFinite(threshold) && threshold > 0 ? threshold : AUTOSKILL_DEFAULT_THRESHOLD;
  return n >= t;
}

// ─── Phase-26 Slice 8: Auto-skill promotion — state machine ──────────────────

/**
 * Sidecar state file tracking per-skill lifecycle decisions:
 * `pending` (eligible but not yet actioned), `promoted`, `rejected`, `deferred`.
 * The markdown candidate files stay untouched; this file records the decision.
 *
 * Schema (inside .forge/skills-auto/state.json):
 *   { "<sha256Prefix>": { status, deferredUntil?: ISO, actionedAt: ISO } }
 */
const AUTOSKILL_STATE_FILE = "state.json";

/** Defer window for `deferAutoSkill` — Phase-26 MUST (Defer 7d). */
export const AUTOSKILL_DEFER_MS = 7 * 24 * 60 * 60 * 1000;

function autoSkillStatePath(cwd) {
  return resolve(cwd, ".forge", AUTOSKILL_DIR, AUTOSKILL_STATE_FILE);
}

function readAutoSkillState(cwd) {
  const path = autoSkillStatePath(cwd);
  if (!existsSync(path)) return {};
  try {
    const data = JSON.parse(readFileSync(path, "utf-8"));
    return data && typeof data === "object" && !Array.isArray(data) ? data : {};
  } catch {
    return {};
  }
}

function writeAutoSkillState(cwd, state) {
  const path = autoSkillStatePath(cwd);
  mkdirSync(resolve(cwd, ".forge", AUTOSKILL_DIR), { recursive: true });
  writeFileSync(path, JSON.stringify(state, null, 2), "utf-8");
}

/**
 * Derive the on-disk status of an auto-skill candidate.
 *   - "promoted"  when `.github/skills/auto-<prefix>/SKILL.md` exists
 *   - "rejected"  when state.json says so (file may also be under rejected/)
 *   - "deferred"  when state.json says so AND `deferredUntil > now`
 *   - "pending"   otherwise (default)
 *
 * Pure w.r.t. its arguments; reads only.
 */
export function getAutoSkillStatus({ cwd = process.cwd(), sha256Prefix, now = Date.now() } = {}) {
  if (!sha256Prefix) return "pending";
  const promotedPath = resolve(cwd, ".github", "skills", `auto-${sha256Prefix}`, "SKILL.md");
  if (existsSync(promotedPath)) return "promoted";
  const state = readAutoSkillState(cwd);
  const entry = state[sha256Prefix];
  if (!entry) return "pending";
  if (entry.status === "rejected") return "rejected";
  if (entry.status === "deferred") {
    const until = entry.deferredUntil ? Date.parse(entry.deferredUntil) : 0;
    if (Number.isFinite(until) && until > now) return "deferred";
    // expired defer → back to pending
    return "pending";
  }
  if (entry.status === "promoted") return "promoted";
  return "pending";
}

/**
 * List auto-skill candidates eligible for promotion.
 * A candidate is "pending" when:
 *   - `reuseCount >= threshold` (Phase-25 D3 default 3; override via
 *     `runtime.autoSkill.promoteThreshold`)
 *   - NOT already promoted (`.github/skills/auto-<prefix>/SKILL.md` absent)
 *   - NOT rejected (state.json)
 *   - NOT currently deferred (state.json `deferredUntil` in the future)
 *
 * @returns {Array<object>} pending skill records, ordered by reuseCount desc.
 */
export function listPendingAutoSkills({ cwd = process.cwd(), threshold, now = Date.now() } = {}) {
  const t = Number.isFinite(threshold) && threshold > 0
    ? Math.floor(threshold)
    : AUTOSKILL_DEFAULT_THRESHOLD;
  const all = listAutoSkills({ cwd });
  const out = [];
  for (const skill of all) {
    if (!shouldPromoteAutoSkill(skill, t)) continue;
    const status = getAutoSkillStatus({ cwd, sha256Prefix: skill.sha256Prefix, now });
    if (status !== "pending") continue;
    out.push(skill);
  }
  out.sort((a, b) => (b.reuseCount || 0) - (a.reuseCount || 0));
  return out;
}

/**
 * Promote an auto-skill to `.github/skills/auto-<sha256Prefix>/SKILL.md`.
 * Copies the current rendered markdown; records `promoted` in state.json so
 * the candidate no longer appears in `listPendingAutoSkills`.
 *
 * @returns {{ ok: boolean, promotedPath?: string, error?: string }}
 */
export function acceptAutoSkill({ cwd = process.cwd(), sha256Prefix, now = new Date() } = {}) {
  if (!sha256Prefix) return { ok: false, error: "sha256Prefix required" };
  const record = readAutoSkill({ cwd, sha256Prefix });
  if (!record) return { ok: false, error: `auto-skill ${sha256Prefix} not found` };
  const skillDir = resolve(cwd, ".github", "skills", `auto-${sha256Prefix}`);
  mkdirSync(skillDir, { recursive: true });
  const promotedPath = resolve(skillDir, "SKILL.md");
  writeFileSync(promotedPath, renderAutoSkillMarkdown(record), "utf-8");
  const state = readAutoSkillState(cwd);
  state[sha256Prefix] = {
    status: "promoted",
    actionedAt: (now instanceof Date ? now : new Date(now)).toISOString(),
  };
  writeAutoSkillState(cwd, state);
  return { ok: true, promotedPath };
}

/**
 * Reject an auto-skill candidate. Moves the candidate file to
 * `.forge/skills-auto/rejected/<sha256Prefix>.md` and records the decision.
 *
 * @returns {{ ok: boolean, rejectedPath?: string, error?: string }}
 */
export function rejectAutoSkill({ cwd = process.cwd(), sha256Prefix, reason = "", now = new Date() } = {}) {
  if (!sha256Prefix) return { ok: false, error: "sha256Prefix required" };
  const srcPath = resolve(cwd, ".forge", AUTOSKILL_DIR, `${sha256Prefix}.md`);
  if (!existsSync(srcPath)) return { ok: false, error: `auto-skill ${sha256Prefix} not found` };
  const rejectedDir = resolve(cwd, ".forge", AUTOSKILL_DIR, "rejected");
  mkdirSync(rejectedDir, { recursive: true });
  const rejectedPath = resolve(rejectedDir, `${sha256Prefix}.md`);
  writeFileSync(rejectedPath, readFileSync(srcPath, "utf-8"), "utf-8");
  try {
    unlinkSync(srcPath);
  } catch { /* best effort — state record is authoritative */ }
  const state = readAutoSkillState(cwd);
  state[sha256Prefix] = {
    status: "rejected",
    reason: String(reason || ""),
    actionedAt: (now instanceof Date ? now : new Date(now)).toISOString(),
  };
  writeAutoSkillState(cwd, state);
  return { ok: true, rejectedPath };
}

/**
 * Defer an auto-skill candidate for `AUTOSKILL_DEFER_MS` (7 days). The
 * candidate returns to `pending` automatically once the defer window expires.
 *
 * @returns {{ ok: boolean, deferredUntil?: string, error?: string }}
 */
export function deferAutoSkill({ cwd = process.cwd(), sha256Prefix, now = Date.now() } = {}) {
  if (!sha256Prefix) return { ok: false, error: "sha256Prefix required" };
  const nowMs = typeof now === "number" ? now : Date.parse(String(now));
  if (!Number.isFinite(nowMs)) return { ok: false, error: "invalid now" };
  const record = readAutoSkill({ cwd, sha256Prefix });
  if (!record) return { ok: false, error: `auto-skill ${sha256Prefix} not found` };
  const deferredUntil = new Date(nowMs + AUTOSKILL_DEFER_MS).toISOString();
  const state = readAutoSkillState(cwd);
  state[sha256Prefix] = {
    status: "deferred",
    deferredUntil,
    actionedAt: new Date(nowMs).toISOString(),
  };
  writeAutoSkillState(cwd, state);
  return { ok: true, deferredUntil };
}


/**
 * Build a prompt block listing retrieved auto-skills for worker injection.
 * Returns `""` when no skills are provided.
 */
export function buildAutoSkillContext(skills) {
  if (!Array.isArray(skills) || skills.length === 0) return "";
  const lines = [
    "",
    "--- AUTO-SKILL CONTEXT (Phase-25 L2) ---",
    "These recipes worked on past slices matching your domain keywords.",
    "Consider their commands when deciding your approach — but you remain",
    "responsible for the current slice's validation gate.",
    "",
  ];
  for (const s of skills) {
    lines.push(`### ${s.summary} (reused ${s.reuseCount}×)`);
    lines.push("");
    for (const c of s.commands) lines.push("- `" + c + "`");
    lines.push("");
  }
  lines.push("--- END AUTO-SKILL CONTEXT ---");
  lines.push("");
  return lines.join("\n");
}

/**
 * Build a run summary thought for capture after completion.
 *
 * @param {object} summary - Run summary object
 * @param {string} projectName - Project name
 * @returns {{ content: string, project: string, source: string, created_by: string }}
 */
export function buildRunSummaryThought(summary, projectName) {
  const parts = [
    `Plan execution completed: ${summary.plan}`,
    `Status: ${summary.status}`,
    `Slices: ${summary.results?.passed || 0} passed, ${summary.results?.failed || 0} failed`,
    `Duration: ${Math.round((summary.totalDuration || 0) / 1000)}s`,
  ];

  if (summary.cost?.total_cost_usd > 0) {
    parts.push(`Cost: $${summary.cost.total_cost_usd}`);
  }

  if (summary.sweep?.ran) {
    parts.push(`Sweep: ${summary.sweep.clean ? "clean" : `${summary.sweep.markerCount || "?"} markers`}`);
  }

  if (summary.analyze?.score != null) {
    parts.push(`Consistency score: ${summary.analyze.score}/100`);
  }

  // Include per-slice outcomes for learning
  if (summary.sliceResults) {
    for (const sr of summary.sliceResults) {
      if (sr.status === "failed") {
        parts.push(`Slice ${sr.number || sr.sliceId} FAILED: ${sr.gateError || sr.error || "unknown"}`);
      }
    }
  }

  return {
    content: parts.join(". "),
    project: projectName,
    source: `plan-forge-orchestrator/${summary.plan}`,
    created_by: "plan-forge-orchestrator",
  };
}

/**
 * Build a cost anomaly thought if current run cost differs significantly.
 *
 * @param {object} summary - Current run summary
 * @param {object} costReport - Historical cost report
 * @param {string} projectName - Project name
 * @returns {object|null} Thought to capture, or null if no anomaly
 */
export function buildCostAnomalyThought(summary, costReport, projectName) {
  if (!summary.cost?.total_cost_usd || !costReport?.total_cost_usd || costReport.runs < 2) {
    return null;
  }

  const avgCostPerRun = costReport.total_cost_usd / costReport.runs;
  const currentCost = summary.cost.total_cost_usd;
  const ratio = currentCost / avgCostPerRun;

  if (ratio > 2.0) {
    return {
      content: `Cost anomaly: ${summary.plan} cost $${currentCost} (${ratio.toFixed(1)}x the average of $${avgCostPerRun.toFixed(2)}). Review slice complexity or model selection.`,
      project: projectName,
      source: `plan-forge-orchestrator/${summary.plan}`,
      created_by: "plan-forge-orchestrator",
      type: "insight",
    };
  }

  return null;
}

// ─── Watcher anomaly → thought shaping (v2.35.1 / G3.1) ─────────────────

/**
 * Shape a watcher anomaly into a capturable thought.
 *
 * Pure function: given an anomaly object + run metadata, returns the
 * `{ content, type, source }` triple that callers pass to `captureMemory()`.
 * Keeps the source attribution format consistent with GX.4: `<tool>/<code>`.
 *
 * Severity → type mapping:
 *   - "info"        → "lesson" (e.g. all-skipped is a learning, not a gotcha)
 *   - "warn"/"error"→ "gotcha" (recurring patterns worth remembering)
 *
 * @param {{ severity: string, code: string, message: string }} anomaly
 * @param {{ targetPath?: string, runId?: string|null, runState?: string }} meta
 * @param {"forge_watch"|"forge_watch_live"} [tool="forge_watch"]
 * @returns {{ content: string, type: string, source: string }}
 */
export function shapeWatcherAnomalyThought(anomaly, meta = {}, tool = "forge_watch") {
  const type = anomaly.severity === "info" ? "lesson" : "gotcha";
  const prefix = tool === "forge_watch_live" ? "Live watcher anomaly" : "Watcher anomaly";
  const parts = [`${prefix} [${anomaly.code}]: ${anomaly.message}`];
  if (meta.targetPath) parts.push(`targetPath=${meta.targetPath}`);
  parts.push(`runId=${meta.runId || "n/a"}`);
  if (meta.runState) parts.push(`state=${meta.runState}`);
  return {
    content: parts.join(". "),
    type,
    source: `${tool}/${anomaly.code}`,
  };
}

/**
 * Deduplicate watcher anomalies within a single session by `code|message`.
 * Pure function — the caller decides what to do with the result.
 *
 * @param {Array<{ code: string, message: string }>} anomalies
 * @returns {Array} unique anomalies preserving first-seen order
 */
export function dedupeWatcherAnomalies(anomalies) {
  if (!Array.isArray(anomalies)) return [];
  const seen = new Set();
  const out = [];
  for (const a of anomalies) {
    if (!a || !a.code) continue;
    const key = `${a.code}|${a.message || ""}`;
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(a);
  }
  return out;
}

// ─── G2.6 — OpenBrain queue state + DLQ ────────────────────────────────

/**
 * G2.6 (v2.36): wrap an enqueued thought with bookkeeping fields so a worker
 * (or the SessionStart drain hook) can track delivery state across attempts.
 *
 * Pure function — caller appends the result to `.forge/openbrain-queue.jsonl`.
 *
 *  _v             — schema version (G2.2)
 *  _status        — "pending" | "processing" | "failed" | "delivered"
 *  _attempts      — number of delivery attempts so far
 *  _enqueuedAt    — ISO timestamp the thought was first queued
 *  _nextAttemptAt — ISO timestamp the next delivery attempt is allowed
 *
 * @param {object} thought - The captured thought (content/type/source/etc.)
 * @returns {object} enriched queue record
 */
export function shapeQueueRecord(thought) {
  const now = new Date().toISOString();
  return {
    _v: 1,
    _status: "pending",
    _attempts: 0,
    _enqueuedAt: now,
    _nextAttemptAt: now,
    ...thought,
  };
}

/**
 * G2.6 (v2.36): given a current attempt count, return the next-attempt
 * timestamp using exponential backoff with jitter.
 *
 *   attempt 1 → 30s, 2 → 60s, 3 → 120s, 4 → 240s, 5 → 480s
 *   jitter ±20% to avoid thundering herd
 *
 * @param {number} attempts - Current attempt count (after increment)
 * @param {number} [now=Date.now()]
 * @returns {string} ISO timestamp
 */
export function nextBackoffTimestamp(attempts, now = Date.now()) {
  const base = 30_000 * Math.pow(2, Math.max(0, attempts - 1)); // ms
  const jitter = base * (Math.random() * 0.4 - 0.2); // ±20%
  return new Date(now + base + jitter).toISOString();
}

/**
 * G2.6 (v2.36): decide what to do with a queue record after a failed
 * delivery attempt. Pure function — returns either the updated record
 * (still in queue) or a DLQ marker (move to .forge/openbrain-dlq.jsonl).
 *
 *   maxAttempts (default 5) — after this many failures, move to DLQ.
 *
 * @param {object} record - Queue record from shapeQueueRecord
 * @param {{maxAttempts?: number, error?: string, now?: number}} [opts]
 * @returns {{action: "retry"|"dlq", record: object}}
 */
export function applyDeliveryFailure(record, opts = {}) {
  const { maxAttempts = 5, error = "unknown", now = Date.now() } = opts;
  const attempts = (record._attempts || 0) + 1;
  if (attempts >= maxAttempts) {
    return {
      action: "dlq",
      record: {
        ...record,
        _status: "failed",
        _attempts: attempts,
        _failedAt: new Date(now).toISOString(),
        _lastError: String(error).slice(0, 500),
      },
    };
  }
  return {
    action: "retry",
    record: {
      ...record,
      _status: "pending",
      _attempts: attempts,
      _lastError: String(error).slice(0, 500),
      _nextAttemptAt: nextBackoffTimestamp(attempts, now),
    },
  };
}

/**
 * G2.6 (v2.36): partition queue records into those eligible for delivery
 * right now vs those still in backoff. Pure function — caller dispatches
 * the eligible records to the actual ingestor.
 *
 * @param {Array<object>} records
 * @param {number} [now=Date.now()]
 * @returns {{ready: Array, deferred: Array}}
 */
export function partitionByBackoff(records, now = Date.now()) {
  const ready = [];
  const deferred = [];
  if (!Array.isArray(records)) return { ready, deferred };
  const cutoff = now;
  for (const r of records) {
    if (!r || r._status === "delivered" || r._status === "failed") continue;
    const next = r._nextAttemptAt ? Date.parse(r._nextAttemptAt) : 0;
    if (Number.isFinite(next) && next <= cutoff) ready.push(r);
    else deferred.push(r);
  }
  return { ready, deferred };
}

// ─── G2.8 — Capture observability ──────────────────────────────────────

/**
 * G2.8 (v2.36): build a stats record summarising a drain pass for the
 * `.forge/openbrain-stats.jsonl` ledger. Lets the dashboard show queue
 * health (delivered vs deferred vs DLQ over time) without re-reading
 * the queue file every render.
 *
 * Pure function — caller writes the result.
 *
 * @param {{attempted: number, delivered: number, deferred: number, dlq: number, durationMs: number, source?: string}} pass
 * @returns {object}
 */
export function buildDrainStatsRecord(pass) {
  return {
    _v: 1,
    timestamp: new Date().toISOString(),
    source: pass.source || "drain",
    attempted: pass.attempted | 0,
    delivered: pass.delivered | 0,
    deferred: pass.deferred | 0,
    dlq: pass.dlq | 0,
    durationMs: pass.durationMs | 0,
  };
}

// ─── Phase-28.4 — OpenBrain queue drain orchestrator ────────────────────

/**
 * Phase-28.4 (v2.62.3): drain eligible records from the OpenBrain queue.
 * Pure function — composes partitionByBackoff, calls injected dispatcher,
 * calls applyDeliveryFailure on failures, returns structured result.
 * Zero filesystem I/O — caller handles persistence.
 *
 * @param {Array<object>} records - Queue records from openbrain-queue.jsonl
 * @param {(record: object) => Promise<{ok: boolean, error?: string}>} dispatcher - Injected delivery function
 * @param {{maxBatch?: number, maxAttempts?: number, now?: number, source?: string}} [opts]
 * @returns {Promise<{delivered: Array, deferred: Array, dlq: Array, archive: Array, stats: object}>}
 */
export async function drainOpenBrainQueue(records, dispatcher, opts = {}) {
  const { maxBatch = 50, maxAttempts = 5, now = Date.now(), source = "drain" } = opts;
  const t0 = now;

  const { ready, deferred } = partitionByBackoff(records, now);

  // Slice to batch ceiling; surplus records go back to deferred untouched
  const batch = ready.slice(0, maxBatch);
  const surplus = ready.slice(maxBatch);
  const allDeferred = [...deferred, ...surplus];

  const delivered = [];
  const archive = [];
  const dlq = [];
  const retrying = [];

  for (const record of batch) {
    let result;
    try {
      result = await dispatcher(record);
    } catch (err) {
      result = { ok: false, error: String(err?.message || err || "unknown") };
    }

    if (result && result.ok) {
      const done = {
        ...record,
        _status: "delivered",
        _deliveredAt: new Date(now).toISOString(),
      };
      delivered.push(done);
      archive.push(done);
    } else {
      const error = result?.error || "unknown";
      const outcome = applyDeliveryFailure(record, { maxAttempts, error, now });
      if (outcome.action === "dlq") {
        dlq.push(outcome.record);
      } else {
        retrying.push(outcome.record);
      }
    }
  }

  const stats = buildDrainStatsRecord({
    attempted: batch.length,
    delivered: delivered.length,
    deferred: allDeferred.length + retrying.length,
    dlq: dlq.length,
    durationMs: Date.now() - t0,
    source,
  });

  return {
    delivered,
    deferred: [...allDeferred, ...retrying],
    dlq,
    archive,
    stats,
  };
}

// ─── G3.2 — Similarity-based dedupe ────────────────────────────────────

/**
 * G3.2 (v2.36): tokenise a string into a bag of lowercase word tokens.
 * Pure helper used by `cosineSimilarity` and `dedupeThoughtsBySimilarity`.
 *
 * @param {string} text
 * @returns {Map<string, number>} token → count
 */
export function tokenize(text) {
  const out = new Map();
  if (!text || typeof text !== "string") return out;
  const tokens = text.toLowerCase().match(/[a-z0-9_]+/g) || [];
  for (const t of tokens) out.set(t, (out.get(t) || 0) + 1);
  return out;
}

/**
 * G3.2 (v2.36): cosine similarity between two token bags (0..1).
 * Pure — used to suppress near-duplicate thoughts before they land in L2/L3.
 * Uses term-frequency vectors; intentionally simple, no IDF.
 *
 * @param {string|Map<string,number>} a
 * @param {string|Map<string,number>} b
 * @returns {number} in [0, 1]
 */
export function cosineSimilarity(a, b) {
  const va = a instanceof Map ? a : tokenize(a);
  const vb = b instanceof Map ? b : tokenize(b);
  if (va.size === 0 || vb.size === 0) return 0;
  let dot = 0, magA = 0, magB = 0;
  for (const [, v] of va) magA += v * v;
  for (const [, v] of vb) magB += v * v;
  const smaller = va.size < vb.size ? va : vb;
  const larger = smaller === va ? vb : va;
  for (const [t, v] of smaller) {
    const w = larger.get(t);
    if (w) dot += v * w;
  }
  const denom = Math.sqrt(magA) * Math.sqrt(magB);
  return denom === 0 ? 0 : dot / denom;
}

/**
 * G3.2 (v2.36): dedupe a batch of thoughts by cosine similarity on their
 * `content` field. Keeps the first occurrence; drops later ones whose
 * similarity to any kept thought exceeds `threshold` (default 0.9).
 *
 * Pure function — caller decides which survivors to persist.
 *
 * @param {Array<{content?: string}>} thoughts
 * @param {{threshold?: number}} [opts]
 * @returns {{kept: Array, dropped: Array<{thought: object, similarTo: object, similarity: number}>}}
 */
export function dedupeThoughtsBySimilarity(thoughts, opts = {}) {
  const threshold = typeof opts.threshold === "number" ? opts.threshold : 0.9;
  const kept = [];
  const dropped = [];
  const vectors = [];
  if (!Array.isArray(thoughts)) return { kept, dropped };
  for (const t of thoughts) {
    if (!t || typeof t.content !== "string" || t.content.length === 0) {
      kept.push(t); // nothing to compare — pass through untouched
      vectors.push(null);
      continue;
    }
    const vec = tokenize(t.content);
    let match = null;
    let bestScore = 0;
    for (let i = 0; i < vectors.length; i++) {
      if (!vectors[i]) continue;
      const score = cosineSimilarity(vec, vectors[i]);
      if (score >= threshold && score > bestScore) {
        match = kept[i];
        bestScore = score;
      }
    }
    if (match) {
      dropped.push({ thought: t, similarTo: match, similarity: Math.round(bestScore * 1000) / 1000 });
    } else {
      kept.push(t);
      vectors.push(vec);
    }
  }
  return { kept, dropped };
}

// ─── G3.3 — Proactive search prompt for watcher anomalies ─────────────

/**
 * G3.3 (v2.36): build an OpenBrain search-instruction block tailored to a
 * watcher anomaly. The MCP tool embeds this block in its response so the
 * caller (agent) proactively asks OpenBrain for prior findings on the same
 * anomaly code before reacting — closing the "observer is amnesic" loop.
 *
 * Returns "" when projectName is falsy or the anomaly is shapeless.
 *
 * @param {{code?: string, message?: string}} anomaly
 * @param {string} projectName
 * @returns {string}
 */
export function buildWatcherSearchPrompt(anomaly, projectName) {
  if (!anomaly || !anomaly.code || !projectName) return "";
  const query = `watcher anomaly ${anomaly.code}`;
  const lines = [
    "--- PRIOR FINDINGS (OpenBrain) ---",
    `Before reacting to anomaly '${anomaly.code}', check prior occurrences:`,
    `  Use search_thoughts tool with query: "${query}", project: "${projectName}", limit: 5`,
    "If matches exist, apply their documented mitigations. If not, record this occurrence via capture_thought after investigation.",
    "--- END PRIOR FINDINGS ---",
  ];
  return lines.join("\n") + "\n";
}

// ─── G3.5 — Thought TTL / expiresAt ────────────────────────────────────

/**
 * G3.5 (v2.36): stamp an `expiresAt` field on a thought based on type.
 * Mutates-free: returns a shallow clone. Used by `captureMemory()` so
 * short-lived observations don't haunt searches forever.
 *
 *   lesson   → 365d
 *   decision → 180d
 *   gotcha   → 90d
 *   pattern  → no expiry
 *   convention → no expiry
 *   (default) 90d
 *
 * Caller-supplied `expiresAt` wins.
 *
 * @param {object} thought
 * @param {{now?: number, overrides?: Record<string, number>}} [opts]
 * @returns {object}
 */
export function stampThoughtExpiry(thought, opts = {}) {
  if (!thought || typeof thought !== "object") return thought;
  if (thought.expiresAt) return thought;
  const DAY = 24 * 60 * 60 * 1000;
  const defaults = { lesson: 365, decision: 180, gotcha: 90, pattern: null, convention: null };
  const byType = { ...defaults, ...(opts.overrides || {}) };
  const days = byType[thought.type];
  if (days == null) return thought; // no expiry
  const now = opts.now ?? Date.now();
  return { ...thought, expiresAt: new Date(now + days * DAY).toISOString() };
}

/**
 * G3.5 (v2.36): filter out thoughts whose `expiresAt` is in the past.
 * Missing/invalid `expiresAt` means never-expires.
 *
 * @param {Array<object>} thoughts
 * @param {number} [now=Date.now()]
 * @returns {Array<object>}
 */
export function filterUnexpiredThoughts(thoughts, now = Date.now()) {
  if (!Array.isArray(thoughts)) return [];
  return thoughts.filter((t) => {
    if (!t || !t.expiresAt) return true;
    const ts = Date.parse(t.expiresAt);
    return !Number.isFinite(ts) || ts > now;
  });
}

// ─── G3.6 — Capture telemetry ──────────────────────────────────────────

/**
 * G3.6 (v2.36): shape a capture-telemetry record. Every `captureMemory()`
 * call emits one of these to `.forge/telemetry/memory-captures.jsonl` so
 * we can answer "who's capturing what, and how often" without scraping
 * the memory files themselves.
 *
 * @param {{tool: string, type: string, source: string, content?: string, project?: string, deduped?: boolean}} ctx
 * @returns {object}
 */
export function buildCaptureTelemetry(ctx) {
  const contentLen = typeof ctx.content === "string" ? ctx.content.length : 0;
  return {
    _v: 1,
    timestamp: new Date().toISOString(),
    tool: ctx.tool || "unknown",
    type: ctx.type || "unknown",
    source: ctx.source || "unknown",
    project: ctx.project || null,
    contentLen,
    deduped: !!ctx.deduped,
  };
}

// ─── Issue #205 — Single capture pipeline shared by CLI + MCP paths ────

/**
 * Append a record as a `_v: 1`-stamped JSON line under `.forge/<relPath>`.
 * Mirrors `orchestrator.appendForgeJsonl` but lives in memory.mjs so the
 * capture pipeline doesn't pull orchestrator.mjs into a circular import.
 *
 * @param {string} cwd
 * @param {string} relPath  — path relative to `.forge/` (e.g. "openbrain-queue.jsonl")
 * @param {object} record
 */
function _appendForgeJsonl(cwd, relPath, record) {
  const full = resolve(cwd, ".forge", relPath);
  mkdirSync(resolve(full, ".."), { recursive: true });
  const stamped = { _v: 1, ...record };
  appendFileSync(full, JSON.stringify(stamped) + "\n");
}

/**
 * Read up to the last `tail` records from a `.forge/<relPath>` JSONL.
 * Returns [] on any error (missing file, parse failure).
 *
 * @param {string} cwd
 * @param {string} relPath
 * @param {number} [tail=50]
 * @returns {object[]}
 */
function _readForgeJsonlTail(cwd, relPath, tail = 50) {
  try {
    const full = resolve(cwd, ".forge", relPath);
    if (!existsSync(full)) return [];
    const lines = readFileSync(full, "utf-8").split("\n").filter((l) => l.trim());
    const slice = lines.length > tail ? lines.slice(-tail) : lines;
    const out = [];
    for (const line of slice) {
      try { out.push(JSON.parse(line)); } catch { /* skip malformed */ }
    }
    return out;
  } catch {
    return [];
  }
}

/**
 * Issue #205 (May 2026): unified L2/L3 capture pipeline.
 *
 * Previously this function lived only in `server.mjs` and was wired only
 * into the MCP `forge_run_plan` handler. CLI runs (`pforge run-plan`)
 * spawn the orchestrator directly and bypassed it entirely — so every
 * CLI-driven run silently dropped its memory capture. This is now the
 * single source of truth, called from both surfaces.
 *
 * Effects:
 *   1. Always appends to `.forge/liveguard-memories.jsonl` (L2)
 *   2. Queues to `.forge/openbrain-queue.jsonl` (L3) if OpenBrain configured
 *   3. Emits a `.forge/telemetry/memory-captures.jsonl` row
 *   4. Calls `opts.onCapture(thought, deduped)` if provided (e.g., for hub broadcast)
 *
 * Best-effort: any internal error is swallowed — callers should never
 * see capture failures break tool/orchestrator execution.
 *
 * @param {string} content - Human-readable description of the finding
 * @param {string} type - Thought type ('decision'|'gotcha'|'lesson'|'pattern'|'convention')
 * @param {string} source - Originating tool/subsystem (e.g. 'forge_run_plan')
 * @param {string} cwd - Project root
 * @param {{onCapture?: (thought: object, deduped: boolean) => void}} [opts]
 * @returns {{captured: boolean, deduped: boolean, openBrainQueued: boolean, thought: object|null}}
 */
export function captureMemory({ content, type, source, cwd, opts = {} }) {
  try {
    // ── 1. Project name (from .forge.json) ───────────────────────────
    let project = "plan-forge";
    try {
      const forgeConfig = JSON.parse(readFileSync(resolve(cwd, ".forge.json"), "utf-8"));
      project = forgeConfig.projectName || "plan-forge";
    } catch { /* use default */ }

    // ── 2. Validate source format (warn but persist) ─────────────────
    const sourceCheck = validateSourceFormat(source);
    if (!sourceCheck.valid) {
      console.error(`[memory] non-standard source '${source}': ${sourceCheck.reason}`);
    }

    // ── 3. Build + stamp the thought ─────────────────────────────────
    let thought = {
      content,
      project,
      type,
      source,
      created_by: "liveguard-auto",
      captured_at: new Date().toISOString(),
    };
    thought = stampThoughtExpiry(thought);

    // ── 4. Near-duplicate suppression (cosine similarity vs last 50) ─
    let threshold = 0.9;
    try {
      const cfg = JSON.parse(readFileSync(resolve(cwd, ".forge.json"), "utf-8"));
      if (typeof cfg?.openbrain?.dedupThreshold === "number") {
        threshold = cfg.openbrain.dedupThreshold;
      }
    } catch { /* use default */ }

    let deduped = false;
    try {
      const recent = _readForgeJsonlTail(cwd, "liveguard-memories.jsonl", 50);
      const { dropped } = dedupeThoughtsBySimilarity([...recent, thought], { threshold });
      deduped = dropped.some((d) => d.thought === thought);
    } catch { /* best-effort */ }

    let openBrainQueued = false;
    if (!deduped) {
      // ── 5. Always persist to L2 ─────────────────────────────────────
      try {
        _appendForgeJsonl(cwd, "liveguard-memories.jsonl", thought);
      } catch { /* swallow */ }

      // ── 6. Queue to L3 (OpenBrain) when configured ──────────────────
      if (isOpenBrainConfigured(cwd)) {
        try {
          _appendForgeJsonl(cwd, "openbrain-queue.jsonl", shapeQueueRecord(thought));
          openBrainQueued = true;
        } catch { /* swallow */ }
      }
    }

    // ── 7. Telemetry (always — even dedupes count) ───────────────────
    try {
      _appendForgeJsonl(
        cwd,
        "telemetry/memory-captures.jsonl",
        buildCaptureTelemetry({ tool: source, type, source, content, project, deduped }),
      );
    } catch { /* swallow */ }

    // ── 8. Optional broadcast hook (e.g., hub) ───────────────────────
    if (typeof opts.onCapture === "function") {
      try { opts.onCapture(thought, deduped); } catch { /* swallow */ }
    }

    return { captured: !deduped, deduped, openBrainQueued, thought };
  } catch {
    return { captured: false, deduped: false, openBrainQueued: false, thought: null };
  }
}

// ─── Issue #205 fix #3 — Auto-drain OpenBrain queue ───────────────────

/**
 * Drain the OpenBrain queue via a direct SSE dispatcher. Designed for
 * CLI/orchestrator use where the MCP server (and its dashboard HTTP
 * dispatcher) may not be running. Best-effort: any failure is contained
 * and returned in the result; the caller never sees a throw.
 *
 * Pipeline:
 *   1. If OpenBrain not configured → `{ skipped: "not-configured" }`
 *   2. Read `.forge/openbrain-queue.jsonl`; empty → `{ skipped: "empty" }`
 *   3. Build SSE client via `createSseClient` (dynamic import from
 *      `openbrain-replay.mjs` to avoid eager SDK load)
 *   4. Call `drainOpenBrainQueue` with a dispatcher wrapping
 *      `client.capture(normalizeQueueRecord(record))`
 *   5. Atomically rewrite queue with `deferred` survivors
 *   6. Append delivered → `openbrain-queue.archive.jsonl`
 *   7. Append DLQ rows  → `openbrain-dlq.jsonl`
 *   8. Append stats row → `openbrain-stats.jsonl`
 *   9. Close client
 *
 * @param {string} cwd  — project root
 * @param {{source?: string, maxBatch?: number, maxAttempts?: number, timeoutMs?: number, dispatcher?: Function}} [opts]
 *   `dispatcher` — DI override for testing: `(record) => Promise<{ok, error?}>`.
 *   When provided, skips SSE client creation entirely. Production callers
 *   should omit it so the live SSE dispatcher is used.
 * @returns {Promise<{
 *   ok?: boolean, skipped?: string, error?: string,
 *   attempted?: number, delivered?: number, deferred?: number, dlq?: number, durationMs?: number
 * }>}
 */
async function _buildOpenBrainDispatcher(cwd, opts, t0, timeoutMs) {
  if (opts.dispatcher) {
    return { dispatcher: opts.dispatcher, closeClient: async () => {} };
  }
  const { createSseClient, readOpenBrainConfig, normalizeQueueRecord } =
    await import("./openbrain-replay.mjs");

  const cfg = readOpenBrainConfig(cwd);
  if (!cfg || !cfg.url || !cfg.key) {
    return { skipped: "no-config", durationMs: Date.now() - t0 };
  }

  const timeoutErr = new Error("autoDrainOpenBrainQueue: SSE timeout");
  const withTimeout = (p) => Promise.race([
    p,
    new Promise((_, reject) => setTimeout(() => reject(timeoutErr), timeoutMs)),
  ]);

  let client;
  try {
    client = await withTimeout(createSseClient(cfg));
  } catch (err) {
    return { error: `connect: ${err.message}`, durationMs: Date.now() - t0 };
  }
  const closeClient = async () => { try { await client.close(); } catch { /* best-effort */ } };

  const dispatcher = async (record) => {
    const payload = normalizeQueueRecord(record);
    if (!payload) return { ok: true };
    try {
      await withTimeout(client.capture(payload));
      return { ok: true };
    } catch (err) {
      return { ok: false, error: String(err?.message || err) };
    }
  };
  return { dispatcher, closeClient };
}

function _writeOpenBrainSurvivors(forgeDir, queuePath, survivors, t0) {
  const tmpPath = queuePath + ".tmp";
  try {
    mkdirSync(forgeDir, { recursive: true });
    const survivorLines = survivors.map((r) => JSON.stringify(r)).join("\n");
    writeFileSync(tmpPath, survivorLines ? survivorLines + "\n" : "", "utf-8");
    renameSync(tmpPath, queuePath);
    return null;
  } catch (err) {
    try { if (existsSync(tmpPath)) unlinkSync(tmpPath); } catch { /* cleanup */ }
    return { error: `atomic-write: ${err.message}`, durationMs: Date.now() - t0 };
  }
}

function _appendOpenBrainSideEffects(cwd, result) {
  for (const rec of result.archive) {
    try { _appendForgeJsonl(cwd, "openbrain-queue.archive.jsonl", rec); } catch { /* swallow */ }
  }
  for (const rec of result.dlq) {
    try { _appendForgeJsonl(cwd, "openbrain-dlq.jsonl", rec); } catch { /* swallow */ }
  }
  try { _appendForgeJsonl(cwd, "openbrain-stats.jsonl", result.stats); } catch { /* swallow */ }
}

export async function autoDrainOpenBrainQueue(cwd, opts = {}) {
  const { source = "cli-drain", maxBatch = 50, maxAttempts = 5, timeoutMs = 10_000 } = opts;
  const t0 = Date.now();

  try {
    if (!isOpenBrainConfigured(cwd) && !opts.dispatcher) {
      return { skipped: "not-configured" };
    }

    const forgeDir = resolve(cwd, ".forge");
    const queuePath = join(forgeDir, "openbrain-queue.jsonl");
    if (!existsSync(queuePath)) {
      return { skipped: "empty" };
    }
    const records = _readJsonl(queuePath);
    if (records.length === 0) {
      return { skipped: "empty" };
    }

    const built = await _buildOpenBrainDispatcher(cwd, opts, t0, timeoutMs);
    if (built.skipped || built.error) return built;
    const { dispatcher, closeClient } = built;

    let result;
    try {
      result = await drainOpenBrainQueue(records, dispatcher, {
        maxBatch, maxAttempts, source,
      });
    } finally {
      await closeClient();
    }

    const writeErr = _writeOpenBrainSurvivors(forgeDir, queuePath, result.deferred, t0);
    if (writeErr) return writeErr;

    _appendOpenBrainSideEffects(cwd, result);

    return {
      ok: true,
      attempted: result.stats.attempted,
      delivered: result.stats.delivered,
      deferred: result.stats.deferred,
      dlq: result.stats.dlq,
      durationMs: result.stats.durationMs,
      source,
    };
  } catch (err) {
    return { error: String(err?.message || err), durationMs: Date.now() - t0 };
  }
}

// ─── G3.7 — Search-result caching ──────────────────────────────────────

/**
 * G3.7 (v2.36): the MCP layer caches OpenBrain search results to
 * `.forge/memory-search-cache.jsonl` so agents don't re-query for the
 * same slice. Default TTL 1h.
 *
 * Pure helper: given a cached entry `{cachedAt, ttlMs}`, decide whether
 * it's still fresh.
 *
 * @param {{cachedAt: string|number, ttlMs?: number}} entry
 * @param {number} [now=Date.now()]
 * @returns {boolean}
 */
export function isCacheEntryFresh(entry, now = Date.now()) {
  if (!entry || !entry.cachedAt) return false;
  const ts = typeof entry.cachedAt === "number" ? entry.cachedAt : Date.parse(entry.cachedAt);
  if (!Number.isFinite(ts)) return false;
  const ttl = typeof entry.ttlMs === "number" ? entry.ttlMs : 60 * 60 * 1000;
  return now - ts < ttl;
}

/**
 * G3.7 (v2.36): shape a cache entry. `key` should be a deterministic hash
 * of (query, project, limit) — the caller decides. We don't hash here so
 * the helper stays pure + dep-free.
 *
 * @param {{key: string, query: string, project: string, limit: number, results: Array<object>, ttlMs?: number}} ctx
 * @returns {object}
 */
export function buildCacheEntry(ctx) {
  return {
    _v: 1,
    key: ctx.key,
    query: ctx.query,
    project: ctx.project,
    limit: ctx.limit,
    results: Array.isArray(ctx.results) ? ctx.results : [],
    cachedAt: new Date().toISOString(),
    ttlMs: typeof ctx.ttlMs === "number" ? ctx.ttlMs : 60 * 60 * 1000,
  };
}

// ─── GX.4 — Source-attribution format ──────────────────────────────────

/**
 * GX.4 (v2.36): standardised source-attribution format is
 *   `<tool>` or `<tool>/<subsystem>` — e.g. `forge_watch/quorum-dissent`.
 *
 * - tool must match /^forge_[a-z_]+$/
 * - subsystem (when present) must match /^[a-z0-9_-]+$/
 *
 * Returns `{ valid: boolean, reason?: string }`.
 *
 * @param {string} source
 * @returns {{valid: boolean, reason?: string}}
 */
export function validateSourceFormat(source) {
  if (typeof source !== "string" || source.length === 0) {
    return { valid: false, reason: "source must be a non-empty string" };
  }
  const parts = source.split("/");
  if (parts.length > 2) {
    return { valid: false, reason: "source must be '<tool>' or '<tool>/<subsystem>' (exactly one '/')" };
  }
  const [tool, subsystem] = parts;
  if (!/^forge_[a-z_]+$/.test(tool)) {
    return { valid: false, reason: `tool segment '${tool}' must match /^forge_[a-z_]+$/` };
  }
  if (subsystem !== undefined && !/^[a-z0-9_-]+$/.test(subsystem)) {
    return { valid: false, reason: `subsystem segment '${subsystem}' must match /^[a-z0-9_-]+$/` };
  }
  return { valid: true };
}

// ─── GX.3 — forge_memory_report aggregator ─────────────────────────────

function _safeStat(path) {
  try { return statSync(path); } catch { return null; }
}

function _readJsonl(path, limit = Infinity) {
  try {
    const text = readFileSync(path, "utf-8");
    const lines = text.split(/\r?\n/).filter(Boolean);
    const slice = Number.isFinite(limit) && lines.length > limit ? lines.slice(-limit) : lines;
    const out = [];
    for (const line of slice) {
      try { out.push(JSON.parse(line)); } catch { /* skip malformed */ }
    }
    return out;
  } catch {
    return [];
  }
}

function _summariseFile(forgeDir, name) {
  const path = join(forgeDir, name);
  const st = _safeStat(path);
  if (!st) return { name, exists: false, size: 0, records: 0 };
  const records = _readJsonl(path);
  const versions = {};
  for (const r of records) {
    const v = r && r._v != null ? String(r._v) : "none";
    versions[v] = (versions[v] || 0) + 1;
  }
  return { name, exists: true, size: st.size, records: records.length, versions };
}

/**
 * Bucket openbrain-queue.jsonl records by status (pending / delivered /
 * failed / deferred). Extracted helper so buildMemoryReport stays readable.
 *
 * @param {object[]} records
 * @param {number} now - Date.now()
 * @returns {{ pending: number, delivered: number, failed: number, deferred: number }}
 */
function _computeQueueHealth(records, now) {
  const buckets = { pending: 0, delivered: 0, failed: 0, deferred: 0 };
  for (const r of records) {
    const status = r?._status || "pending";
    if (status === "delivered") buckets.delivered++;
    else if (status === "failed") buckets.failed++;
    else {
      const next = r?._nextAttemptAt ? Date.parse(r._nextAttemptAt) : 0;
      if (Number.isFinite(next) && next > now) buckets.deferred++;
      else buckets.pending++;
    }
  }
  return buckets;
}

/**
 * Scan `.forge/` for files/dirs not in the known registry.
 *
 * @param {string} forgeDir - Absolute path to the .forge/ directory
 * @param {boolean} exists - Whether forgeDir exists on disk
 * @returns {string[]}
 */
function _findForgeOrphans(forgeDir, exists) {
  const knownFiles = new Set([
    "liveguard-memories.jsonl", "openbrain-queue.jsonl", "openbrain-dlq.jsonl",
    "openbrain-stats.jsonl", "hub-events.jsonl", "drift-history.jsonl",
    "incidents.jsonl", "regression-history.jsonl", "env-diff-history.jsonl",
    "memory-search-cache.jsonl", "openbrain-queue.archive.jsonl",
    "runs", "traces", "last-orch.pid", "server-ports.json",
    "cost-history.json", "drift-history.json", "model-performance.json",
    "quorum-history.jsonl", "watch-history.jsonl",
    "dashboard-state.json",
    "secrets.json", "rbac.example.json",
    "update-check.json", "version-check.json",
    "secret-scan-cache.json",
    "fm-prefs.json", "forge-master-observer-state.json",
    "liveguard-events.jsonl", "fix-proposals.json",
    "team-activity.jsonl",
    "health-dna.jsonl",
    "local-recall-index.json",
  ]);
  const knownDirs = new Set([
    "telemetry", "runs", "traces", "plans", "digests", "trajectories",
    "crucible", "tempering", "runbooks", "graph", "bugs", "analysis",
    "fm-sessions", "skills-auto", "cache", "validation", "chain-logs",
    "health", "archive", "network-logs", "notifications",
    "hammer-forge-master", "load-sim", "orchestrator-logs",
  ]);
  const ephemeralPatterns = [
    /^release-notes-v[\d.]+.*\.(md|txt)$/,
    /^chain-runner.*\.log$/, /^run-phase-.*\.log$/, /^harden-.*\.log$/,
    /^fm-.*\.(log|json|txt)$/, /^mcp-.*\.log$/, /^sequencer-.*\.log$/,
    /^load-sim.*\.(log|json)$/, /^meta-bug-.*\.(md|txt|json)$/,
    /^gate-tmp\./, /^tmp[-_]/, /\.pid$/, /\.log$/,
  ];
  const orphans = [];
  if (exists) {
    try {
      for (const entry of readdirSync(forgeDir)) {
        if (entry.startsWith(".")) continue;
        if (knownFiles.has(entry)) continue;
        if (knownDirs.has(entry)) continue;
        if (entry.endsWith(".bak") || /\.bak-\d{4}-\d{2}-\d{2}$/.test(entry)) continue;
        if (ephemeralPatterns.some((re) => re.test(entry))) continue;
        orphans.push(entry);
      }
    } catch { /* ignore unreadable dirs */ }
  }
  return orphans;
}

/**
 * GX.3 (v2.36): aggregate the health of every memory surface into a
 * single report — L2 files, OpenBrain queue state, drain stats trend,
 * capture telemetry, search cache. Consumed by the `forge_memory_report`
 * MCP tool (and by the dashboard Memory tab in a follow-up PR).
 *
 * Pure-ish: only reads from `.forge/` — never writes, never calls network.
 *
 * @param {string} [cwd=process.cwd()]
 * @returns {object}
 */
export function buildMemoryReport(cwd = process.cwd()) {
  const forgeDir = resolve(cwd, ".forge");
  const telemetryDir = join(forgeDir, "telemetry");
  const exists = existsSync(forgeDir);

  const l2Files = [
    "liveguard-memories.jsonl",
    "openbrain-queue.jsonl",
    "openbrain-dlq.jsonl",
    "openbrain-stats.jsonl",
    "hub-events.jsonl",
    "drift-history.jsonl",
    "incidents.jsonl",
    "regression-history.jsonl",
    "env-diff-history.jsonl",
    "memory-search-cache.jsonl",
  ].map((n) => _summariseFile(forgeDir, n));

  // Queue health (derived from openbrain-queue.jsonl)
  const queueRecords = exists ? _readJsonl(join(forgeDir, "openbrain-queue.jsonl")) : [];
  const now = Date.now();
  const queueBuckets = _computeQueueHealth(queueRecords, now);
  const dlq = exists ? _readJsonl(join(forgeDir, "openbrain-dlq.jsonl")).length : 0;

  // Drain trend — last 20 drain passes
  const drainRecords = exists ? _readJsonl(join(forgeDir, "openbrain-stats.jsonl"), 20) : [];
  const drainTrend = {
    passes: drainRecords.length,
    lastAttempted: drainRecords.at(-1)?.attempted ?? 0,
    lastDelivered: drainRecords.at(-1)?.delivered ?? 0,
    totalDelivered: drainRecords.reduce((a, r) => a + (r.delivered | 0), 0),
    totalDeferred: drainRecords.reduce((a, r) => a + (r.deferred | 0), 0),
  };

  // Capture telemetry — last 500 records
  const telemetryPath = join(telemetryDir, "memory-captures.jsonl");
  const telemetryRecords = _readJsonl(telemetryPath, 500);
  const telemetry = {
    total: telemetryRecords.length,
    dedupedCount: telemetryRecords.filter((r) => r.deduped).length,
    byTool: {},
    byType: {},
  };
  for (const r of telemetryRecords) {
    if (r?.tool) telemetry.byTool[r.tool] = (telemetry.byTool[r.tool] || 0) + 1;
    if (r?.type) telemetry.byType[r.type] = (telemetry.byType[r.type] || 0) + 1;
  }

  // Search cache health
  const cacheRecords = exists ? _readJsonl(join(forgeDir, "memory-search-cache.jsonl")) : [];
  const uniqueKeys = new Set(cacheRecords.map((r) => r?.key).filter(Boolean));
  const freshEntries = cacheRecords.filter((r) => isCacheEntryFresh(r, now)).length;
  const cache = {
    totalEntries: cacheRecords.length,
    uniqueKeys: uniqueKeys.size,
    freshEntries,
  };

  const orphans = _findForgeOrphans(forgeDir, exists);

  return {
    _v: 1,
    timestamp: new Date().toISOString(),
    cwd,
    forgeDirExists: exists,
    l2Files,
    queue: { ...queueBuckets, dlq },
    drainTrend,
    telemetry,
    cache,
    orphans,
  };
}

// ─── GX.2 — L3 → L1 preload on plan-start ──────────────────────────────

/**
 * GX.2 (v2.36): build a "plan boot context" — a small bundle of OpenBrain
 * search hints derived from the plan itself. Emitted into the L1 hub at
 * `run-started` time so the dashboard, watchers, and the first worker
 * see prior decisions about *this plan* and *its slice domains* before
 * the first slice starts (instead of waiting until mid-slice for the
 * worker's own `search_thoughts` call).
 *
 * The hints are deterministic — the actual L3 lookup is still performed
 * by the agent (we don't have OpenBrain credentials server-side). What
 * GX.2 closes is the "no semantic context at boot" gap.
 *
 * Pure function. Returns an empty `hints` array when projectName/plan
 * are absent — caller can broadcast unconditionally.
 *
 * @param {{slices?: Array<{title?: string, name?: string}>, name?: string}} plan
 * @param {string} projectName
 * @param {{maxHints?: number}} [opts]
 * @returns {{_v: number, projectName: string, planName: string, hints: Array<{kind: string, query: string, limit: number}>}}
 */
export function buildPlanBootContext(plan, projectName, opts = {}) {
  const maxHints = typeof opts.maxHints === "number" ? opts.maxHints : 8;
  const planName = (plan && (plan.name || plan.planName)) || "";
  const out = { _v: 1, projectName: projectName || "", planName, hints: [] };
  if (!projectName || !plan) return out;

  // 1) Plan-level hint — prior runs of this exact plan
  if (planName) {
    out.hints.push({ kind: "plan-history", query: `plan ${planName}`, limit: 5 });
  }

  // 2) Slice-keyword hints — dedup by query string
  const map = loadKeywordSearchMap();
  const seen = new Set();
  const slices = Array.isArray(plan.slices) ? plan.slices : [];
  for (const slice of slices) {
    const title = (slice && (slice.title || slice.name)) || "";
    if (!title) continue;
    for (const { pattern, query } of map) {
      if (seen.has(query)) continue;
      if (pattern.test(title)) {
        out.hints.push({ kind: "slice-keyword", query, limit: 5 });
        seen.add(query);
        if (out.hints.length >= maxHints) return out;
      }
    }
  }

  return out;
}

// ─── Phase-26 Slice 7: Gate-suggestion accept counter (C4) ───────────────────

/**
 * Path to the gate-suggestions event ledger. Append-only JSONL.
 * One record per user action (accept / reject / defer).
 */
const GATE_SUGGESTIONS_PATH = ".forge/gate-suggestions.jsonl";

/**
 * Derive a stable per-suggestion key from its domain and suggested command.
 * Same `(domain, suggestedCommand)` tuple across plans yields the same key
 * so accept counts aggregate. Truncated SHA-256 (12 hex chars) keeps the key
 * short but collision-resistant at this cardinality.
 *
 * @param {{ domain: string, suggestedCommand: string }} suggestion
 * @returns {string}
 */
export function computeGateSuggestionKey(suggestion) {
  const domain = String(suggestion?.domain || "");
  const command = String(suggestion?.suggestedCommand || "");
  return createHash("sha256").update(`${domain}\u0000${command}`).digest("hex").slice(0, 12);
}

/**
 * Append an `accept` event for a gate suggestion to `.forge/gate-suggestions.jsonl`.
 * Returns the suggestion's current `acceptCount` after this record is persisted.
 *
 * Schema:
 *   { type: "accept", suggestionKey, sliceNumber, sliceTitle, domain,
 *     suggestedCommand, at: ISO-timestamp }
 *
 * Phase-26 MUST #C4 / D8: per-suggestion counter, not global; used by
 * `synthesizeGateSuggestions` in `enforce` mode to decide when to auto-inject
 * (threshold: 5 accepts).
 *
 * @param {object} suggestion - a suggestion object from `synthesizeGateSuggestions`
 * @param {string} [cwd=process.cwd()]
 * @returns {{ suggestionKey: string, acceptCount: number }}
 */
export function recordGateAccept(suggestion, cwd = process.cwd()) {
  if (!suggestion || typeof suggestion !== "object") {
    throw new Error("recordGateAccept: suggestion object required");
  }
  const suggestionKey = computeGateSuggestionKey(suggestion);
  const record = {
    type: "accept",
    suggestionKey,
    sliceNumber: suggestion.sliceNumber ?? null,
    sliceTitle: suggestion.sliceTitle || "",
    domain: suggestion.domain || "",
    suggestedCommand: suggestion.suggestedCommand || "",
    at: new Date().toISOString(),
  };
  const path = resolve(cwd, GATE_SUGGESTIONS_PATH);
  mkdirSync(resolve(cwd, ".forge"), { recursive: true });
  appendFileSync(path, `${JSON.stringify(record)}\n`, "utf-8");
  return { suggestionKey, acceptCount: getGateSuggestionCounter(suggestionKey, cwd) };
}

/**
 * Count `accept` events recorded for a given suggestion key.
 * Reads `.forge/gate-suggestions.jsonl` and returns 0 when the ledger is
 * missing, empty, or malformed.
 *
 * @param {string} suggestionKey
 * @param {string} [cwd=process.cwd()]
 * @returns {number}
 */
export function getGateSuggestionCounter(suggestionKey, cwd = process.cwd()) {
  if (!suggestionKey) return 0;
  const path = resolve(cwd, GATE_SUGGESTIONS_PATH);
  if (!existsSync(path)) return 0;
  let count = 0;
  for (const record of _readJsonl(path)) {
    if (record && record.type === "accept" && record.suggestionKey === suggestionKey) {
      count += 1;
    }
  }
  return count;
}

/**
 * Plan Forge — Notification Core
 *
 * Phase FORGE-SHOP-03 Slice 03.1
 *
 * Central notification router: subscribes to hub events, matches routes,
 * dispatches to adapters with rate limiting and digest coalescing.
 *
 * Architecture:
 *   - Config loaded from `.forge/notifications/config.json`
 *   - Route matcher supports event glob + severity filtering
 *   - Token-bucket rate limiter per adapter
 *   - Digest coalescer buffers bursts into single summary
 *   - Env-var templates (`${env:VAR}`) resolved at dispatch time
 *   - Meta-event cascade guard (notification-* events never re-route)
 */

import { randomUUID } from "node:crypto";
import { readForgeJson } from "../orchestrator.mjs";
import { validateAdapterShape } from "../../pforge-sdk/src/notifications/adapter-contract.mjs";
import { ERROR_CODES } from "../enums.mjs";

// ─── Constants ────────────────────────────────────────────────────────
const SEND_TIMEOUT_MS = 5_000;

const SEVERITY_ORDINAL = Object.freeze({ low: 1, medium: 2, high: 3, blocker: 4 });

const DEFAULT_CONFIG = Object.freeze({
  enabled: false,
  adapters: {},
  routes: [],
  rateLimit: { perMinute: 10, digestAfter: 5 },
});

// ─── Env-var resolution ───────────────────────────────────────────────

const ENV_TEMPLATE_RE = /\$\{env:([^}]+)\}/g;
const LITERAL_URL_RE = /^https?:\/\//i;

/**
 * Resolve `${env:VAR_NAME}` templates in a string.
 * @param {string} str
 * @returns {string|null}
 */
export function resolveEnvTemplate(str) {
  if (typeof str !== "string") return str;
  if (LITERAL_URL_RE.test(str) && !ENV_TEMPLATE_RE.test(str)) {
    const err = new Error("Config contains literal URL instead of env-var template. Use ${env:VAR_NAME} pattern.");
    err.code = "ERR_LITERAL_SECRET";
    throw err;
  }
  return str.replace(ENV_TEMPLATE_RE, (_, varName) => process.env[varName] ?? "");
}

/**
 * Resolve all string values in an adapter config object.
 * @param {Object} config
 * @returns {Object}
 */
function resolveAdapterConfig(config) {
  if (!config || typeof config !== "object") return config;
  const resolved = {};
  for (const [k, v] of Object.entries(config)) {
    resolved[k] = typeof v === "string" ? resolveEnvTemplate(v) : v;
  }
  return resolved;
}

// ─── Route matcher ────────────────────────────────────────────────────

/**
 * Convert a simple glob pattern to a RegExp.
 * Only supports `*` (match anything) at the end.
 * @param {string} pattern
 * @returns {RegExp}
 */
function globToRegex(pattern) {
  const escaped = pattern.replace(/[.+^${}()|[\]\\]/g, "\\$&").replace(/\*/g, ".*");
  return new RegExp(`^${escaped}$`);
}

/**
 * Parse a severity filter expression like ">=high" or "=blocker".
 * @param {string} expr
 * @returns {{ op: string, level: number }|null}
 */
function parseSeverityFilter(expr) {
  if (!expr || typeof expr !== "string") return null;
  const match = expr.match(/^(>=|<=|>|<|=)?\s*(\w+)$/);
  if (!match) return null;
  const op = match[1] || "=";
  const level = SEVERITY_ORDINAL[match[2]];
  if (level === undefined) return null;
  return { op, level };
}

/**
 * Check whether an event severity passes a filter.
 * @param {string|undefined} eventSeverity
 * @param {{ op: string, level: number }} filter
 * @returns {boolean}
 */
function severityPasses(eventSeverity, filter) {
  const val = SEVERITY_ORDINAL[eventSeverity];
  if (val === undefined) return false;
  switch (filter.op) {
    case "=":  return val === filter.level;
    case ">=": return val >= filter.level;
    case ">":  return val >  filter.level;
    case "<=": return val <= filter.level;
    case "<":  return val <  filter.level;
    default:   return false;
  }
}

/**
 * Match event against configured routes.
 * @param {Object} event
 * @param {Array} routes
 * @returns {string[]} - Deduplicated array of adapter names to dispatch to
 */
export function matchRoutes(event, routes) {
  if (!Array.isArray(routes) || !event?.type) return [];
  const matched = new Set();
  for (const route of routes) {
    const when = route?.when;
    if (!when?.event) continue;

    // Event type glob match
    const re = globToRegex(when.event);
    if (!re.test(event.type)) continue;

    // Severity filter (optional)
    if (when.severity) {
      const filter = parseSeverityFilter(when.severity);
      if (filter) {
        const eventSev = event.data?.severity || event.severity;
        if (!severityPasses(eventSev, filter)) continue;
      }
    }

    // Matched — collect adapter names
    const via = Array.isArray(route.via) ? route.via : [route.via];
    for (const v of via) {
      if (typeof v === "string") matched.add(v);
    }
  }
  return [...matched];
}

// ─── Token-bucket rate limiter ────────────────────────────────────────

export class TokenBucket {
  /**
   * @param {{ perMinute?: number }} config
   * @param {() => number} [nowFn]
   */
  constructor(config = {}, nowFn = () => Date.now()) {
    this._perMinute = config.perMinute || 10;
    this._nowFn = nowFn;
    /** @type {Map<string, { tokens: number, lastRefill: number }>} */
    this._buckets = new Map();
  }

  /**
   * Try to consume a token for the given adapter.
   * @param {string} adapterName
   * @returns {{ ok: boolean, reason?: string }}
   */
  tryConsume(adapterName) {
    const now = this._nowFn();
    let bucket = this._buckets.get(adapterName);
    if (!bucket) {
      bucket = { tokens: this._perMinute, lastRefill: now };
      this._buckets.set(adapterName, bucket);
    }

    // Refill tokens based on elapsed time
    const elapsedMs = now - bucket.lastRefill;
    if (elapsedMs >= 60_000) {
      bucket.tokens = this._perMinute;
      bucket.lastRefill = now;
    } else {
      const refill = (elapsedMs / 60_000) * this._perMinute;
      bucket.tokens = Math.min(this._perMinute, bucket.tokens + refill);
      bucket.lastRefill = now;
    }

    if (bucket.tokens >= 1) {
      bucket.tokens -= 1;
      return { ok: true };
    }
    return { ok: false, reason: "token-bucket" };
  }

  shutdown() {
    this._buckets.clear();
  }
}

// ─── Digest coalescer ─────────────────────────────────────────────────

export class DigestTracker {
  /**
   * @param {{ digestAfter?: number }} config
   * @param {(digest: Object) => void} onDigest - Callback when digest fires
   */
  constructor(config = {}, onDigest = () => {}) {
    this._digestAfter = config.digestAfter || 5;
    this._onDigest = onDigest;
    /** @type {Map<string, { count: number, firstEvent: Object, timer: any }>} */
    this._windows = new Map();
  }

  /**
   * Track an event for digest coalescing.
   * @param {string} routeKey - adapter:eventType combo
   * @param {Object} event
   * @returns {boolean} true if event should be sent individually, false if coalesced
   */
  track(routeKey, event) {
    let window = this._windows.get(routeKey);
    if (!window) {
      window = { count: 0, firstEvent: event, timer: null };
      this._windows.set(routeKey, window);

      // Start 60s window timer
      window.timer = setTimeout(() => {
        const w = this._windows.get(routeKey);
        if (w && w.count >= this._digestAfter) {
          this._onDigest({
            type: "notification-digested",
            routeKey,
            digestCount: w.count,
            firstEvent: w.firstEvent,
          });
        }
        this._windows.delete(routeKey);
      }, 60_000);
      if (window.timer?.unref) window.timer.unref();
    }

    window.count += 1;

    // Under threshold: send individually
    if (window.count <= this._digestAfter) return true;

    // Over threshold: coalesce (don't send individually)
    return false;
  }

  shutdown() {
    for (const [, w] of this._windows) {
      if (w.timer) clearTimeout(w.timer);
    }
    this._windows.clear();
  }
}

// ─── Config loader ────────────────────────────────────────────────────

/**
 * Load notification config from `.forge/notifications/config.json`.
 * @param {string} projectRoot
 * @returns {Object}
 */
export function loadNotificationsConfig(projectRoot) {
  const config = readForgeJson("notifications/config.json", null, projectRoot);
  if (!config) return { ...DEFAULT_CONFIG };
  return {
    enabled: !!config.enabled,
    adapters: config.adapters || {},
    routes: Array.isArray(config.routes) ? config.routes : [],
    rateLimit: {
      perMinute: config.rateLimit?.perMinute ?? 10,
      digestAfter: config.rateLimit?.digestAfter ?? 5,
    },
  };
}

// ─── Format message ───────────────────────────────────────────────────

/**
 * Generate a human-readable message from an event.
 * @param {Object} event
 * @returns {string}
 */
function formatMessage(event) {
  const type = event?.type || "unknown";
  const sev = event?.data?.severity || event?.severity || "";
  const sevTag = sev ? ` [${sev}]` : "";
  const msg = event?.data?.message || event?.message || "";
  return msg ? `${type}${sevTag}: ${msg}` : `${type}${sevTag}`;
}

// ─── Core factory ─────────────────────────────────────────────────────

/**
 * Create the notification core instance.
 *
 * @param {Object} options
 * @param {Object|null} options.hub           - Hub instance (for broadcasting meta-events)
 * @param {string}      options.projectRoot   - Project root directory
 * @param {Object}      [options.adapters]    - Map of adapter name → adapter object
 * @param {Function}    [options.captureMemoryFn] - L3 memory capture
 * @param {() => number} [options.nowFn]      - Injectable clock for testing
 * @returns {{ ingest: Function, directSend: Function, testAdapter: Function, getStats: Function, shutdown: Function }}
 */
function createDisabledNotificationCore() {
  return {
    ingest: () => {},
    directSend: () => ({ ok: false, error: "Notifications disabled" }),
    testAdapter: () => ({ ok: true, adapters: [], note: "Notifications disabled" }),
    getStats: () => ({ sent: 0, failed: 0 }),
    shutdown: () => {},
  };
}

function createNotificationBroadcaster(hub) {
  return function broadcastNotification(metaEvent) {
    try {
      hub?.broadcast({ ...metaEvent, timestamp: new Date().toISOString() });
    } catch { /* best-effort */ }
  };
}

function createNotificationFailureCapture({ captureMemoryFn, projectRoot }) {
  return function captureNotificationFailure(adapterName, errorCode) {
    try {
      captureMemoryFn?.(
        `Notification delivery failed: ${adapterName} → ${errorCode}`,
        "gotcha",
        `notification/${adapterName}`,
        projectRoot,
      );
    } catch { /* best-effort */ }
  };
}

function resolveDispatchContext({ adapterName, event, adapters, config, broadcastNotification, stats }) {
  const adapter = adapters[adapterName];
  if (!adapter) return { skip: true };

  const adapterConfig = config.adapters?.[adapterName] || {};
  if (adapterConfig.enabled === false) return { skip: true };

  try {
    const resolvedConfig = resolveAdapterConfig(adapterConfig);
    return { adapter, resolvedConfig };
  } catch (err) {
    if (err.code === "ERR_LITERAL_SECRET") {
      broadcastNotification({
        type: "notification-send-failed",
        adapter: adapterName,
        event: event.type,
        errorCode: "ERR_LITERAL_SECRET",
      });
      stats.failed++;
      return { skip: true };
    }
    throw err;
  }
}

function shouldSkipResolvedAdapter({ adapterName, event, resolvedConfig, warnedNullUrls, rateLimiter, digestTracker, broadcastNotification }) {
  if (resolvedConfig.url === "" || resolvedConfig.url === undefined || resolvedConfig.url === null) {
    if (!warnedNullUrls.has(adapterName)) {
      console.warn(`[notifications] ${adapterName} enabled but URL is null or empty`);
      warnedNullUrls.add(adapterName);
    }
    return true;
  }

  const allowed = rateLimiter.tryConsume(adapterName);
  if (!allowed.ok) {
    broadcastNotification({
      type: "notification-rate-limited",
      adapter: adapterName,
      event: event.type,
      reason: allowed.reason,
    });
    return true;
  }

  const routeKey = `${adapterName}:${event.type}`;
  return !digestTracker.track(routeKey, event);
}

function handleDispatchSuccess({ result, adapterName, event, correlationId, deliveryMs, broadcastNotification, captureNotificationFailure, stats }) {
  if (result?.ok) {
    stats.sent++;
    broadcastNotification({
      type: "notification-sent",
      adapter: adapterName,
      event: event.type,
      correlationId,
      deliveryMs,
    });
    return;
  }

  const errorCode = result?.errorCode || "SEND_FAILED";
  stats.failed++;
  broadcastNotification({
    type: "notification-send-failed",
    adapter: adapterName,
    event: event.type,
    errorCode,
    correlationId,
    deliveryMs,
  });
  captureNotificationFailure(adapterName, errorCode);
}

function handleDispatchError({ adapterName, event, correlationId, deliveryMs, err, broadcastNotification, captureNotificationFailure, stats }) {
  const errorCode = err.message === ERROR_CODES.TIMEOUT.code ? ERROR_CODES.TIMEOUT.code : (err.code || "SEND_FAILED");
  stats.failed++;
  broadcastNotification({
    type: "notification-send-failed",
    adapter: adapterName,
    event: event.type,
    errorCode,
    correlationId,
    deliveryMs,
  });
  captureNotificationFailure(adapterName, errorCode);
}

async function dispatchNotificationEvent({ adapterName, event, adapters, config, warnedNullUrls, rateLimiter, digestTracker, broadcastNotification, captureNotificationFailure, nowFn, stats }) {
  const context = resolveDispatchContext({
    adapterName,
    event,
    adapters,
    config,
    broadcastNotification,
    stats,
  });
  if (context.skip) return;
  if (shouldSkipResolvedAdapter({
    adapterName,
    event,
    resolvedConfig: context.resolvedConfig,
    warnedNullUrls,
    rateLimiter,
    digestTracker,
    broadcastNotification,
  })) {
    return;
  }

  const correlationId = event.correlationId || randomUUID();
  const formattedMessage = formatMessage(event);
  const t0 = nowFn();

  try {
    const result = await Promise.race([
      context.adapter.send({
        event,
        route: adapterName,
        formattedMessage,
        correlationId,
        config: context.resolvedConfig,
      }),
      new Promise((_, reject) => setTimeout(() => reject(new Error(ERROR_CODES.TIMEOUT.code)), SEND_TIMEOUT_MS)),
    ]);
    handleDispatchSuccess({
      result,
      adapterName,
      event,
      correlationId,
      deliveryMs: nowFn() - t0,
      broadcastNotification,
      captureNotificationFailure,
      stats,
    });
  } catch (err) {
    handleDispatchError({
      adapterName,
      event,
      correlationId,
      deliveryMs: nowFn() - t0,
      err,
      broadcastNotification,
      captureNotificationFailure,
      stats,
    });
  }
}

async function directSendNotification({ via, payload, formattedMessage, adapters, config, nowFn }) {
  const adapter = adapters[via];
  if (!adapter) return { ok: false, error: "ERR_ADAPTER_NOT_FOUND", adapter: via };

  const adapterConfig = config.adapters?.[via] || {};
  let resolvedConfig;
  try {
    resolvedConfig = resolveAdapterConfig(adapterConfig);
  } catch (err) {
    return { ok: false, error: err.code || "ERR_CONFIG", message: err.message };
  }

  const correlationId = randomUUID();
  const message = formattedMessage || formatMessage(payload);
  const t0 = nowFn();

  try {
    const result = await Promise.race([
      adapter.send({ event: payload, route: via, formattedMessage: message, correlationId, config: resolvedConfig }),
      new Promise((_, reject) => setTimeout(() => reject(new Error(ERROR_CODES.TIMEOUT.code)), SEND_TIMEOUT_MS)),
    ]);
    return { ...result, adapter: via, deliveryMs: nowFn() - t0 };
  } catch (err) {
    return {
      ok: false,
      adapter: via,
      errorCode: err.message === ERROR_CODES.TIMEOUT.code ? ERROR_CODES.TIMEOUT.code : "SEND_FAILED",
      error: err.message,
      deliveryMs: nowFn() - t0,
    };
  }
}

function validateNotificationAdapters({ adapterName, adapters, config }) {
  const names = adapterName ? [adapterName] : Object.keys(adapters);
  const results = [];

  for (const name of names) {
    const adapter = adapters[name];
    if (!adapter) {
      results.push({ name, configValid: false, reason: "adapter-not-registered" });
      continue;
    }

    const shape = validateAdapterShape(adapter);
    if (!shape.valid) {
      results.push({ name, configValid: false, reason: `missing: ${shape.missing.join(", ")}` });
      continue;
    }

    const adapterConfig = config.adapters?.[name] || {};
    let resolvedConfig;
    try {
      resolvedConfig = resolveAdapterConfig(adapterConfig);
    } catch (err) {
      results.push({ name, configValid: false, reason: err.code || err.message });
      continue;
    }

    const validation = adapter.validate(resolvedConfig);
    results.push({ name, configValid: validation.ok, reason: validation.reason || undefined });
  }

  return { ok: true, adapters: results };
}

function createNotificationCoreRuntime({ hub, projectRoot, adapters, captureMemoryFn, nowFn, config }) {
  const rateLimiter = new TokenBucket(config.rateLimit, nowFn);
  const warnedNullUrls = new Set();
  const stats = { sent: 0, failed: 0 };
  const broadcastNotification = createNotificationBroadcaster(hub);
  const captureNotificationFailure = createNotificationFailureCapture({ captureMemoryFn, projectRoot });
  const digestTracker = new DigestTracker(config.rateLimit, (digest) => {
    try {
      hub?.broadcast({
        type: "notification-digested",
        routeKey: digest.routeKey,
        digestCount: digest.digestCount,
        timestamp: new Date().toISOString(),
      });
    } catch { /* best-effort */ }
  });

  function ingest(event) {
    if (event?.type?.startsWith("notification-")) return;
    if (process.env.NODE_ENV === "test") return;

    const matched = matchRoutes(event, config.routes);
    for (const adapterName of matched) {
      dispatchNotificationEvent({
        adapterName,
        event,
        adapters,
        config,
        warnedNullUrls,
        rateLimiter,
        digestTracker,
        broadcastNotification,
        captureNotificationFailure,
        nowFn,
        stats,
      }).catch(() => { /* best-effort */ });
    }
  }

  return {
    ingest,
    directSend({ via, payload, formattedMessage }) {
      return directSendNotification({ via, payload, formattedMessage, adapters, config, nowFn });
    },
    testAdapter({ adapter: adapterName } = {}) {
      return validateNotificationAdapters({ adapterName, adapters, config });
    },
    getStats() {
      return { sent: stats.sent, failed: stats.failed };
    },
    shutdown() {
      rateLimiter.shutdown();
      digestTracker.shutdown();
    },
  };
}

export function createNotificationCore({ hub = null, projectRoot, adapters = {}, captureMemoryFn = null, nowFn = () => Date.now() } = {}) {
  const config = loadNotificationsConfig(projectRoot);
  if (!config.enabled) {
    return createDisabledNotificationCore();
  }
  return createNotificationCoreRuntime({
    hub,
    projectRoot,
    adapters,
    captureMemoryFn,
    nowFn,
    config,
  });
}

/**
 * Plan Forge — Webhook Notification Adapter
 *
 * Phase FORGE-SHOP-03 Slice 03.1
 *
 * Sends notifications via HTTP POST (webhook). Uses native fetch() — no deps.
 * Conforms to the adapter contract defined in pforge-sdk/src/notifications/adapter-contract.mjs.
 */

/**
 * Validate webhook adapter config.
 * @param {Object} config
 * @returns {{ ok: boolean, reason?: string }}
 */
function validate(config) {
  if (!config || typeof config !== "object") return { ok: false, reason: "config-missing" };
  if (config.url === null || config.url === undefined) return { ok: false, reason: "url-missing" };
  if (typeof config.url !== "string" || config.url.trim() === "") return { ok: false, reason: "url-missing" };
  return { ok: true };
}

/**
 * Mask sensitive segments in URLs for error logging.
 * @param {string} url
 * @returns {string}
 */
function maskUrl(url) {
  try {
    return url
      .replace(/\/bot[^/]+\//i, "/bot[REDACTED]/")
      .replace(/hooks\.slack\.com\/services\/[^\s]+/i, "hooks.slack.com/services/[REDACTED]")
      .replace(/discord(app)?\.com\/api\/webhooks\/[^\s]+/i, "discord.com/api/webhooks/[REDACTED]");
  } catch { return "[URL]"; }
}

/**
 * Send a notification via HTTP POST.
 * @param {import('../../pforge-sdk/src/notifications/adapter-contract.mjs').AdapterSendArgs} args
 * @returns {Promise<import('../../pforge-sdk/src/notifications/adapter-contract.mjs').AdapterSendResult>}
 */
async function send({ event, route, formattedMessage, correlationId, config }) {
  const url = config?.url;
  if (!url) return { ok: false, errorCode: "NO_URL", error: "No URL configured" };

  const body = {
    event: event?.type || "unknown",
    severity: event?.data?.severity || event?.severity || null,
    correlationId,
    message: formattedMessage || "",
    timestamp: event?.timestamp || new Date().toISOString(),
    data: event?.data || {},
  };

  try {
    const response = await fetch(url, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body),
    });

    const statusCode = response.status;
    if (response.ok) {
      return { ok: true, statusCode, deliveryMs: 0 };
    }
    return { ok: false, statusCode, errorCode: `HTTP_${statusCode}`, error: `HTTP ${statusCode}` };
  } catch (err) {
    console.error(`[notifications/webhook] Send error (${maskUrl(url)}): ${err.message}`);
    return { ok: false, errorCode: "NETWORK_ERROR", error: err.message };
  }
}

/** @type {import('../../pforge-sdk/src/notifications/adapter-contract.mjs').NotificationAdapter} */
export const webhookAdapter = Object.freeze({
  name: "webhook",
  send,
  validate,
});

/**
 * openbrain-replay.mjs
 * ─────────────────────────────────────────────────────────────────────
 * Round-trip test + bulk replay utilities for OpenBrain (L3 memory).
 *
 * Pure module — all I/O is dependency-injected (filesystem path strings,
 * MCP client object). Live SSE transport lives in `createSseClient()` so
 * tests can substitute a mock client.
 *
 * Companions:
 *   - REST: POST /api/brain/test, POST /api/brain/replay  (server.mjs)
 *   - MCP : forge_brain_test, forge_brain_replay           (capabilities.mjs)
 *   - CLI : pforge brain test, pforge brain replay         (pforge.ps1/sh)
 *
 * Scope: project-agnostic; reads OpenBrain endpoint from .vscode/mcp.json.
 * Does NOT dedupe against existing OpenBrain records; does NOT migrate schema.
 */

import { existsSync, readFileSync, statSync, readdirSync } from "node:fs";
import { resolve, basename, join } from "node:path";

// ─── Config discovery ──────────────────────────────────────────────────

/**
 * Read OpenBrain SSE endpoint + auth key from .vscode/mcp.json (or .claude/mcp.json).
 * Supports both header-form (`headers: { "x-brain-key": "..." }`) and query-form
 * (`url: ".../sse?key=..."`) auth. Resolves `${env:NAME}` placeholders.
 *
 * @param {string} cwd
 * @returns {{ url: string, key: string|null, source: string } | null}
 */
export function readOpenBrainConfig(cwd) {
  const candidates = [
    resolve(cwd, ".vscode", "mcp.json"),
    resolve(cwd, ".claude", "mcp.json"),
  ];

  for (const path of candidates) {
    if (!existsSync(path)) continue;
    const config = readJsonFile(path);
    if (!config) continue;
    const entry = findOpenBrainServer(config);
    const parsed = entry ? parseOpenBrainConfigEntry(entry, path) : null;
    if (parsed) return parsed;
  }
  return null;
}

/** Resolve `${env:NAME}` → process.env[NAME]. Returns input unchanged otherwise. */
function resolveEnvPlaceholder(value) {
  if (typeof value !== "string") return null;
  const m = value.match(/^\$\{env:([A-Z_][A-Z0-9_]*)\}$/i);
  if (!m) return value;
  const envName = m[1];
  return process.env[envName] ?? null;
}

function readJsonFile(path) {
  try {
    return JSON.parse(readFileSync(path, "utf-8"));
  } catch {
    return null;
  }
}

function findOpenBrainServer(config) {
  const servers = config?.servers ?? config?.mcpServers ?? {};
  for (const name of Object.keys(servers)) {
    if (/openbrain|open-brain/i.test(name)) return servers[name];
  }
  return null;
}

function openBrainHeaderKey(entry) {
  const headers = entry?.headers ?? {};
  for (const headerName of Object.keys(headers)) {
    if (/^x-brain-key$/i.test(headerName)) {
      return resolveEnvPlaceholder(headers[headerName]);
    }
  }
  return null;
}

function openBrainQueryKey(url) {
  try {
    return new URL(url).searchParams.get("key");
  } catch {
    return null;
  }
}

function parseOpenBrainConfigEntry(entry, source) {
  const url = typeof entry?.url === "string" ? entry.url : null;
  if (!url) return null;
  const key = openBrainHeaderKey(entry)
    || openBrainQueryKey(url)
    || process.env.OPENBRAIN_KEY
    || null;
  return { url, key, source };
}

// ─── Normalizers ───────────────────────────────────────────────────────

const QUEUE_META_PREFIX = "_"; // queue-internal fields start with _ (e.g. _status)
const CAPTURE_TOP_LEVEL = new Set(["content", "project", "source", "created_by"]);

/**
 * Normalize a `.forge/openbrain-queue.jsonl` record → capture_thought payload.
 * Returns null for tombstones (`_action=delete`) or records missing content.
 *
 * @param {object} record
 * @returns {{ content: string, project?: string, source?: string, created_by?: string, metadata?: object } | null}
 */
export function normalizeQueueRecord(record) {
  if (!record || typeof record !== "object") return null;
  if (record._action === "delete") return null;
  const content = typeof record.content === "string" ? record.content.trim() : "";
  if (!content) return null;

  const out = { content };
  if (record.project) out.project = String(record.project);
  if (record.source) out.source = String(record.source);
  if (record.created_by) out.created_by = String(record.created_by);

  // Everything else (excluding queue internals) becomes metadata.
  const metadata = {};
  for (const k of Object.keys(record)) {
    if (k.startsWith(QUEUE_META_PREFIX)) continue;
    if (CAPTURE_TOP_LEVEL.has(k)) continue;
    if (k === "content") continue;
    metadata[k] = record[k];
  }
  if (Object.keys(metadata).length > 0) out.metadata = metadata;

  return out;
}

/**
 * Normalize a markdown file → array of capture_thought records, one per H2 section.
 * Falls back to a single record (whole file) when no H2 headings are found.
 *
 * @param {string} path
 * @param {{ project?: string, source?: string, maxBytes?: number }} opts
 */
export function normalizeMarkdownFile(path, opts = {}) {
  const { project, source, maxBytes = 8192 } = opts;
  const raw = readFileSync(path, "utf-8");
  const fileName = basename(path);

  const sections = splitByHeading(raw);
  return sections.map((sec) => {
    let content = sec.body.trim() ? `${sec.heading}\n\n${sec.body.trim()}` : sec.heading;
    let truncated = false;
    if (content.length > maxBytes) {
      content = content.slice(0, maxBytes) + "\n\n[…truncated]";
      truncated = true;
    }
    const metadata = { source_file: fileName, heading: stripHashPrefix(sec.heading) };
    if (truncated) metadata.truncated = true;
    const record = { content };
    if (project) record.project = project;
    if (source) record.source = source;
    record.metadata = metadata;
    return record;
  });
}

/**
 * Walk a directory and return all `.md` files (non-recursive by default).
 * Exposed so the REST layer can resolve a "source" argument uniformly.
 */
export function listMarkdownFiles(dir, { recursive = false } = {}) {
  const out = [];
  function walk(d) {
    for (const name of readdirSync(d)) {
      const p = join(d, name);
      const st = statSync(p);
      if (st.isDirectory()) {
        if (recursive) walk(p);
      } else if (/\.md$/i.test(name)) {
        out.push(p);
      }
    }
  }
  if (existsSync(dir) && statSync(dir).isDirectory()) walk(dir);
  return out;
}

function splitByHeading(raw) {
  const lines = raw.split(/\r?\n/);

  // First pass: detect whether the document has any H2 sections.
  const hasH2 = lines.some((l) => /^##\s+\S/.test(l));

  const sections = [];
  let current = null;

  if (hasH2) {
    // H2-only mode: ignore preamble (H1, intro paragraphs); emit one section
    // per H2 heading, including the heading line + everything below until the
    // next H2.
    for (const line of lines) {
      const h2 = /^##\s+(.+)$/.exec(line);
      if (h2) {
        if (current) sections.push(current);
        current = { heading: line, body: "" };
      } else if (current) {
        current.body += line + "\n";
      }
    }
    if (current) sections.push(current);
    return sections;
  }

  // Fallback: no H2s. Emit one section using the first H1 as the heading
  // (or "# Document" if no headings at all).
  let heading = "# Document";
  for (const line of lines) {
    const h1 = /^#\s+(.+)$/.exec(line);
    if (h1) { heading = line; break; }
  }
  // Body = all non-heading content.
  const body = lines.filter((l) => !/^#\s+/.test(l)).join("\n");
  sections.push({ heading, body });
  return sections;
}

function stripHashPrefix(heading) {
  return heading.replace(/^#+\s+/, "").trim();
}

// ─── Round-trip ────────────────────────────────────────────────────────

/**
 * Distinctive natural-language probe phrase embedded in every canary thought
 * and used as the semantic-search query. Random alphanumeric markers (e.g.
 * `PFTEST-RT-ABC123`) have weak embeddings and rank poorly once the corpus
 * contains real entries — see issue #204. The probe phrase is unique to our
 * canary thoughts, so hits are reliably retrievable regardless of corpus size.
 *
 * Treat this string as a contract: changing it invalidates older canaries
 * (which is fine — they're throwaway).
 */
const ROUND_TRIP_PROBE_PHRASE =
  "pforge brain test round-trip canary verifier sentinel phrase";

export { ROUND_TRIP_PROBE_PHRASE };

/**
 * Capture a unique marker thought, then search for it. Returns ok=true when
 * the search response includes a record whose content carries the marker.
 *
 * Search strategy: query by a fixed distinctive probe phrase (not the random
 * marker) so semantic search reliably surfaces canary thoughts at the top of
 * results. Among the returned hits, find the one whose content includes our
 * marker — that's positive verification of the current round-trip.
 *
 * @param {object} client  - mock or live MCP client with capture()/search()
 * @param {{ project?: string, source?: string, indexDelayMs?: number, searchLimit?: number }} opts
 */
export async function roundTrip(client, opts = {}) {
  const start = Date.now();
  const marker = `PFTEST-RT-${randomId(10)}`;
  const project = opts.project || "plan-forge";
  const source = opts.source || "pforge-brain-test";

  try {
    const captureRes = await client.capture({
      content: `${ROUND_TRIP_PROBE_PHRASE} — marker=${marker} (pforge brain test canary; safe to ignore)`,
      project,
      source,
    });
    // Allow OpenBrain a moment to index (best-effort; many backends are
    // synchronous, but pgvector REINDEX windows can lag a second).
    if (opts.indexDelayMs) await delay(opts.indexDelayMs);

    const searchRes = await client.search({
      query: ROUND_TRIP_PROBE_PHRASE,
      project,
      limit: opts.searchLimit || 25,
    });
    const hits = searchRes?.results ?? searchRes?.thoughts ?? [];
    const hit = hits.find((h) => String(h.content || "").includes(marker)) ?? null;

    return {
      ok: hit !== null,
      marker,
      hit,
      capturedId: captureRes?.id ?? null,
      searchedHits: hits.length,
      durationMs: Date.now() - start,
    };
  } catch (e) {
    return {
      ok: false,
      marker,
      hit: null,
      error: String(e?.message || e),
      durationMs: Date.now() - start,
    };
  }
}

// ─── Bulk replay ───────────────────────────────────────────────────────

/**
 * Replay a batch of records into OpenBrain via capture_thought.
 * Rate-limited; retries on any thrown error up to maxRetries.
 *
 * @param {object} client
 * @param {Array<object|null>} records  - pre-normalized capture payloads (or nulls to skip)
 * @param {{
 *   rate?: number,           // ms between calls (default 50)
 *   maxRetries?: number,     // default 3
 *   retryDelayMs?: number,   // base backoff (default 250)
 *   dryRun?: boolean,
 *   sampleSize?: number,     // # of sample receipts to return (default 5)
 *   onProgress?: (event: {index, total, status, error?}) => void,
 * }} opts
 */
function isReplayableRecord(rec) {
  return rec && typeof rec === "object" && typeof rec.content === "string" && rec.content.trim();
}

function recordPreview(rec) {
  return rec.content.slice(0, 80);
}

async function captureReplayRecord(client, rec, maxRetries, retryDelayMs) {
  let attempt = 0;
  let lastErr = null;
  while (attempt < maxRetries) {
    attempt += 1;
    try {
      return { ok: true, response: await client.capture(rec) };
    } catch (e) {
      lastErr = String(e?.message || e);
      if (attempt < maxRetries) {
        await delay(retryDelayMs * Math.pow(2, attempt - 1));
      }
    }
  }
  return { ok: false, error: lastErr };
}

function shouldDelayReplay(rate, index, total) {
  return rate > 0 && index < total - 1;
}

export async function replayRecords(client, records, opts = {}) {
  const {
    rate = 50,
    maxRetries = 3,
    retryDelayMs = 250,
    dryRun = false,
    sampleSize = 5,
    onProgress = null,
  } = opts;

  const start = Date.now();
  const total = records.length;
  let sent = 0;
  let failed = 0;
  let skipped = 0;
  const samples = [];
  const failures = [];

  for (let i = 0; i < records.length; i++) {
    const rec = records[i];
    if (!isReplayableRecord(rec)) {
      skipped += 1;
      onProgress?.({ index: i, total, status: "skipped" });
      continue;
    }
    if (dryRun) {
      onProgress?.({ index: i, total, status: "dryrun" });
      continue;
    }

    const outcome = await captureReplayRecord(client, rec, maxRetries, retryDelayMs);
    if (outcome.ok) {
      sent += 1;
      if (samples.length < sampleSize) {
        samples.push({ index: i, id: outcome.response?.id ?? null, content: recordPreview(rec) });
      }
      onProgress?.({ index: i, total, status: "sent" });
    } else {
      failed += 1;
      failures.push({ index: i, error: outcome.error, contentPreview: recordPreview(rec) });
      onProgress?.({ index: i, total, status: "failed", error: outcome.error });
    }

    if (shouldDelayReplay(rate, i, records.length)) await delay(rate);
  }

  return {
    attempted: total - skipped,
    sent,
    failed,
    skipped,
    dryRun,
    durationMs: Date.now() - start,
    samples,
    failures,
  };
}

// ─── Live SSE client (thin SDK wrapper) ────────────────────────────────

/**
 * Build a live MCP client connected to OpenBrain via SSE. Returns an object
 * with the same shape used by tests ({ capture, search, close }).
 *
 * @param {{ url: string, key: string|null }} cfg
 */
export async function createSseClient(cfg) {
  if (!cfg?.url) throw new Error("createSseClient: missing url");
  const { Client } = await import("@modelcontextprotocol/sdk/client/index.js");
  const { SSEClientTransport } = await import("@modelcontextprotocol/sdk/client/sse.js");

  const transport = new SSEClientTransport(new URL(cfg.url), {
    requestInit: cfg.key ? { headers: { "x-brain-key": cfg.key } } : undefined,
    eventSourceInit: cfg.key
      ? {
          // Custom fetch lets us inject the auth header into the SSE GET too.
          fetch: (url, init) =>
            fetch(url, {
              ...(init || {}),
              headers: { ...(init?.headers || {}), "x-brain-key": cfg.key },
            }),
        }
      : undefined,
  });

  const client = new Client(
    { name: "pforge-brain-client", version: "1.0.0" },
    { capabilities: {} }
  );
  await client.connect(transport);

  return {
    raw: client,
    transport,
    async capture(args) {
      const res = await client.callTool({ name: "capture_thought", arguments: args });
      return parseToolResult(res);
    },
    async search(args) {
      const res = await client.callTool({ name: "search_thoughts", arguments: args });
      return parseToolResult(res);
    },
    async close() {
      try { await client.close(); } catch { /* best-effort */ }
    },
  };
}

/** Best-effort parse of an MCP tool-call response into a JSON object.
 *  Throws when the MCP server reports `isError: true` so that
 *  `replayRecords` / callers see the failure instead of silently
 *  recording the error text as a successful capture. */
function parseToolResult(res) {
  if (!res) return null;

  // Extract the textual payload (if any) from content parts.
  let extracted = null;
  if (Array.isArray(res.content)) {
    for (const part of res.content) {
      if (part?.type === "text" && typeof part.text === "string") {
        try { extracted = JSON.parse(part.text); } catch { extracted = { text: part.text }; }
        break;
      }
    }
  }
  if (extracted === null && res.structuredContent) extracted = res.structuredContent;
  if (extracted === null) extracted = res;

  // Honor MCP-level error flag. Older code silently returned the error
  // body as if it were a successful result — the root cause of receipt
  // logs reporting `status: "sent"` for embed-failed records.
  if (res.isError === true) {
    const body = typeof extracted === "string"
      ? extracted
      : (extracted?.text ?? JSON.stringify(extracted));
    const err = new Error(`mcp tool error: ${String(body).slice(0, 500)}`);
    err.mcpError = true;
    err.mcpBody = extracted;
    throw err;
  }

  return extracted;
}

// ─── helpers ───────────────────────────────────────────────────────────

function delay(ms) { return new Promise((r) => setTimeout(r, ms)); }

function randomId(len) {
  const alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
  let out = "";
  for (let i = 0; i < len; i++) out += alphabet[Math.floor(Math.random() * alphabet.length)];
  return out;
}

/**
 * Plan Forge — Phase-53 (ORCHESTRATOR-SPLIT) S5: forge-io sub-module
 *
 * I/O helpers and reporting functions extracted from orchestrator.mjs:
 * forge directory management, cost/performance reporting, health trends,
 * run pruning, and gate-check configuration/responder.
 *
 * Private helpers (readForgeJson, readForgeJsonl, appendForgeJsonl,
 * computeTrendDirection, readReviewQueueState) are included here as
 * unexported copies; they will be deduplicated in a later slice when
 * their own sub-modules land.
 */

import {
  readFileSync, writeFileSync, mkdirSync, existsSync,
  appendFileSync, readdirSync, statSync, rmSync,
} from "node:fs";
import { resolve, dirname } from "node:path";
import { isApiOnlyModel } from "./worker-spawn.mjs";
import { recall as brainRecall, loadReviewerConfig, invokeReviewer } from "../brain.mjs";

// ─── Private helpers ──────────────────────────────────────────────────
// These mirror the public implementations in orchestrator.mjs and will be
// removed when the corresponding sub-modules are extracted (Phase-53 S6+).

export function readForgeJson(filePath, defaultValue = null, cwd = process.cwd()) {
  const fullPath = resolve(cwd, ".forge", filePath);
  try {
    if (existsSync(fullPath)) {
      return JSON.parse(readFileSync(fullPath, "utf-8"));
    }
  } catch { /* corrupt/missing → return default */ }
  return defaultValue;
}

export function readForgeJsonl(filePath, defaultValue = [], cwd = process.cwd()) {
  const fullPath = resolve(cwd, ".forge", filePath);
  try {
    if (existsSync(fullPath)) {
      return readFileSync(fullPath, "utf-8")
        .split("\n")
        .filter(line => line.trim())
        .map(line => JSON.parse(line));
    }
    // G2.1 shim: try the legacy `.json` variant for newly-renamed files
    if (filePath.endsWith(".jsonl")) {
      const legacy = resolve(cwd, ".forge", filePath.slice(0, -1)); // .jsonl → .json
      if (existsSync(legacy)) {
        return readFileSync(legacy, "utf-8")
          .split("\n")
          .filter(line => line.trim())
          .map(line => JSON.parse(line));
      }
    }
    return defaultValue;
  } catch { return defaultValue; }
}

export function appendForgeJsonl(filePath, record, cwd = process.cwd(), opts = {}) {
  const fullPath = resolve(cwd, ".forge", filePath);
  mkdirSync(dirname(fullPath), { recursive: true });
  const stamped = {
    _v: 1,
    ...(opts.correlationId ? { _correlationId: opts.correlationId } : {}),
    ...record,
  };
  appendFileSync(fullPath, JSON.stringify(stamped) + "\n");
}

/** Compute trend direction from an ordered array of numeric values. */
function computeTrendDirection(values) {
  if (!values || values.length < 2) return "insufficient-data";
  const mid = Math.floor(values.length / 2);
  const firstHalf = values.slice(0, mid);
  const secondHalf = values.slice(mid);
  const avg1 = firstHalf.reduce((a, b) => a + b, 0) / firstHalf.length;
  const avg2 = secondHalf.reduce((a, b) => a + b, 0) / secondHalf.length;
  const delta = avg2 - avg1;
  const threshold = Math.abs(avg1) * 0.05 || 1;
  if (delta > threshold) return "increasing";
  if (delta < -threshold) return "decreasing";
  return "stable";
}

function readReviewQueueState(targetPath) {
  const dir = resolve(targetPath, ".forge", "review-queue");
  if (!existsSync(dir)) return null;

  let entries = [];
  try {
    entries = readdirSync(dir).filter((f) => f.endsWith(".json"));
  } catch { return null; }

  const state = {
    total: 0, open: 0, resolved: 0, deferred: 0,
    lastActivityTs: null,
    bySeverity: { blocker: 0, high: 0, medium: 0, low: 0 },
    bySource: {},
  };

  for (const file of entries) {
    try {
      const raw = readFileSync(resolve(dir, file), "utf-8");
      const item = JSON.parse(raw);
      state.total++;
      if (item.status === "open") state.open++;
      else if (item.status === "resolved") state.resolved++;
      else if (item.status === "deferred") state.deferred++;

      if (item.severity && state.bySeverity[item.severity] !== undefined) {
        state.bySeverity[item.severity]++;
      }
      if (item.source) {
        state.bySource[item.source] = (state.bySource[item.source] || 0) + 1;
      }

      const ts = item.resolvedAt || item.createdAt;
      if (ts && (!state.lastActivityTs || ts > state.lastActivityTs)) {
        state.lastActivityTs = ts;
      }
    } catch {
      console.warn(`[review-queue] skipping corrupt file in state reader: ${file}`);
    }
  }

  return state;
}

// ─── Operational Data Infrastructure ──────────────────────────────────

/**
 * Ensure a subdirectory exists under .forge/.
 * @param {string} subpath - Relative path under .forge/ (e.g. "runs", "telemetry"). Use "" for .forge/ root.
 * @param {string} [cwd=process.cwd()] - Project root directory
 * @returns {string} Resolved absolute path of the created directory
 */
export function ensureForgeDir(subpath, cwd = process.cwd()) {
  const dir = resolve(cwd, ".forge", subpath);
  mkdirSync(dir, { recursive: true });
  return dir;
}

// ─── G2.3 — Run pruning ───────────────────────────────────────────────

/**
 * G2.3 (v2.36): prune `.forge/runs/<runId>/` directories. Two retention
 * dimensions are checked; a run is removed if it fails EITHER:
 *   - older than `maxAgeDays` days (default 30), OR
 *   - falls outside the newest `maxRuns` runs (default 50)
 *
 * Best-effort: filesystem errors on individual runs are logged via the
 * returned `errors[]` but never throw. The newest run is always kept.
 *
 * @param {string} [cwd=process.cwd()]
 * @param {{maxAgeDays?: number, maxRuns?: number, dryRun?: boolean}} [opts]
 * @returns {{kept: string[], pruned: string[], errors: Array<{runId: string, error: string}>, dryRun: boolean}}
 */
export function pruneForgeRuns(cwd = process.cwd(), opts = {}) {
  const { maxAgeDays = 30, maxRuns = 50, dryRun = false } = opts;
  const runsDir = resolve(cwd, ".forge", "runs");
  const result = { kept: [], pruned: [], errors: [], dryRun };
  if (!existsSync(runsDir)) return result;

  let entries;
  try {
    entries = readdirSync(runsDir, { withFileTypes: true })
      .filter((d) => d.isDirectory())
      .map((d) => d.name)
      .sort()         // ISO-like timestamps sort lexicographically
      .reverse();     // newest first
  } catch (err) {
    result.errors.push({ runId: "<runs-dir>", error: err.message });
    return result;
  }

  const cutoffMs = Date.now() - maxAgeDays * 24 * 60 * 60 * 1000;
  for (let i = 0; i < entries.length; i++) {
    const runId = entries[i];
    const runPath = resolve(runsDir, runId);
    let prune = false;
    if (i >= maxRuns) prune = true;
    if (!prune) {
      try {
        const stat = statSync(runPath);
        if (stat.mtimeMs < cutoffMs) prune = true;
      } catch (err) {
        result.errors.push({ runId, error: err.message });
        continue;
      }
    }
    // Always keep the newest run regardless of age
    if (i === 0) prune = false;

    if (prune) {
      if (!dryRun) {
        try { rmSync(runPath, { recursive: true, force: true }); }
        catch (err) { result.errors.push({ runId, error: err.message }); continue; }
      }
      result.pruned.push(runId);
    } else {
      result.kept.push(runId);
    }
  }
  return result;
}

// ─── Model Performance Tracking (Phase 3) ────────────────────────────

/**
 * Load the model performance log from .forge/model-performance.json.
 * Returns an array of per-slice performance entries, or [] if none exists.
 *
 * Migration (v2.62.1): on first load after the fix, drops any entries where
 * the model name matches an API-only provider (grok-*, gpt-*, etc.), writes
 * the cleaned file back, and logs a one-line notice. Idempotent — if no
 * entries are removed the file is not rewritten.
 */
export function loadModelPerformance(cwd) {
  // Meta-bug #97: callers may pass null cwd to opt out of history lookup.
  if (!cwd) return [];
  const perfPath = resolve(cwd, ".forge", "model-performance.json");
  if (!existsSync(perfPath)) return [];
  try {
    const data = JSON.parse(readFileSync(perfPath, "utf-8"));
    if (!Array.isArray(data)) return [];
    const clean = data.filter(r => !isApiOnlyModel(r.model));
    if (clean.length < data.length) {
      writeFileSync(perfPath, JSON.stringify(clean, null, 2));
      process.stderr.write(`[perf] scrubbed ${data.length - clean.length} API-worker entries from model-performance.json\n`);
    }
    return clean;
  } catch {
    return [];
  }
}

/**
 * Aggregate model performance records into per-model stats.
 * @param {Array} records - from loadModelPerformance()
 * @returns {object} model → { total_slices, passed, failed, success_rate, avg_cost_usd }
 */
export function aggregateModelStats(records) {
  const stats = {};
  for (const r of records) {
    const m = r.model || "unknown";
    if (!stats[m]) stats[m] = { total_slices: 0, passed: 0, failed: 0, total_cost_usd: 0 };
    stats[m].total_slices += 1;
    if (r.status === "passed") stats[m].passed += 1;
    else stats[m].failed += 1;
    stats[m].total_cost_usd += r.cost_usd || 0;
  }
  const result = {};
  for (const [model, s] of Object.entries(stats)) {
    result[model] = {
      total_slices: s.total_slices,
      passed: s.passed,
      failed: s.failed,
      success_rate: s.total_slices > 0 ? Math.round((s.passed / s.total_slices) * 1000) / 1000 : 0,
      avg_cost_usd: s.total_slices > 0 ? Math.round((s.total_cost_usd / s.total_slices) * 1_000_000) / 1_000_000 : 0,
    };
  }
  return result;
}

// ─── Cost History ──────────────────────────────────────────────────────

function _loadCostHistory(historyPath, modelStats) {
  if (!existsSync(historyPath)) {
    return { error: { runs: 0, message: "No cost history yet. Run `pforge run-plan` to start tracking.", forge_model_stats: modelStats } };
  }
  try {
    const history = JSON.parse(readFileSync(historyPath, "utf-8"));
    if (!Array.isArray(history)) {
      return { error: { runs: 0, message: "Invalid cost history format.", forge_model_stats: modelStats } };
    }
    if (history.length === 0) {
      return { error: { runs: 0, message: "Cost history is empty.", forge_model_stats: modelStats } };
    }
    return { history };
  } catch {
    return { error: { runs: 0, message: "Could not parse cost-history.json.", forge_model_stats: modelStats } };
  }
}

function _accumulateCostByModel(modelTotals, entry) {
  if (!entry.by_model) return;
  for (const [model, data] of Object.entries(entry.by_model)) {
    if (!modelTotals[model]) modelTotals[model] = { tokens_in: 0, tokens_out: 0, cost_usd: 0, runs: 0 };
    modelTotals[model].tokens_in += data.tokens_in || 0;
    modelTotals[model].tokens_out += data.tokens_out || 0;
    modelTotals[model].cost_usd += data.cost_usd || 0;
    modelTotals[model].runs += 1;
  }
}

function _accumulateCostMonthly(monthly, entry) {
  const month = (entry.date || "").substring(0, 7); // YYYY-MM
  if (!month) return;
  if (!monthly[month]) monthly[month] = { runs: 0, cost_usd: 0 };
  monthly[month].runs += 1;
  monthly[month].cost_usd += entry.total_cost_usd || 0;
}

function _roundCostUsd(map) {
  for (const m of Object.values(map)) {
    m.cost_usd = Math.round(m.cost_usd * 100) / 100;
  }
}

/**
 * Generate a cost report from .forge/cost-history.json.
 * Returns formatted summary with totals, per-model breakdown, and monthly aggregation.
 */
export function getCostReport(cwd) {
  const historyPath = resolve(cwd, ".forge", "cost-history.json");
  const modelStats = aggregateModelStats(loadModelPerformance(cwd));
  const loaded = _loadCostHistory(historyPath, modelStats);
  if (loaded.error) return loaded.error;
  const history = loaded.history;

  // Aggregate totals
  let totalCost = 0;
  let totalTokensIn = 0;
  let totalTokensOut = 0;
  const modelTotals = {};
  const monthly = {};

  for (const entry of history) {
    totalCost += entry.total_cost_usd || 0;
    totalTokensIn += entry.total_tokens_in || 0;
    totalTokensOut += entry.total_tokens_out || 0;
    _accumulateCostByModel(modelTotals, entry);
    _accumulateCostMonthly(monthly, entry);
  }

  _roundCostUsd(modelTotals);
  _roundCostUsd(monthly);

  return {
    runs: history.length,
    total_cost_usd: Math.round(totalCost * 100) / 100,
    total_tokens_in: totalTokensIn,
    total_tokens_out: totalTokensOut,
    by_model: modelTotals,
    monthly,
    latest: history[history.length - 1],
    forge_model_stats: modelStats,
  };
}

// ─── Health Trend Analysis ────────────────────────────────────────────

/**
 * Compute health trend from .forge/health-snapshots.jsonl.
 * Aggregates cost, drift, incident, and model performance data points
 * over the requested time window.
 *
 * @param {string} [cwd=process.cwd()] - Project root directory
 * @param {number} [days=30] - Number of days of history to include
 * @param {string[]|null} [metrics=null] - Optional metric filter (e.g. ["drift","cost","incidents","models"])
 * @returns {object} Health trend report
 */
function _trendDrift(cutoff, cwd) {
  const driftHistory = readForgeJsonl("drift-history.jsonl", [], cwd); // G2.1: was .json
  const filtered = driftHistory.filter(r => r.timestamp >= cutoff);
  const scores = filtered.map(r => r.score).filter(s => typeof s === "number");
  return {
    drift: {
      snapshots: filtered.length,
      latest: scores.length ? scores[scores.length - 1] : null,
      avg: scores.length ? Math.round((scores.reduce((a, b) => a + b, 0) / scores.length) * 10) / 10 : null,
      min: scores.length ? Math.min(...scores) : null,
      max: scores.length ? Math.max(...scores) : null,
      trend: computeTrendDirection(scores),
    },
    points: filtered.length,
  };
}

function _trendCost(cutoff, cwd) {
  const costHistory = readForgeJson("cost-history.json", [], cwd);
  const filtered = Array.isArray(costHistory) ? costHistory.filter(r => (r.date || "") >= cutoff) : [];
  const costs = filtered.map(r => r.total_cost_usd || 0);
  return {
    cost: {
      runs: filtered.length,
      totalUsd: costs.length ? Math.round(costs.reduce((a, b) => a + b, 0) * 100) / 100 : 0,
      avgPerRun: costs.length ? Math.round((costs.reduce((a, b) => a + b, 0) / costs.length) * 100) / 100 : 0,
      trend: computeTrendDirection(costs),
    },
    points: filtered.length,
  };
}

function _trendIncidents(cutoff, cwd) {
  const incidents = readForgeJsonl("incidents.jsonl", [], cwd);
  const filtered = incidents.filter(r => (r.capturedAt || "") >= cutoff);
  const resolved = filtered.filter(r => r.resolvedAt);
  const mttrs = resolved.map(r => r.mttr).filter(m => typeof m === "number" && m > 0);
  const bySeverity = {};
  for (const inc of filtered) {
    const sev = inc.severity || "unknown";
    bySeverity[sev] = (bySeverity[sev] || 0) + 1;
  }
  return {
    incidents: {
      total: filtered.length,
      resolved: resolved.length,
      open: filtered.length - resolved.length,
      avgMttrMs: mttrs.length ? Math.round(mttrs.reduce((a, b) => a + b, 0) / mttrs.length) : null,
      bySeverity,
    },
    points: filtered.length,
  };
}

function _trendModels(cutoff, cwd) {
  const perfRecords = loadModelPerformance(cwd);
  const filtered = perfRecords.filter(r => (r.date || "") >= cutoff);
  const stats = {};
  for (const r of filtered) {
    const m = r.model || "unknown";
    if (!stats[m]) stats[m] = { slices: 0, passed: 0, failed: 0, totalCost: 0 };
    stats[m].slices += 1;
    if (r.status === "passed") stats[m].passed += 1;
    else stats[m].failed += 1;
    stats[m].totalCost += r.cost_usd || 0;
  }
  const models = {};
  for (const [model, s] of Object.entries(stats)) {
    models[model] = {
      slices: s.slices,
      successRate: s.slices > 0 ? Math.round((s.passed / s.slices) * 1000) / 1000 : 0,
      avgCostUsd: s.slices > 0 ? Math.round((s.totalCost / s.slices) * 1_000_000) / 1_000_000 : 0,
    };
  }
  return {
    models: { totalSlices: filtered.length, byModel: models },
    points: filtered.length,
  };
}

function _trendTests(cutoff, cwd) {
  const regHistory = readForgeJsonl("regression-history.jsonl", [], cwd); // G2.1: was .json
  const filtered = regHistory.filter(r => (r.timestamp || "") >= cutoff);
  const passRates = filtered.map(r => r.gatesChecked > 0 ? r.passed / r.gatesChecked : 1);
  return {
    tests: {
      runs: filtered.length,
      totalGates: filtered.reduce((sum, r) => sum + (r.gatesChecked || 0), 0),
      totalPassed: filtered.reduce((sum, r) => sum + (r.passed || 0), 0),
      totalFailed: filtered.reduce((sum, r) => sum + (r.failed || 0), 0),
      passRate: passRates.length ? Math.round((passRates.reduce((a, b) => a + b, 0) / passRates.length) * 1000) / 1000 : null,
      lastFailure: filtered.filter(r => r.failed > 0).slice(-1)[0]?.timestamp || null,
      trend: computeTrendDirection(passRates.map(r => r * 100)),
    },
    points: filtered.length,
  };
}

function _computeHealthScore(result) {
  const scores = [];
  if (result.drift?.avg != null) scores.push(result.drift.avg);
  if (result.incidents) {
    const incidentPenalty = Math.min(result.incidents.total * 5, 50);
    scores.push(Math.max(0, 100 - incidentPenalty));
  }
  if (result.models?.totalSlices > 0) {
    const allPassRate = Object.values(result.models.byModel).reduce((sum, m) => sum + m.successRate, 0);
    const avgRate = allPassRate / Object.keys(result.models.byModel).length;
    scores.push(Math.round(avgRate * 100));
  }
  if (result.tests?.passRate != null) {
    scores.push(Math.round(result.tests.passRate * 100));
  }
  return scores.length ? Math.round(scores.reduce((a, b) => a + b, 0) / scores.length) : null;
}

function _buildHealthDNA(result, days) {
  const modelSuccessRate = result.models?.totalSlices > 0
    ? Math.round(Object.values(result.models.byModel).reduce((s, m) => s + m.successRate, 0) / Object.keys(result.models.byModel).length * 1000) / 1000
    : null;
  return {
    driftAvg: result.drift?.avg ?? null,
    incidentRate: result.incidents ? Math.round((result.incidents.total / Math.max(days, 1)) * 100) / 100 : null,
    testPassRate: result.tests?.passRate ?? null,
    modelSuccessRate,
    costPerSlice: result.cost?.avgPerRun ?? null,
    timestamp: new Date().toISOString(),
  };
}

export function getHealthTrend(cwd = process.cwd(), days = 30, metrics = null) {
  const cutoff = new Date(Date.now() - days * 24 * 60 * 60 * 1000).toISOString();
  const allMetrics = ["drift", "cost", "incidents", "models", "tests"];
  const active = metrics && metrics.length ? metrics.filter(m => allMetrics.includes(m)) : allMetrics;

  const result = { days, metricsIncluded: active, generatedAt: new Date().toISOString(), dataPoints: 0 };

  const trendHandlers = {
    drift: _trendDrift,
    cost: _trendCost,
    incidents: _trendIncidents,
    models: _trendModels,
    tests: _trendTests,
  };
  for (const name of allMetrics) {
    if (!active.includes(name)) continue;
    const out = trendHandlers[name](cutoff, cwd);
    Object.assign(result, out);
    result.dataPoints += out.points;
    delete result.points;
  }

  result.healthScore = _computeHealthScore(result);
  result.trend = result.drift?.trend || (result.dataPoints === 0 ? "no-data" : "stable");

  // Project Health DNA — composite fingerprint for decay detection
  result.healthDNA = _buildHealthDNA(result, days);

  // Persist health DNA snapshot for cross-session trend analysis
  try {
    if (result.healthDNA.driftAvg != null || result.healthDNA.testPassRate != null) {
      appendForgeJsonl("health-dna.jsonl", { ...result.healthDNA, healthScore: result.healthScore }, cwd); // G2.1: was .json
    }
  } catch { /* best-effort */ }

  return result;
}

// ─── Phase FORGE-SHOP-06 Slice 06.2 — Gate Check Configuration ──────

const GATE_CHECK_DEFAULTS = {
  enabled: false,
  driftThreshold: 0.6,
  timeoutMs: 5000,
};

/**
 * Load gate-check configuration from .forge.json → runtime.gateCheck.
 * Returns GATE_CHECK_DEFAULTS (enabled: false) if absent or malformed.
 * @param {string} cwd - Project root directory
 * @returns {{ enabled: boolean, driftThreshold: number, timeoutMs: number }}
 */
export function loadGateCheckConfig(cwd) {
  let config = { ...GATE_CHECK_DEFAULTS };
  const configPath = resolve(cwd, ".forge.json");
  if (existsSync(configPath)) {
    try {
      const raw = JSON.parse(readFileSync(configPath, "utf-8"));
      if (raw?.runtime?.gateCheck) {
        config = { ...config, ...raw.runtime.gateCheck };
      }
    } catch {
      /* malformed config — use defaults */
    }
  }
  return config;
}

// ─── Phase FORGE-SHOP-06 Slice 06.2 — Gate Check Responder ──────────

/**
 * Register the `brain.gate-check` hub responder.
 * Pure-read: queries brain facade for open blockers, critical incidents, and drift.
 * Returns { proceed, reason, openBlockingReviews, driftScore, openIncidents }.
 *
 * @param {object} hub - Hub instance with onAsk
 * @param {string} cwd - Project root
 * @param {object} [deps] - DI overrides for recall, readReviewQueueState, readForgeJsonl
 */
export function registerGateCheckResponder(hub, cwd, deps = {}) {
  const _recall = deps.recall || brainRecall;
  const _readRQS = deps.readReviewQueueState || readReviewQueueState;
  const _readJsonl = deps.readForgeJsonl || readForgeJsonl;
  const config = deps.config || loadGateCheckConfig(cwd);
  // Phase-25 Slice 7: opt-in reviewer (MUST #7 + #8). Advisory-only in v2.57
  // per D6 (blockOnCritical defaults false). When `deps.quorumInvoke` is
  // absent the reviewer simply reports skipped.
  const reviewerConfig = deps.reviewerConfig || loadReviewerConfig(cwd);
  const reviewerDeps = { quorumInvoke: deps.quorumInvoke };

async function _gateCheckBlockingReviews(_recall, cwd, _readRQS) {
  try {
    const rqState = await _recall("project.review.counts", {}, { cwd, readReviewQueueState: _readRQS });
    const count = rqState?.bySeverity?.blocker || 0;
    return { count, reason: count > 0 ? `${count} blocker-severity review(s) open` : null };
  } catch {
    return { count: 0, reason: null };
  }
}

async function _gateCheckCriticalIncidents(_recall, cwd, _readJsonl) {
  try {
    const incidents = await _recall("project.liveguard.incidents", {}, { cwd, readForgeJsonl: _readJsonl });
    const count = Array.isArray(incidents)
      ? incidents.filter(i => i.status === "open" && i.severity === "critical").length
      : 0;
    return { count, reason: count > 0 ? `${count} critical incident(s) open` : null };
  } catch {
    return { count: 0, reason: null };
  }
}

async function _gateCheckDrift(_recall, cwd, _readJsonl, config) {
  try {
    const driftHistory = await _recall("project.liveguard.drift", {}, { cwd, readForgeJsonl: _readJsonl });
    if (!Array.isArray(driftHistory) || driftHistory.length === 0) return { score: null, reason: null };
    const latest = driftHistory[driftHistory.length - 1];
    const oneHourAgo = Date.now() - 3_600_000;
    const latestTs = new Date(latest.ts || latest.timestamp || 0).getTime();
    if (latestTs < oneHourAgo || typeof latest.driftScore !== "number") return { score: null, reason: null };
    const score = latest.driftScore;
    const reason = score < config.driftThreshold
      ? `drift score ${score} below threshold ${config.driftThreshold}`
      : null;
    return { score, reason };
  } catch {
    return { score: null, reason: null };
  }
}

async function _gateCheckReviewer(payload, reviewerConfig, reviewerDeps, cwd) {
  if (!reviewerConfig.enabled) return { verdict: null, reason: null };
  try {
    const verdict = await invokeReviewer({
      sliceNumber: payload?.sliceNumber,
      sliceTitle: payload?.sliceTitle,
      diffSummary: payload?.diffSummary,
      config: reviewerConfig,
      cwd,
    }, reviewerDeps);
    const reason = verdict.ok && verdict.critical && reviewerConfig.blockOnCritical
      ? `reviewer flagged critical: ${verdict.summary || "(no summary)"}`
      : null;
    return { verdict, reason };
  } catch {
    return { verdict: null, reason: null };
  }
}

  hub.onAsk("brain.gate-check", async (payload) => {
    const reasons = [];

    const blocking = await _gateCheckBlockingReviews(_recall, cwd, _readRQS);
    if (blocking.reason) reasons.push(blocking.reason);

    const incidents = await _gateCheckCriticalIncidents(_recall, cwd, _readJsonl);
    if (incidents.reason) reasons.push(incidents.reason);

    const drift = await _gateCheckDrift(_recall, cwd, _readJsonl, config);
    if (drift.reason) reasons.push(drift.reason);

    const reviewerOut = await _gateCheckReviewer(payload, reviewerConfig, reviewerDeps, cwd);
    if (reviewerOut.reason) reasons.push(reviewerOut.reason);

    const proceed = reasons.length === 0;
    return {
      proceed,
      reason: proceed ? "all checks passed" : reasons.join("; "),
      openBlockingReviews: blocking.count,
      driftScore: drift.score,
      openIncidents: incidents.count,
      reviewer: reviewerOut.verdict,
    };
  });
}

export function recordModelPerformance(cwd, entry) {
  const perfPath = resolve(cwd, ".forge", "model-performance.json");
  const records = loadModelPerformance(cwd);
  records.push(entry);
  mkdirSync(resolve(cwd, ".forge"), { recursive: true });
  writeFileSync(perfPath, JSON.stringify(records, null, 2));
}

// Phase-53 S5: aggregateModelStats, ensureForgeDir → orchestrator/forge-io.mjs

/**
 * Read and parse a JSON file from .forge/.
 * @param {string} filePath - Path relative to .forge/ (e.g. "cost-history.json")
 * @param {*} [defaultValue=null] - Returned when file is missing or contains invalid JSON
 * @param {string} [cwd=process.cwd()] - Project root directory
 * @returns {*} Parsed JSON or defaultValue
 */

export function auditOrphanForgeFiles(cwd = process.cwd()) {
  // Patterns of recognised artifacts (substring or RegExp)
  const WHITELIST = [
    // Top-level state
    "server-ports.json", "hub-events.jsonl", "watch-history.jsonl",
    // L2 LiveGuard / dual-write
    "drift-history.jsonl", "drift-history.json",
    "regression-history.jsonl", "regression-history.json",
    "health-dna.jsonl", "health-dna.json",
    "quorum-history.jsonl", "quorum-history.json",
    "incidents.jsonl", "deploy-journal.jsonl",
    "liveguard-events.jsonl", "liveguard-memories.jsonl",
    "openbrain-queue.jsonl", "openbrain-dlq.jsonl", "openbrain-stats.jsonl",
    "env-diff-history.jsonl",
    // Caches
    "cost-history.json", "model-performance.json",
    "secret-scan-cache.json", "regression-gates.json",
    // Subdirectories handled separately
  ];
  const KNOWN_DIRS = new Set(["runs", "telemetry", "cache", "skills"]);

  const dir = resolve(cwd, ".forge");
  const known = [];
  const orphan = [];
  if (!existsSync(dir)) return { known, orphan, whitelist: WHITELIST };

  let entries;
  try { entries = readdirSync(dir, { withFileTypes: true }); }
  catch { return { known, orphan, whitelist: WHITELIST }; }

  for (const e of entries) {
    if (e.isDirectory()) {
      if (KNOWN_DIRS.has(e.name)) known.push(e.name + "/");
      else orphan.push(e.name + "/");
      continue;
    }
    if (WHITELIST.includes(e.name)) known.push(e.name);
    else orphan.push(e.name);
  }
  return { known, orphan, whitelist: WHITELIST };
}

// Phase-53 S5: getHealthTrend → orchestrator/forge-io.mjs

/**
 * Extract a target release version from a plan file.
 *
 * Scans (in order):
 *   1. Plan filename for `v<MAJOR>.<MINOR>[.<PATCH>][-...]` (e.g. `Phase-33.4-...-v2.67.4-PLAN.md`)
 *   2. Plan frontmatter `version:` field (if present)
 *   3. First `chore(release): vX.Y.Z` literal in the body
 *
 * Returns `null` when no version literal is found (non-release plan).
 *
 * @param {string} planPath - Path to plan markdown file
 * @returns {string|null} Bare semver string (no `v` prefix) or null
 */

const LIVEGUARD_TOOLS = new Set([
  "forge_drift_report", "forge_incident_capture", "forge_dep_watch",
  "forge_regression_guard", "forge_runbook", "forge_hotspot",
  "forge_health_trend", "forge_alert_triage", "forge_deploy_journal",
  "forge_secret_scan", "forge_env_diff", "forge_fix_proposal",
  "forge_quorum_analyze", "forge_liveguard_run",
  // Phase TEMPER-06 Slice 06.1 — Bug Registry tools
  "forge_bug_register", "forge_bug_list", "forge_bug_update_status",
  // Phase TEMPER-06 Slice 06.3 — Closed-loop fix validation
  "forge_bug_validate_fix",
  // Phase FORGE-SHOP-02 Slice 02.1 — Review Queue tools
  "forge_review_add", "forge_review_list", "forge_review_resolve",
  // Phase TEMPER-07 Slice 07.1 — Agent delegation
  "forge_delegate_to_agent",
  // Phase FORGE-SHOP-03 Slice 03.1 — Notification tools
  "forge_notify_send", "forge_notify_test",
]);

export function emitToolTelemetry({ toolName, inputs, result, durationMs, status, cwd = process.cwd() }) {
  const normalizedResult = typeof result === "string"
    ? result.slice(0, 2000)
    : JSON.stringify(result ?? "").slice(0, 2000);
  const record = {
    timestamp: new Date().toISOString(),
    tool: toolName,
    inputs: typeof inputs === "object" ? inputs : { raw: inputs },
    result: normalizedResult,
    durationMs,
    status,
  };
  try {
    appendForgeJsonl("telemetry/tool-calls.jsonl", record, cwd);
  } catch { /* telemetry is best-effort — never crash the tool */ }
  if (LIVEGUARD_TOOLS.has(toolName)) {
    try {
      appendForgeJsonl("liveguard-events.jsonl", { timestamp: record.timestamp, tool: toolName, status, durationMs }, cwd);
    } catch { /* best-effort */ }
  }
  return record;
}

/** Plan Forge — Phase-53 S9: gate helper sub-module */

import { readFileSync, existsSync, readdirSync, statSync } from "node:fs";
import { execSync } from "node:child_process";
import { resolve, basename, dirname, join, relative, extname, isAbsolute } from "node:path";
import { parsePlan } from "./plan-parser.mjs";
import { GATE_ALLOWED_PREFIXES, UNIX_TOOLS } from "./constants.mjs";
import { coalesceGateLines, looksLikeProse, runGate, resolveGateTimeoutMs } from "./schedulers.mjs";
import { recall as brainRecall, loadReviewerConfig, invokeReviewer } from "../brain.mjs";

export function extractPlanReleaseVersion(planPath) {
  if (!planPath || typeof planPath !== "string") return null;

  // 1. Filename: ...-v2.67.4-... or ...-v2.67-... Pre-release suffix is
  //    intentionally NOT captured from the filename (too easy to swallow
  //    "-PLAN.md" etc.) — use frontmatter or chore(release) line for that.
  const fname = planPath.split(/[\\/]/).pop() || "";
  const fnameMatch = fname.match(/[-_]v(\d+\.\d+(?:\.\d+)?)\b/);
  if (fnameMatch) return fnameMatch[1];

  // 2./3. Body scan (frontmatter `version:` or chore(release) line)
  let body = "";
  try {
    body = readFileSync(planPath, "utf-8");
  } catch {
    return null;
  }

  const fmMatch = body.match(/(?:^|\n)version:\s*['"]?v?(\d+\.\d+(?:\.\d+)?(?:[-+][0-9A-Za-z.-]+)?)['"]?/);
  if (fmMatch) return fmMatch[1];

  const choreMatch = body.match(/chore\(release\):\s*v(\d+\.\d+(?:\.\d+)?(?:[-+][0-9A-Za-z.-]+)?)/);
  if (choreMatch) return choreMatch[1];

  return null;
}

/**
 * Check whether a plan's target release version collides with a tag that
 * already exists on `origin`. Prevents the "retrograde release disaster"
 * (re-running an old plan against newer master, producing a `chore(release):`
 * commit + tag that overwrites a shipped release).
 *
 * Behaviour:
 *   - Returns `{ collision: false, version: null }` when no version is detected
 *     (non-release plan — bail out as no-op).
 *   - Returns `{ collision: false, version, originSha: null }` when the tag does
 *     not exist on origin.
 *   - Returns `{ collision: true, version, originSha }` when the tag already
 *     exists on origin.
 *
 * If `git ls-remote` itself fails (no network, no remote, etc.) returns
 * `{ collision: false, version, error }` — the orchestrator treats this as
 * advisory-only so offline runs aren't blocked.
 *
 * @param {string} planPath - Path to plan markdown file
 * @param {string} [cwd=process.cwd()] - Project root (where git is invoked)
 * @param {{ runner?: (cmd: string, opts: object) => string }} [opts] - Test seam
 * @returns {{ version: string|null, collision: boolean, originSha: string|null, error: string|null }}
 */
export function detectVersionCollision(planPath, cwd = process.cwd(), opts = {}) {
  const version = extractPlanReleaseVersion(planPath);
  if (!version) {
    return { version: null, collision: false, originSha: null, error: null };
  }

  const tagRef = `refs/tags/v${version}`;
  const runner = opts.runner || ((cmd, options) => execSync(cmd, options).toString());

  try {
    const out = runner(`git ls-remote --tags origin ${tagRef}`, {
      cwd,
      encoding: "utf-8",
      timeout: 10_000,
      stdio: ["ignore", "pipe", "pipe"],
    });
    const trimmed = (out || "").trim();
    if (!trimmed) {
      return { version, collision: false, originSha: null, error: null };
    }
    // Output format: "<sha>\trefs/tags/v2.67.4"
    const sha = trimmed.split(/\s+/)[0] || null;
    return { version, collision: true, originSha: sha, error: null };
  } catch (err) {
    return {
      version,
      collision: false,
      originSha: null,
      error: err && err.message ? err.message : String(err),
    };
  }
}

/**
 * Extract validation gates from a parsed plan file.
 * Delegates to parsePlan() — does not duplicate parsing logic.
 * @param {string} planFilePath - Absolute or project-relative path to a plan markdown file
 * @param {string} [cwd=process.cwd()] - Project root (used for path-traversal check)
 * @returns {Array<{sliceNumber: string, sliceTitle: string, gates: string[]}>}
 */
export function parseValidationGates(planFilePath, cwd = process.cwd()) {
  const plan = parsePlan(planFilePath, cwd);
  return plan.slices
    .filter(s => s.validationGate)
    .map(s => ({
      sliceNumber: s.number,
      sliceTitle: s.title,
      gates: s.validationGate
        .split("\n")
        .map(l => l.replace(/\s{2,}#\s.*$/, "").trim())
        .filter(l => l.length > 0),
    }));
}

/**
 * Lint all validation gate commands in a plan file.
 * Catches common issues that cause gate failures at runtime:
 *   - Commands not in the allowlist
 *   - Standalone comment lines (# ...) that get treated as commands
 *   - /dev/stdin usage (not cross-platform — fails on Windows)
 *   - curl localhost:* in non-final slices (requires running server)
 *   - `node *.test.mjs` for vitest test files (must use npx vitest)
 *
 * @param {string} planFilePath - Path to the plan Markdown file
 * @returns {{ warnings: Array, errors: Array, passed: boolean }}
 */
function _parseDisableDirectivesAndComments(rawLines, slice, warnings) {
  const disabledRules = new Set();
  for (const raw of rawLines) {
    const disableMatch = raw.match(/^#\s*pforge-lint-disable\s+(.+)$/i);
    if (disableMatch) {
      for (const rid of disableMatch[1].split(",").map(s => s.trim().toUpperCase()).filter(Boolean)) {
        disabledRules.add(rid);
      }
    } else if (raw.startsWith("#")) {
      const loc = `Slice ${slice.number} ("${slice.title}")`;
      warnings.push({
        slice: slice.number,
        command: raw,
        rule: "comment-line",
        severity: "warn",
        message: `${loc}: Standalone comment '${raw.slice(0, 60)}...' will be treated as a command. Remove or prefix with a real command.`,
      });
    }
  }
  return disabledRules;
}

function _resolveCmdToken(line) {
  const tokens = line.split(/\s+/);
  let cmdIdx = 0;
  while (cmdIdx < tokens.length && /^[A-Za-z_][A-Za-z0-9_]*=/.test(tokens[cmdIdx])) {
    cmdIdx++;
  }
  return (tokens[cmdIdx] || tokens[0]).toLowerCase();
}

function _pushWRule({ test, ruleId, rule, msg, line, slice, loc, strictMode, disabledRules, warnings, errors }) {
  if (!test || disabledRules.has(ruleId)) return;
  const _sev = strictMode ? "error" : "warn";
  (_sev === "error" ? errors : warnings).push({
    slice: slice.number,
    command: line,
    ruleId,
    rule,
    severity: _sev,
    message: `${loc}: ${msg}`,
  });
}

function _lintBasicRules({ line, slice, loc, cmdToken, lastSliceNumber, warnings, errors }) {
  if (line.includes("/dev/stdin")) {
    errors.push({
      slice: slice.number, command: line, rule: "unix-only-path", severity: "error",
      message: `${loc}: '/dev/stdin' is Unix-only — fails on Windows. Use readFileSync(0,'utf8') for cross-platform stdin.`,
    });
  }
  const isAllowed = GATE_ALLOWED_PREFIXES.some(p => cmdToken === p || cmdToken.endsWith(`/${p}`));
  if (!isAllowed) {
    errors.push({
      slice: slice.number, command: line, rule: "blocked-command", severity: "error",
      message: `${loc}: '${cmdToken}' is not in the gate allowlist. Add it to GATE_ALLOWED_PREFIXES or rewrite the command.`,
    });
  }
  if (/curl\s.*localhost[:\s]/.test(line) && slice.number !== lastSliceNumber) {
    warnings.push({
      slice: slice.number, command: line, rule: "runtime-gate", severity: "warn",
      message: `${loc}: curl to localhost requires a running server. Move runtime API checks to vitest integration tests.`,
    });
  }
  if (/^node\s+.*\.test\.(mjs|js|ts)/.test(line)) {
    warnings.push({
      slice: slice.number, command: line, rule: "vitest-direct-node", severity: "warn",
      message: `${loc}: 'node *.test.*' fails for vitest test files. Use 'npx vitest run <file>' instead.`,
    });
  }
  if (/\bpforge\s+analyze\b/.test(line)) {
    warnings.push({
      slice: slice.number, command: line, rule: "pforge-analyze-in-gate", severity: "warn",
      message: `${loc}: 'pforge analyze' in a gate exits 1 on noisy text-match heuristics (false-negatived all Phase-38.1–38.8 Slice 5 gates). Omit it — the orchestrator auto-runs analyze post-execution. Use 'pforge regression-guard <plan>' for a doc-integrity check instead.`,
    });
  }
  if (UNIX_TOOLS.includes(cmdToken) && !/^bash\s+-c/.test(line)) {
    warnings.push({
      slice: slice.number, command: line, rule: "windows-unavailable", severity: "warn",
      message: `${loc}: '${cmdToken}' is not available in cmd.exe on Windows. Wrap in 'bash -c' or use a 'node -e' equivalent.`,
    });
  }
  if (/\/tmp\/|\/dev\/null/.test(line)) {
    warnings.push({
      slice: slice.number, command: line, rule: "unix-only-path", severity: "warn",
      message: `${loc}: Unix-only path (/tmp/ or /dev/null) — fails on Windows. Use os.tmpdir() or NUL.`,
    });
  }
  if (/^pforge\s/.test(line)) {
    warnings.push({
      slice: slice.number, command: line, rule: "project-script", severity: "warn",
      message: `${loc}: 'pforge' is a project script, not on PATH during gate execution. Use 'pwsh ./pforge.ps1' or rewrite as 'node -e'.`,
    });
  }
  if (/^node\s+-e\s+".*\/\//.test(line) && !line.includes("http://") && !line.includes("https://")) {
    warnings.push({
      slice: slice.number, command: line, rule: "js-comment-in-eval", severity: "warn",
      message: `${loc}: node -e contains '//' which acts as a line comment on a single line, breaking the code. Remove JS comments from gate commands.`,
    });
  }
}

function _lintWRules({ line, slice, loc, cmdToken, strictMode, disabledRules, warnings, errors }) {
  _pushWRule({
    test: /^bash\s+-c\b/.test(line),
    ruleId: "W1", rule: "bash-prefix",
    msg: `'bash -c' prefix detected — fails on Windows (bash not in PATH). Rewrite as a direct node/npx command or use 'pwsh -Command' instead.`,
    line, slice, loc, strictMode, disabledRules, warnings, errors,
  });
  _pushWRule({
    test: !/^bash\s+-c\b/.test(line) && /^(node|npx|pwsh)\b.*\|/.test(line),
    ruleId: "W2", rule: "pipeline-node",
    msg: `Shell pipeline with '${cmdToken}' as left operand — cmd.exe may handle this differently. Consider wrapping in a 'node -e' script that uses child_process for portability.`,
    line, slice, loc, strictMode, disabledRules, warnings, errors,
  });
  _pushWRule({
    test: /^node\s+-e\s+.*\\\\[sdwSDWbBntr]/.test(line),
    ruleId: "W3", rule: "regex-escape",
    msg: `node -e contains '\\\\<metachar>' — the double-backslash is likely an over-escape; cmd.exe strips one level, so the regex may not match as intended. Use a single '\\' for regex escapes inside node -e strings.`,
    line, slice, loc, strictMode, disabledRules, warnings, errors,
  });
  _pushWRule({
    test: /\bcd\s+\S+.*&&/.test(line),
    ruleId: "W4", rule: "cd-chain",
    msg: `'cd dir && command' chain — on Windows cmd.exe the directory change does not persist for the next command. Use a --cwd flag or run commands from the target directory directly.`,
    line, slice, loc, strictMode, disabledRules, warnings, errors,
  });
  _pushWRule({
    test: /^node\s+-e\s+".*\\"/.test(line),
    ruleId: "W5", rule: "node-e-nested-double-quote",
    msg: `node -e contains nested '\\"' (escaped double-quote) — mangled by PowerShell before reaching Node, produces runtime SyntaxError. Use single quotes inside the inline JS, or invoke a helper script via 'node script.mjs'.`,
    line, slice, loc, strictMode, disabledRules, warnings, errors,
  });
}

function _lintCommandLine(line, slice, {
  lastSliceNumber,
  disabledRules,
  strictMode,
  warnings,
  errors,
  portabilityWarnings,
}) {
  const loc = `Slice ${slice.number} ("${slice.title}")`;
  if (looksLikeProse(line)) {
    warnings.push({
      slice: slice.number, command: line, rule: "prose-detected", severity: "warn",
      message: `${loc}: Line looks like prose, not a command: '${line.slice(0, 60)}...' — will be skipped at runtime.`,
    });
    return;
  }
  const cmdToken = _resolveCmdToken(line);
  _lintBasicRules({ line: line, slice: slice, loc: loc, cmdToken: cmdToken, ...{ lastSliceNumber, warnings, errors } });
  _lintWRules({ line: line, slice: slice, loc: loc, cmdToken: cmdToken, ...{ strictMode, disabledRules, warnings, errors } });

  const portResult = validateGatePortability(line);
  for (const pw of portResult.warnings) {
    portabilityWarnings.push({ ...pw, slice: slice.number, command: line });
  }
}

export function lintGateCommands(planFilePath, cwd = process.cwd()) {
  const plan = (planFilePath !== null && typeof planFilePath === "object")
    ? planFilePath
    : parsePlan(planFilePath, cwd);
  const warnings = [];
  const errors = [];
  const portabilityWarnings = [];
  // Strict mode: PFORGE_GATE_LINT_STRICT=1 promotes all W-rule warnings to errors.
  const strictMode = process.env.PFORGE_GATE_LINT_STRICT === "1";
  const lastSliceNumber = plan.slices.length > 0
    ? plan.slices[plan.slices.length - 1].number
    : null;

  for (const slice of plan.slices) {
    if (!slice.validationGate) continue;
    const rawLines = slice.validationGate.split("\n").map(l => l.trim()).filter(l => l.length > 0);
    const disabledRules = _parseDisableDirectivesAndComments(rawLines, slice, warnings);
    const commands = coalesceGateLines(slice.validationGate);
    for (const line of commands) {
      _lintCommandLine(line, slice, {
        lastSliceNumber,
        disabledRules,
        strictMode,
        warnings,
        errors,
        portabilityWarnings,
      });
    }
  }

  const allFindings = [...errors, ...warnings, ...portabilityWarnings];
  const result = {
    warnings,
    errors,
    portabilityWarnings,
    passed: errors.length === 0,
    summary: `${errors.length} error(s), ${warnings.length} warning(s), ${portabilityWarnings.length} portability warning(s) across ${plan.slices.length} slices`,
    find: (predicate) => allFindings.find(predicate),
    filter: (predicate) => allFindings.filter(predicate),
  };
  return result;
}

/**
 * Check a single gate command for cross-platform portability issues.
 * Returns non-blocking warnings for shell constructs that may behave
 * differently (or fail) across bash, zsh, cmd.exe, and PowerShell.
 * @param {string} command - A single gate command string
 * @returns {{ warnings: Array<{pattern: string, message: string, suggestion: string}> }}
 */
export function validateGatePortability(command) {
  if (!command || typeof command !== "string" || !command.trim()) {
    return { warnings: [] };
  }
  const warnings = [];

  // 1. Pipe into brace-group with read — behavior differs across shells
  if (/\|\s*\{[^}]*\bread\b/.test(command)) {
    warnings.push({
      pattern: "pipe-to-brace-read",
      message: "Pipe to brace-group with 'read' — variable may be lost in a subshell on some shells.",
      suggestion: "Use process substitution or a temp file instead of piping into a brace-group.",
    });
  }

  // 2. Nested double-quotes inside bash -c — escaping is fragile across platforms
  if (/bash\s+-c\s+".*\\"/.test(command) || /bash\s+-c\s+".*\\.+"/.test(command)) {
    warnings.push({
      pattern: "nested-double-quotes",
      message: "Nested double-quotes inside bash -c — escaping is fragile across platforms.",
      suggestion: "Use single-quotes for the outer bash -c argument, or use a script file.",
    });
  }

  // 3. Command substitution containing a pipe — complex nesting, error-prone
  if (/\$\(.*\|.*\)/.test(command)) {
    warnings.push({
      pattern: "cmd-substitution-pipe",
      message: "Command substitution containing a pipe — complex nesting is error-prone cross-platform.",
      suggestion: "Break into separate commands or use a temporary variable.",
    });
  }

  // 4. `bash -c "..."` chained with `&&` to another command — known broken on
  // Windows when the second command is `node -e "..."` containing `(` from
  // JSON.parse, regex literals, etc. The Windows cmd→bash shim mangles outer
  // quoting and inner parens (Phase 51 S0 hit this exact pattern).
  // The fix proven by Phase 41 and Phase 51 is to split each command onto
  // its own line so runGate() dispatches them separately via the inline-node
  // fast path (no shell involved).
  if (/^\s*bash\s+-c\s+["'].*["']\s*&&\s+/.test(command)) {
    warnings.push({
      pattern: "bash-c-chained-with-and",
      message: "`bash -c \"...\" && <cmd>` chains are mangled by the Windows cmd\u2192bash quoting shim when <cmd> contains nested quotes or parens (e.g. `node -e \"JSON.parse(...)\"`). Phase 51 S0 hit this.",
      suggestion: "Split into one command per line. Each line is dispatched separately by runGate(); inline-`node -e` lines bypass the shell entirely. Pattern: `node -e \"process.chdir('pforge-mcp'); require('child_process').execSync('npx vitest run TESTS', {stdio:'inherit',shell:true});\"` on its own line.",
    });
  }

  // 5. `bash -c "cd X && ..."` — cwd-changing wrapper. Same root cause as #4:
  // the `&&` chain inside bash -c is fragile through the Windows shim and the
  // `node -e "process.chdir(X); execSync(...)"` form is strictly better
  // because it bypasses bash entirely.
  if (/^\s*bash\s+-c\s+["']\s*cd\s+\S+\s*&&\s+/.test(command)) {
    warnings.push({
      pattern: "bash-c-cd-prefix",
      message: "`bash -c \"cd X && ...\"` wraps a cwd change in bash, which is fragile through the Windows cmd\u2192bash shim and unnecessary.",
      suggestion: "Use the per-line node pattern: `node -e \"process.chdir('X'); require('child_process').execSync('<cmd>', {stdio:'inherit',shell:true});\"`. This runs through runGate()'s inline-node fast path (no shell), so quoting survives Windows verbatim.",
    });
  }

  return { warnings };
}

/**
 * Check whether a line would pass the gate allowlist (prefix-based) without the prose guard.
 * Used by regressionGuard to implement the precedence rule: allowlisted commands win over prose heuristic.
 * @param {string} cmd - The command line to check
 * @returns {boolean} true if the command matches an allowlist prefix
 */
function wouldPassAllowlist(cmd) {
  if (!cmd || typeof cmd !== "string") return false;
  const trimmed = cmd.trim();
  const tokens = trimmed.split(/\s+/);
  let cmdIdx = 0;
  while (cmdIdx < tokens.length && /^[A-Za-z_][A-Za-z0-9_]*=/.test(tokens[cmdIdx])) {
    cmdIdx++;
  }
  const cmdToken = (tokens[cmdIdx] || tokens[0] || "").toLowerCase();
  return GATE_ALLOWED_PREFIXES.some((p) => cmdToken === p || cmdToken.endsWith(`/${p}`));
}

/**
 * Check if a command string is permitted in validation gates.
 * Uses the same GATE_ALLOWED_PREFIXES allowlist as runGate() and lintGateCommands().
 * Skips leading env-var assignments (e.g., "NODE_ENV=test npm test").
 * Additionally blocks known-dangerous patterns (e.g., rm -rf /) regardless of prefix.
 * @param {string} cmd - The command line to check
 * @returns {boolean} true if the command is allowed, false if blocked
 */
export function isGateCommandAllowed(cmd) {
  if (!cmd || typeof cmd !== "string") return false;
  const trimmed = cmd.trim();

  // Block known-dangerous patterns first — allowlist cannot override these
  const BLOCKED_PATTERNS = [
    /\brm\s+(-[a-z]*r[a-z]*f[a-z]*|-[a-z]*f[a-z]*r[a-z]*)\s+[/~*]/i,  // rm -rf / or rm -fr ~
    /\brm\s+-[a-z]*\s+\/(\s|$)/,                                          // rm -* /
    /\bdd\s+.*of=\/dev\/(sda|hda|nvme)/i,                                 // dd to raw block device
    /\bmkfs\b/i,                                                           // format filesystem
    /\b:>\s*\/dev\/(sda|hda)/i,                                           // truncate block device
  ];
  if (BLOCKED_PATTERNS.some((p) => p.test(trimmed))) return false;

  const tokens = trimmed.split(/\s+/);
  let cmdIdx = 0;
  while (cmdIdx < tokens.length && /^[A-Za-z_][A-Za-z0-9_]*=/.test(tokens[cmdIdx])) {
    cmdIdx++;
  }
  const cmdToken = (tokens[cmdIdx] || tokens[0] || "").toLowerCase();
  if (GATE_ALLOWED_PREFIXES.some((p) => cmdToken === p || cmdToken.endsWith(`/${p}`))) {
    return true;
  }

  // Heuristic prose detection only applies after allowlist matching so
  // command-like lines such as `node -e ...` win over noisy prose heuristics.
  if (looksLikeProse(trimmed)) return false;
  return false;
}

/**
 * Run regression guard — extract validation gate commands from plan files,
 * check each against the allowlist, execute allowed commands, and report results.
 *
 * Stop condition: if parseValidationGates cannot reliably extract commands from a plan
 * (e.g., no bash-block gates found), falls back to `testCommand` fields from parsed slices.
 *
 * @param {string[]} files - Changed file paths to guard (informational — included in result)
 * @param {object} [options]
 * @param {string} [options.plan] - Path to a specific plan file (relative to cwd). If omitted, scans docs/plans/
 * @param {boolean} [options.failFast=false] - Stop on first gate failure
 * @param {string} [options.cwd=process.cwd()] - Project root
 * @returns {Promise<{files: string[], gatesChecked: number, passed: number, failed: number, blocked: number, skipped: number, success: boolean, results: object[]}>}
 */
function _resolvePlanPaths(plan, cwd) {
  if (plan) {
    const resolved = resolve(cwd, plan);
    return existsSync(resolved) ? [resolved] : [];
  }
  const plansDir = resolve(cwd, "docs", "plans");
  if (!existsSync(plansDir)) return [];
  return readdirSync(plansDir)
    .filter((f) => f.endsWith("-PLAN.md") || f.endsWith("-plan.md"))
    .map((f) => resolve(plansDir, f));
}

function _collectFallbackGates(parsed, planPath, gateItems) {
  for (const s of parsed.slices) {
    if (s.testCommand) {
      gateItems.push({ planFile: basename(planPath), sliceNumber: s.number, sliceTitle: s.title, cmd: s.testCommand, source: "testCommand" });
    } else if (s.buildCommand) {
      gateItems.push({ planFile: basename(planPath), sliceNumber: s.number, sliceTitle: s.title, cmd: s.buildCommand, source: "buildCommand" });
    } else if (s.validationGateDescription) {
      const backtickRe = /`([^`]+)`/g;
      let bm;
      while ((bm = backtickRe.exec(s.validationGateDescription)) !== null) {
        const candidate = bm[1].trim();
        if (/^(dotnet|npm|npx|node|bash|pwsh|powershell|python|go|cargo|make|mvn|gradle)\b/i.test(candidate)) {
          gateItems.push({ planFile: basename(planPath), sliceNumber: s.number, sliceTitle: s.title, cmd: candidate, source: "prose-gate" });
        }
      }
    }
  }
}

function _collectGateItemsFromPlans(planPaths, cwd) {
  const gateItems = [];
  for (const planPath of planPaths) {
    try {
      const parsed = parsePlan(planPath, cwd);
      const sliceGates = parsed.slices
        .filter(s => s.validationGate)
        .map(s => ({
          sliceNumber: s.number,
          sliceTitle: s.title,
          gates: s.validationGate
            .split("\n")
            .map(l => l.replace(/\s{2,}#\s.*$/, "").trim())
            .filter(l => l.length > 0),
        }));

      let foundGates = false;
      for (const sg of sliceGates) {
        for (const cmd of sg.gates) {
          gateItems.push({ planFile: basename(planPath), sliceNumber: sg.sliceNumber, sliceTitle: sg.sliceTitle, cmd, source: "validation-gate" });
          foundGates = true;
        }
      }
      if (!foundGates) _collectFallbackGates(parsed, planPath, gateItems);
    } catch { /* unreadable plan — skip */ }
  }
  return gateItems;
}

function _prioritizeByHotspots(gateItems, cwd) {
  try {
    const hotspotCache = resolve(cwd, ".forge", "hotspot-cache.json");
    if (!existsSync(hotspotCache)) return;
    const cached = JSON.parse(readFileSync(hotspotCache, "utf-8"));
    const hotFiles = new Set((cached.hotspots || []).slice(0, 10).map(h => h.file));
    if (hotFiles.size === 0) return;
    gateItems.sort((a, b) => {
      const aHot = a.cmd && [...hotFiles].some(h => a.cmd.includes(h)) ? 1 : 0;
      const bHot = b.cmd && [...hotFiles].some(h => b.cmd.includes(h)) ? 1 : 0;
      return bHot - aHot;
    });
  } catch { /* best-effort prioritization */ }
}

function _classifyAndSkipGate(gate, cwd, results) {
  if (looksLikeProse(gate.cmd) && !wouldPassAllowlist(gate.cmd)) {
    results.push({ ...gate, status: "skipped", reason: "liveguard-prose-skipped" });
    try {
      appendForgeJsonl("liveguard-events.jsonl", {
        timestamp: new Date().toISOString(),
        type: "liveguard-prose-skipped",
        severity: "info",
        sliceNumber: gate.sliceNumber,
        command: gate.cmd,
      }, cwd);
    } catch { /* best-effort telemetry */ }
    return "skipped";
  }
  if (!isGateCommandAllowed(gate.cmd)) {
    results.push({ ...gate, status: "blocked", reason: `'${gate.cmd.split(/\s+/)[0]}' not in gate allowlist` });
    return "blocked";
  }
  return null;
}

function _runGate(gate, cwd, results) {
  try {
    const output = execSync(gate.cmd, { cwd, stdio: "pipe", timeout: resolveGateTimeoutMs(), encoding: "utf-8" });
    results.push({ ...gate, status: "passed", output: (output || "").trim().slice(0, 500) });
    return "passed";
  } catch (err) {
    const errOut = ((err.stderr || "") + (err.stdout || "")).trim().slice(0, 500) || err.message;
    results.push({ ...gate, status: "failed", output: errOut });
    return "failed";
  }
}

export async function regressionGuard(files, { plan, failFast = false, cwd = process.cwd() } = {}) {
  const planPaths = _resolvePlanPaths(plan, cwd);
  const gateItems = _collectGateItemsFromPlans(planPaths, cwd);
  _prioritizeByHotspots(gateItems, cwd);

  const results = [];
  let passed = 0, failed = 0, blocked = 0, skipped = 0;

  for (const gate of gateItems) {
    const classification = _classifyAndSkipGate(gate, cwd, results);
    if (classification === "skipped") { skipped++; continue; }
    if (classification === "blocked") { blocked++; continue; }

    const outcome = _runGate(gate, cwd, results);
    if (outcome === "passed") {
      passed++;
    } else {
      failed++;
      if (failFast) {
        const remaining = gateItems.slice(gateItems.indexOf(gate) + 1);
        for (const rem of remaining) {
          results.push({ ...rem, status: "skipped", reason: "fail-fast: previous gate failed" });
          skipped++;
        }
        break;
      }
    }
  }

  return {
    files: files || [],
    gatesChecked: gateItems.length,
    passed,
    failed,
    blocked,
    skipped,
    success: failed === 0,
    results,
  };
}

