      return new Promise((resolveP) => {
        let eventCount = 0;
        let timer = null;
        const url = `ws://127.0.0.1:${hubInfo.ws}?label=watcher-${Date.now()}`;
        try {
          ws = new WSCtor(url);
        } catch (err) {
          return resolveP({ ok: false, mode: "websocket", events: 0, durationMs: 0, error: err.message });
