function _registerSearchTimelineRoutes(app) {
  app.get("/api/search", async (req, res) => {
    try {
      const params = {
        query: req.query.query || "",
        tags: req.query.tags ? req.query.tags.split(",") : undefined,
        since: req.query.since || undefined,
