      const planFullPath = resolve(cwd, args.planPath);
      if (!existsSync(planFullPath)) {
        return { content: [{ type: "text", text: `${ERROR_CODES.PLAN_NOT_FOUND.code}: ${args.planPath}` }], isError: true };
