    if (line.startsWith("+") && !line.startsWith("+++")) {
      lineNumber++;
      const added = line.slice(1);
      const tokens = added.match(/["']([^"']{8,})["']|(?:=|:|=>)\s*["']?([^\s"',;]{8,})["']?/g) || [];
      for (const raw of tokens) {
        const cleaned = raw.replace(/^[=:>]\s*["']?|["']$/g, "").replace(/^["']/, "");
        if (cleaned.length < 8) continue;
