/**
 * Plan Forge — Copilot Spaces Sync (Phase GITHUB-E).
 *
 * Builds a payload from four local sources and uploads them as versioned files
 * into a designated GitHub Copilot Space.  Unchanged files (matching SHA-256)
 * are skipped to stay within API rate limits.
 *
 * Sources:
 *   1. Active plan  — `.forge/active-plan` pointer → `plan-forge/active-plan.md`
 *   2. Instructions — `.github/instructions/*.instructions.md` → `plan-forge/instructions/<name>.md`
 *   3. Tool catalog — `pforge-mcp/tools.json` (or capabilities snapshot)  → `plan-forge/tool-catalog.md`
 *   4. Project profile — `.github/instructions/project-profile.instructions.md` → `plan-forge/project-profile.md`
 *
 * All API calls are made through the user's `gh` CLI auth.
 * Tests mock `gh` via an injectable `ghCmd` option — no real GitHub API calls in tests.
 *
 * GitHub Copilot Spaces REST API used:
 *   GET  /user/copilot/spaces                         — list user spaces
 *   GET  /orgs/{org}/copilot/spaces                   — list org spaces
 *   GET  /user/copilot/spaces/{id}/files              — list existing files (for SHA comparison)
 *   PUT  /user/copilot/spaces/{id}/files/{path}       — create / update a file
 *
 * @module spaces-sync
 */

import { existsSync, readdirSync, readFileSync, statSync } from "node:fs";
import { join } from "node:path";
import { spawnSync } from "node:child_process";
import { createHash as _createHash } from "node:crypto";

// ─── Error classes ───────────────────────────────────────────────────────────

export class SpacesSyncError extends Error {
  constructor(message, code) {
    super(message);
    this.name = "SpacesSyncError";
    this.code = code ?? "SPACES_ERROR";
  }
}

export class SpacesAuthError extends SpacesSyncError {
  constructor(message) {
    super(message, "SPACES_AUTH_ERROR");
    this.name = "SpacesAuthError";
  }
}

export class SpacesNotFoundError extends SpacesSyncError {
  constructor(message) {
    super(message, "SPACES_NOT_FOUND");
    this.name = "SpacesNotFoundError";
  }
}

export class SpacesRateLimitError extends SpacesSyncError {
  constructor(message) {
    super(message, "SPACES_RATE_LIMIT");
    this.name = "SpacesRateLimitError";
  }
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

/** Compute SHA-256 hex digest of a UTF-8 string. */
export function sha256(content) {
  return _createHash("sha256").update(content, "utf8").digest("hex");
}

/**
 * Call `gh api <args>` synchronously.  Returns parsed JSON on success.
 * Throws the appropriate SpacesSyncError subclass on failure.
 *
 * @param {string[]} args  - Arguments after `gh api`
 * @param {string}   ghCmd - Path to the `gh` binary
 * @param {Object}   env   - Process environment override
 */
function ghSpawnConfig(args, ghCmd, env) {
  const isWin = process.platform === "win32";
  return {
    spawnBin: isWin ? "cmd" : ghCmd,
    spawnArg: isWin ? ["/d", "/s", "/c", ghCmd, "api", ...args] : ["api", ...args],
    options: {
      encoding: "utf-8",
      env: env ?? process.env,
      windowsHide: isWin,
    },
  };
}

function parseGhJson(text, fallback) {
  try {
    return JSON.parse(text || "null");
  } catch {
    return fallback;
  }
}

function throwGhApiError(result) {
  const stderr = result.stderr?.trim() ?? "";
  const stdout = result.stdout?.trim() ?? "";
  const body = parseGhJson(stdout || "{}", {});

  if (result.status === 401 || /401|Unauthorized|Bad credentials/i.test(stderr)) {
    throw new SpacesAuthError(
      "gh auth failed — run `gh auth login` or set GH_TOKEN. " +
      "Token needs `copilot_spaces:write` scope."
    );
  }
  if (result.status === 403 || /403|Forbidden/i.test(stderr)) {
    throw new SpacesAuthError(
      "Token lacks `copilot_spaces:write` scope. " +
      "Run `gh auth refresh -s copilot_spaces:write --hostname github.com`."
    );
  }
  if (result.status === 404 || body.message?.includes("Not Found")) {
    throw new SpacesNotFoundError(`Space not found: ${body.message ?? stderr}`);
  }
  if (result.status === 429 || /429|rate limit/i.test(stderr)) {
    throw new SpacesRateLimitError(
      `API rate limit hit. ${stderr.includes("retry-after") ? stderr : "Retry after 60s."}`
    );
  }
  throw new SpacesSyncError(`gh api failed (exit ${result.status}): ${stderr || stdout}`);
}

function ghApi(args, ghCmd, env) {
  const { spawnBin, spawnArg, options } = ghSpawnConfig(args, ghCmd, env);
  const result = spawnSync(spawnBin, spawnArg, options);

  if (result.error) {
    throw new SpacesSyncError(`Failed to spawn gh: ${result.error.message}`);
  }
  if (result.status !== 0) {
    throwGhApiError(result);
  }
  return parseGhJson(result.stdout, result.stdout);
}

// ─── Space discovery ─────────────────────────────────────────────────────────

/**
 * Resolve `owner/name` slug to a Copilot Space ID.
 *
 * Searches the authenticated user's spaces first, then the org's spaces if
 * `owner` looks like an org (not the authed user's own handle).
 *
 * @param {string} spaceRef  - `owner/name` slug
 * @param {Object} opts
 * @param {string} opts.ghCmd
 * @param {Object} [opts.env]
 * @returns {string} space ID
 */
export function findSpace(spaceRef, { ghCmd = "gh", env } = {}) {
  if (!spaceRef || !spaceRef.includes("/")) {
    throw new SpacesSyncError(
      `Invalid space reference "${spaceRef}" — expected "owner/name" format.`
    );
  }

  const [owner, name] = spaceRef.split("/");

  // Try user spaces first
  let spaces;
  try {
    spaces = ghApi(["/user/copilot/spaces"], ghCmd, env);
  } catch (err) {
    if (err instanceof SpacesNotFoundError) spaces = [];
    else throw err;
  }

  if (Array.isArray(spaces)) {
    const match = spaces.find(
      (s) =>
        s.name === name &&
        (s.owner?.login === owner || s.owner?.slug === owner || !s.owner)
    );
    if (match) return match.id ?? match.node_id ?? String(match.number ?? "");
  }

  // Fall back to org spaces
  try {
    const orgSpaces = ghApi(
      [`/orgs/${encodeURIComponent(owner)}/copilot/spaces`],
      ghCmd,
      env
    );
    if (Array.isArray(orgSpaces)) {
      const match = orgSpaces.find((s) => s.name === name);
      if (match) return match.id ?? match.node_id ?? String(match.number ?? "");
    }
  } catch (err) {
    if (!(err instanceof SpacesNotFoundError)) throw err;
  }

  throw new SpacesNotFoundError(
    `Copilot Space "${spaceRef}" not found. ` +
    `Create it at https://github.com/copilot/spaces and try again.`
  );
}

/**
 * Get all org Space names tagged `plan-forge-sync` for org-wide broadcast.
 *
 * @param {string} orgSlug
 * @param {Object} opts
 * @returns {string[]} Array of `owner/name` slugs
 */
export function listOrgSpaces(orgSlug, { ghCmd = "gh", env } = {}) {
  const spaces = ghApi(
    [`/orgs/${encodeURIComponent(orgSlug)}/copilot/spaces`],
    ghCmd,
    env
  );
  if (!Array.isArray(spaces)) return [];
  return spaces
    .filter((s) => (s.topics ?? []).includes("plan-forge-sync"))
    .map((s) => `${orgSlug}/${s.name}`);
}

// ─── Payload building ────────────────────────────────────────────────────────

/**
 * Read `.forge/active-plan` to find the active plan file path.
 * Falls back to scanning `docs/plans/` for the most recently modified plan.
 *
 * @param {string} projectRoot
 * @returns {{ spacePath: string, content: string }|null}
 */
export function getActivePlan(projectRoot) {
  const pointerFile = join(projectRoot, ".forge", "active-plan");

  if (existsSync(pointerFile)) {
    const relPath = readFileSync(pointerFile, "utf-8").trim();
    const absPath = join(projectRoot, relPath);
    if (existsSync(absPath)) {
      return {
        spacePath: "plan-forge/active-plan.md",
        localPath: absPath,
        content: readFileSync(absPath, "utf-8"),
      };
    }
  }

  // Fallback: most recently modified plan file
  const plansDir = join(projectRoot, "docs", "plans");
  if (!existsSync(plansDir)) return null;

  let entries;
  try {
    entries = readdirSync(plansDir)
      .filter((f) => f.endsWith("-PLAN.md"))
      .map((f) => {
        const abs = join(plansDir, f);
        try {
          const { mtimeMs } = statSync(abs);
          return { abs, mtimeMs };
        } catch {
          return { abs, mtimeMs: 0 };
        }
      })
      .sort((a, b) => b.mtimeMs - a.mtimeMs);
  } catch {
    return null;
  }

  if (!entries.length) return null;
  const { abs } = entries[0];
  return {
    spacePath: "plan-forge/active-plan.md",
    localPath: abs,
    content: readFileSync(abs, "utf-8"),
  };
}

/**
 * Collect `.github/instructions/*.instructions.md` files.
 *
 * @param {string} projectRoot
 * @param {{ includeProjectProfile?: boolean }} [opts]
 * @returns {Array<{ spacePath: string, localPath: string, content: string }>}
 */
export function getInstructionFiles(projectRoot, { includeProjectProfile = true } = {}) {
  const instrDir = join(projectRoot, ".github", "instructions");
  if (!existsSync(instrDir)) return [];

  let files;
  try {
    files = readdirSync(instrDir).filter((f) => f.endsWith(".instructions.md"));
  } catch {
    return [];
  }

  return files.map((f) => {
    const abs = join(instrDir, f);
    const name = f.replace(/\.instructions\.md$/, "");
    // project-profile gets its own top-level space path
    const spacePath =
      f === "project-profile.instructions.md" && includeProjectProfile
        ? "plan-forge/project-profile.md"
        : `plan-forge/instructions/${name}.md`;
    return {
      spacePath,
      localPath: abs,
      content: readFileSync(abs, "utf-8"),
    };
  });
}

/**
 * Build a Markdown tool-catalog summary from `tools.json`.
 *
 * @param {string} projectRoot  - Repo root (parent of pforge-mcp/)
 * @returns {{ spacePath: string, content: string }|null}
 */
export function getToolCatalog(projectRoot) {
  // Try pforge-mcp/tools.json relative to projectRoot (consumer project)
  // and also relative to this module's own package (framework dir).
  const candidates = [
    join(projectRoot, "pforge-mcp", "tools.json"),
    join(projectRoot, "tools.json"),
    new URL("./tools.json", import.meta.url).pathname,
  ];

  let toolsJson = null;
  for (const c of candidates) {
    if (existsSync(c)) {
      try {
        toolsJson = JSON.parse(readFileSync(c, "utf-8"));
        break;
      } catch { /* skip */ }
    }
  }

  if (!toolsJson) return null;

  const tools = Array.isArray(toolsJson) ? toolsJson : [];
  const lines = [
    "# Plan Forge Tool Catalog",
    "",
    `> Generated by \`pforge sync-spaces\`. ${tools.length} tools available.`,
    "",
    "| Tool | Description |",
    "|------|-------------|",
  ];

  for (const t of tools) {
    const desc = (t.description ?? "").split("\n")[0].slice(0, 100);
    lines.push(`| \`${t.name}\` | ${desc} |`);
  }

  return {
    spacePath: "plan-forge/tool-catalog.md",
    content: lines.join("\n") + "\n",
  };
}

/**
 * Build the full sync payload.
 *
 * @param {string} projectRoot
 * @param {{ noInstructions?: boolean }} [opts]
 * @returns {Array<{ spacePath: string, content: string, digest: string }>}
 */
export function buildPayload(projectRoot, { noInstructions = false } = {}) {
  const items = [];

  // 1. Active plan
  const plan = getActivePlan(projectRoot);
  if (plan) {
    items.push({ spacePath: plan.spacePath, content: plan.content });
  }

  // 2. Instruction files
  if (!noInstructions) {
    const instrs = getInstructionFiles(projectRoot);
    items.push(...instrs.map((i) => ({ spacePath: i.spacePath, content: i.content })));
  }

  // 3. Tool catalog
  const catalog = getToolCatalog(projectRoot);
  if (catalog) {
    items.push({ spacePath: catalog.spacePath, content: catalog.content });
  }

  // Attach digests
  return items.map((item) => ({
    ...item,
    digest: sha256(item.content),
  }));
}

// ─── Upload ──────────────────────────────────────────────────────────────────

/**
 * Fetch existing file SHAs from a space to enable skip-unchanged optimization.
 *
 * @param {string} spaceId
 * @param {Object} opts
 * @returns {Map<string, string>}  spacePath → sha256
 */
export function getExistingFileShas(spaceId, { ghCmd = "gh", env } = {}) {
  let files;
  try {
    files = ghApi([`/user/copilot/spaces/${encodeURIComponent(spaceId)}/files`], ghCmd, env);
  } catch {
    return new Map();
  }

  const map = new Map();
  if (!Array.isArray(files)) return map;
  for (const f of files) {
    if (f.path && f.sha) map.set(f.path, f.sha);
  }
  return map;
}

/**
 * Upload a single file to a Copilot Space.
 *
 * @param {string} spaceId
 * @param {string} spacePath
 * @param {string} content    - UTF-8 file content
 * @param {Object} opts
 */
export function uploadFile(spaceId, spacePath, content, { ghCmd = "gh", env } = {}) {
  const encoded = Buffer.from(content, "utf-8").toString("base64");
  ghApi(
    [
      "-X", "PUT",
      `/user/copilot/spaces/${encodeURIComponent(spaceId)}/files/${encodeURIComponent(spacePath)}`,
      "--raw-field", `content=${encoded}`,
      "--field", "encoding=base64",
    ],
    ghCmd,
    env
  );
}

// ─── Main entry point ────────────────────────────────────────────────────────

/**
 * @typedef {Object} SyncResult
 * @property {string[]} uploaded - Space paths that were uploaded
 * @property {string[]} skipped  - Space paths that were unchanged
 * @property {string[]} dryRun   - Space paths that WOULD be uploaded (dry-run only)
 * @property {boolean}  dryRunMode
 * @property {string}   spaceRef - Resolved `owner/name` target
 */

/**
 * Sync Plan Forge artifacts to a GitHub Copilot Space.
 *
 * @param {Object} opts
 * @param {string}   opts.projectRoot    - Repo root to scan for artifacts
 * @param {string}   [opts.spaceRef]     - `owner/name` override; else reads .forge.json
 * @param {string}   [opts.org]          - Org slug for broadcast mode (--org)
 * @param {boolean}  [opts.dryRun]       - Print without uploading
 * @param {boolean}  [opts.force]        - Re-upload even if SHA matches
 * @param {boolean}  [opts.noInstructions] - Skip instruction files
 * @param {string}   [opts.ghCmd]        - Path to `gh` binary (default: "gh")
 * @param {Object}   [opts.env]          - Process environment override
 * @returns {SyncResult|SyncResult[]}    Array if org broadcast; single result otherwise
 */
export function syncSpaces({
  projectRoot,
  spaceRef,
  org,
  dryRun = false,
  force = false,
  noInstructions = false,
  ghCmd = "gh",
  env,
} = {}) {
  if (!projectRoot) throw new SpacesSyncError("projectRoot is required");

  // Resolve target(s)
  const targets = resolveTargets({ projectRoot, spaceRef, org, ghCmd, env });

  if (org) {
    // Broadcast mode: return an array of per-space results
    return targets.map((ref) =>
      _syncOne({ projectRoot, spaceRef: ref, dryRun, force, noInstructions, ghCmd, env })
    );
  }

  return _syncOne({ projectRoot, spaceRef: targets[0], dryRun, force, noInstructions, ghCmd, env });
}

function resolveTargets({ projectRoot, spaceRef, org, ghCmd, env }) {
  if (org) {
    const refs = listOrgSpaces(org, { ghCmd, env });
    if (!refs.length) {
      throw new SpacesNotFoundError(
        `No Copilot Spaces in org "${org}" are tagged "plan-forge-sync". ` +
        "Add the topic to each Space you want to broadcast to."
      );
    }
    return refs;
  }

  // Single target: explicit flag > .forge.json > default "plan-forge"
  const ref = spaceRef ?? readForgeJsonSpacesTarget(projectRoot);
  if (!ref) {
    throw new SpacesSyncError(
      'No Space target specified. Use --space <owner/name>, set github.spacesTarget in .forge.json, ' +
      'or create a Space named "plan-forge" in your org.'
    );
  }
  return [ref];
}

function readForgeJsonSpacesTarget(projectRoot) {
  const configPath = join(projectRoot, ".forge.json");
  if (!existsSync(configPath)) return null;
  try {
    const config = JSON.parse(readFileSync(configPath, "utf-8"));
    return config?.github?.spacesTarget ?? null;
  } catch {
    return null;
  }
}

function _syncOne({ projectRoot, spaceRef, dryRun, force, noInstructions, ghCmd, env }) {
  const payload = buildPayload(projectRoot, { noInstructions });

  if (dryRun) {
    return {
      spaceRef,
      uploaded: [],
      skipped: [],
      dryRun: payload.map((p) => p.spacePath),
      dryRunMode: true,
    };
  }

  const spaceId = findSpace(spaceRef, { ghCmd, env });
  const existingShas = force ? new Map() : getExistingFileShas(spaceId, { ghCmd, env });

  const uploaded = [];
  const skipped = [];

  for (const item of payload) {
    const existingSha = existingShas.get(item.spacePath);
    if (!force && existingSha === item.digest) {
      skipped.push(item.spacePath);
      continue;
    }
    uploadFile(spaceId, item.spacePath, item.content, { ghCmd, env });
    uploaded.push(item.spacePath);
  }

  return { spaceRef, uploaded, skipped, dryRun: [], dryRunMode: false };
}

// ─── CLI entry point (when run directly via node spaces-sync.mjs) ────────────
// Consumed by pforge.ps1 / pforge.sh via: node spaces-sync.mjs <json-opts>

if (process.argv[1] && process.argv[1].endsWith("spaces-sync.mjs")) {
  const raw = process.argv[2];
  if (!raw) {
    console.error("Usage: node spaces-sync.mjs <json-opts>");
    process.exit(1);
  }

  let opts;
  try {
    opts = JSON.parse(raw);
  } catch (e) {
    console.error(`Invalid JSON opts: ${e.message}`);
    process.exit(1);
  }

  try {
    const result = syncSpaces(opts);
    if (opts.dryRun) {
      const r = Array.isArray(result) ? result : [result];
      r.forEach((res) => {
        console.log(`[dry-run] Would upload ${res.dryRun.length} file(s) to ${res.spaceRef}:`);
        res.dryRun.forEach((p) => console.log(`  - ${p}`));
      });
    } else {
      const results = Array.isArray(result) ? result : [result];
      results.forEach((res) => {
        console.log(`✓ ${res.spaceRef}: ${res.uploaded.length} uploaded, ${res.skipped.length} unchanged`);
        res.uploaded.forEach((p) => console.log(`  ↑ ${p}`));
        if (res.skipped.length) console.log(`  (skipped: ${res.skipped.join(", ")})`);
      });
    }
  } catch (err) {
    console.error(`ERROR: ${err.message}`);
    process.exit(
      err instanceof SpacesAuthError ? 1 :
      err instanceof SpacesNotFoundError ? 1 : 2
    );
  }
}

/**
 * Plan Forge — Copilot Instructions Sync (Roadmap D5 / v3.0.0).
 *
 * Generates `.github/copilot-instructions.md` from forge project artifacts
 * so GitHub Copilot receives project-specific custom instructions in every
 * conversation without requiring manual setup.
 *
 * Data sources (all local, no API calls):
 *   1. Project profile     — `.github/instructions/project-profile.instructions.md`
 *   2. Project principles  — `docs/plans/PROJECT-PRINCIPLES.md`
 *                            (fallback: `.github/instructions/project-principles.instructions.md`)
 *   3. Forge configuration — `.forge.json` (model prefs, parallelism, philosophy)
 *   4. Coding standards    — `.github/instructions/project-principles.instructions.md`
 *                            (guards section extracted)
 *
 * Completes the Copilot integration trilogy:
 *   v2.99.0 — forge_sync_memories   → .github/copilot-memory-hints.md
 *   v3.0.0  — forge_sync_instructions → .github/copilot-instructions.md
 *
 * @module sync-instructions
 */

import {
  existsSync, mkdirSync, readdirSync, readFileSync, writeFileSync,
} from "node:fs";
import { join, resolve, dirname } from "node:path";
import { createHash } from "node:crypto";

// ─── Error class ─────────────────────────────────────────────────────────────

export class SyncInstructionsError extends Error {
  constructor(message, code) {
    super(message);
    this.name = "SyncInstructionsError";
    this.code = code ?? "SYNC_INSTRUCTIONS_ERROR";
  }
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

/** SHA-256 hex digest of a UTF-8 string (for changed-content detection). */
export function sha256(content) {
  return createHash("sha256").update(content, "utf8").digest("hex");
}

/**
 * Strip YAML frontmatter (--- … ---) from a Markdown string.
 * Returns the body with leading whitespace removed.
 * @param {string} text
 * @returns {string}
 */
export function stripFrontmatter(text) {
  if (typeof text !== "string") return "";
  const stripped = text.replace(/^---[\r\n][\s\S]*?[\r\n]---[\r\n]?/, "");
  return stripped.trimStart();
}

/**
 * Safe JSON parse — returns `null` on any error.
 * @param {string} text
 * @returns {any|null}
 */
function safeJson(text) {
  try { return JSON.parse(text); } catch { return null; }
}

// ─── Data collection ─────────────────────────────────────────────────────────

/**
 * Collect project profile from `.github/instructions/project-profile.instructions.md`.
 *
 * @param {string} projectRoot
 * @returns {{ content: string, found: boolean }}
 */
export function collectProjectProfile(projectRoot) {
  const profilePath = join(projectRoot, ".github", "instructions", "project-profile.instructions.md");
  if (!existsSync(profilePath)) return { content: "", found: false };

  let raw = "";
  try { raw = readFileSync(profilePath, "utf-8"); } catch { return { content: "", found: false }; }

  const content = stripFrontmatter(raw).trim();
  return { content, found: content.length > 0 };
}

/**
 * Collect project principles.
 *
 * Priority order:
 *   1. `docs/plans/PROJECT-PRINCIPLES.md` (full principles doc)
 *   2. `.github/instructions/project-principles.instructions.md` (generated guards)
 *
 * @param {string} projectRoot
 * @returns {{ content: string, found: boolean, source: string }}
 */
export function collectProjectPrinciples(projectRoot) {
  const primaryPath = join(projectRoot, "docs", "plans", "PROJECT-PRINCIPLES.md");
  if (existsSync(primaryPath)) {
    let raw = "";
    try { raw = readFileSync(primaryPath, "utf-8"); } catch { /* fall through */ }
    const content = raw.trim();
    if (content) return { content, found: true, source: "docs/plans/PROJECT-PRINCIPLES.md" };
  }

  const fallbackPath = join(projectRoot, ".github", "instructions", "project-principles.instructions.md");
  if (existsSync(fallbackPath)) {
    let raw = "";
    try { raw = readFileSync(fallbackPath, "utf-8"); } catch { return { content: "", found: false, source: "" }; }
    const content = stripFrontmatter(raw).trim();
    if (content) return { content, found: true, source: ".github/instructions/project-principles.instructions.md" };
  }

  return { content: "", found: false, source: "" };
}

/**
 * Collect the forge configuration context from `.forge.json`.
 *
 * Extracts human-readable settings relevant to Copilot:
 *   - Model routing / default model
 *   - Quorum mode
 *   - Max parallelism
 *   - forgeMaster reasoning model
 *
 * @param {string} projectRoot
 * @returns {{ settings: Record<string,string>, found: boolean }}
 */
export function collectForgeConfig(projectRoot) {
  const forgePath = join(projectRoot, ".forge.json");
  if (!existsSync(forgePath)) return { settings: {}, found: false };

  let raw = "";
  try { raw = readFileSync(forgePath, "utf-8"); } catch { return { settings: {}, found: false }; }

  const parsed = safeJson(raw);
  if (!parsed || typeof parsed !== "object") return { settings: {}, found: false };

  const settings = {};

  const defaultModel = parsed.modelRouting?.default;
  if (defaultModel) settings["Default model routing"] = String(defaultModel);

  const quorumEnabled = parsed.quorum?.enabled;
  if (quorumEnabled != null) {
    settings["Quorum mode"] = quorumEnabled
      ? `enabled (threshold: ${parsed.quorum.threshold ?? "?"})`
      : "disabled";
  }

  const maxParallelism = parsed.maxParallelism;
  if (maxParallelism != null) settings["Max parallelism"] = String(maxParallelism);

  const maxRetries = parsed.maxRetries;
  if (maxRetries != null) settings["Max retries per slice"] = String(maxRetries);

  const reasoningModel = parsed.forgeMaster?.reasoningModel;
  if (reasoningModel) settings["Forge-Master reasoning model"] = String(reasoningModel);

  const philosophy = parsed.forgeMaster?.philosophy;
  if (typeof philosophy === "string" && philosophy.trim()) {
    settings["Project philosophy"] = philosophy.trim();
  }

  return { settings, found: Object.keys(settings).length > 0 };
}

/**
 * Collect extra instruction files from `.github/instructions/` that are
 * relevant for project context (excludes generic Plan Forge baseline files
 * that ship with the installer and would add noise).
 *
 * Excluded by default:
 *   - `architecture-principles.instructions.md`  (universal baseline — too generic)
 *   - `git-workflow.instructions.md`              (VCS tooling, not project-specific)
 *   - `release-checklist.instructions.md`         (maintainer-only)
 *   - `status-reporting.instructions.md`          (orchestration templates)
 *   - `context-fuel.instructions.md`              (AI meta-guidance)
 *   - `self-repair.instructions.md`               (AI meta-guidance)
 *   - `project-profile.instructions.md`           (handled by collectProjectProfile)
 *   - `project-principles.instructions.md`        (handled by collectProjectPrinciples)
 *   - `ai-plan-hardening-runbook.instructions.md` (plan execution meta)
 *
 * @param {string} projectRoot
 * @param {{ exclude?: string[] }} opts
 * @returns {Array<{ filename: string, title: string, content: string }>}
 */
export function collectInstructionFiles(projectRoot, { exclude = [] } = {}) {
  const DEFAULT_EXCLUDE = new Set([
    "architecture-principles.instructions.md",
    "git-workflow.instructions.md",
    "release-checklist.instructions.md",
    "status-reporting.instructions.md",
    "context-fuel.instructions.md",
    "self-repair.instructions.md",
    "project-profile.instructions.md",
    "project-principles.instructions.md",
    "ai-plan-hardening-runbook.instructions.md",
  ]);

  const extraExclude = new Set(exclude.map((f) => f.replace(/^.*[\\/]/, "")));

  const instrDir = join(projectRoot, ".github", "instructions");
  if (!existsSync(instrDir)) return [];

  let files;
  try { files = readdirSync(instrDir).filter((f) => f.endsWith(".instructions.md")); } catch { return []; }

  const results = [];
  for (const filename of files.sort()) {
    if (DEFAULT_EXCLUDE.has(filename) || extraExclude.has(filename)) continue;

    const abs = join(instrDir, filename);
    let raw = "";
    try { raw = readFileSync(abs, "utf-8"); } catch { continue; }

    const content = stripFrontmatter(raw).trim();
    if (!content) continue;

    // Extract first heading as title, fall back to filename
    const headingMatch = /^#+\s+(.+)$/m.exec(content);
    const title = headingMatch ? headingMatch[1].trim() : filename.replace(".instructions.md", "");

    results.push({ filename, title, content });
  }

  return results;
}

// ─── Markdown rendering ──────────────────────────────────────────────────────

/**
 * Render the copilot-instructions Markdown document.
 *
 * @param {object} data
 * @param {{ content: string, found: boolean }}                  data.profile
 * @param {{ content: string, found: boolean, source: string }}  data.principles
 * @param {{ settings: Record<string,string>, found: boolean }}  data.forgeConfig
 * @param {Array<{ filename: string, title: string, content: string }>} data.extraInstructions
 * @param {Date}   [data.now]
 * @param {boolean} [data.noPrinciples]
 * @param {boolean} [data.noProfile]
 * @param {boolean} [data.noExtras]
 * @returns {string}
 */
export function renderInstructions({
  profile,
  principles,
  forgeConfig,
  extraInstructions = [],
  now,
  noPrinciples = false,
  noProfile = false,
  noExtras = false,
}) {
  const ts = (now instanceof Date ? now : new Date()).toISOString().slice(0, 10);
  const lines = [
    "# Copilot Instructions",
    "",
    `> Generated by Plan Forge \`forge_sync_instructions\` on ${ts}.`,
    "> GitHub Copilot reads this file automatically for project-specific instructions.",
    "> Do **not** edit manually — regenerate with \`pforge sync-instructions\`.",
    "",
  ];

  let sectionsCount = 0;

  // ── Section 1: Project Profile ────────────────────────────────────────────
  if (!noProfile && profile.found) {
    lines.push("## Project Profile", "");
    lines.push(profile.content, "");
    sectionsCount++;
  }

  // ── Section 2: Project Principles ────────────────────────────────────────
  if (!noPrinciples && principles.found) {
    lines.push("## Project Principles", "");
    lines.push(principles.content, "");
    sectionsCount++;
  }

  // ── Section 3: Extra Instruction Files ───────────────────────────────────
  if (!noExtras && extraInstructions.length > 0) {
    for (const instr of extraInstructions) {
      lines.push(`## ${instr.title}`, "");
      lines.push(instr.content, "");
      sectionsCount++;
    }
  }

  // ── Section 4: Forge Configuration ───────────────────────────────────────
  if (forgeConfig.found) {
    lines.push("## Forge Configuration", "");
    for (const [key, value] of Object.entries(forgeConfig.settings)) {
      lines.push(`- **${key}**: ${value}`);
    }
    lines.push("");
    sectionsCount++;
  }

  // ── Empty state ───────────────────────────────────────────────────────────
  if (sectionsCount === 0) {
    lines.push(
      "## No project-specific instructions found",
      "",
      "Add a project profile (`pforge smith` then check `.github/instructions/project-profile.instructions.md`),",
      "project principles (`docs/plans/PROJECT-PRINCIPLES.md`), or forge config (`.forge.json`) to",
      "populate this file with project-specific guidance.",
      "",
    );
  }

  return { markdown: lines.join("\n"), sectionsCount };
}

// ─── Main entry point ────────────────────────────────────────────────────────

/**
 * @typedef {Object} SyncInstructionsResult
 * @property {boolean} ok
 * @property {string}  [outputPath]     - Absolute path written (undefined in dry-run)
 * @property {number}  sectionsCount    - Number of sections rendered
 * @property {{ profile: boolean, principles: boolean, forgeConfig: boolean, extraCount: number }} sections
 * @property {boolean} changed          - true when content differs from existing file
 * @property {boolean} dryRunMode
 * @property {string}  [dryRunContent]  - Rendered Markdown (dry-run only)
 * @property {string}  message
 */

/**
 * Sync forge project context to `.github/copilot-instructions.md`.
 *
 * @param {Object}  opts
 * @param {string}  opts.projectRoot     - Project root (required)
 * @param {boolean} [opts.dryRun]        - Print without writing
 * @param {boolean} [opts.force]         - Overwrite even if content is unchanged
 * @param {boolean} [opts.noPrinciples]  - Skip PROJECT-PRINCIPLES section
 * @param {boolean} [opts.noProfile]     - Skip project-profile section
 * @param {boolean} [opts.noExtras]      - Skip extra instruction files
 * @param {string}  [opts.output]        - Override output path
 * @param {Date}    [opts.now]           - Timestamp override for tests
 * @returns {SyncInstructionsResult}
 */
function collectInstructionSections(projectRoot, noExtras) {
  const profile = collectProjectProfile(projectRoot);
  const principles = collectProjectPrinciples(projectRoot);
  const forgeConfig = collectForgeConfig(projectRoot);
  const extraInstructions = noExtras ? [] : collectInstructionFiles(projectRoot);
  return { profile, principles, forgeConfig, extraInstructions };
}

function resolveInstructionsOutputPath(projectRoot, output) {
  return output
    ? resolve(projectRoot, output)
    : resolve(projectRoot, ".github", "copilot-instructions.md");
}

function shouldWriteInstructions(outputPath, content, force) {
  if (force || !existsSync(outputPath)) return true;
  try {
    return sha256(readFileSync(outputPath, "utf-8")) !== sha256(content);
  } catch {
    return true;
  }
}

function writeInstructionsFile(outputPath, content) {
  try {
    mkdirSync(dirname(outputPath), { recursive: true });
    writeFileSync(outputPath, content, "utf-8");
  } catch (err) {
    throw new SyncInstructionsError(`Failed to write ${outputPath}: ${err.message}`);
  }
}

export function syncInstructions({
  projectRoot,
  dryRun = false,
  force = false,
  noPrinciples = false,
  noProfile = false,
  noExtras = false,
  output,
  now,
} = {}) {
  if (!projectRoot) throw new SyncInstructionsError("projectRoot is required");

  const { profile, principles, forgeConfig, extraInstructions } = collectInstructionSections(projectRoot, noExtras);
  const { markdown: content, sectionsCount } = renderInstructions({
    profile,
    principles,
    forgeConfig,
    extraInstructions,
    now: now instanceof Date ? now : new Date(),
    noPrinciples,
    noProfile,
    noExtras,
  });

  const sections = {
    profile: !noProfile && profile.found,
    principles: !noPrinciples && principles.found,
    forgeConfig: forgeConfig.found,
    extraCount: noExtras ? 0 : extraInstructions.length,
  };

  if (dryRun) {
    return {
      ok: true,
      sectionsCount,
      sections,
      changed: true,
      dryRunMode: true,
      dryRunContent: content,
      message: `Dry run: would write ${sectionsCount} section(s).`,
    };
  }

  const outputPath = resolveInstructionsOutputPath(projectRoot, output);
  const changed = shouldWriteInstructions(outputPath, content, force);
  if (changed) writeInstructionsFile(outputPath, content);

  return {
    ok: true,
    outputPath,
    sectionsCount,
    sections,
    changed,
    dryRunMode: false,
    message: changed
      ? `Wrote ${sectionsCount} section(s) to ${outputPath}.`
      : `No changes — copilot-instructions.md is up to date (${sectionsCount} section(s)).`,
  };
}

// ─── CLI entry point (when run directly via node sync-instructions.mjs) ──────
// Consumed by pforge.ps1 / pforge.sh via: node sync-instructions.mjs <json-opts>

if (process.argv[1] && process.argv[1].endsWith("sync-instructions.mjs")) {
  const raw = process.argv[2];
  if (!raw) {
    console.error("Usage: node sync-instructions.mjs <json-opts>");
    process.exit(1);
  }

  let opts;
  try {
    opts = JSON.parse(raw);
  } catch (e) {
    console.error(`Invalid JSON opts: ${e.message}`);
    process.exit(1);
  }

  try {
    const result = syncInstructions(opts);
    if (result.dryRunMode) {
      console.log(`📋 Dry run — ${result.message}`);
      console.log("");
      console.log(result.dryRunContent);
    } else {
      console.log(`✓ ${result.message}`);
    }
  } catch (err) {
    console.error(`ERROR: ${err.message}`);
    process.exit(1);
  }
}

/**
 * Plan Forge — Copilot Memory Sync (Roadmap C3).
 *
 * Generates `.github/copilot-memory-hints.md` from forge decisions so
 * Copilot Memory can auto-discover project context without requiring
 * OpenBrain configuration.
 *
 * Data sources (all local, no API calls for soft-sync mode):
 *   1. Trajectory notes  — `.forge/trajectories/<plan>/<slice>.md`
 *   2. Auto-skills       — `.forge/skills-auto/<sha>.md`
 *   3. Brain L2 entries  — `.forge/brain/**\/*.json`
 *
 * Hard-sync (Copilot Memory write API) is not yet available upstream; this
 * module implements the soft-sync approach: write a well-structured Markdown
 * file that Copilot Memory auto-discovers as a knowledge source.
 *
 * @module sync-memories
 */

import {
  existsSync, mkdirSync, readdirSync, readFileSync, statSync, writeFileSync,
} from "node:fs";
import { join, resolve, dirname, basename } from "node:path";
import { createHash } from "node:crypto";

// ─── Error classes ───────────────────────────────────────────────────────────

export class SyncMemoriesError extends Error {
  constructor(message, code) {
    super(message);
    this.name = "SyncMemoriesError";
    this.code = code ?? "SYNC_MEMORIES_ERROR";
  }
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

/** SHA-256 hex digest of a UTF-8 string (for changed-content detection). */
export function sha256(content) {
  return createHash("sha256").update(content, "utf8").digest("hex");
}

/**
 * Safe JSON parse — returns `null` on any error.
 * @param {string} text
 * @returns {any|null}
 */
function safeJson(text) {
  try { return JSON.parse(text); } catch { return null; }
}

// ─── Data collection ─────────────────────────────────────────────────────────

/**
 * Collect all trajectory notes from `.forge/trajectories/`.
 *
 * @param {string} projectRoot
 * @param {{ since?: Date, limit?: number }} opts
 * @returns {Array<{ planBasename: string, sliceId: string, content: string, mtime: Date }>}
 */
export function collectTrajectories(projectRoot, { since, limit = 50 } = {}) {
  const trajDir = join(projectRoot, ".forge", "trajectories");
  if (!existsSync(trajDir)) return [];

  const results = [];

  let plans;
  try { plans = readdirSync(trajDir); } catch { return []; }

  for (const plan of plans) {
    const planDir = join(trajDir, plan);
    let planStat;
    try { planStat = statSync(planDir); } catch { continue; }
    if (!planStat.isDirectory()) continue;

    let files;
    try { files = readdirSync(planDir); } catch { continue; }

    for (const f of files) {
      if (!f.endsWith(".md")) continue;
      const abs = join(planDir, f);
      let fstat;
      try { fstat = statSync(abs); } catch { continue; }
      const mtime = new Date(fstat.mtimeMs);
      if (since && mtime < since) continue;

      let content = "";
      try { content = readFileSync(abs, "utf-8").trim(); } catch { continue; }
      if (!content) continue;

      // Extract slice ID from filename: "slice-<id>.md"
      const m = /^slice-(.+)\.md$/.exec(f);
      const sliceId = m ? m[1] : basename(f, ".md");

      results.push({ planBasename: plan, sliceId, content, mtime });
    }
  }

  // Sort newest-first
  results.sort((a, b) => b.mtime - a.mtime);
  return results.slice(0, limit);
}

/**
 * Collect auto-skill records from `.forge/skills-auto/`.
 *
 * @param {string} projectRoot
 * @param {{ since?: Date, limit?: number }} opts
 * @returns {Array<{ sha256Prefix: string, summary: string, commands: string[], domainKeywords: string[], createdAt: string, reuseCount: number }>}
 */
export function collectAutoSkills(projectRoot, { since, limit = 20 } = {}) {
  const skillsDir = join(projectRoot, ".forge", "skills-auto");
  if (!existsSync(skillsDir)) return [];

  let files;
  try { files = readdirSync(skillsDir).filter((f) => f.endsWith(".md")); } catch { return []; }

  const results = [];
  for (const f of files) {
    const abs = join(skillsDir, f);
    let text = "";
    try { text = readFileSync(abs, "utf-8"); } catch { continue; }

    const record = parseAutoSkillFrontmatter(text);
    if (!record) continue;

    if (since) {
      const createdDate = new Date(record.createdAt);
      if (isNaN(createdDate.getTime()) || createdDate < since) continue;
    }

    results.push(record);
  }

  // Sort by reuseCount DESC, then createdAt DESC
  results.sort((a, b) => {
    const diff = b.reuseCount - a.reuseCount;
    if (diff !== 0) return diff;
    return new Date(b.createdAt) - new Date(a.createdAt);
  });
  return results.slice(0, limit);
}

/**
 * Parse auto-skill frontmatter without importing memory.mjs (keeps this
 * module self-contained for tree-shakability and testability).
 *
 * @param {string} text
 * @returns {{ sha256Prefix, summary, commands, domainKeywords, createdAt, reuseCount }|null}
 */
function frontmatterField(fm, field) {
  return (new RegExp(`^${field}:\\s*(.+)$`, "m").exec(fm) || [])[1] || "";
}

function parseFrontmatterJson(value, fallback) {
  try {
    return JSON.parse(value);
  } catch {
    return fallback;
  }
}

function parseFrontmatterInlineStringArray(fm, field) {
  const match = new RegExp(`^\\s*${field}:\\s*\\[([^\\]]*)\\]$`, "m").exec(fm);
  if (!match || !match[1].trim()) return [];
  const parsed = parseFrontmatterJson(`[${match[1]}]`, []);
  return Array.isArray(parsed) ? parsed.filter((s) => typeof s === "string") : [];
}

function parseFrontmatterCommands(fm) {
  const commands = [];
  const sectionMatch = /\ncommands:\n([\s\S]*)$/.exec(fm);
  if (!sectionMatch) return commands;
  for (const raw of sectionMatch[1].split("\n")) {
    const match = /^\s*-\s*(.+)$/.exec(raw);
    if (!match) continue;
    const value = parseFrontmatterJson(match[1].trim(), match[1].trim());
    if (typeof value === "string" && value.length > 0) commands.push(value);
  }
  return commands;
}

export function parseAutoSkillFrontmatter(text) {
  if (typeof text !== "string") return null;
  const fmMatch = /^---\n([\s\S]*?)\n---/.exec(text);
  if (!fmMatch) return null;
  const fm = fmMatch[1];

  const sha256Prefix = frontmatterField(fm, "sha256Prefix");
  if (!sha256Prefix) return null;

  const summaryLine = frontmatterField(fm, "summary");
  const summary = parseFrontmatterJson(summaryLine, summaryLine);
  const createdAt = frontmatterField(fm, "createdAt");
  const reuseCount = Number(frontmatterField(fm, "reuseCount") || 0) || 0;

  return {
    sha256Prefix,
    summary,
    commands: parseFrontmatterCommands(fm),
    domainKeywords: parseFrontmatterInlineStringArray(fm, "domainKeywords"),
    createdAt,
    reuseCount,
  };
}

/**
 * Collect decision entries from `.forge/brain/**\/*.json`.
 *
 * Reads all JSON files under `.forge/brain/`, filters to objects that look
 * like decisions (have a `content` or `value.content` string field).
 *
 * @param {string} projectRoot
 * @param {{ since?: Date, limit?: number }} opts
 * @returns {Array<{ key: string, content: string, mtime: Date }>}
 */
export function collectBrainDecisions(projectRoot, { since, limit = 30 } = {}) {
  const brainDir = join(projectRoot, ".forge", "brain");
  if (!existsSync(brainDir)) return [];

  const results = [];
  _walkBrainDir(brainDir, brainDir, results, since);

  results.sort((a, b) => b.mtime - a.mtime);
  return results.slice(0, limit);
}

function _walkBrainDir(brainRoot, dir, results, since) {
  let entries;
  try { entries = readdirSync(dir); } catch { return; }

  for (const entry of entries) {
    const abs = join(dir, entry);
    let stat;
    try { stat = statSync(abs); } catch { continue; }

    if (stat.isDirectory()) {
      _walkBrainDir(brainRoot, abs, results, since);
      continue;
    }

    if (!entry.endsWith(".json")) continue;
    const mtime = new Date(stat.mtimeMs);
    if (since && mtime < since) continue;

    let text = "";
    try { text = readFileSync(abs, "utf-8"); } catch { continue; }
    const parsed = safeJson(text);
    if (!parsed || typeof parsed !== "object") continue;

    // Extract content: try {value: {content}}, {content}, {value}
    let content = null;
    if (typeof parsed.content === "string" && parsed.content.trim()) {
      content = parsed.content.trim();
    } else if (typeof parsed.value?.content === "string" && parsed.value.content.trim()) {
      content = parsed.value.content.trim();
    } else if (typeof parsed.value === "string" && parsed.value.trim()) {
      content = parsed.value.trim();
    }

    if (!content) continue;

    // Build human-readable key from path relative to .forge/brain/
    const relPath = abs.slice(brainRoot.length + 1).replace(/\\/g, "/").replace(/\.json$/, "");
    results.push({ key: relPath, content, mtime });
  }
}

// ─── Markdown rendering ──────────────────────────────────────────────────────

/**
 * Render the memory-hints Markdown document.
 *
 * @param {object} data
 * @param {Array}  data.trajectories
 * @param {Array}  data.autoSkills
 * @param {Array}  data.decisions
 * @param {Date}   [data.now]
 * @returns {string}
 */
export function renderMemoryHints({ trajectories, autoSkills, decisions, now }) {
  const ts = (now instanceof Date ? now : new Date()).toISOString().slice(0, 10);
  const lines = [
    "# Copilot Memory Hints",
    "",
    `> Generated by Plan Forge \`forge_sync_memories\` on ${ts}.`,
    "> Copilot Memory auto-discovers this file as a project knowledge source.",
    "> Do **not** edit manually — regenerate with \`pforge sync-memories\`.",
    "",
  ];

  // ── Section 1: Architecture Decisions ──────────────────────────────────
  if (decisions.length > 0) {
    lines.push("## Architecture Decisions", "");
    for (const d of decisions) {
      const short = d.content.split("\n")[0].slice(0, 200);
      lines.push(`- **${d.key}**: ${short}`);
    }
    lines.push("");
  }

  // ── Section 2: Conventions & Patterns (auto-skills) ────────────────────
  if (autoSkills.length > 0) {
    lines.push("## Conventions & Patterns", "");
    for (const s of autoSkills) {
      lines.push(`### ${s.summary}`);
      if (s.domainKeywords.length > 0) {
        lines.push(`*Domains: ${s.domainKeywords.join(", ")}*`);
      }
      if (s.reuseCount > 0) {
        lines.push(`*Reused ${s.reuseCount} time${s.reuseCount !== 1 ? "s" : ""}.*`);
      }
      if (s.commands.length > 0) {
        lines.push("", "Validation commands that worked:", "```");
        for (const c of s.commands) lines.push(c);
        lines.push("```");
      }
      lines.push("");
    }
  }

  // ── Section 3: Lessons Learned (trajectory notes) ──────────────────────
  if (trajectories.length > 0) {
    lines.push("## Lessons Learned", "");
    for (const t of trajectories) {
      const heading = `Plan \`${t.planBasename}\` / Slice ${t.sliceId}`;
      lines.push(`### ${heading}`, "");
      // Trim to first 300 chars to keep the file bounded
      const excerpt = t.content.slice(0, 300) + (t.content.length > 300 ? "\n\n*[truncated — see .forge/trajectories for full note]*" : "");
      lines.push(excerpt, "");
    }
  }

  // ── Empty state ─────────────────────────────────────────────────────────
  if (decisions.length === 0 && autoSkills.length === 0 && trajectories.length === 0) {
    lines.push(
      "## No hints yet",
      "",
      "Run at least one plan (`pforge run-plan`) to generate trajectory notes and auto-skills.",
      "OpenBrain decisions will appear here once the brain store is populated.",
      "",
    );
  }

  return lines.join("\n");
}

// ─── Main entry point ────────────────────────────────────────────────────────

/**
 * @typedef {Object} SyncMemoriesResult
 * @property {boolean} ok
 * @property {string}  [outputPath]     - Absolute path written (undefined in dry-run)
 * @property {number}  hintsCount       - Total hint items across all sections
 * @property {{ trajectories: number, autoSkills: number, decisions: number }} sections
 * @property {boolean} changed          - true when content differs from existing file
 * @property {boolean} dryRunMode
 * @property {string}  [dryRunContent]  - Rendered Markdown (dry-run only)
 * @property {string}  message
 */

/**
 * Sync forge decisions to `.github/copilot-memory-hints.md`.
 *
 * @param {Object} opts
 * @param {string}  opts.projectRoot  - Project root (required)
 * @param {boolean} [opts.dryRun]     - Print without writing
 * @param {boolean} [opts.force]      - Overwrite even if content is unchanged
 * @param {number}  [opts.limit]      - Max entries per section (default: 10)
 * @param {string}  [opts.since]      - ISO date string to filter by
 * @param {string}  [opts.output]     - Override output path (default: .github/copilot-memory-hints.md)
 * @param {Date}    [opts.now]        - Timestamp override for tests
 * @returns {SyncMemoriesResult}
 */
export function syncMemories({
  projectRoot,
  dryRun = false,
  force = false,
  limit = 10,
  since,
  output,
  now,
} = {}) {
  if (!projectRoot) throw new SyncMemoriesError("projectRoot is required");

  const sinceDate = since ? new Date(since) : undefined;
  if (sinceDate && isNaN(sinceDate.getTime())) {
    throw new SyncMemoriesError(`Invalid --since value: "${since}"`);
  }

  const trajectories = collectTrajectories(projectRoot, { since: sinceDate, limit });
  const autoSkills   = collectAutoSkills(projectRoot, { since: sinceDate, limit });
  const decisions    = collectBrainDecisions(projectRoot, { since: sinceDate, limit });

  const content = renderMemoryHints({
    trajectories,
    autoSkills,
    decisions,
    now: now instanceof Date ? now : new Date(),
  });

  const hintsCount = trajectories.length + autoSkills.length + decisions.length;
  const sections = {
    trajectories: trajectories.length,
    autoSkills:   autoSkills.length,
    decisions:    decisions.length,
  };

  if (dryRun) {
    return {
      ok: true,
      hintsCount,
      sections,
      changed: true,
      dryRunMode: true,
      dryRunContent: content,
      message: `Dry run: would write ${hintsCount} hint(s) (${sections.trajectories} trajectories, ${sections.autoSkills} auto-skills, ${sections.decisions} decisions).`,
    };
  }

  const outputPath = output
    ? resolve(projectRoot, output)
    : resolve(projectRoot, ".github", "copilot-memory-hints.md");

  // Skip write when content is unchanged (unless --force)
  let changed = true;
  if (!force && existsSync(outputPath)) {
    try {
      const existing = readFileSync(outputPath, "utf-8");
      if (sha256(existing) === sha256(content)) {
        changed = false;
      }
    } catch { /* treat as changed */ }
  }

  if (changed) {
    try {
      mkdirSync(dirname(outputPath), { recursive: true });
      writeFileSync(outputPath, content, "utf-8");
    } catch (err) {
      throw new SyncMemoriesError(`Failed to write ${outputPath}: ${err.message}`);
    }
  }

  return {
    ok: true,
    outputPath,
    hintsCount,
    sections,
    changed,
    dryRunMode: false,
    message: changed
      ? `Wrote ${hintsCount} hint(s) to ${outputPath}.`
      : `No changes — memory hints are up to date (${hintsCount} hint(s)).`,
  };
}

// ─── CLI entry point (when run directly via node sync-memories.mjs) ──────────
// Consumed by pforge.ps1 / pforge.sh via: node sync-memories.mjs <json-opts>

if (process.argv[1] && process.argv[1].endsWith("sync-memories.mjs")) {
  const raw = process.argv[2];
  if (!raw) {
    console.error("Usage: node sync-memories.mjs <json-opts>");
    process.exit(1);
  }

  let opts;
  try {
    opts = JSON.parse(raw);
  } catch (e) {
    console.error(`Invalid JSON opts: ${e.message}`);
    process.exit(1);
  }

  try {
    const result = syncMemories(opts);
    if (result.dryRunMode) {
      console.log(`📋 Dry run — ${result.message}`);
      console.log("");
      console.log(result.dryRunContent);
    } else if (result.changed) {
      console.log(`✓ ${result.message}`);
    } else {
      console.log(`✓ ${result.message}`);
    }
  } catch (err) {
    console.error(`ERROR: ${err.message}`);
    process.exit(1);
  }
}

import { appendFileSync, existsSync, mkdirSync, readFileSync } from "node:fs";
import { spawnSync } from "node:child_process";
import { dirname, join, resolve } from "node:path";

const TEAM_ACTIVITY_FILE = "team-activity.jsonl";
const TEAM_ACTIVITY_VERSION = "1.0";

function readGitConfig(cwd, key) {
  try {
    const result = spawnSync("git", ["config", key], {
      cwd,
      encoding: "utf-8",
      windowsHide: true,
    });
    if (result.error || result.status !== 0) return "";
    return (result.stdout || "").trim();
  } catch {
    return "";
  }
}

export function getOperator(cwd = process.cwd()) {
  const resolvedCwd = resolve(cwd);
  const name = readGitConfig(resolvedCwd, "user.name");
  const email = readGitConfig(resolvedCwd, "user.email");
  if (name && email) return `${name} <${email}>`;
  return name || email || "unknown";
}

function normalizeActivity(summary = {}, storeDir) {
  const resolvedStoreDir = resolve(storeDir ?? join(process.cwd(), ".forge"));
  return {
    timestamp: summary.timestamp || new Date().toISOString(),
    run_id: summary.run_id || summary.runId || null,
    plan: summary.plan ?? null,
    status: summary.status || "unknown",
    slice_count: summary.slice_count ?? summary.sliceCount ?? null,
    duration_ms: summary.duration_ms ?? summary.totalDuration ?? null,
    cost_usd: summary.cost_usd ?? summary.cost?.total_cost_usd ?? null,
    operator: summary.operator || getOperator(dirname(resolvedStoreDir)),
    version: TEAM_ACTIVITY_VERSION,
  };
}

export function recordActivity(summary, { storeDir } = {}) {
  const resolvedStoreDir = resolve(storeDir ?? join(process.cwd(), ".forge"));
  mkdirSync(resolvedStoreDir, { recursive: true });
  const record = normalizeActivity(summary, resolvedStoreDir);
  appendFileSync(join(resolvedStoreDir, TEAM_ACTIVITY_FILE), `${JSON.stringify(record)}\n`, "utf-8");
  return record;
}

export function loadActivity({ storeDir, limit = 20, since } = {}) {
  const resolvedStoreDir = resolve(storeDir ?? join(process.cwd(), ".forge"));
  const feedPath = join(resolvedStoreDir, TEAM_ACTIVITY_FILE);
  if (!existsSync(feedPath)) return [];

  let content = "";
  try {
    content = readFileSync(feedPath, "utf-8");
  } catch {
    return [];
  }

  const max = Number.isFinite(limit) ? Math.max(0, Math.trunc(limit)) : 20;
  const sinceMs = since ? Date.parse(since) : NaN;
  const filterSince = Number.isFinite(sinceMs);

  const activities = [];
  for (const line of content.split(/\r?\n/).filter(Boolean).reverse()) {
    try {
      const entry = JSON.parse(line);
      const tsMs = Date.parse(entry?.timestamp);
      if (filterSince && (!Number.isFinite(tsMs) || tsMs < sinceMs)) continue;
      activities.push(entry);
      if (activities.length >= max) break;
    } catch {
      // Skip malformed lines to keep the shared feed resilient.
    }
  }

  return activities;
}

/**
 * Plan Forge — Unified Telemetry (v2.4)
 *
 * OTLP-compatible trace/span/log capture for end-to-end observability.
 * Writes trace.json, manifest.json, and index.jsonl per run.
 *
 * @module telemetry
 */

import { writeFileSync, readFileSync, appendFileSync, existsSync, mkdirSync, readdirSync, rmSync } from "node:fs";
import { resolve, basename } from "node:path";
import { randomUUID } from "node:crypto";
import { hostname, type as osType } from "node:os";
import { execSync } from "node:child_process";

// Severity levels per OTLP convention
export const Severity = {
  TRACE: { text: "TRACE", number: 1 },
  DEBUG: { text: "DEBUG", number: 5 },
  INFO:  { text: "INFO",  number: 9 },
  WARN:  { text: "WARN",  number: 13 },
  ERROR: { text: "ERROR", number: 17 },
  FATAL: { text: "FATAL", number: 21 },
};

/**
 * Create trace context for a new run.
 */
export function createTraceContext(planPath, options = {}) {
  const { mode = "auto", model = "auto", sliceCount = 0 } = options;

  // Resource context — who/where/what
  let userName = "unknown";
  try { userName = execSync("git config user.name", { encoding: "utf-8", timeout: 5000 }).trim(); } catch { /* ignore */ }

  const traceId = randomUUID().replace(/-/g, "").substring(0, 32);

  return {
    resource: {
      "service.name": "plan-forge-orchestrator",
      "service.version": "2.4.0",
      "host.name": hostname(),
      "os.type": osType(),
      "user.name": userName,
      "project.name": basename(process.cwd()),
    },
    traceId,
    plan: planPath,
    mode,
    model,
    sliceCount,
    spans: [],
    _activeSpans: new Map(),
    _startTime: new Date().toISOString(),
  };
}

/**
 * Start a root span (run-plan).
 */
export function startRootSpan(trace, name, attributes = {}) {
  const span = {
    spanId: randomUUID().replace(/-/g, "").substring(0, 16),
    parentSpanId: null,
    name,
    kind: "SERVER",
    startTime: new Date().toISOString(),
    endTime: null,
    status: "UNSET",
    attributes,
    events: [],
    logSummary: [],
  };
  trace.spans.push(span);
  trace._activeSpans.set(name, span);
  return span;
}

/**
 * Start a child span (slice, worker, gate).
 */
export function startSpan({ trace, name, parentSpanId, kind = "INTERNAL", attributes = {} }) {
  const span = {
    spanId: randomUUID().replace(/-/g, "").substring(0, 16),
    parentSpanId,
    name,
    kind,
    startTime: new Date().toISOString(),
    endTime: null,
    status: "UNSET",
    attributes,
    events: [],
    logSummary: [],
  };
  trace.spans.push(span);
  trace._activeSpans.set(name, span);
  return span;
}

/**
 * End a span with status.
 */
export function endSpan(span, status = "OK") {
  span.endTime = new Date().toISOString();
  span.status = status;
}

/**
 * Add an event to a span.
 */
export function addEvent(span, name, severity = Severity.INFO, attributes = {}) {
  span.events.push({
    time: new Date().toISOString(),
    name,
    severity: severity.text,
    severityNumber: severity.number,
    attributes,
  });
}

/**
 * Add log summary lines to a span (extracted from worker output).
 */
export function addLogSummary(span, output) {
  if (!output) return;
  const lines = output.split("\n");
  const patterns = /creat|modif|writ|delet|error|fail|warn|pass|compil|test|build/i;
  const summary = lines
    .filter((l) => patterns.test(l))
    .slice(0, 50)
    .map((l) => l.trim().substring(0, 200));
  span.logSummary = summary;
}

// ─── Trace Writer ─────────────────────────────────────────────────────

/**
 * Write trace.json to the run directory.
 */
export function writeTrace(trace, runDir) {
  const output = {
    resource: trace.resource,
    traceId: trace.traceId,
    spans: trace.spans.map((s) => ({
      spanId: s.spanId,
      parentSpanId: s.parentSpanId,
      name: s.name,
      kind: s.kind,
      startTime: s.startTime,
      endTime: s.endTime,
      status: s.status,
      attributes: s.attributes,
      events: s.events,
      logSummary: s.logSummary,
    })),
  };
  writeFileSync(resolve(runDir, "trace.json"), JSON.stringify(output, null, 2));
}

// ─── Manifest + Index (Log Registry) ──────────────────────────────────

/**
 * Write manifest.json for a completed run.
 */
export function writeManifest(runDir, runId, summary) {
  const files = [];
  const checkFile = (name) => {
    const path = resolve(runDir, name);
    if (existsSync(path)) files.push(name);
  };

  checkFile("run.json");
  checkFile("summary.json");
  checkFile("trace.json");
  checkFile("events.log");

  // Find slice files
  const slices = [];
  try {
    const entries = readdirSync(runDir);
    const sliceJsonFiles = entries.filter((f) => /^slice-[\d.]+\.json$/.test(f)).sort();
    for (const sjf of sliceJsonFiles) {
      const num = sjf.match(/slice-([\d.]+)\.json/)?.[1];
      if (!num) continue;
      const logFile = `slice-${num}-log.txt`;
      slices.push({
        number: num,
        result: sjf,
        log: entries.includes(logFile) ? logFile : null,
        status: summary?.sliceResults?.find((r) => String(r.number || r.sliceId) === num)?.status || "unknown",
      });
    }
  } catch { /* ignore */ }

  const manifest = {
    runId,
    traceId: summary?.traceId || null,
    plan: summary?.plan || null,
    startTime: summary?.startTime || null,
    endTime: summary?.endTime || null,
    status: summary?.status || "unknown",
    artifacts: files,
    slices,
  };

  writeFileSync(resolve(runDir, "manifest.json"), JSON.stringify(manifest, null, 2));
  return manifest;
}

/**
 * Append a run entry to .forge/runs/index.jsonl.
 * JSONL format — one JSON object per line, safe for concurrent appends.
 */
export function appendRunIndex(cwd, runId, manifest) {
  const indexPath = resolve(cwd, ".forge", "runs", "index.jsonl");
  mkdirSync(resolve(cwd, ".forge", "runs"), { recursive: true });

  const entry = JSON.stringify({
    runId,
    plan: manifest.plan,
    status: manifest.status,
    startTime: manifest.startTime,
    endTime: manifest.endTime,
    dir: runId,
    sliceCount: manifest.slices?.length || 0,
  });

  appendFileSync(indexPath, entry + "\n");
}

/**
 * Read the run index. Skips malformed lines (corruption recovery).
 */
export function readRunIndex(cwd) {
  const indexPath = resolve(cwd, ".forge", "runs", "index.jsonl");
  if (!existsSync(indexPath)) return [];

  const lines = readFileSync(indexPath, "utf-8").split("\n").filter((l) => l.trim());
  const entries = [];
  for (const line of lines) {
    try {
      entries.push(JSON.parse(line));
    } catch {
      // Skip malformed lines (corruption recovery — Gap 6)
      continue;
    }
  }
  return entries;
}

// ─── Log Rotation ─────────────────────────────────────────────────────

/**
 * Prune old run directories beyond maxRunHistory.
 */
export function pruneRunHistory(cwd, maxRunHistory = 50) {
  const runsDir = resolve(cwd, ".forge", "runs");
  if (!existsSync(runsDir)) return;

  const dirs = readdirSync(runsDir, { withFileTypes: true })
    .filter((d) => d.isDirectory())
    .map((d) => d.name)
    .sort()
    .reverse();

  if (dirs.length <= maxRunHistory) return;

  const toRemove = dirs.slice(maxRunHistory);
  for (const dir of toRemove) {
    try {
      rmSync(resolve(runsDir, dir), { recursive: true, force: true });
    } catch { /* best effort */ }
  }

  // Compact index — remove entries for deleted directories
  const indexPath = resolve(runsDir, "index.jsonl");
  if (existsSync(indexPath)) {
    const remaining = new Set(dirs.slice(0, maxRunHistory));
    const entries = readRunIndex(cwd).filter((e) => remaining.has(e.dir));
    writeFileSync(indexPath, entries.map((e) => JSON.stringify(e)).join("\n") + "\n");
  }
}

// ─── OTel Chat Span Emitter ────────────────────────────────────────────

// Singleton tracer promise — resolved once per process lifetime.
let _otelTracerPromise = null;

// Singleton meter promise — resolved once per process lifetime.
let _otelMeterPromise = null;

/**
 * Lazily initialize the OTel tracer when OTEL_EXPORTER_OTLP_ENDPOINT is set.
 * All OTel packages are loaded via dynamic import (optional deps).
 * Returns null if the endpoint is unset or if packages are unavailable.
 * @returns {Promise<object|null>}
 */
async function _getOtelTracer() {
  if (!process.env.OTEL_EXPORTER_OTLP_ENDPOINT) return null;
  if (_otelTracerPromise !== null) return _otelTracerPromise;

  _otelTracerPromise = (async () => {
    try {
      const { initOtel } = await import("./otel-init.mjs");
      await initOtel();
      const { trace } = await import("@opentelemetry/api");
      return trace.getTracer("pforge-mcp", "2.4.0");
    } catch {
      // Optional packages not installed — graceful no-op.
      return null;
    }
  })();

  return _otelTracerPromise;
}

/**
 * Lazily initialize the OTel meter when OTEL_EXPORTER_OTLP_ENDPOINT is set.
 * All OTel packages are loaded via dynamic import (optional deps).
 * Returns null if the endpoint is unset or if packages are unavailable.
 * @returns {Promise<object|null>}
 */
async function _getOtelMeter() {
  if (!process.env.OTEL_EXPORTER_OTLP_ENDPOINT) return null;
  if (_otelMeterPromise !== null) return _otelMeterPromise;

  _otelMeterPromise = (async () => {
    try {
      const { initOtel } = await import("./otel-init.mjs");
      await initOtel();
      const { metrics } = await import("@opentelemetry/api");
      return metrics.getMeter("pforge-mcp", "2.4.0");
    } catch {
      // Optional packages not installed — graceful no-op.
      return null;
    }
  })();

  return _otelMeterPromise;
}

/**
 * Record gen_ai.client.operation.duration and gen_ai.client.token.usage histograms.
 * Fires and forgets — caller should not await (never throws).
 *
 * Histogram names follow the OpenTelemetry GenAI semantic conventions:
 *   gen_ai.client.operation.duration — unit: s
 *   gen_ai.client.token.usage        — unit: {token}, split by gen_ai.token.type
 *
 * @param {object} data - Same payload as _emitChatSpan.
 */
function _buildOtelBaseAttrs(data, model) {
  const provider = data?.provider ?? _inferProvider(model);
  return {
    "gen_ai.operation.name": "chat",
    "gen_ai.system": provider,
    "gen_ai.request.model": data?.requestModel ?? model,
    "gen_ai.response.model": data?.responseModel ?? model,
  };
}

function _extractOtelTokenCounts(data) {
  return {
    tokensIn: data?.tokens?.tokens_in ?? data?.tokensIn ?? 0,
    tokensOut: data?.tokens?.tokens_out ?? data?.tokensOut ?? 0,
  };
}

async function _recordChatMetrics(data) {
  try {
    const meter = await _getOtelMeter();
    if (!meter) return;

    const model = data?.model ?? "unknown";
    const baseAttrs = _buildOtelBaseAttrs(data, model);
    const durationMs = data?.durationMs ?? data?.duration ?? 0;

    meter.createHistogram("gen_ai.client.operation.duration", {
      description: "GenAI operation duration", unit: "s",
    }).record(durationMs / 1000, baseAttrs);

    const tokenHist = meter.createHistogram("gen_ai.client.token.usage", {
      description: "GenAI token usage", unit: "{token}",
    });
    const { tokensIn, tokensOut } = _extractOtelTokenCounts(data);
    if (tokensIn > 0) tokenHist.record(tokensIn, { ...baseAttrs, "gen_ai.token.type": "input" });
    if (tokensOut > 0) tokenHist.record(tokensOut, { ...baseAttrs, "gen_ai.token.type": "output" });
  } catch {
    // Never surface OTel errors to the orchestrator.
  }
}

/**
 * Infer the gen_ai.provider.name from a model identifier string.
 * @param {string} model
 * @returns {string}
 */
function _inferProvider(model) {
  if (!model) return "unknown";
  if (/^gpt-|^o[1-9]/.test(model)) return "openai";
  if (/^claude/.test(model)) return "anthropic";
  if (/^grok/.test(model)) return "xai";
  if (/^gemini/.test(model)) return "google";
  if (/^mistral/.test(model)) return "mistralai";
  return "unknown";
}

/**
 * Emit a `gen_ai.chat <model>` span to the OTLP endpoint.
 * Fires and forgets — caller should not await (never throws).
 *
 * @param {object} data - Payload from the `chat-completed` orchestrator event.
 *   Expected fields: model, requestModel, responseModel, provider,
 *   tokens.tokens_in, tokens.tokens_out, cost_usd, sliceId, runId.
 */
function _buildChatSpanAttrs(data, model) {
  const { tokensIn, tokensOut } = _extractOtelTokenCounts(data);
  return {
    "gen_ai.operation.name": "chat",
    "gen_ai.provider.name": data?.provider ?? _inferProvider(model),
    "gen_ai.request.model": data?.requestModel ?? model,
    "gen_ai.response.model": data?.responseModel ?? model,
    "gen_ai.usage.input_tokens": tokensIn,
    "gen_ai.usage.output_tokens": tokensOut,
    "pforge.cost.usd": data?.cost_usd ?? data?.costUsd ?? 0,
    "pforge.slice.number": String(data?.sliceId ?? ""),
    "pforge.run.id": data?.runId ?? "",
  };
}

async function _emitChatSpan(data) {
  try {
    const tracer = await _getOtelTracer();
    if (!tracer) return;

    const model = data?.model ?? "unknown";
    const span = tracer.startSpan(`gen_ai.chat ${model}`, {
      kind: 3, // SpanKind.CLIENT
      attributes: _buildChatSpanAttrs(data, model),
    });
    span.end();

    await _recordChatMetrics(data);
  } catch {
    // Never surface OTel errors to the orchestrator.
  }
}

// ─── OTel Agent (Slice) Span Emitter ──────────────────────────────────

/**
 * Emit an `invoke_agent slice-N` span to the OTLP endpoint.
 * Fires and forgets — caller should not await (never throws).
 *
 * @param {object} data - Payload from the `slice-started` orchestrator event.
 *   Expected fields: sliceId, title, planName, planCommitSha, runId.
 */
async function _emitAgentSpan(data) {
  try {
    const tracer = await _getOtelTracer();
    if (!tracer) return;

    const sliceId = data?.sliceId ?? "";
    const span = tracer.startSpan(`invoke_agent slice-${sliceId}`, {
      kind: 3, // SpanKind.CLIENT
      attributes: {
        "gen_ai.agent.name": `slice-${sliceId}`,
        "gen_ai.agent.version": data?.planCommitSha ?? "",
        "pforge.plan.name": data?.planName ?? data?.plan ?? "",
        "pforge.slice.number": String(sliceId),
        "pforge.run.id": data?.runId ?? "",
        "pforge.actor.source": data?.source ?? "",
        "pforge.action.security_risk": data?.security_risk ?? "",
      },
    });

    span.end();
  } catch {
    // Never surface OTel errors to the orchestrator.
  }
}

/**
 * Public fire-and-forget entry point for agent-span emission.
 * Called by the telemetry handler on slice-started events.
 *
 * @param {{ sliceId: string|number, title?: string, planName?: string, planCommitSha?: string, runId?: string }} data
 */
export function emitAgentSpan(data) {
  _emitAgentSpan(data).catch(() => {});
}

// ─── OTel Workflow (Plan) Span Emitter ────────────────────────────────

/**
 * Emit an `invoke_workflow <plan>` span to the OTLP endpoint.
 * Fires and forgets — caller should not await (never throws).
 *
 * @param {object} data - Payload from the `run-started` orchestrator event.
 *   Expected fields: plan, planCommitSha, mode, model, sliceCount, runId, quorumMode, quorumThreshold.
 */
async function _emitWorkflowSpan(data) {
  try {
    const tracer = await _getOtelTracer();
    if (!tracer) return;

    const plan = data?.plan ?? "unknown";
    const span = tracer.startSpan(`invoke_workflow ${plan}`, {
      kind: 3, // SpanKind.CLIENT
      attributes: {
        "gen_ai.workflow.name": plan,
        "pforge.plan.path": plan,
        "pforge.plan.commit_sha": data?.planCommitSha ?? "",
        "pforge.quorum.mode": data?.quorumMode ?? data?.mode ?? "",
        "pforge.quorum.threshold": data?.quorumThreshold ?? 0,
        "pforge.run.id": data?.runId ?? "",
      },
    });

    span.end();
  } catch {
    // Never surface OTel errors to the orchestrator.
  }
}

/**
 * Public fire-and-forget entry point for workflow-span emission.
 * Called by the telemetry handler on run-started events.
 *
 * @param {{ plan: string, planCommitSha?: string, mode?: string, quorumMode?: string, quorumThreshold?: number, runId?: string }} data
 */
export function emitWorkflowSpan(data) {
  _emitWorkflowSpan(data).catch(() => {});
}

// ─── OTel Tool Span Emitter ────────────────────────────────────────────

/**
 * Emit an `execute_tool <tool_name>` span to the OTLP endpoint.
 * Fires and forgets — caller should not await (never throws).
 *
 * @param {object} data - Payload from the tool dispatcher wrapper.
 *   Expected fields: toolName, durationMs, isError, runId.
 */
async function _emitToolSpan(data) {
  try {
    const tracer = await _getOtelTracer();
    if (!tracer) return;

    const toolName = data?.toolName ?? "unknown";
    const durationMs = data?.durationMs ?? 0;
    const startTime = new Date(Date.now() - durationMs);

    const span = tracer.startSpan(`execute_tool ${toolName}`, {
      kind: 3, // SpanKind.CLIENT
      startTime,
      attributes: {
        "pforge.tool.name": toolName,
        "pforge.tool.duration_ms": durationMs,
        "pforge.tool.error": data?.isError ?? false,
        "pforge.run.id": data?.runId ?? "",
      },
    });

    span.end();
  } catch {
    // Never surface OTel errors to the dispatcher.
  }
}

/**
 * Public fire-and-forget entry point for tool-span emission.
 * Called by the server.mjs wrap layer after each MCP tool invocation.
 *
 * @param {{ toolName: string, durationMs: number, isError: boolean, runId?: string }} data
 */
export function emitToolSpan(data) {
  _emitToolSpan(data).catch(() => {});
}

// ─── OTel Gate Span Emitter ───────────────────────────────────────────

/**
 * Emit a `run_gate slice-N` span to the OTLP endpoint.
 * Fires and forgets — caller should not await (never throws).
 *
 * @param {object} data - Payload from the `gate-passed` orchestrator event.
 *   Expected fields: sliceId, runId, failOpen, durationMs.
 */
async function _emitGateSpan(data) {
  try {
    const tracer = await _getOtelTracer();
    if (!tracer) return;

    const sliceId = data?.sliceId ?? "";
    const durationMs = data?.durationMs ?? 0;
    const startTime = durationMs ? new Date(Date.now() - durationMs) : new Date();

    const span = tracer.startSpan(`run_gate slice-${sliceId}`, {
      kind: 3, // SpanKind.CLIENT
      startTime,
      attributes: {
        "pforge.gate.passed": !(data?.failed ?? false),
        "pforge.gate.fail_open": data?.failOpen ?? false,
        "pforge.slice.number": String(sliceId),
        "pforge.run.id": data?.runId ?? "",
      },
    });

    span.end();
  } catch {
    // Never surface OTel errors to the orchestrator.
  }
}

/**
 * Public fire-and-forget entry point for gate-span emission.
 * Called by the telemetry handler on gate-passed events.
 *
 * @param {{ sliceId: string|number, runId?: string, failOpen?: boolean, durationMs?: number }} data
 */
export function emitGateSpan(data) {
  _emitGateSpan(data).catch(() => {});
}

// ─── Orchestrator Event Handler for Telemetry ─────────────────────────

/**
 * Create a telemetry event handler that builds trace.json from orchestrator events.
 * Plug this into the orchestrator via DI (eventHandler option).
 */
function createRunTelemetryHandlers({ trace, state, runDir }) {
  return {
    "run-started": (data) => {
      state.rootSpan = startRootSpan(trace, "run-plan", {
        plan: data?.plan,
        mode: data?.mode,
        model: data?.model,
        sliceCount: data?.sliceCount,
      });
      _emitWorkflowSpan({ ...data, runId: trace.traceId }).catch(() => {});
    },
    "slice-started": (data) => {
      const parentId = state.rootSpan?.spanId || null;
      startSpan({
        trace,
        name: `slice-${data?.sliceId}`,
        parentSpanId: parentId,
        kind: "INTERNAL",
        attributes: {
          sliceId: data?.sliceId,
          title: data?.title,
          parallel: data?.parallel || false,
          "pforge.actor.source": data?.source ?? null,
          "pforge.action.security_risk": data?.security_risk ?? null,
        },
      });
      _emitAgentSpan({ ...data, runId: trace.traceId }).catch(() => {});
    },
    "slice-completed": (data) => {
      const span = trace._activeSpans.get(`slice-${data?.sliceId}`);
      if (!span) return;
      addEvent(span, "completed", Severity.INFO, {
        duration: data?.duration,
        model: data?.model,
        tokens_out: data?.tokens?.tokens_out,
        cost_usd: data?.tokens?.cost_usd,
        attempts: data?.attempts,
      });
      span.attributes.duration = data?.duration;
      span.attributes.model = data?.model;
      span.attributes.cost_usd = data?.cost_usd;
      span.attributes.attempts = data?.attempts;
      endSpan(span, "OK");
    },
    "slice-failed": (data) => {
      const span = trace._activeSpans.get(`slice-${data?.sliceId}`);
      if (!span) return;
      addEvent(span, "failed", Severity.ERROR, {
        error: data?.error,
        failedCommand: data?.failedCommand,
        gateError: data?.gateError,
      });
      endSpan(span, "ERROR");
    },
    "run-completed": (data) => {
      if (state.rootSpan) {
        addEvent(state.rootSpan, "completed", Severity.INFO, {
          status: data?.status,
          passed: data?.results?.passed,
          failed: data?.results?.failed,
          report: data?.report,
        });
        endSpan(state.rootSpan, data?.status === "completed" ? "OK" : "ERROR");
      }
      writeTrace(trace, runDir);
    },
    "run-aborted": (data) => {
      if (state.rootSpan) {
        addEvent(state.rootSpan, "aborted", Severity.WARN, { reason: data?.reason });
        endSpan(state.rootSpan, "ERROR");
      }
      writeTrace(trace, runDir);
    },
  };
}

function endQuorumLegByModel(trace, data) {
  for (const [key, span] of trace._activeSpans) {
    if (key.startsWith(`slice-${data?.sliceId}-quorum-`) && span.attributes?.model === data?.model) {
      addEvent(span, "leg-completed", data?.success ? Severity.INFO : Severity.WARN, {
        model: data?.model,
        duration: data?.duration,
        tokens_out: data?.tokens?.tokens_out,
      });
      endSpan(span, data?.success ? "OK" : "ERROR");
      break;
    }
  }
}

function createQuorumTelemetryHandlers(trace) {
  return {
    "quorum-dispatch-started": (data) => {
      const parentSpan = trace._activeSpans.get(`slice-${data?.sliceId}`);
      if (!parentSpan) return;
      addEvent(parentSpan, "quorum-dispatch", Severity.INFO, {
        models: data?.models,
        score: data?.score,
      });
      for (let i = 0; i < (data?.models || []).length; i++) {
        startSpan({
          trace,
          name: `slice-${data?.sliceId}-quorum-${i}`,
          parentSpanId: parentSpan.spanId,
          kind: "CLIENT",
          attributes: { quorumLeg: i, model: data.models[i] },
        });
      }
    },
    "quorum-leg-completed": (data) => {
      const legSpan = trace._activeSpans.get(`slice-${data?.sliceId}-quorum-${data?.legIndex ?? ""}`);
      if (!legSpan) {
        endQuorumLegByModel(trace, data);
        return;
      }
      endSpan(legSpan, data?.success ? "OK" : "ERROR");
    },
    "quorum-review-completed": (data) => {
      const parentSpan = trace._activeSpans.get(`slice-${data?.sliceId}`);
      if (!parentSpan) return;
      addEvent(parentSpan, "quorum-review", Severity.INFO, {
        reviewerModel: data?.reviewerModel,
        tokens_out: data?.tokens?.tokens_out,
        modelCount: data?.modelCount,
      });
    },
  };
}

function createSupplementalTelemetryHandlers(trace) {
  return {
    "gate-passed": (data) => {
      const parentSpan = trace._activeSpans.get(`slice-${data?.sliceId}`);
      if (parentSpan) {
        addEvent(parentSpan, "gate-passed", Severity.INFO, {
          failOpen: data?.failOpen ?? false,
        });
      }
      _emitGateSpan({ ...data, runId: trace.traceId }).catch(() => {});
    },
    "chat-completed": (data) => {
      const parentSpan = trace._activeSpans.get(`slice-${data?.sliceId}`);
      if (parentSpan) {
        addEvent(parentSpan, "chat-completed", Severity.INFO, {
          model: data?.model,
          tokens_in: data?.tokens?.tokens_in ?? data?.tokensIn,
          tokens_out: data?.tokens?.tokens_out ?? data?.tokensOut,
          cost_usd: data?.cost_usd ?? data?.costUsd,
        });
      }
      _emitChatSpan({ ...data, runId: trace.traceId }).catch(() => {});
    },
  };
}

export function createTelemetryHandler(trace, runDir) {
  const state = { rootSpan: null };
  const dispatch = {
    ...createRunTelemetryHandlers({ trace, state, runDir }),
    ...createQuorumTelemetryHandlers(trace),
    ...createSupplementalTelemetryHandlers(trace),
  };

  return {
    handle(event) {
      const handler = dispatch[event?.type];
      if (handler) handler(event.data);
    },
  };
}

/**
 * Plan Forge — Tempering: foundation (Phase TEMPER-01 Slice 01.1)
 *
 * Read-only test-intelligence subsystem. This slice introduces:
 *   - `.forge/tempering/config.json` with enterprise defaults
 *   - Storage helpers (ensureTemperingDirs, readTemperingConfig)
 *   - Stack detection via presets/
 *   - Coverage-report location + parsing (lcov, coverage-final.json,
 *     cobertura.xml, coverage.py XML, jacoco.xml, go cover.out)
 *   - Gap analysis vs. config minima
 *   - handleScan / handleStatus — pure functions invoked by server.mjs
 *   - readTemperingState — cheap snapshot for watcher + dashboard
 *
 * Mirrors the pattern established by crucible-server.mjs: hub events are
 * emitted by a small `emit` helper; side effects are isolated behind
 * filesystem writes; handlers never throw — callers expect
 * `{ ok, ... } | { ok: false, error, code }` shapes.
 *
 * Forbidden this phase (enforced by scope contract, not by code):
 *   - Running any test framework
 *   - Creating bugs (Bug Registry lands in TEMPER-06)
 *   - Editing production source files
 *   - Extending forge_liveguard_run (TEMPER-06 owns that)
 *
 * @module tempering
 */

import {
  existsSync,
  mkdirSync,
  readFileSync,
  writeFileSync,
  appendFileSync,
  readdirSync,
  statSync,
} from "node:fs";
import { resolve, dirname, basename } from "node:path";
import { randomUUID } from "node:crypto";

// ─── Constants ────────────────────────────────────────────────────────

