/**
 * Coverage-report filenames, in priority order per stack. First match on
 * disk wins. Paths are globs relative to project root.
 */
const COVERAGE_REPORTS = [
  // TypeScript / JavaScript (Jest, Vitest, c8, nyc)
  { name: "lcov", path: "coverage/lcov.info", format: "lcov", stacks: ["typescript"] },
  { name: "coverage-final", path: "coverage/coverage-final.json", format: "istanbul-json", stacks: ["typescript"] },
  // .NET (Coverlet, dotCover)
  { name: "cobertura", path: "coverage/cobertura.xml", format: "cobertura", stacks: ["dotnet"] },
  { name: "cobertura-testresults", path: "TestResults/coverage.cobertura.xml", format: "cobertura", stacks: ["dotnet"] },
  // Python (coverage.py)
  { name: "coverage-py-xml", path: "coverage.xml", format: "cobertura", stacks: ["python"] },
  { name: "coverage-py-json", path: "coverage.json", format: "coverage-py-json", stacks: ["python"] },
  // Java / Kotlin (JaCoCo)
  { name: "jacoco", path: "target/site/jacoco/jacoco.xml", format: "jacoco", stacks: ["java"] },
  { name: "jacoco-build", path: "build/reports/jacoco/test/jacocoTestReport.xml", format: "jacoco", stacks: ["java"] },
  // Go
  { name: "go-cover", path: "coverage.out", format: "go-cover", stacks: ["go"] },
  { name: "go-cover-alt", path: "cover.out", format: "go-cover", stacks: ["go"] },
  // Rust (cargo-tarpaulin, cargo-llvm-cov)
  { name: "tarpaulin", path: "tarpaulin-report.json", format: "tarpaulin", stacks: ["rust"] },
  { name: "rust-lcov", path: "lcov.info", format: "lcov", stacks: ["rust"] },
];

// ─── Directory + config storage ───────────────────────────────────────

/**
 * Ensure `.forge/tempering/` exists. Never overwrites an existing
 * config.json — treating it as "never auto-mutate user intent".
 *
 * @param {string} projectDir
 * @returns {{ dir: string, configPath: string, configWritten: boolean }}
 */
export function ensureTemperingDirs(projectDir) {
  const dir = resolve(projectDir, ".forge", "tempering");
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });

  const configPath = resolve(dir, "config.json");
  let configWritten = false;
  if (!existsSync(configPath)) {
    writeFileSync(
      configPath,
      JSON.stringify(TEMPERING_DEFAULT_CONFIG, null, 2) + "\n",
      "utf-8",
    );
    configWritten = true;
  }
  return { dir, configPath, configWritten };
}

/**
 * Load config. Never throws — returns baked-in defaults on any error
 * and stamps a `_source` field so callers can distinguish.
 *
 * @param {string} projectDir
 * @returns {object} config (with shallow-merged defaults for any missing keys)
 */
export function readTemperingConfig(projectDir) {
  const configPath = resolve(projectDir, ".forge", "tempering", "config.json");
  if (!existsSync(configPath)) {
    return { ...TEMPERING_DEFAULT_CONFIG, _source: "defaults" };
  }
  try {
    const raw = readFileSync(configPath, "utf-8");
    const parsed = JSON.parse(raw);
    return { ...TEMPERING_DEFAULT_CONFIG, ...parsed, _source: "file" };
  } catch {
    return { ...TEMPERING_DEFAULT_CONFIG, _source: "defaults-fallback" };
  }
}

// Phase-25 Slice 4 (L6 adaptive gate synthesis) — read-only accessor.
// Returns the coverage-minimum + runtime-budget numbers for a given domain
// profile (domain | integration | controller | overall). Used by the
// orchestrator's `synthesizeGateSuggestions()` pre-flight to advise adding
// missing gates to slices whose title matches a domain keyword.
// NOT a mutation point — logic remains in orchestrator.mjs, tempering.mjs
// just exposes its minima read-only as mandated by Phase-25 Forbidden Actions.
/**
 * @param {string} projectDir
 * @param {"domain"|"integration"|"controller"|"overall"} [domain="domain"]
 * @returns {{ domain: string, coverageMin: number|null, runtimeBudgetMs: number|null }}
 */
export function getMinimaForDomain(projectDir, domain = "domain") {
  const cfg = readTemperingConfig(projectDir);
  const coverageMin = cfg?.coverageMinima?.[domain];
  // Map each domain onto a budget key — conservative defaults mirror the
  // Phase-25 research report's "cheap cold-path / hot-path-aware" stance.
  const budgetKey = {
    domain: "unitMaxMs",
    integration: "integrationMaxMs",
    controller: "integrationMaxMs",
    overall: "unitMaxMs",
  }[domain] || "unitMaxMs";
  const runtimeBudgetMs = cfg?.runtimeBudgets?.[budgetKey];
  return {
    domain,
    coverageMin: Number.isFinite(coverageMin) ? coverageMin : null,
    runtimeBudgetMs: Number.isFinite(runtimeBudgetMs) ? runtimeBudgetMs : null,
  };
}

// ─── Stack detection ──────────────────────────────────────────────────

/**
 * Detect the project stack by scanning for marker files. Cheap — only
 * `existsSync` calls. Returns one of: typescript, dotnet, python, go,
 * java, rust, or "unknown". Does NOT scan node_modules / .git / vendor.
 *
 * @param {string} projectDir
 * @returns {string} stack id
 */
function _hasDotnetMarker(dirPath) {
  try {
    return readdirSync(dirPath).some((f) =>
      f.endsWith(".csproj") || f.endsWith(".sln") || f.endsWith(".slnx") || f.endsWith(".fsproj") || f.endsWith(".vbproj")
    );
  } catch { return false; }
}

function _isSkipSubdir(name) {
  return name.startsWith(".") || name === "node_modules" || name === "bin" || name === "obj";
}

function _scanForDotnet(projectDir, dirEntries) {
  if (_hasDotnetMarker(projectDir)) return true;
  for (const sub of dirEntries) {
    try {
      const subPath = resolve(projectDir, sub);
      if (!statSync(subPath).isDirectory()) continue;
      if (_isSkipSubdir(sub)) continue;
      if (_hasDotnetMarker(subPath)) return true;
      const subEntries = readdirSync(subPath);
      for (const subSub of subEntries) {
        try {
          const subSubPath = resolve(subPath, subSub);
          if (!statSync(subSubPath).isDirectory()) continue;
          if (_isSkipSubdir(subSub)) continue;
          if (_hasDotnetMarker(subSubPath)) return true;
        } catch { /* not a directory or unreadable */ }
      }
    } catch { /* not a directory or unreadable */ }
  }
  return false;
}

export function detectStack(projectDir) {
  const has = (p) => existsSync(resolve(projectDir, p));

  const dirEntries = (() => {
    try { return readdirSync(projectDir); } catch { return []; }
  })();

  if (_scanForDotnet(projectDir, dirEntries)) return "dotnet";
  if (has("package.json") || has("tsconfig.json")) return "typescript";
  if (has("pyproject.toml") || has("setup.py") || has("setup.cfg") || has("requirements.txt")) {
    return "python";
  }
  if (has("go.mod")) return "go";
  if (has("Cargo.toml")) return "rust";
  if (has("pom.xml") || has("build.gradle") || has("build.gradle.kts")) return "java";
  return "unknown";
}

// ─── Coverage report location ─────────────────────────────────────────

/**
 * Find the first existing coverage report matching the stack.
 *
 * @param {string} projectDir
 * @param {string} stack
 * @returns {{ name, path, absPath, format, mtimeMs }|null}
 */
export function locateCoverageReport(projectDir, stack) {
  for (const entry of COVERAGE_REPORTS) {
    if (!entry.stacks.includes(stack)) continue;
    const abs = resolve(projectDir, entry.path);
    if (!existsSync(abs)) continue;
    let mtimeMs = 0;
    try { mtimeMs = statSync(abs).mtimeMs; } catch { /* ignore */ }
    return { name: entry.name, path: entry.path, absPath: abs, format: entry.format, mtimeMs };
  }
  return null;
}

// ─── Coverage parsers ─────────────────────────────────────────────────

/**
 * Parse an lcov.info file into per-file line coverage.
 * Format reference: http://ltp.sourceforge.net/coverage/lcov/geninfo.1.php
 *
 * We only extract what we need for a layer-level roll-up:
 *   - SF:<file>
 *   - LF:<total-lines-instrumented>
 *   - LH:<total-lines-hit>
 *   - end_of_record
 *
 * @param {string} content
 * @returns {Array<{ file, linesTotal, linesHit }>}
 */
export function parseLcov(content) {
  if (typeof content !== "string" || !content) return [];
  const records = [];
  let current = null;
  for (const rawLine of content.split(/\r?\n/)) {
    const line = rawLine.trim();
    if (!line) continue;
    if (line.startsWith("SF:")) {
      current = { file: line.slice(3), linesTotal: 0, linesHit: 0 };
    } else if (current && line.startsWith("LF:")) {
      current.linesTotal = parseInt(line.slice(3), 10) || 0;
    } else if (current && line.startsWith("LH:")) {
      current.linesHit = parseInt(line.slice(3), 10) || 0;
    } else if (line === "end_of_record") {
      if (current) records.push(current);
      current = null;
    }
  }
  return records;
}

/**
 * Parse Istanbul coverage-final.json into per-file line coverage.
 *
 * @param {string} content
 * @returns {Array<{ file, linesTotal, linesHit }>}
 */
export function parseIstanbulJson(content) {
  try {
    const data = JSON.parse(content);
    const out = [];
    for (const [file, entry] of Object.entries(data)) {
      if (!entry || typeof entry !== "object") continue;
      const statementMap = entry.s || {};
      let total = 0;
      let hit = 0;
      for (const count of Object.values(statementMap)) {
        total++;
        if (typeof count === "number" && count > 0) hit++;
      }
      out.push({ file, linesTotal: total, linesHit: hit });
    }
    return out;
  } catch {
    return [];
  }
}

/**
 * Parse Cobertura XML (used by .NET Coverlet and coverage.py).
 * Parser is deliberately small — we extract `<class filename="..." line-rate="0.82">`
 * entries with a regex to avoid pulling in an XML dep.
 *
 * @param {string} content
 * @returns {Array<{ file, linesTotal, linesHit }>}
 */
export function parseCobertura(content) {
  if (typeof content !== "string" || !content) return [];
  const out = [];
  // <class ... filename="..." ... line-rate="0.75" ...> with optional lines-covered / lines-valid
  const classRe = /<class\b([^>]*?)>/g;
  let match;
  while ((match = classRe.exec(content)) !== null) {
    const attrs = match[1];
    const filename = /filename="([^"]+)"/.exec(attrs)?.[1];
    if (!filename) continue;
    const lineRate = parseFloat(/line-rate="([^"]+)"/.exec(attrs)?.[1] || "0");
    const linesValid = parseInt(/lines-valid="([^"]+)"/.exec(attrs)?.[1] || "0", 10);
    const linesCovered = parseInt(/lines-covered="([^"]+)"/.exec(attrs)?.[1] || "0", 10);
    if (linesValid > 0) {
      out.push({ file: filename, linesTotal: linesValid, linesHit: linesCovered });
    } else if (Number.isFinite(lineRate)) {
      // fallback: we don't know the absolute counts, synthesise 100-scale
      out.push({ file: filename, linesTotal: 100, linesHit: Math.round(lineRate * 100) });
    }
  }
  return out;
}

/**
 * Parse JaCoCo XML — one `<counter type="LINE" covered=".." missed=".." />`
 * per `<class>` or per-file.
 *
 * @param {string} content
 * @returns {Array<{ file, linesTotal, linesHit }>}
 */
export function parseJacoco(content) {
  if (typeof content !== "string" || !content) return [];
  const out = [];
  // <class name="com/foo/Bar" sourcefilename="Bar.java">...<counter type="LINE" missed="5" covered="15"/>
  const classRe = /<class\b([^>]*?)>([\s\S]*?)<\/class>/g;
  let match;
  while ((match = classRe.exec(content)) !== null) {
    const attrs = match[1];
    const body = match[2];
    const sourcefilename = /sourcefilename="([^"]+)"/.exec(attrs)?.[1];
    const className = /name="([^"]+)"/.exec(attrs)?.[1];
    const file = sourcefilename || className || "";
    if (!file) continue;
    const lineCounter = /<counter\s+type="LINE"\s+missed="(\d+)"\s+covered="(\d+)"\s*\/>/.exec(body);
    if (!lineCounter) continue;
    const missed = parseInt(lineCounter[1], 10);
    const covered = parseInt(lineCounter[2], 10);
    out.push({ file, linesTotal: missed + covered, linesHit: covered });
  }
  return out;
}

/**
 * Parse go cover.out (mode: set|count|atomic). Format:
 *   mode: set
 *   path/to/file.go:3.23,5.10 2 1
 *
 * We sum coverage per file using the number of statements in each block
 * (third-to-last column) weighted by hit-count (last column).
 *
 * @param {string} content
 * @returns {Array<{ file, linesTotal, linesHit }>}
 */
export function parseGoCover(content) {
  if (typeof content !== "string" || !content) return [];
  const perFile = new Map();
  for (const rawLine of content.split(/\r?\n/)) {
    const line = rawLine.trim();
    if (!line || line.startsWith("mode:")) continue;
    // file.go:3.23,5.10 N C
    const m = /^(.+?):\d+\.\d+,\d+\.\d+\s+(\d+)\s+(\d+)$/.exec(line);
    if (!m) continue;
    const [, file, statementsStr, hitsStr] = m;
    const statements = parseInt(statementsStr, 10);
    const hits = parseInt(hitsStr, 10);
    if (!perFile.has(file)) perFile.set(file, { file, linesTotal: 0, linesHit: 0 });
    const rec = perFile.get(file);
    rec.linesTotal += statements;
    if (hits > 0) rec.linesHit += statements;
  }
  return [...perFile.values()];
}

/**
 * Parse coverage.py JSON format (`coverage json`).
 *
 * @param {string} content
 * @returns {Array<{ file, linesTotal, linesHit }>}
 */
export function parseCoveragePyJson(content) {
  try {
    const data = JSON.parse(content);
    const files = data.files || {};
    const out = [];
    for (const [file, entry] of Object.entries(files)) {
      const summary = entry?.summary || {};
      out.push({
        file,
        linesTotal: summary.num_statements || 0,
        linesHit: summary.covered_lines || 0,
      });
    }
    return out;
  } catch {
    return [];
  }
}

/**
 * Parse tarpaulin JSON (cargo-tarpaulin `--out Json`).
 *
 * @param {string} content
 * @returns {Array<{ file, linesTotal, linesHit }>}
 */
export function parseTarpaulin(content) {
  try {
    const data = JSON.parse(content);
    const files = data.files || [];
    return files.map((f) => ({
      file: (f.path || []).join("/") || f.file || "",
      linesTotal: f.coverable || 0,
      linesHit: f.covered || 0,
    }));
  } catch {
    return [];
  }
}

/**
 * Dispatch to the right parser for a format id.
 *
 * @param {string} format
 * @param {string} content
 * @returns {Array<{ file, linesTotal, linesHit }>}
 */
export function parseCoverage(format, content) {
  switch (format) {
    case "lcov": return parseLcov(content);
    case "istanbul-json": return parseIstanbulJson(content);
    case "cobertura": return parseCobertura(content);
    case "jacoco": return parseJacoco(content);
    case "go-cover": return parseGoCover(content);
    case "coverage-py-json": return parseCoveragePyJson(content);
    case "tarpaulin": return parseTarpaulin(content);
    default: return [];
  }
}

// ─── Layer classification ─────────────────────────────────────────────

/**
 * Classify a file path into a coverage layer (domain / integration /
 * controller / overall).
 *
 * Heuristic, not config — TEMPER-02 will promote this to a config
 * `layerGlobs` block. For now, we lean on conventional folder names so
 * the first-run experience "just works" on most codebases:
 *
 *   controllers/ routes/ handlers/ api/ endpoints/  → controller
 *   repositories/ repo/ data/ db/ database/ dal/    → integration
 *   services/ domain/ models/ entities/ logic/      → domain
 *   everything else                                 → overall (not double-counted)
 *
 * @param {string} file
 * @returns {"domain" | "integration" | "controller" | "overall"}
 */
export function classifyLayer(file) {
  if (typeof file !== "string" || !file) return "overall";
  const lower = file.toLowerCase().replace(/\\/g, "/");
  // controller-family
  if (/(^|\/)(controllers?|routes?|handlers?|api|endpoints?)(\/|$)/.test(lower)) {
    return "controller";
  }
  // integration-family (data access)
  if (/(^|\/)(repositories?|repo|data|db|database|dal|storage|persistence)(\/|$)/.test(lower)) {
    return "integration";
  }
  // domain-family (business logic)
  if (/(^|\/)(services?|domain|models?|entities?|logic|business|core)(\/|$)/.test(lower)) {
    return "domain";
  }
  return "overall";
}

/**
 * Roll up per-file coverage into per-layer percentages.
 *
 * @param {Array<{ file, linesTotal, linesHit }>} records
 * @returns {{ domain, integration, controller, overall, perFile }}
 */
export function rollupByLayer(records) {
  const agg = {
    domain: { total: 0, hit: 0, files: 0 },
    integration: { total: 0, hit: 0, files: 0 },
    controller: { total: 0, hit: 0, files: 0 },
    overall: { total: 0, hit: 0, files: 0 },
  };
  for (const rec of records) {
    const layer = classifyLayer(rec.file);
    agg[layer].total += rec.linesTotal;
    agg[layer].hit += rec.linesHit;
    agg[layer].files += 1;
    // overall always accumulates
    if (layer !== "overall") {
      agg.overall.total += rec.linesTotal;
      agg.overall.hit += rec.linesHit;
      agg.overall.files += 1;
    } else {
      // already counted in overall
    }
  }
  const pct = (a) => (a.total > 0 ? Math.round((a.hit / a.total) * 10000) / 100 : 0);
  return {
    domain: { percent: pct(agg.domain), ...agg.domain },
    integration: { percent: pct(agg.integration), ...agg.integration },
    controller: { percent: pct(agg.controller), ...agg.controller },
    overall: { percent: pct(agg.overall), ...agg.overall },
  };
}

/**
 * Compute gaps: (minimum - actual) per layer, with the files that pulled
 * each layer below minimum to the top of the list (sorted by lowest
 * coverage first). `records` is the parsed per-file coverage.
 *
 * @param {object} rollup
 * @param {object} coverageMinima
 * @param {Array<{ file, linesTotal, linesHit }>} records
 * @returns {Array<{ layer, minimum, actual, gap, files }>}
 */
export function computeGaps(rollup, coverageMinima, records) {
  const gaps = [];
  for (const layer of ["domain", "integration", "controller", "overall"]) {
    const minimum = coverageMinima?.[layer];
    if (typeof minimum !== "number") continue;
    // Skip layers with no instrumented lines — you can't fail a
    // minimum for code you don't have. TEMPER-02 will revisit this
    // once "missing layer" is itself a reportable signal.
    const layerRollup = rollup[layer];
    if (!layerRollup || layerRollup.total === 0) continue;
    const actual = layerRollup.percent ?? 0;
    if (actual >= minimum) continue;
    const gap = Math.round((minimum - actual) * 100) / 100;
    const layerFiles = (records || [])
      .filter((r) => classifyLayer(r.file) === layer && r.linesTotal > 0)
      .map((r) => ({
        file: r.file,
        percent: Math.round((r.linesHit / r.linesTotal) * 10000) / 100,
        linesTotal: r.linesTotal,
      }))
      .sort((a, b) => a.percent - b.percent)
      .slice(0, 10); // top-10 worst offenders
    gaps.push({ layer, minimum, actual, gap, files: layerFiles });
  }
  return gaps;
}

// ─── Scan-record IO ───────────────────────────────────────────────────

/**
 * List scan-record files by mtime desc. Returns empty array when the
 * directory or files are missing/unreadable.
 *
 * @param {string} projectDir
 * @returns {Array<{ name, absPath, mtimeMs }>}
 */
export function listScanRecords(projectDir) {
  const dir = resolve(projectDir, ".forge", "tempering");
  if (!existsSync(dir)) return [];
  let entries;
  try { entries = readdirSync(dir, { withFileTypes: true }); } catch { return []; }
  const out = [];
  for (const entry of entries) {
    if (!entry.isFile()) continue;
    if (!entry.name.startsWith("scan-")) continue;
    if (!entry.name.endsWith(".json")) continue;
    const absPath = resolve(dir, entry.name);
    try {
      const mtimeMs = statSync(absPath).mtimeMs;
      out.push({ name: entry.name, absPath, mtimeMs });
    } catch { /* ignore */ }
  }
  out.sort((a, b) => b.mtimeMs - a.mtimeMs);
  return out;
}

/**
 * Read and parse a single scan record. Returns null on any error.
 *
 * @param {string} absPath
 * @returns {object|null}
 */
export function readScanRecord(absPath) {
  try {
    return JSON.parse(readFileSync(absPath, "utf-8"));
  } catch {
    return null;
  }
}

// ─── Run record helpers (TEMPER-02) ───────────────────────────────────

/**
 * List all Tempering run records (`run-<ts>.json`), newest first.
 * Same contract as `listScanRecords` — used by the dashboard's slice-card
 * pill, the watcher, and `forge_smith` Tempering section.
 *
 * @param {string} projectDir
 * @returns {Array<{ name, absPath, mtimeMs }>}
 */
export function listRunRecords(projectDir) {
  const dir = resolve(projectDir, ".forge", "tempering");
  if (!existsSync(dir)) return [];
  let entries;
  try { entries = readdirSync(dir, { withFileTypes: true }); } catch { return []; }
  const out = [];
  for (const entry of entries) {
    if (!entry.isFile()) continue;
    if (!entry.name.startsWith("run-")) continue;
    if (!entry.name.endsWith(".json")) continue;
    const absPath = resolve(dir, entry.name);
    try {
      const mtimeMs = statSync(absPath).mtimeMs;
      out.push({ name: entry.name, absPath, mtimeMs });
    } catch { /* ignore */ }
  }
  out.sort((a, b) => b.mtimeMs - a.mtimeMs);
  return out;
}

/**
 * Read and parse a single run record. Returns null on any error —
 * same contract as `readScanRecord`.
 *
 * @param {string} absPath
 * @returns {object|null}
 */
export function readRunRecord(absPath) {
  try {
    return JSON.parse(readFileSync(absPath, "utf-8"));
  } catch {
    return null;
  }
}

// ─── Watcher snapshot helper ──────────────────────────────────────────

/**
 * Read the Tempering subsystem state for a watched project. Returns
 * null when `.forge/tempering/` does not exist so callers can cheaply
 * branch — same contract as readCrucibleState.
 *
 * Never throws. Bounded work: walks the tempering dir once, reads at
 * most the latest scan-record, stats remaining files for mtime.
 *
 * @param {string} targetPath - Absolute path to project being watched
 * @returns {object|null}
 */
function _readTemperingScanSummary(targetPath) {
  const records = listScanRecords(targetPath);
  const latest = records[0] || null;
  const latestScan = latest ? readScanRecord(latest.absPath) : null;
  const latestScanAgeMs = latest ? Date.now() - latest.mtimeMs : null;

  const latestStatus = latestScan?.status || null;
  const gaps = Array.isArray(latestScan?.coverageVsMinima)
    ? latestScan.coverageVsMinima.length
    : 0;
  const belowMinimum = Array.isArray(latestScan?.coverageVsMinima)
    ? latestScan.coverageVsMinima.filter((g) => g.gap >= 5).length
    : 0;
  const stale = latestScanAgeMs !== null
    ? latestScanAgeMs > TEMPERING_SCAN_STALE_DAYS * 24 * 60 * 60 * 1000
    : false;

  return {
    totalScans: records.length,
    latest,
    latestScanAgeMs,
    latestStatus,
    gaps,
    belowMinimum,
    stale,
  };
}

function _readTemperingRunSummary(targetPath) {
  const runRecords = listRunRecords(targetPath);
  const latestRunFile = runRecords[0] || null;
  const latestRun = latestRunFile ? readRunRecord(latestRunFile.absPath) : null;
  const latestRunVerdict = latestRun?.verdict || null;
  const latestRunAgeMs = latestRunFile ? Date.now() - latestRunFile.mtimeMs : null;
  const latestRunStack = latestRun?.stack || null;
  const runFailed = latestRunVerdict === "fail" || latestRunVerdict === "budget-exceeded" || latestRunVerdict === "error";

  return {
    totalRuns: runRecords.length,
    latestRunFile,
    latestRun,
    latestRunAgeMs,
    latestRunVerdict,
    latestRunStack,
    runFailed,
  };
}

function _collectContractAndScanners(latestRun) {
  let contractMismatch = 0;
  const latestScanners = {};
  const contractFrame = latestRun.scanners.find((s) => s && s.scanner === "contract");
  if (contractFrame) {
    contractMismatch = Array.isArray(contractFrame.violations)
      ? contractFrame.violations.length
      : (contractFrame.violationCount || 0);
  }
  for (const frame of latestRun.scanners) {
    if (frame && frame.scanner) {
      latestScanners[frame.scanner] = {
        verdict: frame.verdict || "skipped",
        pass: frame.pass || 0,
        fail: frame.fail || 0,
        durationMs: frame.durationMs || 0,
        violationCount: frame.violationCount || 0,
        reason: frame.reason || null,
      };
    }
  }
  return { contractMismatch, latestScanners };
}

function _collectMutationFlakyPerf(latestRun) {
  let mutationBelowMinimum = 0;
  let flakyCount = 0;
  let perfRegressionCount = 0;
  const mutationFrame = latestRun.scanners.find((s) => s && s.scanner === "mutation");
  if (mutationFrame && mutationFrame.verdict === "fail") {
    mutationBelowMinimum = Array.isArray(mutationFrame.layers)
      ? mutationFrame.layers.filter((l) => !l.pass).length
      : 1;
  }
  const flakinessFrame = latestRun.scanners.find((s) => s && s.scanner === "flakiness");
  if (flakinessFrame && flakinessFrame.fail > 0) {
    flakyCount = flakinessFrame.fail;
  }
  const perfFrame = latestRun.scanners.find((s) => s && s.scanner === "performance-budget");
  if (perfFrame && perfFrame.verdict === "fail") {
    perfRegressionCount = perfFrame.fail || 1;
  }
  return { mutationBelowMinimum, flakyCount, perfRegressionCount };
}

function _collectScannerMetrics(latestRun) {
  const empty = { contractMismatch: 0, latestScanners: {}, mutationBelowMinimum: 0, flakyCount: 0, perfRegressionCount: 0 };
  if (!latestRun || !Array.isArray(latestRun.scanners)) return empty;
  const a = _collectContractAndScanners(latestRun);
  const b = _collectMutationFlakyPerf(latestRun);
  return { ...a, ...b };
}

export function readTemperingState(targetPath) {
  const dir = resolve(targetPath, ".forge", "tempering");
  if (!existsSync(dir)) return null;

  const scanSummary = _readTemperingScanSummary(targetPath);
  const runSummary = _readTemperingRunSummary(targetPath);
  const scannerMetrics = _collectScannerMetrics(runSummary.latestRun);

  return {
    initialized: true,
    totalScans: scanSummary.totalScans,
    latestScanTs: scanSummary.latest ? new Date(scanSummary.latest.mtimeMs).toISOString() : null,
    latestScanAgeMs: scanSummary.latestScanAgeMs,
    latestStatus: scanSummary.latestStatus,
    gaps: scanSummary.gaps,
    belowMinimum: scanSummary.belowMinimum,
    stale: scanSummary.stale,
    staleCutoffDays: TEMPERING_SCAN_STALE_DAYS,
    totalRuns: runSummary.totalRuns,
    latestRunTs: runSummary.latestRunFile ? new Date(runSummary.latestRunFile.mtimeMs).toISOString() : null,
    latestRunAgeMs: runSummary.latestRunAgeMs,
    latestRunVerdict: runSummary.latestRunVerdict,
    latestRunStack: runSummary.latestRunStack,
    runFailed: runSummary.runFailed,
    contractMismatch: scannerMetrics.contractMismatch,
    latestScanners: scannerMetrics.latestScanners,
    mutationBelowMinimum: scannerMetrics.mutationBelowMinimum,
    flakyCount: scannerMetrics.flakyCount,
    perfRegressionCount: scannerMetrics.perfRegressionCount,
    openBugCount: readOpenBugCount(targetPath),
  };
}

/**
 * Read open bug counts from .forge/bugs/ — lightweight summary for watcher.
 * @param {string} targetPath
 * @returns {{ total: number, criticalOrHigh: number, unaddressed: Array<{ bugId: string, discoveredAt: string }> }}
 */
function readOpenBugCount(targetPath) {
  const bugsDir = resolve(targetPath, ".forge", "bugs");
  if (!existsSync(bugsDir)) return { total: 0, criticalOrHigh: 0, unaddressed: [] };

  const now = Date.now();
  const FOURTEEN_DAYS_MS = 14 * 24 * 60 * 60 * 1000;
  let total = 0;
  let criticalOrHigh = 0;
  const unaddressed = [];

  try {
    const files = readdirSync(bugsDir).filter(f => f.endsWith(".json"));
    for (const file of files) {
      try {
        const bug = JSON.parse(readFileSync(resolve(bugsDir, file), "utf-8"));
        if (bug.status !== "open") continue;
        total++;
        if (bug.severity === "critical" || bug.severity === "high") criticalOrHigh++;
        if (
          bug.classification === "real-bug" &&
          !bug.linkedFixPlan &&
          bug.discoveredAt &&
          (now - new Date(bug.discoveredAt).getTime()) > FOURTEEN_DAYS_MS
        ) {
          unaddressed.push({ bugId: bug.bugId, discoveredAt: bug.discoveredAt });
        }
      } catch { /* skip corrupt */ }
    }
  } catch { /* dir unreadable */ }

  // Cap unaddressed payload at 10
  return { total, criticalOrHigh, unaddressed: unaddressed.slice(0, 10) };
}

// ─── Hub event helper ─────────────────────────────────────────────────

function emit(hub, type, data) {
  if (!hub || typeof hub.broadcast !== "function") return;
  try {
    hub.broadcast({ type, data, timestamp: new Date().toISOString() });
  } catch { /* best-effort */ }
}

// ─── Handlers ─────────────────────────────────────────────────────────

/**
 * forge_tempering_scan — read-only coverage scan.
 *
 * 1. Ensure `.forge/tempering/` exists and config is seeded
 * 2. Detect stack
 * 3. Locate existing coverage report (lcov, cobertura, etc.)
 * 4. Parse it, roll up by layer, compute gaps vs. minima
 * 5. Write `.forge/tempering/scan-<ts>.json`
 * 6. Emit hub events (start + complete)
 *
 * @param {{ projectDir: string, hub?: object, correlationId?: string|null }} opts
 * @returns {object}
 */
export function handleScan({ projectDir, hub = null, correlationId = null }) {
  const corr = correlationId || `temper-scan-${randomUUID()}`;
  const startedAt = new Date().toISOString();

  // Seed dirs + config if first run
  const { dir, configWritten } = ensureTemperingDirs(projectDir);
  const config = readTemperingConfig(projectDir);

  emit(hub, "tempering-scan-started", {
    correlationId: corr,
    projectDir,
    configWritten,
  });

  const stack = detectStack(projectDir);
  const report = stack !== "unknown" ? locateCoverageReport(projectDir, stack) : null;

  let coverageRollup = null;
  let coverageGaps = [];
  let reportFormat = null;
  let reportPath = null;
  let fileCount = 0;
  let status = "green";
  let reason = null;

  if (!report) {
    status = "no-data";
    reason = stack === "unknown"
      ? "Could not detect project stack (no package.json / *.csproj / pyproject.toml / go.mod / Cargo.toml / pom.xml found)."
      : `No coverage report found for ${stack}. Generate one with your test runner's coverage flag (e.g. 'vitest --coverage', 'dotnet test --collect:"XPlat Code Coverage"', 'pytest --cov=. --cov-report=xml').`;
  } else {
    reportFormat = report.format;
    reportPath = report.path;
    let content = "";
    try {
      content = readFileSync(report.absPath, "utf-8");
    } catch (err) {
      status = "error";
      reason = `Failed to read coverage report at ${report.path}: ${err.message}`;
    }
    if (!reason) {
      const records = parseCoverage(report.format, content);
      fileCount = records.length;
      if (records.length === 0) {
        status = "error";
        reason = `Coverage report ${report.path} parsed to zero records (format: ${report.format}). It may be empty or malformed.`;
      } else {
        coverageRollup = rollupByLayer(records);
        coverageGaps = computeGaps(coverageRollup, config.coverageMinima, records);
        if (coverageGaps.some((g) => g.gap >= 5)) {
          status = "amber";
        }
        // No "red" from TEMPER-01 alone — red requires a failing test
        // run which lands in TEMPER-02.
      }
    }
  }

  const scanId = `scan-${startedAt.replace(/[:.]/g, "-")}`;
  const completedAt = new Date().toISOString();
  const scanRecord = {
    scanId,
    correlationId: corr,
    startedAt,
    completedAt,
    stack,
    report: report
      ? { path: reportPath, format: reportFormat, fileCount, mtimeMs: report.mtimeMs }
      : null,
    coverage: coverageRollup,
    // Phase TEMPER-01 Slice 01.2 — persist the minima snapshot alongside
    // the rollup so dashboards + downstream tooling can render a
    // coverage-vs-minima bar without re-reading config.json.
    coverageMinima: config.coverageMinima || null,
    coverageVsMinima: coverageGaps,
    status,
    reason,
    phase: "TEMPER-01",
  };

  // Persist the scan record — best-effort, never block the handler
  const outPath = resolve(dir, `${scanId}.json`);
  try {
    writeFileSync(outPath, JSON.stringify(scanRecord, null, 2) + "\n", "utf-8");
  } catch { /* best-effort */ }

  emit(hub, "tempering-scan-completed", {
    correlationId: corr,
    scanId,
    stack,
    status,
    gaps: coverageGaps.length,
    belowMinimum: coverageGaps.filter((g) => g.gap >= 5).length,
    reportPath,
  });

  return {
    ok: status !== "error",
    scanId,
    correlationId: corr,
    stack,
    status,
    reason,
    report: scanRecord.report,
    coverage: coverageRollup,
    coverageVsMinima: coverageGaps,
    scanRecordPath: outPath,
    configWritten,
  };
}

/**
 * forge_tempering_status — latest N scan summaries.
 *
 * @param {{ projectDir: string, limit?: number }} opts
 * @returns {object}
 */
export function handleStatus({ projectDir, limit = 10 }) {
  const safeLimit = Math.max(1, Math.min(100, Number.isFinite(limit) ? limit : 10));
  const records = listScanRecords(projectDir).slice(0, safeLimit);
  const summaries = records
    .map((r) => {
      const rec = readScanRecord(r.absPath);
      if (!rec) return null;
      return {
        scanId: rec.scanId,
        correlationId: rec.correlationId || null,
        completedAt: rec.completedAt,
        stack: rec.stack,
        status: rec.status,
        reason: rec.reason || null,
        gaps: Array.isArray(rec.coverageVsMinima) ? rec.coverageVsMinima.length : 0,
        belowMinimum: Array.isArray(rec.coverageVsMinima)
          ? rec.coverageVsMinima.filter((g) => g.gap >= 5).length
          : 0,
        coverage: rec.coverage
          ? {
              domain: rec.coverage.domain?.percent ?? 0,
              integration: rec.coverage.integration?.percent ?? 0,
              controller: rec.coverage.controller?.percent ?? 0,
              overall: rec.coverage.overall?.percent ?? 0,
            }
          : null,
        // Phase TEMPER-01 Slice 01.2 — surface the minima + the gap
        // report to the dashboard without needing a second tool call.
        // `files` arrays are already bounded top-10 by computeGaps.
        coverageMinima: rec.coverageMinima || null,
        coverageVsMinima: Array.isArray(rec.coverageVsMinima) ? rec.coverageVsMinima : [],
      };
    })
    .filter(Boolean);
  const state = readTemperingState(projectDir);
  return {
    ok: true,
    initialized: state !== null,
    state,
    scans: summaries,
  };
}

// ─── Phase-31 Slice 6: Suppression promoter ─────────────────────────────────

const SUPPRESSIONS_DIR = ".forge/tempering";
const SUPPRESSIONS_FILE = "suppressions.jsonl";
const BUGS_DIR = ".forge/bugs";
const PROMOTE_THRESHOLD_DEFAULT = 3;

/**
 * Read the promote threshold from .forge.json.
 * Returns runtime.tempering.promoteThreshold if it is a positive integer > 0,
 * otherwise returns defaultThreshold (default: 3).
 *
 * @param {string} cwd - Project root directory
 * @param {number} [defaultThreshold=3] - Fallback threshold
 * @returns {number}
 */
export function readPromoteThreshold(cwd, defaultThreshold = PROMOTE_THRESHOLD_DEFAULT) {
  try {
    const configPath = resolve(cwd, ".forge.json");
    if (!existsSync(configPath)) return defaultThreshold;
    const raw = JSON.parse(readFileSync(configPath, "utf-8"));
    const val = raw?.runtime?.tempering?.promoteThreshold;
    if (typeof val === "number" && Number.isInteger(val) && val > 0) return val;
    return defaultThreshold;
  } catch {
    return defaultThreshold;
  }
}

/**
 * Append one suppression record to .forge/tempering/suppressions.jsonl.
 *
 * @param {object} opts
 * @param {string} opts.cwd - Project root
 * @param {string} opts.fingerprint - Suppression fingerprint
 * @param {string} [opts.scanner="unit"] - Scanner name
 * @param {object} [opts.evidence={}] - Additional evidence (testName, etc.)
 * @param {string} [opts.runId] - Run identifier
 * @param {Function} [opts.nowFn] - Override for current timestamp (for testing)
 */
export function logSuppression({ cwd, fingerprint, scanner = "unit", evidence = {}, runId, nowFn }) {
  const dir = resolve(cwd, SUPPRESSIONS_DIR);
  mkdirSync(dir, { recursive: true });
  const record = {
    _v: 1,
    fingerprint,
    scanner,
    evidence,
    suppressedAt: (nowFn ? nowFn() : new Date().toISOString()),
    ...(runId !== undefined ? { runId } : {}),
  };
  appendFileSync(resolve(dir, SUPPRESSIONS_FILE), JSON.stringify(record) + "\n", "utf-8");
}

/**
 * Read all suppression records from .forge/tempering/suppressions.jsonl.
 * Malformed lines are silently skipped.
 *
 * @param {string} cwd - Project root
 * @returns {object[]}
 */
export function readSuppressions(cwd) {
  const filePath = resolve(cwd, SUPPRESSIONS_DIR, SUPPRESSIONS_FILE);
  if (!existsSync(filePath)) return [];
  const lines = readFileSync(filePath, "utf-8").split("\n").filter(Boolean);
  const records = [];
  for (const line of lines) {
    try { records.push(JSON.parse(line)); } catch { /* skip malformed */ }
  }
  return records;
}

/**
 * Generate a unique bug ID in the format bug-YYYY-MM-DD-NNN, where NNN is
 * one higher than the highest existing sequence number for that date.
 *
 * @param {string} bugsDir - Absolute path to .forge/bugs/
 * @param {string} datePart - e.g. "2026-04-22"
 * @returns {string}
 */
function nextBugId(bugsDir, datePart) {
  let max = 0;
  if (existsSync(bugsDir)) {
    for (const f of readdirSync(bugsDir)) {
      const m = f.match(new RegExp(`^bug-${datePart.replace(/-/g, "\\-")}-(\\d{3})\\.json$`));
      if (m) max = Math.max(max, parseInt(m[1], 10));
    }
  }
  return `bug-${datePart}-${String(max + 1).padStart(3, "0")}`;
}

/**
 * Promote recurring suppression groups into bug files.
 *
 * Groups suppression records by fingerprint. For each fingerprint with a
 * count >= effective threshold (read from .forge.json, falling back to the
 * `threshold` parameter), writes a JSON bug file to .forge/bugs/ unless one
 * already exists for that fingerprint.
 *
 * @param {object} opts
 * @param {string} opts.cwd - Project root
 * @param {number} [opts.threshold=3] - Default threshold (overridden by .forge.json)
 * @returns {{ ok: boolean, promoted: object[], skipped: object[] }}
 */
function _groupSuppressionsByFingerprint(records) {
  const groups = new Map();
  for (const rec of records) {
    if (!rec.fingerprint) continue;
    if (!groups.has(rec.fingerprint)) groups.set(rec.fingerprint, []);
    groups.get(rec.fingerprint).push(rec);
  }
  return groups;
}

function _loadExistingBugFingerprints(bugsDir) {
  const map = new Map();
  if (!existsSync(bugsDir)) return map;
  for (const f of readdirSync(bugsDir)) {
    if (!f.endsWith(".json") || f.startsWith(".")) continue;
    try {
      const data = JSON.parse(readFileSync(resolve(bugsDir, f), "utf-8"));
      if (data.fingerprint) map.set(data.fingerprint, data.bugId || f.replace(/\.json$/, ""));
    } catch { /* skip unreadable */ }
  }
  return map;
}

function _promoteSingleSuppression({ fingerprint, recs, bugsDir, datePart, now }) {
  const last = recs[recs.length - 1];
  const first = recs[0];

  mkdirSync(bugsDir, { recursive: true });
  const bugId = nextBugId(bugsDir, datePart);
  const bug = {
    bugId,
    fingerprint,
    source: "suppression-promoter",
    scanner: last.scanner || "unit",
    evidence: last.evidence || {},
    suppressionCount: recs.length,
    firstSeenAt: first.suppressedAt || now,
    lastSeenAt: last.suppressedAt || now,
    status: "open",
    promotedAt: now,
    classification: "real-bug",
    classifierMeta: { rule: "suppression-promoter" },
    severity: "medium",
    discoveredAt: first.suppressedAt || now,
    updatedAt: now,
  };

  const bugPath = resolve(bugsDir, `${bugId}.json`);
  try {
    writeFileSync(bugPath, JSON.stringify(bug, null, 2) + "\n", { flag: "wx", encoding: "utf-8" });
    return { ok: true, bugId };
  } catch {
    return { ok: false, bugId };
  }
}

export function promoteSuppressions({ cwd, threshold = PROMOTE_THRESHOLD_DEFAULT } = {}) {
  const effectiveThreshold = readPromoteThreshold(cwd, threshold);
  const records = readSuppressions(cwd);

  const groups = _groupSuppressionsByFingerprint(records);

  const bugsDir = resolve(cwd, BUGS_DIR);
  const promoted = [];
  const skipped = [];

  const existingByFingerprint = _loadExistingBugFingerprints(bugsDir);

  const now = new Date().toISOString();
  const datePart = now.slice(0, 10);

  for (const [fingerprint, recs] of groups) {
    const count = recs.length;
    if (count < effectiveThreshold) {
      skipped.push({ fingerprint, count, reason: "below-threshold" });
      continue;
    }

    if (existingByFingerprint.has(fingerprint)) {
      skipped.push({ fingerprint, count, reason: "already-exists", bugId: existingByFingerprint.get(fingerprint) });
      continue;
    }

    const res = _promoteSingleSuppression({ fingerprint, recs, bugsDir, datePart, now });
    if (res.ok) {
      promoted.push({ fingerprint, bugId: res.bugId, count });
      existingByFingerprint.set(fingerprint, res.bugId);
    } else {
      skipped.push({ fingerprint, count, reason: "already-exists", bugId: res.bugId });
    }
  }

  return { ok: true, promoted, skipped };
}

/**
 * Plan Forge — Tempering: Agent Router (Phase TEMPER-07 Slice 07.1)
 *
 * Routes tempering bugs to the appropriate agent/skill for read-only analysis.
 * All routing is deterministic — no LLM calls, no network IO.
 *
 * Design contracts:
 *   - deriveBugType is the LOCKED type-derivation contract (deterministic precedence).
 *   - resolveRoute is pure: null bug → null, no route → null + console.warn.
 *   - buildAnalystPrompt includes literal "do NOT edit files" (test-verifiable).
 *   - writeAnalystFinding uses atomic write (tmp + rename).
 *   - recordDelegation uses appendFileSync for crash-safe JSONL append.
 *   - loadAgentRoutingConfig returns { enabled: false } on any error.
 *
 * @module tempering/agent-router
 */

import { existsSync, mkdirSync, writeFileSync, readFileSync, appendFileSync, renameSync } from "node:fs";
import { resolve, dirname } from "node:path";

// ─── Routing Table ────────────────────────────────────────────────────

export const ROUTING_TABLE = Object.freeze({
  "security|critical":    { agent: "security",      skill: "security-audit" },
  "security|major":       { agent: "security",      skill: "security-audit" },
  "performance|critical": { agent: "performance",   skill: null },
  "performance|major":    { agent: "performance",   skill: null },
  "functional|critical":  { agent: "test-runner",   skill: "test-sweep" },
  "functional|major":     { agent: "test-runner",   skill: null },
  "contract|*":           { agent: "api-contracts", skill: "api-doc-gen" },
  "visual|*":             { agent: "accessibility", skill: null },
});

// ─── Scanner → Bug Type Mapping ──────────────────────────────────────

const SCANNER_TYPE_MAP = Object.freeze({
  contract:             "contract",
  "visual-diff":        "visual",
  "performance-budget": "performance",
  "load-stress":        "performance",
  unit:                 "functional",
  integration:          "functional",
  "ui-playwright":      "functional",
  mutation:             "functional",
  flakiness:            "functional",
});

// ─── deriveBugType ───────────────────────────────────────────────────
/**
 * Deterministic bug-type derivation with strict precedence:
 *   1. bug.type (explicit field) — preferred, future-proof
 *   2. bug.classifierMeta.bugType
 *   3. Map from bug.scanner via SCANNER_TYPE_MAP
 *   4. null if unmappable
 *
 * @param {object} bug
 * @returns {string|null}
 */
export function deriveBugType(bug) {
  if (!bug) return null;
  if (typeof bug.type === "string" && bug.type) return bug.type;
  if (bug.classifierMeta?.bugType && typeof bug.classifierMeta.bugType === "string") {
    return bug.classifierMeta.bugType;
  }
  if (typeof bug.scanner === "string" && SCANNER_TYPE_MAP[bug.scanner]) {
    return SCANNER_TYPE_MAP[bug.scanner];
  }
  return null;
}

// ─── resolveRoute ────────────────────────────────────────────────────
/**
 * Pure route resolution. Tries `${type}|${severity}` then `${type}|*`.
 *
 * @param {object} bug - Must have severity; type derived via deriveBugType.
 * @returns {{ agent: string, skill: string|null }|null}
 */
export function resolveRoute(bug) {
  if (!bug) return null;
  const type = deriveBugType(bug);
  if (!type) return null;
  const severity = bug.severity || "medium";

  const exact = ROUTING_TABLE[`${type}|${severity}`];
  if (exact) return { ...exact };

  const wildcard = ROUTING_TABLE[`${type}|*`];
  if (wildcard) return { ...wildcard };

  console.warn(`[agent-router] No route for bugId=${bug.bugId || "?"} type=${type} severity=${severity}`);
  return null;
}

// ─── buildAnalystPrompt ──────────────────────────────────────────────
/**
 * Builds a structured read-only analysis prompt for the routed agent.
 * MUST include literal phrase "do NOT edit files" (test-verifiable).
 *
 * @param {object} bug
 * @param {{ agent: string, skill: string|null }} route
 * @returns {string}
 */
export function buildAnalystPrompt(bug, route) {
  const lines = [
    `## Agent Analysis Request`,
    ``,
    `**IMPORTANT: This is a read-only analysis. You MUST do NOT edit files.**`,
    ``,
    `**Bug ID:** ${bug.bugId || "unknown"}`,
    `**Scanner:** ${bug.scanner || "unknown"}`,
    `**Severity:** ${bug.severity || "unknown"}`,
    `**Agent:** ${route.agent}`,
  ];
  if (route.skill) {
    lines.push(`**Skill:** ${route.skill}`);
  }
  lines.push(``);
  if (bug.evidence) {
    lines.push(`### Evidence`);
    if (bug.evidence.testName) lines.push(`- **Test:** ${bug.evidence.testName}`);
    if (bug.evidence.assertionMessage) lines.push(`- **Assertion:** ${bug.evidence.assertionMessage}`);
    if (bug.evidence.stackTrace) lines.push(`- **Stack:** \`${bug.evidence.stackTrace.split("\n")[0]}\``);
    lines.push(``);
  }
  if (bug.affectedFiles?.length) {
    lines.push(`### Affected Files`);
    for (const f of bug.affectedFiles) lines.push(`- ${f}`);
    lines.push(``);
  }
  if (bug.reproSteps?.length) {
    lines.push(`### Reproduction Steps`);
    for (const s of bug.reproSteps) lines.push(`- ${s}`);
    lines.push(``);
  }
  lines.push(`### Instructions`);
  lines.push(`Analyze this bug from the perspective of the **${route.agent}** agent.`);
  lines.push(`Provide root-cause analysis, impact assessment, and recommended fix strategy.`);
  return lines.join("\n");
}

// ─── writeAnalystFinding ─────────────────────────────────────────────
/**
 * Atomic write of analyst finding to `.forge/tempering/findings/<bugId>.json`.
 *
 * @param {string} targetPath - Project root (cwd)
 * @param {object} bug
 * @param {{ agent: string, skill: string|null }} route
 * @param {*} finding - Free-form finding payload from agent analysis
 */
export function writeAnalystFinding(targetPath, bug, route, finding) {
  const dir = resolve(targetPath, ".forge", "tempering", "findings");
  mkdirSync(dir, { recursive: true });

  const record = {
    _v: 1,
    bugId: bug.bugId,
    agent: route.agent,
    skill: route.skill || null,
    finding,
    createdAt: new Date().toISOString(),
  };

  const finalPath = resolve(dir, `${bug.bugId}.json`);
  const tmpPath = resolve(dir, `.${bug.bugId}.tmp`);
  writeFileSync(tmpPath, JSON.stringify(record, null, 2) + "\n", "utf-8");
  try {
    renameSync(tmpPath, finalPath);
  } catch {
    writeFileSync(finalPath, JSON.stringify(record, null, 2) + "\n", "utf-8");
  }
}

// ─── recordDelegation ────────────────────────────────────────────────
/**
 * Append a delegation record to `.forge/tempering/delegations.jsonl`.
 *
 * @param {string} targetPath - Project root (cwd)
 * @param {string} bugId
 * @param {{ agent: string, skill: string|null }} route
 * @param {string} mode - "analyst" | "review-queue-item"
 * @param {string|null} reviewItemId
 */
export function recordDelegation({ targetPath, bugId, route, mode, reviewItemId }) {
  const dir = resolve(targetPath, ".forge", "tempering");
  mkdirSync(dir, { recursive: true });

  const record = {
    _v: 1,
    bugId,
    agent: route.agent,
    skill: route.skill || null,
    mode,
    reviewItemId: reviewItemId || null,
    timestamp: new Date().toISOString(),
  };

  appendFileSync(
    resolve(dir, "delegations.jsonl"),
    JSON.stringify(record) + "\n",
    "utf-8",
  );
}

// ─── loadAgentRoutingConfig ──────────────────────────────────────────
/**
 * Reads `.forge/tempering/config.json` and returns `config.agentRouting`.
 * Returns `{ enabled: false }` on missing file, malformed JSON, or missing key.
 *
 * @param {string} targetPath - Project root (cwd)
 * @returns {{ enabled: boolean, [key: string]: any }}
 */
export function loadAgentRoutingConfig(targetPath) {
  try {
    const configPath = resolve(targetPath, ".forge", "tempering", "config.json");
    if (!existsSync(configPath)) return { enabled: false };
    const raw = readFileSync(configPath, "utf-8");
    const parsed = JSON.parse(raw);
    return parsed?.agentRouting || { enabled: false };
  } catch {
    return { enabled: false };
  }
}

// ─── Phase FORGE-SHOP-06 Slice 06.2 — Delegate Sync Responder ───────

/**
 * Register the `tempering.delegate-sync` hub responder.
 * Looks up a bug by ID, resolves its route, builds the analyst prompt,
 * and records the delegation. Returns the prompt and routing info.
 *
 * @param {object} hub - Hub instance with onAsk
 * @param {string} cwd - Project root
 * @param {object} [deps] - DI overrides: { readForgeJsonl }
 */
export function registerDelegateSyncResponder(hub, cwd, deps = {}) {
  const _readJsonl = deps.readForgeJsonl || ((filePath, defaultValue = []) => {
    const fullPath = resolve(cwd, ".forge", filePath);
    try {
      if (existsSync(fullPath)) {
        return readFileSync(fullPath, "utf-8")
          .split("\n")
          .filter((line) => line.trim())
          .map((line) => JSON.parse(line));
      }
      return defaultValue;
    } catch { return defaultValue; }
  });

  hub.onAsk("tempering.delegate-sync", async (payload) => {
    const { bugId } = payload || {};
    if (!bugId) {
      return { ok: false, error: "missing-bugId" };
    }

    const bugs = _readJsonl("tempering/bugs.jsonl", []);
    const bug = bugs.find((b) => b.bugId === bugId);
    if (!bug) {
      return { ok: false, error: "bug-not-found" };
    }

    const route = resolveRoute(bug);
    if (!route) {
      return { ok: false, error: "no-route", bugId };
    }

    const prompt = buildAnalystPrompt(bug, route);
    recordDelegation({ targetPath: cwd, bugId: bugId, route: route, mode: "sync-ask", reviewItemId: null });

    return {
      ok: true,
      prompt,
      bugId,
      agent: route.agent,
      skill: route.skill,
    };
  });
}

/**
 * Tempering artifact lifecycle (TEMPER-03 Slice 03.1).
 *
 * Tempering runs that capture non-text output (screenshots, HAR files,
 * a11y JSON reports, later visual-diff images) write under
 * `.forge/tempering/artifacts/<runId>/`. This module owns the
 * directory shape, deterministic URL-to-filename hashing, and
 * retention GC. Kept separate from `runner.mjs` so scanners in later
 * phases (visual diff, load, mutation) can reuse the same primitives
 * without dragging runner orchestration into their test matrix.
 *
 * Design constraints:
 *   - Artifact directories are never committed to git — `.gitignore`
 *     entry is seeded by the Tempering subsystem, not here
 *   - Never throws on filesystem errors — returns best-effort results
 *     so a scanner that can't write a screenshot doesn't kill a run
 *   - Pure functions of (projectDir, runId, now) so tests don't need
 *     the real clock
 */
import { existsSync, mkdirSync, readdirSync, rmSync, statSync, readFileSync, writeFileSync, appendFileSync } from "node:fs";
import { resolve } from "node:path";
import { createHash } from "node:crypto";

/**
 * Default retention for run artifacts — anything older than this
 * window is eligible for GC. Matches the `bugRegistry` + coverage
 * retention cadence documented in TEMPER-ARC so operators only have
 * one mental model of "how long does Tempering keep data".
 */
export const DEFAULT_ARTIFACT_RETENTION_DAYS = 7;

/**
 * Canonical per-run artifact directory. All scanners write under
 * `<projectDir>/.forge/tempering/artifacts/<runId>/<scanner>/…`.
 *
 * @param {string} projectDir
 * @param {string} runId
 * @returns {string}
 */
export function getArtifactDir(projectDir, runId) {
  return resolve(projectDir, ".forge", "tempering", "artifacts", runId);
}

/**
 * Per-scanner subdirectory under the run's artifact root. Scanners
 * shouldn't hand-roll path joins — they get a directory they own.
 *
 * @param {string} projectDir
 * @param {string} runId
 * @param {string} scanner
 * @returns {string}
 */
export function getScannerArtifactDir(projectDir, runId, scanner) {
  return resolve(getArtifactDir(projectDir, runId), scanner);
}

/**
 * Ensure the scanner's artifact directory exists. Returns the
 * absolute path on success; returns `null` if the directory can't be
 * created (read-only FS, permissions). Callers should fall back to
 * "no artifact written" rather than failing the run.
 *
 * @param {string} projectDir
 * @param {string} runId
 * @param {string} scanner
 * @returns {string|null}
 */
export function ensureScannerArtifactDir(projectDir, runId, scanner) {
  const dir = getScannerArtifactDir(projectDir, runId, scanner);
  try {
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
    return dir;
  } catch {
    return null;
  }
}

/**
 * Deterministic, filesystem-safe filename derived from a URL. Uses
 * sha1 truncated to 16 hex chars — collision probability for the
 * ≤ maxPages=100 URLs a single sweep will visit is astronomically
 * small, and the shortened hash keeps filenames scannable.
 *
 * @param {string} url
 * @returns {string}
 */
export function hashUrl(url) {
  return createHash("sha1").update(String(url || "")).digest("hex").slice(0, 16);
}

/**
 * Retention GC — remove any per-run artifact directory older than
 * `retentionDays`. Best-effort; a locked or vanished directory is
 * silently skipped because a failed GC is never worse than a full
 * disk (operators can always clear `.forge/tempering/artifacts/` by
 * hand).
 *
 * @param {object} params
 * @param {string} params.projectDir
 * @param {number} [params.retentionDays=DEFAULT_ARTIFACT_RETENTION_DAYS]
 * @param {Function} [params.now=Date.now]
 * @returns {{ removed: string[], kept: string[] }}
 */
export function gcArtifacts({
  projectDir,
  retentionDays = DEFAULT_ARTIFACT_RETENTION_DAYS,
  now = Date.now,
} = {}) {
  const root = resolve(projectDir, ".forge", "tempering", "artifacts");
  const removed = [];
  const kept = [];
  if (!existsSync(root)) return { removed, kept };

  const cutoff = now() - retentionDays * 24 * 60 * 60 * 1000;
  let entries;
  try { entries = readdirSync(root, { withFileTypes: true }); } catch { return { removed, kept }; }

  for (const entry of entries) {
    if (!entry.isDirectory()) continue;
    const abs = resolve(root, entry.name);
    let mtimeMs = 0;
    try { mtimeMs = statSync(abs).mtimeMs; } catch { continue; }
    if (mtimeMs < cutoff) {
      try {
        rmSync(abs, { recursive: true, force: true });
        removed.push(entry.name);
      } catch { /* ignore, GC is best-effort */ }
    } else {
      kept.push(entry.name);
    }
  }
  return { removed, kept };
}

/**
 * Append the artifacts directory to the project's `.gitignore` if not
 * already present. Called once when a Tempering run produces its
 * first artifact so users don't accidentally commit screenshots. The
 * append is idempotent — reading the file line-by-line and checking
 * for the entry avoids duplicate appends.
 *
 * @param {string} projectDir
 * @param {object} [fs]
 * @returns {boolean} true when a new entry was appended
 */
export function seedArtifactsGitignore(projectDir) {
  const gitignore = resolve(projectDir, ".gitignore");
  const entry = ".forge/tempering/artifacts/";
  try {
    if (!existsSync(gitignore)) {
      writeFileSync(gitignore, `${entry}\n`, "utf-8");
      return true;
    }
    const current = readFileSync(gitignore, "utf-8");
    const lines = current.split(/\r?\n/).map((l) => l.trim());
    if (lines.includes(entry) || lines.includes(entry.replace(/\/$/, ""))) return false;
    const suffix = current.endsWith("\n") ? "" : "\n";
    appendFileSync(gitignore, `${suffix}${entry}\n`, "utf-8");
    return true;
  } catch {
    return false;
  }
}

/**
 * Audit-loop activation surface — off / auto / always (Phase-39 Slice 7).
 *
 * Provides:
 *   - `AUDIT_DEFAULTS` — frozen default config (mode: "off")
 *   - `loadAuditConfig(cwd)` — reads `.forge.json#audit`, merges with defaults
 *   - `saveAuditConfig(cwd, patch)` — persists audit config to `.forge.json`
 *   - `shouldAutoDrain(planContext)` — threshold evaluator for "auto" mode
 *
 * Design contracts:
 *   - Never throws — returns safe defaults on any error
 *   - `forbidProduction` is immutable — cannot be overridden at runtime
 *   - Config source of truth is `.forge.json#audit`
 *   - Gate-compatible: the literal `"mode": "off"` appears in AUDIT_DEFAULTS
 *
 * @module tempering/auto-activate
 */

import { existsSync, readFileSync, writeFileSync } from "node:fs";
import { resolve } from "node:path";

// ─── Default config ──────────────────────────────────────────────────

/**
 * Default audit activation config. `"mode": "off"` is the safe default.
 * The string `"mode": "off"` must remain as a JSON-compatible literal
 * for gate validation (`grep -q '"mode": *"off"'`).
 */
export const AUDIT_DEFAULTS = Object.freeze({
  "mode": "off",
  maxRounds: 5,
  forbidProduction: true,
  autoThresholds: Object.freeze({
    minFilesChanged: 5,
    minDaysSinceLastDrain: 3,
    requireFindings: true,
  }),
  environments: Object.freeze(["dev", "staging"]),
});

// ─── Config loader ───────────────────────────────────────────────────

/**
 * Load audit config from `.forge.json#audit`. Never throws.
 *
 * @param {string} cwd — project root
 * @returns {object} merged config with `_source` stamp
 */
export function loadAuditConfig(cwd) {
  const configPath = resolve(cwd, ".forge.json");
  if (!existsSync(configPath)) {
    return { ...AUDIT_DEFAULTS, _source: "defaults" };
  }
  try {
    const raw = readFileSync(configPath, "utf-8");
    const parsed = JSON.parse(raw);
    if (!parsed.audit || typeof parsed.audit !== "object") {
      return { ...AUDIT_DEFAULTS, _source: "defaults" };
    }
    const merged = { ...AUDIT_DEFAULTS, ...parsed.audit };
    // forbidProduction is immutable — always true
    merged.forbidProduction = true;
    merged._source = "file";
    return merged;
  } catch {
    return { ...AUDIT_DEFAULTS, _source: "defaults-fallback" };
  }
}

// ─── Config saver ────────────────────────────────────────────────────

/**
 * Persist audit config to `.forge.json#audit`. Merges with existing
 * `.forge.json` content. Never throws — returns `{ ok, error? }`.
 *
 * @param {string} cwd — project root
 * @param {object} patch — partial audit config to merge
 * @returns {{ ok: boolean, config?: object, error?: string }}
 */
export function saveAuditConfig(cwd, patch) {
  try {
    const configPath = resolve(cwd, ".forge.json");
    let existing = {};
    if (existsSync(configPath)) {
      try {
        existing = JSON.parse(readFileSync(configPath, "utf-8"));
      } catch {
        existing = {};
      }
    }
    const current = existing.audit && typeof existing.audit === "object"
      ? existing.audit
      : {};
    const merged = { ...AUDIT_DEFAULTS, ...current, ...patch };
    // forbidProduction is immutable
    merged.forbidProduction = true;
    delete merged._source;
    existing.audit = merged;
    writeFileSync(configPath, JSON.stringify(existing, null, 2) + "\n", "utf-8");
    return { ok: true, config: { ...merged, _source: "file" } };
  } catch (err) {
    return { ok: false, error: err.message };
  }
}

// ─── Threshold evaluator ────────────────────────────────────────────

/**
 * Evaluate whether an automatic drain should fire based on plan context
 * and change-surface signals.
 *
 * Returns `{ fire: boolean, signals: object }` — never just a boolean,
 * so callers can log/display the decision reasoning.
 *
 * @param {object} planContext
 * @param {string}   planContext.cwd — project root
 * @param {object}   [planContext.config] — pre-loaded audit config (skips re-read)
 * @param {number}   [planContext.filesChanged] — number of files changed in the plan run
 * @param {number}   [planContext.lastDrainTs] — epoch ms of last drain (0 = never)
 * @param {string}   [planContext.lastVerdict] — verdict from last drain ("converged"|"max-rounds"|etc.)
 * @param {number}   [planContext.recentFindingCount] — findings from most recent tempering run
 * @param {string}   [planContext.env] — current environment
 * @param {Function} [planContext.now] — injectable clock
 * @returns {{ fire: boolean, signals: object }}
 */
function autoDrainModeResponse(mode, fire, extra = {}) {
  return { fire, signals: { mode, ...extra } };
}

function isProductionBlocked(config, env) {
  return config.forbidProduction && env === "production";
}

function evaluateAutoDrainSignals({ filesChanged, lastDrainTs, lastVerdict, recentFindingCount, thresholds, now }) {
  const currentMs = now();
  const daysSinceLastDrain = lastDrainTs > 0
    ? (currentMs - lastDrainTs) / (1000 * 60 * 60 * 24)
    : Infinity;
  const filesSignal = filesChanged >= thresholds.minFilesChanged;
  const daysSignal = daysSinceLastDrain >= thresholds.minDaysSinceLastDrain;
  const findingsSignal = !thresholds.requireFindings || recentFindingCount > 0;
  const verdictSignal = lastVerdict !== "converged";
  return {
    filesSignal,
    daysSignal,
    findingsSignal,
    verdictSignal,
    signals: {
      filesChanged,
      filesThreshold: thresholds.minFilesChanged,
      daysSinceLastDrain: Math.round(daysSinceLastDrain * 10) / 10,
      daysThreshold: thresholds.minDaysSinceLastDrain,
      recentFindingCount,
      requireFindings: thresholds.requireFindings,
      lastVerdict,
    },
  };
}

function buildAutoDrainDecision(evaluated) {
  const fire = (evaluated.filesSignal || evaluated.daysSignal)
    && evaluated.findingsSignal
    && evaluated.verdictSignal;
  return {
    fire,
    decision: {
      filesSignal: evaluated.filesSignal,
      daysSignal: evaluated.daysSignal,
      findingsSignal: evaluated.findingsSignal,
      verdictSignal: evaluated.verdictSignal,
    },
    reason: fire ? "threshold signals tripped" : "no drain signals tripped",
  };
}

export function shouldAutoDrain(planContext = {}) {
  const {
    cwd = process.cwd(),
    config: preloadedConfig,
    filesChanged = 0,
    lastDrainTs = 0,
    lastVerdict = null,
    recentFindingCount = 0,
    env = "dev",
    now = () => Date.now(),
  } = planContext;

  const config = preloadedConfig || loadAuditConfig(cwd);
  if (config.mode === "off") {
    return autoDrainModeResponse("off", false, { reason: "audit-loop disabled" });
  }
  if (config.mode === "always") {
    if (isProductionBlocked(config, env)) {
      return autoDrainModeResponse("always", false, { blocked: true, reason: "production-forbidden" });
    }
    return autoDrainModeResponse("always", true, { reason: "always-mode active" });
  }

  const thresholds = config.autoThresholds || AUDIT_DEFAULTS.autoThresholds;
  if (isProductionBlocked(config, env)) {
    return autoDrainModeResponse("auto", false, { blocked: true, reason: "production-forbidden" });
  }

  const allowedEnvs = config.environments || AUDIT_DEFAULTS.environments;
  if (!allowedEnvs.includes(env)) {
    return autoDrainModeResponse("auto", false, { envBlocked: true, reason: `env '${env}' not in allowed list` });
  }

  const evaluated = evaluateAutoDrainSignals({
    filesChanged,
    lastDrainTs,
    lastVerdict,
    recentFindingCount,
    thresholds,
    now,
  });
  const decision = buildAutoDrainDecision(evaluated);

  return autoDrainModeResponse("auto", decision.fire, {
    ...evaluated.signals,
    decision: decision.decision,
    reason: decision.reason,
  });
}

/**
 * Tempering baselines — storage, promotion, diff helpers (TEMPER-04 Slice 04.1).
 *
 * Baselines are the "expected" screenshots that the visual-diff scanner
 * compares against. They live under `.forge/tempering/baselines/` with
 * one PNG per URL hash and a JSON sidecar recording promotion metadata.
 *
 * @module tempering/baselines
 */
import { existsSync, mkdirSync, readFileSync, writeFileSync, readdirSync, statSync, copyFileSync } from "node:fs";
import { resolve, relative, normalize } from "node:path";
import { createHash } from "node:crypto";
import { PNG } from "pngjs";
import pixelmatch from "pixelmatch";
import { hashUrl } from "./artifacts.mjs";

// Re-export for convenience — scanners import from baselines.mjs
export { hashUrl };

// ─── Directories ──────────────────────────────────────────────────────

function baselinesDir(cwd) {
  return resolve(cwd, ".forge", "tempering", "baselines");
}

function artifactsDir(cwd) {
  return resolve(cwd, ".forge", "tempering", "artifacts");
}

// ─── Path safety ──────────────────────────────────────────────────────

function assertSafePath(target, root) {
  const norm = normalize(resolve(target));
  const normRoot = normalize(resolve(root));
  if (!norm.startsWith(normRoot)) {
    throw new Error(`Path traversal rejected: ${target}`);
  }
}

// ─── Public API ───────────────────────────────────────────────────────

/**
 * List all baselines currently stored.
 * @param {string} cwd — project root
 * @returns {Array<{urlHash: string, path: string, updatedAt: string|null}>}
 */
export function listBaselines(cwd) {
  const dir = baselinesDir(cwd);
  if (!existsSync(dir)) return [];
  const results = [];
  try {
    for (const entry of readdirSync(dir)) {
      if (!entry.endsWith(".png")) continue;
      const urlHash = entry.replace(/\.png$/, "");
      const fullPath = resolve(dir, entry);
      let updatedAt = null;
      try { updatedAt = statSync(fullPath).mtime.toISOString(); } catch { /* best-effort */ }
      results.push({ urlHash, path: fullPath, updatedAt });
    }
  } catch { /* dir unreadable */ }
  return results;
}

/**
 * Read a baseline PNG buffer by URL hash.
 * @param {string} urlHash
 * @param {string} cwd
 * @returns {Buffer|null}
 */
export function getBaseline(urlHash, cwd) {
  const dir = baselinesDir(cwd);
  const target = resolve(dir, `${urlHash}.png`);
  assertSafePath(target, dir);
  if (!existsSync(target)) return null;
  return readFileSync(target);
}

/**
 * Read the TEMPER-03 screenshot manifest.
 * @param {string} cwd
 * @returns {Array<{url: string, urlHash: string, path: string}>|null}
 */
export function getScreenshotManifest(cwd) {
  const candidates = [
    resolve(cwd, ".forge", "tempering", "screenshot-manifest.json"),
  ];
  for (const p of candidates) {
    if (!existsSync(p)) continue;
    try {
      const raw = JSON.parse(readFileSync(p, "utf-8"));
      if (!Array.isArray(raw)) continue;
      return raw.map((entry) => ({
        url: entry.url,
        urlHash: entry.urlHash || hashUrl(entry.url),
        path: entry.path || entry.screenshotPath || null,
      }));
    } catch { continue; }
  }
  return null;
}

/**
 * Promote the current screenshot for a URL to the baselines directory.
 * Idempotent — re-promoting the same content overwrites + updates sidecar.
 *
 * @param {object} opts
 * @param {string} [opts.urlHash]
 * @param {string} [opts.url]
 * @param {string} [opts.runId]
 * @param {string} [opts.screenshotPath] — explicit path to promote
 * @param {string} cwd
 * @returns {{ok: boolean, urlHash: string, baselinePath: string, sidecarPath: string, previousHash?: string}}
 */
function listArtifactRuns(artRoot) {
  return readdirSync(artRoot)
    .filter((d) => {
      if (!d.startsWith("run-")) return false;
      try { return statSync(resolve(artRoot, d)).isDirectory(); } catch { return false; }
    })
    .map((d) => ({ name: d, mtimeMs: statSync(resolve(artRoot, d)).mtimeMs }))
    .sort((a, b) => b.mtimeMs - a.mtimeMs)
    .map((entry) => entry.name);
}

function findScreenshotToPromote(cwd, urlHash, runId, screenshotPath) {
  if (screenshotPath) return screenshotPath;
  const artRoot = artifactsDir(cwd);
  if (!existsSync(artRoot)) return null;
  for (const run of listArtifactRuns(artRoot)) {
    if (runId && run !== runId) continue;
    for (const scanner of ["ui-playwright", "visual-diff"]) {
      const candidate = resolve(artRoot, run, scanner, `${urlHash}.png`);
      if (existsSync(candidate)) return candidate;
    }
  }
  return null;
}

function readPreviousBaselineHash(baselinePath) {
  if (!existsSync(baselinePath)) return null;
  try {
    return createHash("sha256").update(readFileSync(baselinePath)).digest("hex").slice(0, 16);
  } catch {
    return null;
  }
}

function writeBaselineSidecar(sidecarPath, sidecar) {
  writeFileSync(sidecarPath, JSON.stringify(sidecar, null, 2) + "\n", "utf-8");
}

export function promoteBaseline(opts, cwd) {
  const { url, runId, screenshotPath } = opts || {};
  const urlHash = opts?.urlHash || (url ? hashUrl(url) : null);
  if (!urlHash) throw new Error("INVALID_URL_HASH: urlHash or url required");

  const dir = baselinesDir(cwd);
  const baselinePath = resolve(dir, `${urlHash}.png`);
  assertSafePath(baselinePath, dir);

  const srcPath = findScreenshotToPromote(cwd, urlHash, runId, screenshotPath);
  if (!srcPath || !existsSync(srcPath)) {
    throw new Error(`NO_SCREENSHOT: No screenshot found for hash ${urlHash}`);
  }

  const previousHash = readPreviousBaselineHash(baselinePath);
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
  copyFileSync(srcPath, baselinePath);

  const sidecarPath = resolve(dir, `${urlHash}.json`);
  writeBaselineSidecar(sidecarPath, {
    urlHash,
    url: url || null,
    promotedAt: new Date().toISOString(),
    promotedBy: "forge_tempering_approve_baseline",
    previousHash,
    runId: runId || null,
    sourcePath: srcPath,
  });

  return { ok: true, urlHash, baselinePath, sidecarPath, previousHash };
}

/**
 * Pixel-diff two PNG buffers using pixelmatch + pngjs.
 *
 * @param {Buffer} baselineBuf
 * @param {Buffer} currentBuf
 * @param {object} [opts]
 * @param {number} [opts.threshold=0.1] — pixelmatch color distance threshold
 * @returns {{diffPercent: number, diffPixels: number, totalPixels: number, diffBuffer: Buffer, width: number, height: number}}
 */
export function diffImages(baselineBuf, currentBuf, opts = {}) {
  const baseline = PNG.sync.read(baselineBuf);
  const current = PNG.sync.read(currentBuf);

  // Normalize dimensions — resize current to baseline if mismatch
  let currentData = current.data;
  let width = baseline.width;
  let height = baseline.height;

  if (current.width !== baseline.width || current.height !== baseline.height) {
    const resized = new PNG({ width, height });
    for (let y = 0; y < height; y++) {
      for (let x = 0; x < width; x++) {
        const idx = (y * width + x) * 4;
        if (x < current.width && y < current.height) {
          const srcIdx = (y * current.width + x) * 4;
          resized.data[idx] = current.data[srcIdx];
          resized.data[idx + 1] = current.data[srcIdx + 1];
          resized.data[idx + 2] = current.data[srcIdx + 2];
          resized.data[idx + 3] = current.data[srcIdx + 3];
        } else {
          resized.data[idx] = 255;
          resized.data[idx + 1] = 255;
          resized.data[idx + 2] = 255;
          resized.data[idx + 3] = 255;
        }
      }
    }
    currentData = resized.data;
  }

  const diff = new PNG({ width, height });
  const totalPixels = width * height;
  const diffPixels = pixelmatch(
    baseline.data,
    currentData,
    diff.data,
    width,
    height,
    { threshold: opts.threshold ?? 0.1 },
  );

  const diffPercent = totalPixels > 0 ? diffPixels / totalPixels : 0;
  const diffBuffer = PNG.sync.write(diff);

  return { diffPercent, diffPixels, totalPixels, diffBuffer, width, height };
}

/**
 * Plan Forge — Tempering: Bug Adapter Contract + Dispatcher (Phase TEMPER-06 Slice 06.2)
 *
 * Defines the adapter contract, validates extension adapters, and dispatches
 * bug operations to both the local JSONL adapter (always) and any configured
 * external adapter (GitHub, GitLab, Jira, etc.).
 *
 * Design contracts:
 *   - Local (JSONL) is canonical; external is advisory.
 *   - Never throws. Returns structured results.
 *   - Extension adapters loaded from `.forge/extensions/<provider>/tempering-bug-adapter.mjs`.
 *
 * @module tempering/bug-adapters/contract
 */

import { resolve } from "node:path";
import { existsSync } from "node:fs";
import { pathToFileURL } from "node:url";

// ─── Contract Definition ─────────────────────────────────────────────

/**
 * The 4-function contract every bug adapter must implement.
 * Each function is async, accepts (bug, config, opts), and returns { provider, ok, ... }.
 */
export const ADAPTER_CONTRACT = {
  registerBug: "async (bug, config, opts) => { provider, ok, ... }",
  updateBugStatus: "async (bug, config, opts) => { provider, ok, ... }",
  commentValidatedFix: "async (bug, config, opts) => { provider, ok, ... }",
  syncStatusFromProvider: "async (bugId, config, opts) => { provider, ok, ... }",
};

const CONTRACT_FN_NAMES = Object.keys(ADAPTER_CONTRACT);

// ─── Operation → function name mapping ───────────────────────────────

const OPERATION_MAP = {
  register: "registerBug",
  updateStatus: "updateBugStatus",
  commentValidatedFix: "commentValidatedFix",
  syncStatus: "syncStatusFromProvider",
};

// ─── Validator ───────────────────────────────────────────────────────

/**
 * Validate that an adapter module implements all required contract functions.
 *
 * @param {object} adapter - The adapter module
 * @returns {{ ok: boolean, errors: string[] }}
 */
export function validateAdapter(adapter) {
  const errors = [];

  if (!adapter || typeof adapter !== "object") {
    return { ok: false, errors: ["Adapter is null or not an object"] };
  }

  for (const fnName of CONTRACT_FN_NAMES) {
    if (typeof adapter[fnName] !== "function") {
      errors.push(`Missing or non-function: ${fnName}`);
    }
  }

  return { ok: errors.length === 0, errors };
}

// ─── Extension Loader ────────────────────────────────────────────────

/**
 * Load a community extension adapter from `.forge/extensions/<provider>/tempering-bug-adapter.mjs`.
 * Returns the adapter module or null if not found/invalid.
 *
 * @param {string} provider - Extension provider name
 * @param {object} [opts]
 * @param {string} [opts.cwd]
 * @returns {Promise<object|null>}
 */
export async function loadExtensionAdapter(provider, { cwd } = {}) {
  try {
    const base = cwd || process.cwd();
    const adapterPath = resolve(base, ".forge", "extensions", provider, "tempering-bug-adapter.mjs");

    if (!existsSync(adapterPath)) {
      return null;
    }

    const adapterUrl = pathToFileURL(adapterPath).href;
    const adapter = await import(adapterUrl);

    const validation = validateAdapter(adapter);
    if (!validation.ok) {
      console.warn(`[tempering] Extension adapter "${provider}" failed validation: ${validation.errors.join(", ")}`);
      return null;
    }

    return adapter;
  } catch (err) {
    console.warn(`[tempering] Failed to load extension adapter "${provider}": ${err.message}`);
    return null;
  }
}

// ─── Dispatcher ──────────────────────────────────────────────────────

/**
 * Dispatch a bug operation to the appropriate adapters.
 *
 * Always invokes the JSONL fallback first (local is canonical).
 * Then, if configured, invokes the external adapter (GitHub, extension, etc.).
 *
 * @param {string} operation - One of: "register", "updateStatus", "commentValidatedFix", "syncStatus"
 * @param {object} bug - Bug record
 * @param {object} config - Forge config
 * @param {object} [opts] - { cwd, fetch, execSync, ... }
 * @returns {Promise<{ local: object, external: object|null }>}
 */
export async function dispatch(operation, bug, config, opts = {}) {
  const fnName = OPERATION_MAP[operation];
  if (!fnName) {
    return {
      local: { provider: "jsonl", ok: false, error: `UNKNOWN_OPERATION: ${operation}` },
      external: null,
    };
  }

  // 1. Always invoke local JSONL adapter
  let localResult;
  try {
    const jsonl = await import("./jsonl-fallback.mjs");
    localResult = await jsonl[fnName](bug, config, opts);
  } catch {
    localResult = { provider: "jsonl", ok: false, error: "JSONL_IMPORT_FAILED" };
  }

  // 2. Determine if external adapter is needed
  const integration = config?.bugRegistry?.integration;
  if (!integration || integration === "jsonl") {
    return { local: localResult, external: null };
  }

  // For register, require autoCreateIssues to be true
  if (operation === "register" && !config?.bugRegistry?.autoCreateIssues) {
    return { local: localResult, external: null };
  }

  // 3. Load external adapter
  let externalAdapter = null;

  if (integration === "github") {
    try {
      externalAdapter = await import("./github.mjs");
    } catch {
      return {
        local: localResult,
        external: { provider: "github", ok: false, error: "ADAPTER_IMPORT_FAILED" },
      };
    }
  } else {
    // Community extension
    externalAdapter = await loadExtensionAdapter(integration, { cwd: opts.cwd });
    if (!externalAdapter) {
      return {
        local: localResult,
        external: { provider: integration, ok: false, error: "EXTENSION_NOT_FOUND" },
      };
    }
  }

  // 4. Invoke external adapter (never throw)
  let externalResult;
  try {
    externalResult = await externalAdapter[fnName](bug, config, opts);
  } catch (err) {
    externalResult = { provider: integration, ok: false, error: `ADAPTER_ERROR: ${err.message}` };
  }

  return { local: localResult, external: externalResult };
}

/**
 * Plan Forge — Tempering: GitHub Issues Bug Adapter (Phase TEMPER-06 Slice 06.2)
 *
 * Syncs bugs discovered by tempering scanners to GitHub Issues.
 * All public functions return structured results and never throw.
 *
 * Token resolution priority: GITHUB_TOKEN env → .forge/secrets.json → `gh auth token`
 * Issue creation: tries `gh issue create` first, falls back to REST API.
 *
 * @module tempering/bug-adapters/github
 */

import { resolve } from "node:path";
import { existsSync, readFileSync } from "node:fs";
import { createHash } from "node:crypto";
import { ERROR_CODES } from "../../enums.mjs";

// ─── Helpers (exported for tests) ─────────────────────────────────────

/**
 * Resolve a GitHub token from multiple sources.
 * Priority: GITHUB_TOKEN env → .forge/secrets.json#github.token → `gh auth token`
 *
 * @param {object} config
 * @param {object} [deps]
 * @param {Function} [deps.execSync]
 * @param {string} [deps.cwd]
 * @returns {{ token: string, source: string } | { token: null, error: string }}
 */
export function resolveGitHubToken(config, { execSync, cwd } = {}) {
  // 1. Environment variable
  const envToken = process.env.GITHUB_TOKEN;
  if (envToken) {
    return { token: envToken, source: "env" };
  }

  // 2. .forge/secrets.json
  if (cwd) {
    const secretsPath = resolve(cwd, ".forge", "secrets.json");
    try {
      if (existsSync(secretsPath)) {
        const secrets = JSON.parse(readFileSync(secretsPath, "utf-8"));
        if (secrets?.github?.token) {
          return { token: secrets.github.token, source: "secrets.json" };
        }
      }
    } catch { /* malformed JSON — skip */ }
  }

  // 3. gh auth token subprocess
  if (typeof execSync === "function") {
    try {
      const token = execSync("gh auth token", {
        encoding: "utf-8",
        timeout: 10_000,
        stdio: ["pipe", "pipe", "pipe"],
        cwd,
      }).trim();
      if (token) {
        return { token, source: "gh-cli" };
      }
    } catch { /* gh not installed or not logged in */ }
  }

  return { token: null, error: ERROR_CODES.NO_TOKEN.code };
}

/**
 * Resolve owner/repo from config or git remote.
 *
 * @param {object} config
 * @param {object} [deps]
 * @param {Function} [deps.execSync]
 * @param {string} [deps.cwd]
 * @returns {{ owner: string, repo: string } | null}
 */
export function resolveGitHubRepo(config, { execSync, cwd } = {}) {
  // 1. Explicit config
  const cfgRepo = config?.bugRegistry?.githubRepo;
  if (cfgRepo && cfgRepo.includes("/")) {
    const [owner, repo] = cfgRepo.split("/");
    if (owner && repo) return { owner, repo };
  }

  // 2. Parse git remote
  if (typeof execSync === "function") {
    try {
      const url = execSync("git remote get-url origin", {
        encoding: "utf-8",
        timeout: 5_000,
        stdio: ["pipe", "pipe", "pipe"],
        cwd,
      }).trim();
      return parseGitRemoteUrl(url);
    } catch { /* no git or no remote */ }
  }

  return null;
}

/**
 * Parse a GitHub remote URL (HTTPS or SSH) into owner/repo.
 * @param {string} url
 * @returns {{ owner: string, repo: string } | null}
 */
export function parseGitRemoteUrl(url) {
  if (!url || typeof url !== "string") return null;

  // HTTPS: https://github.com/owner/repo(.git)?
  const httpsMatch = url.match(/github\.com\/([^/]+)\/([^/.]+?)(?:\.git)?$/);
  if (httpsMatch) return { owner: httpsMatch[1], repo: httpsMatch[2] };

  // SSH: git@github.com:owner/repo(.git)?
  const sshMatch = url.match(/github\.com:([^/]+)\/([^/.]+?)(?:\.git)?$/);
  if (sshMatch) return { owner: sshMatch[1], repo: sshMatch[2] };

  return null;
}

// ─── Issue body builders ─────────────────────────────────────────────

const SEVERITY_BADGES = {
  critical: "🔴 Critical",
  high: "🟠 High",
  medium: "🟡 Medium",
  low: "🟢 Low",
};

/**
 * Build the markdown body for a GitHub issue.
 * @param {object} bug
 * @returns {string}
 */
export function buildIssueBody(bug) {
  const badge = SEVERITY_BADGES[bug.severity] || bug.severity;
  const lines = [
    `## Tempering Bug Report`,
    "",
    `**Severity:** ${badge}`,
    `**Scanner:** ${bug.scanner}`,
    `**Bug ID:** \`${bug.bugId}\``,
    `**Discovered:** ${bug.discoveredAt}`,
  ];

  if (bug.classification) {
    lines.push(`**Classification:** ${bug.classification}`);
  }

  if (bug.affectedFiles?.length) {
    lines.push("", "### Affected Files", "");
    for (const f of bug.affectedFiles) {
      lines.push(`- \`${f}\``);
    }
  }

  if (bug.evidence) {
    lines.push("", "### Evidence", "");
    if (bug.evidence.testName) {
      lines.push(`**Test:** \`${bug.evidence.testName}\``);
    }
    if (bug.evidence.assertionMessage) {
      lines.push(`**Assertion:** ${bug.evidence.assertionMessage}`);
    }
  }

  // Full evidence in collapsed block
  lines.push(...[
    "",
    "<details>",
    "<summary>Full evidence JSON</summary>",
    "",
    "```json",
    JSON.stringify(bug.evidence || {}, null, 2),
    "```",
    "",
    "</details>",
    "",
    "---",
    "*Filed automatically by [Plan Forge Tempering](https://github.com/srnichols/plan-forge)*",
  ]);

  return lines.join("\n");
}

/**
 * Build labels for a GitHub issue.
 * @param {object} bug
 * @param {object} config
 * @returns {string[]}
 */
export function buildLabels(bug, config) {
  const prefix = config?.bugRegistry?.labelPrefix || "tempering";
  const labels = [`${prefix}:bug`];
  if (bug.severity) labels.push(`severity:${bug.severity}`);
  if (bug.scanner) labels.push(`scanner:${bug.scanner}`);
  return labels;
}

// ─── REST API helpers ────────────────────────────────────────────────

/**
 * Create an issue via the GitHub REST API.
 * @returns {Promise<{ issueNumber: number, url: string } | null>}
 */
async function createIssueViaRest({ token, owner, repo, title, body, labels, fetch: fetchFn }) {
  try {
    const res = await fetchFn(`https://api.github.com/repos/${owner}/${repo}/issues`, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${token}`,
        Accept: "application/vnd.github+json",
        "Content-Type": "application/json",
        "X-GitHub-Api-Version": "2022-11-28",
      },
      body: JSON.stringify({ title, body, labels }),
      signal: AbortSignal.timeout(30_000),
    });

    // Rate limit check
    const remaining = res.headers?.get?.("x-ratelimit-remaining");
    const resetAt = res.headers?.get?.("x-ratelimit-reset");
    if (res.status === 403 && remaining === "0") {
      return { error: ERROR_CODES.RATE_LIMITED.code, resetAt: resetAt ? new Date(Number(resetAt) * 1000).toISOString() : null };
    }

    if (!res.ok) {
      return { error: `HTTP_${res.status}` };
    }

    const data = await res.json();
    return { issueNumber: data.number, url: data.html_url };
  } catch (err) {
    if (err.name === "TimeoutError" || err.name === "AbortError") {
      return { error: ERROR_CODES.TIMEOUT.code };
    }
    return { error: ERROR_CODES.NETWORK_ERROR.code };
  }
}

/**
 * Create an issue via `gh issue create`. Returns null on any failure.
 */
function createIssueViaGh({ owner, repo, title, body, labels, execSync: execSyncFn, cwd }) {
  if (typeof execSyncFn !== "function") return null;
  try {
    const labelArg = labels.map((l) => `--label "${l}"`).join(" ");
    const cmd = `gh issue create --repo "${owner}/${repo}" --title "${title.replace(/"/g, '\\"')}" --body "${body.replace(/"/g, '\\"').replace(/\n/g, "\\n")}" ${labelArg}`;
    const output = execSyncFn(cmd, {
      encoding: "utf-8",
      timeout: 30_000,
      stdio: ["pipe", "pipe", "pipe"],
      cwd,
    }).trim();

    // gh outputs the URL of the created issue
    const match = output.match(/\/issues\/(\d+)/);
    if (match) {
      return { issueNumber: parseInt(match[1], 10), url: output };
    }
    return null;
  } catch {
    return null;
  }
}

/**
 * Add a comment to an existing issue via REST API.
 */
async function addComment({ token, owner, repo, issueNumber, body, fetch: fetchFn }) {
  try {
    const res = await fetchFn(`https://api.github.com/repos/${owner}/${repo}/issues/${issueNumber}/comments`, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${token}`,
        Accept: "application/vnd.github+json",
        "Content-Type": "application/json",
        "X-GitHub-Api-Version": "2022-11-28",
      },
      body: JSON.stringify({ body }),
      signal: AbortSignal.timeout(30_000),
    });

    if (!res.ok) {
      return { error: `HTTP_${res.status}` };
    }

    const data = await res.json();
    return { commentId: data.id, url: data.html_url };
  } catch (err) {
    if (err.name === "TimeoutError" || err.name === "AbortError") {
      return { error: ERROR_CODES.TIMEOUT.code };
    }
    return { error: ERROR_CODES.NETWORK_ERROR.code };
  }
}

// ─── Public API (4-function contract) ────────────────────────────────

/**
 * Register a new bug as a GitHub Issue.
 *
 * @param {object} bug - Bug record from registry
 * @param {object} config - Forge config
 * @param {object} [deps]
 * @returns {Promise<{ provider: string, ok: boolean, issueNumber?: number, url?: string, error?: string, warnings?: string[] }>}
 */
export async function registerBug(bug, config, { fetch: fetchFn = globalThis.fetch, execSync: execSyncFn, cwd } = {}) {
  try {
    // Short-circuit if already linked
    if (bug.externalRef?.provider === "github" && bug.externalRef?.issueNumber) {
      return { provider: "github", ok: true, issueNumber: bug.externalRef.issueNumber, url: bug.externalRef.url };
    }

    const tokenResult = resolveGitHubToken(config, { execSync: execSyncFn, cwd });
    if (!tokenResult.token) {
      return { provider: "github", ok: false, error: tokenResult.error || ERROR_CODES.NO_TOKEN.code };
    }

    const repoInfo = resolveGitHubRepo(config, { execSync: execSyncFn, cwd });
    if (!repoInfo) {
      return { provider: "github", ok: false, error: ERROR_CODES.NO_REPO.code };
    }

    const title = `[Tempering] ${bug.scanner}: ${bug.evidence?.testName || bug.bugId}`;
    const body = buildIssueBody(bug);
    const labels = buildLabels(bug, config);

    // Try gh CLI first, fall back to REST
    let result = createIssueViaGh({ owner: repoInfo.owner, repo: repoInfo.repo, title, body, labels, execSync: execSyncFn, cwd });

    if (!result) {
      result = await createIssueViaRest({
        token: tokenResult.token,
        owner: repoInfo.owner,
        repo: repoInfo.repo,
        title,
        body,
        labels,
        fetch: fetchFn,
      });
    }

    if (!result || result.error) {
      return { provider: "github", ok: false, error: result?.error || ERROR_CODES.CREATE_FAILED.code };
    }

    return { provider: "github", ok: true, issueNumber: result.issueNumber, url: result.url };
  } catch {
    return { provider: "github", ok: false, error: ERROR_CODES.UNEXPECTED.code };
  }
}

/**
 * Update bug status by adding a comment to the linked GitHub issue.
 * Never rewrites issue body.
 */
export async function updateBugStatus(bug, config, { fetch: fetchFn = globalThis.fetch, execSync: execSyncFn, cwd } = {}) {
  try {
    const issueNumber = bug.externalRef?.issueNumber;
    if (!issueNumber) {
      return { provider: "github", ok: false, error: ERROR_CODES.NO_ISSUE_NUMBER.code };
    }

    const tokenResult = resolveGitHubToken(config, { execSync: execSyncFn, cwd });
    if (!tokenResult.token) {
      return { provider: "github", ok: false, error: tokenResult.error || ERROR_CODES.NO_TOKEN.code };
    }

    const repoInfo = resolveGitHubRepo(config, { execSync: execSyncFn, cwd });
    if (!repoInfo) {
      return { provider: "github", ok: false, error: ERROR_CODES.NO_REPO.code };
    }

    const body = `## Status Update\n\n**New Status:** \`${bug.status}\`\n**Updated:** ${bug.updatedAt || new Date().toISOString()}\n\n${bug.statusHistory?.at(-1)?.note ? `**Note:** ${bug.statusHistory.at(-1).note}` : ""}`;

    const result = await addComment({ token: tokenResult.token, owner: repoInfo.owner, repo: repoInfo.repo, issueNumber, body, fetch: fetchFn });

    if (result.error) {
      return { provider: "github", ok: false, error: result.error };
    }

    return { provider: "github", ok: true, commentId: result.commentId, url: result.url };
  } catch {
    return { provider: "github", ok: false, error: ERROR_CODES.UNEXPECTED.code };
  }
}

/**
 * Post a "validated fix" comment to the linked GitHub issue.
 * Does NOT close the issue automatically.
 */
export async function commentValidatedFix(bug, config, { fetch: fetchFn = globalThis.fetch, execSync: execSyncFn, cwd } = {}) {
  try {
    const issueNumber = bug.externalRef?.issueNumber;
    if (!issueNumber) {
      return { provider: "github", ok: false, error: ERROR_CODES.NO_ISSUE_NUMBER.code };
    }

    const tokenResult = resolveGitHubToken(config, { execSync: execSyncFn, cwd });
    if (!tokenResult.token) {
      return { provider: "github", ok: false, error: tokenResult.error || ERROR_CODES.NO_TOKEN.code };
    }

    const repoInfo = resolveGitHubRepo(config, { execSync: execSyncFn, cwd });
    if (!repoInfo) {
      return { provider: "github", ok: false, error: ERROR_CODES.NO_REPO.code };
    }

    const scanRef = bug.validationHistory?.at(-1)?.scanRef || "";
    const body = `## 🔥 Tempering validated this fix\n\n**Bug ID:** \`${bug.bugId}\`\n**Scanner:** ${bug.scanner}\n**Validated at:** ${new Date().toISOString()}\n${scanRef ? `**Scan Reference:** \`${scanRef}\`` : ""}\n\nThe tempering subsystem has confirmed this bug is fixed. The issue remains open for human review.`;

    const result = await addComment({ token: tokenResult.token, owner: repoInfo.owner, repo: repoInfo.repo, issueNumber, body, fetch: fetchFn });

    if (result.error) {
      return { provider: "github", ok: false, error: result.error };
    }

    return { provider: "github", ok: true, commentId: result.commentId, url: result.url };
  } catch {
    return { provider: "github", ok: false, error: ERROR_CODES.UNEXPECTED.code };
  }
}

/**
 * Sync status from GitHub (read labels and state).
 */
export async function syncStatusFromProvider(bugId, config, { fetch: fetchFn = globalThis.fetch, execSync: execSyncFn, cwd } = {}) {
  try {
    // We need the bug record to get the issueNumber
    // The caller should provide the full bug, but bugId is also accepted
    const bug = typeof bugId === "object" ? bugId : { bugId };
    const issueNumber = bug.externalRef?.issueNumber;
    if (!issueNumber) {
      return { provider: "github", ok: false, error: ERROR_CODES.NO_ISSUE_NUMBER.code };
    }

    const tokenResult = resolveGitHubToken(config, { execSync: execSyncFn, cwd });
    if (!tokenResult.token) {
      return { provider: "github", ok: false, error: tokenResult.error || ERROR_CODES.NO_TOKEN.code };
    }

    const repoInfo = resolveGitHubRepo(config, { execSync: execSyncFn, cwd });
    if (!repoInfo) {
      return { provider: "github", ok: false, error: ERROR_CODES.NO_REPO.code };
    }

    const res = await fetchFn(`https://api.github.com/repos/${repoInfo.owner}/${repoInfo.repo}/issues/${issueNumber}`, {
      method: "GET",
      headers: {
        Authorization: `Bearer ${tokenResult.token}`,
        Accept: "application/vnd.github+json",
        "X-GitHub-Api-Version": "2022-11-28",
      },
      signal: AbortSignal.timeout(30_000),
    });

    if (!res.ok) {
      return { provider: "github", ok: false, error: `HTTP_${res.status}` };
    }

    const data = await res.json();
    return {
      provider: "github",
      ok: true,
      status: data.state,
      labels: (data.labels || []).map((l) => (typeof l === "string" ? l : l.name)),
    };
  } catch (err) {
    if (err.name === "TimeoutError" || err.name === "AbortError") {
      return { provider: "github", ok: false, error: ERROR_CODES.TIMEOUT.code };
    }
    return { provider: "github", ok: false, error: ERROR_CODES.NETWORK_ERROR.code };
  }
}

// ─── Meta-bug class schema & repo resolver ────────────────────────────

/**
 * Canonical meta-bug classes for Plan Forge self-repair.
 *
 * - plan-defect: brittle gate, missing scope, wrong path, over-narrow grep
 * - orchestrator-defect: runtime bug in Plan Forge (timeout, spawn, stash)
 * - prompt-defect: unsafe output, missing rule, placeholder not expanded
 */
export const META_BUG_CLASSES = Object.freeze([
  "plan-defect",
  "orchestrator-defect",
  "prompt-defect",
]);

/** Default labels applied to every meta-bug issue. */
export const SELF_REPAIR_LABELS = Object.freeze([
  "self-repair",
  "plan-forge-internal",
]);

/**
 * Resolve the target repository for meta-bug (self-repair) issues.
 *
 * Resolution priority:
 *   1. config.meta.selfRepairRepo  ("owner/repo" string)
 *   2. Fallback: srnichols/plan-forge
 *
 * @param {object|null|undefined} config - Forge configuration object
 * @returns {{ owner: string, repo: string }}
 */
export function resolveSelfRepairRepo(config) {
  const raw = config?.meta?.selfRepairRepo;
  if (!raw || typeof raw !== "string") {
    return { owner: "srnichols", repo: "plan-forge" };
  }
  const trimmed = raw.trim();
  const parts = trimmed.split("/");
  if (parts.length !== 2 || !parts[0] || !parts[1]) {
    return { owner: "srnichols", repo: "plan-forge" };
  }
  return { owner: parts[0], repo: parts[1] };
}

// ─── Meta-bug filer with dedupe ───────────────────────────────────────

/**
 * Compute a stable 12-char hex hash for meta-bug deduplication.
 * @param {string} bugClass - One of META_BUG_CLASSES
 * @param {string} title    - Human-readable bug title
 * @returns {string} 12-character hex hash
 */
export function computeMetaBugHash(bugClass, title) {
  const normalized = title.toLowerCase().replace(/\s+/g, " ").trim();
  return createHash("sha256")
    .update(bugClass + ":" + normalized)
    .digest("hex")
    .slice(0, 12);
}

/**
 * Search for an existing open meta-bug issue by hash.
 * Tries `gh issue list` first, falls back to REST search API.
 *
 * @returns {Promise<{ issueNumber: number, url: string } | null>}
 */
async function findExistingMetaBug({ hash, owner, repo, token, execSync: execSyncFn, fetch: fetchFn, cwd }) {
  // 1. Try gh CLI
  if (typeof execSyncFn === "function") {
    try {
      const cmd = `gh issue list --repo "${owner}/${repo}" --label "self-repair" --state open --search "${hash}" --json number,url,title --limit 10`;
      const raw = execSyncFn(cmd, {
        encoding: "utf-8",
        timeout: 30_000,
        stdio: ["pipe", "pipe", "pipe"],
        cwd,
      }).trim();
      if (raw) {
        const issues = JSON.parse(raw);
        const match = issues.find((i) => i.title?.includes(hash));
        if (match) {
          return { issueNumber: match.number, url: match.url };
        }
      }
    } catch { /* gh CLI unavailable or failed — fall through to REST */ }
  }

  // 2. REST search fallback
  if (token && typeof fetchFn === "function") {
    try {
      const q = encodeURIComponent(`repo:${owner}/${repo} label:self-repair state:open "${hash}" in:title`);
      const res = await fetchFn(`https://api.github.com/search/issues?q=${q}&per_page=5`, {
        headers: {
          Authorization: `Bearer ${token}`,
          Accept: "application/vnd.github+json",
          "X-GitHub-Api-Version": "2022-11-28",
        },
        signal: AbortSignal.timeout(30_000),
      });
      if (res.ok) {
        const data = await res.json();
        const match = (data.items || []).find((i) => i.title?.includes(hash));
        if (match) {
          return { issueNumber: match.number, url: match.html_url };
        }
      }
    } catch { /* search failed — treat as no match */ }
  }

  return null;
}

/**
 * Build the markdown body for a meta-bug issue.
 */
function buildMetaBugBody({ bugClass, symptom, workaround, filePaths, slice, plan, trajectoryExcerpt }) {
  const sections = [];
  sections.push(`## Class\n\n\`${bugClass}\``);
  sections.push(`## Symptom\n\n${symptom}`);
  if (workaround) {
    sections.push(`## Workaround Applied\n\n${workaround}`);
  }
  if (filePaths?.length) {
    sections.push(`## Files\n\n${filePaths.map((f) => `- \`${f}\``).join("\n")}`);
  }
  if (plan || slice) {
    const parts = [];
    if (plan) parts.push(`**Plan**: ${plan}`);
    if (slice) parts.push(`**Slice**: ${slice}`);
    sections.push(`## Reference\n\n${parts.join("\n")}`);
  }
  if (trajectoryExcerpt) {
    sections.push(`## Context\n\n${trajectoryExcerpt}`);
  }
  return sections.join("\n\n");
}

/**
 * File a meta-bug (self-repair) issue on GitHub with hash-based deduplication.
 *
 * If an open issue with the same hash exists, appends a comment instead of
 * creating a duplicate. All errors return structured `{ ok: false, error }`.
 *
 * @param {object} params
 * @param {string} params.class      - One of META_BUG_CLASSES
 * @param {string} params.title      - Human-readable title
 * @param {string} params.symptom    - What went wrong
 * @param {string} [params.workaround] - Fix applied
 * @param {string[]} [params.filePaths] - Affected files
 * @param {string} [params.slice]    - Slice reference
 * @param {string} [params.plan]     - Plan reference
 * @param {string} [params.severity] - low|medium|high|critical
 * @param {string} [params.trajectoryExcerpt] - Trajectory context
 * @param {object} config            - Forge configuration
 * @param {object} [deps]
 * @returns {Promise<{ ok: boolean, issueNumber?: number, url?: string, deduped?: boolean, hash?: string, error?: string }>}
 */
async function _handleExistingMetaBug({ existing, params, tokenResult, repoInfo, hash, fetchFn }) {
  const commentParts = [];
  if (params.workaround) commentParts.push(`## Workaround Applied\n\n${params.workaround}`);
  if (params.slice || params.plan) {
    const refs = [];
    if (params.plan) refs.push(`**Plan**: ${params.plan}`);
    if (params.slice) refs.push(`**Slice**: ${params.slice}`);
    commentParts.push(`## Reference\n\n${refs.join("\n")}`);
  }
  commentParts.push(`_Duplicate occurrence detected at ${new Date().toISOString()}_`);

  const commentResult = await addComment({
    token: tokenResult.token,
    owner: repoInfo.owner,
    repo: repoInfo.repo,
    issueNumber: existing.issueNumber,
    body: commentParts.join("\n\n"),
    fetch: fetchFn,
  });

  if (commentResult?.error) {
    return { ok: false, error: commentResult.error, hash };
  }
  return { ok: true, issueNumber: existing.issueNumber, url: existing.url, deduped: true, hash };
}

async function _createNewMetaBug({ repoInfo, issueTitle, body, labels, tokenResult, execSyncFn, fetchFn, cwd, hash }) {
  let result = createIssueViaGh({ owner: repoInfo.owner, repo: repoInfo.repo, title: issueTitle, body, labels, execSync: execSyncFn, cwd });

  if (!result) {
    result = await createIssueViaRest({
      token: tokenResult.token,
      owner: repoInfo.owner,
      repo: repoInfo.repo,
      title: issueTitle,
      body,
      labels,
      fetch: fetchFn,
    });
  }

  if (!result || result.error) {
    return { ok: false, error: result?.error || ERROR_CODES.CREATE_FAILED.code, hash };
  }
  return { ok: true, issueNumber: result.issueNumber, url: result.url, deduped: false, hash };
}

export async function fileMetaBug(params, config, { execSync: execSyncFn, fetch: fetchFn = globalThis.fetch, cwd } = {}) {
  try {
    const bugClass = params?.class;
    const title = params?.title;
    const symptom = params?.symptom;

    if (!bugClass || !title || !symptom) {
      return { ok: false, error: ERROR_CODES.MISSING_REQUIRED_FIELDS.code };
    }

    const tokenResult = resolveGitHubToken(config, { execSync: execSyncFn, cwd });
    if (!tokenResult.token) {
      return { ok: false, error: ERROR_CODES.NO_TOKEN.code };
    }

    const repoInfo = resolveSelfRepairRepo(config);
    if (!repoInfo?.owner || !repoInfo?.repo) {
      return { ok: false, error: ERROR_CODES.NO_REPO.code };
    }

    const hash = computeMetaBugHash(bugClass, title);
    const issueTitle = `[self-repair:${hash}] [${bugClass}] ${title}`;
    const labels = [...SELF_REPAIR_LABELS, bugClass, params.severity || "medium"];
    const body = buildMetaBugBody({
      bugClass,
      symptom,
      workaround: params.workaround,
      filePaths: params.filePaths,
      slice: params.slice,
      plan: params.plan,
      trajectoryExcerpt: params.trajectoryExcerpt,
    });

    const existing = await findExistingMetaBug({ hash: hash, owner: repoInfo.owner, repo: repoInfo.repo, token: tokenResult.token, ...{
      execSync: execSyncFn,
      fetch: fetchFn,
      cwd,
    } });

    if (existing) {
      return _handleExistingMetaBug({ existing, params, tokenResult, repoInfo, hash, fetchFn });
    }

    return _createNewMetaBug({ repoInfo, issueTitle, body, labels, tokenResult, execSyncFn, fetchFn, cwd, hash });
  } catch {
    return { ok: false, error: ERROR_CODES.UNEXPECTED.code };
  }
}

/**
 * Plan Forge — Tempering: Bug Classifier (Phase TEMPER-06 Slice 06.1)
 *
 * Two-layer classification: deterministic rules first, LLM arbitration
 * as fallback. Never throws — all failures produce structured results.
 *
 * Design contracts:
 *   - `classify()` never throws. Returns `{ classification, rule?, reason, confidence, source }`.
 *   - Layer 1 (rules) is synchronous, first-match wins, ordered by confidence.
 *   - Layer 2 (LLM) is async, single-model by default, quorum opt-in.
 *   - confidence < 0.7 from LLM → 'needs-human-review'.
 *   - LLM unavailable → 'unknown'.
 *
 * @module tempering/bug-classifier
 */

import { existsSync, readdirSync, readFileSync } from "node:fs";
import { resolve } from "node:path";

// ─── Rule Definitions ─────────────────────────────────────────────────

/**
 * Deterministic classification rules, ordered by confidence.
 * First match wins. Each rule returns a classification or null.
 */
const RULES = [
  // Rule 1: test-frame-top — stack top in test files
  {
    id: "test-frame-top",
    test: (opts) => {
      const top = extractTopFrame(opts.evidence?.stackTrace);
      if (!top) return null;
      if (/tests?[/\\]|\.spec\.|\.test\./i.test(top)) {
        return { classification: "infra", confidence: 0.95, reason: "Stack trace top frame is in test code" };
      }
      return null;
    },
  },
  // Rule 2: visual-quorum — visual-diff scanner with quorum verdict
  {
    id: "visual-quorum",
    test: (opts) => {
      if (opts.scanner !== "visual-diff") return null;
      if (opts.evidence?.quorumVerdict || opts.evidence?.verdict) {
        return { classification: "real-bug", confidence: 0.95, reason: "Visual-diff quorum confirmed regression" };
      }
      return null;
    },
  },
  // Rule 3: src-assertion — top frame in src/ with assertion failure
  {
    id: "src-assertion",
    test: (opts) => {
      const top = extractTopFrame(opts.evidence?.stackTrace);
      if (!top) return null;
      if (/src[/\\]/i.test(top) && opts.evidence?.assertionMessage) {
        return { classification: "real-bug", confidence: 0.90, reason: "Assertion failure in production source code" };
      }
      return null;
    },
  },
  // Rule 4: a11y-critical — accessibility violations from UI scanner
  {
    id: "a11y-critical",
    test: (opts) => {
      if (opts.scanner !== "ui-playwright") return null;
      const sev = opts.evidence?.a11ySeverity || opts.evidence?.severity;
      if (sev === "serious" || sev === "critical") {
        return { classification: "real-bug", confidence: 0.90, reason: `Accessibility violation: ${sev}` };
      }
      return null;
    },
  },
  // Rule 5: contract-mismatch — contract scanner with violation
  {
    id: "contract-mismatch",
    test: (opts) => {
      if (opts.scanner !== "contract") return null;
      if (opts.evidence?.violation || opts.evidence?.violations?.length > 0) {
        return { classification: "real-bug", confidence: 0.90, reason: "API contract violation detected" };
      }
      return null;
    },
  },
  // Rule 6: flaky-threshold — ≥3 failures in rolling window
  {
    id: "flaky-threshold",
    test: (opts) => {
      const flaky = opts.flakinessData;
      if (!flaky || typeof flaky.failureCount !== "number") return null;
      if (flaky.failureCount >= 3) {
        return { classification: "infra", confidence: 0.85, reason: `Flaky: ${flaky.failureCount} failures in rolling window` };
      }
      return null;
    },
  },
  // Rule 7: perf-consecutive — perf regression in 2+ consecutive runs
  {
    id: "perf-consecutive",
    test: (opts) => {
      if (opts.scanner !== "performance-budget") return null;
      if (opts.evidence?.consecutiveFailures >= 2) {
        return { classification: "real-bug", confidence: 0.85, reason: "Performance regression in 2+ consecutive runs" };
      }
      return null;
    },
  },
  // Rule 8: load-error-rate — load-stress scanner error rate breach
  {
    id: "load-error-rate",
    test: (opts) => {
      if (opts.scanner !== "load-stress") return null;
      if (opts.evidence?.errorRateBreach || opts.evidence?.errorRate > (opts.evidence?.threshold || 0.05)) {
        return { classification: "real-bug", confidence: 0.85, reason: "Load test error rate exceeds threshold" };
      }
      return null;
    },
  },
  // Rule 9: test-modified-same-commit
  {
    id: "test-modified-same-commit",
    test: (opts) => {
      const top = extractTopFrame(opts.evidence?.stackTrace);
      if (!top) return null;
      if (/tests?[/\\]|\.spec\.|\.test\./i.test(top) && opts.evidence?.testModifiedInCommit) {
        return { classification: "infra", confidence: 0.90, reason: "Test file modified in same commit as failure" };
      }
      return null;
    },
  },
];

// ─── Helpers ──────────────────────────────────────────────────────────

function extractTopFrame(stackTrace) {
  if (!stackTrace || typeof stackTrace !== "string") return "";
  const lines = stackTrace.split("\n").map((l) => l.trim()).filter(Boolean);
  for (const line of lines) {
    if (line.startsWith("at ") && !line.includes("node_modules")) {
      return line;
    }
  }
  return lines[0] || "";
}

// ─── Layer 1: Rule-Based Classification ──────────────────────────────

/**
 * Classify using deterministic rules. Synchronous.
 *
 * @param {object} opts - { scanner, evidence, flakinessData? }
 * @returns {{ classification, rule, reason, confidence, source: 'rule' } | null}
 */
export function classifyByRules(opts) {
  for (const rule of RULES) {
    try {
      const result = rule.test(opts);
      if (result) {
        return {
          classification: result.classification,
          rule: rule.id,
          reason: result.reason,
          confidence: result.confidence,
          source: "rule",
        };
      }
    } catch { /* skip broken rule */ }
  }
  return null;
}

// ─── Layer 2: LLM Arbitration ─────────────────────────────────────────

const CLASSIFIER_SYSTEM_PROMPT = `You are a bug classifier. Given scanner evidence from an automated test suite, decide if this is a product bug ('real-bug') or test-infrastructure issue ('infra'). Return JSON only: { "classification": "real-bug"|"infra", "reason": "<brief explanation>", "confidence": <0.0-1.0> }`;

function buildClassifierPrompt(scanner, evidence) {
  return JSON.stringify({
    scanner,
    testName: evidence?.testName || null,
    assertionMessage: evidence?.assertionMessage || null,
    stackTrace: (evidence?.stackTrace || "").slice(0, 1500),
    visualDiffScore: evidence?.visualDiffScore || null,
  });
}

function parseClassifierResponse(response) {
  const text = typeof response === "string" ? response : response?.text || response?.content || "";
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (!jsonMatch) return null;
  const parsed = JSON.parse(jsonMatch[0]);
  return {
    classification: parsed.classification || "unknown",
    confidence: typeof parsed.confidence === "number" ? parsed.confidence : 0,
    reason: parsed.reason || "LLM classified",
  };
}

function finalizeClassifierResult(parsed) {
  if (!parsed) {
    return { classification: "unknown", reason: "LLM response not parseable", confidence: 0, source: "llm" };
  }
  if (parsed.confidence < 0.7) {
    return { classification: "needs-human-review", reason: parsed.reason, confidence: parsed.confidence, source: "llm" };
  }
  return { ...parsed, source: "llm" };
}

/**
 * Classify using LLM when rules don't match. Never throws.
 *
 * @param {object} opts
 * @param {string} opts.scanner
 * @param {object} opts.evidence
 * @param {Function} opts.callModel - DI injected model caller
 * @param {object} [opts.config]
 * @returns {Promise<{ classification, reason, confidence, source: 'llm' }>}
 */
export async function classifyByLLM(opts) {
  const { scanner, evidence, callModel, config } = opts;

  if (typeof callModel !== "function") {
    return { classification: "unknown", reason: "LLM unavailable (no callModel)", confidence: 0, source: "llm" };
  }

  try {
    const response = await callModel({
      systemPrompt: CLASSIFIER_SYSTEM_PROMPT,
      userPrompt: buildClassifierPrompt(scanner, evidence),
      maxTokens: 200,
      temperature: 0.1,
    });
    return finalizeClassifierResult(parseClassifierResponse(response));
  } catch (err) {
    return { classification: "unknown", reason: `LLM unavailable: ${err.message}`, confidence: 0, source: "llm" };
  }
}

// ─── Flakiness Data Loader ────────────────────────────────────────────

/**
 * Load flakiness data for a test name from recent run records.
 *
 * @param {string} cwd
 * @param {string} testName
 * @param {number} [windowSize=20]
 * @returns {{ failureCount: number, runCount: number, failureRate: number }}
 */
export function loadFlakinessData(cwd, testName, windowSize = 20) {
  if (!testName || typeof testName !== "string") {
    return { failureCount: 0, runCount: 0, failureRate: 0 };
  }

  const temperingDir = resolve(cwd, ".forge", "tempering");
  if (!existsSync(temperingDir)) {
    return { failureCount: 0, runCount: 0, failureRate: 0 };
  }

  let runFiles;
  try {
    runFiles = readdirSync(temperingDir)
      .filter((f) => f.startsWith("run-") && f.endsWith(".json"))
      .sort()
      .reverse()
      .slice(0, windowSize);
  } catch {
    return { failureCount: 0, runCount: 0, failureRate: 0 };
  }

  let failures = 0;
  let runs = 0;

  for (const file of runFiles) {
    try {
      const record = JSON.parse(readFileSync(resolve(temperingDir, file), "utf-8"));
      if (!Array.isArray(record.scanners)) continue;

      for (const scanner of record.scanners) {
        if (scanner.failures && Array.isArray(scanner.failures)) {
          const hasFail = scanner.failures.some(
            (f) => f.testName === testName || f.evidence?.testName === testName
          );
          if (hasFail) failures++;
        }
      }
      runs++;
    } catch { /* skip corrupt */ }
  }

  return {
    failureCount: failures,
    runCount: runs,
    failureRate: runs > 0 ? failures / runs : 0,
  };
}

// ─── Top-level classifier ─────────────────────────────────────────────

/**
 * Two-layer classification: rules first, then LLM fallback.
 * Never throws.
 *
 * @param {object} opts
 * @param {string} opts.scanner
 * @param {object} opts.evidence
 * @param {object} [opts.flakinessData]
 * @param {object|null} [opts.sliceRef]
 * @param {Function} [opts.callModel]
 * @param {object} [opts.config]
 * @returns {Promise<{ classification, rule?, reason, confidence, source }>}
 */
export async function classify(opts) {
  try {
    // Layer 1: rules
    const ruleResult = classifyByRules(opts);
    if (ruleResult) return ruleResult;

    // Layer 2: LLM
    return await classifyByLLM(opts);
  } catch (err) {
    return {
      classification: "unknown",
      reason: `Classifier error: ${err.message}`,
      confidence: 0,
      source: "rule",
    };
  }
}

/**
 * Plan Forge — Tempering: Bug Registry (Phase TEMPER-06 Slice 06.1)
 *
 * Stores, deduplicates, and manages bugs discovered by tempering scanners.
 * Each bug is a JSON file in `.forge/bugs/<bugId>.json`.
 *
 * Design contracts:
 *   - Never throws. All public functions return structured results.
 *   - Atomic writes (tmp + rename) to avoid partial JSON on crash.
 *   - Path traversal safety: all writes constrained to .forge/bugs/.
 *   - Hub/captureMemory are injected for testability.
 *
 * @module tempering/bug-registry
 */

import { existsSync, mkdirSync, writeFileSync, readFileSync, readdirSync, renameSync } from "node:fs";
import { resolve, basename, join } from "node:path";
import { createHash, randomUUID } from "node:crypto";
import { ERROR_CODES } from "../enums.mjs";
import { dispatch } from "./bug-adapters/contract.mjs";

// ─── Constants ────────────────────────────────────────────────────────

export const BUG_STATUSES = ["open", "in-fix", "fixed", "wont-fix", "duplicate"];

export const VALID_TRANSITIONS = {
  "open":      ["in-fix", "wont-fix", "duplicate"],
  "in-fix":    ["fixed", "open", "wont-fix"],
  "fixed":     [],
  "wont-fix":  [],
  "duplicate": [],
};

// ─── Directory helpers ────────────────────────────────────────────────

/**
 * Ensure `.forge/bugs/` exists under cwd.
 * @param {string} cwd
 * @returns {string} resolved bugs directory path
 */
export function ensureBugsDir(cwd) {
  const dir = resolve(cwd, ".forge", "bugs");
  mkdirSync(dir, { recursive: true });
  return dir;
}

// ─── Bug ID generation ───────────────────────────────────────────────

/**
 * Generate a unique bug ID: `bug-YYYY-MM-DD-NNN`.
 * Reads existing files to find next sequence number. Retries on collision.
 *
 * @param {string} cwd
 * @param {Function} [nowFn] - injectable clock for testing
 * @returns {string}
 */
export function generateBugId(cwd, nowFn = () => Date.now()) {
  const dir = ensureBugsDir(cwd);
  const date = new Date(nowFn()).toISOString().slice(0, 10);
  const prefix = `bug-${date}-`;

  let existing = [];
  try {
    existing = readdirSync(dir)
      .filter((f) => f.startsWith(prefix) && f.endsWith(".json"))
      .map((f) => {
        const numStr = f.slice(prefix.length, -5); // remove .json
        return parseInt(numStr, 10);
      })
      .filter((n) => !isNaN(n));
  } catch { /* empty dir or unreadable */ }

  const next = existing.length > 0 ? Math.max(...existing) + 1 : 1;
  return `${prefix}${String(next).padStart(3, "0")}`;
}

// ─── Fingerprinting & Deduplication ──────────────────────────────────

/**
 * Normalize assertion messages for stable fingerprinting.
 * Strips timestamps, hex addresses, random UUIDs, and numeric noise.
 */
function normalizeForFingerprint(str) {
  if (!str || typeof str !== "string") return "";
  return str
    .replace(/\d{4}-\d{2}-\d{2}T[\d:.Z+-]+/g, "<ts>")        // ISO timestamps
    .replace(/0x[0-9a-fA-F]+/g, "<hex>")                      // hex addresses
    .replace(/[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/gi, "<uuid>") // UUIDs
    .replace(/\d{10,}/g, "<num>")                              // long numbers (timestamps, IDs)
    .trim();
}

/**
 * Compute a fingerprint for deduplication.
 * SHA-1 of (scanner|testName|topFrame|normalized-assertionMessage).
 *
 * @param {string} scanner
 * @param {object} evidence
 * @returns {string} hex fingerprint
 */
export function computeFingerprint(scanner, evidence) {
  const parts = [
    scanner || "",
    evidence?.testName || "",
    extractTopFrame(evidence?.stackTrace),
    normalizeForFingerprint(evidence?.assertionMessage),
  ];
  return createHash("sha1").update(parts.join("|")).digest("hex");
}

/**
 * Extract the first meaningful (non-node_modules) frame from a stack trace.
 */
function extractTopFrame(stackTrace) {
  if (!stackTrace || typeof stackTrace !== "string") return "";
  const lines = stackTrace.split("\n").map((l) => l.trim()).filter(Boolean);
  for (const line of lines) {
    if (line.startsWith("at ") && !line.includes("node_modules")) {
      return line;
    }
  }
  return lines[0] || "";
}

/**
 * Search existing bugs for a duplicate by fingerprint.
 *
 * @param {string} cwd
 * @param {string} scanner
 * @param {string} testName
 * @param {string} fingerprint
 * @returns {{ bugId: string, status: string } | null}
 */
export function findDuplicate(cwd, scanner, testName, fingerprint) {
  const dir = resolve(cwd, ".forge", "bugs");
  if (!existsSync(dir)) return null;

  let files;
  try {
    files = readdirSync(dir).filter((f) => f.endsWith(".json"));
  } catch { return null; }

  for (const file of files) {
    try {
      const bug = JSON.parse(readFileSync(resolve(dir, file), "utf-8"));
      if (bug.fingerprint === fingerprint) {
        return { bugId: bug.bugId, status: bug.status };
      }
    } catch { /* skip corrupt */ }
  }
  return null;
}

// ─── Load / List ─────────────────────────────────────────────────────

/**
 * Load a single bug record by ID.
 * @param {string} cwd
 * @param {string} bugId
 * @returns {object|null}
 */
export function loadBug(cwd, bugId) {
  // Path traversal guard
  const safe = basename(bugId).replace(/[^a-zA-Z0-9_-]/g, "");
  if (!safe || safe !== bugId) return null;

  const filePath = resolve(cwd, ".forge", "bugs", `${safe}.json`);
  try {
    if (!existsSync(filePath)) return null;
    return JSON.parse(readFileSync(filePath, "utf-8"));
  } catch {
    return null;
  }
}

/**
 * List bugs with optional filters.
 *
 * @param {string} cwd
 * @param {object} [filters]
 * @param {string} [filters.status]
 * @param {string} [filters.severity]
 * @param {string} [filters.scanner]
 * @param {string} [filters.since] - ISO date string
 * @param {string} [filters.until] - ISO date string
 * @returns {object[]}
 */
export function listBugs(cwd, filters = {}) {
  const dir = resolve(cwd, ".forge", "bugs");
  if (!existsSync(dir)) return [];

  let files;
  try {
    files = readdirSync(dir).filter((f) => f.endsWith(".json"));
  } catch { return []; }

  const bugs = [];
  for (const file of files) {
    try {
      const bug = JSON.parse(readFileSync(resolve(dir, file), "utf-8"));
      if (filters.status && bug.status !== filters.status) continue;
      if (filters.severity && bug.severity !== filters.severity) continue;
      if (filters.scanner && bug.scanner !== filters.scanner) continue;
      if (filters.since && bug.discoveredAt < filters.since) continue;
      if (filters.until && bug.discoveredAt > filters.until) continue;
      bugs.push(bug);
    } catch { /* skip corrupt */ }
  }

  // Sort newest first
  bugs.sort((a, b) => (b.discoveredAt || "").localeCompare(a.discoveredAt || ""));
  return bugs;
}

// ─── Hub event helper ─────────────────────────────────────────────────

function emit(hub, type, data) {
  if (!hub || typeof hub.broadcast !== "function") return;
  try {
    hub.broadcast({ type, data, timestamp: new Date().toISOString() });
  } catch { /* best-effort */ }
}

// ─── Registration ─────────────────────────────────────────────────────

function validateRegisterBugInput(classification, evidence) {
  if (classification === "infra") {
    return {
      ok: true,
      classification: "infra",
      action: "recorded-in-run",
    };
  }
  if (!evidence.testName && !(evidence.assertionMessage && evidence.stackTrace)) {
    return { ok: false, error: ERROR_CODES.MISSING_EVIDENCE.code };
  }
  return null;
}

function findDuplicateRegistration(cwd, scanner, evidence) {
  const fingerprint = computeFingerprint(scanner, evidence);
  const dup = findDuplicate(cwd, scanner, evidence.testName, fingerprint);
  return { fingerprint, dup };
}

function buildBugRecord({ bugId, fingerprint, scanner, severity, classification, classifierMeta, evidence, affectedFiles, reproSteps, correlationId, sliceRef, discoveredAt }) {
  return {
    bugId,
    fingerprint,
    scanner,
    severity,
    status: "open",
    classification,
    classifierMeta,
    evidence,
    affectedFiles,
    reproSteps,
    correlationId,
    sliceRef,
    discoveredAt,
    updatedAt: discoveredAt,
  };
}

function persistBugRecord(dir, bugId, record, tmpSuffix = "tmp") {
  const finalPath = resolve(dir, `${bugId}.json`);
  const tmpPath = resolve(dir, `.${bugId}.${tmpSuffix}`);
  writeFileSync(tmpPath, JSON.stringify(record, null, 2) + "\n", "utf-8");
  try {
    renameSync(tmpPath, finalPath);
  } catch {
    writeFileSync(finalPath, JSON.stringify(record, null, 2) + "\n", "utf-8");
  }
  return finalPath;
}

async function maybeQueueCriticalBugReview({ classification, severity, cwd, bugId, scanner, evidence, hub, captureMemory }) {
  if (classification !== "real-bug" || severity !== "critical") return;
  try {
    const { maybeAddBugReview } = await import("../orchestrator.mjs");
    maybeAddBugReview(cwd, {
      title: `Bug ${bugId} needs human review (critical/functional)`,
      severity: "blocker",
      context: { bugId, classification, scanner, evidence: evidence ?? null },
      correlationId: bugId,
    }, hub, captureMemory);
  } catch { /* review hook is advisory */ }
}

async function maybeDelegateRegisteredBug({ classification, severity, cwd, bugId, record, hub, captureMemory }) {
  if (classification !== "real-bug" || (severity !== "critical" && severity !== "major")) return;
  try {
    const { loadAgentRoutingConfig, resolveRoute, recordDelegation, deriveBugType } = await import("./agent-router.mjs");
    const routingCfg = loadAgentRoutingConfig(cwd);
    if (!routingCfg.enabled) return;
    const route = resolveRoute({ ...record, type: deriveBugType(record) });
    if (!route) return;
    recordDelegation({ targetPath: cwd, bugId, route, mode: "review-queue-item", reviewItemId: null });
    const { addReviewItem } = await import("../orchestrator.mjs");
    const reviewResult = addReviewItem(cwd, {
      source: "fix-plan-approval",
      severity: severity === "critical" ? "blocker" : "high",
      title: `Agent delegation: ${bugId} → ${route.agent}`,
      context: { bugId, recordRef: `.forge/bugs/${bugId}.json`, suggestedAgent: route.agent, suggestedSkill: route.skill },
      correlationId: bugId,
    }, hub, captureMemory);
    emit(hub, "tempering-bug-delegated", { bugId, agent: route.agent, skill: route.skill, mode: "review-queue-item", reviewItemId: reviewResult?.itemId || null });
  } catch { /* advisory — never block registration */ }
}

function maybeCaptureRegisteredBug({ classification, captureMemory, bugId, scanner, evidence, severity, cwd }) {
  if (classification !== "real-bug" || typeof captureMemory !== "function") return;
  try {
    const summary = `Bug ${bugId} from ${scanner}: ${evidence.testName || evidence.assertionMessage || "unknown"} — severity=${severity}`;
    captureMemory(summary, "decision", `forge_bug_register/${scanner}/${severity}`, cwd);
  } catch { /* best-effort */ }
}

function attachExternalRef(record, external) {
  if (!external?.ok || !external?.issueNumber) return false;
  record.externalRef = {
    provider: external.provider,
    issueNumber: external.issueNumber,
    url: external.url || null,
    syncedAt: new Date().toISOString(),
  };
  return true;
}

async function maybeDispatchRegisteredBug(opts, record, dir, bugId) {
  if (record.classification !== "real-bug") return null;
  try {
    const dispatchConfig = opts?.config || {};
    const dispatchResult = await dispatch("register", record, dispatchConfig, { cwd: opts.cwd, ...opts });
    const external = dispatchResult?.external || null;
    if (attachExternalRef(record, external)) persistBugRecord(dir, bugId, record, "ext.tmp");
    return external;
  } catch {
    return null;
  }
}

/**
 * Register a bug discovered by a tempering scanner.
 *
 * @param {object} opts
 * @param {string} opts.cwd
 * @param {string} opts.scanner
 * @param {string} opts.severity - critical|high|medium|low
 * @param {object} opts.evidence - { testName, assertionMessage, stackTrace, ... }
 * @param {string[]} [opts.affectedFiles]
 * @param {string[]} [opts.reproSteps]
 * @param {string} opts.correlationId
 * @param {object|null} [opts.sliceRef]
 * @param {string} opts.classification - 'real-bug'|'infra'|'needs-human-review'|'unknown'
 * @param {object} opts.classifierMeta - { rule?, reason, confidence, source }
 * @param {object} [opts.hub]
 * @param {Function} [opts.captureMemory]
 * @param {Function} [opts.nowFn]
 * @returns {{ ok: boolean, bugId?: string, classification: string, action?: string, error?: string, existingBugId?: string }}
 */
export async function registerBug(opts) {
  try {
    const {
      cwd,
      scanner,
      severity = "medium",
      evidence = {},
      affectedFiles = [],
      reproSteps = [],
      correlationId,
      sliceRef = null,
      classification,
      classifierMeta = {},
      hub = null,
      captureMemory = null,
      nowFn = () => Date.now(),
    } = opts || {};

    const earlyResult = validateRegisterBugInput(classification, evidence);
    if (earlyResult) return earlyResult;

    const { fingerprint, dup } = findDuplicateRegistration(cwd, scanner, evidence);
    if (dup) {
      return { ok: false, error: ERROR_CODES.DUPLICATE_BUG.code, existingBugId: dup.bugId };
    }

    const bugId = generateBugId(cwd, nowFn);
    const discoveredAt = new Date(nowFn()).toISOString();
    const record = buildBugRecord({
      bugId,
      fingerprint,
      scanner,
      severity,
      classification,
      classifierMeta,
      evidence,
      affectedFiles,
      reproSteps,
      correlationId,
      sliceRef,
      discoveredAt,
    });

    const dir = ensureBugsDir(cwd);
    persistBugRecord(dir, bugId, record);

    emit(hub, "tempering-bug-registered", {
      bugId,
      scanner,
      severity,
      correlationId,
      classification,
      timestamp: discoveredAt,
    });

    await maybeQueueCriticalBugReview({ classification, severity, cwd, bugId, scanner, evidence, hub, captureMemory });
    await maybeDelegateRegisteredBug({ classification, severity, cwd, bugId, record, hub, captureMemory });
    maybeCaptureRegisteredBug({ classification, captureMemory, bugId, scanner, evidence, severity, cwd });
    const external = await maybeDispatchRegisteredBug(opts || {}, record, dir, bugId);

    return { ok: true, bugId, classification, external };
  } catch (err) {
    return { ok: false, error: `REGISTER_FAILED: ${err.message}` };
  }
}

// ─── Status transitions ──────────────────────────────────────────────

/**
 * Transition a bug's status with validation.
 *
 * @param {string} cwd
 * @param {string} bugId
 * @param {string} newStatus
 * @param {object} [opts]
 * @param {string} [opts.note]
 * @returns {{ ok: boolean, error?: string }}
 */
export async function updateBugStatus(cwd, bugId, newStatus, opts = {}) {
  try {
    const bug = loadBug(cwd, bugId);
    if (!bug) {
      return { ok: false, error: ERROR_CODES.BUG_NOT_FOUND.code };
    }

    if (!BUG_STATUSES.includes(newStatus)) {
      return { ok: false, error: ERROR_CODES.INVALID_STATUS.code };
    }

    const allowed = VALID_TRANSITIONS[bug.status];
    if (!allowed || !allowed.includes(newStatus)) {
      return { ok: false, error: ERROR_CODES.INVALID_TRANSITION.code, from: bug.status, to: newStatus };
    }

    bug.status = newStatus;
    bug.updatedAt = new Date().toISOString();
    if (opts.note) {
      bug.statusHistory = bug.statusHistory || [];
      bug.statusHistory.push({
        from: bug.status,
        to: newStatus,
        note: opts.note,
        at: bug.updatedAt,
      });
    }

    // Atomic write
    const dir = resolve(cwd, ".forge", "bugs");
    const finalPath = resolve(dir, `${bugId}.json`);
    const tmpPath = resolve(dir, `.${bugId}.tmp`);
    writeFileSync(tmpPath, JSON.stringify(bug, null, 2) + "\n", "utf-8");
    try {
      renameSync(tmpPath, finalPath);
    } catch {
      writeFileSync(finalPath, JSON.stringify(bug, null, 2) + "\n", "utf-8");
    }

    // External adapter dispatch (advisory)
    let external = null;
    try {
      const dispatchConfig = opts?.config || {};
      const dispatchResult = await dispatch("updateStatus", bug, dispatchConfig, { cwd, ...opts });
      external = dispatchResult?.external || null;
    } catch { /* external dispatch is advisory */ }

    return { ok: true, bugId, newStatus, external };
  } catch (err) {
    return { ok: false, error: `UPDATE_FAILED: ${err.message}` };
  }
}

// ─── External reference management ───────────────────────────────────

/**
 * Set or update the external reference on a bug (for reconciliation paths).
 *
 * @param {string} cwd
 * @param {string} bugId
 * @param {object} ref - { provider, issueNumber, url, syncedAt }
 * @returns {{ ok: boolean, error?: string }}
 */
export function setExternalRef(cwd, bugId, ref) {
  try {
    const bug = loadBug(cwd, bugId);
    if (!bug) return { ok: false, error: ERROR_CODES.BUG_NOT_FOUND.code };

    bug.externalRef = ref;
    bug.updatedAt = new Date().toISOString();

    const dir = resolve(cwd, ".forge", "bugs");
    const finalPath = resolve(dir, `${bugId}.json`);
    const tmpPath = resolve(dir, `.${bugId}.ext.tmp`);
    writeFileSync(tmpPath, JSON.stringify(bug, null, 2) + "\n", "utf-8");
    try {
      renameSync(tmpPath, finalPath);
    } catch {
      writeFileSync(finalPath, JSON.stringify(bug, null, 2) + "\n", "utf-8");
    }

    return { ok: true };
  } catch (err) {
    return { ok: false, error: `SET_REF_FAILED: ${err.message}` };
  }
}

// ─── Closed-loop helpers (Phase TEMPER-06 Slice 06.3) ─────────────────

/**
 * Set the linked fix-plan path on a bug record.
 *
 * @param {string} cwd
 * @param {string} bugId
 * @param {string} planPath - relative plan file path
 * @returns {{ ok: boolean, error?: string }}
 */
export function setLinkedFixPlan(cwd, bugId, planPath) {
  try {
    const bug = loadBug(cwd, bugId);
    if (!bug) return { ok: false, error: ERROR_CODES.BUG_NOT_FOUND.code };

    bug.linkedFixPlan = planPath;
    bug.updatedAt = new Date().toISOString();

    const dir = resolve(cwd, ".forge", "bugs");
    const finalPath = resolve(dir, `${bugId}.json`);
    const tmpPath = resolve(dir, `.${bugId}.lfp.tmp`);
    writeFileSync(tmpPath, JSON.stringify(bug, null, 2) + "\n", "utf-8");
    try {
      renameSync(tmpPath, finalPath);
    } catch {
      writeFileSync(finalPath, JSON.stringify(bug, null, 2) + "\n", "utf-8");
    }

    return { ok: true };
  } catch (err) {
    return { ok: false, error: `SET_LINKED_FIX_PLAN_FAILED: ${err.message}` };
  }
}

/**
 * Append a validation attempt to a bug's validationAttempts array.
 *
 * @param {string} cwd
 * @param {string} bugId
 * @param {object} attempt - { at, scanners, result, details }
 * @returns {{ ok: boolean, error?: string }}
 */
export function appendValidationAttempt(cwd, bugId, attempt) {
  try {
    const bug = loadBug(cwd, bugId);
    if (!bug) return { ok: false, error: ERROR_CODES.BUG_NOT_FOUND.code };

    if (!Array.isArray(bug.validationAttempts)) {
      bug.validationAttempts = [];
    }
    bug.validationAttempts.push(attempt);
    bug.updatedAt = new Date().toISOString();

    const dir = resolve(cwd, ".forge", "bugs");
    const finalPath = resolve(dir, `${bugId}.json`);
    const tmpPath = resolve(dir, `.${bugId}.va.tmp`);
    writeFileSync(tmpPath, JSON.stringify(bug, null, 2) + "\n", "utf-8");
    try {
      renameSync(tmpPath, finalPath);
    } catch {
      writeFileSync(finalPath, JSON.stringify(bug, null, 2) + "\n", "utf-8");
    }

    return { ok: true };
  } catch (err) {
    return { ok: false, error: `APPEND_VALIDATION_FAILED: ${err.message}` };
  }
}

/**
 * Plan Forge — Classifier-Lane GitHub Issue Filer (v3.5.0)
 *
 * When tempering triage routes a finding to the "classifier" lane
 * (classification: "infra"), this module creates a GitHub issue proposing
 * an update to the classifier rules that would suppress the pattern.
 *
 * The issue is deduped by a stable hash of `(findingClass, reason)` so
 * repeated runs of the same noisy pattern don't spam the tracker.
 *
 * Design contracts:
 *   - Never throws — all paths return structured `{ ok, ... }`
 *   - No side effects beyond GitHub issue creation
 *   - Dedup window: 7 days (same hash in an open issue = comment instead)
 *   - Token resolution: env → .forge/secrets.json → gh auth token
 *
 * @module tempering/classifier-issue
 */

import { createHash } from "node:crypto";
import { existsSync, readFileSync } from "node:fs";
import { resolve } from "node:path";
import { ERROR_CODES } from "../enums.mjs";

// ─── Labels ──────────────────────────────────────────────────────────────────

export const CLASSIFIER_ISSUE_LABELS = Object.freeze([
  "classifier-noise",
  "plan-forge-internal",
]);

// ─── Hash helper ─────────────────────────────────────────────────────────────

/**
 * Compute a stable 12-char hex hash for deduplication.
 * @param {string} findingClass - The finding class (e.g. "missing-h1")
 * @param {string} reason       - Classifier reason string
 * @returns {string} 12-character hex hash
 */
export function computeClassifierIssueHash(findingClass, reason) {
  const key = `classifier:${(findingClass || "").toLowerCase()}:${(reason || "").toLowerCase().replace(/\s+/g, " ").trim()}`;
  return createHash("sha256").update(key).digest("hex").slice(0, 12);
}

// ─── Issue body builder ───────────────────────────────────────────────────────

/**
 * Build the markdown body for a classifier-noise GitHub issue.
 *
 * @param {object} payload - Classifier-lane payload from `routeFinding`
 * @param {string} hash    - Dedup hash to embed in title
 * @returns {string}
 */
export function buildClassifierIssueBody(payload, hash) {
  const lines = [
    `## Classifier Noise Report`,
    "",
    `**Finding Class:** \`${payload.findingClass || "unknown"}\``,
  ];
  if (payload.route) {
    lines.push(`**Route:** \`${payload.route}\``);
  }
  lines.push(
    `**Current Classification:** \`${payload.currentClassification || "infra"}\``,
    "",
    `## Proposed Action`,
    "",
    payload.proposedAction || "Add or update a classifier rule to suppress this pattern.",
    "",
  );
  if (payload.reason) {
    lines.push("## Classifier Reason", "", payload.reason, "");
  }
  if (payload.rule) {
    lines.push(`**Matched Rule:** \`${payload.rule}\``);
  }
  const evidenceKeys = Object.keys(payload.evidence || {});
  if (evidenceKeys.length > 0) {
    lines.push(...[
      "",
      "<details>",
      "<summary>Evidence JSON</summary>",
      "",
      "```json",
      JSON.stringify(payload.evidence, null, 2),
      "```",
      "",
      "</details>",
    ]);
  }
  lines.push(
    "",
    "---",
    `*Filed automatically by [Plan Forge Tempering](https://github.com/srnichols/plan-forge) — hash \`${hash || ""}\`*`,
  );
  return lines.join("\n");
}

// ─── Token + repo resolution (mirrors bug-adapters/github.mjs) ───────────────

function resolveToken(config, { execSync: execSyncFn, cwd } = {}) {
  const envToken = process.env.GITHUB_TOKEN;
  if (envToken) return { token: envToken, source: "env" };

  if (cwd) {
    const secretsPath = resolve(cwd, ".forge", "secrets.json");
    try {
      if (existsSync(secretsPath)) {
        const s = JSON.parse(readFileSync(secretsPath, "utf-8"));
        if (s?.github?.token) return { token: s.github.token, source: "secrets.json" };
      }
    } catch { /* malformed */ }
  }

  if (typeof execSyncFn === "function") {
    try {
      const t = execSyncFn("gh auth token", { encoding: "utf-8", timeout: 10_000, stdio: ["pipe", "pipe", "pipe"], cwd }).trim();
      if (t) return { token: t, source: "gh-cli" };
    } catch { /* gh not available */ }
  }

  return { token: null, error: ERROR_CODES.NO_TOKEN.code };
}

function resolveRepo(config, { execSync: execSyncFn, cwd } = {}) {
  const cfgRepo = config?.bugRegistry?.githubRepo;
  if (cfgRepo?.includes("/")) {
    const [owner, repo] = cfgRepo.split("/");
    if (owner && repo) return { owner, repo };
  }
  if (typeof execSyncFn === "function") {
    try {
      const url = execSyncFn("git remote get-url origin", { encoding: "utf-8", timeout: 5_000, stdio: ["pipe", "pipe", "pipe"], cwd }).trim();
      const https = url.match(/github\.com\/([^/]+)\/([^/.]+?)(?:\.git)?$/);
      if (https) return { owner: https[1], repo: https[2] };
      const ssh = url.match(/github\.com:([^/]+)\/([^/.]+?)(?:\.git)?$/);
      if (ssh) return { owner: ssh[1], repo: ssh[2] };
    } catch { /* no remote */ }
  }
  return null;
}

// ─── Dedup check ─────────────────────────────────────────────────────────────

async function findExisting({ hash, owner, repo, token, execSync: execSyncFn, fetch: fetchFn, cwd }) {
  if (typeof execSyncFn === "function") {
    try {
      const cmd = `gh issue list --repo "${owner}/${repo}" --label "classifier-noise" --state open --search "${hash}" --json number,url,title --limit 10`;
      const raw = execSyncFn(cmd, { encoding: "utf-8", timeout: 30_000, stdio: ["pipe", "pipe", "pipe"], cwd }).trim();
      if (raw) {
        const issues = JSON.parse(raw);
        const match = issues.find((i) => i.title?.includes(hash));
        if (match) return { issueNumber: match.number, url: match.url };
      }
    } catch { /* fall through */ }
  }
  if (token && typeof fetchFn === "function") {
    try {
      const q = encodeURIComponent(`repo:${owner}/${repo} label:classifier-noise state:open "${hash}" in:title`);
      const res = await fetchFn(`https://api.github.com/search/issues?q=${q}&per_page=5`, {
        headers: { Authorization: `Bearer ${token}`, Accept: "application/vnd.github+json", "X-GitHub-Api-Version": "2022-11-28" },
        signal: AbortSignal.timeout(30_000),
      });
      if (res.ok) {
        const data = await res.json();
        const match = (data.items || []).find((i) => i.title?.includes(hash));
        if (match) return { issueNumber: match.number, url: match.html_url };
      }
    } catch { /* search failed */ }
  }
  return null;
}

// ─── Issue creation helpers ──────────────────────────────────────────────────

function createViaGh({ owner, repo, title, body, labels, execSync: execSyncFn, cwd }) {
  if (typeof execSyncFn !== "function") return null;
  try {
    const labelArg = labels.map((l) => `--label "${l}"`).join(" ");
    const safeTitle = title.replace(/"/g, '\\"');
    const safeBody = body.replace(/"/g, '\\"').replace(/\n/g, "\\n");
    const cmd = `gh issue create --repo "${owner}/${repo}" --title "${safeTitle}" --body "${safeBody}" ${labelArg}`;
    const out = execSyncFn(cmd, { encoding: "utf-8", timeout: 30_000, stdio: ["pipe", "pipe", "pipe"], cwd }).trim();
    const m = out.match(/\/issues\/(\d+)/);
    if (m) return { issueNumber: parseInt(m[1], 10), url: out };
    return null;
  } catch {
    return null;
  }
}

async function createViaRest({ token, owner, repo, title, body, labels, fetch: fetchFn }) {
  if (typeof fetchFn !== "function") return null;
  try {
    const res = await fetchFn(`https://api.github.com/repos/${owner}/${repo}/issues`, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${token}`,
        Accept: "application/vnd.github+json",
        "Content-Type": "application/json",
        "X-GitHub-Api-Version": "2022-11-28",
      },
      body: JSON.stringify({ title, body, labels }),
      signal: AbortSignal.timeout(30_000),
    });
    if (!res.ok) return { error: `HTTP_${res.status}` };
    const data = await res.json();
    return { issueNumber: data.number, url: data.html_url };
  } catch (err) {
    return { error: err.name === "TimeoutError" ? ERROR_CODES.TIMEOUT.code : ERROR_CODES.NETWORK_ERROR.code };
  }
}

async function addComment({ token, owner, repo, issueNumber, body, fetch: fetchFn }) {
  if (typeof fetchFn !== "function") return null;
  try {
    const res = await fetchFn(`https://api.github.com/repos/${owner}/${repo}/issues/${issueNumber}/comments`, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${token}`,
        Accept: "application/vnd.github+json",
        "Content-Type": "application/json",
        "X-GitHub-Api-Version": "2022-11-28",
      },
      body: JSON.stringify({ body }),
      signal: AbortSignal.timeout(30_000),
    });
    if (!res.ok) return { error: `HTTP_${res.status}` };
    const data = await res.json();
    return { commentId: data.id, url: data.html_url };
  } catch {
    return null;
  }
}

// ─── Main entry point ────────────────────────────────────────────────────────

/**
 * File (or dedup-comment on) a classifier-noise GitHub issue.
 *
 * @param {object} payload  - Classifier-lane payload from `routeFinding`
 * @param {object} config   - Forge configuration (from .forge.json)
 * @param {object} [deps]
 * @param {Function} [deps.execSync]
 * @param {Function} [deps.fetch]
 * @param {string}   [deps.cwd]
 * @returns {Promise<{ ok: boolean, issueNumber?: number, url?: string, deduped?: boolean, message: string }>}
 */
export async function fileClassifierIssue(payload, config, {
  execSync: execSyncFn,
  fetch: fetchFn = globalThis.fetch,
  cwd,
} = {}) {
  try {
    const hash = computeClassifierIssueHash(payload.findingClass, payload.reason);

    const tokenResult = resolveToken(config, { execSync: execSyncFn, cwd });
    if (!tokenResult.token) {
      return { ok: false, error: ERROR_CODES.NO_TOKEN.code, message: "No GitHub token — set GITHUB_TOKEN, .forge/secrets.json#github.token, or run `gh auth login`." };
    }

    const repoInfo = resolveRepo(config, { execSync: execSyncFn, cwd });
    if (!repoInfo) {
      return { ok: false, error: ERROR_CODES.NO_REPO.code, message: "Could not resolve GitHub repository. Set bugRegistry.githubRepo in .forge.json." };
    }

    // Dedup: check for existing open issue with same hash
    const existing = await findExisting({ hash: hash, owner: repoInfo.owner, repo: repoInfo.repo, token: tokenResult.token, ...{ execSync: execSyncFn, fetch: fetchFn, cwd } });
    if (existing) {
      const commentBody = `## Recurrence\n\nThis classifier noise pattern was observed again.\n\n**Finding:** \`${payload.findingClass || "unknown"}\`\n**Route:** \`${payload.route || ""}\`\n\n*Reported by Plan Forge Tempering — hash \`${hash}\`*`;
      await addComment({ token: tokenResult.token, owner: repoInfo.owner, repo: repoInfo.repo, issueNumber: existing.issueNumber, body: commentBody, fetch: fetchFn });
      return { ok: true, issueNumber: existing.issueNumber, url: existing.url, deduped: true, message: `Commented on existing issue #${existing.issueNumber} (hash ${hash} already open).` };
    }

    const title = `[classifier-noise:${hash}] ${payload.findingClass || "unknown"}: ${(payload.reason || "noise pattern").slice(0, 80)}`;
    const body = buildClassifierIssueBody(payload, hash);

    let result = createViaGh({ owner: repoInfo.owner, repo: repoInfo.repo, title, body, labels: [...CLASSIFIER_ISSUE_LABELS], execSync: execSyncFn, cwd });
    if (!result || result.error) {
      result = await createViaRest({
        token: tokenResult.token,
        owner: repoInfo.owner,
        repo: repoInfo.repo,
        title,
        body,
        labels: [...CLASSIFIER_ISSUE_LABELS],
        fetch: fetchFn,
      });
    }

    if (!result || result.error) {
      return { ok: false, error: result?.error || ERROR_CODES.CREATE_FAILED.code, message: "GitHub issue creation failed. Check token permissions and repository access." };
    }

    return { ok: true, issueNumber: result.issueNumber, url: result.url, deduped: false, message: `Classifier-noise issue #${result.issueNumber} created.` };
  } catch (err) {
    return { ok: false, error: ERROR_CODES.UNEXPECTED.code, message: err?.message || "Unexpected error in fileClassifierIssue." };
  }
}

/**
 * Tempering drain — round-loop driver that wraps `runTemperingRun` and
 * iterates until convergence or max-rounds (Phase-39 Slice 2).
 *
 * The drain is the novel contract from proposal 0001: run tempering
 * repeatedly, counting real findings and noise patterns per round,
 * until the system has either fixed everything or taught its classifier
 * not to flag it. The drain curve (e.g., 88→31→4→0) is a compact,
 * auditable session artifact.
 *
 * Design constraints:
 *   - Never throws — always returns a result frame
 *   - `runTemperingRun` dependency is injectable for tests
 *   - Per-round deltas written to `.forge/tempering/drain-history.jsonl`
 *   - Convergence rule injectable; default requires zero real findings
 *     AND zero patterns AND a healthy run (ok === true)
 *   - Max-rounds cap prevents infinite tuning
 *   - AbortSignal checked between rounds (not mid-round)
 *
 * @module tempering/drain
 */

import { existsSync, mkdirSync, appendFileSync } from "node:fs";
import { resolve } from "node:path";
import { randomUUID } from "node:crypto";
import { runTemperingRun } from "./runner.mjs";

// ─── Hub event helper ────────────────────────────────────────────────

function emit(hub, type, data) {
  if (!hub || typeof hub.broadcast !== "function") return;
  try {
    hub.broadcast({ type, data, timestamp: new Date().toISOString() });
  } catch { /* best-effort */ }
}

// ─── Finding extraction ──────────────────────────────────────────────

/**
 * Extract real-finding and pattern counts from a `runTemperingRun` result.
 *
 * - realFindings: severity !== "info" && severity !== "ok"
 * - patterns:     severity === "info" (noise / classifier-fixable)
 */
function extractCounts(runResult) {
  if (!runResult || !runResult.ok || !Array.isArray(runResult.scanners)) {
    return { realFindings: 0, patterns: 0, findings: [] };
  }
  const allFindings = [];
  for (const scanner of runResult.scanners) {
    if (Array.isArray(scanner.findings)) {
      allFindings.push(...scanner.findings);
    }
  }
  let realFindings = 0;
  let patterns = 0;
  for (const f of allFindings) {
    if (f.severity === "info" || f.severity === "ok") {
      patterns++;
    } else {
      realFindings++;
    }
  }
  return { realFindings, patterns, findings: allFindings };
}

// ─── JSONL history writer ────────────────────────────────────────────

function ensureHistoryDir(projectDir) {
  const dir = resolve(projectDir, ".forge", "tempering");
  const errors = [];
  if (!existsSync(dir)) {
    try {
      mkdirSync(dir, { recursive: true });
    } catch (err) {
      errors.push({ op: "mkdir", path: dir, message: err.message });
    }
  }
  return { historyPath: resolve(dir, "drain-history.jsonl"), errors };
}

function appendHistoryLine(historyPath, line, errors) {
  try {
    appendFileSync(historyPath, JSON.stringify(line) + "\n", "utf-8");
    return true;
  } catch (err) {
    // Record the first write error we see; subsequent failures are usually
    // the same cause and noisy to log individually.
    if (errors && errors.length === 0) {
      errors.push({ op: "append", path: historyPath, message: err.message });
    }
    return false;
  }
}

// ─── Default convergence rule ────────────────────────────────────────

function defaultConvergenceRule(roundData) {
  return roundData.realFindings === 0 && roundData.patterns === 0;
}

function makeDrainRoundBase(round, runResult, now) {
  return {
    round,
    runId: runResult?.runId || null,
    ts: new Date(now()).toISOString(),
    verdict: runResult?.verdict || null,
  };
}

function failedDrainRound(round, runResult, now) {
  return {
    ...makeDrainRoundBase(round, runResult, now),
    realFindings: 0,
    patterns: 0,
    deltas: null,
    error: runResult?.error || "run-failed",
  };
}

function noWorkDrainRound(round, runResult, now) {
  return {
    ...makeDrainRoundBase(round, runResult, now),
    realFindings: 0,
    patterns: 0,
    deltas: null,
    findingCount: 0,
    noWork: true,
    reason: runResult.skipped ? (runResult.reason || "tempering-skipped") : "no-scanners-executed",
  };
}

function completedDrainRound({ round, runResult, now, prevRealFindings, prevPatterns }) {
  const { realFindings, patterns, findings } = extractCounts(runResult);
  return {
    ...makeDrainRoundBase(round, runResult, now),
    realFindings,
    patterns,
    deltas: prevRealFindings !== null
      ? { realFindings: realFindings - prevRealFindings, patterns: patterns - prevPatterns }
      : null,
    findingCount: findings.length,
  };
}

function finalizeDrainSummary({ corr, rounds, terminated, historyPath, fsErrors }) {
  const summary = {
    correlationId: corr,
    totalRounds: rounds.length,
    terminated,
    drainCurve: rounds.map((r) => r.realFindings),
    finalRealFindings: rounds.length > 0 ? rounds[rounds.length - 1].realFindings : 0,
    finalPatterns: rounds.length > 0 ? rounds[rounds.length - 1].patterns : 0,
    historyPath,
  };
  if (fsErrors.length > 0) summary.fsErrors = fsErrors;
  if (terminated === "no-work" && rounds.length > 0) summary.reason = rounds[rounds.length - 1].reason;
  return summary;
}

async function executeDrainLoop({ project, maxRounds, convergenceRule, spawnWorker, hub, abortSignal, runTemperingRunFn, now, corr, historyPath, fsErrors }) {
  emit(hub, "drain-started", {
    correlationId: corr,
    project,
    maxRounds,
    ts: new Date(now()).toISOString(),
  });

  const rounds = [];
  let terminated = "max-rounds";
  let prevRealFindings = null;
  let prevPatterns = null;

  for (let round = 1; round <= maxRounds; round++) {
    if (abortSignal && abortSignal.aborted) {
      terminated = "aborted";
      break;
    }

    const runResult = await runTemperingRunFn({
      projectDir: project,
      hub,
      correlationId: `${corr}-round-${round}`,
      spawnWorker,
      now,
    });

    if (!runResult || !runResult.ok) {
      rounds.push(failedDrainRound(round, runResult, now));
      appendHistoryLine(historyPath, rounds[rounds.length - 1], fsErrors);
      terminated = "aborted";
      break;
    }

    if (runResult.skipped === true || !Array.isArray(runResult.scanners) || runResult.scanners.length === 0) {
      rounds.push(noWorkDrainRound(round, runResult, now));
      appendHistoryLine(historyPath, rounds[rounds.length - 1], fsErrors);
      terminated = "no-work";
      break;
    }

    const roundData = completedDrainRound({ round: round, runResult: runResult, now: now, prevRealFindings: prevRealFindings, prevPatterns: prevPatterns });
    rounds.push(roundData);
    appendHistoryLine(historyPath, roundData, fsErrors);
    emit(hub, "drain-round-completed", { correlationId: corr, ...roundData });

    if (convergenceRule(roundData)) {
      terminated = "converged";
      break;
    }
    prevRealFindings = roundData.realFindings;
    prevPatterns = roundData.patterns;
  }

  const summary = finalizeDrainSummary({ corr: corr, rounds: rounds, terminated: terminated, historyPath: historyPath, fsErrors: fsErrors });
  emit(hub, "drain-completed", { correlationId: corr, ...summary });
  return { rounds, terminated, summary };
}

// ─── Main entry point ────────────────────────────────────────────────

/**
 * Run tempering in a drain loop until convergence or max-rounds.
 *
 * @param {object} opts
 * @param {string}   opts.project          — project directory
 * @param {number}   [opts.maxRounds=5]    — cap to prevent infinite loops
 * @param {string[]} [opts.scanners]       — scanner names to run (passed to runner)
 * @param {Function} [opts.convergenceRule] — `(roundData) => boolean`
 * @param {Function} [opts.spawnWorker]    — DI for LLM workers
 * @param {object}   [opts.hub]            — SSE event hub
 * @param {string}   [opts.correlationId]  — trace correlation
 * @param {AbortSignal} [opts.abortSignal] — cancel between rounds
 * @param {Function} [opts.runTemperingRunFn] — DI for tests
 * @param {Function} [opts.now]            — injectable clock
 * @returns {Promise<{ rounds: Array, terminated: string, summary: object }>}
 */
export function runTemperingDrain(opts = {}) {
  const {
    project,
    maxRounds = 5,
    scanners: scannerNames,
    convergenceRule = defaultConvergenceRule,
    spawnWorker = null,
    hub = null,
    correlationId = null,
    abortSignal = null,
    runTemperingRunFn = runTemperingRun,
    now = () => Date.now(),
  } = opts;

  const corr = correlationId || `drain-${randomUUID()}`;

  if (!project || typeof project !== "string") {
    return Promise.resolve({
      rounds: [],
      terminated: "aborted",
      summary: { error: "project directory required", correlationId: corr },
    });
  }

  const historyFs = ensureHistoryDir(project);
  const historyPath = historyFs.historyPath;
  const fsErrors = [...historyFs.errors];

  return executeDrainLoop({
    project,
    maxRounds,
    convergenceRule,
    spawnWorker,
    hub,
    abortSignal,
    runTemperingRunFn,
    now,
    corr,
    historyPath,
    fsErrors,
  });
}

/**
 * Plan Forge — Tempering: execution orchestrator (Phase TEMPER-02 Slice 02.1)
 *
 * First phase that actually *runs* code. TEMPER-01 was read-only —
 * it scanned pre-existing coverage reports. This module owns the
 * subprocess boundary that executes test suites and parses their output.
 *
 * Design contracts (non-negotiable):
 *   - Handlers never throw. Always return `{ ok, ... }` shapes.
 *   - Subprocess is abort-able against `config.runtimeBudgets.<scanner>MaxMs`.
 *     SIGTERM first, SIGKILL 2s later if the process ignores it.
 *   - Tests inject `spawn` + `now` + `adapter` overrides — nothing in
 *     this file reaches the real filesystem or the real child_process
 *     module when a test provides overrides.
 *   - Scope contract (from Phase-TEMPER-02.md):
 *       * MUST NOT edit production source during a run
 *       * MUST NOT create bugs (TEMPER-06 owns that)
 *       * MUST NOT invoke itself recursively
 *
 * @module tempering/runner
 */

import { spawn as realSpawn } from "node:child_process";
import { existsSync, mkdirSync, writeFileSync } from "node:fs";
import { resolve } from "node:path";
import { randomUUID } from "node:crypto";
import { ERROR_CODES } from "../enums.mjs";

import {
  readTemperingConfig,
  detectStack,
  ensureTemperingDirs,
} from "../tempering.mjs";
import { loadAdapter, validateAdapterEntry, SUPPORTED_STACKS_SLICE_02_1 } from "./adapters.mjs";
// TEMPER-06 Slice 06.1 — Bug registry + classifier
import { classify as realClassify } from "./bug-classifier.mjs";
import { registerBug as realRegisterBug } from "./bug-registry.mjs";

// ─── Constants ────────────────────────────────────────────────────────

/** Kill grace period between SIGTERM and SIGKILL. */
const KILL_GRACE_MS = 2000;

/** Default per-scanner budget fallback (matches tempering.mjs). */
const DEFAULT_UNIT_BUDGET_MS = 120000;

// ─── Hub event helper (mirrors tempering.mjs) ─────────────────────────

function emit(hub, type, data) {
  if (!hub || typeof hub.broadcast !== "function") return;
  try {
    hub.broadcast({ type, data, timestamp: new Date().toISOString() });
  } catch { /* best-effort */ }
}

// ─── Subprocess boundary ──────────────────────────────────────────────

/**
 * Execute a command and return its stdout/stderr/exitCode, with a
 * hard timeout. Pure function of its inputs when `spawnFn` is injected.
 *
 * Behaviour:
 *   - Never throws. Errors are captured as `{ exitCode: -1, error }`.
 *   - On timeout: `timedOut: true`, SIGTERM, then SIGKILL after 2s.
 *   - On spawn error (ENOENT / command not found): `{ exitCode: -1, error }`.
 *
 * @param {string[]} cmd        - argv, e.g. ["npx", "vitest", "run"]
 * @param {{ cwd: string, budgetMs: number, spawn?: Function, env?: object }} opts
 * @returns {Promise<{ stdout: string, stderr: string, exitCode: number, timedOut: boolean, error?: string, durationMs: number }>}
 */
export function runSubprocess(cmd, { cwd, budgetMs, spawn: spawnFn = realSpawn, env } = {}) {
  return new Promise((settle) => {
    if (!Array.isArray(cmd) || cmd.length === 0) {
      settle({ stdout: "", stderr: "", exitCode: -1, timedOut: false, error: "empty-cmd", durationMs: 0 });
      return;
    }
    const [bin, ...args] = cmd;
    const t0 = Date.now();
    let proc;
    try {
      proc = spawnFn(bin, args, {
        cwd,
        shell: false,
        windowsHide: true,
        env: env || process.env,
      });
    } catch (err) {
      settle({ stdout: "", stderr: "", exitCode: -1, timedOut: false, error: err.message, durationMs: 0 });
      return;
    }

    let stdout = "";
    let stderr = "";
    let timedOut = false;
    let settled = false;

    const done = (outcome) => {
      if (settled) return;
      settled = true;
      try { clearTimeout(timer); } catch { /* ignore */ }
      try { clearTimeout(killer); } catch { /* ignore */ }
      settle({ ...outcome, durationMs: Date.now() - t0 });
    };

    const timer = setTimeout(() => {
      timedOut = true;
      try { proc.kill("SIGTERM"); } catch { /* best-effort */ }
    }, Math.max(1, budgetMs || DEFAULT_UNIT_BUDGET_MS));

    const killer = setTimeout(() => {
      if (!settled) {
        try { proc.kill("SIGKILL"); } catch { /* best-effort */ }
      }
    }, Math.max(1, budgetMs || DEFAULT_UNIT_BUDGET_MS) + KILL_GRACE_MS);

    if (proc.stdout) proc.stdout.on("data", (d) => { stdout += d.toString(); });
    if (proc.stderr) proc.stderr.on("data", (d) => { stderr += d.toString(); });

    proc.on("error", (err) => {
      done({ stdout, stderr, exitCode: -1, timedOut, error: err.message });
    });
    proc.on("close", (code, signal) => {
      // timeout-triggered SIGTERM returns code=null, signal=SIGTERM
      done({
        stdout,
        stderr,
        exitCode: typeof code === "number" ? code : -1,
        timedOut,
        error: signal && timedOut ? `killed-${signal}` : undefined,
      });
    });
  });
}

// ─── Regression-first ordering ────────────────────────────────────────

/**
 * Pick the changed-files list for regression-first ordering. Returns
 * an array of file paths relative to `cwd`, or `[]` when we can't or
 * shouldn't narrow. Never throws.
 *
 * This is a hint to the adapter, not an enforcement — adapters decide
 * whether to honour it (e.g. `vitest --changed` supports it natively).
 *
 * @param {object} opts
 * @param {string} opts.cwd
 * @param {string|null} opts.lastGreenSha
 * @param {Function} [opts.gitSpawn]     - injectable for tests
 * @returns {Promise<string[]>}
 */
export async function pickChangedFiles({ cwd, lastGreenSha, gitSpawn = realSpawn } = {}) {
  if (!lastGreenSha || typeof lastGreenSha !== "string") return [];
  const result = await runSubprocess(
    ["git", "diff", "--name-only", `${lastGreenSha}..HEAD`],
    { cwd, budgetMs: 5000, spawn: gitSpawn },
  );
  if (result.exitCode !== 0 || !result.stdout) return [];
  return result.stdout
    .split(/\r?\n/)
    .map((l) => l.trim())
    .filter(Boolean);
}

// ─── Per-scanner runners ──────────────────────────────────────────────

/**
 * Budget-key map: scanner id → config.runtimeBudgets key.
 * Keeps the generic runner free of scanner-specific branching.
 */
const SCANNER_BUDGET_KEYS = Object.freeze({
  unit: "unitMaxMs",
  integration: "integrationMaxMs",
  "visual-diff": "visualDiffMaxMs",
  flakiness: "flakinessMaxMs",
  "performance-budget": "perfBudgetMaxMs",
  "load-stress": "loadStressMaxMs",
  mutation: "mutationMaxMs",
  "content-audit": "contentAuditMaxMs",
});

/**
 * Generic scanner runner — the same orchestration logic for any
 * scanner whose adapter entry has `{ supported, cmd, parseOutput }`.
 * Pure function of its inputs when `spawnFn`, `now`, `adapter` are
 * injected.
 *
 * @param {object} ctx
 * @param {string} ctx.scanner           - "unit" | "integration" (future: "ui-playwright" …)
 * @param {object} ctx.config            - loaded tempering config
 * @param {string} ctx.stack
 * @param {object|null} ctx.adapter
 * @param {{plan:string, slice:string}|null} ctx.sliceRef
 * @param {string} ctx.cwd
 * @param {Function} [ctx.spawn]
 * @param {Function} [ctx.now]
 * @returns {Promise<object>} scanner result record
 */
function _checkScannerSkipReason(scanner, config, adapter) {
  if (!scanner) return "missing-scanner-id";
  if (!config || !config.scanners || config.scanners[scanner] === false) return "scanner-disabled";
  if (!adapter || !adapter[scanner]) return "no-adapter";
  const check = validateAdapterEntry(adapter[scanner]);
  if (!check.ok) return `invalid-adapter:${check.reason}`;
  if (adapter[scanner].supported === false) return adapter[scanner].reason || "stack-not-supported";
  return null;
}

function _computeScannerVerdict(proc, parsed) {
  if (proc.timedOut) return "budget-exceeded";
  if (proc.error && proc.exitCode === -1) return "error";
  if ((parsed.fail || 0) > 0) return "fail";
  if (proc.exitCode !== 0) return "fail";
  return "pass";
}

export async function runScanner(ctx) {
  const {
    scanner,
    config,
    stack,
    adapter,
    sliceRef = null,
    cwd,
    spawn: spawnFn = realSpawn,
    now = () => Date.now(),
  } = ctx || {};

  const t0 = now();
  const base = { scanner, stack, sliceRef, startedAt: new Date(t0).toISOString() };
  const skippedFrame = (reason) => ({
    ...base, skipped: true, reason, verdict: "skipped", durationMs: 0,
    completedAt: new Date(now()).toISOString(),
  });

  const skipReason = _checkScannerSkipReason(scanner, config, adapter);
  if (skipReason) return skippedFrame(skipReason);

  const budgetKey = SCANNER_BUDGET_KEYS[scanner] || `${scanner}MaxMs`;
  const budgetMs = (config.runtimeBudgets && config.runtimeBudgets[budgetKey]) || DEFAULT_UNIT_BUDGET_MS;

  const proc = await runSubprocess(adapter[scanner].cmd, { cwd, budgetMs, spawn: spawnFn });

  let parsed = { pass: 0, fail: 0, skipped: 0, coverage: null };
  try {
    parsed = adapter[scanner].parseOutput(proc.stdout, proc.stderr, proc.exitCode) || parsed;
  } catch (err) {
    parsed = { pass: 0, fail: 0, skipped: 0, coverage: null, parseError: err.message };
  }

  return {
    ...base,
    completedAt: new Date(now()).toISOString(),
    cmd: adapter[scanner].cmd,
    exitCode: proc.exitCode,
    timedOut: proc.timedOut,
    error: proc.error || null,
    pass: parsed.pass || 0,
    fail: parsed.fail || 0,
    skipped: parsed.skipped || 0,
    coverage: parsed.coverage || null,
    parseError: parsed.parseError || null,
    durationMs: now() - t0,
    verdict: _computeScannerVerdict(proc, parsed),
  };
}

/**
 * Back-compat wrapper — Slice 02.1 shipped `runScannerUnit` as the
 * public API; Slice 02.2 generalises it to `runScanner`. The wrapper
 * keeps any external callers that imported `runScannerUnit` working.
 */
export function runScannerUnit(ctx) {
  return runScanner({ ...ctx, scanner: "unit" });
}

/**
 * Integration-scanner entry point (TEMPER-02 Slice 02.2). Same
 * contract as `runScannerUnit` — just routes through the generic
 * runner with `scanner: "integration"`.
 */
export function runScannerIntegration(ctx) {
  return runScanner({ ...ctx, scanner: "integration" });
}

// ─── Top-level dispatcher ─────────────────────────────────────────────

// TEMPER-06 Slice 06.1 — Extract failures from a scanner result.
// Per-scanner normalizer: each scanner shape may encode failures
// differently. This function returns a uniform `{ evidence, severity }` array.
function _extractFromFailuresArray(scannerResult) {
  return scannerResult.failures.map((f) => ({
    evidence: f.evidence || f,
    severity: f.severity || (scannerResult.verdict === "error" ? "high" : "medium"),
  }));
}

function _extractFromRegressionsArray(scannerResult) {
  return scannerResult.regressions.map((r) => ({
    evidence: {
      testName: r.url || r.urlHash || r.name || `${scannerResult.scanner}-regression`,
      assertionMessage: r.explanation || r.verdict || "regression detected",
      visualDiffScore: r.diffScore || r.score || null,
      quorumVerdict: r.quorumVerdict || null,
    },
    severity: r.severity || "medium",
  }));
}

function _extractFromViolationsArray(scannerResult) {
  return scannerResult.violations.map((v) => ({
    evidence: {
      testName: v.path || v.endpoint || `${scannerResult.scanner}-violation`,
      assertionMessage: v.message || v.description || "contract violation",
      violation: true,
    },
    severity: v.severity || "medium",
  }));
}

function _extractGenericFailure(scannerResult) {
  if (scannerResult.fail <= 0 && scannerResult.verdict !== "fail" && scannerResult.verdict !== "error") return [];
  return [{
    evidence: {
      testName: `${scannerResult.scanner}-failure`,
      assertionMessage: scannerResult.error || scannerResult.reason || `${scannerResult.scanner} ${scannerResult.verdict}`,
      stackTrace: scannerResult.stderr || null,
    },
    severity: scannerResult.verdict === "error" ? "high" : "medium",
  }];
}

function extractFailures(scannerResult) {
  if (!scannerResult || scannerResult.skipped || scannerResult.verdict === "skipped" || scannerResult.verdict === "pass") return [];
  if (Array.isArray(scannerResult.failures)) return _extractFromFailuresArray(scannerResult);
  if (Array.isArray(scannerResult.regressions)) return _extractFromRegressionsArray(scannerResult);
  if (Array.isArray(scannerResult.violations)) return _extractFromViolationsArray(scannerResult);
  return _extractGenericFailure(scannerResult);
}

async function _runUnitScanner({ config, stack, adapter, sliceRef, projectDir, spawnFn, now, hub, corr }) {
  emit(hub, "tempering-run-scanner-started", { correlationId: corr, scanner: "unit", stack });
  const unitResult = await runScanner({
    scanner: "unit", config, stack, adapter, sliceRef,
    cwd: projectDir, spawn: spawnFn, now,
  });
  emit(hub, "tempering-run-scanner-completed", {
    correlationId: corr,
    scanner: "unit",
    stack,
    verdict: unitResult.verdict,
    pass: unitResult.pass,
    fail: unitResult.fail,
    skipped: unitResult.skipped,
    durationMs: unitResult.durationMs,
  });
  return unitResult;
}

async function _runIntegrationScanner({ unitResult, config, stack, adapter, sliceRef, projectDir, spawnFn, now, hub, corr }) {
  emit(hub, "tempering-run-scanner-started", { correlationId: corr, scanner: "integration", stack });
  let integrationResult;
  if (unitResult.verdict === "budget-exceeded") {
    integrationResult = {
      scanner: "integration",
      stack,
      sliceRef,
      startedAt: new Date(now()).toISOString(),
      completedAt: new Date(now()).toISOString(),
      skipped: true,
      reason: "prior-budget-exceeded",
      verdict: "skipped",
      durationMs: 0,
    };
  } else {
    integrationResult = await runScanner({
      scanner: "integration", config, stack, adapter, sliceRef,
      cwd: projectDir, spawn: spawnFn, now,
    });
  }
  emit(hub, "tempering-run-scanner-completed", {
    correlationId: corr,
    scanner: "integration",
    stack,
    verdict: integrationResult.verdict,
    pass: integrationResult.pass || 0,
    fail: integrationResult.fail || 0,
    skipped: integrationResult.skipped || 0,
    durationMs: integrationResult.durationMs || 0,
  });
  return integrationResult;
}

async function _runCrossStackScanners(opts) {
  const {
    unitResult, integrationResult,
    config, projectDir, runId, sliceRef, now, hub, corr, stack, env,
    importFn, uiImportFn, captureMemory, spawnWorker,
    uiScannerImpl, contractScannerImpl, visualDiffScannerImpl,
    flakinessScannerImpl, perfBudgetScannerImpl, loadStressScannerImpl,
    mutationScannerImpl, contentAuditScannerImpl,
  } = opts;

  const stepCommon = { sliceRef, now, hub, corr, stack };
  const importFnSafe = importFn || ((spec) => import(spec));
  const uiImportFnSafe = uiImportFn || ((spec) => import(spec));

  const uiResult = await _runCrossStackScannerStep({
    ...stepCommon,
    name: "ui-playwright",
    priorScanners: [unitResult, integrationResult],
    invokeInjected: _maybeInvoke(uiScannerImpl, { config, projectDir, runId, sliceRef, now, env, importFn: uiImportFn }),
    invokeDefault: async () => {
      const { runUiSweep } = await import("./scanners/ui-playwright.mjs");
      return runUiSweep({ config, projectDir, runId, sliceRef, now, env, importFn: uiImportFnSafe });
    },
  });

  const contractResult = await _runCrossStackScannerStep({
    ...stepCommon,
    name: "contract",
    priorScanners: [unitResult, integrationResult, uiResult],
    invokeInjected: _maybeInvoke(contractScannerImpl, { config, projectDir, runId, sliceRef, now, env, importFn }),
    invokeDefault: async () => {
      const { runContractScan } = await import("./scanners/contract.mjs");
      return runContractScan({ config, projectDir, runId, sliceRef, now, env, importFn: importFnSafe });
    },
  });

  const visualDiffEnabled = config.scanners?.["visual-diff"] !== false
    && config.visualAnalyzer?.enabled !== false;
  const visualDiffResult = await _runCrossStackScannerStep({
    ...stepCommon,
    name: "visual-diff",
    priorScanners: [unitResult, integrationResult, uiResult, contractResult],
    enabled: visualDiffEnabled,
    invokeInjected: _maybeInvoke(visualDiffScannerImpl, { config, projectDir, runId, sliceRef, now, env, hub, captureMemory, spawnWorker }),
    invokeDefault: async () => {
      const { runVisualDiffScan } = await import("./scanners/visual-diff.mjs");
      return runVisualDiffScan({ config, projectDir, runId, sliceRef, now, env, hub, captureMemory, spawnWorker });
    },
  });

  const flakinessResult = await _runCrossStackScannerStep({
    ...stepCommon,
    name: "flakiness",
    priorScanners: [unitResult, integrationResult, uiResult, contractResult, visualDiffResult],
    invokeInjected: _maybeInvoke(flakinessScannerImpl, { config, projectDir, runId, sliceRef, now, env, hub, captureMemory }),
    invokeDefault: async () => {
      const { runFlakinessScan } = await import("./scanners/flakiness.mjs");
      return runFlakinessScan({ config, projectDir, runId, sliceRef, now, env, hub, captureMemory });
    },
  });

  const perfBudgetResult = await _runCrossStackScannerStep({
    ...stepCommon,
    name: "performance-budget",
    priorScanners: [unitResult, integrationResult, uiResult, contractResult, visualDiffResult, flakinessResult],
    invokeInjected: _maybeInvoke(perfBudgetScannerImpl, { config, projectDir, runId, sliceRef, now, env, hub, captureMemory, importFn: importFnSafe }),
    invokeDefault: async () => {
      const { runPerformanceBudgetScan } = await import("./scanners/performance-budget.mjs");
      return runPerformanceBudgetScan({ config, projectDir, runId, sliceRef, now, env, hub, captureMemory, importFn: importFnSafe });
    },
  });

  const loadStressResult = await _runCrossStackScannerStep({
    ...stepCommon,
    name: "load-stress",
    priorScanners: [unitResult, integrationResult, uiResult, contractResult, visualDiffResult, flakinessResult, perfBudgetResult],
    invokeInjected: _maybeInvoke(loadStressScannerImpl, { config, projectDir, runId, sliceRef, now, env, hub, importFn: importFnSafe }),
    invokeDefault: async () => {
      const { runLoadStressScan } = await import("./scanners/load-stress.mjs");
      return runLoadStressScan({ config, projectDir, runId, sliceRef, now, env, hub, importFn: importFnSafe });
    },
  });

  const mutationResult = await _runCrossStackScannerStep({
    ...stepCommon,
    name: "mutation",
    priorScanners: [unitResult, integrationResult, uiResult, contractResult, visualDiffResult, flakinessResult, perfBudgetResult, loadStressResult],
    invokeInjected: _maybeInvoke(mutationScannerImpl, { config, projectDir, runId, sliceRef, now, env, hub, captureMemory }),
    invokeDefault: async () => {
      const { runMutationScan } = await import("./scanners/mutation.mjs");
      return runMutationScan({ config, projectDir, runId, sliceRef, now, env, hub, captureMemory });
    },
  });

  const contentAuditResult = await _runCrossStackScannerStep({
    ...stepCommon,
    name: "content-audit",
    priorScanners: [unitResult, integrationResult, uiResult, contractResult, visualDiffResult, flakinessResult, perfBudgetResult, loadStressResult, mutationResult],
    invokeInjected: _maybeInvoke(contentAuditScannerImpl, { config, projectDir, runId, sliceRef, now, env }),
    invokeDefault: async () => {
      const { runContentAudit } = await import("./scanners/content-audit.mjs");
      return runContentAudit({ config, projectDir, runId, sliceRef, now, env });
    },
  });

  return [uiResult, contractResult, visualDiffResult, flakinessResult, perfBudgetResult, loadStressResult, mutationResult, contentAuditResult];
}

function _maybeInvoke(impl, args) {
  if (!impl) return null;
  return () => impl(args);
}

async function _maybeRunObjectivePost(opts) {
  const { objective, objectiveBaseline, objectiveSpawn, spawnFn, projectDir } = opts;
  const enabled = objective && objective.command && typeof objective.command === "string" && objectiveBaseline !== null;
  if (!enabled) return { objectiveResult: null, failed: false };
  return _runObjectivePost({
    objective, baseline: objectiveBaseline, objectiveSpawn, spawnFn, projectDir,
  });
}

async function _maybeFetchChangedFiles({ config, lastGreenSha, projectDir, spawnFn }) {
  if (!(config.execution && config.execution.regressionFirst && lastGreenSha)) return [];
  return pickChangedFiles({ cwd: projectDir, lastGreenSha, gitSpawn: spawnFn });
}

// ─── Tempering run sub-helpers (Phase ESLINT-D1/D2 — extracted) ───────

function _crossStackSkippedResult(name, sliceRef, now, reason) {
  const ts = new Date(now()).toISOString();
  return {
    scanner: name,
    sliceRef,
    startedAt: ts,
    completedAt: ts,
    skipped: true,
    reason,
    verdict: "skipped",
    pass: 0,
    fail: 0,
    durationMs: 0,
  };
}

async function _runCrossStackScannerStep(opts) {
  const {
    name,
    sliceRef,
    now,
    hub,
    corr,
    stack,
    priorScanners,
    enabled = true,
    disabledReason = "scanner-disabled",
    invokeInjected = null,
    invokeDefault,
  } = opts;

  emit(hub, "tempering-run-scanner-started", { correlationId: corr, scanner: name, stack });

  let result;
  const priorBudgetExceeded = priorScanners.some((s) => s && s.verdict === "budget-exceeded");
  try {
    if (priorBudgetExceeded) {
      result = _crossStackSkippedResult(name, sliceRef, now, "prior-budget-exceeded");
    } else if (!enabled) {
      result = _crossStackSkippedResult(name, sliceRef, now, disabledReason);
    } else if (invokeInjected) {
      result = await invokeInjected();
    } else {
      result = await invokeDefault();
    }
  } catch (err) {
    result = _crossStackSkippedResult(name, sliceRef, now, `scanner-load-failed:${err.message || err}`);
  }

  emit(hub, "tempering-run-scanner-completed", {
    correlationId: corr,
    scanner: name,
    stack,
    verdict: result.verdict,
    pass: result.pass || 0,
    fail: result.fail || 0,
    skipped: result.skipped ? 1 : 0,
    durationMs: result.durationMs || 0,
  });

  return result;
}

async function _runObjectiveBaseline({ objective, objectiveSpawn, spawnFn, projectDir, corr }) {
  if (!objective || !objective.command || typeof objective.command !== "string") {
    return { ok: true, baseline: null };
  }
  const objSpawn = objectiveSpawn || spawnFn;
  const cmdParts = objective.command.trim().split(/\s+/);
  const baselineProc = await runSubprocess(cmdParts, {
    cwd: projectDir,
    budgetMs: 30000,
    spawn: objSpawn,
  });
  if (baselineProc.exitCode !== 0 || baselineProc.timedOut) {
    return {
      ok: false,
      response: {
        ok: false,
        error: "objective-baseline-failed",
        code: "objective-baseline-failed",
        correlationId: corr,
        objective: {
          accepted: false,
          blocked: true,
          reason: baselineProc.timedOut ? "objective-baseline-timed-out" : "objective-baseline-non-zero-exit",
        },
      },
    };
  }
  const baselineNum = parseFloat(baselineProc.stdout.trim());
  if (!isFinite(baselineNum)) {
    return {
      ok: false,
      response: {
        ok: false,
        error: "objective-baseline-non-numeric",
        code: "objective-baseline-non-numeric",
        correlationId: corr,
        objective: {
          accepted: false,
          blocked: true,
          reason: "objective-baseline-non-numeric",
        },
      },
    };
  }
  return { ok: true, baseline: baselineNum };
}

async function _runObjectivePost({ objective, baseline, objectiveSpawn, spawnFn, projectDir }) {
  const acceptIf = (objective.acceptIf === "less") ? "less" : "greater";
  const objSpawn = objectiveSpawn || spawnFn;
  const cmdParts = objective.command.trim().split(/\s+/);
  const postProc = await runSubprocess(cmdParts, {
    cwd: projectDir,
    budgetMs: 30000,
    spawn: objSpawn,
  });
  if (postProc.exitCode !== 0 || postProc.timedOut) {
    return {
      objectiveResult: {
        accepted: false,
        blocked: true,
        reason: postProc.timedOut ? "objective-post-timed-out" : "objective-post-non-zero-exit",
        acceptIf,
      },
      failed: true,
    };
  }
  const postNum = parseFloat(postProc.stdout.trim());
  if (!isFinite(postNum)) {
    return {
      objectiveResult: {
        accepted: false,
        blocked: true,
        reason: "objective-post-non-numeric",
        acceptIf,
      },
      failed: true,
    };
  }
  const accepted = acceptIf === "greater" ? postNum > baseline : postNum < baseline;
  return {
    objectiveResult: {
      accepted,
      blocked: !accepted,
      reason: accepted ? "objective-met" : "objective-not-met",
      acceptIf,
    },
    failed: !accepted,
  };
}

async function _registerScannerBugs(opts) {
  const {
    scanners, projectDir, corr, sliceRef, hub, captureMemory, config, callModel,
    classifyFn, registerBugFn,
  } = opts;
  const _classify = classifyFn || realClassify;
  const _registerBug = registerBugFn || realRegisterBug;
  const registeredBugs = [];
  const infraFixes = [];

  for (const scannerResult of scanners) {
    const failures = extractFailures(scannerResult);
    for (const failure of failures) {
      try {
        const classification = await _classify({
          scanner: scannerResult.scanner,
          evidence: failure.evidence,
          flakinessData: null,
          callModel,
          config,
        });
        const bugResult = await _registerBug({
          cwd: projectDir,
          scanner: scannerResult.scanner,
          severity: failure.severity,
          evidence: failure.evidence,
          correlationId: corr,
          sliceRef,
          classification: classification.classification,
          classifierMeta: classification,
          hub,
          captureMemory,
        });
        if (classification.classification === "infra") {
          infraFixes.push({
            scanner: scannerResult.scanner,
            testName: failure.evidence.testName,
            rule: classification.rule,
          });
        } else if (bugResult.ok) {
          registeredBugs.push(bugResult.bugId);
        }
      } catch { /* bug registration is best-effort */ }
    }
  }

  return { registeredBugs, infraFixes };
}

function _persistRunRecord(runRecord, temperingDir, outPath) {
  try {
    if (!existsSync(temperingDir)) mkdirSync(temperingDir, { recursive: true });
    writeFileSync(outPath, JSON.stringify(runRecord, null, 2) + "\n", "utf-8");
  } catch { /* best-effort */ }
}

/**
 * forge_tempering_run — execute enabled scanners, write a run record,
 * emit hub events per scanner. Slice 02.1 runs the **unit** scanner
 * only; Slice 02.2 adds integration; later phases add UI/visual/load.
 *
 * Writes `.forge/tempering/run-<ts>.json`. Never throws.
 *
 * @param {object} opts
 * @param {string} opts.projectDir
 * @param {object} [opts.hub]
 * @param {string} [opts.correlationId]
 * @param {{plan:string, slice:string}} [opts.sliceRef]
 * @param {string|null} [opts.lastGreenSha]   - for regression-first ordering
 * @param {Function} [opts.spawn]
 * @param {Function} [opts.importFn]          - for loadAdapter injection
 * @param {object}   [opts.adapter]           - direct override (tests)
 * @param {Function} [opts.now]
 * @returns {Promise<object>}
 */
const _RUN_OPTS_DEFAULTS = Object.freeze({
  projectDir: undefined,
  hub: null,
  correlationId: null,
  sliceRef: null,
  lastGreenSha: null,
  importFn: undefined,
  now: undefined,
  uiImportFn: null,
  uiScannerImpl: null,
  contractScannerImpl: null,
  visualDiffScannerImpl: null,
  captureMemory: null,
  flakinessScannerImpl: null,
  perfBudgetScannerImpl: null,
  loadStressScannerImpl: null,
  mutationScannerImpl: null,
  contentAuditScannerImpl: null,
  classifyFn: null,
  registerBugFn: null,
  callModel: null,
  spawnWorker: null,
  objective: null,
  objectiveSpawn: null,
});

function _normalizeRunOpts(opts) {
  const merged = { ..._RUN_OPTS_DEFAULTS, ...opts };
  merged.spawnFn = opts.spawn || realSpawn;
  merged.adapterOverride = opts.adapter || null;
  merged.now = opts.now || (() => Date.now());
  merged.env = opts.env || process.env;
  return merged;
}

function _sumScannerTotals(scanners) {
  return scanners.reduce((acc, s) => ({
    pass: acc.pass + (s.pass || 0),
    fail: acc.fail + (s.fail || 0),
    skipped: acc.skipped + (s.skipped || 0),
    durationMs: acc.durationMs + (s.durationMs || 0),
  }), { pass: 0, fail: 0, skipped: 0, durationMs: 0 });
}

export async function runTemperingRun(opts = {}) {
  const o = _normalizeRunOpts(opts);
  const {
    projectDir, hub, sliceRef, lastGreenSha, spawnFn, importFn, now,
    uiImportFn, captureMemory, env, spawnWorker, objective, objectiveSpawn,
  } = o;

  const corr = o.correlationId || `temper-run-${randomUUID()}`;
  const startedAt = new Date(now()).toISOString();
  const runId = `run-${startedAt.replace(/[:.]/g, "-")}`;

  if (!projectDir || typeof projectDir !== "string") {
    return { ok: false, error: "projectDir required", code: "missing-projectDir", correlationId: corr };
  }

  const { dir: temperingDir, configWritten } = ensureTemperingDirs(projectDir);
  const config = readTemperingConfig(projectDir);

  if (config.enabled === false) {
    emit(hub, "tempering-run-skipped", { correlationId: corr, reason: "disabled" });
    return { ok: true, skipped: true, reason: "tempering-disabled", correlationId: corr, configWritten };
  }

  const stack = detectStack(projectDir);
  emit(hub, "tempering-run-started", { correlationId: corr, projectDir, stack, sliceRef, configWritten });

  const adapter = o.adapterOverride || await loadAdapter(stack, { importFn });
  const changedFiles = await _maybeFetchChangedFiles({ config, lastGreenSha, projectDir, spawnFn });

  const baselineGate = await _runObjectiveBaseline({ objective, objectiveSpawn, spawnFn, projectDir, corr });
  if (!baselineGate.ok) return baselineGate.response;
  const objectiveBaseline = baselineGate.baseline;

  const unitResult = await _runUnitScanner({
    config, stack, adapter, sliceRef, projectDir, spawnFn, now, hub, corr,
  });
  const integrationResult = await _runIntegrationScanner({
    unitResult, config, stack, adapter, sliceRef, projectDir, spawnFn, now, hub, corr,
  });

  const crossStack = await _runCrossStackScanners({
    unitResult, integrationResult,
    config, projectDir, runId, sliceRef, now, hub, corr, stack, env,
    importFn, uiImportFn, captureMemory, spawnWorker,
    uiScannerImpl: o.uiScannerImpl,
    contractScannerImpl: o.contractScannerImpl,
    visualDiffScannerImpl: o.visualDiffScannerImpl,
    flakinessScannerImpl: o.flakinessScannerImpl,
    perfBudgetScannerImpl: o.perfBudgetScannerImpl,
    loadStressScannerImpl: o.loadStressScannerImpl,
    mutationScannerImpl: o.mutationScannerImpl,
    contentAuditScannerImpl: o.contentAuditScannerImpl,
  });

  const scanners = [unitResult, integrationResult, ...crossStack];
  let overallVerdict = deriveOverallVerdict(scanners);

  const postOut = await _maybeRunObjectivePost({
    objective, objectiveBaseline, objectiveSpawn, spawnFn, projectDir,
  });
  const objectiveResult = postOut.objectiveResult;
  if (postOut.failed) overallVerdict = "fail";

  const { registeredBugs, infraFixes } = await _registerScannerBugs({
    scanners, projectDir, corr, sliceRef, hub, captureMemory, config, callModel: o.callModel,
    classifyFn: o.classifyFn, registerBugFn: o.registerBugFn,
  });

  const completedAt = new Date(now()).toISOString();
  const objectiveFields = objectiveResult !== null ? { objective: objectiveResult } : {};
  const runRecord = {
    runId, correlationId: corr, startedAt, completedAt, stack, sliceRef,
    changedFilesCount: changedFiles.length, lastGreenSha,
    scanners, verdict: overallVerdict, infraFixes, registeredBugs,
    ...objectiveFields,
    phase: "TEMPER-06", slice: "06.1",
  };

  const outPath = resolve(temperingDir, `${runId}.json`);
  _persistRunRecord(runRecord, temperingDir, outPath);

  const totals = _sumScannerTotals(scanners);

  emit(hub, "tempering-run-completed", {
    correlationId: corr, runId, stack, verdict: overallVerdict,
    scannerCount: scanners.length,
    pass: totals.pass, fail: totals.fail, skipped: totals.skipped, durationMs: totals.durationMs,
    sliceRef,
  });

  return {
    ok: true, runId, correlationId: corr, stack, verdict: overallVerdict,
    scanners, runRecordPath: outPath, configWritten,
    changedFilesCount: changedFiles.length,
    ...objectiveFields,
  };
}

// ─── Scanner name → dynamic import map ────────────────────────────────

const SCANNER_IMPORT_MAP = {
  "unit":               null,  // handled inline by runTemperingRun (spawn-based)
  "integration":        null,  // handled inline by runTemperingRun (spawn-based)
  "ui-playwright":      "./scanners/ui-playwright.mjs",
  "contract":           "./scanners/contract.mjs",
  "visual-diff":        "./scanners/visual-diff.mjs",
  "flakiness":          "./scanners/flakiness.mjs",
  "performance-budget": "./scanners/performance-budget.mjs",
  "load-stress":        "./scanners/load-stress.mjs",
  "mutation":           "./scanners/mutation.mjs",
  "content-audit":      "./scanners/content-audit.mjs",
};

const SCANNER_ENTRY_POINTS = {
  "ui-playwright":      "runUiSweep",
  "contract":           "runContractScan",
  "visual-diff":        "runVisualDiffScan",
  "flakiness":          "runFlakinessScan",
  "performance-budget": "runPerformanceBudgetScan",
  "load-stress":        "runLoadStressScan",
  "mutation":           "runMutationScan",
  "content-audit":      "runContentAudit",
};

/**
 * Run a single scanner by name — narrow export for closed-loop validation
 * (forge_bug_validate_fix). Does NOT register bugs or persist run records;
 * that's the caller's responsibility.
 *
 * @param {string} name - Scanner name (one of the 9 registered scanners)
 * @param {object} [opts]
 * @param {string} [opts.cwd] - Project directory
 * @param {string|null} [opts.testNameFilter] - Restrict to a single test name
 * @param {number} [opts.timeoutMs=120000] - Per-scanner budget
 * @param {Function} [opts.now] - Injectable clock
 * @param {Function} [opts.scannerImpl] - DI override for tests
 * @returns {Promise<{ scanner: string, startedAt: string, completedAt: string, failures: number, findings: Array, raw: object }>}
 */
async function _runSpawnBasedScanner({ name, cwd, timeoutMs, started, now }) {
  const config = await readTemperingConfig(cwd);
  const stack = detectStack(cwd);
  const adapter = loadAdapter(stack);
  if (!adapter) {
    const err = new Error(`No adapter for stack "${stack}" — scanner "${name}" unavailable`);
    err.code = ERROR_CODES.SCANNER_UNAVAILABLE.code;
    throw err;
  }
  const cmd = name === "unit"
    ? adapter.unitTestCommand(config, cwd)
    : adapter.integrationTestCommand?.(config, cwd) ?? adapter.unitTestCommand(config, cwd);
  if (!cmd) {
    const err = new Error(`Adapter does not provide a ${name} command for stack "${stack}"`);
    err.code = ERROR_CODES.SCANNER_UNAVAILABLE.code;
    throw err;
  }

  const result = await new Promise((resolve, reject) => {
    const timer = setTimeout(() => {
      try { child.kill("SIGTERM"); } catch { /* ignore */ }
      setTimeout(() => { try { child.kill("SIGKILL"); } catch { /* ignore */ } }, KILL_GRACE_MS);
      reject(Object.assign(new Error(`Scanner "${name}" timed out after ${timeoutMs}ms`), { code: "SCANNER_TIMEOUT" }));
    }, timeoutMs);

    let stdout = "", stderr = "";
    const child = realSpawn(cmd.bin, cmd.args || [], { cwd, shell: true, env: { ...process.env, CI: "1" } });
    child.stdout?.on("data", (d) => { stdout += d; });
    child.stderr?.on("data", (d) => { stderr += d; });
    child.on("close", (code) => { clearTimeout(timer); resolve({ code, stdout, stderr }); });
    child.on("error", (err) => { clearTimeout(timer); reject(err); });
  });

  const completed = now();
  return {
    scanner: name,
    startedAt: started.toISOString(),
    completedAt: completed.toISOString(),
    failures: result.code !== 0 ? 1 : 0,
    findings: [],
    raw: { exitCode: result.code, stdout: result.stdout.slice(0, 2000), stderr: result.stderr.slice(0, 2000) },
  };
}

async function _runImportBasedScanner(name, opts) {
  const { modulePath, entryPoint, cwd, timeoutMs, started, now } = opts;
  const mod = await import(modulePath);
  const runFn = mod[entryPoint];
  if (typeof runFn !== "function") {
    const err = new Error(`Scanner "${name}" module missing entry point "${entryPoint}"`);
    err.code = ERROR_CODES.SCANNER_UNAVAILABLE.code;
    throw err;
  }

  const config = await readTemperingConfig(cwd);
  const runId = `validate-${started.toISOString().replace(/[:.]/g, "-")}`;
  const result = await Promise.race([
    runFn({ config, projectDir: cwd, runId, sliceRef: null, now: () => now().getTime(), env: process.env }),
    new Promise((_, reject) =>
      setTimeout(() => reject(Object.assign(new Error(`Scanner "${name}" timed out after ${timeoutMs}ms`), { code: "SCANNER_TIMEOUT" })), timeoutMs)
    ),
  ]);

  const completed = now();
  return {
    scanner: name,
    startedAt: started.toISOString(),
    completedAt: completed.toISOString(),
    failures: result.fail ?? result.failures?.length ?? 0,
    findings: result.findings ?? [],
    raw: result,
  };
}

export async function runSingleScanner(name, opts = {}) {
  const {
    cwd = process.cwd(),
    testNameFilter = null,
    timeoutMs = 120_000,
    now = () => new Date(),
    scannerImpl = null,
  } = opts;

  if (!name || !(name in SCANNER_IMPORT_MAP)) {
    const err = new Error(`Scanner "${name}" is not registered`);
    err.code = ERROR_CODES.SCANNER_UNAVAILABLE.code;
    throw err;
  }

  const started = now();

  if (scannerImpl) {
    const result = await scannerImpl({ cwd, filter: { testName: testNameFilter } });
    const completed = now();
    return {
      scanner: name,
      startedAt: started.toISOString(),
      completedAt: completed.toISOString(),
      failures: result.failures?.length ?? (result.fail ?? 0),
      findings: result.findings ?? [],
      raw: result,
    };
  }

  if (name === "unit" || name === "integration") {
    return _runSpawnBasedScanner({ name: name, cwd: cwd, timeoutMs: timeoutMs, started: started, now: now });
  }

  const modulePath = SCANNER_IMPORT_MAP[name];
  const entryPoint = SCANNER_ENTRY_POINTS[name];
  return _runImportBasedScanner(name, { modulePath, entryPoint, cwd, timeoutMs, started, now });
}

/**
 * Derive a single run-level verdict from scanner verdicts.
 * Priority: error > budget-exceeded > fail > pass > skipped.
 */
export function deriveOverallVerdict(scanners) {
  if (!Array.isArray(scanners) || scanners.length === 0) return "skipped";
  const order = ["error", "budget-exceeded", "fail", "pass", "skipped"];
  let worst = "skipped";
  for (const s of scanners) {
    const v = s && s.verdict ? s.verdict : "skipped";
    if (order.indexOf(v) < order.indexOf(worst)) worst = v;
  }
  return worst;
}

/**
 * Content-audit scanner — HTTP-probe + HTML-inspection reference impl
 * (Phase-39 Slice 1).
 *
 * Ported from Rummag's `scripts/audit/audit-content.mjs`. Probes a set
 * of routes against a live base URL and emits structured findings per
 * route: HTTP status, title, h1, word count, placeholder markers, and
 * client-shell detection for hydrated SPAs.
 *
 * Does NOT execute JS — this is a static-content/SSR audit. SPA support
 * (Playwright) is out of scope for v2.80.
 *
 * Follows the cross-stack scanner result contract:
 *   { scanner, startedAt, completedAt, verdict, pass, fail, skipped,
 *     durationMs, findings, ... }
 *
 * Design constraints:
 *   - Never throws — always returns a result frame
 *   - Fetcher injectable for testing (no real HTTP in tests)
 *   - Production guard via looksLikeProduction() from ui-playwright
 *   - Uses redirect: "manual" so 3xx responses are visible
 *   - Only non-ok findings are emitted into findings[] (ok routes
 *     count toward pass but don't inflate the findings array)
 *
 * @module tempering/scanners/content-audit
 */
import { existsSync, readFileSync, mkdirSync, writeFileSync } from "node:fs";
import { resolve as pathResolve } from "node:path";
import { looksLikeProduction, resolveAppUrl } from "./ui-playwright.mjs";
import { ensureScannerArtifactDir, seedArtifactsGitignore } from "../artifacts.mjs";

// ─── Placeholder patterns (visible text only) ────────────────────────

const PLACEHOLDER_PATTERNS = [
  /\bTODO\b/,
  /\bFIXME\b/,
  /coming soon/i,
  /under construction/i,
  /\blorem ipsum\b/i,
  /\bmock data\b/i,
  /\bsample data\b/i,
  /lipsum/i,
  /\bnot yet implemented\b/i,
  /\bwork in progress\b/i,
];

const MIN_WORD_COUNT = 30;

// Next.js / React hydration markers — pages with these present render
// content client-side so low SSR word count is expected. Classified as
// info/client-shell rather than medium/empty-shell.
const HYDRATION_MARKERS = [
  /\/_next\//,
  /__NEXT_DATA__/,
  /self\.__next_f\.push/,
  /<next-route-announcer/,
];

// ─── Scanner config defaults ─────────────────────────────────────────

export const CONTENT_AUDIT_DEFAULTS = Object.freeze({
  baseUrl: null,
  routesPath: null,
  allowProduction: false,
  userAgent: "PlanForgeContentAudit/1.0",
  timeoutMs: 10000,
  maxRoutes: 500,
});

// ─── HTML helpers ────────────────────────────────────────────────────

export function extractTag(html, tag) {
  const re = new RegExp(`<${tag}\\b[^>]*>([\\s\\S]*?)</${tag}>`, "i");
  const m = html.match(re);
  if (!m) return null;
  return m[1].replace(/<[^>]+>/g, "").replace(/\s+/g, " ").trim();
}

export function wordCount(text) {
  return text ? text.split(/\s+/).filter(Boolean).length : 0;
}

export function cleanBodyText(html) {
  return extractTag(html, "main") ?? extractTag(html, "body") ?? "";
}

export function findPlaceholders(html) {
  const text = html
    .replace(/<script[\s\S]*?<\/script>/gi, "")
    .replace(/<style[\s\S]*?<\/style>/gi, "")
    .replace(/<[^>]+>/g, " ");
  const hits = [];
  for (const pattern of PLACEHOLDER_PATTERNS) {
    const m = text.match(pattern);
    if (m) hits.push(m[0]);
  }
  return [...new Set(hits)];
}

export function looksLikeClientShell(body) {
  if (!body) return false;
  return HYDRATION_MARKERS.some((re) => re.test(body));
}

// ─── Classifier ──────────────────────────────────────────────────────

/**
 * Priority-ordered classifier. Returns `{ severity, class, evidence }`.
 * Order matters: client-shell MUST fire before missing-h1/empty-shell
 * to avoid false positives on hydrated SPAs.
 */
export function classifyRoute({ status, location, body, title, h1, words, placeholders }) {
  if (status === 0) return { severity: "blocker", class: "network-error", evidence: {} };
  if (status >= 500) return { severity: "blocker", class: `http-${status}`, evidence: { status } };
  if (status === 404) return { severity: "high", class: "hard-404", evidence: { status } };
  if (status >= 300 && status < 400) {
    if (location && /\/signin/i.test(location)) {
      return { severity: "info", class: "auth-gated-redirect", evidence: { status, location } };
    }
    return { severity: "info", class: `redirect-${status}`, evidence: { status, location } };
  }
  if (status !== 200) return { severity: "medium", class: `http-${status}`, evidence: { status } };
  if (placeholders.length > 0) {
    return { severity: "high", class: "placeholder-content", evidence: { placeholders } };
  }
  // Client-shell: runs BEFORE missing-h1 and empty-shell checks.
  if (words < MIN_WORD_COUNT && looksLikeClientShell(body)) {
    return { severity: "info", class: "client-shell", evidence: { words } };
  }
  if (!h1) return { severity: "medium", class: "missing-h1", evidence: { title } };
  if (!title) return { severity: "medium", class: "missing-title", evidence: { h1 } };
  if (words < MIN_WORD_COUNT) {
    return { severity: "medium", class: "empty-shell", evidence: { words } };
  }
  return { severity: "ok", class: "ok", evidence: {} };
}

// ─── Route loading ───────────────────────────────────────────────────

/**
 * Load routes from explicit input, or fall back to
 * `.forge/audits/routes.json`. Returns `string[]` of path segments
 * (e.g., `["/", "/about", "/campaigns/:id"]`).
 */
export function loadRoutes({ routes, projectDir, settings }) {
  // Explicit routes take priority
  if (Array.isArray(routes) && routes.length > 0) return routes;

  // Fallback: .forge/audits/routes.json
  const routesFile = settings.routesPath
    ? pathResolve(projectDir, settings.routesPath)
    : pathResolve(projectDir, ".forge", "audits", "routes.json");

  if (existsSync(routesFile)) {
    try {
      const data = JSON.parse(readFileSync(routesFile, "utf-8"));
      if (Array.isArray(data.routes)) return data.routes;
      if (Array.isArray(data)) return data;
    } catch { /* malformed file — fall through */ }
  }

  return [];
}

// ─── Default fetcher ─────────────────────────────────────────────────

async function defaultFetcher(url, { userAgent, timeoutMs }) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const res = await fetch(url, {
      redirect: "manual",
      signal: controller.signal,
      headers: { "User-Agent": userAgent },
    });
    const body = res.status >= 200 && res.status < 400 ? await res.text() : "";
    const location = res.headers.get("location");
    return { ok: true, status: res.status, location, body };
  } catch (e) {
    return { ok: false, status: 0, location: null, body: "", error: e.message };
  } finally {
    clearTimeout(timer);
  }
}

// ─── Seed substitution ──────────────────────────────────────────────

/**
 * Expand parameterized routes using seed values.
 * E.g., route `/campaigns/:id` with seeds `{ id: "abc123" }`
 * → `/campaigns/abc123`.
 */
export function expandRoute(route, seeds) {
  if (!seeds || typeof seeds !== "object") return { expanded: route, seed: null };
  let expanded = route;
  let usedSeed = null;
  for (const [key, value] of Object.entries(seeds)) {
    const pattern = `:${key}`;
    if (expanded.includes(pattern)) {
      expanded = expanded.replace(pattern, String(value));
      usedSeed = usedSeed || {};
      usedSeed[key] = value;
    }
  }
  return { expanded, seed: usedSeed };
}

// ─── Main entry point ────────────────────────────────────────────────

/**
 * Run the content-audit scanner. Probes each route via HTTP and
 * classifies the response. Non-ok findings are emitted into the
 * `findings[]` array with the shared contract fields.
 *
 * @param {object} ctx
 * @param {object} [ctx.config]     — loaded tempering config
 * @param {string} ctx.projectDir   — project root
 * @param {string} ctx.runId        — current run ID
 * @param {{plan:string,slice:string}|null} [ctx.sliceRef]
 * @param {Function} [ctx.now]      — injectable clock
 * @param {object}   [ctx.env]      — process.env-shaped map
 * @param {Function} [ctx.fetcher]  — injectable HTTP fetcher for tests
 * @param {string[]} [ctx.routes]   — explicit route list (overrides file)
 * @param {object}   [ctx.seeds]    — seed values for parameterized routes
 * @returns {Promise<object>} scanner result record
 */
function createContentAuditSkippedFrame(base, now, reason) {
  return {
    ...base,
    skipped: true,
    reason,
    verdict: "skipped",
    pass: 0,
    fail: 0,
    durationMs: 0,
    findings: [],
    completedAt: new Date(now()).toISOString(),
  };
}

function resolveContentAuditSettings(scannerConfig) {
  return {
    ...CONTENT_AUDIT_DEFAULTS,
    ...(typeof scannerConfig === "object" ? scannerConfig : {}),
  };
}

function resolveContentAuditBaseUrl(settings, config, env) {
  return settings.baseUrl || (env && env.PFORGE_TEMPERING_URL) || resolveAppUrl(config, env);
}

function buildAuditUrl(baseUrl, expandedRoute) {
  return baseUrl.replace(/\/+$/, "") + (expandedRoute.startsWith("/") ? expandedRoute : `/${expandedRoute}`);
}

async function auditRoute({ route, seeds, baseUrl, fetcher, settings }) {
  const { expanded, seed } = expandRoute(route, seeds);
  const url = buildAuditUrl(baseUrl, expanded);
  const response = await fetcher(url, {
    userAgent: settings.userAgent,
    timeoutMs: settings.timeoutMs,
  });
  const body = response.body ?? "";
  const title = extractTag(body, "title");
  const h1 = extractTag(body, "h1");
  const words = wordCount(cleanBodyText(body));
  const placeholders = findPlaceholders(body);
  const verdict = classifyRoute({
    status: response.status,
    location: response.location,
    body,
    title,
    h1,
    words,
    placeholders,
  });
  return {
    verdict,
    finding: verdict.severity === "ok"
      ? null
      : {
          class: verdict.class,
          route,
          severity: verdict.severity,
          evidence: { ...verdict.evidence, url, status: response.status, title, h1, words },
          ...(seed ? { seed } : {}),
        },
  };
}

function resolveContentAuditVerdict(findings, budgetTripped) {
  if (budgetTripped) return "budget-exceeded";
  if (findings.some((finding) => finding.severity === "blocker" || finding.severity === "high")) return "fail";
  if (findings.length > 0) return "warn";
  return "pass";
}

function writeContentAuditArtifact(projectDir, runId, report) {
  const artifactDir = ensureScannerArtifactDir(projectDir, runId, "content-audit");
  if (!artifactDir) return artifactDir;
  seedArtifactsGitignore(projectDir);
  try {
    writeFileSync(
      pathResolve(artifactDir, "report.json"),
      JSON.stringify(report, null, 2) + "\n",
      "utf-8",
    );
  } catch { /* best-effort */ }
  return artifactDir;
}

function resolveContentAuditContext(ctx) {
  const {
    config = {},
    projectDir,
    runId,
    sliceRef = null,
    now = () => Date.now(),
    env = process.env,
    fetcher = defaultFetcher,
    routes: explicitRoutes = null,
    seeds = null,
  } = ctx || {};
  return {
    config,
    projectDir,
    runId,
    sliceRef,
    now,
    env,
    fetcher,
    explicitRoutes,
    seeds,
  };
}

function isContentAuditDisabled(scannerConfig) {
  return scannerConfig === false || (scannerConfig && scannerConfig.enabled === false);
}

function resolveContentAuditRouteList(projectDir, explicitRoutes, settings) {
  return loadRoutes({
    routes: explicitRoutes,
    projectDir: projectDir || ".",
    settings,
  }).slice(0, settings.maxRoutes);
}

async function processContentAuditRoutes({ routes, now, hardDeadline, seeds, baseUrl, fetcher, settings }) {
  const findings = [];
  let passCount = 0;
  let failCount = 0;
  let budgetTripped = false;

  for (const route of routes) {
    if (now() >= hardDeadline) {
      budgetTripped = true;
      break;
    }
    const result = await auditRoute({ route, seeds, baseUrl, fetcher, settings });
    if (!result.finding) {
      passCount++;
      continue;
    }
    failCount++;
    findings.push(result.finding);
  }

  return { findings, passCount, failCount, budgetTripped };
}

function buildContentAuditResult({
  base,
  now,
  t0,
  projectDir,
  runId,
  baseUrl,
  routes,
  findings,
  passCount,
  failCount,
  budgetTripped,
}) {
  const overallVerdict = resolveContentAuditVerdict(findings, budgetTripped);
  const artifactDir = writeContentAuditArtifact(projectDir, runId, {
    scanner: "content-audit",
    startedAt: base.startedAt,
    baseUrl,
    routeCount: routes.length,
    verdict: overallVerdict,
    findings,
    summary: { pass: passCount, fail: failCount },
  });

  return {
    ...base,
    verdict: overallVerdict,
    pass: passCount,
    fail: failCount,
    skipped: 0,
    findings,
    findingCount: findings.length,
    routesProbed: Math.min(routes.length, passCount + failCount),
    budgetTripped,
    durationMs: now() - t0,
    artifactDir,
    completedAt: new Date(now()).toISOString(),
  };
}

export async function runContentAudit(ctx) {
  const auditCtx = resolveContentAuditContext(ctx);
  const t0 = auditCtx.now();
  const base = {
    scanner: "content-audit",
    sliceRef: auditCtx.sliceRef,
    startedAt: new Date(t0).toISOString(),
  };
  const scannerConfig = auditCtx.config.scanners?.["content-audit"];
  if (isContentAuditDisabled(scannerConfig)) {
    return createContentAuditSkippedFrame(base, auditCtx.now, "scanner-disabled");
  }

  const settings = resolveContentAuditSettings(scannerConfig);
  const baseUrl = resolveContentAuditBaseUrl(settings, auditCtx.config, auditCtx.env);
  if (!baseUrl) return createContentAuditSkippedFrame(base, auditCtx.now, "url-not-configured");
  if (looksLikeProduction(baseUrl) && !settings.allowProduction) {
    return createContentAuditSkippedFrame(base, auditCtx.now, "production-url-without-opt-in");
  }

  const routes = resolveContentAuditRouteList(auditCtx.projectDir, auditCtx.explicitRoutes, settings);
  if (routes.length === 0) return createContentAuditSkippedFrame(base, auditCtx.now, "no-routes");

  const hardDeadline = t0 + ((auditCtx.config.runtimeBudgets && auditCtx.config.runtimeBudgets.contentAuditMaxMs) || 300000);
  const scanResult = await processContentAuditRoutes({
    routes,
    now: auditCtx.now,
    hardDeadline,
    seeds: auditCtx.seeds,
    baseUrl,
    fetcher: auditCtx.fetcher,
    settings,
  });

  return buildContentAuditResult({
    base,
    now: auditCtx.now,
    t0,
    projectDir: auditCtx.projectDir,
    runId: auditCtx.runId,
    baseUrl,
    routes,
    findings: scanResult.findings,
    passCount: scanResult.passCount,
    failCount: scanResult.failCount,
    budgetTripped: scanResult.budgetTripped,
  });
}

// ─── Default export (scanner module interface) ───────────────────────

export default {
  name: "content-audit",
  run: runContentAudit,
};

/**
 * GraphQL schema contract validator (TEMPER-03 Slice 03.2).
 *
 * Validates a live GraphQL API against a local `schema.graphql` by:
 *   1. Regex-parsing root Query/Mutation field names from the file
 *   2. Fetching the introspection query from the endpoint
 *   3. Diffing local fields vs introspected fields
 *   4. Firing sample `{ <field> { __typename } }` queries
 *
 * No `graphql-js` dependency — uses simple regex extraction.
 * Introspection disabled → graceful skip (not a failure).
 *
 * @module tempering/scanners/contract-graphql
 */
import { readFileSync } from "node:fs";

const INTROSPECTION_QUERY = '{ __schema { queryType { name } mutationType { name } types { name kind fields { name } } } }';

/**
 * Validate a live GraphQL API against a local schema file.
 *
 * @param {string} schemaPath   — absolute path to schema.graphql
 * @param {string} baseUrl      — base URL of the API server
 * @param {object} opts
 * @param {string} [opts.graphqlEndpoint] — path override (default: /graphql)
 * @param {number} [opts.timeoutMs=5000]
 * @param {number} [opts.maxQueries=50]
 * @param {Function} [opts.now]
 * @param {number} [opts.hardDeadline]
 * @returns {Promise<{ queries: number, passed: number, failed: number, violations: Array }>}
 */
function graphqlResult(reason, extra = {}) {
  return { queries: 0, passed: 0, failed: 0, violations: [], ...extra, reason };
}

function readSchemaText(schemaPath) {
  try {
    return { ok: true, schemaText: readFileSync(schemaPath, "utf-8") };
  } catch (err) {
    return { ok: false, result: graphqlResult(`schema-read-error: ${err.message}`, { error: true }) };
  }
}

async function fetchIntrospectionData(endpoint, timeoutMs) {
  try {
    const resp = await fetch(endpoint, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Tempering-Scan": "true",
      },
      body: JSON.stringify({ query: INTROSPECTION_QUERY }),
      signal: AbortSignal.timeout(timeoutMs),
    });
    if (resp.status >= 400) {
      return { ok: false, result: graphqlResult("introspection-disabled", { skipped: true }) };
    }
    const json = await resp.json();
    if (json.errors && json.errors.length > 0 && !json.data) {
      return { ok: false, result: graphqlResult("introspection-disabled", { skipped: true }) };
    }
    return { ok: true, data: json.data };
  } catch (err) {
    const reason = /ECONNREFUSED/.test(err.message) ? "connection-refused" : `introspection-error: ${err.message}`;
    return { ok: false, result: graphqlResult(reason, { error: true }) };
  }
}

function pushMissingRootFieldViolations(violations, fields, rootType, introspected) {
  for (const field of fields) {
    if (introspected.has(field)) continue;
    violations.push({
      field,
      rootType,
      reason: "missing-from-introspection",
      expected: `${rootType}.${field} in introspection`,
      actual: "not found",
    });
  }
}

async function runGraphqlQueryProbe(endpoint, field, timeoutMs) {
  try {
    const resp = await fetch(endpoint, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Tempering-Scan": "true",
      },
      body: JSON.stringify({ query: `{ ${field} { __typename } }` }),
      signal: AbortSignal.timeout(timeoutMs),
    });
    const json = await resp.json();
    if (json.errors && json.errors.length > 0) {
      return {
        ok: false,
        violation: {
          field,
          rootType: "Query",
          reason: "query-error",
          expected: `data.${field} without errors`,
          actual: json.errors[0].message || "GraphQL error",
        },
      };
    }
    if (json.data && field in json.data) return { ok: true };
    return {
      ok: false,
      violation: {
        field,
        rootType: "Query",
        reason: "missing-data-field",
        expected: `data.${field}`,
        actual: "field missing from response",
      },
    };
  } catch (err) {
    return {
      ok: false,
      violation: {
        field,
        rootType: "Query",
        reason: /ECONNREFUSED/.test(err.message) ? "connection-refused" : "fetch-error",
        expected: null,
        actual: err.message,
      },
    };
  }
}

export async function validateGraphqlSchema(schemaPath, baseUrl, opts = {}) {
  const {
    graphqlEndpoint = "/graphql",
    timeoutMs = 5000,
    maxQueries = 50,
    now = () => Date.now(),
    hardDeadline = Infinity,
  } = opts;

  const schemaRead = readSchemaText(schemaPath);
  if (!schemaRead.ok) return schemaRead.result;

  const localQueryFields = extractRootFields(schemaRead.schemaText, "Query");
  const localMutationFields = extractRootFields(schemaRead.schemaText, "Mutation");
  if (localQueryFields.length + localMutationFields.length === 0) {
    return graphqlResult("no-root-fields-found", { skipped: true });
  }

  const endpoint = resolveEndpoint(baseUrl, graphqlEndpoint);
  const introspection = await fetchIntrospectionData(endpoint, timeoutMs);
  if (!introspection.ok) return introspection.result;

  const violations = [];
  const introspectedFields = extractIntrospectedRootFields(introspection.data);
  pushMissingRootFieldViolations(violations, localQueryFields, "Query", introspectedFields.query);
  pushMissingRootFieldViolations(violations, localMutationFields, "Mutation", introspectedFields.mutation);

  const queryFields = localQueryFields.slice(0, maxQueries);
  let passed = 0;
  let failed = 0;

  for (const field of queryFields) {
    if (now() >= hardDeadline) {
      return { queries: queryFields.length, passed, failed, violations, budgetExceeded: true };
    }
    const probe = await runGraphqlQueryProbe(endpoint, field, timeoutMs);
    if (probe.ok) {
      passed++;
      continue;
    }
    failed++;
    violations.push(probe.violation);
  }

  return { queries: queryFields.length, passed, failed, violations };
}

/**
 * Extract root field names from a schema.graphql type block using regex.
 * Handles `type Query { ... }` and `extend type Query { ... }`.
 */
export function extractRootFields(schemaText, typeName) {
  const fields = new Set();
  // Match `type <typeName> {` or `extend type <typeName> {` blocks
  const blockRegex = new RegExp(
    `(?:extend\\s+)?type\\s+${typeName}\\s*\\{([^}]*)\\}`,
    "gs",
  );
  let match;
  while ((match = blockRegex.exec(schemaText)) !== null) {
    const body = match[1];
    // Each field line: `fieldName(args): Type`
    const fieldRegex = /^\s*(\w+)\s*[\(:{]/gm;
    let fm;
    while ((fm = fieldRegex.exec(body)) !== null) {
      fields.add(fm[1]);
    }
  }
  return [...fields];
}

/**
 * Extract root field names from introspection data.
 */
function extractIntrospectedRootFields(data) {
  const result = { query: new Set(), mutation: new Set() };
  if (!data || !data.__schema) return result;

  const queryTypeName = data.__schema.queryType?.name || "Query";
  const mutationTypeName = data.__schema.mutationType?.name || "Mutation";

  for (const type of (data.__schema.types || [])) {
    if (type.name === queryTypeName && type.fields) {
      for (const f of type.fields) result.query.add(f.name);
    }
    if (type.name === mutationTypeName && type.fields) {
      for (const f of type.fields) result.mutation.add(f.name);
    }
  }
  return result;
}

function resolveEndpoint(baseUrl, path) {
  const b = baseUrl.endsWith("/") ? baseUrl.slice(0, -1) : baseUrl;
  const p = path.startsWith("/") ? path : `/${path}`;
  return `${b}${p}`;
}

/**
 * OpenAPI 3.x contract validator (TEMPER-03 Slice 03.2).
 *
 * Validates a live API against its OpenAPI spec by:
 *   1. Parsing the spec (JSON or YAML via injected `importFn`)
 *   2. Enumerating paths × methods (GET/HEAD by default)
 *   3. Firing requests with `X-Tempering-Scan: true` header
 *   4. Checking response status against spec `responses` keys
 *   5. Shallow key+type check on JSON response bodies
 *
 * Intentionally shallow — no `$ref` resolution, no full JSON Schema
 * validation. Deep validation (e.g. via ajv) is extension territory.
 *
 * @module tempering/scanners/contract-openapi
 */
import { readFileSync } from "node:fs";

// Methods considered non-mutating (safe to fire without opt-in)
const SAFE_METHODS = new Set(["get", "head", "options"]);

/**
 * Validate a live API against an OpenAPI spec.
 *
 * @param {string} specPath    — absolute path to the spec file
 * @param {string} baseUrl     — base URL of the running API
 * @param {object} opts
 * @param {boolean} [opts.allowMutatingMethods=false]
 * @param {number}  [opts.maxOperations=200]
 * @param {number}  [opts.timeoutMs=5000]
 * @param {Function} [opts.importFn] — dynamic import for js-yaml
 * @param {Function} [opts.now]
 * @param {number}  [opts.hardDeadline] — epoch ms budget ceiling
 * @returns {Promise<{ operations: number, passed: number, failed: number, violations: Array, truncated?: boolean }>}
 */
function parseSpecFailure(reason, skipped = false) {
  return { operations: 0, passed: 0, failed: 0, violations: [], ...(skipped ? { skipped: true } : { error: true }), reason };
}

async function parseOpenApiSpec(specPath, importFn) {
  try {
    const raw = readFileSync(specPath, "utf-8");
    if (!/\.ya?ml$/i.test(specPath)) {
      return { spec: JSON.parse(raw) };
    }
    return loadYamlOpenApiSpec(raw, importFn);
  } catch (err) {
    return { error: parseSpecFailure(`parse-error: ${err.message}`) };
  }
}

async function loadYamlOpenApiSpec(raw, importFn) {
  let yaml;
  try {
    yaml = await importFn("js-yaml");
  } catch {
    return { error: parseSpecFailure("yaml-parser-not-installed", true) };
  }
  const loadFn = yaml.load || yaml.default?.load;
  if (!loadFn) {
    return { error: parseSpecFailure("yaml-parser-not-installed", true) };
  }
  try {
    return { spec: loadFn(raw) };
  } catch (err) {
    return { error: parseSpecFailure(`parse-error: ${err.message}`) };
  }
}

function enumerateOpenApiOperations(spec, allowMutatingMethods) {
  const operations = [];
  for (const [path, pathItem] of Object.entries(spec.paths || {})) {
    for (const [method, op] of Object.entries(pathItem)) {
      if (!shouldIncludeOpenApiOperation(method, op, allowMutatingMethods)) continue;
      operations.push({ path, method: method.toLowerCase(), op });
    }
  }
  return operations;
}

function shouldIncludeOpenApiOperation(method, op, allowMutatingMethods) {
  if (typeof op !== "object" || op === null) return false;
  return allowMutatingMethods || SAFE_METHODS.has(method.toLowerCase());
}

function capOpenApiOperations(operations, maxOperations) {
  return {
    toRun: operations.slice(0, maxOperations),
    truncated: operations.length > maxOperations,
  };
}

function buildFetchOptions(method, op, timeoutMs) {
  const headers = { "X-Tempering-Scan": "true" };
  const fetchOpts = {
    method: method.toUpperCase(),
    headers,
    signal: AbortSignal.timeout(timeoutMs),
  };
  if (!SAFE_METHODS.has(method)) {
    const body = synthesizeBody(op);
    if (body !== undefined) {
      fetchOpts.body = JSON.stringify(body);
      headers["Content-Type"] = "application/json";
    }
  }
  return fetchOpts;
}

function createFetchViolation(err) {
  const reason = err.name === "TimeoutError"
    ? "timeout"
    : err.cause?.code === "ECONNREFUSED" || /ECONNREFUSED/.test(err.message)
      ? "connection-refused"
      : `fetch-error: ${err.message}`;
  return { expected: null, actual: null, reason };
}

function matchResponseStatus(response, op) {
  const specResponses = op.responses || {};
  const statusStr = String(response.status);
  return {
    specResponses,
    statusStr,
    statusMatch: specResponses[statusStr] || specResponses[`${statusStr[0]}XX`] || specResponses.default,
  };
}

async function validateOpenApiOperation({ baseUrl, path, method, op, timeoutMs }) {
  const url = resolveUrl(baseUrl, path);
  let response;
  try {
    response = await fetch(url, buildFetchOptions(method, op, timeoutMs));
  } catch (err) {
    return { passed: false, violation: { path, method, ...createFetchViolation(err) } };
  }

  const statusCheck = matchResponseStatus(response, op);
  if (!statusCheck.statusMatch) {
    return {
      passed: false,
      violation: {
        path,
        method,
        expected: Object.keys(statusCheck.specResponses).join(", "),
        actual: statusCheck.statusStr,
        reason: "status-mismatch",
      },
    };
  }

  if (response.status === 401 || response.status === 403) {
    return {
      passed: false,
      violation: { path, method, expected: null, actual: statusCheck.statusStr, reason: "auth-required" },
    };
  }

  const contentType = response.headers.get("content-type") || "";
  if (!contentType.includes("application/json")) {
    return { passed: true };
  }

  const shapeResult = await checkResponseShape(response, statusCheck.statusMatch);
  if (!shapeResult) {
    return { passed: true };
  }
  return {
    passed: false,
    violation: { path, method, ...shapeResult, reason: "shape-mismatch" },
  };
}

export async function validateOpenApiSpec(specPath, baseUrl, opts = {}) {
  const {
    allowMutatingMethods = false,
    maxOperations = 200,
    timeoutMs = 5000,
    importFn = (spec) => import(spec),
    now = () => Date.now(),
    hardDeadline = Infinity,
  } = opts;

  const parsedSpec = await parseOpenApiSpec(specPath, importFn);
  if (parsedSpec.error) {
    return parsedSpec.error;
  }

  const spec = parsedSpec.spec;
  if (!spec || !spec.paths) {
    return parseSpecFailure("no-paths-in-spec");
  }

  const operations = enumerateOpenApiOperations(spec, allowMutatingMethods);
  const { toRun, truncated } = capOpenApiOperations(operations, maxOperations);
  const violations = [];
  let passed = 0;
  let failed = 0;

  for (const operation of toRun) {
    if (now() >= hardDeadline) {
      return { operations: toRun.length, passed, failed, violations, truncated, budgetExceeded: true };
    }
    const result = await validateOpenApiOperation({ baseUrl, timeoutMs, ...operation });
    if (result.passed) {
      passed++;
    } else {
      failed++;
      violations.push(result.violation);
    }
  }

  return { operations: toRun.length, passed, failed, violations, truncated };
}

/**
 * Resolve a spec path template against the base URL. Replaces
 * `{param}` placeholders with `__test__` so the URL is valid.
 */
function resolveUrl(base, path) {
  const resolved = path.replace(/\{[^}]+\}/g, "__test__");
  const b = base.endsWith("/") ? base.slice(0, -1) : base;
  return `${b}${resolved}`;
}

/**
 * Synthesize a request body from the OpenAPI operation spec.
 * Priority: examples → example → minimal from schema → undefined.
 */
function synthesizeBody(op) {
  const rb = op.requestBody;
  if (!rb || !rb.content) return undefined;
  const jsonContent = rb.content["application/json"];
  if (!jsonContent) return undefined;

  // Spec-provided examples (highest priority)
  if (jsonContent.examples) {
    const first = Object.values(jsonContent.examples)[0];
    if (first && first.value !== undefined) return first.value;
  }
  if (jsonContent.example !== undefined) return jsonContent.example;

  // Minimal from schema
  if (jsonContent.schema) return {};
  return undefined;
}

/**
 * Shallow key+type check on a JSON response body against the spec
 * schema. Only checks top-level `required` properties. Returns a
 * violation descriptor or null if OK.
 */
async function parseResponseJson(response) {
  try {
    return { body: await response.json() };
  } catch {
    return { error: { expected: "valid JSON", actual: "parse-error", reason: "parse-error" } };
  }
}

function validateRequiredResponseKey(body, schema, key) {
  if (!(key in body)) {
    return { expected: `key "${key}"`, actual: `missing key "${key}"` };
  }
  return validateResponsePropertyType(body[key], schema.properties && schema.properties[key], key);
}

function validateResponsePropertyType(value, propSchema, key) {
  if (!propSchema || !propSchema.type) return null;
  const actualType = Array.isArray(value) ? "array" : typeof value;
  if (propSchema.type === "integer") {
    return actualType === "number" ? null : { expected: `"${key}" as integer`, actual: `"${key}" is ${actualType}` };
  }
  if (propSchema.type === actualType || (propSchema.type === "number" && actualType === "number")) {
    return null;
  }
  return { expected: `"${key}" as ${propSchema.type}`, actual: `"${key}" is ${actualType}` };
}

async function checkResponseShape(response, statusMatch) {
  const parsed = await parseResponseJson(response);
  if (parsed.error) {
    return parsed.error;
  }

  const schema = statusMatch?.content?.["application/json"]?.schema;
  if (!schema || !schema.required || !Array.isArray(schema.required)) return null;
  if (typeof parsed.body !== "object" || parsed.body === null) {
    return { expected: `object with keys: ${schema.required.join(", ")}`, actual: typeof parsed.body };
  }

  for (const key of schema.required) {
    const violation = validateRequiredResponseKey(parsed.body, schema, key);
    if (violation) return violation;
  }
  return null;
}

/**
 * Contract scanner dispatcher (TEMPER-03 Slice 03.2).
 *
 * Cross-stack scanner — validates live API responses against OpenAPI
 * or GraphQL specs. Loaded lazily by runner.mjs so missing optional
 * dependencies (js-yaml) don't fail the unit+integration path.
 *
 * Follows the same result contract as ui-playwright.mjs:
 *   { scanner, startedAt, completedAt, verdict, pass, fail, skipped,
 *     durationMs, violations?, reason?, details? }
 *
 * Spec auto-detection order:
 *   config.scanners.contract.specPath →
 *   openapi.yaml → openapi.json →
 *   docs/api/openapi.yaml → docs/api/openapi.json →
 *   schema.graphql → docs/api/schema.graphql
 *
 * @module tempering/scanners/contract
 */
import { existsSync } from "node:fs";
import { resolve as pathResolve } from "node:path";
import { writeFileSync } from "node:fs";
import { ensureScannerArtifactDir, seedArtifactsGitignore } from "../artifacts.mjs";
import { looksLikeProduction, resolveAppUrl } from "./ui-playwright.mjs";
import { validateOpenApiSpec } from "./contract-openapi.mjs";
import { validateGraphqlSchema } from "./contract-graphql.mjs";

// ─── Spec auto-detection paths ────────────────────────────────────────

const SPEC_SEARCH_PATHS = [
  "openapi.yaml",
  "openapi.yml",
  "openapi.json",
  "docs/api/openapi.yaml",
  "docs/api/openapi.yml",
  "docs/api/openapi.json",
  "schema.graphql",
  "docs/api/schema.graphql",
];

/**
 * Run the contract scanner. Entry point called by runner.mjs.
 *
 * @param {object} ctx
 * @param {object} ctx.config         — loaded tempering config
 * @param {string} ctx.projectDir     — project root
 * @param {string} ctx.runId          — current run ID
 * @param {{plan:string,slice:string}|null} [ctx.sliceRef]
 * @param {Function} [ctx.importFn]   — for js-yaml injection
 * @param {Function} [ctx.now]
 * @param {object}   [ctx.env]        — process.env-shaped map
 * @returns {Promise<object>} scanner result record
 */
function createContractSkippedFrame(base, now, reason) {
  return {
    ...base,
    skipped: true,
    reason,
    verdict: "skipped",
    pass: 0,
    fail: 0,
    durationMs: 0,
    completedAt: new Date(now()).toISOString(),
  };
}

function resolveContractSettings(scannerConfig) {
  return {
    enabled: true,
    specPath: null,
    baseUrl: null,
    allowMutatingMethods: false,
    maxOperations: 200,
    timeoutMs: 5000,
    graphqlEndpoint: null,
    ...(typeof scannerConfig === "object" ? scannerConfig : {}),
  };
}

function resolveContractBaseUrl(settings, config, env) {
  return settings.baseUrl || (env && env.PFORGE_TEMPERING_CONTRACT_URL) || resolveAppUrl(config, env);
}

async function runContractValidator({ specPath, baseUrl, settings, importFn, now, hardDeadline }) {
  if (/\.graphql$/i.test(specPath)) {
    return validateGraphqlSchema(specPath, baseUrl, {
      graphqlEndpoint: settings.graphqlEndpoint || "/graphql",
      timeoutMs: settings.timeoutMs,
      now,
      hardDeadline,
    });
  }
  return validateOpenApiSpec(specPath, baseUrl, {
    allowMutatingMethods: settings.allowMutatingMethods,
    maxOperations: settings.maxOperations,
    timeoutMs: settings.timeoutMs,
    importFn,
    now,
    hardDeadline,
  });
}

function resolveContractVerdict(result, fail) {
  if (result.budgetExceeded) return "budget-exceeded";
  if (result.error) return "error";
  if (fail > 0) return "fail";
  if (result.skipped) return "skipped";
  return "pass";
}

function writeContractArtifact(projectDir, runId, report) {
  const artifactDir = ensureScannerArtifactDir(projectDir, runId, "contract");
  if (!artifactDir) return artifactDir;
  seedArtifactsGitignore(projectDir);
  try {
    writeFileSync(
      pathResolve(artifactDir, "report.json"),
      JSON.stringify(report, null, 2) + "\n",
      "utf-8",
    );
  } catch { /* best-effort */ }
  return artifactDir;
}

function resolveContractContext(ctx) {
  const {
    config = {},
    projectDir,
    runId,
    sliceRef = null,
    importFn = (spec) => import(spec),
    now = () => Date.now(),
    env = process.env,
  } = ctx || {};
  return { config, projectDir, runId, sliceRef, importFn, now, env };
}

function isContractDisabled(scannerConfig) {
  return scannerConfig === false || (scannerConfig && scannerConfig.enabled === false);
}

function buildContractErrorFrame(base, now, t0, err) {
  return {
    ...base,
    verdict: "error",
    error: err.message || String(err),
    pass: 0,
    fail: 0,
    durationMs: now() - t0,
    completedAt: new Date(now()).toISOString(),
  };
}

function buildContractResult({ base, now, t0, projectDir, runId, specPath, baseUrl, result }) {
  const isGraphql = /\.graphql$/i.test(specPath);
  const violations = result.violations || [];
  const pass = result.passed || 0;
  const fail = result.failed || 0;
  const verdict = resolveContractVerdict(result, fail);
  const specType = isGraphql ? "graphql" : "openapi";
  const artifactDir = writeContractArtifact(projectDir, runId, {
    scanner: "contract",
    startedAt: base.startedAt,
    specPath,
    specType,
    baseUrl,
    violations,
    verdict,
    pass,
    fail,
  });

  return {
    ...base,
    verdict,
    specPath,
    specType,
    pass,
    fail,
    skipped: 0,
    violations,
    violationCount: violations.length,
    durationMs: now() - t0,
    artifactDir,
    completedAt: new Date(now()).toISOString(),
    ...(result.truncated ? { details: { truncated: true } } : {}),
    ...(result.reason ? { reason: result.reason } : {}),
  };
}

export async function runContractScan(ctx) {
  const contractCtx = resolveContractContext(ctx);
  const t0 = contractCtx.now();
  const base = {
    scanner: "contract",
    sliceRef: contractCtx.sliceRef,
    startedAt: new Date(t0).toISOString(),
  };
  const scannerConfig = contractCtx.config.scanners?.contract;
  if (isContractDisabled(scannerConfig)) {
    return createContractSkippedFrame(base, contractCtx.now, "scanner-disabled");
  }

  const settings = resolveContractSettings(scannerConfig);
  const specPath = findSpec(contractCtx.projectDir, settings.specPath);
  if (!specPath) return createContractSkippedFrame(base, contractCtx.now, "no-spec-found");

  const baseUrl = resolveContractBaseUrl(settings, contractCtx.config, contractCtx.env);
  if (!baseUrl) return createContractSkippedFrame(base, contractCtx.now, "url-not-configured");
  if (looksLikeProduction(baseUrl) && !settings.allowProduction) {
    return createContractSkippedFrame(base, contractCtx.now, "production-url-without-opt-in");
  }

  const hardDeadline = t0 + ((contractCtx.config.runtimeBudgets && contractCtx.config.runtimeBudgets.contractMaxMs) || 300000);
  try {
    const result = await runContractValidator({
      specPath,
      baseUrl,
      settings,
      importFn: contractCtx.importFn,
      now: contractCtx.now,
      hardDeadline,
    });
    return buildContractResult({
      base,
      now: contractCtx.now,
      t0,
      projectDir: contractCtx.projectDir,
      runId: contractCtx.runId,
      specPath,
      baseUrl,
      result,
    });
  } catch (err) {
    return buildContractErrorFrame(base, contractCtx.now, t0, err);
  }
}

/**
 * Find the spec file — config override first, then auto-detection.
 */
function findSpec(projectDir, configSpecPath) {
  if (configSpecPath) {
    const abs = pathResolve(projectDir, configSpecPath);
    return existsSync(abs) ? abs : null;
  }
  for (const rel of SPEC_SEARCH_PATHS) {
    const abs = pathResolve(projectDir, rel);
    if (existsSync(abs)) return abs;
  }
  return null;
}

/**
 * Plan Forge — TEMPER-05 Slice 05.1: Flakiness scanner.
 *
 * Reads the last N tempering run records and classifies each test
 * by its pass/fail outcome history. Tests that flake above the
 * configured threshold are flagged; optionally quarantined when
 * the guard is met (≥ confirmedFlakeMinFailures).
 */

import { resolve } from "node:path";
import { existsSync, readdirSync, readFileSync } from "node:fs";

// ─── Defaults ─────────────────────────────────────────────────────────

export const FLAKINESS_DEFAULTS = Object.freeze({
  enabled: true,
  windowSize: 20,
  flakeThreshold: 0.05,
  minRunsForClassification: 3,
  quarantine: false,
  confirmedFlakeMinFailures: 3,
});

// ─── Hub helper ───────────────────────────────────────────────────────

function emit(hub, type, data) {
  if (!hub || typeof hub.broadcast !== "function") return;
  try {
    hub.broadcast({ type, data, timestamp: new Date().toISOString() });
  } catch { /* best-effort */ }
}

// ─── Scanner entry point ──────────────────────────────────────────────

/**
 * @param {object} ctx - DI context
 * @returns {Promise<object>} scanner result
 */
function buildFlakinessResult({ sliceRef, startedAt, completedAt, verdict, pass = 0, fail = 0, flakes = [], quarantined = [], reason = null, nowMs = 0 }) {
  const result = {
    scanner: "flakiness",
    sliceRef,
    startedAt,
    completedAt,
    verdict,
    pass,
    fail,
    skipped: 0,
    violationCount: flakes.length,
    durationMs: nowMs,
    flakes,
    quarantined,
  };
  if (reason) result.reason = reason;
  return result;
}

function maybeCaptureConfirmedFlake({ captureMemory, settings, testId, outcomes, classification }) {
  const failureCount = outcomes.filter((o) => o !== "pass").length;
  if (!captureMemory || failureCount < settings.confirmedFlakeMinFailures) return failureCount;
  try {
    captureMemory({
      type: "flaky-test",
      testId,
      failureRate: classification.failureRate,
      window: classification.window,
    });
  } catch { /* best-effort */ }
  return failureCount;
}

function buildQuarantineList(flakes, outcomeMap, settings) {
  if (!settings.quarantine) return [];
  return flakes
    .filter((flake) => (outcomeMap[flake.testId] || []).filter((o) => o !== "pass").length >= settings.confirmedFlakeMinFailures)
    .map((flake) => flake.testId);
}

export async function runFlakinessScan(ctx) {
  const {
    config = {},
    projectDir,
    runId,
    sliceRef = null,
    now = () => Date.now(),
    env = process.env,
    hub = null,
    captureMemory = null,
  } = ctx || {};

  const startedAt = new Date(now()).toISOString();
  const raw = config.scanners?.flakiness;
  const settings = { ...FLAKINESS_DEFAULTS, ...(typeof raw === "object" ? raw : {}) };
  const deadline = now() + (config.runtimeBudgets?.flakinessMaxMs ?? 60_000);

  if (raw === false || settings.enabled === false) {
    return buildFlakinessResult({
      sliceRef,
      startedAt,
      completedAt: new Date(now()).toISOString(),
      verdict: "skipped",
      reason: "scanner-disabled",
    });
  }

  const runs = loadRunRecords(resolve(projectDir, ".forge", "tempering"), settings.windowSize);
  if (runs.length < 2) {
    return buildFlakinessResult({
      sliceRef,
      startedAt,
      completedAt: new Date(now()).toISOString(),
      verdict: "skipped",
      reason: "no-prior-runs",
    });
  }

  const outcomeMap = buildOutcomeMap(runs);
  const flakes = [];
  let passCount = 0;
  let failCount = 0;

  for (const [testId, outcomes] of Object.entries(outcomeMap)) {
    if (now() > deadline) {
      return buildFlakinessResult({
        sliceRef,
        startedAt,
        completedAt: new Date(now()).toISOString(),
        verdict: "budget-exceeded",
        pass: passCount,
        fail: failCount,
        flakes,
        quarantined: [],
        reason: "budget-exceeded",
        nowMs: now() - new Date(startedAt).getTime(),
      });
    }

    const classification = classifyTest(testId, outcomes, settings);
    if (classification.classification !== "flaky") {
      passCount++;
      continue;
    }

    flakes.push(classification);
    failCount++;
    emit(hub, "tempering-flakiness-detected", {
      testId,
      failureRate: classification.failureRate,
      window: classification.window,
    });
    maybeCaptureConfirmedFlake({ captureMemory: captureMemory, settings: settings, testId: testId, outcomes: outcomes, classification: classification });
  }

  const completedAt = new Date(now()).toISOString();
  return buildFlakinessResult({
    sliceRef,
    startedAt,
    completedAt,
    verdict: flakes.length > 0 ? "fail" : "pass",
    pass: passCount,
    fail: failCount,
    flakes,
    quarantined: buildQuarantineList(flakes, outcomeMap, settings),
    nowMs: new Date(completedAt).getTime() - new Date(startedAt).getTime(),
  });
}

// ─── Internals ────────────────────────────────────────────────────────

function loadRunRecords(temperingDir, windowSize) {
  if (!existsSync(temperingDir)) return [];
  try {
    const files = readdirSync(temperingDir)
      .filter((f) => f.startsWith("run-") && f.endsWith(".json"))
      .sort()
      .reverse()
      .slice(0, windowSize);

    const records = [];
    for (const f of files) {
      try {
        const raw = readFileSync(resolve(temperingDir, f), "utf-8");
        records.push(JSON.parse(raw));
      } catch {
        // skip corrupted records
      }
    }
    return records;
  } catch {
    return [];
  }
}

function buildOutcomeMap(runs) {
  const map = {};
  for (const run of runs) {
    if (!Array.isArray(run.scanners)) continue;
    for (const scanner of run.scanners) {
      const tests = scanner?.tests || scanner?.unitResult?.tests || scanner?.integrationResult?.tests;
      if (!Array.isArray(tests)) continue;
      for (const test of tests) {
        const id = test.testId || test.name || test.id;
        if (!id) continue;
        if (!map[id]) map[id] = [];
        map[id].push(test.status === "pass" ? "pass" : test.status || "fail");
      }
    }
  }
  return map;
}

function classifyTest(testId, outcomes, settings) {
  const window = outcomes.length;
  const failures = outcomes.filter((o) => o !== "pass").length;
  const failureRate = window > 0 ? failures / window : 0;

  let classification;
  if (window < settings.minRunsForClassification) {
    classification = "new";
  } else if (failures === 0) {
    classification = "stable-pass";
  } else if (failures === window) {
    classification = "stable-fail";
  } else if (failureRate > settings.flakeThreshold) {
    classification = "flaky";
  } else {
    classification = "stable-pass";
  }

  return {
    testId,
    classification,
    failureRate,
    window,
    runs: outcomes,
  };
}

/**
 * Plan Forge — TEMPER-05 Slice 05.1: Load / Stress scanner.
 *
 * Drives HTTP load via `autocannon` (lazy-imported via `importFn` DI)
 * against configured or auto-derived endpoints. Optionally ramps
 * concurrency until the error-rate threshold is breached (stress mode).
 *
 * FORBIDDEN: never run against production without explicit opt-in.
 */

import { resolve } from "node:path";
import { existsSync, readFileSync } from "node:fs";
import { appendPerfEntry } from "../perf-history.mjs";

// ─── Defaults ─────────────────────────────────────────────────────────

export const LOAD_DEFAULTS = Object.freeze({
  enabled: true,
  concurrency: 100,
  durationSec: 60,
  allowProduction: false,
  stressMode: false,
  stressErrorRateThreshold: 0.01,
  endpoints: [],
});

// ─── Hub helper ───────────────────────────────────────────────────────

function emit(hub, type, data) {
  if (!hub || typeof hub.broadcast !== "function") return;
  try {
    hub.broadcast({ type, data, timestamp: new Date().toISOString() });
  } catch { /* best-effort */ }
}

function buildLoadStressResult({ sliceRef, startedAt, now, verdict, pass = 0, fail = 0, results = [], reason = null, settings = LOAD_DEFAULTS }) {
  const completedAt = new Date(now()).toISOString();
  return {
    scanner: "load-stress",
    sliceRef,
    startedAt,
    completedAt,
    verdict,
    pass,
    fail,
    skipped: 0,
    violationCount: countLoadStressViolations(results, settings),
    durationMs: new Date(completedAt).getTime() - new Date(startedAt).getTime(),
    results,
    ...(reason ? { reason } : {}),
  };
}

function resolveLoadEndpoints(settings, projectDir) {
  if (Array.isArray(settings.endpoints) && settings.endpoints.length > 0) {
    return settings.endpoints;
  }
  return resolveEndpointsFromOpenAPI(projectDir);
}

async function loadAutocannon(importFn) {
  const mod = await importFn("autocannon");
  return mod.default || mod;
}

function firstDefinedMetric(...values) {
  for (const value of values) {
    if (value != null) return value;
  }
  return 0;
}

function extractLatencyMetrics(acResult) {
  const latency = acResult?.latency || {};
  return {
    p50: firstDefinedMetric(latency.p50, acResult?.p50),
    p95: firstDefinedMetric(latency.p95, acResult?.p95),
    p99: firstDefinedMetric(latency.p99, acResult?.p99),
  };
}

function extractRequestMetrics(acResult) {
  return {
    totalRequests: firstDefinedMetric(acResult?.requests?.total, acResult?.totalRequests),
    errors: firstDefinedMetric(acResult?.errors, acResult?.non2xx),
    throughput: firstDefinedMetric(acResult?.throughput?.average, acResult?.throughput),
  };
}

function extractAutocannonMetrics(acResult) {
  const latencyMetrics = extractLatencyMetrics(acResult);
  const requestMetrics = extractRequestMetrics(acResult);
  return {
    ...latencyMetrics,
    totalRequests: requestMetrics.totalRequests,
    throughput: requestMetrics.throughput,
    errorRate: requestMetrics.totalRequests > 0 ? requestMetrics.errors / requestMetrics.totalRequests : 0,
  };
}

async function findStressBreakpoint({ autocannon, url, method, settings, now, deadline }) {
  let breakpoint = null;
  let currentConcurrency = settings.concurrency;
  while (currentConcurrency <= settings.concurrency * 8) {
    if (now() > deadline) break;
    currentConcurrency *= 2;
    try {
      const stressResult = await autocannon({
        url,
        connections: currentConcurrency,
        duration: Math.min(settings.durationSec, 10),
        method,
      });
      const { errorRate } = extractAutocannonMetrics(stressResult);
      if (errorRate >= settings.stressErrorRateThreshold) {
        breakpoint = currentConcurrency;
        break;
      }
    } catch {
      breakpoint = currentConcurrency;
      break;
    }
  }
  return breakpoint;
}

function appendLoadPerfEntry({ now, runId, projectDir, url, method, metrics }) {
  try {
    appendPerfEntry({
      timestamp: new Date(now()).toISOString(),
      runId,
      endpoint: url,
      method,
      p50: metrics.p50,
      p95: metrics.p95,
      p99: metrics.p99,
      errorRate: metrics.errorRate,
      source: "load-stress",
    }, projectDir);
  } catch { /* best-effort */ }
}

async function scanLoadEndpoint({ autocannon, endpoint, settings, now, deadline, runId, projectDir }) {
  const url = endpoint.url || endpoint.path || endpoint.endpoint;
  const method = (endpoint.method || "GET").toUpperCase();

  try {
    const acResult = await autocannon({
      url,
      connections: settings.concurrency,
      duration: settings.durationSec,
      method,
    });
    const metrics = extractAutocannonMetrics(acResult);
    const result = { endpoint: url, method, ...metrics };
    if (settings.stressMode) {
      result.breakpointConcurrency = await findStressBreakpoint({
        autocannon,
        url,
        method,
        settings,
        now,
        deadline,
      });
    }
    appendLoadPerfEntry({ now, runId, projectDir, url, method, metrics });
    return {
      result,
      pass: metrics.errorRate <= settings.stressErrorRateThreshold,
    };
  } catch (err) {
    return {
      result: {
        endpoint: url,
        method,
        p50: 0,
        p95: 0,
        p99: 0,
        errorRate: 1,
        totalRequests: 0,
        throughput: 0,
        error: err.message || String(err),
      },
      pass: false,
    };
  }
}

function countLoadStressViolations(results, settings) {
  return results.filter((result) => result.errorRate > settings.stressErrorRateThreshold).length;
}

// ─── Scanner entry point ──────────────────────────────────────────────

/**
 * @param {object} ctx - DI context
 * @returns {Promise<object>} scanner result
 */
function resolveLoadStressContext(ctx) {
  const {
    config = {},
    projectDir,
    runId,
    sliceRef = null,
    now = () => Date.now(),
    env = process.env,
    hub = null,
    importFn = (spec) => import(spec),
  } = ctx || {};
  return { config, projectDir, runId, sliceRef, now, env, hub, importFn };
}

function buildLoadStressSkippedResult(sliceRef, startedAt, now, reason) {
  return buildLoadStressResult({ sliceRef, startedAt, now, verdict: "skipped", reason });
}

async function runLoadStressEndpoints({ endpoints, autocannon, settings, now, deadline, runId, projectDir, sliceRef, startedAt }) {
  const results = [];
  let passCount = 0;
  let failCount = 0;

  for (const endpoint of endpoints) {
    if (now() >= deadline) {
      return buildLoadStressResult({
        sliceRef,
        startedAt,
        now,
        verdict: "budget-exceeded",
        pass: passCount,
        fail: failCount,
        results,
        reason: "budget-exceeded",
        settings,
      });
    }

    const outcome = await scanLoadEndpoint({
      autocannon,
      endpoint,
      settings,
      now,
      deadline,
      runId,
      projectDir,
    });
    results.push(outcome.result);
    if (outcome.pass) passCount++;
    else failCount++;
  }

  return { results, passCount, failCount };
}

export async function runLoadStressScan(ctx) {
  const loadCtx = resolveLoadStressContext(ctx);
  const startedAt = new Date(loadCtx.now()).toISOString();
  const raw = loadCtx.config.scanners?.["load-stress"];
  const settings = { ...LOAD_DEFAULTS, ...(typeof raw === "object" ? raw : {}) };
  const deadline = loadCtx.now() + (loadCtx.config.runtimeBudgets?.loadStressMaxMs ?? 300_000);

  if (raw === false || settings.enabled === false) {
    return buildLoadStressSkippedResult(loadCtx.sliceRef, startedAt, loadCtx.now, "scanner-disabled");
  }
  if (loadCtx.env.NODE_ENV === "production" && !settings.allowProduction) {
    return buildLoadStressSkippedResult(loadCtx.sliceRef, startedAt, loadCtx.now, "production-url-without-opt-in");
  }

  const endpoints = resolveLoadEndpoints(settings, loadCtx.projectDir);
  if (!endpoints || endpoints.length === 0) {
    return buildLoadStressSkippedResult(loadCtx.sliceRef, startedAt, loadCtx.now, "no-endpoints-configured");
  }

  let autocannon;
  try {
    autocannon = await loadAutocannon(loadCtx.importFn);
  } catch {
    return buildLoadStressResult({ sliceRef: loadCtx.sliceRef, startedAt, now: loadCtx.now, verdict: "error", reason: "autocannon-import-failed" });
  }

  const outcome = await runLoadStressEndpoints({
    endpoints,
    autocannon,
    settings,
    now: loadCtx.now,
    deadline,
    runId: loadCtx.runId,
    projectDir: loadCtx.projectDir,
    sliceRef: loadCtx.sliceRef,
    startedAt,
  });
  if (outcome.verdict) return outcome;

  const verdict = countLoadStressViolations(outcome.results, settings) > 0 ? "fail" : "pass";
  emit(loadCtx.hub, "tempering-load-completed", {
    endpointCount: outcome.results.length,
    passCount: outcome.passCount,
    failCount: outcome.failCount,
    verdict,
  });

  return buildLoadStressResult({
    sliceRef: loadCtx.sliceRef,
    startedAt,
    now: loadCtx.now,
    verdict,
    pass: outcome.passCount,
    fail: outcome.failCount,
    results: outcome.results,
    settings,
  });
}

// ─── Internals ────────────────────────────────────────────────────────

function resolveEndpointsFromOpenAPI(projectDir) {
  const candidates = [
    "openapi.json", "openapi.yaml", "openapi.yml",
    "swagger.json", "swagger.yaml",
    "docs/openapi.json", "api/openapi.json",
  ];
  for (const candidate of candidates) {
    const specPath = resolve(projectDir, candidate);
    if (existsSync(specPath)) {
      try {
        const raw = readFileSync(specPath, "utf-8");
        const spec = JSON.parse(raw);
        return deriveEndpointsFromSpec(spec);
      } catch {
        continue;
      }
    }
  }
  return [];
}

function deriveEndpointsFromSpec(spec) {
  const endpoints = [];
  const paths = spec.paths || {};
  for (const [path, methods] of Object.entries(paths)) {
    for (const method of Object.keys(methods)) {
      if (["get", "post", "put", "patch", "delete"].includes(method.toLowerCase())) {
        endpoints.push({ path, method: method.toUpperCase(), url: path });
      }
    }
  }
  return endpoints;
}

/**
 * Plan Forge — TEMPER-05 Slice 05.2: Mutation scanner.
 *
 * 9th scanner — drives mutation testing tools (Stryker, dotnet-stryker,
 * mutmut, pitest, go-mutesting, cargo-mutants) via the stack's preset
 * adapter. Scheduling is delegated to `scheduling.mjs`; this module
 * owns the subprocess boundary, output parsing, and result shaping.
 *
 * Design contracts (inherited from load-stress.mjs / contract.mjs):
 *   - Never throws — all errors captured as `{ verdict: "error", reason }`.
 *   - Budget enforced via deadline check.
 *   - Tests inject `spawnFn` + `importFn` to avoid real subprocesses.
 */

import { resolve } from "node:path";
import { shouldRunMutation } from "../scheduling.mjs";

// ─── Defaults ─────────────────────────────────────────────────────────

export const MUTATION_DEFAULTS = Object.freeze({
  enabled: true,
  minima: { domain: 70, integration: 50, overall: 60 },
  criticalPaths: [],
  fullMutation: false,
  nightlyOnly: true,
  mutationMaxMs: 600_000,
});

// ─── Hub helper ───────────────────────────────────────────────────────

function emit(hub, type, data) {
  if (!hub || typeof hub.broadcast !== "function") return;
  try {
    hub.broadcast({ type, data, timestamp: new Date().toISOString() });
  } catch { /* best-effort */ }
}

// ─── Skipped frame helper ─────────────────────────────────────────────

function skippedFrame(sliceRef, now, reason) {
  const ts = new Date(now()).toISOString();
  return {
    scanner: "mutation",
    sliceRef,
    startedAt: ts,
    completedAt: ts,
    verdict: "skipped",
    pass: 0, fail: 0, skipped: 0,
    durationMs: 0,
    mutationScore: null,
    layers: null,
    reason,
  };
}

function buildMutationFrame({ sliceRef, startedAt, now, verdict, reason, mutationScore = null, layers = null }) {
  const completedAt = new Date(now()).toISOString();
  return {
    scanner: "mutation",
    sliceRef,
    startedAt,
    completedAt,
    verdict,
    pass: 0,
    fail: 0,
    skipped: 0,
    durationMs: new Date(completedAt).getTime() - new Date(startedAt).getTime(),
    mutationScore,
    layers,
    reason,
  };
}

async function loadMutationAdapter(config, importFn) {
  try {
    const stack = config._detectedStack || "typescript";
    const mod = await importFn(`../../../presets/${stack}/tempering-adapter.mjs`);
    return mod.temperingAdapter || mod.default;
  } catch {
    return null;
  }
}

async function runMutationProcess({ spawnFn, command, projectDir, budgetMs }) {
  if (!spawnFn) {
    return { skipped: true, reason: "tool-not-installed" };
  }
  const proc = await spawnFn(command, { cwd: projectDir, budgetMs });
  if (proc.timedOut) {
    return { budgetExceeded: true };
  }
  return {
    stdout: proc.stdout || "",
    stderr: proc.stderr || "",
    exitCode: proc.exitCode ?? -1,
  };
}

function parseMutationOutput(parseOutput, stdout, stderr, exitCode) {
  try {
    return parseOutput(stdout, stderr, exitCode) || {
      mutationScore: null,
      killed: 0,
      survived: 0,
      timeout: 0,
      noCoverage: 0,
      layers: null,
    };
  } catch {
    return {
      mutationScore: exitCode === 0 ? 100 : null,
      killed: 0,
      survived: 0,
      timeout: 0,
      noCoverage: 0,
      layers: null,
      reason: "parse-degraded",
    };
  }
}

function evaluateMutationResults(parsed, settings) {
  const totalMutants = (parsed.killed || 0) + (parsed.survived || 0) + (parsed.timeout || 0) + (parsed.noCoverage || 0);
  const minima = settings.minima || MUTATION_DEFAULTS.minima;
  const overallScore = parsed.mutationScore ?? (totalMutants > 0 ? ((parsed.killed || 0) / totalMutants) * 100 : 0);
  const layerResults = buildLayerResults(parsed.layers, minima);
  const overallMinimum = minima.overall ?? 60;
  const failures = countMutationFailures(layerResults, overallScore, overallMinimum);
  return {
    totalMutants,
    overallScore,
    overallMinimum,
    layerResults,
    failures,
    verdict: failures > 0 ? "fail" : "pass",
  };
}

function buildLayerResults(layers, minima) {
  if (!layers || typeof layers !== "object") return [];
  return Object.entries(layers).map(([layer, score]) => {
    const minimum = minima[layer] ?? minima.overall ?? 60;
    return { layer, score, minimum, pass: score >= minimum };
  });
}

function countMutationFailures(layerResults, overallScore, overallMinimum) {
  let failCount = layerResults.filter((layer) => !layer.pass).length;
  if (overallScore < overallMinimum) {
    failCount++;
  }
  return failCount;
}

function emitMutationFailure({ hub, runId, sliceRef, overallScore, overallMinimum, layerResults }) {
  emit(hub, "tempering-mutation-below-minimum", {
    runId,
    sliceRef,
    overallScore,
    overallMinimum,
    layersBelowMinimum: layerResults.filter((layer) => !layer.pass),
  });
}

function captureMutationFailure({ captureMemory, layerResults, overallScore, overallMinimum, projectDir }) {
  if (!captureMemory || typeof captureMemory !== "function") return;
  try {
    const gapSummary = layerResults
      .filter((layer) => !layer.pass)
      .map((layer) => `${layer.layer}: ${layer.score.toFixed(1)}% (min ${layer.minimum}%)`)
      .join(", ");
    captureMemory(
      `Mutation score below minimum: overall=${overallScore.toFixed(1)}% (min ${overallMinimum}%). Gaps: ${gapSummary || "overall only"}`,
      "lesson",
      `tempering/mutation-gap`,
      projectDir,
    );
  } catch { /* best-effort */ }
}

function resolveMutationContext(ctx) {
  const {
    config = {},
    projectDir,
    runId,
    sliceRef = null,
    now = () => Date.now(),
    env = process.env,
    hub = null,
    captureMemory = null,
    importFn = (spec) => import(spec),
    spawnFn = null,
    trigger = "manual",
    touchedFiles = [],
  } = ctx || {};
  return {
    config,
    projectDir,
    runId,
    sliceRef,
    now,
    env,
    hub,
    captureMemory,
    importFn,
    spawnFn,
    trigger,
    touchedFiles,
  };
}

function buildScheduleSkippedFrame(sliceRef, now, schedule) {
  return {
    ...skippedFrame(sliceRef, now, "schedule-skipped"),
    scheduleReason: schedule.reason,
  };
}

function buildMutationSuccessResult({ sliceRef, startedAt, now, parsed, evaluation }) {
  const completedAt = new Date(now()).toISOString();
  return {
    scanner: "mutation",
    sliceRef,
    startedAt,
    completedAt,
    verdict: evaluation.verdict,
    pass: evaluation.verdict === "pass" ? 1 : 0,
    fail: evaluation.verdict === "fail" ? 1 : 0,
    skipped: 0,
    durationMs: new Date(completedAt).getTime() - new Date(startedAt).getTime(),
    mutationScore: evaluation.overallScore,
    killed: parsed.killed || 0,
    survived: parsed.survived || 0,
    timeout: parsed.timeout || 0,
    noCoverage: parsed.noCoverage || 0,
    layers: evaluation.layerResults.length > 0 ? evaluation.layerResults : null,
    reason: parsed.reason || null,
  };
}

function handleMutationFailureEffects(mutationCtx, evaluation) {
  if (evaluation.verdict !== "fail") return;
  emitMutationFailure({
    hub: mutationCtx.hub,
    runId: mutationCtx.runId,
    sliceRef: mutationCtx.sliceRef,
    overallScore: evaluation.overallScore,
    overallMinimum: evaluation.overallMinimum,
    layerResults: evaluation.layerResults,
  });
  captureMutationFailure({
    captureMemory: mutationCtx.captureMemory,
    layerResults: evaluation.layerResults,
    overallScore: evaluation.overallScore,
    overallMinimum: evaluation.overallMinimum,
    projectDir: mutationCtx.projectDir,
  });
}

async function executeMutationProcess(mutationCtx, adapter, budgetMs, startedAt) {
  try {
    return await runMutationProcess({
      spawnFn: mutationCtx.spawnFn,
      command: adapter.mutation.cmd,
      projectDir: mutationCtx.projectDir,
      budgetMs,
    });
  } catch (err) {
    return buildMutationFrame({
      sliceRef: mutationCtx.sliceRef,
      startedAt,
      now: mutationCtx.now,
      verdict: "error",
      reason: `spawn-error:${err.message || err}`,
    });
  }
}

// ─── Scanner entry point ──────────────────────────────────────────────

/**
 * @param {object} ctx - DI context
 * @returns {Promise<object>} scanner result
 */
export async function runMutationScan(ctx) {
  const mutationCtx = resolveMutationContext(ctx);
  const startedAt = new Date(mutationCtx.now()).toISOString();
  const raw = mutationCtx.config.scanners?.mutation;
  if (raw === false) {
    return skippedFrame(mutationCtx.sliceRef, mutationCtx.now, "scanner-disabled");
  }

  const settings = { ...MUTATION_DEFAULTS, ...(typeof raw === "object" ? raw : {}) };
  const schedule = shouldRunMutation({
    config: mutationCtx.config,
    trigger: mutationCtx.trigger,
    touchedFiles: mutationCtx.touchedFiles,
  });
  if (!schedule.run) return buildScheduleSkippedFrame(mutationCtx.sliceRef, mutationCtx.now, schedule);

  const adapter = await loadMutationAdapter(mutationCtx.config, mutationCtx.importFn);
  if (!adapter || !adapter.mutation || !adapter.mutation.supported) {
    return skippedFrame(mutationCtx.sliceRef, mutationCtx.now, "stack-not-supported");
  }

  const budgetMs = mutationCtx.config.runtimeBudgets?.mutationMaxMs ?? settings.mutationMaxMs;
  const deadline = mutationCtx.now() + budgetMs;
  const proc = await executeMutationProcess(mutationCtx, adapter, budgetMs, startedAt);
  if (proc?.scanner === "mutation") return proc;
  if (proc?.skipped) return skippedFrame(mutationCtx.sliceRef, mutationCtx.now, proc.reason);
  if (proc?.budgetExceeded || mutationCtx.now() > deadline) {
    return buildMutationFrame({ sliceRef: mutationCtx.sliceRef, startedAt, now: mutationCtx.now, verdict: "budget-exceeded", reason: "budget-exceeded" });
  }

  const parsed = parseMutationOutput(adapter.mutation.parseOutput, proc.stdout, proc.stderr, proc.exitCode);
  const evaluation = evaluateMutationResults(parsed, settings);
  if (evaluation.totalMutants === 0 && parsed.mutationScore == null) {
    return skippedFrame(mutationCtx.sliceRef, mutationCtx.now, "no-mutants-generated");
  }

  handleMutationFailureEffects(mutationCtx, evaluation);
  return buildMutationSuccessResult({ sliceRef: mutationCtx.sliceRef, startedAt: startedAt, now: mutationCtx.now, parsed: parsed, evaluation: evaluation });
}

/**
 * Plan Forge — TEMPER-05 Slice 05.1: Performance Budget scanner.
 *
 * Compares per-endpoint p95 latencies against baselines stored in
 * `.forge/tempering/perf-history.jsonl`. A regression is confirmed
 * only when the threshold is breached for `consecutiveRunsRequired`
 * consecutive runs (default 2).
 *
 * FORBIDDEN: never auto-promote baselines when perf improves.
 */

import { resolve, dirname } from "node:path";
import { existsSync, readFileSync } from "node:fs";
import {
  appendPerfEntry,
  readPerfHistory,
  isConsecutiveRegression,
} from "../perf-history.mjs";
// Phase FORGE-SHOP-07 Slice 07.2 — brain facade for perf-history reads
import { recall as brainRecall } from "../../brain.mjs";

// ─── Defaults ─────────────────────────────────────────────────────────

export const PERF_BUDGET_DEFAULTS = Object.freeze({
  enabled: true,
  regressionThreshold: 0.10,
  consecutiveRunsRequired: 2,
  endpoints: [],
  tti: { enabled: false, budgetMs: 3000 },
});

// ─── Hub helper ───────────────────────────────────────────────────────

function emit(hub, type, data) {
  if (!hub || typeof hub.broadcast !== "function") return;
  try {
    hub.broadcast({ type, data, timestamp: new Date().toISOString() });
  } catch { /* best-effort */ }
}

function buildPerfBudgetResult({ sliceRef, startedAt, now, verdict, pass = 0, fail = 0, regressions = [], ttiResults = [], reason = null }) {
  const completedAt = new Date(now()).toISOString();
  return {
    scanner: "performance-budget",
    sliceRef,
    startedAt,
    completedAt,
    verdict,
    pass,
    fail,
    skipped: 0,
    violationCount: regressions.length + ttiResults.filter((result) => result.verdict === "fail").length,
    durationMs: new Date(completedAt).getTime() - new Date(startedAt).getTime(),
    regressions,
    ttiResults,
    ...(reason ? { reason } : {}),
  };
}

function resolvePerfBudgetEndpoints(settings, projectDir) {
  if (Array.isArray(settings.endpoints) && settings.endpoints.length > 0) {
    return settings.endpoints;
  }
  return resolveEndpointsFromOpenAPI(projectDir);
}

function appendBudgetPerfEntry(ep, { now, runId, projectDir, endpoint, method, currentP95 }) {
  if (currentP95 == null) return;
  try {
    appendPerfEntry({
      timestamp: new Date(now()).toISOString(),
      runId,
      endpoint,
      method,
      p50: ep.p50 || null,
      p95: currentP95,
      p99: ep.p99 || null,
      errorRate: ep.errorRate || 0,
      source: "performance-budget",
    }, projectDir);
  } catch { /* best-effort */ }
}

async function resolveBaselineP95(endpoint, method, projectDir) {
  try {
    const history = await brainRecall("project.tempering.perf-history", { fallback: "none" }, {
      cwd: projectDir,
      readPerfHistory,
    });
    return findLatestBaseline(history, endpoint, method);
  } catch {
    return null;
  }
}

function findLatestBaseline(history, endpoint, method) {
  if (!Array.isArray(history)) return null;
  for (let i = history.length - 1; i >= 0; i--) {
    const entry = history[i];
    if (entry.endpoint === endpoint && entry.method === method && entry.p95 != null) {
      return entry.p95;
    }
  }
  return null;
}

function maybeCapturePerfRegression(captureMemory, regression) {
  if (!captureMemory) return;
  try {
    captureMemory({ type: "perf-regression", ...regression });
  } catch { /* best-effort */ }
}

function evaluateEndpointRegression({ endpoint, method, budgetP95, currentP95, baselineP95, settings, projectDir }) {
  if (baselineP95 == null || currentP95 == null) {
    return { pass: true, regression: null };
  }
  const deltaPercent = (currentP95 - baselineP95) / baselineP95;
  const isRegression = isConsecutiveRegression({
    endpoint,
    method,
    threshold: settings.regressionThreshold,
    cwd: projectDir,
    requiredConsecutive: settings.consecutiveRunsRequired,
  });
  if (!isRegression) {
    return { pass: true, regression: null };
  }
  return {
    pass: false,
    regression: {
      endpoint,
      method,
      baselineP95,
      currentP95,
      deltaPercent,
      consecutiveRuns: settings.consecutiveRunsRequired,
      budgetMs: budgetP95,
    },
  };
}

function readTtiResults(projectDir, runId, ttiSettings) {
  if (!ttiSettings.enabled) return [];
  const artifactsRunDir = resolve(projectDir, ".forge", "tempering", "artifacts", runId || "unknown");
  const timingPath = resolve(artifactsRunDir, "ui-playwright", "timing.json");
  if (!existsSync(timingPath)) return [];
  try {
    const timing = JSON.parse(readFileSync(timingPath, "utf-8"));
    const pages = Array.isArray(timing) ? timing : (timing.pages || []);
    return pages.map((page) => {
      const ttiMs = page.tti || page.ttiMs || 0;
      return {
        page: page.url || page.page,
        ttiMs,
        budgetMs: ttiSettings.budgetMs,
        verdict: ttiMs > ttiSettings.budgetMs ? "fail" : "pass",
      };
    });
  } catch {
    return [];
  }
}

function countTtiResults(ttiResults) {
  return ttiResults.reduce((counts, result) => {
    if (result.verdict === "fail") counts.fail++;
    else counts.pass++;
    return counts;
  }, { pass: 0, fail: 0 });
}

function resolvePerformanceBudgetContext(ctx) {
  const {
    config = {},
    projectDir,
    runId,
    sliceRef = null,
    now = () => Date.now(),
    env = process.env,
    hub = null,
    captureMemory = null,
    importFn = (spec) => import(spec),
  } = ctx || {};
  return {
    config,
    projectDir,
    runId,
    sliceRef,
    now,
    env,
    hub,
    captureMemory,
    importFn,
  };
}

async function evaluatePerfBudgetEndpoints({ endpoints, budgetCtx, settings, deadline }) {
  const regressions = [];
  let passCount = 0;
  let failCount = 0;

  for (const ep of endpoints) {
    if (budgetCtx.now() > deadline) {
      return {
        verdict: "budget-exceeded",
        regressions,
        passCount,
        failCount,
        reason: "budget-exceeded",
      };
    }

    const endpoint = ep.path || ep.endpoint;
    const method = (ep.method || "GET").toUpperCase();
    const budgetP95 = ep.p95BudgetMs || null;
    const currentP95 = ep.currentP95 || ep.p95 || null;

    appendBudgetPerfEntry(ep, {
      now: budgetCtx.now,
      runId: budgetCtx.runId,
      projectDir: budgetCtx.projectDir,
      endpoint,
      method,
      currentP95,
    });

    const baselineP95 = await resolveBaselineP95(endpoint, method, budgetCtx.projectDir);
    const evaluation = evaluateEndpointRegression({
      endpoint,
      method,
      budgetP95,
      currentP95,
      baselineP95,
      settings,
      projectDir: budgetCtx.projectDir,
    });

    if (evaluation.regression) {
      regressions.push(evaluation.regression);
      failCount++;
      emit(budgetCtx.hub, "tempering-perf-regression", evaluation.regression);
      maybeCapturePerfRegression(budgetCtx.captureMemory, evaluation.regression);
      continue;
    }
    if (evaluation.pass) passCount++;
  }

  return { regressions, passCount, failCount };
}

// ─── Scanner entry point ──────────────────────────────────────────────

/**
 * @param {object} ctx - DI context
 * @returns {Promise<object>} scanner result
 */
export async function runPerformanceBudgetScan(ctx) {
  const budgetCtx = resolvePerformanceBudgetContext(ctx);
  const startedAt = new Date(budgetCtx.now()).toISOString();
  const raw = budgetCtx.config.scanners?.["performance-budget"];
  const settings = { ...PERF_BUDGET_DEFAULTS, ...(typeof raw === "object" ? raw : {}) };
  const ttiSettings = { ...PERF_BUDGET_DEFAULTS.tti, ...(typeof settings.tti === "object" ? settings.tti : {}) };
  const deadline = budgetCtx.now() + (budgetCtx.config.runtimeBudgets?.perfBudgetMaxMs ?? 120_000);

  if (raw === false || settings.enabled === false) {
    return buildPerfBudgetResult({ sliceRef: budgetCtx.sliceRef, startedAt, now: budgetCtx.now, verdict: "skipped", reason: "scanner-disabled" });
  }

  const endpoints = resolvePerfBudgetEndpoints(settings, budgetCtx.projectDir);
  if (!endpoints || endpoints.length === 0) {
    return buildPerfBudgetResult({ sliceRef: budgetCtx.sliceRef, startedAt, now: budgetCtx.now, verdict: "skipped", reason: "no-endpoints-configured" });
  }

  const endpointOutcome = await evaluatePerfBudgetEndpoints({
    endpoints,
    budgetCtx,
    settings,
    deadline,
  });
  if (endpointOutcome.verdict) {
    return buildPerfBudgetResult({
      sliceRef: budgetCtx.sliceRef,
      startedAt,
      now: budgetCtx.now,
      verdict: endpointOutcome.verdict,
      pass: endpointOutcome.passCount,
      fail: endpointOutcome.failCount,
      regressions: endpointOutcome.regressions,
      reason: endpointOutcome.reason,
    });
  }

  const ttiResults = readTtiResults(budgetCtx.projectDir, budgetCtx.runId, ttiSettings);
  const ttiCounts = countTtiResults(ttiResults);
  const passCount = endpointOutcome.passCount + ttiCounts.pass;
  const failCount = endpointOutcome.failCount + ttiCounts.fail;
  const verdict = endpointOutcome.regressions.length > 0 || ttiCounts.fail > 0 ? "fail" : "pass";

  return buildPerfBudgetResult({
    sliceRef: budgetCtx.sliceRef,
    startedAt,
    now: budgetCtx.now,
    verdict,
    pass: passCount,
    fail: failCount,
    regressions: endpointOutcome.regressions,
    ttiResults,
  });
}

// ─── Internals ────────────────────────────────────────────────────────

function resolveEndpointsFromOpenAPI(projectDir) {
  const candidates = [
    "openapi.json", "openapi.yaml", "openapi.yml",
    "swagger.json", "swagger.yaml",
    "docs/openapi.json", "api/openapi.json",
  ];
  for (const candidate of candidates) {
    const specPath = resolve(projectDir, candidate);
    if (existsSync(specPath)) {
      try {
        const raw = readFileSync(specPath, "utf-8");
        const spec = JSON.parse(raw);
        return deriveEndpointsFromSpec(spec);
      } catch {
        continue;
      }
    }
  }
  return [];
}

function deriveEndpointsFromSpec(spec) {
  const endpoints = [];
  const paths = spec.paths || {};
  for (const [path, methods] of Object.entries(paths)) {
    for (const method of Object.keys(methods)) {
      if (["get", "post", "put", "patch", "delete"].includes(method.toLowerCase())) {
        endpoints.push({ path, method: method.toUpperCase() });
      }
    }
  }
  return endpoints;
}

/**
 * UI sweep scanner — Playwright BFS link crawler + axe-core a11y pass
 * (TEMPER-03 Slice 03.1).
 *
 * Cross-stack scanner (not a preset adapter) — runs against a deployed
 * app URL rather than source code. Loads Playwright + @axe-core/playwright
 * via injected `importFn` so:
 *   1. The MCP process doesn't hard-depend on Playwright (heavy dep;
 *      browser install is non-trivial and some environments won't
 *      have it). Missing deps → scanner skips cleanly with
 *      reason="playwright-not-installed", never throws.
 *   2. Tests don't need a real browser — the fixture path injects a
 *      fake Playwright that scripts page responses.
 *
 * The scanner follows the same result contract as the preset-adapter
 * scanners (runScannerUnit / runScannerIntegration) so the top-level
 * `runTemperingRun` dispatcher can treat it uniformly:
 *   { scanner, startedAt, completedAt, verdict, pass, fail, skipped,
 *     durationMs, ... }
 *
 * Forbidden actions (enforced):
 *   - Never follows external-origin links (same-origin only)
 *   - Never issues POST/PUT/DELETE (GET/HEAD only)
 *   - Never runs against production unless config.allowProduction=true
 *   - Aborts cleanly when budget exceeded (closes browser)
 */
import { ensureScannerArtifactDir, hashUrl, seedArtifactsGitignore } from "../artifacts.mjs";
import { existsSync, mkdirSync, writeFileSync } from "node:fs";
import { resolve as pathResolve } from "node:path";

// ─── Scanner config defaults ──────────────────────────────────────────

/**
 * Enterprise-leaning defaults for the UI scanner. Operators can dial
 * any of these down in `.forge/tempering/config.json` under the
 * `ui-playwright` key, but the defaults catch real violations against
 * a real-world dashboard without excessive false-positives.
 */
export const UI_SCANNER_DEFAULTS = Object.freeze({
  url: null,                          // must be set by caller or auto-detected
  maxDepth: 5,                        // BFS depth cap
  maxPages: 100,                      // absolute page-count cap
  allowProduction: false,             // forbidden unless true
  headless: true,                     // always headless in CI
  waitUntil: "networkidle",           // Playwright `page.goto()` waitUntil
  navigationTimeoutMs: 15000,         // per-page timeout
  captureScreenshots: true,
  runAccessibility: true,
  // axe-core severity levels that count as violations; moderate+ is
  // the default bar so trivial "best-practice" warnings don't flag
  // the run as failed.
  a11yMinSeverity: "moderate",        // "minor" | "moderate" | "serious" | "critical"
  // Max a11y violations (>= minSeverity) before the scanner's verdict
  // flips to "fail". 0 = strict. Larger values let the scanner warn
  // without blocking a slice.
  a11yFailThreshold: 0,
  // Same-origin is enforced by parsing config.url and comparing host;
  // this list is for extra-origin allow-list when a multi-origin SPA
  // is legitimate. Empty = strict same-origin-only.
  extraAllowedOrigins: [],
});

// ─── Utility: same-origin check ───────────────────────────────────────

/**
 * Returns true when `target` is same-origin as `base` or matches one
 * of the allow-listed extra origins.
 *
 * @param {string} target
 * @param {string} base
 * @param {string[]} extraAllowed
 */
export function isAllowedOrigin(target, base, extraAllowed = []) {
  try {
    const t = new URL(target);
    const b = new URL(base);
    if (t.origin === b.origin) return true;
    return extraAllowed.includes(t.origin);
  } catch {
    return false;
  }
}

/**
 * Production-URL heuristic — any host that isn't localhost, 127.*,
 * a private IP block, or `*.local`. Errs on the side of calling
 * things "production" so operators must explicitly opt-in via
 * `allowProduction: true` for real environments.
 */
export function looksLikeProduction(url) {
  try {
    const u = new URL(url);
    const h = u.hostname.toLowerCase();
    if (h === "localhost") return false;
    if (h === "127.0.0.1") return false;
    if (h.endsWith(".local")) return false;
    if (/^10\./.test(h)) return false;
    if (/^192\.168\./.test(h)) return false;
    if (/^172\.(1[6-9]|2\d|3[01])\./.test(h)) return false;
    return true;
  } catch {
    return true; // unparseable → treat as prod
  }
}

// ─── Auto-detection for app URL ───────────────────────────────────────

/**
 * Resolve the app URL, in priority order:
 *   1. `config["ui-playwright"].url` (operator explicit)
 *   2. `env.PFORGE_TEMPERING_URL`
 *   3. Fallback: null → scanner reports skipped:"url-not-configured"
 *
 * The plan also lists `package.json` script parsing and
 * `.forge/env-config.json` lookup; those are deferred to a Slice 03.1
 * follow-up so the first cut has a tight, predictable contract.
 *
 * @param {object} config — loaded tempering config
 * @param {object} env — process.env-shaped map
 */
export function resolveAppUrl(config, env = process.env) {
  const fromConfig = config && config["ui-playwright"] && config["ui-playwright"].url;
  if (fromConfig) return String(fromConfig);
  if (env && env.PFORGE_TEMPERING_URL) return String(env.PFORGE_TEMPERING_URL);
  return null;
}

// ─── Main entry point ────────────────────────────────────────────────

function createUiSkippedFrame(base, now, reason) {
  return {
    ...base,
    skipped: true,
    reason,
    verdict: "skipped",
    pass: 0,
    fail: 0,
    durationMs: 0,
    completedAt: new Date(now()).toISOString(),
  };
}

async function loadUiDependencies(settings, importFn) {
  let playwright;
  try {
    playwright = await importFn("playwright");
  } catch {
    return { reason: "playwright-not-installed" };
  }
  if (!playwright || !playwright.chromium) {
    return { reason: "playwright-api-missing" };
  }

  let axeInjector = null;
  if (settings.runAccessibility) {
    try {
      const axeMod = await importFn("@axe-core/playwright");
      axeInjector = axeMod && (axeMod.AxeBuilder || axeMod.default);
    } catch { /* non-fatal */ }
  }

  return { playwright, axeInjector };
}

function createUiCrawlState(url) {
  return {
    visited: new Map(),
    queue: [{ url: normalizeUrl(url), depth: 0 }],
    a11yViolations: [],
    brokenLinks: [],
    pagesVisited: 0,
    budgetTripped: false,
  };
}

function shouldVisitQueuedPage(state, settings, now, hardDeadline) {
  if (now() >= hardDeadline) {
    state.budgetTripped = true;
    return false;
  }
  return state.pagesVisited < settings.maxPages;
}

function recordPageResult(state, currentUrl, pageResult) {
  state.visited.set(currentUrl, pageResult);
  if (!pageResult.ok) {
    state.brokenLinks.push({ url: currentUrl, status: pageResult.status, reason: pageResult.reason });
  }
  if (pageResult.a11yViolations) {
    for (const violation of pageResult.a11yViolations) {
      state.a11yViolations.push({ url: currentUrl, ...violation });
    }
  }
}

function enqueueAllowedLinks({ state, pageResult, depth, url, settings }) {
  if (!pageResult.links || depth >= settings.maxDepth) return;
  for (const link of pageResult.links) {
    if (!isAllowedOrigin(link, url, settings.extraAllowedOrigins)) continue;
    const normalized = normalizeUrl(link);
    if (!state.visited.has(normalized)) {
      state.queue.push({ url: normalized, depth: depth + 1 });
    }
  }
}

async function crawlUiPages({ playwright, context, url, settings, artifactDir, axeInjector, now, hardDeadline, state }) {
  while (state.queue.length > 0 && shouldVisitQueuedPage(state, settings, now, hardDeadline)) {
    const next = state.queue.shift();
    const currentUrl = next?.url;
    const depth = next?.depth ?? 0;
    if (!currentUrl || state.visited.has(currentUrl) || depth > settings.maxDepth) continue;

    state.pagesVisited += 1;
    const pageResult = await visitPage({
      browser: playwright,
      context,
      url: currentUrl,
      settings,
      artifactDir,
      axeInjector,
    });
    recordPageResult(state, currentUrl, pageResult);
    enqueueAllowedLinks({ state: state, pageResult: pageResult, depth: depth, url: url, settings: settings });
  }
  return state;
}

async function executeUiCrawl(playwright, crawlArgs) {
  let browser = null;
  const state = createUiCrawlState(crawlArgs.url);
  try {
    browser = await playwright.chromium.launch({ headless: crawlArgs.settings.headless !== false });
    const context = await browser.newContext();
    return { state: await crawlUiPages({ playwright: browser, context, state, ...crawlArgs }) };
  } catch (err) {
    return { error: err, state };
  } finally {
    try { if (browser) await browser.close(); } catch { /* ignore */ }
  }
}

function getScoringA11yViolations(a11yViolations, minSeverity) {
  const severityRank = { minor: 0, moderate: 1, serious: 2, critical: 3 };
  const minRank = severityRank[minSeverity] ?? 1;
  return a11yViolations.filter((violation) => (severityRank[violation.impact] ?? 0) >= minRank);
}

function determineUiVerdict({ budgetTripped, brokenLinks, scoringViolations, settings }) {
  if (budgetTripped) return "budget-exceeded";
  if (brokenLinks.length > 0) return "fail";
  if (scoringViolations.length > settings.a11yFailThreshold) return "fail";
  return "pass";
}

function writeUiReport(artifactDir, { startedAt, url, pagesVisited, brokenLinks, a11yViolations, settings, verdict }) {
  if (!artifactDir) return;
  try {
    writeFileSync(
      pathResolve(artifactDir, "report.json"),
      JSON.stringify({
        scanner: "ui-playwright",
        startedAt,
        url,
        pagesVisited,
        brokenLinks,
        a11yViolations,
        settings,
        verdict,
      }, null, 2) + "\n",
      "utf-8",
    );
  } catch { /* best-effort */ }
}

function writeUiScreenshotManifest({ artifactDir, settings, visited, projectDir, runId }) {
  if (!artifactDir || !settings.captureScreenshots) return;
  try {
    const manifestEntries = [];
    for (const [visitedUrl] of visited) {
      const urlHash = hashUrl(visitedUrl);
      const screenshotPath = pathResolve(artifactDir, `${urlHash}.png`);
      if (existsSync(screenshotPath)) {
        manifestEntries.push({ url: visitedUrl, urlHash, path: screenshotPath });
      }
    }
    writeScreenshotManifest(projectDir, manifestEntries, runId);
  } catch { /* best-effort */ }
}

function resolveUiSweepContext(ctx) {
  const {
    config = {},
    projectDir,
    runId,
    sliceRef = null,
    importFn = (spec) => import(spec),
    now = () => Date.now(),
    env = process.env,
  } = ctx || {};
  return { config, projectDir, runId, sliceRef, importFn, now, env };
}

function isUiSweepDisabled(config) {
  return !config || !config.scanners || config.scanners["ui-playwright"] === false;
}

function prepareUiArtifactDir(settings, projectDir, runId) {
  if (!settings.captureScreenshots) return null;
  const artifactDir = ensureScannerArtifactDir(projectDir, runId, "ui-playwright");
  if (artifactDir) seedArtifactsGitignore(projectDir);
  return artifactDir;
}

function buildUiErrorFrame(base, now, t0, crawl) {
  return {
    ...base,
    verdict: "error",
    error: crawl.error.message || String(crawl.error),
    pagesVisited: crawl.state?.pagesVisited || 0,
    brokenLinks: crawl.state?.brokenLinks || [],
    a11yViolationCount: crawl.state?.a11yViolations?.length || 0,
    durationMs: now() - t0,
    completedAt: new Date(now()).toISOString(),
  };
}

function buildUiSweepResult({ base, now, t0, url, settings, artifactDir, projectDir, runId, crawlState }) {
  const { visited, a11yViolations, brokenLinks, pagesVisited, budgetTripped } = crawlState;
  const scoringViolations = getScoringA11yViolations(a11yViolations, settings.a11yMinSeverity);
  const verdict = determineUiVerdict({ budgetTripped, brokenLinks, scoringViolations, settings });
  writeUiReport(artifactDir, {
    startedAt: base.startedAt,
    url,
    pagesVisited,
    brokenLinks,
    a11yViolations,
    settings,
    verdict,
  });
  writeUiScreenshotManifest({ artifactDir: artifactDir, settings: settings, visited: visited, projectDir: projectDir, runId: runId });

  return {
    ...base,
    verdict,
    pagesVisited,
    pass: pagesVisited - brokenLinks.length,
    fail: brokenLinks.length + scoringViolations.length,
    skipped: 0,
    brokenLinkCount: brokenLinks.length,
    a11yViolationCount: a11yViolations.length,
    a11yScoringCount: scoringViolations.length,
    budgetTripped,
    durationMs: now() - t0,
    artifactDir,
    completedAt: new Date(now()).toISOString(),
  };
}

/**
 * Run the UI sweep scanner. Contract mirrors runScannerUnit /
 * runScannerIntegration from runner.mjs:
 *
 * @param {object} ctx
 * @param {object} ctx.config
 * @param {string} ctx.projectDir
 * @param {string} ctx.runId
 * @param {{plan:string, slice:string}|null} [ctx.sliceRef]
 * @param {Function} [ctx.importFn] — injectable dynamic import
 * @param {Function} [ctx.now]
 * @returns {Promise<object>} scanner result record
 */
export async function runUiSweep(ctx) {
  const uiCtx = resolveUiSweepContext(ctx);
  const t0 = uiCtx.now();
  const base = {
    scanner: "ui-playwright",
    sliceRef: uiCtx.sliceRef,
    startedAt: new Date(t0).toISOString(),
  };

  if (isUiSweepDisabled(uiCtx.config)) {
    return createUiSkippedFrame(base, uiCtx.now, "scanner-disabled");
  }

  const settings = { ...UI_SCANNER_DEFAULTS, ...(uiCtx.config["ui-playwright"] || {}) };
  const url = resolveAppUrl(uiCtx.config, uiCtx.env);
  if (!url) return createUiSkippedFrame(base, uiCtx.now, "url-not-configured");
  if (looksLikeProduction(url) && !settings.allowProduction) {
    return createUiSkippedFrame(base, uiCtx.now, "production-url-without-opt-in");
  }

  const deps = await loadUiDependencies(settings, uiCtx.importFn);
  if (deps.reason) return createUiSkippedFrame(base, uiCtx.now, deps.reason);

  const artifactDir = prepareUiArtifactDir(settings, uiCtx.projectDir, uiCtx.runId);
  const hardDeadline = t0 + ((uiCtx.config.runtimeBudgets && uiCtx.config.runtimeBudgets.uiMaxMs) || 600000);
  const crawl = await executeUiCrawl(deps.playwright, {
    url,
    settings,
    artifactDir,
    axeInjector: deps.axeInjector,
    now: uiCtx.now,
    hardDeadline,
  });

  if (crawl.error) return buildUiErrorFrame(base, uiCtx.now, t0, crawl);
  return buildUiSweepResult({
    base,
    now: uiCtx.now,
    t0,
    url,
    settings,
    artifactDir,
    projectDir: uiCtx.projectDir,
    runId: uiCtx.runId,
    crawlState: crawl.state,
  });
}

// ─── Per-page work ────────────────────────────────────────────────────

/**
 * Visit a single URL: navigate, capture screenshot, collect console
 * errors, capture same-origin links, optionally run axe-core. Never
 * throws — returns a page-result frame with `ok: false` on failure so
 * the crawler can continue.
 */
async function visitPage({ browser, context, url, settings, artifactDir, axeInjector }) {
  const page = await context.newPage();
  const consoleErrors = [];
  const failedRequests = [];
  page.on("console", (msg) => {
    if (msg.type && msg.type() === "error") consoleErrors.push(msg.text ? msg.text() : String(msg));
  });
  page.on("requestfailed", (req) => {
    failedRequests.push({ url: req.url ? req.url() : "", failure: req.failure ? req.failure() : null });
  });

  let status = 0;
  let ok = false;
  let reason = null;
  let links = [];
  let a11yViolations = null;

  try {
    const response = await page.goto(url, {
      waitUntil: settings.waitUntil || "networkidle",
      timeout: settings.navigationTimeoutMs || 15000,
    });
    status = response && response.status ? response.status() : 0;
    ok = status >= 200 && status < 400;
    if (!ok) reason = `http-${status}`;

    // Link extraction — same-origin filter is applied upstream.
    links = await page.$$eval("a[href]", (anchors) =>
      anchors
        .map((a) => a.href)
        .filter((h) => typeof h === "string" && /^https?:/.test(h)),
    ).catch(() => []);

    // Screenshot
    if (artifactDir && settings.captureScreenshots) {
      try {
        const out = pathResolve(artifactDir, `${hashUrl(url)}.png`);
        await page.screenshot({ path: out, fullPage: false });
      } catch { /* ignore */ }
    }

    // Accessibility pass
    if (axeInjector && settings.runAccessibility) {
      try {
        const builder = new axeInjector({ page });
        const results = await builder.analyze();
        a11yViolations = Array.isArray(results?.violations)
          ? results.violations.map((v) => ({
              id: v.id,
              impact: v.impact || "minor",
              help: v.help,
              nodes: Array.isArray(v.nodes) ? v.nodes.length : 0,
            }))
          : [];
      } catch { /* a11y per-page failure is non-fatal */ }
    }
  } catch (err) {
    ok = false;
    reason = err && err.message ? err.message : "navigation-failed";
  } finally {
    try { await page.close(); } catch { /* ignore */ }
  }

  return { status, ok, reason, links, consoleErrors, failedRequests, a11yViolations };
}

/**
 * Write (or overwrite) the screenshot manifest at
 * `.forge/tempering/screenshot-manifest.json`. Each entry has
 * `{ url, urlHash, path }`. Passing an empty array clears a stale manifest.
 *
 * @param {string} projectDir
 * @param {Array<{url:string, urlHash:string, path:string}>} entries
 * @param {string} _runId — reserved for future per-run manifests
 */
export function writeScreenshotManifest(projectDir, entries, _runId) {
  const manifestDir = pathResolve(projectDir, ".forge", "tempering");
  mkdirSync(manifestDir, { recursive: true });
  writeFileSync(
    pathResolve(manifestDir, "screenshot-manifest.json"),
    JSON.stringify(entries),
    "utf-8",
  );
}

/**
 * Normalize a URL for deduplication — strips fragment + trailing
 * slash on the path. Query strings are preserved because they often
 * drive real routes (e.g. `/search?q=x`).
 */
export function normalizeUrl(raw) {
  try {
    const u = new URL(raw);
    u.hash = "";
    if (u.pathname.length > 1 && u.pathname.endsWith("/")) {
      u.pathname = u.pathname.slice(0, -1);
    }
    return u.toString();
  } catch {
    return String(raw || "");
  }
}

/**
 * Visual-diff scanner (TEMPER-04 Slice 04.1).
 *
 * 3-band pixel diff + single-model LLM analyzer for the investigate band.
 * Follows the same result contract as contract.mjs:
 *   { scanner, startedAt, completedAt, verdict, pass, fail, skipped,
 *     durationMs, regressions?, reason?, details? }
 *
 * @module tempering/scanners/visual-diff
 */
import { existsSync, mkdirSync, readFileSync, statSync, writeFileSync } from "node:fs";
import { resolve } from "node:path";
import {
  getScreenshotManifest,
  getBaseline,
  diffImages,
  hashUrl,
} from "../baselines.mjs";
import { ensureScannerArtifactDir, seedArtifactsGitignore } from "../artifacts.mjs";
// Phase-27 (v2.60.0): Pricing canonical source lives in cost-service. The
// local estimateCost() is now a thin adapter over priceSlice.
import { priceSlice } from "../../cost-service.mjs";
// Phase-28.5: secrets.json fallback for API key detection
import { loadSecretFromForge } from "../../secrets.mjs";

// ─── Default visual analyzer config ──────────────────────────────────

const VISUAL_ANALYZER_DEFAULTS = {
  enabled: true,
  ignorableDiff: 0.001,     // 0.1%
  failureDiff: 0.02,        // 2.0%
  maxCostUsd: 2.0,
  mode: "quorum",           // "quorum" | "single"; default "quorum" when models.length >= 2
  models: ["claude-opus-4.7", "gpt-5.3-codex", "grok-4.20"],
  agreementThreshold: 2,    // N-of-M majority
  analyzerTimeoutMs: 60_000,
  maxImageWidth: 1920,
};

// ─── Hub event helper ─────────────────────────────────────────────────

function emit(hub, type, data) {
  if (!hub || typeof hub.broadcast !== "function") return;
  try {
    hub.broadcast({ type, data, timestamp: new Date().toISOString() });
  } catch { /* best-effort */ }
}

// ─── Scanner entry point ──────────────────────────────────────────────

/**
 * Run the visual-diff scanner.
 *
 * @param {object} ctx
 * @param {object} ctx.config         — loaded tempering config
 * @param {string} ctx.projectDir     — project root
 * @param {string} ctx.runId          — current run ID
 * @param {{plan:string,slice:string}|null} [ctx.sliceRef]
 * @param {Function} [ctx.now]
 * @param {object}   [ctx.env]        — process.env-shaped map
 * @param {Function} [ctx.spawnWorker] — DI for LLM analyzer
 * @param {object}   [ctx.hub]        — hub for event broadcasting
 * @returns {Promise<object>} scanner result record
 */
function createVisualDiffSkippedFrame(base, now, reason) {
  return {
    ...base,
    verdict: "skipped",
    pass: 0,
    fail: 0,
    skipped: 1,
    violationCount: 0,
    regressions: [],
    reason,
    durationMs: 0,
    completedAt: new Date(now()).toISOString(),
  };
}

function createVisualDiffState() {
  return {
    regressions: [],
    passCount: 0,
    failCount: 0,
    skippedCount: 0,
    cumulativeCostUsd: 0,
    budgetExceeded: false,
  };
}

function resolveVisualArtifactDir(projectDir, runId) {
  const artifactDir = ensureScannerArtifactDir(projectDir, runId, "visual-diff");
  if (artifactDir) seedArtifactsGitignore(projectDir);
  return artifactDir;
}

function getVisualArtifactPaths(artifactDir, urlHash) {
  return {
    baseline: artifactDir ? resolve(artifactDir, `${urlHash}-baseline.png`) : null,
    current: artifactDir ? resolve(artifactDir, `${urlHash}-current.png`) : null,
    diff: artifactDir ? resolve(artifactDir, `${urlHash}-diff.png`) : null,
  };
}

function findCurrentRunScreenshotPath(projectDir, runId, urlHash) {
  const artifactsRunDir = resolve(projectDir, ".forge", "tempering", "artifacts", runId);
  const candidates = [
    resolve(artifactsRunDir, "ui-playwright", `${urlHash}.png`),
    resolve(artifactsRunDir, "visual-diff", `${urlHash}.png`),
  ];
  return candidates.find((candidate) => existsSync(candidate)) || null;
}

function readPreferredCurrentScreenshot(entry, currentRunPath) {
  if (!currentRunPath) {
    return entry.path && existsSync(entry.path) ? readFileSync(entry.path) : null;
  }
  const manifestPath = entry.path && existsSync(entry.path) ? entry.path : null;
  if (!manifestPath) {
    return readFileSync(currentRunPath);
  }
  return readFileSync(selectNewerScreenshotPath(manifestPath, currentRunPath));
}

function selectNewerScreenshotPath(manifestPath, currentRunPath) {
  let manifestMtime = 0;
  let runMtime = 0;
  try { manifestMtime = statSync(manifestPath).mtimeMs; } catch { /* fallback */ }
  try { runMtime = statSync(currentRunPath).mtimeMs; } catch { /* fallback */ }
  return runMtime >= manifestMtime ? currentRunPath : manifestPath;
}

function loadCurrentScreenshot(entry, projectDir, runId, urlHash) {
  try {
    const currentRunPath = findCurrentRunScreenshotPath(projectDir, runId, urlHash);
    return readPreferredCurrentScreenshot(entry, currentRunPath);
  } catch {
    return null;
  }
}

function writeVisualBuffer(path, buffer) {
  if (!path || !buffer) return;
  try {
    writeFileSync(path, buffer);
  } catch { /* best-effort */ }
}

function writeVisualArtifacts(paths, baselineBuf, currentBuf, diffBuffer) {
  writeVisualBuffer(paths.baseline, baselineBuf);
  writeVisualBuffer(paths.current, currentBuf);
  writeVisualBuffer(paths.diff, diffBuffer);
}

function pushVisualRegression(state, regression, kind = "skipped") {
  state.regressions.push(regression);
  if (kind === "pass") state.passCount++;
  else if (kind === "fail") state.failCount++;
  else if (kind === "skipped") state.skippedCount++;
}

function handleMissingVisualBaseline(state, entry, urlHash) {
  pushVisualRegression(state, {
    url: entry.url,
    urlHash,
    band: "skipped",
    reason: "needs-baseline",
  });
}

function handleMissingCurrentScreenshot(state, entry, urlHash) {
  pushVisualRegression(state, {
    url: entry.url,
    urlHash,
    band: "skipped",
    reason: "no-current-screenshot",
  });
}

function handleVisualDiffError(state, entry, urlHash, err) {
  pushVisualRegression(state, {
    url: entry.url,
    urlHash,
    band: "error",
    reason: `diff-error: ${err.message}`,
  });
}

function emitVisualAutoFail({ hub, entry, urlHash, diffPercent, sliceRef, paths }) {
  emit(hub, "tempering-visual-regression-detected", {
    url: entry.url,
    urlHash,
    diffPercent,
    band: "fail",
    verdict: "regression",
    sliceRef,
    artifacts: paths,
  });
}

function handleVisualAutoFail(state, { entry, urlHash, diffPercent, paths, hub, sliceRef }) {
  pushVisualRegression(state, {
    url: entry.url,
    urlHash,
    diffPercent,
    band: "fail",
    diffPath: paths.diff,
  }, "fail");
  emitVisualAutoFail({ hub, entry, urlHash, diffPercent, sliceRef, paths });
}

function buildAnalyzerImages(baselineBuf, currentBuf, diffBuffer) {
  const images = [
    { type: "baseline", data: baselineBuf.toString("base64") },
    { type: "current", data: currentBuf.toString("base64") },
  ];
  if (diffBuffer) images.push({ type: "diff", data: diffBuffer.toString("base64") });
  return images;
}

function tallyQuorumVotes(votes, threshold) {
  const valid = votes.filter((vote) => vote.ok);
  const yes = valid.filter((vote) => vote.regression).length;
  const no = valid.length - yes;
  return { valid, yes, no, threshold, agreementMet: yes >= threshold || no >= threshold };
}

function summarizeQuorumDecision(votes, threshold, models) {
  const tally = tallyQuorumVotes(votes, threshold);
  const llmVerdict = !tally.agreementMet ? "inconclusive" : tally.yes >= threshold ? "regression" : "acceptable";
  return {
    llmVerdict,
    severity: llmVerdict === "regression" ? resolveHighestSeverity(tally.valid.filter((vote) => vote.regression)) : null,
    explanation: buildQuorumExplanation(llmVerdict, tally),
    quorumData: {
      models,
      votes: votes.map((vote) => ({
        model: vote.model,
        regression: vote.regression ?? null,
        severity: vote.severity ?? null,
        explanation: vote.explanation ?? null,
        ok: !!vote.ok,
      })),
      agreement: `${Math.max(tally.yes, tally.no)}-of-${tally.valid.length}`,
      threshold,
    },
  };
}

function buildQuorumExplanation(llmVerdict, tally) {
  if (llmVerdict === "regression") {
    return tally.valid
      .filter((vote) => vote.regression)
      .map((vote) => `${vote.model}: ${vote.explanation || "regression"}`)
      .join("; ");
  }
  if (llmVerdict === "acceptable") {
    return tally.valid
      .filter((vote) => !vote.regression)
      .map((vote) => `${vote.model}: ${vote.explanation || "acceptable"}`)
      .join("; ");
  }
  return `Insufficient agreement: ${tally.yes} regression, ${tally.no} acceptable out of ${tally.valid.length} valid legs (threshold: ${tally.threshold})`;
}

async function runQuorumLlmAnalysis({ entry, sliceRef, diffPercent, analyzerConfig, spawnWorker, baselineBuf, currentBuf, diffBuffer, state }) {
  const models = analyzerConfig.models || ["claude-opus-4.7"];
  const threshold = analyzerConfig.agreementThreshold || 2;
  const prompt = buildAnalyzerPrompt(entry.url, sliceRef, diffPercent);
  const images = buildAnalyzerImages(baselineBuf, currentBuf, diffBuffer);
  const legs = await Promise.allSettled(
    models.map((model) => runLegWithBudget({
      model,
      prompt,
      images,
      timeoutMs: analyzerConfig.analyzerTimeoutMs,
      spawnWorker,
      estimateCost,
      budget: { cap: analyzerConfig.maxCostUsd, used: () => state.cumulativeCostUsd },
    })),
  );
  const votes = legs.map((leg, index) => normalizeQuorumVote(leg, models[index], analyzerConfig, state));
  return summarizeQuorumDecision(votes, threshold, models);
}

function normalizeQuorumVote(leg, model, analyzerConfig, state) {
  if (leg.status === "rejected") {
    return { model, ok: false, error: leg.reason?.message || String(leg.reason) };
  }
  const vote = leg.value;
  if (vote.costUsd) {
    state.cumulativeCostUsd += vote.costUsd;
    if (state.cumulativeCostUsd >= analyzerConfig.maxCostUsd) state.budgetExceeded = true;
  }
  return vote;
}

async function runSingleModelLlmAnalysis({ entry, sliceRef, diffPercent, analyzerConfig, spawnWorker, baselineBuf, currentBuf, diffBuffer, state }) {
  const model = (analyzerConfig.models || ["claude-opus-4.7"])[0] || "claude-opus-4.7";
  try {
    const workerResult = await Promise.race([
      spawnWorker({
        model,
        prompt: buildAnalyzerPrompt(entry.url, sliceRef, diffPercent),
        images: buildAnalyzerImages(baselineBuf, currentBuf, diffBuffer),
        responseFormat: "json",
      }),
      new Promise((_, reject) => setTimeout(() => reject(new Error("analyzer-timeout")), analyzerConfig.analyzerTimeoutMs)),
    ]);
    return parseSingleModelAnalysisResult(workerResult, model, analyzerConfig, state);
  } catch (err) {
    return { llmVerdict: "inconclusive", severity: null, explanation: err.message || String(err), quorumData: null };
  }
}

function parseSingleModelAnalysisResult(workerResult, model, analyzerConfig, state) {
  if (!workerResult || typeof workerResult !== "object") {
    return { llmVerdict: "inconclusive", severity: null, explanation: "empty worker response", quorumData: null };
  }
  const parsed = typeof workerResult.text === "string" ? tryParseJson(workerResult.text) : workerResult;
  if (workerResult.usage) {
    const tokens = (workerResult.usage.inputTokens || 0) + (workerResult.usage.outputTokens || 0);
    state.cumulativeCostUsd += estimateCost(tokens, model);
    if (state.cumulativeCostUsd >= analyzerConfig.maxCostUsd) state.budgetExceeded = true;
  }
  if (!parsed || typeof parsed.regression !== "boolean") {
    return { llmVerdict: "inconclusive", severity: null, explanation: "LLM response did not match expected schema", quorumData: null };
  }
  return {
    llmVerdict: parsed.regression ? "regression" : "acceptable",
    severity: parsed.severity || null,
    explanation: parsed.explanation || null,
    quorumData: null,
  };
}

function resolveMissingWorkerAnalysis(env, projectDir) {
  const hasKey = env?.ANTHROPIC_API_KEY || env?.OPENAI_API_KEY || env?.XAI_API_KEY
    || loadSecretFromForge("ANTHROPIC_API_KEY", projectDir)
    || loadSecretFromForge("OPENAI_API_KEY", projectDir)
    || loadSecretFromForge("XAI_API_KEY", projectDir);
  return {
    llmVerdict: "inconclusive",
    severity: null,
    explanation: hasKey ? "no spawnWorker provided" : "no API key configured",
    quorumData: null,
  };
}

async function runLlmAnalysis({ entry, sliceRef, diffPercent, analyzerConfig, spawnWorker, baselineBuf, currentBuf, diffBuffer, env, projectDir, state }) {
  const models = analyzerConfig.models || ["claude-opus-4.7"];
  const useQuorum = analyzerConfig.mode !== "single" && models.length >= 2;
  if (spawnWorker && useQuorum) {
    return runQuorumLlmAnalysis({ entry, sliceRef, diffPercent, analyzerConfig, spawnWorker, baselineBuf, currentBuf, diffBuffer, state });
  }
  if (spawnWorker) {
    return runSingleModelLlmAnalysis({ entry, sliceRef, diffPercent, analyzerConfig, spawnWorker, baselineBuf, currentBuf, diffBuffer, state });
  }
  return resolveMissingWorkerAnalysis(env, projectDir);
}

function buildVisualEventPayload({ entry, urlHash, diffPercent, llmVerdict, severity, explanation, sliceRef, quorumData, paths }) {
  return {
    url: entry.url,
    urlHash,
    diffPercent,
    band: "investigate",
    verdict: llmVerdict,
    severity,
    explanation,
    sliceRef,
    ...(quorumData ? { quorum: quorumData } : {}),
    artifacts: paths,
  };
}

async function maybeQueueVisualReview({ config, projectDir, entry, urlHash, diffPercent, llmVerdict, hub, captureMemory }) {
  const vdConfig = config?.visualDiff || {};
  if (vdConfig.autoQueueReview !== true) return;
  try {
    const { maybeAddVisualBaselineReview } = await import("../../orchestrator.mjs");
    maybeAddVisualBaselineReview(projectDir, {
      title: `Visual regression on ${entry.url} — review baseline update`,
      severity: "medium",
      context: { url: entry.url, diffPercent, quorumVerdict: llmVerdict },
      correlationId: `visual-${urlHash}`,
    }, hub, captureMemory);
  } catch { /* review hook is advisory */ }
}

async function maybeQueueInconclusiveReview({ projectDir, entry, urlHash, diffPercent, quorumData, explanation, hub, captureMemory }) {
  try {
    const { maybeAddTemperingReview } = await import("../../orchestrator.mjs");
    maybeAddTemperingReview(projectDir, {
      title: `Visual-diff quorum inconclusive for ${entry.url}`,
      severity: "medium",
      context: { url: entry.url, diffPercent, quorum: quorumData, explanation },
      correlationId: `quorum-${urlHash}`,
    }, hub, captureMemory);
  } catch { /* review hook is advisory */ }
}

function captureVisualAnalysis({ captureMemory, llmVerdict, entry, diffPercent, quorumData, projectDir }) {
  if (!captureMemory) return;
  try {
    captureMemory(
      `Visual quorum ${llmVerdict}: ${entry.url} (${(diffPercent * 100).toFixed(2)}% diff). ` +
      (quorumData
        ? quorumData.votes.filter((vote) => vote.ok).map((vote) => `${vote.model}:${vote.regression ? "reg" : "ok"}`).join(", ")
        : `single-model: ${llmVerdict}`),
      llmVerdict === "inconclusive" ? "gotcha" : "decision",
      `forge_tempering_scan/visual-diff/${llmVerdict}`,
      projectDir,
    );
  } catch { /* best-effort */ }
}

async function handleInvestigateBand({ state, entry, urlHash, diffPercent, analyzerConfig, spawnWorker, baselineBuf, currentBuf, diffBuffer, paths, env, projectDir, sliceRef, hub, captureMemory, config }) {
  if (state.budgetExceeded) {
    pushVisualRegression(state, {
      url: entry.url,
      urlHash,
      diffPercent,
      band: "investigate",
      reason: "budget-exceeded",
    });
    return;
  }

  const analysis = await runLlmAnalysis({
    entry,
    sliceRef,
    diffPercent,
    analyzerConfig,
    spawnWorker,
    baselineBuf,
    currentBuf,
    diffBuffer,
    env,
    projectDir,
    state,
  });
  const regression = {
    url: entry.url,
    urlHash,
    diffPercent,
    band: "investigate",
    llmVerdict: analysis.llmVerdict,
    severity: analysis.severity,
    explanation: analysis.explanation,
    diffPath: paths.diff,
    ...(analysis.quorumData ? { quorum: analysis.quorumData } : {}),
  };
  state.regressions.push(regression);
  const eventPayload = buildVisualEventPayload({
    entry,
    urlHash,
    diffPercent,
    llmVerdict: analysis.llmVerdict,
    severity: analysis.severity,
    explanation: analysis.explanation,
    sliceRef,
    quorumData: analysis.quorumData,
    paths,
  });
  emit(hub, "tempering-visual-regression-detected", eventPayload);

  if (analysis.llmVerdict === "regression") {
    state.failCount++;
    await maybeQueueVisualReview({ config: config, projectDir: projectDir, entry: entry, urlHash: urlHash, diffPercent: diffPercent, ...{ llmVerdict: analysis.llmVerdict, hub, captureMemory } });
  } else if (analysis.llmVerdict === "acceptable") {
    state.passCount++;
  } else {
    state.skippedCount++;
    await maybeQueueInconclusiveReview({ projectDir: projectDir, entry: entry, urlHash: urlHash, diffPercent: diffPercent, quorumData: analysis.quorumData, ...{ explanation: analysis.explanation, hub, captureMemory } });
  }

  captureVisualAnalysis({ captureMemory: captureMemory, llmVerdict: analysis.llmVerdict, entry: entry, diffPercent: diffPercent, quorumData: analysis.quorumData, projectDir: projectDir });
}

async function processVisualDiffEntry({ entry, projectDir, runId, artifactDir, analyzerConfig, state, spawnWorker, hub, captureMemory, config, env, sliceRef }) {
  const urlHash = entry.urlHash || hashUrl(entry.url);
  const baselineBuf = getBaseline(urlHash, projectDir);
  if (!baselineBuf) {
    handleMissingVisualBaseline(state, entry, urlHash);
    return;
  }

  const currentBuf = loadCurrentScreenshot(entry, projectDir, runId, urlHash);
  if (!currentBuf) {
    handleMissingCurrentScreenshot(state, entry, urlHash);
    return;
  }

  let diffResult;
  try {
    diffResult = diffImages(baselineBuf, currentBuf);
  } catch (err) {
    handleVisualDiffError(state, entry, urlHash, err);
    return;
  }

  const paths = getVisualArtifactPaths(artifactDir, urlHash);
  writeVisualBuffer(paths.diff, diffResult.diffBuffer);

  if (diffResult.diffPercent < analyzerConfig.ignorableDiff) {
    state.passCount++;
    return;
  }

  if (diffResult.diffPercent >= analyzerConfig.failureDiff) {
    writeVisualArtifacts(paths, baselineBuf, currentBuf, diffResult.diffBuffer);
    handleVisualAutoFail(state, {
      entry,
      urlHash,
      diffPercent: diffResult.diffPercent,
      paths,
      hub,
      sliceRef,
    });
    return;
  }

  writeVisualArtifacts(paths, baselineBuf, currentBuf, null);
  await handleInvestigateBand({
    state,
    entry,
    urlHash,
    diffPercent: diffResult.diffPercent,
    analyzerConfig,
    spawnWorker,
    baselineBuf,
    currentBuf,
    diffBuffer: diffResult.diffBuffer,
    paths,
    env,
    projectDir,
    sliceRef,
    hub,
    captureMemory,
    config,
  });
}

function resolveVisualOverallVerdict(state) {
  if (state.budgetExceeded && state.failCount === 0) return "budget-exceeded";
  if (state.failCount > 0) return "fail";
  return "pass";
}

function writeVisualDiffReport(artifactDir, startedAt, verdict, state) {
  if (!artifactDir) return;
  try {
    writeFileSync(
      resolve(artifactDir, "report.json"),
      JSON.stringify({
        scanner: "visual-diff",
        startedAt,
        verdict,
        pass: state.passCount,
        fail: state.failCount,
        skipped: state.skippedCount,
        regressions: state.regressions,
        analyzerCostUsd: state.cumulativeCostUsd,
      }, null, 2) + "\n",
      "utf-8",
    );
  } catch { /* best-effort */ }
}

export async function runVisualDiffScan(ctx) {
  const {
    config = {},
    projectDir,
    runId,
    sliceRef = null,
    now = () => Date.now(),
    env = process.env,
    spawnWorker = null,
    hub = null,
    captureMemory = null,
  } = ctx || {};

  const t0 = now();
  const base = {
    scanner: "visual-diff",
    sliceRef,
    startedAt: new Date(t0).toISOString(),
  };

  const analyzerConfig = {
    ...VISUAL_ANALYZER_DEFAULTS,
    ...(config.visualAnalyzer || {}),
  };
  if (analyzerConfig.enabled === false) {
    return createVisualDiffSkippedFrame(base, now, "scanner-disabled");
  }

  const manifest = getScreenshotManifest(projectDir);
  if (!manifest || manifest.length === 0) {
    return createVisualDiffSkippedFrame(base, now, "no-screenshot-manifest");
  }

  const artifactDir = resolveVisualArtifactDir(projectDir, runId);
  const state = createVisualDiffState();
  for (const entry of manifest) {
    await processVisualDiffEntry({
      entry,
      projectDir,
      runId,
      artifactDir,
      analyzerConfig,
      state,
      spawnWorker,
      hub,
      captureMemory,
      config,
      env,
      sliceRef,
    });
  }

  const verdict = resolveVisualOverallVerdict(state);
  const durationMs = now() - t0;
  writeVisualDiffReport(artifactDir, base.startedAt, verdict, state);

  return {
    ...base,
    verdict,
    pass: state.passCount,
    fail: state.failCount,
    skipped: state.skippedCount,
    violationCount: state.failCount,
    regressions: state.regressions,
    artifactDir,
    durationMs,
    completedAt: new Date(now()).toISOString(),
    ...(state.budgetExceeded ? { details: { budgetExceeded: true, costUsd: state.cumulativeCostUsd } } : {}),
  };
}

// ─── Helpers ──────────────────────────────────────────────────────────

function buildAnalyzerPrompt(url, sliceRef, diffPercent) {
  const sliceContext = sliceRef ? `\nSlice: ${sliceRef.plan} / ${sliceRef.slice}` : "";
  return [
    `You are a visual regression analyzer for the Plan Forge tempering system.`,
    `Compare the baseline screenshot, current screenshot, and diff overlay for: ${url}${sliceContext}`,
    `The pixel diff is ${(diffPercent * 100).toFixed(4)}% — within the investigate band.`,
    `Determine whether this represents a true visual regression or an acceptable change.`,
    `\nRespond with ONLY valid JSON:`,
    `{ "regression": true/false, "severity": "low"|"medium"|"high"|"critical", "explanation": "brief reason" }`,
  ].join("\n");
}

function tryParseJson(text) {
  try { return JSON.parse(text); } catch { return null; }
}

function estimateCost(tokens, model) {
  const half = Math.round(tokens / 2);
  return priceSlice(
    { tokens_in: half, tokens_out: tokens - half, model },
    "api-visual-diff",
  ).cost_usd;
}

// ─── Quorum helpers ──────────────────────────────────────────────────

const SEVERITY_ORDER = ["critical", "high", "medium", "low"];

function resolveHighestSeverity(votes) {
  let best = null;
  let bestIdx = SEVERITY_ORDER.length;
  for (const v of votes) {
    if (!v.severity) continue;
    const idx = SEVERITY_ORDER.indexOf(v.severity);
    if (idx >= 0 && idx < bestIdx) {
      bestIdx = idx;
      best = v.severity;
    }
  }
  return best;
}

async function runLegWithBudget({ model, prompt, images, timeoutMs, spawnWorker, estimateCost: estCost, budget }) {
  // Skip if budget already exhausted
  if (budget.used() >= budget.cap) {
    return { model, ok: false, error: "budget-exceeded" };
  }

  try {
    const workerResult = await Promise.race([
      spawnWorker({ model, prompt, images, responseFormat: "json" }),
      new Promise((_, reject) =>
        setTimeout(() => reject(new Error("analyzer-timeout")), timeoutMs),
      ),
    ]);

    if (!workerResult || typeof workerResult !== "object") {
      return { model, ok: false, error: "empty worker response" };
    }

    const parsed = typeof workerResult.text === "string"
      ? tryParseJson(workerResult.text)
      : workerResult;

    let costUsd = 0;
    if (workerResult.usage) {
      const tokens = (workerResult.usage.inputTokens || 0) + (workerResult.usage.outputTokens || 0);
      costUsd = estCost(tokens, model);
    }

    if (parsed && typeof parsed.regression === "boolean") {
      return {
        model,
        ok: true,
        regression: parsed.regression,
        severity: parsed.severity || null,
        explanation: parsed.explanation || null,
        costUsd,
      };
    }
    return { model, ok: false, error: "malformed-response", costUsd };
  } catch (err) {
    return { model, ok: false, error: err.message || String(err) };
  }
}

/**
 * Plan Forge — TEMPER-05 Slice 05.2: Mutation scheduling decision helper.
 *
 * Pure functions — no I/O, no shared state. Determines whether the
 * mutation scanner should run based on trigger type, critical paths,
 * and explicit overrides.
 *
 * @module tempering/scheduling
 */

// ─── Critical path matching ──────────────────────────────────────────

/**
 * Check whether any touched file matches a critical path glob pattern.
 * Uses simple glob matching (supports `*` and `**` wildcards).
 *
 * @param {string[]} touchedFiles - Files changed in the current slice
 * @param {string[]} criticalPaths - Glob patterns from config
 * @returns {boolean}
 */
export function isCriticalPathTouched(touchedFiles = [], criticalPaths = []) {
  if (!Array.isArray(touchedFiles) || touchedFiles.length === 0) return false;
  if (!Array.isArray(criticalPaths) || criticalPaths.length === 0) return false;

  for (const pattern of criticalPaths) {
    if (typeof pattern !== "string" || !pattern) continue;
    try {
      const re = globToRegex(pattern);
      for (const file of touchedFiles) {
        if (typeof file === "string" && re.test(file)) return true;
      }
    } catch {
      // Malformed glob — treat as non-match (logged by caller if needed)
      continue;
    }
  }
  return false;
}

/**
 * Convert a simple glob pattern to a RegExp.
 * Supports `*` (single segment) and `**` (multi-segment).
 *
 * @param {string} glob
 * @returns {RegExp}
 */
function globToRegex(glob) {
  let re = glob
    .replace(/[.+^${}()|[\]\\]/g, "\\$&")  // escape regex chars (except * and ?)
    .replace(/\*\*/g, "<<GLOBSTAR>>")
    .replace(/\*/g, "[^/]*")
    .replace(/<<GLOBSTAR>>/g, ".*")
    .replace(/\?/g, "[^/]");
  return new RegExp(`^${re}$`);
}

// ─── Nightly window ──────────────────────────────────────────────────

/**
 * Check if the current context is within a nightly window.
 *
 * @param {string} trigger - "post-slice" | "nightly" | "manual"
 * @param {object} config - Tempering config
 * @returns {boolean}
 */
export function isNightlyWindow(trigger, config) {
  if (trigger === "nightly") return true;
  // Future: time-based fallback if config.scanners.mutation.nightlyWindow set
  return false;
}

// ─── Main scheduling decision ────────────────────────────────────────

/**
 * Decide whether the mutation scanner should run.
 *
 * @param {object} ctx
 * @param {object} ctx.config - Tempering config
 * @param {string} ctx.trigger - "post-slice" | "nightly" | "manual"
 * @param {object} [ctx.sliceRef] - Current slice reference
 * @param {string[]} [ctx.touchedFiles] - Files changed in this slice
 * @param {Function} [ctx.now] - Clock function
 * @returns {{ run: boolean, reason: string }}
 */
export function shouldRunMutation(ctx) {
  const { config = {}, trigger = "manual", touchedFiles = [] } = ctx || {};

  const mutationConfig = typeof config.scanners?.mutation === "object"
    ? config.scanners.mutation
    : {};

  // Explicit full-mutation override
  if (mutationConfig.fullMutation) {
    return { run: true, reason: "explicit-full" };
  }

  // Manual trigger always runs
  if (trigger === "manual") {
    return { run: true, reason: "manual-trigger" };
  }

  // Nightly trigger always runs
  if (trigger === "nightly") {
    return { run: true, reason: "nightly-trigger" };
  }

  // Post-slice: only run if critical path touched
  if (trigger === "post-slice") {
    const criticalPaths = Array.isArray(mutationConfig.criticalPaths)
      ? mutationConfig.criticalPaths
      : [];
    if (isCriticalPathTouched(touchedFiles, criticalPaths)) {
      return { run: true, reason: "critical-path-touched" };
    }
    return { run: false, reason: "non-critical-post-slice" };
  }

  // Unknown trigger — conservative skip
  return { run: false, reason: "unknown-trigger" };
}

/**
 * Plan Forge — Testbed Defect Log
 *
 * Phase TESTBED-01 Slice 01
 *
 * Writes, reads, and updates defect findings produced by testbed
 * scenario runs. Findings are stored as individual JSON files under
 * `docs/plans/testbed-findings/`.
 *
 * @module testbed/defect-log
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync, readdirSync } from "node:fs";
import { resolve, join } from "node:path";

// ─── Frozen Enums ─────────────────────────────────────────────────────
export const SEVERITY_VALUES = Object.freeze(["blocker", "high", "medium", "low", "polish"]);
export const SURFACE_VALUES  = Object.freeze(["crucible", "forge-exec", "tempering", "liveguard", "forge-shop", "cli", "docs"]);
export const STATUS_VALUES   = Object.freeze(["open", "fixed", "wontfix", "duplicate"]);
export const OWNER_ARC_VALUES = Object.freeze(["TEMPER", "FORGE-SHOP", "TESTBED", "AUTO-UPDATE", "MANUAL"]);

// ─── Redaction ────────────────────────────────────────────────────────
const SECRET_PATTERNS = [
  /ghp_[A-Za-z0-9]{36,}/g,
  /gho_[A-Za-z0-9]{36,}/g,
  /sk-[A-Za-z0-9]{20,}/g,
  /Bearer\s+[A-Za-z0-9._\-]{20,}/gi,
  /xai-[A-Za-z0-9]{20,}/g,
  /AKIA[A-Z0-9]{16}/g,
];

function redact(text) {
  if (typeof text !== "string") return text;
  let result = text;
  for (const pat of SECRET_PATTERNS) {
    result = result.replace(pat, "[REDACTED]");
  }
  return result;
}

function redactObject(obj) {
  if (typeof obj === "string") return redact(obj);
  if (Array.isArray(obj)) return obj.map(redactObject);
  if (obj && typeof obj === "object") {
    const out = {};
    for (const [k, v] of Object.entries(obj)) out[k] = redactObject(v);
    return out;
  }
  return obj;
}

// ─── Slug ─────────────────────────────────────────────────────────────
export function toSlug(title) {
  return title
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-|-$/g, "")
    .slice(0, 40);
}

// ─── Validation ───────────────────────────────────────────────────────
export function validateFinding(finding) {
  const errors = [];
  const required = ["findingId", "date", "scenario", "severity", "surface", "title", "expected", "observed", "status"];
  for (const field of required) {
    if (!finding[field]) errors.push(`missing required field: ${field}`);
  }
  if (finding.severity && !SEVERITY_VALUES.includes(finding.severity)) {
    errors.push(`invalid severity '${finding.severity}'; expected one of: ${SEVERITY_VALUES.join(", ")}`);
  }
  if (finding.surface && !SURFACE_VALUES.includes(finding.surface)) {
    errors.push(`invalid surface '${finding.surface}'; expected one of: ${SURFACE_VALUES.join(", ")}`);
  }
  if (finding.status && !STATUS_VALUES.includes(finding.status)) {
    errors.push(`invalid status '${finding.status}'; expected one of: ${STATUS_VALUES.join(", ")}`);
  }
  return { ok: errors.length === 0, errors };
}

// ─── Finding Directory ────────────────────────────────────────────────
function findingsDir(projectRoot) {
  return resolve(projectRoot, "docs", "plans", "testbed-findings");
}

function ensureFindingsDir(projectRoot) {
  const dir = findingsDir(projectRoot);
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
  return dir;
}

function findExistingByFindingId(dir, findingId) {
  if (!existsSync(dir)) return null;
  for (const f of readdirSync(dir).filter(n => n.endsWith(".json"))) {
    try {
      const data = JSON.parse(readFileSync(join(dir, f), "utf-8"));
      if (data.findingId === findingId) return f;
    } catch { /* skip malformed */ }
  }
  return null;
}

function resolveFilename(dir, slug) {
  let candidate = `${slug}.json`;
  if (!existsSync(join(dir, candidate))) return candidate;
  let i = 2;
  while (existsSync(join(dir, `${slug}-${i}.json`))) i++;
  return `${slug}-${i}.json`;
}

// ─── Public API ───────────────────────────────────────────────────────

/**
 * Write a finding to the testbed-findings directory.
 * Idempotent by findingId — re-logging the same ID overwrites the file.
 */
export function logFinding(finding, { hub, projectRoot }) {
  const validation = validateFinding(finding);
  if (!validation.ok) {
    const err = new Error(`Invalid finding: ${validation.errors.join("; ")}`);
    err.code = "ERR_INVALID_FINDING";
    throw err;
  }

  const sanitized = { ...finding };
  sanitized.observed = redactObject(sanitized.observed);
  if (sanitized.artefacts) sanitized.artefacts = redactObject(sanitized.artefacts);

  const dir = ensureFindingsDir(projectRoot);
  const existing = findExistingByFindingId(dir, finding.findingId);
  const slug = `${finding.date}-${toSlug(finding.title)}`;
  const filename = existing || resolveFilename(dir, slug);

  writeFileSync(join(dir, filename), JSON.stringify(sanitized, null, 2), "utf-8");

  hub?.broadcast({ type: "testbed-finding-logged", data: { findingId: finding.findingId, severity: finding.severity, surface: finding.surface, title: finding.title, filename } });

  return { ok: true, filename, path: join(dir, filename) };
}

/**
 * List findings, optionally filtered by status, severity, and date.
 */
export function listFindings({ status, severity, since } = {}, { projectRoot }) {
  const dir = findingsDir(projectRoot);
  if (!existsSync(dir)) return [];

  const results = [];
  for (const f of readdirSync(dir).filter(n => n.endsWith(".json"))) {
    try {
      const data = JSON.parse(readFileSync(join(dir, f), "utf-8"));
      if (status && data.status !== status) continue;
      if (severity && data.severity !== severity) continue;
      if (since && data.date < since) continue;
      results.push({ ...data, _filename: f });
    } catch {
      console.warn(`[testbed] skipping malformed finding: ${f}`);
    }
  }

  return results.sort((a, b) => (b.date || "").localeCompare(a.date || ""));
}

/**
 * Update a finding's status. Validates transition (open → fixed|wontfix|duplicate).
 */
export function updateFindingStatus(findingId, status, linkedPlanForgeIssue, { projectRoot }) {
  if (!STATUS_VALUES.includes(status)) {
    const err = new Error(`Invalid status '${status}'`);
    err.code = "ERR_INVALID_STATUS";
    throw err;
  }

  const dir = findingsDir(projectRoot);
  const filename = findExistingByFindingId(dir, findingId);
  if (!filename) {
    const err = new Error(`Finding not found: ${findingId}`);
    err.code = "ERR_FINDING_NOT_FOUND";
    throw err;
  }

  const filepath = join(dir, filename);
  const data = JSON.parse(readFileSync(filepath, "utf-8"));

  // Idempotent — same status is a no-op
  if (data.status === status) return { ok: true, noop: true };

  data.status = status;
  if (linkedPlanForgeIssue) data.linkedPlanForgeIssue = linkedPlanForgeIssue;

  writeFileSync(filepath, JSON.stringify(data, null, 2), "utf-8");
  return { ok: true, noop: false };
}

/**
 * Plan Forge — Testbed Runner
 *
 * Phase TESTBED-01 Slice 01
 *
 * Executes a scenario fixture against a testbed repository:
 *   preflight → setup → execute → assertions → teardown
 *
 * DI-based: all external deps injected for testability.
 *
 * @module testbed/runner
 */

import { existsSync, readFileSync, writeFileSync, readdirSync, mkdirSync, unlinkSync } from "node:fs";
import { resolve, join } from "node:path";
import { randomUUID } from "node:crypto";
import { execSync } from "node:child_process";
import { logFinding } from "./defect-log.mjs";

// ─── Constants ────────────────────────────────────────────────────────
const LOCK_STALE_MS = 60 * 60 * 1000; // 1 hour
const MAX_CAPTURE_BYTES = 100 * 1024;  // 100 KB per step output

// ─── Lock ─────────────────────────────────────────────────────────────

function lockPath(projectRoot) {
  return resolve(projectRoot, ".forge", "testbed.lock");
}

export function acquireLock(projectRoot, hub) {
  const forgeDir = resolve(projectRoot, ".forge");
  if (!existsSync(forgeDir)) mkdirSync(forgeDir, { recursive: true });

  const lp = lockPath(projectRoot);
  if (existsSync(lp)) {
    try {
      const existing = JSON.parse(readFileSync(lp, "utf-8"));
      const age = Date.now() - new Date(existing.ts).getTime();
      if (age < LOCK_STALE_MS) {
        const err = new Error(`Testbed is locked by PID ${existing.pid} since ${existing.ts}`);
        err.code = "ERR_TESTBED_LOCKED";
        throw err;
      }
      // Stale lock — reclaim with warning
      hub?.broadcast({ type: "testbed-lock-reclaimed", data: { stalePid: existing.pid, staleTs: existing.ts, ageMs: age } });
    } catch (e) {
      if (e.code === "ERR_TESTBED_LOCKED") throw e;
      // Corrupt lock file — overwrite
    }
  }

  writeFileSync(lp, JSON.stringify({ pid: process.pid, ts: new Date().toISOString() }), "utf-8");
}

export function releaseLock(projectRoot) {
  const lp = lockPath(projectRoot);
  try { if (existsSync(lp)) unlinkSync(lp); } catch { /* best-effort */ }
}

// ─── Preflight ────────────────────────────────────────────────────────

export function preflight(testbedPath, expectedHead, spawnFn) {
  if (!existsSync(testbedPath)) {
    const err = new Error(`Testbed repo not found at: ${testbedPath}`);
    err.code = "ERR_TESTBED_NOT_FOUND";
    throw err;
  }

  // Check for clean working tree
  let statusOutput;
  try {
    const exec = spawnFn || execSync;
    statusOutput = exec("git status --porcelain", { cwd: testbedPath, encoding: "utf-8", timeout: 10_000 });
  } catch (e) {
    const err = new Error(`Failed to check testbed git status: ${e.message}`);
    err.code = "ERR_TESTBED_GIT";
    throw err;
  }

  if (typeof statusOutput === "string" && statusOutput.trim().length > 0) {
    const err = new Error(`Testbed has uncommitted changes:\n${statusOutput.trim()}`);
    err.code = "ERR_TESTBED_DIRTY";
    throw err;
  }

  // Check HEAD match
  if (expectedHead) {
    let head;
    try {
      const exec = spawnFn || execSync;
      head = exec("git rev-parse HEAD", { cwd: testbedPath, encoding: "utf-8", timeout: 10_000 });
      if (typeof head === "string") head = head.trim();
    } catch (e) {
      const err = new Error(`Failed to read testbed HEAD: ${e.message}`);
      err.code = "ERR_TESTBED_GIT";
      throw err;
    }

    if (head !== expectedHead) {
      const err = new Error(`Testbed HEAD mismatch: expected ${expectedHead}, got ${head}`);
      err.code = "ERR_TESTBED_HEAD_MISMATCH";
      throw err;
    }
  }

  return { ok: true };
}

// ─── Assertion Handlers ───────────────────────────────────────────────

export const ASSERTION_HANDLERS = {
  "file-exists": (a, ctx) => {
    const target = resolve(ctx.testbedPath, a.path);
    const exists = existsSync(target);
    return { passed: exists, kind: "file-exists", detail: exists ? `File exists: ${a.path}` : `File missing: ${a.path}` };
  },

  "file-contains": (a, ctx) => {
    const target = resolve(ctx.testbedPath, a.path);
    if (!existsSync(target)) return { passed: false, kind: "file-contains", detail: `File missing: ${a.path}` };
    const content = readFileSync(target, "utf-8");
    const matched = new RegExp(a.pattern).test(content);
    return { passed: matched, kind: "file-contains", detail: matched ? `Pattern matched in ${a.path}` : `Pattern '${a.pattern}' not found in ${a.path}` };
  },

  "event-emitted": (a, ctx) => {
    const withinMs = a.within || 30_000;
    const cutoff = ctx.startTime - withinMs;
    const matching = (ctx.hubEvents || []).filter(e => e.type === a.eventType && new Date(e.timestamp).getTime() >= cutoff);
    const passed = matching.length > 0;
    return { passed, kind: "event-emitted", detail: passed ? `Event '${a.eventType}' found (${matching.length} match(es))` : `Event '${a.eventType}' not found within ${withinMs}ms` };
  },

  "correlationId-thread": (a, ctx) => {
    const matching = (ctx.hubEvents || []).filter(e => e.correlationId === ctx.correlationId);
    const minSize = a.minSize || 1;
    const passed = matching.length >= minSize;
    return { passed, kind: "correlationId-thread", detail: `${matching.length} events with correlationId (need ≥ ${minSize})` };
  },

  "exit-code": (a, ctx) => {
    const actual = ctx.lastExitCode;
    const expected = a.expected ?? 0;
    const passed = actual === expected;
    return { passed, kind: "exit-code", detail: `Exit code: ${actual} (expected ${expected})` };
  },

  "duration-under": (a, ctx) => {
    const actual = ctx.lastDurationMs;
    const budget = a.budgetMs;
    const passed = actual <= budget;
    return { passed, kind: "duration-under", detail: `Duration ${actual}ms ${passed ? "≤" : ">"} budget ${budget}ms` };
  },

  "artefact-count": (a, ctx) => {
    const dir = resolve(ctx.testbedPath, a.dir || ".forge/runs");
    let count = 0;
    try {
      if (existsSync(dir)) {
        const entries = readdirSync(dir);
        count = entries.length;
      }
    } catch { /* empty */ }
    const min = a.min || 1;
    const passed = count >= min;
    return { passed, kind: "artefact-count", detail: `${count} artefact(s) in ${a.dir || ".forge/runs"} (need ≥ ${min})` };
  },
};

// ─── Step Execution ───────────────────────────────────────────────────

function executeSteps(steps, cwd, spawnFn) {
  const results = [];
  for (const step of steps) {
    const t0 = Date.now();
    let stdout = "", stderr = "", exitCode = 0;
    try {
      const exec = spawnFn || execSync;
      const output = exec(step.cmd || step, { cwd, encoding: "utf-8", timeout: step.timeout || 120_000 });
      stdout = typeof output === "string" ? output.slice(0, MAX_CAPTURE_BYTES) : "";
    } catch (e) {
      exitCode = e.status ?? 1;
      stdout = (e.stdout || "").slice(0, MAX_CAPTURE_BYTES);
      stderr = (e.stderr || "").slice(0, MAX_CAPTURE_BYTES);
    }
    results.push({ cmd: step.cmd || step, stdout, stderr, exitCode, durationMs: Date.now() - t0 });
    if (exitCode !== 0) break; // abort on first failure
  }
  return results;
}

function createScenarioResult(scenarioId, correlationId) {
  return {
    scenarioId,
    correlationId,
    status: "passed",
    durationMs: 0,
    assertions: [],
    findings: [],
    setupResults: [],
    executeResults: [],
    teardownResults: [],
  };
}

function buildSetupFailureFinding(scenario, correlationId, lastSetup) {
  return {
    findingId: `${scenario.scenarioId}-setup-${correlationId.slice(0, 8)}`,
    date: new Date().toISOString().slice(0, 10),
    scenario: scenario.scenarioId,
    severity: "high",
    surface: "cli",
    title: `Setup step failed: ${lastSetup.cmd}`,
    expected: "exit code 0",
    observed: `exit code ${lastSetup.exitCode}`,
    status: "open",
  };
}

function runScenarioSetup(result, scenario, testbedPath, spawnFn) {
  if (!scenario.setup || scenario.setup.length === 0) return;
  result.setupResults = executeSteps(scenario.setup, testbedPath, spawnFn);
  const lastSetup = result.setupResults[result.setupResults.length - 1];
  if (!lastSetup || lastSetup.exitCode === 0) return;
  result.status = "setup-failed";
  result.findings.push(buildSetupFailureFinding(scenario, result.correlationId, lastSetup));
}

function buildAssertionContext(result, { testbedPath, startTime, correlationId, hub }) {
  const hubEvents = hub?.eventHistory || [];
  const lastExec = result.executeResults[result.executeResults.length - 1];
  return {
    testbedPath,
    startTime,
    correlationId,
    hubEvents,
    lastExitCode: lastExec?.exitCode ?? 0,
    lastDurationMs: lastExec?.durationMs ?? 0,
  };
}

function recordAssertionFailure({ result, assertion, assertionResult, scenario, context = {} }) {
  const { correlationId = result.correlationId, hub, projectRoot } = context;
  result.status = "failed";
  const finding = {
    findingId: `${scenario.scenarioId}-${assertion.kind}-${correlationId.slice(0, 8)}`,
    date: new Date().toISOString().slice(0, 10),
    scenario: scenario.scenarioId,
    severity: assertion.severity || "medium",
    surface: assertion.surface || "cli",
    title: `Assertion failed: ${assertion.kind}`,
    expected: assertion.expected || assertionResult.detail,
    observed: assertionResult.detail,
    status: "open",
  };
  result.findings.push(finding);
  try {
    logFinding(finding, { hub, projectRoot });
  } catch { /* defect-log write is best-effort during runs */ }
}

function runScenarioAssertions(result, scenario, assertionContext, { hub, projectRoot }) {
  for (const assertion of scenario.assertions) {
    const handler = ASSERTION_HANDLERS[assertion.kind];
    if (!handler) {
      result.assertions.push({ passed: false, kind: assertion.kind, detail: `Unknown assertion kind: ${assertion.kind}` });
      continue;
    }
    const assertionResult = handler(assertion, assertionContext);
    result.assertions.push(assertionResult);
    if (!assertionResult.passed) {
      recordAssertionFailure({ result: result, assertion: assertion, assertionResult: assertionResult, scenario: scenario, context: {
        correlationId: result.correlationId,
        hub,
        projectRoot,
      } });
    }
  }
}

function captureScenarioFindings(result, captureMemoryFn, scenarioId, projectRoot) {
  if (!captureMemoryFn) return;
  for (const finding of result.findings) {
    if (finding.severity !== "blocker" && finding.severity !== "high") continue;
    try {
      captureMemoryFn(
        `Testbed finding [${finding.severity}]: ${finding.title} — expected: ${finding.expected}, observed: ${finding.observed}`,
        "testbed-finding",
        `testbed/${scenarioId}`,
        projectRoot,
      );
    } catch { /* best-effort */ }
  }
}

function finalizeScenarioRun({ result, startTime, hub, scenarioId, correlationId }) {
  result.durationMs = Date.now() - startTime;
  hub?.broadcast({
    type: "testbed-scenario-completed",
    data: {
      scenarioId,
      correlationId,
      status: result.status,
      failedAssertions: result.assertions.filter((assertion) => !assertion.passed).length,
      durationMs: result.durationMs,
    },
  });
  return result;
}

function cleanupScenarioRun({ result, dryRun, scenario, testbedPath, spawnFn, projectRoot }) {
  if (!dryRun && scenario.teardown && scenario.teardown.length > 0) {
    try {
      result.teardownResults = executeSteps(scenario.teardown, testbedPath, spawnFn);
    } catch { /* teardown failure must not mask assertion results */ }
  }

  if (!dryRun && testbedPath) {
    try {
      const exec = spawnFn || execSync;
      exec("git checkout -- .", { cwd: testbedPath, encoding: "utf-8", timeout: 15_000 });
    } catch { /* best-effort — non-fatal if testbed has no tracked files to restore */ }
  }

  releaseLock(projectRoot);
}

// ─── Main Runner ──────────────────────────────────────────────────────

/**
 * Run a testbed scenario.
 *
 * @param {object} scenario - Parsed scenario fixture
 * @param {object} deps - DI deps: { hub, projectRoot, captureMemoryFn, spawnFn }
 * @returns {Promise<object>} Run result
 */
export async function runScenario(scenario, deps) {
  const { hub, projectRoot, captureMemoryFn, spawnFn } = deps;
  const correlationId = randomUUID();
  const startTime = Date.now();
  const testbedPath = deps.testbedPath;
  const dryRun = deps.dryRun || false;

  hub?.broadcast({ type: "testbed-scenario-started", data: { scenarioId: scenario.scenarioId, correlationId, testbedPath } });
  preflight(testbedPath, scenario.expectedHead, spawnFn);
  acquireLock(projectRoot, hub);

  const result = createScenarioResult(scenario.scenarioId, correlationId);
  try {
    runScenarioSetup(result, scenario, testbedPath, spawnFn);
    if (result.status === "passed" && !dryRun) {
      result.executeResults = executeSteps(scenario.execute, testbedPath, spawnFn);
    }

    const assertionContext = buildAssertionContext(result, {
      testbedPath,
      startTime,
      correlationId,
      hub,
    });
    runScenarioAssertions(result, scenario, assertionContext, { hub, projectRoot });
    captureScenarioFindings(result, captureMemoryFn, scenario.scenarioId, projectRoot);
  } finally {
    cleanupScenarioRun({ result, dryRun, scenario, testbedPath, spawnFn, projectRoot });
  }

  return finalizeScenarioRun({ result: result, startTime: startTime, hub: hub, scenarioId: scenario.scenarioId, correlationId: correlationId });
}

/**
 * Plan Forge — Testbed Scenarios
 *
 * Phase TESTBED-01 Slice 01
 *
 * Loads, validates, and lists scenario fixture files from
 * `docs/plans/testbed-scenarios/`. Each fixture is a JSON file
 * describing setup, execute, assertions, and teardown steps.
 *
 * @module testbed/scenarios
 */

import { existsSync, readFileSync, readdirSync } from "node:fs";
import { resolve, join, basename } from "node:path";

// ─── Constants ────────────────────────────────────────────────────────
export const SCENARIO_KINDS = Object.freeze(["happy-path", "chaos", "perf", "long-horizon"]);

export const ASSERTION_KINDS = Object.freeze([
  "file-exists",
  "file-contains",
  "event-emitted",
  "correlationId-thread",
  "exit-code",
  "duration-under",
  "artefact-count",
]);

// ─── Validation ───────────────────────────────────────────────────────

/**
 * Validate a scenario fixture object.
 * @returns {{ ok: boolean, errors: string[] }}
 */
export function validateScenarioFixture(fixture) {
  const errors = [];

  if (!fixture.scenarioId) errors.push("missing required field: scenarioId");
  if (!fixture.kind) errors.push("missing required field: kind");
  if (fixture.kind && !SCENARIO_KINDS.includes(fixture.kind)) {
    errors.push(`invalid kind '${fixture.kind}'; expected one of: ${SCENARIO_KINDS.join(", ")}`);
  }

  if (!fixture.execute || !Array.isArray(fixture.execute)) {
    errors.push("missing or invalid field: execute (must be an array of steps)");
  }
  if (!fixture.assertions || !Array.isArray(fixture.assertions)) {
    errors.push("missing or invalid field: assertions (must be an array)");
  }

  if (fixture.assertions && Array.isArray(fixture.assertions)) {
    for (let i = 0; i < fixture.assertions.length; i++) {
      const a = fixture.assertions[i];
      if (!a.kind) {
        errors.push(`assertion[${i}]: missing kind`);
      } else if (!ASSERTION_KINDS.includes(a.kind)) {
        errors.push(`assertion[${i}]: unsupported kind '${a.kind}'; expected one of: ${ASSERTION_KINDS.join(", ")}`);
      }
    }
  }

  return { ok: errors.length === 0, errors };
}

// ─── Scenario Directory ───────────────────────────────────────────────
function scenariosDir(projectRoot) {
  return resolve(projectRoot, "docs", "plans", "testbed-scenarios");
}

// ─── Public API ───────────────────────────────────────────────────────

/**
 * Resolve the testbed path from input, config, or platform default.
 */
export function resolveTestbedPath(input, { projectRoot }) {
  // 1. Explicit argument
  if (input?.testbedPath) return input.testbedPath;

  // 2. .forge.json config
  try {
    const forgeJsonPath = resolve(projectRoot, ".forge.json");
    if (existsSync(forgeJsonPath)) {
      const config = JSON.parse(readFileSync(forgeJsonPath, "utf-8"));
      if (config.testbed?.path) return config.testbed.path;
    }
  } catch { /* ignore parse errors */ }

  // 3. Platform default (Windows only)
  if (process.platform === "win32") {
    return "E:\\GitHub\\plan-forge-testbed";
  }

  const err = new Error("Testbed path not configured. Set testbed.path in .forge.json or pass testbedPath argument.");
  err.code = "ERR_TESTBED_PATH_REQUIRED";
  throw err;
}

/**
 * Load a scenario fixture by ID.
 */
export function loadScenario(scenarioId, { projectRoot }) {
  const dir = scenariosDir(projectRoot);
  const filePath = join(dir, `${scenarioId}.json`);

  if (!existsSync(filePath)) {
    const err = new Error(`Scenario not found: ${scenarioId} (looked in ${dir})`);
    err.code = "ERR_SCENARIO_NOT_FOUND";
    throw err;
  }

  const raw = readFileSync(filePath, "utf-8");
  let fixture;
  try {
    fixture = JSON.parse(raw);
  } catch (parseErr) {
    const err = new Error(`Scenario file is not valid JSON: ${scenarioId}.json — ${parseErr.message}`);
    err.code = "ERR_SCENARIO_PARSE";
    throw err;
  }

  const validation = validateScenarioFixture(fixture);
  if (!validation.ok) {
    const err = new Error(`Invalid scenario fixture: ${validation.errors.join("; ")}`);
    err.code = "ERR_SCENARIO_INVALID";
    throw err;
  }

  return fixture;
}

/**
 * List all scenarios in the scenarios directory.
 */
export function listScenarios({ projectRoot }) {
  const dir = scenariosDir(projectRoot);
  if (!existsSync(dir)) return [];

  return readdirSync(dir)
    .filter(f => f.endsWith(".json"))
    .map(f => {
      try {
        const data = JSON.parse(readFileSync(join(dir, f), "utf-8"));
        return {
          scenarioId: data.scenarioId || basename(f, ".json"),
          kind: data.kind || "unknown",
          description: data.description || "",
        };
      } catch {
        return { scenarioId: basename(f, ".json"), kind: "unknown", description: "(parse error)" };
      }
    });
}

/**
 * Testbed Scenario: memory-upgrade-e2e
 *
 * Phase-MEMORY-QA-PLAN Slice 6
 *
 * In-process happy-path scenario that validates the full memory-upgrade
 * pipeline: Anvil caching, Hallmark provenance capture, Lattice indexing,
 * and capability-aware brain writes — all against a mock-OpenBrain and a
 * temporary forge home.  No real git repo or external network is required.
 *
 * Registered via `pforge-mcp/testbed/scenarios/index.mjs` so
 * `forge_testbed_happypath` discovers it automatically.
 *
 * Summary shape returned from run():
 *   { anvilHits, anvilMisses, latticeChunks, hallmarkRecords, dlqCount }
 *
 * @module testbed/scenarios/memory-upgrade-e2e
 */

import { mkdirSync, writeFileSync, existsSync } from "node:fs";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

import { withAnvil, anvilDlqList } from "../../anvil.mjs";
import { latticeIndex } from "../../lattice.mjs";
import { buildProvenance } from "../../../pforge-sdk/src/hallmark.mjs";
import { createMockOpenBrain } from "../../tests/integration/memory-upgrade/helpers/mock-openbrain.mjs";
import { createTmpForgeHome } from "../../tests/integration/memory-upgrade/helpers/with-tmp-forge-home.mjs";

// ─── Inline mock exec for latticeIndex (no real git required) ────────────────

function makeMockExec(fileList) {
  return function mockExec(cmd) {
    if (cmd.startsWith("git ls-files")) return fileList.join("\n") + "\n";
    return "";
  };
}

// ─── Tiny inline chunker (no tree-sitter required) ──────────────────────────

async function testChunker({ filePath, content }) {
  return [
    {
      filePath,
      kind: "module",
      name: filePath,
      startByte: 0,
      endByte: content.length,
      references: [],
    },
  ];
}

// ─── Scenario definition ────────────────────────────────────────────────────

export const scenario = {
  scenarioId: "memory-upgrade-e2e",
  kind: "happy-path",
  description:
    "End-to-end validation of Hallmark provenance, Anvil caching, Lattice indexing, " +
    "and capability-aware brain writes against an in-process mock-OpenBrain.",

  /**
   * Run the scenario.
   *
   * Creates its own tmp forge home and mock-OpenBrain server; tears both
   * down in a `finally` block regardless of outcome.
   *
   * @param {object} [deps] - Optional injection points (hub, projectRoot).
   * @returns {Promise<{
   *   ok:           boolean,
   *   status:       "passed" | "failed" | "error",
   *   durationMs:   number,
   *   tmpDir:       string,
   *   tmpDirCleaned:boolean,
   *   summary: {
   *     anvilHits:      number,
   *     anvilMisses:    number,
   *     latticeChunks:  number,
   *     hallmarkRecords:number,
   *     dlqCount:       number,
   *   }
   * }>}
   */
  async run(deps = {}) {
    const t0 = Date.now();
    const home = createTmpForgeHome({ prefix: "pforge-memory-upgrade-e2e-" });
    const tmpDir = home.cwd;
    let ob = null;
    const findings = [];
    let result = null;

    try {
      // ── Boot mock-OpenBrain with provenance capability ────────────────────
      ob = await createMockOpenBrain({
        capabilities: ["provenance", "search", "write"],
      });

      // ── Create a tiny in-process project inside the tmp dir ────────────────
      const srcDir = join(home.cwd, "src");
      mkdirSync(srcDir, { recursive: true });

      writeFileSync(
        join(srcDir, "alpha.mjs"),
        'export function frobnicate(x) { return combulate(x); }\n',
        "utf-8",
      );
      writeFileSync(
        join(srcDir, "beta.mjs"),
        'export function combulate(x) { return x * 2; }\n',
        "utf-8",
      );
      writeFileSync(
        join(srcDir, "gamma.mjs"),
        'export function flibbert(x) { return x + 1; }\n',
        "utf-8",
      );

      const projectFiles = [
        "src/alpha.mjs",
        "src/beta.mjs",
        "src/gamma.mjs",
      ];

      // ── Slice 1: forge_analyze (Anvil-wrapped) — first call = miss ─────────
      let innerCallCount = 0;
      const analyzeFn = async (opts) => {
        innerCallCount++;
        return { findings: [], file: opts?.file ?? "unknown" };
      };

      const analyzeOpts1 = {
        toolName: "forge_analyze",
        inputs: { file: "src/alpha.mjs", line: 1 },
        codeHashSeed: "memory-upgrade-e2e:alpha@v1",
      };

      const miss1 = await withAnvil(analyzeFn, analyzeOpts1, { cwd: home.cwd });

      // ── Slice 2: forge_sweep (Anvil cache hit on same inputs) ───────────────
      const hit1 = await withAnvil(analyzeFn, analyzeOpts1, { cwd: home.cwd });

      // Second file: fresh miss
      const analyzeOpts2 = {
        toolName: "forge_analyze",
        inputs: { file: "src/beta.mjs", line: 1 },
        codeHashSeed: "memory-upgrade-e2e:beta@v1",
      };
      const miss2 = await withAnvil(analyzeFn, analyzeOpts2, { cwd: home.cwd });

      const anvilMisses = [miss1, miss2].filter((r) => !r.anvil?.hit).length;
      const anvilHits   = [hit1].filter((r) =>  r.anvil?.hit).length;

      if (anvilHits < 1) findings.push("anvil cache did not produce a hit on identical inputs");
      if (anvilMisses < 1) findings.push("anvil did not produce a miss on first call");

      // ── Slice 3: brain_capture — write Hallmark records to mock-OpenBrain ──
      const memoriesFetches = [];

      const writeMemory = async (content, toolName, sourceFile) => {
        const prov = buildProvenance({ toolName, sourceFile });
        const res = await fetch(`${ob.url}/memories`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            content,
            metadata: { provenance: prov },
          }),
        });
        memoriesFetches.push(res.ok);
        return res.ok;
      };

      await writeMemory("Analysis of frobnicate in src/alpha.mjs", "forge_analyze", "src/alpha.mjs");
      await writeMemory("Analysis of combulate in src/beta.mjs",   "forge_analyze", "src/beta.mjs");
      await writeMemory("Sweep result for gamma.mjs",              "forge_sweep",   "src/gamma.mjs");

      const hallmarkRecords = ob.hitCounts.memories;
      if (hallmarkRecords < 3) findings.push(`expected ≥3 hallmark records, got ${hallmarkRecords}`);

      // ── Slice 4: forge_lattice_index ────────────────────────────────────────
      const mockExec = makeMockExec(projectFiles);
      const latticeResult = await latticeIndex({
        paths: ["."],
        deps: {
          cwd: home.cwd,
          exec: mockExec,
          chunker: testChunker,
          chunkerName: "test",
          chunkerVersion: "0.0.0",
        },
      });

      const latticeChunks = latticeResult.chunks ?? 0;
      if (latticeChunks < 1) findings.push(`lattice indexed ${latticeChunks} chunks — expected ≥1`);

      // ── Verify artifacts ────────────────────────────────────────────────────
      const anvilDirExists   = existsSync(home.forge("anvil"));
      const latticeDirExists = existsSync(home.forge("lattice"));

      if (!anvilDirExists)   findings.push(".forge/anvil directory not created");
      if (!latticeDirExists) findings.push(".forge/lattice directory not created");

      // ── DLQ count (should be 0 in the happy path) ──────────────────────────
      const { total: dlqCount } = anvilDlqList({}, { cwd: home.cwd });

      const summary = {
        anvilHits,
        anvilMisses,
        latticeChunks,
        hallmarkRecords,
        dlqCount,
      };

      const status = findings.length === 0 ? "passed" : "failed";

      result = {
        ok:     status === "passed",
        status,
        durationMs:    Date.now() - t0,
        tmpDir,
        tmpDirCleaned: false,
        findings,
        summary,
      };
    } catch (err) {
      result = {
        ok:     false,
        status: "error",
        durationMs:    Date.now() - t0,
        tmpDir,
        tmpDirCleaned: false,
        error:  err.message,
        findings,
        summary: {
          anvilHits:      0,
          anvilMisses:    0,
          latticeChunks:  0,
          hallmarkRecords:0,
          dlqCount:       0,
        },
      };
    } finally {
      if (ob) {
        try { await ob.close(); } catch { /* best-effort */ }
      }
      home.cleanup();
      if (result) result.tmpDirCleaned = !existsSync(tmpDir);
    }

    return result;
  },
};

/* @vitest-environment jsdom */
/**
 * Tests for Forge-Master chat cost meter — Phase-38.3.
 *
 * Verifies that forgeMasterRenderCostMeter renders a #fm-cost-meter element
 * after #fm-dial when tokens are present, renders empty when tokens are 0,
 * and updates the meter in place on repeated calls.
 */
import { describe, it, expect, beforeEach } from "vitest";
import { readFileSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));

function seedDOM() {
  document.body.innerHTML = `
    <div id="fm-dial"></div>
    <div id="fm-chat-stream"></div>
    <div id="fm-tool-trace"></div>
    <textarea id="fm-composer"></textarea>
  `;
}

function loadModule() {
  const src = readFileSync(resolve(__dirname, "../dashboard/forge-master.js"), "utf-8");
  // eslint-disable-next-line no-new-func
  const fn = new Function("window", "document", "crypto", "sessionStorage", src);
  fn(window, document, window.crypto, window.sessionStorage);
}

describe("forgeMasterRenderCostMeter", () => {
  beforeEach(() => {
    seedDOM();
    loadModule();
  });

  it("creates #fm-cost-meter element after #fm-dial", () => {
    window._forgeMasterSetChatCost(0.0015, 500, 300);

    const meterEl = document.getElementById("fm-cost-meter");
    expect(meterEl).not.toBeNull();
  });

  it("renders cost string with token count when tokens > 0", () => {
    window._forgeMasterSetChatCost(0.0015, 500, 300);

    const meterEl = document.getElementById("fm-cost-meter");
    expect(meterEl.textContent).toContain("Chat:");
    expect(meterEl.textContent).toContain("tok");
  });

  it("renders <$0.0001 for very small costs", () => {
    window._forgeMasterSetChatCost(0.000001, 10, 5);

    const meterEl = document.getElementById("fm-cost-meter");
    expect(meterEl.textContent).toContain("<$0.0001");
  });

