/**
 * Plan Forge — Timeline Core
 *
 * Unified chronological view across all forge event sources.
 * Time-window filter, source merger, correlationId grouper, LRU cache.
 *
 * Performance budget: p95 < 400 ms over 10k events.
 *
 * @module timeline/core
 */

import { statSync } from "node:fs";
import { resolve } from "node:path";
import { parseSince } from "../search/core.mjs";
import { TIMELINE_SOURCES, matchEventGlob } from "./sources.mjs";

// ─── LRU Cache ────────────────────────────────────────────────────────

const MAX_CACHE = 100;
const CACHE_TTL_MS = 60_000;
const cache = new Map();

function cacheKey(params) {
  return JSON.stringify({
    from: params.from || "",
    to: params.to || "",
    correlationId: params.correlationId || "",
    sources: params.sources || [],
    events: params.events || [],
    groupBy: params.groupBy || "time",
    limit: params.limit || 500,
  });
}

function forgeDirMtime(forgeDir) {
  // Use the max mtime across .forge root and .forge/fm-sessions so that new
  // Forge-Master turns (written to fm-sessions/) invalidate the cache promptly.
  let m = 0;
  try { m = Math.max(m, statSync(forgeDir).mtimeMs); } catch { /* missing */ }
  try { m = Math.max(m, statSync(resolve(forgeDir, "fm-sessions")).mtimeMs); } catch { /* missing */ }
  return m;
}

function cacheGet(key, forgeDir) {
  const entry = cache.get(key);
  if (!entry) return null;
  if (Date.now() - entry.insertedAt > CACHE_TTL_MS) {
    cache.delete(key);
    return null;
  }
  // Invalidate if .forge directory or fm-sessions mtime changed
  const current = forgeDirMtime(forgeDir);
  if (current === 0 || current !== entry.mtimeMs) {
    cache.delete(key);
    return null;
  }
  return entry.data;
}

function cacheSet(key, forgeDir, data) {
  if (cache.size >= MAX_CACHE) {
    let oldestKey = null;
    let oldestTime = Infinity;
    for (const [k, val] of cache) {
      if (val.insertedAt < oldestTime) {
        oldestTime = val.insertedAt;
        oldestKey = k;
      }
    }
    if (oldestKey) cache.delete(oldestKey);
  }
  cache.set(key, { data, insertedAt: Date.now(), mtimeMs: forgeDirMtime(forgeDir) });
}

/** Exposed for testing — clears the internal LRU cache. */
export function clearTimelineCache() {
  cache.clear();
}

// ─── Main timeline function ───────────────────────────────────────────

const DEFAULT_LIMIT = 500;
const MAX_LIMIT = 2000;

/**
 * Unified chronological view across forge event sources.
 *
 * @param {{ from?: string, to?: string, correlationId?: string, sources?: string[], events?: string[], groupBy?: string, limit?: number }} params
 * @param {{ cwd: string }} opts
 * @returns {Promise<{ events?: Array, threads?: Array, total: number, truncated: boolean, durationMs: number, windowFrom: string, windowTo: string, sourcesQueried: string[] }>}
 */
function _groupEventsByCorrelation(allEvents, limit) {
  const threadMap = new Map();
  for (const evt of allEvents) {
    const cid = evt.correlationId || "__ungrouped__";
    if (!threadMap.has(cid)) threadMap.set(cid, []);
    threadMap.get(cid).push(evt);
  }
  let threads = [];
  for (const [cid, events] of threadMap) {
    threads.push({
      correlationId: cid,
      events,
      firstTs: events[0].ts,
      lastTs: events[events.length - 1].ts,
      sources: [...new Set(events.map((e) => e.source))],
    });
  }
  threads.sort((a, b) => (new Date(b.lastTs).getTime() || 0) - (new Date(a.lastTs).getTime() || 0));
  const truncated = threads.length > limit;
  return { threads: threads.slice(0, limit), truncated };
}

function _buildTimelineEmptyMessage({ windowFrom, windowTo, correlationId, eventFilters, params }) {
  const fromHuman = windowFrom || "unset";
  const toHuman = windowTo || "now";
  const filterParts = [];
  if (correlationId) filterParts.push(`correlationId=${correlationId}`);
  if (eventFilters && eventFilters.length > 0) filterParts.push(`events=[${eventFilters.join(", ")}]`);
  if (params.sources) filterParts.push(`sources=[${(params.sources || []).join(", ")}]`);
  const filterDesc = filterParts.length > 0 ? ` with filters ${filterParts.join(", ")}` : "";
  return `No events in window ${fromHuman} → ${toHuman}${filterDesc}. Try widening the from/to range (default is last 24h), removing event filters, or checking that the project has activity in .forge/.`;
}

function resolveTimelineWindow(params) {
  const now = new Date();
  return {
    fromDate: params.from ? parseSince(params.from) : new Date(now.getTime() - 86_400_000),
    toDate: params.to ? parseSince(params.to) : now,
  };
}

function resolveTimelineSources(params) {
  const allSourceNames = Object.keys(TIMELINE_SOURCES);
  return params.sources
    ? params.sources.filter((source) => allSourceNames.includes(source))
    : allSourceNames;
}

function resolveTimelineQuery(params) {
  const { fromDate, toDate } = resolveTimelineWindow(params);
  return {
    fromDate,
    toDate,
    limit: Math.min(Math.max(params.limit != null ? params.limit : DEFAULT_LIMIT, 0), MAX_LIMIT),
    groupBy: params.groupBy || "time",
    correlationId: params.correlationId || null,
    eventFilters: params.events || [],
    sourcesQueried: resolveTimelineSources(params),
  };
}

async function readTimelineSourceResults(cwd, sourcesQueried, filters) {
  return Promise.all(sourcesQueried.map((name) => {
    const source = TIMELINE_SOURCES[name];
    if (!source) return Promise.resolve([]);
    return source.read(cwd, filters).catch(() => []);
  }));
}

function flattenTimelineEvents(sourceResults) {
  const allEvents = [];
  for (const events of sourceResults) {
    allEvents.push(...events);
  }
  allEvents.sort((a, b) => {
    const ta = new Date(a.ts).getTime() || 0;
    const tb = new Date(b.ts).getTime() || 0;
    return ta - tb;
  });
  return allEvents;
}

function buildTimelinePayload({ groupBy, allEvents, limit, total, windowFrom, windowTo, sourcesQueried }) {
  if (groupBy === "correlation") {
    const { threads, truncated } = _groupEventsByCorrelation(allEvents, limit);
    return { threads, total, truncated, durationMs: 0, windowFrom, windowTo, sourcesQueried };
  }
  return {
    events: allEvents.slice(0, limit),
    total,
    truncated: total > limit,
    durationMs: 0,
    windowFrom,
    windowTo,
    sourcesQueried,
  };
}

function applyTimelineEmptyMessage(result, { windowFrom, windowTo, correlationId, eventFilters, params }) {
  if (result.total !== 0) return result;
  return {
    ...result,
    message: _buildTimelineEmptyMessage({ windowFrom: windowFrom, windowTo: windowTo, correlationId: correlationId, eventFilters: eventFilters, params: params }),
  };
}

export async function timeline(params = {}, opts = {}) {
  const start = performance.now();
  const cwd = opts.cwd || process.cwd();
  const forgeDir = resolve(cwd, ".forge");
  const query = resolveTimelineQuery(params);
  const cacheEntryKey = cacheKey({
    ...params,
    from: query.fromDate?.toISOString(),
    to: query.toDate?.toISOString(),
  });
  const cached = cacheGet(cacheEntryKey, forgeDir);
  if (cached) {
    return { ...cached, durationMs: Math.round(performance.now() - start) };
  }

  const filters = {
    from: query.fromDate,
    to: query.toDate,
    events: query.eventFilters,
    correlationId: query.correlationId,
  };
  const sourceResults = await readTimelineSourceResults(cwd, query.sourcesQueried, filters);
  const allEvents = flattenTimelineEvents(sourceResults);
  const windowFrom = query.fromDate ? query.fromDate.toISOString() : "";
  const windowTo = query.toDate ? query.toDate.toISOString() : "";
  const result = applyTimelineEmptyMessage(
    buildTimelinePayload({
      groupBy: query.groupBy,
      allEvents,
      limit: query.limit,
      total: allEvents.length,
      windowFrom,
      windowTo,
      sourcesQueried: query.sourcesQueried,
    }),
    {
      windowFrom,
      windowTo,
      correlationId: query.correlationId,
      eventFilters: query.eventFilters,
      params,
    },
  );

  result.durationMs = Math.round(performance.now() - start);
  cacheSet(cacheEntryKey, forgeDir, result);
  return result;
}

export { matchEventGlob };

/**
 * Plan Forge — Timeline L2 Source Adapters
 *
 * Eight adapters that normalize raw `.forge/` files into timeline events:
 *   { ts, source, event, correlationId, payload }
 *
 * Large JSONL files (hub-events, memories) use streaming readers via
 * readline over createReadStream to avoid loading the full file into memory.
 *
 * Each adapter accepts (cwd, { from, to, events, correlationId }) and
 * returns pre-filtered events.
 *
 * @module timeline/sources
 */

import { createReadStream, existsSync, readdirSync, readFileSync, statSync } from "node:fs";
import { createInterface } from "node:readline";
import { resolve, basename } from "node:path";

// ─── Helpers ──────────────────────────────────────────────────────────

function safeReadJson(filePath) {
  try {
    return JSON.parse(readFileSync(filePath, "utf-8"));
  } catch {
    return null;
  }
}

function listDir(dirPath) {
  try {
    if (!existsSync(dirPath)) return [];
    return readdirSync(dirPath);
  } catch {
    return [];
  }
}

function fileMtime(filePath) {
  try {
    return statSync(filePath).mtime.toISOString();
  } catch {
    return new Date(0).toISOString();
  }
}

/**
 * Match an event type against a glob-like pattern.
 * Supports `*` as wildcard (e.g. `slice-*` matches `slice-started`).
 * @param {string} pattern
 * @param {string} value
 * @returns {boolean}
 */
export function matchEventGlob(pattern, value) {
  if (pattern === "*") return true;
  if (!pattern.includes("*")) return pattern === value;
  const re = new RegExp("^" + pattern.replace(/[.+^${}()|[\]\\]/g, "\\$&").replace(/\*/g, ".*") + "$");
  return re.test(value);
}

/**
 * Check if an event passes the filter criteria.
 * @param {{ ts: string }} evt
 * @param {{ from?: Date, to?: Date, events?: string[], correlationId?: string }} filters
 * @returns {boolean}
 */
function passesFilter(evt, filters) {
  if (filters.from && new Date(evt.ts) < filters.from) return false;
  if (filters.to && new Date(evt.ts) > filters.to) return false;
  if (filters.correlationId && evt.correlationId !== filters.correlationId) return false;
  if (filters.events && filters.events.length > 0) {
    const matched = filters.events.some((pat) => matchEventGlob(pat, evt.event));
    if (!matched) return false;
  }
  return true;
}

// ─── Streaming JSONL reader ───────────────────────────────────────────

async function streamJsonl(filePath, mapFn, filters) {
  if (!existsSync(filePath)) return [];
  const results = [];
  const rl = createInterface({
    input: createReadStream(filePath, { encoding: "utf-8" }),
    crlfDelay: Infinity,
  });
  for await (const line of rl) {
    if (!line.trim()) continue;
    try {
      const record = JSON.parse(line);
      const evt = mapFn(record);
      if (evt && passesFilter(evt, filters)) results.push(evt);
    } catch { /* skip malformed */ }
  }
  return results;
}

// ─── Synchronous JSONL reader (small files) ───────────────────────────

function readJsonlSync(filePath, mapFn, filters) {
  if (!existsSync(filePath)) return [];
  const results = [];
  try {
    const raw = readFileSync(filePath, "utf-8");
    const lines = raw.split("\n").filter((l) => l.trim());
    for (const line of lines) {
      try {
        const record = JSON.parse(line);
        const evt = mapFn(record);
        if (evt && passesFilter(evt, filters)) results.push(evt);
      } catch { /* skip malformed */ }
    }
  } catch { /* file read error */ }
  return results;
}

// ─── Source: hub-event ────────────────────────────────────────────────

async function readHubEvents(cwd, filters) {
  const filePath = resolve(cwd, ".forge", "hub-events.jsonl");
  return streamJsonl(filePath, (rec) => ({
    ts: rec.timestamp || "",
    source: "hub-event",
    event: rec.type || "unknown",
    correlationId: rec._correlationId || rec.correlationId || rec.data?.correlationId || "",
    payload: rec.data || rec,
  }), filters);
}

// ─── Source: run ──────────────────────────────────────────────────────

async function readRunEvents(cwd, filters) {
  const runsDir = resolve(cwd, ".forge", "runs");
  const results = [];
  for (const runName of listDir(runsDir)) {
    const eventsLog = resolve(runsDir, runName, "events.log");
    if (!existsSync(eventsLog)) continue;
    const events = readJsonlSync(eventsLog, (rec) => ({
      ts: rec.timestamp || "",
      source: "run",
      event: rec.type || "unknown",
      correlationId: rec._correlationId || runName,
      payload: { sliceTitle: rec.sliceTitle, plan: rec.plan, message: rec.message, ...rec },
    }), filters);
    results.push(...events);
  }
  return results;
}

// ─── Source: memory ──────────────────────────────────────────────────

async function readMemories(cwd, filters) {
  const filePath = resolve(cwd, ".forge", "liveguard-memories.jsonl");
  return streamJsonl(filePath, (rec) => ({
    ts: rec.timestamp || "",
    source: "memory",
    event: "memory-captured",
    correlationId: rec._correlationId || rec.correlationId || "",
    payload: { tags: rec.tags, summary: rec.summary, content: rec.content },
  }), filters);
}

// ─── Source: openbrain ───────────────────────────────────────────────

async function readOpenBrain(cwd, filters) {
  const filePath = resolve(cwd, ".forge", "openbrain-queue.jsonl");
  return readJsonlSync(filePath, (rec) => ({
    ts: rec.timestamp || "",
    source: "openbrain",
    event: rec.status || rec.type || "queued",
    correlationId: rec._correlationId || rec.correlationId || "",
    payload: rec,
  }), filters);
}

// ─── Source: watch ───────────────────────────────────────────────────

async function readWatchHistory(cwd, filters) {
  const filePath = resolve(cwd, ".forge", "watch-history.jsonl");
  return readJsonlSync(filePath, (rec) => ({
    ts: rec.timestamp || "",
    source: "watch",
    event: rec.anomalyName || rec.type || "watch-event",
    correlationId: rec._correlationId || rec.correlationId || "",
    payload: rec,
  }), filters);
}

// ─── Source: tempering ──────────────────────────────────────────────

async function readTempering(cwd, filters) {
  const dir = resolve(cwd, ".forge", "tempering");
  const results = [];
  for (const file of listDir(dir).filter((f) => f.endsWith(".json"))) {
    const data = safeReadJson(resolve(dir, file));
    if (!data) continue;
    const runId = basename(file, ".json");
    const corrId = data.correlationId || data._correlationId || runId;

    // Unroll runSteps if present
    if (Array.isArray(data.runSteps)) {
      for (const step of data.runSteps) {
        const evt = {
          ts: step.timestamp || step.startedAt || data.timestamp || fileMtime(resolve(dir, file)),
          source: "tempering",
          event: step.status === "passed" ? "step-passed" : step.status === "failed" ? "step-failed" : "step-started",
          correlationId: corrId,
          payload: { scanner: step.scanner, summary: step.summary, ...step },
        };
        if (passesFilter(evt, filters)) results.push(evt);
      }
    } else {
      const evt = {
        ts: data.timestamp || fileMtime(resolve(dir, file)),
        source: "tempering",
        event: data.status || "tempering-run",
        correlationId: corrId,
        payload: data,
      };
      if (passesFilter(evt, filters)) results.push(evt);
    }
  }
  return results;
}

// ─── Source: bug ─────────────────────────────────────────────────────

async function readBugs(cwd, filters) {
  const dir = resolve(cwd, ".forge", "bugs");
  const results = [];
  for (const file of listDir(dir).filter((f) => f.endsWith(".json"))) {
    const data = safeReadJson(resolve(dir, file));
    if (!data) continue;
    const bugId = basename(file, ".json");
    const corrId = data.correlationId || data._correlationId || bugId;
    const eventType = data.status === "resolved" ? "bug-resolved" : "bug-registered";
    const evt = {
      ts: data.registeredAt || data.timestamp || data.createdAt || fileMtime(resolve(dir, file)),
      source: "bug",
      event: eventType,
      correlationId: corrId,
      payload: { title: data.title, severity: data.severity, status: data.status, ...data },
    };
    if (passesFilter(evt, filters)) results.push(evt);
  }
  return results;
}

// ─── Source: forge-master ────────────────────────────────────────────

async function readForgeMasterSessions(cwd, filters) {
  const sessDir = resolve(cwd, ".forge", "fm-sessions");
  if (!existsSync(sessDir)) return [];

  const files = listDir(sessDir).filter((f) => f.endsWith(".jsonl"));
  const seen = new Set(); // dedupe across archive + active during rotation
  const results = [];

  for (const file of files) {
    // Derive sessionId: strip .archive.jsonl or .jsonl suffix
    const sessionId = file.replace(/\.archive\.jsonl$/, "").replace(/\.jsonl$/, "");
    const filePath = resolve(sessDir, file);

    const events = await streamJsonl(filePath, (rec) => {
      const dedupeKey = `${sessionId}:${rec.turn}`;
      if (seen.has(dedupeKey)) return null;
      seen.add(dedupeKey);

      const lane = rec.classification?.lane || rec.classification || "";
      const msgPreview = typeof rec.userMessage === "string"
        ? rec.userMessage.slice(0, 200)
        : "";

      return {
        ts: rec.timestamp || "",
        source: "forge-master",
        event: "fm-turn",
        correlationId: sessionId,
        payload: { turn: rec.turn, lane, userMessage: msgPreview },
      };
    }, filters);

    results.push(...events);
  }

  return results;
}

// ─── Source: incident ───────────────────────────────────────────────

async function readIncidents(cwd, filters) {
  const dir = resolve(cwd, ".forge", "incidents");
  const results = [];
  for (const file of listDir(dir).filter((f) => f.endsWith(".json"))) {
    const data = safeReadJson(resolve(dir, file));
    if (!data) continue;
    const id = basename(file, ".json");
    const corrId = data.correlationId || data._correlationId || id;
    const eventType = data.resolvedAt ? "incident-resolved" : "incident-opened";
    const evt = {
      ts: data.openedAt || data.timestamp || data.createdAt || fileMtime(resolve(dir, file)),
      source: "incident",
      event: eventType,
      correlationId: corrId,
      payload: { title: data.title, severity: data.severity, summary: data.summary, ...data },
    };
    if (passesFilter(evt, filters)) results.push(evt);
  }
  return results;
}

// ─── Source Registry ─────────────────────────────────────────────────

export const TIMELINE_SOURCES = {
  "hub-event": { read: readHubEvents },
  "run": { read: readRunEvents },
  "memory": { read: readMemories },
  "openbrain": { read: readOpenBrain },
  "watch": { read: readWatchHistory },
  "tempering": { read: readTempering },
  "bug": { read: readBugs },
  "incident": { read: readIncidents },
  "forge-master": { read: readForgeMasterSessions },
};

/**
 * Plan Forge — Update Notifier (Phase UPDATE-01).
 *
 * Non-intrusive check against the GitHub Releases API for a newer Plan Forge
 * release. Runs at most once per 24h per project, honors an opt-out env var,
 * and *never* throws — network failure or API hiccup returns `null` and the
 * caller silently continues.
 *
 * Separation of concerns:
 *   - This module does HTTP + cache + semver only.
 *   - Dashboard rendering and REST exposure live in server.mjs / app.js.
 */

import { existsSync, mkdirSync, readFileSync, statSync, writeFileSync } from "node:fs";
import { resolve } from "node:path";

const RELEASES_URL = "https://api.github.com/repos/srnichols/plan-forge/releases/latest";
const DEFAULT_TTL_MS = 24 * 60 * 60 * 1000; // 24h
const FETCH_TIMEOUT_MS = 4000;

export function cachePath(projectDir) {
  return resolve(projectDir, ".forge", "update-check.json");
}

/**
 * Resolve the framework's own version — the VERSION file shipped with the
 * running install. Always reads from the install's repo root (computed from
 * `serverDir`) so the answer is independent of `PROJECT_DIR`, the user's
 * `cwd`, and any stale literals baked into source.
 *
 * Resolution order (first match wins):
 *   1. `<serverDir>/../VERSION`  — repo root when server.mjs lives in `pforge-mcp/`
 *   2. `<serverDir>/VERSION`     — server.mjs at repo root (defensive)
 *   3. `<projectDir>/VERSION`    — caller-provided fallback (legacy callers)
 *   4. `"unknown"`               — never throws, never invents a number
 *
 * Issue #106: previously the MCP handshake hard-coded "2.12.3" and the
 * capabilities generator fell back to "2.14.0" when VERSION was missing.
 * Both produced stale or fictitious version strings in the boot log,
 * dashboard, and `/api/version` endpoint after self-update. This helper
 * collapses all framework-version reads to a single source of truth.
 *
 * @param {{ serverDir: string, projectDir?: string|null }} opts
 * @returns {string} bare version string ("2.81.0", "2.82.0-dev", or "unknown")
 */
export function resolveFrameworkVersion({ serverDir, projectDir = null } = {}) {
  if (!serverDir || typeof serverDir !== "string") return "unknown";
  const candidates = [
    resolve(serverDir, "..", "VERSION"),
    resolve(serverDir, "VERSION"),
  ];
  if (projectDir && typeof projectDir === "string") {
    candidates.push(resolve(projectDir, "VERSION"));
  }
  for (const path of candidates) {
    try {
      if (existsSync(path)) {
        const v = readFileSync(path, "utf-8").trim();
        if (v) return v.replace(/^v/i, "");
      }
    } catch { /* keep looking */ }
  }
  return "unknown";
}

/**
 * Compare two semver-like version strings. Returns:
 *   -1  if `a` < `b`
 *    0  if equal
 *    1  if `a` > `b`
 * Tolerates leading `v` and `-dev` / `-rc.*` suffixes (suffix is treated as
 * older than the bare release per semver precedence).
 */
export function compareVersions(a, b) {
  const parse = (v) => {
    const clean = String(v || "").trim().replace(/^v/i, "");
    const [core, pre] = clean.split("-", 2);
    const parts = core.split(".").map((p) => Number.parseInt(p, 10));
    while (parts.length < 3) parts.push(0);
    return { parts: parts.slice(0, 3), pre: pre || null };
  };
  const pa = parse(a);
  const pb = parse(b);
  for (let i = 0; i < 3; i++) {
    const da = pa.parts[i] || 0;
    const db = pb.parts[i] || 0;
    if (!Number.isFinite(da) || !Number.isFinite(db)) return 0;
    if (da < db) return -1;
    if (da > db) return 1;
  }
  // Pre-release precedence: any pre-release is lower than no pre-release
  if (pa.pre && !pb.pre) return -1;
  if (!pa.pre && pb.pre) return 1;
  if (pa.pre && pb.pre) return pa.pre < pb.pre ? -1 : pa.pre > pb.pre ? 1 : 0;
  return 0;
}

function readCache(projectDir) {
  const path = cachePath(projectDir);
  if (!existsSync(path)) return null;
  try { return JSON.parse(readFileSync(path, "utf-8")); }
  catch { return null; }
}

function writeCache(projectDir, payload) {
  const path = cachePath(projectDir);
  try {
    mkdirSync(resolve(projectDir, ".forge"), { recursive: true });
    writeFileSync(path, JSON.stringify(payload, null, 2), "utf-8");
  } catch { /* best-effort; cache is not critical */ }
}

function updateCheckSuppressed(env) {
  return env.PFORGE_NO_UPDATE_CHECK === "1" || env.PFORGE_NO_UPDATE_CHECK === "true";
}

function cachedUpdatePayload(cached, currentVersion) {
  return {
    ...cached,
    current: currentVersion,
    isNewer: compareVersions(currentVersion, cached.latest) < 0,
    fromCache: true,
  };
}

function versionFileNewerThanCache(projectDir) {
  const versionFile = resolve(projectDir, "VERSION");
  const cacheFile = cachePath(projectDir);
  if (!existsSync(versionFile) || !existsSync(cacheFile)) return false;
  return statSync(versionFile).mtimeMs > statSync(cacheFile).mtimeMs;
}

function readFreshCachedUpdate(projectDir, currentVersion, ttlMs) {
  const cached = readCache(projectDir);
  if (!cached?.checkedAt) return null;
  const age = Date.now() - new Date(cached.checkedAt).getTime();
  if (!Number.isFinite(age) || age < 0 || age >= ttlMs) return null;
  try {
    return versionFileNewerThanCache(projectDir) ? null : cachedUpdatePayload(cached, currentVersion);
  } catch {
    return cachedUpdatePayload(cached, currentVersion);
  }
}

async function fetchLatestRelease(fetchImpl) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), FETCH_TIMEOUT_MS);
  try {
    const res = await fetchImpl(RELEASES_URL, {
      headers: {
        accept: "application/vnd.github+json",
        "user-agent": "plan-forge-update-check",
      },
      signal: controller.signal,
    });
    if (!res || !res.ok) return null;
    return await res.json();
  } catch {
    return null;
  } finally {
    clearTimeout(timer);
  }
}

function buildUpdatePayload(currentVersion, json) {
  const tag = typeof json?.tag_name === "string" ? json.tag_name : null;
  if (!tag) return null;
  const latest = tag.replace(/^v/i, "").trim();
  if (!/^\d+\.\d+\.\d+/.test(latest)) return null;
  return {
    current: currentVersion,
    latest,
    isNewer: compareVersions(currentVersion, latest) < 0,
    url: typeof json.html_url === "string" ? json.html_url : `https://github.com/srnichols/plan-forge/releases/tag/${tag}`,
    publishedAt: typeof json.published_at === "string" ? json.published_at : null,
    checkedAt: new Date().toISOString(),
    fromCache: false,
  };
}

/**
 * Check GitHub for a newer release. Returns:
 *   {
 *     current: "2.37.0",
 *     latest:  "2.38.0",
 *     isNewer: true,
 *     url:     "https://github.com/.../releases/tag/v2.38.0",
 *     publishedAt: "2026-04-25T12:34:56Z",
 *     checkedAt:   "2026-04-19T01:00:00Z",
 *     fromCache: false,
 *   }
 *
 * Returns `null` when the check is suppressed (env var), the network is
 * unavailable, or the response is malformed. Never throws.
 *
 * @param {object} opts
 * @param {string} opts.currentVersion
 * @param {string} opts.projectDir
 * @param {boolean} [opts.force=false]   Bypass the TTL.
 * @param {number}  [opts.ttlMs]         Override cache TTL (for tests).
 * @param {typeof fetch} [opts.fetchImpl] Inject fetch (for tests).
 * @param {NodeJS.ProcessEnv} [opts.env] Inject env (for tests).
 */
export async function checkForUpdate({
  currentVersion,
  projectDir,
  force = false,
  ttlMs = DEFAULT_TTL_MS,
  fetchImpl = globalThis.fetch,
  env = process.env,
} = {}) {
  if (updateCheckSuppressed(env) || !currentVersion || !projectDir) return null;
  if (!force) {
    const cached = readFreshCachedUpdate(projectDir, currentVersion, ttlMs);
    if (cached) return cached;
  }
  if (typeof fetchImpl !== "function") return null;

  const payload = buildUpdatePayload(currentVersion, await fetchLatestRelease(fetchImpl));
  if (!payload) return null;
  writeCache(projectDir, payload);
  return payload;
}

/**
 * Detect a "corrupt install" — a client running from a release tarball whose
 * VERSION file ends in `-dev` despite a matching bare release existing on GitHub.
 *
 * Root cause: tags v2.50.0, v2.51.0, v2.52.0 were published with VERSION=`X.Y.Z-dev`
 * baked into the tarball. Any client who installed those releases sees `-dev`
 * locally and never heals on their own because `pforge update` skips same-hash
 * files and some paths read version from `.forge.json` templateVersion.
 *
 * Detection rule (conservative — only flags known-bad states):
 *   - current ends in `-dev`
 *   - AND a bare release with core ≥ current's core exists on GitHub
 *
 * A genuine `-dev` working branch ahead of the latest release (e.g. local
 * 2.54.0-dev while latest is 2.53.1) returns { isCorrupt: false } because its
 * core (2.54.0) is newer than latest (2.53.1).
 *
 * Returns:
 *   { isCorrupt: boolean, reason: string|null, current: string, latest: string|null, recommendedAction: string|null }
 *
 * Never throws. `latest` may be null if GitHub is unreachable — in that case
 * isCorrupt is false (err on the side of not alarming offline users).
 */
/**
 * Write a fresh cache entry after a successful self-update so the next
 * `checkForUpdate` returns `isNewer: false` without hitting the network.
 *
 * @param {string} projectDir  Project root (parent of `.forge/`).
 * @param {string} version     The version just installed.
 */
export function writeFreshCache(projectDir, version) {
  if (!projectDir || !version) return;
  const v = String(version).trim().replace(/^v/i, "");
  if (!/^\d+\.\d+\.\d+/.test(v)) return;
  writeCache(projectDir, {
    latest: v,
    checkedAt: new Date().toISOString(),
    url: `https://github.com/srnichols/plan-forge/releases/tag/v${v}`,
    publishedAt: null,
  });
}

export function detectCorruptInstall({ currentVersion, latestVersion } = {}) {
  const result = {
    isCorrupt: false,
    reason: null,
    current: currentVersion || null,
    latest: latestVersion || null,
    recommendedAction: null,
  };
  if (!currentVersion || typeof currentVersion !== "string") return result;

  const cur = String(currentVersion).trim();
  if (!/-dev\b/i.test(cur)) return result;

  if (!latestVersion || typeof latestVersion !== "string") return result;
  const latest = String(latestVersion).trim().replace(/^v/i, "");
  if (!/^\d+\.\d+\.\d+/.test(latest)) return result;

  // Compare bare cores: if latest >= current's core, current-dev is stale.
  const curCore = cur.replace(/^v/i, "").split("-")[0];
  if (!/^\d+\.\d+\.\d+/.test(curCore)) return result;

  // If latest bare release is newer than OR equal to current's core → corrupt.
  // (Equal means: current says "X.Y.Z-dev" and GitHub has released "X.Y.Z" — stale bytes.)
  const cmp = compareVersions(curCore, latest);
  if (cmp <= 0) {
    result.isCorrupt = true;
    result.reason = `Local VERSION '${cur}' ends in '-dev' but a matching bare release exists on GitHub (latest=v${latest}). This indicates a corrupt install from a broken release tarball (v2.50.0/v2.51.0/v2.52.0 shipped with '-dev' VERSION baked in).`;
    result.recommendedAction = `Run: pforge self-update --force`;
  }
  return result;
}

/**
 * Plan Forge — Update from GitHub (Phase AUTO-UPDATE-01, Slice 1).
 *
 * Shared helpers for `pforge update --from-github`. Both pforge.ps1 and
 * pforge.sh invoke this module via `node pforge-mcp/update-from-github.mjs`
 * with a JSON payload on stdin. Keeps download, verify, and audit logic
 * testable in JS instead of duplicated across shells.
 *
 * Separation of concerns:
 *   - This module handles: tag resolution, tarball download, gzip verify,
 *     SHA-256, size cap, audit log, config loading.
 *   - Shell scripts handle: argument parsing, tar extraction, file-copy
 *     (existing flow), cleanup, user prompts.
 */

import { createHash } from "node:crypto";
import { existsSync, mkdirSync, readFileSync, writeFileSync, appendFileSync, unlinkSync, createReadStream } from "node:fs";
import { resolve, join } from "node:path";

const RELEASES_URL = "https://api.github.com/repos/srnichols/plan-forge/releases/latest";
const TAGS_URL = "https://api.github.com/repos/srnichols/plan-forge/tags?per_page=100";
const TARBALL_BASE = "https://api.github.com/repos/srnichols/plan-forge/tarball";
const DEFAULT_MAX_TARBALL_BYTES = 52_428_800; // 50 MB
const DEFAULT_CACHE_DIR = ".forge/cache";
const CONNECT_TIMEOUT_MS = 4_000;
const TOTAL_TIMEOUT_MS = 30_000;

// ─── Error codes ─────────────────────────────────────────────────────
export class UpdateError extends Error {
  constructor(code, message, cause) {
    super(message);
    this.name = "UpdateError";
    this.code = code;
    if (cause) this.cause = cause;
  }
}

// ─── Config ──────────────────────────────────────────────────────────
export function loadFromGitHubConfig(projectDir) {
  const configPath = resolve(projectDir, ".forge.json");
  let cacheDir = DEFAULT_CACHE_DIR;
  let maxTarballBytes = DEFAULT_MAX_TARBALL_BYTES;

  if (existsSync(configPath)) {
    try {
      const config = JSON.parse(readFileSync(configPath, "utf-8"));
      const fg = config?.update?.fromGitHub;
      if (fg?.cacheDir && typeof fg.cacheDir === "string") cacheDir = fg.cacheDir;
      if (fg?.maxTarballBytes && typeof fg.maxTarballBytes === "number" && fg.maxTarballBytes > 0) {
        maxTarballBytes = fg.maxTarballBytes;
      }
    } catch { /* use defaults */ }
  }

  const resolved = resolve(projectDir, cacheDir);
  return { cacheDir: resolved, maxTarballBytes };
}

// ─── Tag resolution ──────────────────────────────────────────────────
export async function resolveTag({ tag, fetchImpl = globalThis.fetch, env = process.env } = {}) {
  if (tag && /^HEAD$/i.test(tag)) {
    throw new UpdateError("ERR_NO_HEAD_TAG", "Tag 'HEAD' is not allowed — this command is for releases, not dev builds.");
  }
  if (tag && !/^latest$/i.test(tag)) {
    return tag;
  }

  const headers = {
    accept: "application/vnd.github+json",
    "user-agent": "plan-forge-update",
  };
  if (env.GITHUB_TOKEN) headers.authorization = `token ${env.GITHUB_TOKEN}`;

  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), CONNECT_TIMEOUT_MS);

  let res;
  try {
    res = await fetchImpl(RELEASES_URL, { headers, signal: controller.signal });
  } catch (err) {
    clearTimeout(timer);
    if (err.name === "AbortError") {
      throw new UpdateError("ERR_NETWORK_TIMEOUT", "Timed out connecting to GitHub API.", err);
    }
    throw new UpdateError("ERR_NETWORK", `Network error: ${err.message}`, err);
  }
  clearTimeout(timer);

  if (res.status === 403) {
    throw new UpdateError("ERR_RATE_LIMITED", "GitHub API rate limit exceeded. Set GITHUB_TOKEN env var for higher limits.");
  }
  if (!res.ok) {
    throw new UpdateError("ERR_API", `GitHub API returned ${res.status}: ${res.statusText}`);
  }

  const json = await res.json();
  const tagName = json?.tag_name;
  if (!tagName || typeof tagName !== "string") {
    throw new UpdateError("ERR_API", "GitHub API response missing tag_name.");
  }
  return tagName;
}

// ─── Semver comparison ──────────────────────────────────────────────
// Parses "v1.2.3" / "1.2.3" into [1,2,3]. Returns null for non-semver tags
// (e.g., pre-release suffixes "v1.2.3-beta" are parsed as [1,2,3] and the
// suffix is preserved separately so stable > pre-release).
function parseSemver(tag) {
  if (typeof tag !== "string") return null;
  const m = tag.match(/^v?(\d+)\.(\d+)\.(\d+)(?:-([0-9A-Za-z.-]+))?$/);
  if (!m) return null;
  return {
    major: Number(m[1]),
    minor: Number(m[2]),
    patch: Number(m[3]),
    pre: m[4] || null,
  };
}

function compareSemver(a, b) {
  if (a.major !== b.major) return a.major - b.major;
  if (a.minor !== b.minor) return a.minor - b.minor;
  if (a.patch !== b.patch) return a.patch - b.patch;
  // Stable (no pre) ranks higher than pre-release.
  if (!a.pre && b.pre) return 1;
  if (a.pre && !b.pre) return -1;
  if (a.pre && b.pre) return a.pre < b.pre ? -1 : a.pre > b.pre ? 1 : 0;
  return 0;
}

// ─── Drift detection ─────────────────────────────────────────────────
// Fetches /tags and returns the newest stable semver tag. Used to detect
// the case where tags have been pushed but no GitHub Release was cut —
// /releases/latest then silently returns an older version than HEAD.
// Returns null on network failure or no parseable tags (non-fatal).
export async function fetchNewestSemverTag({ fetchImpl = globalThis.fetch, env = process.env } = {}) {
  const headers = {
    accept: "application/vnd.github+json",
    "user-agent": "plan-forge-update",
  };
  if (env.GITHUB_TOKEN) headers.authorization = `token ${env.GITHUB_TOKEN}`;

  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), CONNECT_TIMEOUT_MS);
  let res;
  try {
    res = await fetchImpl(TAGS_URL, { headers, signal: controller.signal });
  } catch {
    clearTimeout(timer);
    return null;
  }
  clearTimeout(timer);

  if (!res.ok) return null;
  let tags;
  try { tags = await res.json(); } catch { return null; }
  if (!Array.isArray(tags)) return null;

  let newest = null;
  let newestName = null;
  for (const t of tags) {
    const parsed = parseSemver(t?.name);
    if (!parsed) continue;
    // Skip pre-releases — we only want stable tags for drift comparison.
    if (parsed.pre) continue;
    if (!newest || compareSemver(parsed, newest) > 0) {
      newest = parsed;
      newestName = t.name;
    }
  }
  return newestName;
}

// Returns { drift: boolean, newestTag, releaseTag, message }. Non-null only
// when a newer stable tag exists than the resolved Release tag.
export async function checkLatestDrift(resolvedReleaseTag, opts = {}) {
  const releaseSemver = parseSemver(resolvedReleaseTag);
  if (!releaseSemver) return null;
  const newestTag = await fetchNewestSemverTag(opts);
  if (!newestTag) return null;
  const newestSemver = parseSemver(newestTag);
  if (!newestSemver) return null;
  if (compareSemver(newestSemver, releaseSemver) <= 0) return null;
  return {
    drift: true,
    newestTag,
    releaseTag: resolvedReleaseTag,
    message: `GitHub tag ${newestTag} exists but the latest published Release is ${resolvedReleaseTag}. ` +
             `The source repo pushed tags without cutting Releases — you are getting an older version. ` +
             `Re-run with --tag ${newestTag} to fetch the newest tag, or ask the maintainer to publish the missing Release(s).`,
  };
}

// ─── URL builder ─────────────────────────────────────────────────────
export function buildTarballUrl(tag) {
  return `${TARBALL_BASE}/${tag}`;
}

// ─── Gzip verification ──────────────────────────────────────────────
export function verifyGzip(buffer) {
  if (!buffer || buffer.length < 2) return false;
  return buffer[0] === 0x1f && buffer[1] === 0x8b;
}

// ─── SHA-256 ─────────────────────────────────────────────────────────
export function computeSha256(filePath) {
  const hash = createHash("sha256");
  const data = readFileSync(filePath);
  hash.update(data);
  return hash.digest("hex");
}

// ─── Tarball download ────────────────────────────────────────────────
export async function downloadTarball({
  tag,
  cacheDir,
  maxTarballBytes = DEFAULT_MAX_TARBALL_BYTES,
  fetchImpl = globalThis.fetch,
  env = process.env,
} = {}) {
  mkdirSync(cacheDir, { recursive: true });
  const destPath = join(cacheDir, `update-${tag.replace(/[^a-zA-Z0-9._-]/g, "_")}.tar.gz`);
  const url = buildTarballUrl(tag);

  const headers = {
    accept: "application/vnd.github+json",
    "user-agent": "plan-forge-update",
  };
  if (env.GITHUB_TOKEN) headers.authorization = `token ${env.GITHUB_TOKEN}`;

  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), TOTAL_TIMEOUT_MS);

  let res;
  try {
    res = await fetchImpl(url, { headers, signal: controller.signal, redirect: "follow" });
  } catch (err) {
    clearTimeout(timer);
    _cleanupPartial(destPath);
    if (err.name === "AbortError") {
      throw new UpdateError("ERR_NETWORK_TIMEOUT", "Timed out downloading tarball.", err);
    }
    throw new UpdateError("ERR_NETWORK", `Network error during download: ${err.message}`, err);
  }

  if (res.status === 404) {
    clearTimeout(timer);
    throw new UpdateError("ERR_TAG_NOT_FOUND", `Tag '${tag}' not found on GitHub.`);
  }
  if (res.status === 403) {
    clearTimeout(timer);
    throw new UpdateError("ERR_RATE_LIMITED", "GitHub API rate limit exceeded. Set GITHUB_TOKEN env var for higher limits.");
  }
  if (!res.ok) {
    clearTimeout(timer);
    throw new UpdateError("ERR_DOWNLOAD", `Download failed with status ${res.status}: ${res.statusText}`);
  }

  // Stream the response body, enforcing the size cap
  const chunks = [];
  let totalBytes = 0;

  try {
    if (res.body && typeof res.body[Symbol.asyncIterator] === "function") {
      for await (const chunk of res.body) {
        totalBytes += chunk.length;
        if (totalBytes > maxTarballBytes) {
          controller.abort();
          clearTimeout(timer);
          _cleanupPartial(destPath);
          throw new UpdateError(
            "ERR_TARBALL_TOO_LARGE",
            `Tarball exceeds ${maxTarballBytes} bytes (received ${totalBytes} so far). Aborting.`
          );
        }
        chunks.push(chunk);
      }
    } else {
      // Fallback: read as arrayBuffer (works in all fetch implementations)
      const ab = await res.arrayBuffer();
      totalBytes = ab.byteLength;
      if (totalBytes > maxTarballBytes) {
        clearTimeout(timer);
        throw new UpdateError(
          "ERR_TARBALL_TOO_LARGE",
          `Tarball is ${totalBytes} bytes, exceeds ${maxTarballBytes} byte limit.`
        );
      }
      chunks.push(Buffer.from(ab));
    }
  } catch (err) {
    clearTimeout(timer);
    _cleanupPartial(destPath);
    if (err instanceof UpdateError) throw err;
    if (err.name === "AbortError") {
      throw new UpdateError("ERR_NETWORK_TIMEOUT", "Timed out downloading tarball.", err);
    }
    throw new UpdateError("ERR_NETWORK", `Download stream error: ${err.message}`, err);
  }
  clearTimeout(timer);

  const buffer = Buffer.concat(chunks);

  if (!verifyGzip(buffer)) {
    throw new UpdateError("ERR_INVALID_GZIP", "Downloaded file is not valid gzip (magic bytes mismatch).");
  }

  writeFileSync(destPath, buffer);
  const sha256 = computeSha256(destPath);

  return { path: destPath, sha256, sizeBytes: totalBytes };
}

function _cleanupPartial(path) {
  try { if (existsSync(path)) unlinkSync(path); } catch { /* best-effort */ }
}

// ─── Audit log ───────────────────────────────────────────────────────
export function appendAuditLog(projectDir, entry) {
  const logPath = resolve(projectDir, ".forge", "update-audit.log");
  mkdirSync(resolve(projectDir, ".forge"), { recursive: true });
  const line = JSON.stringify({
    ts: new Date().toISOString(),
    from: "github",
    ...entry,
  });
  appendFileSync(logPath, line + "\n", "utf-8");
}

// ─── CLI entry point ─────────────────────────────────────────────────
// Invoked by pforge.ps1/pforge.sh as:
//   node pforge-mcp/update-from-github.mjs <action> [--tag <tag>] [--project-dir <dir>]
//
// Actions:
//   resolve-tag   → prints resolved tag to stdout
//   download      → downloads tarball, prints JSON {path, sha256, sizeBytes}
//   audit         → appends audit log entry (reads JSON from stdin)

async function main() {
  const args = process.argv.slice(2);
  const action = args[0];

  let tag = null;
  let projectDir = process.cwd();

  for (let i = 1; i < args.length; i++) {
    if (args[i] === "--tag" && args[i + 1]) { tag = args[++i]; continue; }
    if (args[i] === "--project-dir" && args[i + 1]) { projectDir = args[++i]; continue; }
  }

  try {
    if (action === "resolve-tag") {
      const wasLatest = !tag || /^latest$/i.test(tag);
      const resolved = await resolveTag({ tag });
      const out = { ok: true, tag: resolved };
      // Only probe for drift when caller asked for "latest" — if they
      // pinned an explicit tag, they already know what they want.
      if (wasLatest) {
        try {
          const drift = await checkLatestDrift(resolved);
          if (drift) out.warning = drift;
        } catch { /* drift check is advisory — never fail resolve-tag over it */ }
      }
      process.stdout.write(JSON.stringify(out) + "\n");
    } else if (action === "download") {
      const config = loadFromGitHubConfig(projectDir);
      if (!tag) { process.stderr.write("ERROR: --tag required for download\n"); process.exit(1); }
      const result = await downloadTarball({
        tag,
        cacheDir: config.cacheDir,
        maxTarballBytes: config.maxTarballBytes,
      });
      process.stdout.write(JSON.stringify({ ok: true, ...result }) + "\n");
    } else if (action === "audit") {
      // Read entry from stdin
      const chunks = [];
      process.stdin.setEncoding("utf-8");
      for await (const chunk of process.stdin) { chunks.push(chunk); }
      const entry = JSON.parse(chunks.join(""));
      appendAuditLog(projectDir, entry);
      process.stdout.write(JSON.stringify({ ok: true }) + "\n");
    } else {
      process.stderr.write(`Unknown action: ${action}\nUsage: update-from-github.mjs <resolve-tag|download|audit>\n`);
      process.exit(1);
    }
  } catch (err) {
    const out = {
      ok: false,
      code: err.code || "ERR_UNKNOWN",
      message: err.message,
    };
    process.stdout.write(JSON.stringify(out) + "\n");
    process.exit(1);
  }
}

// Run CLI if invoked directly
const _thisFile = new URL(import.meta.url).pathname.replace(/^\/([A-Z]:)/i, "$1");
const _argFile = process.argv[1] ? resolve(process.argv[1]) : "";
const isMainModule = _argFile && resolve(_thisFile) === _argFile;
if (isMainModule) {
  main();
}

/**
 * Plan Forge — Watcher Module (Phase-39 Slice 3)
 *
 * Provides `buildCrossRunSnapshot(rootDir, opts)` — aggregates historical
 * `.forge/runs/{runId}/summary.json` files into a cross-run health snapshot that
 * feeds the existing `detectWatchAnomalies()` + `recommendFromAnomalies()`
 * pipeline in orchestrator.mjs.
 *
 * Contract: all exports are pure computation (no LLM calls, no disk writes).
 *
 * New anomaly codes produced via crossRun snapshot:
 *   cross-run.recurring-gate-failure  — same slice failed in ≥2 runs
 *   cross-run.retry-rate-spike        — avg retries/slice > 2 across runs
 *   cross-run.cost-anomaly-trend      — cost trend up >20% vs earlier window
 *   cross-run.slice-timeout-cluster   — same slice timed out in ≥2 runs
 */

import { readdirSync, readFileSync, existsSync } from "node:fs";
import { resolve } from "node:path";

const MS_PER_DAY = 24 * 60 * 60 * 1000;

/**
 * Parse a window string like "14d", "7d", "30d" into milliseconds.
 * Falls back to 14 days for unrecognised formats.
 *
 * @param {string} [window="14d"]
 * @returns {number} Milliseconds
 */
export function parseWindowMs(window = "14d") {
  const match = String(window).match(/^(\d+)d$/);
  return match ? parseInt(match[1], 10) * MS_PER_DAY : 14 * MS_PER_DAY;
}

/**
 * Aggregate historical run summaries into a cross-run health snapshot.
 *
 * Reads all `.forge/runs/{runId}/summary.json` files whose `startTime` falls
 * within the requested window, then computes:
 *   - Per-slice failure-mode buckets
 *   - Retry rate trend
 *   - Cost trend (first-half vs second-half of window)
 *   - Slice timeout clusters
 *
 * The returned `crossRun` sub-object is consumed by `detectWatchAnomalies()`.
 * The top-level shape (`{ ok, anomalies, recommendations, snapshot }`) is
 * compatible with the existing `forge_watch` callers — no breaking change.
 *
 * @param {string} rootDir - Project root containing `.forge/runs/`
 * @param {object} [opts={}]
 * @param {string} [opts.window="14d"] - Lookback window (e.g. "7d", "14d", "30d")
 * @returns {Promise<object>} Cross-run snapshot
 */
function readRunSummaries(runsDir, cutoffMs) {
  const summaries = [];
  const entries = readdirSync(runsDir, { withFileTypes: true });
  for (const entry of entries) {
    if (!entry.isDirectory()) continue;
    const summaryPath = resolve(runsDir, entry.name, "summary.json");
    if (!existsSync(summaryPath)) continue;
    try {
      const raw = JSON.parse(readFileSync(summaryPath, "utf-8"));
      const startMs = raw.startTime ? new Date(raw.startTime).getTime() : NaN;
      if (!Number.isFinite(startMs) || startMs < cutoffMs) continue;
      summaries.push({ runId: entry.name, ...raw });
    } catch {
      // Skip unreadable or malformed summary files
    }
  }
  return summaries;
}

function emptyCrossRunSnapshot(rootDir, runsDir, window, windowMs) {
  return {
    ok: true,
    mode: "cross-run",
    targetPath: rootDir,
    window,
    windowMs,
    totalRuns: 0,
    passedRuns: 0,
    failedRuns: 0,
    runs: [],
    message: `No completed runs found within the last ${window} under ${runsDir}. Try a wider window or run a plan first.`,
    crossRun: {
      recurringFailures: [],
      retryRateSpike: false,
      costTrend: "flat",
      costTrendPercent: 0,
      sliceTimeoutClusters: [],
    },
  };
}

function sliceKey(sr) {
  const label = (sr.title ?? "slice").replace(/\s+/g, "-").slice(0, 40);
  return `${sr.number ?? "?"}-${label}`;
}

function isSliceTimeout(sr) {
  return (sr.duration != null && sr.duration > 5 * 60_000)
    || sr.killedBySignal === true
    || (typeof sr.statusReason === "string" && sr.statusReason.toLowerCase().includes("timeout"));
}

function aggregateSliceStats(summaries) {
  const sliceFailMap = {};
  const sliceRetryMap = {};
  const sliceTimeoutMap = {};
  for (const run of summaries) {
    if (!Array.isArray(run.sliceResults)) continue;
    for (const sr of run.sliceResults) {
      const key = sliceKey(sr);
      if (!sliceFailMap[key]) sliceFailMap[key] = { failCount: 0, totalCount: 0, runIds: [] };
      sliceFailMap[key].totalCount++;
      if (sr.status === "failed") {
        sliceFailMap[key].failCount++;
        if (!sliceFailMap[key].runIds.includes(run.runId)) sliceFailMap[key].runIds.push(run.runId);
      }
      if (!sliceRetryMap[key]) sliceRetryMap[key] = { totalAttempts: 0, occurrences: 0 };
      sliceRetryMap[key].totalAttempts += typeof sr.attempts === "number" ? sr.attempts : 1;
      sliceRetryMap[key].occurrences++;
      if (isSliceTimeout(sr)) sliceTimeoutMap[key] = (sliceTimeoutMap[key] ?? 0) + 1;
    }
  }
  return { sliceFailMap, sliceRetryMap, sliceTimeoutMap };
}

function buildRecurringFailures(sliceFailMap) {
  return Object.entries(sliceFailMap)
    .filter(([, value]) => value.failCount >= 2)
    .map(([sliceName, value]) => ({ sliceName, failCount: value.failCount, totalCount: value.totalCount, runIds: value.runIds }))
    .sort((a, b) => b.failCount - a.failCount);
}

function hasRetryRateSpike(sliceRetryMap) {
  return Object.values(sliceRetryMap).some((value) => value.occurrences > 0 && value.totalAttempts / value.occurrences > 2);
}

function buildCostTrend(sorted) {
  const half = Math.floor(sorted.length / 2);
  if (half < 1) return { costTrend: "flat", costTrendPercent: 0 };
  const first = sorted.slice(0, half);
  const second = sorted.slice(half);
  const avgFirst = first.reduce((sum, run) => sum + (run.cost?.total_cost_usd ?? 0), 0) / first.length;
  const avgSecond = second.reduce((sum, run) => sum + (run.cost?.total_cost_usd ?? 0), 0) / second.length;
  if (avgFirst <= 0) return { costTrend: "flat", costTrendPercent: 0 };
  const costTrendPercent = Math.round(((avgSecond - avgFirst) / avgFirst) * 100);
  return {
    costTrend: costTrendPercent > 20 ? "up" : costTrendPercent < -20 ? "down" : "flat",
    costTrendPercent,
  };
}

function buildSliceTimeoutClusters(sliceTimeoutMap) {
  return Object.entries(sliceTimeoutMap)
    .filter(([, count]) => count >= 2)
    .map(([sliceName, timeoutCount]) => ({ sliceName, timeoutCount }))
    .sort((a, b) => b.timeoutCount - a.timeoutCount);
}

function summarizeRuns(sorted) {
  return sorted.map((run) => ({
    runId: run.runId,
    startTime: run.startTime,
    endTime: run.endTime ?? null,
    status: run.status ?? null,
    cost: run.cost?.total_cost_usd ?? null,
    sliceCount: run.results?.total ?? (run.sliceResults?.length ?? 0),
  }));
}

export async function buildCrossRunSnapshot(rootDir, opts = {}) {
  const { window = "14d" } = opts;
  const windowMs = parseWindowMs(window);
  const runsDir = resolve(rootDir, ".forge", "runs");
  if (!existsSync(runsDir)) {
    return { ok: false, mode: "cross-run", error: `No .forge/runs/ directory found at ${rootDir}` };
  }

  let summaries;
  try {
    summaries = readRunSummaries(runsDir, Date.now() - windowMs);
  } catch (err) {
    return { ok: false, mode: "cross-run", error: `Cannot read runs directory: ${err.message}` };
  }
  if (summaries.length === 0) return emptyCrossRunSnapshot(rootDir, runsDir, window, windowMs);

  const sorted = [...summaries].sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime());
  const { sliceFailMap, sliceRetryMap, sliceTimeoutMap } = aggregateSliceStats(summaries);
  const { costTrend, costTrendPercent } = buildCostTrend(sorted);

  return {
    ok: true,
    mode: "cross-run",
    targetPath: rootDir,
    window,
    windowMs,
    totalRuns: summaries.length,
    passedRuns: summaries.filter((s) => s.status === "completed").length,
    failedRuns: summaries.filter((s) => s.status === "failed").length,
    runs: summarizeRuns(sorted),
    crossRun: {
      recurringFailures: buildRecurringFailures(sliceFailMap),
      retryRateSpike: hasRetryRateSpike(sliceRetryMap),
      costTrend,
      costTrendPercent,
      sliceTimeoutClusters: buildSliceTimeoutClusters(sliceTimeoutMap),
    },
  };
}

/**
 * Plan Forge — Phase GITHUB-B Slice 1: Copilot Coding Agent dispatch worker.
 *
 * Exports:
 *   dispatchSlice(slice, opts)          → { issueNumber, issueUrl }
 *   pollPullRequest(issueNumber, opts)  → { prNumber, prUrl, status } | { status: "timeout" }
 *
 * Both functions shell out to `gh` (GitHub CLI) via spawnSync. Dependency-inject
 * `env` (containing a modified PATH) in tests to route `gh` to a mock binary.
 */

import { spawnSync } from "node:child_process";

// ─── Constants ────────────────────────────────────────────────────────────────

export const DEFAULT_POLL_INTERVAL_MS = 60_000;   // 60 s
export const DEFAULT_TIMEOUT_MS = 30 * 60 * 1000; // 30 min

// ─── Error type ───────────────────────────────────────────────────────────────

export class GhError extends Error {
  constructor(message, exitCode, stderr) {
    super(message);
    this.name = "GhError";
    this.exitCode = exitCode;
    this.stderr = stderr;
  }
}

// ─── Helpers ──────────────────────────────────────────────────────────────────

/**
 * Build a Markdown issue body from a slice descriptor.
 * Exported for unit tests.
 */
export function buildIssueBody(slice) {
  const parts = [];

  if (slice.goal) {
    parts.push(`## Goal\n${slice.goal}`);
  }

  if (slice.scope) {
    const text = Array.isArray(slice.scope) ? slice.scope.join("\n") : slice.scope;
    parts.push(`## Files in Scope\n${text}`);
  }

  if (slice.gate) {
    parts.push(`## Validation Gate\n\`\`\`\n${slice.gate}\n\`\`\``);
  }

  return parts.length > 0 ? parts.join("\n\n") : "*(no details)*";
}

/**
 * Low-level wrapper around spawnSync for `gh`.
 * On Windows, routes through cmd.exe to resolve `.cmd` shims without
 * triggering Node's DEP0190 deprecation (shell:true + array args).
 * Throws GhError on non-zero exit or spawn failure.
 */
function spawnGh(args, { cwd = process.cwd(), env = process.env } = {}) {
  const isWindows = process.platform === "win32";
  const cmd = isWindows ? "cmd" : "gh";
  const cmdArgs = isWindows ? ["/d", "/s", "/c", "gh", ...args] : args;

  const result = spawnSync(cmd, cmdArgs, {
    cwd,
    env,
    encoding: "utf8",
    windowsHide: isWindows,
  });

  if (result.error) {
    throw new GhError(
      `gh failed to start: ${result.error.message}`,
      -1,
      "",
    );
  }

  if (result.status !== 0) {
    const sub = args.slice(0, 2).join(" ");
    const detail = (result.stderr ?? "").trim();
    throw new GhError(
      `gh ${sub} exited ${result.status}${detail ? `: ${detail}` : ""}`,
      result.status,
      result.stderr ?? "",
    );
  }

  return result.stdout ?? "";
}

// ─── Public API ───────────────────────────────────────────────────────────────

/**
 * Create a GitHub Issue for a plan slice and assign it to @copilot.
 *
 * @param {{ title?: string, goal?: string, scope?: string|string[], gate?: string }} slice
 * @param {{ cwd?: string, env?: object, repo?: string }} opts
 * @returns {{ issueNumber: number, issueUrl: string }}
 */
export function dispatchSlice(slice, opts = {}) {
  const {
    cwd = process.cwd(),
    env = process.env,
    repo,
    _spawnGh = spawnGh,
  } = opts;

  const title = slice.title ?? "Untitled slice";
  const body = buildIssueBody(slice);

  const args = [
    "issue", "create",
    "--title", title,
    "--body", body,
    "--assignee", "@copilot",
  ];
  if (repo) args.push("--repo", repo);

  const stdout = _spawnGh(args, { cwd, env });

  // gh issue create outputs the issue URL on stdout: https://github.com/o/r/issues/42
  const url = stdout.trim();
  const match = url.match(/\/issues\/(\d+)$/);
  if (!match) {
    throw new Error(`Unexpected gh issue create output: ${JSON.stringify(url)}`);
  }

  return {
    issueNumber: parseInt(match[1], 10),
    issueUrl: url,
  };
}

/**
 * Poll for a PR linked to the given issue number.
 *
 * Tries `--search "linked:<n>"` first; falls back to `head:copilot/issue-<n>`.
 * Draft PRs are skipped (treated as not-yet-ready).
 *
 * @param {number} issueNumber
 * @param {{ cwd?: string, env?: object, repo?: string,
 *           intervalMs?: number, timeoutMs?: number }} opts
 * @returns {Promise<{ prNumber: number, prUrl: string, status: string }|{ status: "timeout" }>}
 */
export async function pollPullRequest(issueNumber, opts = {}) {
  const {
    cwd = process.cwd(),
    env = process.env,
    repo,
    intervalMs = DEFAULT_POLL_INTERVAL_MS,
    timeoutMs = DEFAULT_TIMEOUT_MS,
    _spawnGh = spawnGh,
    _sleep = (ms) => new Promise((r) => setTimeout(r, ms)),
  } = opts;

  const baseArgs = ["pr", "list", "--json", "number,url,state,isDraft"];
  if (repo) baseArgs.push("--repo", repo);

  const deadline = Date.now() + timeoutMs;

  while (Date.now() < deadline) {
    const spawnOpts = { cwd, env };

    // Primary: PRs linked to this issue
    const pr =
      tryFindPr([...baseArgs, "--search", `linked:${issueNumber}`], spawnOpts, _spawnGh) ??
      // Fallback: Copilot's conventional branch naming pattern
      tryFindPr([...baseArgs, "--search", `head:copilot/issue-${issueNumber}`], spawnOpts, _spawnGh);

    if (pr) {
      return {
        prNumber: pr.number,
        prUrl: pr.url,
        status: normalizePrState(pr.state),
      };
    }

    await _sleep(intervalMs);
  }

  return { status: "timeout" };
}

// ─── Internal helpers ─────────────────────────────────────────────────────────

function tryFindPr(args, spawnOpts, _spawnGh) {
  let stdout;
  try {
    stdout = _spawnGh(args, spawnOpts);
  } catch {
    return null;
  }

  let prs;
  try {
    prs = JSON.parse(stdout.trim() || "[]");
  } catch {
    return null;
  }

  if (!Array.isArray(prs)) return null;

  // Skip drafts — Copilot marks newly-opened PRs as draft until ready
  return prs.find((pr) => !pr.isDraft) ?? null;
}

function normalizePrState(state) {
  if (!state) return "open";
  const s = state.toLowerCase();
  if (s === "merged") return "merged";
  if (s === "closed") return "closed";
  return "open";
}

/**
 * Plan Forge — Worktree Manager (Phase-26 Slice 1)
 *
 * Pure filesystem + `git worktree` wrapper for competitive-slice execution.
 * Manages the lifecycle of per-variant workspaces under `.forge/worktrees/`
 * and archived losers under `.forge/worktrees-archive/`.
 *
 * Contract:
 *   - All paths stay inside `<projectDir>/.forge/worktrees{,-archive}/`.
 *   - Archive retention is capped by `runtime.competitive.archiveDays`
 *     (default 7) — `cleanupAgedArchives()` removes older entries.
 *   - Never writes to `refs/heads/`; only uses detached worktrees.
 *   - All inputs are sanitized with `sanitizeComponent()` (no `..`, no
 *     path separators, no control chars) before path assembly.
 *   - Opt-in: nothing in this module runs unless the orchestrator's
 *     CompetitiveScheduler (Slice 2) invokes it.
 *
 * @module worktree-manager
 */

import { mkdirSync, existsSync, statSync, readdirSync, renameSync, rmSync } from "node:fs";
import { resolve, join, isAbsolute } from "node:path";
import { spawnSync } from "node:child_process";

export const WORKTREES_DIR = ".forge/worktrees";
export const WORKTREES_ARCHIVE_DIR = ".forge/worktrees-archive";
export const DEFAULT_ARCHIVE_DAYS = 7;
export const MIN_VARIANTS = 2;
export const MAX_VARIANTS = 5;
export const DEFAULT_MAX_VARIANTS = 3;

/**
 * Sanitize a user-supplied path component to something safe to use
 * inside `.forge/worktrees/<plan>/<slice>/variant-<n>/`.
 *
 * Strips anything that isn't `[A-Za-z0-9._-]`, collapses `..` sequences
 * (defense against traversal), and caps length at 128. Mirrors
 * memory.mjs#sanitizePathComponent so trajectories + worktrees share
 * the same safety posture.
 *
 * @param {unknown} s
 * @returns {string}
 */
export function sanitizeComponent(s) {
  let cleaned = String(s ?? "").replace(/[^A-Za-z0-9._-]/g, "_");
  while (cleaned.includes("..")) {
    cleaned = cleaned.replace(/\.\./g, "_");
  }
  cleaned = cleaned.slice(0, 128);
  return cleaned.length > 0 ? cleaned : "_";
}

/**
 * Compute the absolute worktree path for a variant.
 * @param {string} projectDir absolute path to the repo root
 * @param {string} planBasename plan filename without extension
 * @param {string|number} sliceId
 * @param {number} variant 1-based variant index
 * @returns {string}
 */
export function variantPath(projectDir, planBasename, sliceId, variant) {
  if (!isAbsolute(projectDir)) {
    throw new Error("variantPath: projectDir must be absolute");
  }
  const n = Number(variant);
  if (!Number.isInteger(n) || n < 1 || n > MAX_VARIANTS) {
    throw new Error(`variantPath: variant must be integer in [1, ${MAX_VARIANTS}]`);
  }
  const p = join(
    projectDir,
    WORKTREES_DIR,
    sanitizeComponent(planBasename),
    sanitizeComponent(sliceId),
    `variant-${n}`,
  );
  const root = join(projectDir, WORKTREES_DIR);
  const resolved = resolve(p);
  if (!resolved.startsWith(resolve(root))) {
    throw new Error("variantPath: resolved path escapes worktrees root");
  }
  return resolved;
}

/**
 * Compute the absolute archive path for a variant.
 * @param {string} projectDir
 * @param {string} planBasename
 * @param {string|number} sliceId
 * @param {number} variant
 * @returns {string}
 */
export function archivePath(projectDir, planBasename, sliceId, variant) {
  if (!isAbsolute(projectDir)) {
    throw new Error("archivePath: projectDir must be absolute");
  }
  const n = Number(variant);
  if (!Number.isInteger(n) || n < 1 || n > MAX_VARIANTS) {
    throw new Error(`archivePath: variant must be integer in [1, ${MAX_VARIANTS}]`);
  }
  const p = join(
    projectDir,
    WORKTREES_ARCHIVE_DIR,
    sanitizeComponent(planBasename),
    sanitizeComponent(sliceId),
    `variant-${n}`,
  );
  const root = join(projectDir, WORKTREES_ARCHIVE_DIR);
  const resolved = resolve(p);
  if (!resolved.startsWith(resolve(root))) {
    throw new Error("archivePath: resolved path escapes archive root");
  }
  return resolved;
}

/**
 * Return the clamped, integer maxVariants value given a raw config input.
 * @param {unknown} raw
 * @returns {number}
 */
export function clampMaxVariants(raw) {
  if (raw === null || raw === undefined || raw === "") return DEFAULT_MAX_VARIANTS;
  const n = Number(raw);
  if (!Number.isFinite(n)) return DEFAULT_MAX_VARIANTS;
  const i = Math.trunc(n);
  if (i < MIN_VARIANTS) return MIN_VARIANTS;
  if (i > MAX_VARIANTS) return MAX_VARIANTS;
  return i;
}

/**
 * Create a git worktree at the computed variant path. Thin wrapper around
 * `git worktree add --detach`. Creates parent directories if needed.
 *
 * @param {object} opts
 * @param {string} opts.projectDir absolute path to repo root
 * @param {string} opts.planBasename
 * @param {string|number} opts.sliceId
 * @param {number} opts.variant
 * @param {string} [opts.baseRef="HEAD"] ref the worktree starts from
 * @param {(cmd: string, args: string[], options?: object) => {status: number|null, stdout?: string|Buffer, stderr?: string|Buffer}} [opts.spawn]
 *        Inject a spawn implementation (tests override; defaults to spawnSync).
 * @returns {{ path: string, baseRef: string }}
 */
export function createWorktree({
  projectDir,
  planBasename,
  sliceId,
  variant,
  baseRef = "HEAD",
  spawn = spawnSync,
}) {
  const path = variantPath(projectDir, planBasename, sliceId, variant);
  if (existsSync(path)) {
    throw new Error(`createWorktree: path already exists: ${path}`);
  }
  mkdirSync(join(path, ".."), { recursive: true });
  const result = spawn(
    "git",
    ["worktree", "add", "--detach", path, baseRef],
    { cwd: projectDir, encoding: "utf8" },
  );
  if (!result || result.status !== 0) {
    const stderr = result?.stderr ? String(result.stderr) : "";
    throw new Error(
      `createWorktree: git worktree add failed (status=${result?.status ?? "?"}): ${stderr.slice(0, 500)}`,
    );
  }
  return { path, baseRef };
}

/**
 * Archive a variant worktree — moves the directory from
 * `.forge/worktrees/<plan>/<slice>/variant-<n>` to
 * `.forge/worktrees-archive/<plan>/<slice>/variant-<n>`. Also removes the
 * worktree registration with `git worktree remove --force` so git stops
 * tracking it. Safe to call on an already-archived variant (no-op).
 *
 * @param {object} opts
 * @param {string} opts.projectDir
 * @param {string} opts.planBasename
 * @param {string|number} opts.sliceId
 * @param {number} opts.variant
 * @param {Function} [opts.spawn]
 * @returns {{ archived: boolean, from: string, to: string }}
 */
export function archiveWorktree({
  projectDir,
  planBasename,
  sliceId,
  variant,
  spawn = spawnSync,
}) {
  const from = variantPath(projectDir, planBasename, sliceId, variant);
  const to = archivePath(projectDir, planBasename, sliceId, variant);
  if (!existsSync(from)) {
    return { archived: false, from, to };
  }
  // Try git worktree remove first; ignore failures (might not be registered).
  try {
    spawn("git", ["worktree", "remove", "--force", from], { cwd: projectDir, encoding: "utf8" });
  } catch { /* swallow — filesystem move below is authoritative */ }
  // If `git worktree remove` already deleted the directory, nothing to move.
  if (!existsSync(from)) {
    return { archived: false, from, to };
  }
  mkdirSync(join(to, ".."), { recursive: true });
  if (existsSync(to)) {
    rmSync(to, { recursive: true, force: true });
  }
  renameSync(from, to);
  return { archived: true, from, to };
}

/**
 * Phase-26 Slice 3 — promote the winning variant's commits into the parent
 * branch. Cherry-picks the commit range `baseRef..variantHEAD` onto the
 * current HEAD of `projectDir`. The caller (CompetitiveScheduler) is
 * responsible for archiving the winner worktree afterwards if desired; this
 * function does NOT delete it (keeps a post-mortem trail).
 *
 * Never modifies the winner worktree. Never touches loser worktrees.
 *
 * @param {object} opts
 * @param {string} opts.projectDir
 * @param {string} opts.planBasename
 * @param {string|number} opts.sliceId
 * @param {number} opts.variant
 * @param {string} [opts.baseRef="HEAD"] the ref the variant was created from
 * @param {Function} [opts.spawn=spawnSync]
 * @returns {{ promoted: boolean, commits: string[], from: string, to: string }}
 */
function gitRevParse(spawn, cwd, ref, errorMessage) {
  const result = spawn("git", ["rev-parse", ref], { cwd, encoding: "utf8" });
  if (!result || result.status !== 0) {
    const stderr = result?.stderr ? String(result.stderr) : "";
    throw new Error(errorMessage(stderr));
  }
  return String(result.stdout).trim();
}

function gitRevList(spawn, cwd, from, to) {
  const result = spawn("git", ["rev-list", "--reverse", `${from}..${to}`], { cwd, encoding: "utf8" });
  if (!result || result.status !== 0) {
    throw new Error(`promoteWinner: rev-list failed: ${String(result?.stderr || "").slice(0, 300)}`);
  }
  return String(result.stdout || "")
    .split("\n")
    .map((s) => s.trim())
    .filter(Boolean);
}

function cherryPickCommits(spawn, projectDir, commits) {
  if (commits.length === 0) return;
  const result = spawn("git", ["cherry-pick", "-x", ...commits], { cwd: projectDir, encoding: "utf8" });
  if (!result || result.status !== 0) {
    throw new Error(
      `promoteWinner: cherry-pick failed (status=${result?.status ?? "?"}): ${String(result?.stderr || "").slice(0, 500)}`,
    );
  }
}

export function promoteWinner({
  projectDir,
  planBasename,
  sliceId,
  variant,
  baseRef = "HEAD",
  spawn = spawnSync,
}) {
  const worktree = variantPath(projectDir, planBasename, sliceId, variant);
  if (!existsSync(worktree)) {
    return { promoted: false, commits: [], from: worktree, to: projectDir, error: "worktree missing" };
  }

  const headSha = gitRevParse(
    spawn,
    worktree,
    "HEAD",
    (stderr) => `promoteWinner: rev-parse HEAD failed in worktree: ${stderr.slice(0, 300)}`,
  );
  const baseSha = gitRevParse(
    spawn,
    worktree,
    baseRef,
    () => `promoteWinner: rev-parse ${baseRef} failed`,
  );

  if (baseSha === headSha) {
    return { promoted: true, commits: [], from: worktree, to: projectDir };
  }

  const commits = gitRevList(spawn, worktree, baseSha, headSha);
  cherryPickCommits(spawn, projectDir, commits);
  return { promoted: true, commits, from: worktree, to: projectDir };
}

/**
 * List archived variants older than `archiveDays` and remove them.
 * Uses directory mtime; never touches live worktrees. Idempotent.
 *
 * @param {object} opts
 * @param {string} opts.projectDir
 * @param {number} [opts.archiveDays=DEFAULT_ARCHIVE_DAYS]
 * @param {Date} [opts.now=new Date()]
 * @returns {{ removed: string[], kept: string[] }}
 */
export function cleanupAgedArchives({
  projectDir,
  archiveDays = DEFAULT_ARCHIVE_DAYS,
  now = new Date(),
}) {
  if (!isAbsolute(projectDir)) {
    throw new Error("cleanupAgedArchives: projectDir must be absolute");
  }
  const root = join(projectDir, WORKTREES_ARCHIVE_DIR);
  const removed = [];
  const kept = [];
  if (!existsSync(root)) {
    return { removed, kept };
  }
  const cutoff = now.getTime() - archiveDays * 24 * 60 * 60 * 1000;

  // .forge/worktrees-archive/<plan>/<slice>/variant-<n>
  for (const plan of readdirSync(root, { withFileTypes: true })) {
    if (!plan.isDirectory()) continue;
    const planDir = join(root, plan.name);
    for (const slice of readdirSync(planDir, { withFileTypes: true })) {
      if (!slice.isDirectory()) continue;
      const sliceDir = join(planDir, slice.name);
      for (const variant of readdirSync(sliceDir, { withFileTypes: true })) {
        if (!variant.isDirectory()) continue;
        const variantDir = join(sliceDir, variant.name);
        let mtime;
        try { mtime = statSync(variantDir).mtimeMs; } catch { continue; }
        if (mtime < cutoff) {
          rmSync(variantDir, { recursive: true, force: true });
          removed.push(variantDir);
        } else {
          kept.push(variantDir);
        }
      }
    }
  }
  return { removed, kept };
}

/**
 * List live (unarchived) variant directories. Used by the Dashboard and by
 * the Teardown Safety Guard exemption (Slice 4) to know what paths are
 * managed by this module.
 *
 * @param {string} projectDir
 * @returns {string[]} absolute paths
 */
export function listLiveVariants(projectDir) {
  if (!isAbsolute(projectDir)) {
    throw new Error("listLiveVariants: projectDir must be absolute");
  }
  const root = join(projectDir, WORKTREES_DIR);
  const out = [];
  if (!existsSync(root)) return out;
  for (const plan of readdirSync(root, { withFileTypes: true })) {
    if (!plan.isDirectory()) continue;
    const planDir = join(root, plan.name);
    for (const slice of readdirSync(planDir, { withFileTypes: true })) {
      if (!slice.isDirectory()) continue;
      const sliceDir = join(planDir, slice.name);
      for (const variant of readdirSync(sliceDir, { withFileTypes: true })) {
        if (!variant.isDirectory()) continue;
        out.push(join(sliceDir, variant.name));
      }
    }
  }
  return out;
}

// One-off screenshot generator for the GitHub-stack readiness terminal output.
// Renders a stylised "terminal" view of `pforge github status` against the
// testbed and saves a PNG that matches the manual's screenshot convention.
//
// Run with:  node --experimental-vm-modules scripts/capture-github-status-screenshot.mjs
// (Playwright lives in pforge-mcp/node_modules, so we import via absolute path.)
import { execFileSync } from "node:child_process";
import { writeFileSync, mkdirSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath, pathToFileURL } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const repoRoot = resolve(__dirname, "..");
const playwrightUrl = pathToFileURL(
  resolve(repoRoot, "pforge-mcp/node_modules/playwright/index.mjs")
).href;
const { chromium } = await import(playwrightUrl);

const testbed = "E:\\GitHub\\plan-forge-testbed";
const outPath = resolve(repoRoot, "docs/manual/assets/screenshots/github-status-testbed.png");

// 1. Run the introspection — capture human output.
const stdoutBuf = execFileSync("node", [
  resolve(repoRoot, "pforge-mcp/github-introspect.mjs"),
  "--project", testbed,
], { encoding: "utf8", maxBuffer: 1024 * 1024 });

// 2. Build a styled HTML page that looks like a dark terminal pane.
const html = `<!doctype html>
<html><head><meta charset="utf-8"><style>
  html,body { margin:0; padding:0; background:#0b1220; }
  .term {
    font-family: "JetBrains Mono","Cascadia Code","Consolas",monospace;
    font-size: 13px;
    line-height: 1.55;
    color: #cbd5e1;
    background: #0b1220;
    border: 1px solid rgba(148,163,184,0.18);
    border-radius: 12px;
    padding: 24px 28px;
    margin: 28px;
    box-shadow: 0 10px 30px rgba(0,0,0,0.35);
    white-space: pre;
    width: max-content;
    min-width: 760px;
  }
  .head { display:flex; gap:8px; padding-bottom:14px; }
  .dot { width:12px; height:12px; border-radius:50%; }
  .r { background:#ef4444; } .y { background:#f59e0b; } .g { background:#10b981; }
  .prompt { color:#a78bfa; }
  .cmd { color:#f8fafc; }
  body { display:flex; align-items:flex-start; justify-content:flex-start; }
</style></head><body>
<div class="term">
  <div class="head"><div class="dot r"></div><div class="dot y"></div><div class="dot g"></div></div>
  <span class="prompt">PS&nbsp;E:\\GitHub\\plan-forge-testbed&gt;</span>
  <span class="cmd">pforge github status</span>
${escapeHtml(stdoutBuf)}</div>
</body></html>`;

function escapeHtml(s) {
  return s.replace(/[&<>]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;" }[c]));
}

// 3. Render and screenshot via playwright.
const browser = await chromium.launch();
try {
  const ctx = await browser.newContext({ viewport: { width: 900, height: 700 }, deviceScaleFactor: 2 });
  const page = await ctx.newPage();
  await page.setContent(html, { waitUntil: "domcontentloaded" });
  const term = await page.locator(".term");
  const buf = await term.screenshot({ type: "png", omitBackground: false });
  mkdirSync(dirname(outPath), { recursive: true });
  writeFileSync(outPath, buf);
  console.log(`wrote ${outPath} (${buf.length} bytes)`);
} finally {
  await browser.close();
}

#!/usr/bin/env node
// Capture Tier 1 manual screenshots from the running dashboard.
// Prerequisites: dashboard server must be running at http://127.0.0.1:3100/dashboard
// Usage: node scripts/capture-manual-screenshots.mjs
//
// Captures (Tier 1, per MANUAL-AUDIT-2026-05.md):
//   dashboard-runs-tab.png    -> historical runs view
//   dashboard-cost-tab.png    -> cost report
//   dashboard-config-tab.png  -> .forge.json editor
//   dashboard-progress-tab.png-> in-flight slice progress (or empty state if none active)
//   dashboard-forge-master-tab.png -> Studio tab
//   dashboard-timeline-tab.png-> unified timeline

import { chromium } from "playwright";
import { mkdirSync } from "node:fs";
import { resolve } from "node:path";

const OUT_DIR = resolve(process.cwd(), "docs/manual/assets/screenshots");
mkdirSync(OUT_DIR, { recursive: true });

const URL = "http://127.0.0.1:3100/dashboard/";
const VIEWPORT = { width: 1600, height: 1000 };

// Each capture: [filename, click sequence, optional waitFor selector]
const captures = [
  {
    name: "dashboard-runs-tab.png",
    clicks: ['.tab-btn[data-tab="runs"]'],
    description: "Runs tab — historical run list",
  },
  {
    name: "dashboard-cost-tab.png",
    clicks: ['.tab-btn[data-tab="cost"]'],
    description: "Cost tab — per-model breakdown + monthly trend",
  },
  {
    name: "dashboard-progress-tab.png",
    clicks: ['.tab-btn[data-tab="progress"]'],
    description: "Progress tab — slice progression",
  },
  {
    name: "dashboard-timeline-tab.png",
    clicks: ['.tab-btn[data-tab="timeline"]'],
    description: "Timeline tab — unified 9-source chronological view",
  },
  {
    name: "dashboard-forge-master-tab.png",
    clicks: ['button[data-group="forge-master"]', '.tab-btn[data-tab="forge-master"]'],
    description: "Forge-Master Studio tab — intent classifier + chat + cache stats",
  },
  {
    name: "dashboard-lg-health-tab.png",
    clicks: ['button[data-group="liveguard"]', '.tab-btn[data-tab="lg-health"]'],
    description: "LiveGuard Health tab — composite score + 30-day trend",
  },
];

const browser = await chromium.launch({ headless: true });
const ctx = await browser.newContext({ viewport: VIEWPORT, deviceScaleFactor: 1.5 });
const page = await ctx.newPage();

console.log(`[shot] Loading ${URL} …`);
try {
  await page.goto(URL, { waitUntil: "domcontentloaded", timeout: 20000 });
  // Wait for the dashboard JS to render at least one tab button
  await page.waitForSelector(".tab-btn", { timeout: 15000 });
} catch (err) {
  console.error(`[shot] Could not reach dashboard at ${URL}: ${err.message}`);
  console.error(`[shot] Make sure 'node pforge-mcp/server.mjs --dashboard-only' is running.`);
  await browser.close();
  process.exit(1);
}
await page.waitForTimeout(1500); // settle WebSocket + initial data fetch

let okCount = 0;
let failCount = 0;

for (const cap of captures) {
  const outPath = resolve(OUT_DIR, cap.name);
  try {
    for (const sel of cap.clicks) {
      const btn = page.locator(sel).first();
      const count = await btn.count();
      if (count === 0) {
        console.warn(`[shot] ${cap.name}: selector ${sel} not found, skipping click`);
        continue;
      }
      await btn.click({ force: true });
      await page.waitForTimeout(400);
    }
    await page.waitForTimeout(2500); // allow tab content fetch + render
    await page.screenshot({ path: outPath, fullPage: false });
    console.log(`[shot] ${cap.name} → ${outPath}`);
    okCount++;
  } catch (err) {
    console.error(`[shot] ${cap.name} FAILED: ${err.message}`);
    failCount++;
  }
}

await browser.close();
console.log(`\n[shot] Done. ${okCount} OK, ${failCount} failed.`);
process.exit(failCount > 0 ? 1 : 0);

#!/usr/bin/env node
// One-shot conversion of chapter-hero JPGs -> WebP @ q82.
// Reports per-file before/after size + total savings.
import { readdirSync, statSync, unlinkSync } from 'node:fs';
import { join, basename, extname } from 'node:path';
import sharp from '../pforge-mcp/node_modules/sharp/lib/index.js';

const dir = 'docs/manual/assets/chapter-heroes';
const files = readdirSync(dir).filter((f) => f.endsWith('.jpg'));

let beforeTotal = 0;
let afterTotal = 0;
const rows = [];

for (const f of files) {
  const src = join(dir, f);
  const dst = join(dir, basename(f, extname(f)) + '.webp');
  const before = statSync(src).size;
  await sharp(src).webp({ quality: 82, effort: 6 }).toFile(dst);
  const after = statSync(dst).size;
  beforeTotal += before;
  afterTotal += after;
  rows.push({ file: f, beforeKB: Math.round(before / 1024), afterKB: Math.round(after / 1024), pct: Math.round((1 - after / before) * 100) });
  unlinkSync(src);
}

rows.sort((a, b) => b.pct - a.pct);
console.table(rows);
console.log(`\nTotal: ${(beforeTotal / 1024 / 1024).toFixed(2)} MB -> ${(afterTotal / 1024 / 1024).toFixed(2)} MB`);
console.log(`Saved: ${((beforeTotal - afterTotal) / 1024 / 1024).toFixed(2)} MB (${Math.round((1 - afterTotal / beforeTotal) * 100)}%)`);
console.log(`Files: ${files.length}`);

#!/usr/bin/env node
/**
 * Plan Forge — Daily Digest CLI (Phase-38.5 Slice 3)
 *
 * Generates a structured daily digest, writes it to `.forge/digests/<date>.json`,
 * prints Markdown to stdout, and optionally dispatches notifications via
 * configured `extensions/notify-*` adapters.
 *
 * Usage:
 *   node scripts/digest.mjs [--date <YYYY-MM-DD>] [--force] [--notify]
 *
 * @module scripts/digest
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";
import { pathToFileURL } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = resolve(__dirname, "..");

// ─── Arg parsing ──────────────────────────────────────────────────────

function parseArgs(argv) {
  const args = { date: null, force: false, notify: false };
  for (let i = 2; i < argv.length; i++) {
    const a = argv[i];
    if (a === "--date" && argv[i + 1]) {
      args.date = argv[++i];
    } else if (a === "--force") {
      args.force = true;
    } else if (a === "--notify") {
      args.notify = true;
    }
  }
  if (!args.date) {
    args.date = new Date().toISOString().slice(0, 10);
  }
  return args;
}

// ─── Severity helpers ─────────────────────────────────────────────────

const SEVERITY_ORDINAL = { info: 0, warn: 1, alert: 2 };

function severityMeetsThreshold(sectionSeverity, threshold) {
  const sev = SEVERITY_ORDINAL[sectionSeverity] ?? 0;
  const thr = SEVERITY_ORDINAL[threshold] ?? 0;
  return sev >= thr;
}

// ─── Notify config loader ─────────────────────────────────────────────

function loadNotifyConfig(projectDir) {
  const candidates = [
    resolve(projectDir, ".forge", "notify.config.json"),
    resolve(projectDir, "notify.config.json"),
  ];
  for (const p of candidates) {
    if (existsSync(p)) {
      try {
        return JSON.parse(readFileSync(p, "utf-8"));
      } catch {
        console.warn(`[digest] Warning: failed to parse ${p}`);
      }
    }
  }
  return null;
}

// ─── Adapter loader ───────────────────────────────────────────────────

async function loadAdapter(projectDir, adapterName) {
  const extDir = resolve(projectDir, "extensions", `notify-${adapterName}`);
  const indexPath = resolve(extDir, "index.mjs");
  if (!existsSync(indexPath)) return null;
  try {
    const mod = await import(pathToFileURL(indexPath).href);
    return mod.adapter || mod.default?.adapter || null;
  } catch {
    return null;
  }
}

// ─── Notification dispatch ────────────────────────────────────────────

function getSectionsForChannel(digest, minSeverity) {
  return digest.sections.filter(
    (section) => section.items.length > 0 && severityMeetsThreshold(section.severity, minSeverity)
  );
}

function buildDigestNotificationMessage(sectionsToSend) {
  return sectionsToSend
    .map((section) => `${section.title} [${section.severity}]: ${section.items.length} item(s)`)
    .join("\n");
}

async function dispatchNotificationChannel(digest, projectDir, channel) {
  const adapterName = channel.adapter;
  const minSeverity = channel.minSeverity || "warn";
  const sectionsToSend = getSectionsForChannel(digest, minSeverity);
  if (sectionsToSend.length === 0) return;

  const adapter = await loadAdapter(projectDir, adapterName);
  if (!adapter) {
    console.warn(`[digest] Adapter '${adapterName}' not found at extensions/notify-${adapterName}/index.mjs — skipping.`);
    return;
  }

  const adapterConfig = channel.config || {};
  const validation = adapter.validate(adapterConfig);
  if (!validation.ok) {
    console.warn(`[digest] Adapter '${adapterName}' config invalid (${validation.reason}) — skipping.`);
    return;
  }

  const message = buildDigestNotificationMessage(sectionsToSend);
  try {
    const result = await adapter.send({
      event: {
        type: "digest",
        data: { sections: sectionsToSend, date: digest.generatedAt },
        severity: sectionsToSend.some((section) => section.severity === "alert") ? "high" : "medium",
      },
      route: adapterName,
      formattedMessage: `Daily Digest — ${sectionsToSend.length} section(s) need attention\n\n${message}`,
      correlationId: `digest-${digest.generatedAt?.slice(0, 10) || "unknown"}`,
      config: adapterConfig,
    });
    if (result?.ok) {
      console.log(`[digest] Notified via ${adapterName} ✓`);
      return;
    }
    console.warn(`[digest] ${adapterName} send failed: ${result?.errorCode || result?.error || "unknown"}`);
  } catch (err) {
    if (err.code === "ERR_NOT_IMPLEMENTED") {
      console.warn(`[digest] Adapter '${adapterName}' is a stub (not installed) — skipping.`);
    } else {
      console.warn(`[digest] ${adapterName} error: ${err.message}`);
    }
  }
}

async function dispatchNotifications(digest, projectDir) {
  const config = loadNotifyConfig(projectDir);
  if (!config || !Array.isArray(config.channels) || config.channels.length === 0) {
    console.warn("[digest] No notification channels configured — skipping. Create .forge/notify.config.json to enable.");
    return;
  }

  for (const channel of config.channels) {
    await dispatchNotificationChannel(digest, projectDir, channel);
  }
}

// ─── Main ─────────────────────────────────────────────────────────────

async function main() {
  const args = parseArgs(process.argv);
  const projectDir = REPO_ROOT;

  // Compute baseline date (7 days before target)
  const targetDate = new Date(args.date + "T00:00:00Z");
  const baselineDate = new Date(targetDate);
  baselineDate.setDate(baselineDate.getDate() - 7);
  const baselineDateStr = baselineDate.toISOString().slice(0, 10);

  // Idempotency guard
  const digestDir = resolve(projectDir, ".forge", "digests");
  const digestPath = resolve(digestDir, `${args.date}.json`);

  if (existsSync(digestPath) && !args.force) {
    console.log("Digest already exists — use --force to regenerate.");
    process.exit(0);
  }

  // Import aggregator and renderer
  const { buildDigest } = await import(pathToFileURL(resolve(projectDir, "pforge-mcp", "digest", "aggregator.mjs")).href);
  const { renderMarkdown, renderJson } = await import(pathToFileURL(resolve(projectDir, "pforge-mcp", "digest", "render.mjs")).href);

  // Build digest
  const digest = buildDigest({
    projectDir,
    date: args.date,
    baselineDate: baselineDateStr,
  });

  // Render
  const markdown = renderMarkdown(digest);
  const json = renderJson(digest);

  // Write JSON to .forge/digests/<date>.json
  mkdirSync(digestDir, { recursive: true });
  writeFileSync(digestPath, JSON.stringify(json, null, 2), "utf-8");

  // Print Markdown to stdout
  console.log(markdown);
  console.log(`Digest written to ${digestPath}`);

  // Notify if requested
  if (args.notify) {
    await dispatchNotifications(digest, projectDir);
  }
}

main().catch((err) => {
  console.error(`[digest] Fatal: ${err.message}`);
  process.exit(1);
});

// One-shot route inventory dumper. Reads handler files and prints METHOD + PATH.
import fs from 'node:fs';
import path from 'node:path';

const files = [
  'pforge-mcp/server.mjs',
  'pforge-mcp/bridge.mjs',
  'pforge-mcp/forge-master-routes.mjs',
  'pforge-mcp/hub.mjs',
];

const routes = [];
for (const f of files) {
  if (!fs.existsSync(f)) continue;
  const src = fs.readFileSync(f, 'utf8');
  const re = /(?:app|router)\.(get|post|put|delete|patch)\s*\(\s*['"`]([^'"`]+)['"`]/g;
  let m;
  while ((m = re.exec(src)) !== null) {
    routes.push({ method: m[1].toUpperCase(), path: m[2], file: path.basename(f) });
  }
}

console.log(`Total routes: ${routes.length}`);
const byPrefix = {};
for (const r of routes) {
  const parts = r.path.split('/').filter(Boolean);
  let key;
  if (parts[0] === 'api' && parts.length >= 2) key = `/api/${parts[1]}`;
  else if (parts[0] === '.well-known') key = '/.well-known';
  else key = '/' + (parts[0] || '');
  (byPrefix[key] = byPrefix[key] || []).push(r);
}
for (const p of Object.keys(byPrefix).sort()) {
  console.log(`\n${p}  (${byPrefix[p].length})`);
  for (const r of byPrefix[p]) {
    console.log(`  ${r.method.padEnd(6)} ${r.path}   [${r.file}]`);
  }
}

#!/usr/bin/env node
/**
 * Plan Forge — fm-recall CLI helper (Phase-38.2).
 *
 * Usage:
 *   node scripts/fm-recall.mjs query "<text>"    — top-3 recall results
 *   node scripts/fm-recall.mjs rebuild           — rebuild recall index
 *
 * Runs from the repository root; resolves projectDir to process.cwd().
 */

import { readFileSync } from "node:fs";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const repoRoot = join(__dirname, "..");

// Dynamic import so this script is discoverable even if run from outside pforge-master
const { buildIndex, queryIndex, loadIndex } = await import(
  join(repoRoot, "pforge-master", "src", "recall-index.mjs")
);

const [sub, ...rest] = process.argv.slice(2);
const projectDir = process.cwd();

if (sub === "rebuild") {
  await buildIndex(projectDir);
  try {
    const idx = JSON.parse(
      readFileSync(join(projectDir, ".forge", "fm-sessions", "recall-index.json"), "utf-8"),
    );
    console.log(`Rebuilt recall index: ${idx.docs?.length ?? 0} document(s) indexed.`);
  } catch {
    console.log("Recall index rebuilt (empty — no sessions found).");
  }
  process.exit(0);
}

if (sub === "query") {
  const query = rest.join(" ").trim();
  if (!query) {
    console.error('Usage: pforge fm-recall query "<text>"');
    process.exit(1);
  }
  await loadIndex(projectDir);
  const results = await queryIndex(query, { topK: 3, projectDir });
  if (results.length === 0) {
    console.log("No results.");
  } else {
    for (const r of results) {
      const ts = (r.timestamp || "").slice(0, 10);
      const sid = r.sessionId ? r.sessionId.slice(0, 16) + "…" : "unknown";
      console.log(`[${ts} · ${r.lane} · ${sid}] ${r.userMessage}`);
    }
  }
  process.exit(0);
}

console.error('Usage: pforge fm-recall query "<text>" | rebuild');
process.exit(1);

#!/usr/bin/env node
/**
 * forge-home-cleanup.mjs — Issue #203
 *
 * Moves ephemeral / orphaned files from .forge/ to .forge/archive/<YYYY-MM>/
 * and optionally deletes archive entries older than 90 days.
 *
 * Usage:
 *   node scripts/forge-home-cleanup.mjs [--dry-run] [--no-confirm] [--max-age-days=90]
 *
 * Flags:
 *   --dry-run        Print what would happen; don't move or delete anything.
 *   --no-confirm     Skip the interactive confirmation prompts.
 *   --max-age-days   Archive entries older than N days are eligible for deletion
 *                    (default: 90). Pass 0 to disable deletion entirely.
 *   --cwd            Project root to scan (default: process.cwd()).
 */

import { existsSync, readdirSync, statSync, mkdirSync, renameSync, rmSync, readFileSync } from "fs";
import { join, resolve } from "path";
import { createInterface } from "readline";

// ─── Config ─────────────────────────────────────────────────────────────────

const EPHEMERAL_PATTERNS = [
  /^release-notes-v[\d.]+.*\.(md|txt)$/,
  /^chain-runner.*\.log$/,
  /^run-phase-.*\.log$/,
  /^harden-.*\.log$/,
  /^fm-.*\.(log|txt)$/,
  /^fm-experiment-/,
  /^fm-dashboard-.*\.log$/,
  /^mcp-hammer.*\.(log|err\.log)$/,
  /^mcp-val\..*\.log$/,
  /^sequencer-.*\.log$/,
  /^load-sim.*\.(log|json)$/,
  /^meta-bug-.*\.(md|txt|json)$/,
  /^gate-tmp\./,
  /^tmp[-_]/,
  /^tmp\//,
  /^served-app.*\.js$/,
  /\.pid$/,
  /^liveguard-broadcast\.log$/,
];

// Directories under .forge/ that are ephemeral-candidate (contents only — the
// dir itself is kept so live processes don't get confused).
const EPHEMERAL_DIRS_SCAN = [
  // intentionally empty — we only archive top-level files, not subdirs
];

// ─── Helpers ────────────────────────────────────────────────────────────────

function isEphemeral(name) {
  return EPHEMERAL_PATTERNS.some((re) => re.test(name));
}

function yyyymm(date) {
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}`;
}

async function confirm(question) {
  const rl = createInterface({ input: process.stdin, output: process.stdout });
  return new Promise((resolve) => {
    rl.question(`${question} [y/N] `, (answer) => {
      rl.close();
      resolve(answer.trim().toLowerCase() === "y");
    });
  });
}

function parseArgs(argv) {
  const args = { dryRun: false, noConfirm: false, maxAgeDays: 90, cwd: process.cwd() };
  for (const arg of argv) {
    if (arg === "--dry-run") args.dryRun = true;
    else if (arg === "--no-confirm") args.noConfirm = true;
    else if (arg.startsWith("--max-age-days=")) args.maxAgeDays = parseInt(arg.split("=")[1], 10);
    else if (arg.startsWith("--cwd=")) args.cwd = arg.split("=").slice(1).join("=");
  }
  return args;
}

function collectArchiveCandidates(forgeDir) {
  const candidates = [];
  for (const entry of readdirSync(forgeDir)) {
    if (entry.startsWith(".")) continue;
    const fullPath = join(forgeDir, entry);
    let st;
    try { st = statSync(fullPath); } catch { continue; }
    if (st.isDirectory()) continue;
    if (!isEphemeral(entry)) continue;
    candidates.push({ name: entry, fullPath, size: st.size, mtime: st.mtime });
  }
  return candidates;
}

function logArchiveCandidates(candidates) {
  console.log(`Found ${candidates.length} ephemeral file(s) to archive:\n`);
  for (const candidate of candidates) {
    const kb = (candidate.size / 1024).toFixed(1);
    console.log(`  ${candidate.name}  (${kb} KB, modified ${candidate.mtime.toISOString().slice(0, 10)})`);
  }
  console.log();
}

function buildArchiveSlot(forgeDir, now = new Date()) {
  return { now, slotName: yyyymm(now), slotPath: join(forgeDir, "archive", yyyymm(now)) };
}

function archiveCandidates(candidates, archiveSlot) {
  mkdirSync(archiveSlot.slotPath, { recursive: true });
  let moved = 0;
  for (const candidate of candidates) {
    const dest = join(archiveSlot.slotPath, candidate.name);
    try {
      renameSync(candidate.fullPath, dest);
      moved++;
    } catch (err) {
      console.warn(`  ⚠ Could not move ${candidate.name}: ${err.message}`);
    }
  }
  console.log(`✓ Moved ${moved} file(s) → .forge/archive/${archiveSlot.slotName}/\n`);
}

function collectOldArchiveSlots(archiveDir, cutoff) {
  const old = [];
  for (const slot of readdirSync(archiveDir)) {
    const slotPath = join(archiveDir, slot);
    let st;
    try { st = statSync(slotPath); } catch { continue; }
    if (!st.isDirectory()) continue;
    if (st.mtime < cutoff) {
      const files = readdirSync(slotPath);
      old.push({ slot, slotPath, fileCount: files.length });
    }
  }
  return old;
}

function logOldArchiveSlots(old, maxAgeDays) {
  const totalFiles = old.reduce((n, slot) => n + slot.fileCount, 0);
  console.log(`Found ${old.length} archive slot(s) older than ${maxAgeDays} days (${totalFiles} file(s)):\n`);
  for (const slot of old) {
    console.log(`  .forge/archive/${slot.slot}/  (${slot.fileCount} files)`);
  }
  console.log();
}

function deleteArchiveSlots(old) {
  let deleted = 0;
  for (const slot of old) {
    try {
      rmSync(slot.slotPath, { recursive: true, force: true });
      deleted++;
    } catch (err) {
      console.warn(`  ⚠ Could not delete .forge/archive/${slot.slot}: ${err.message}`);
    }
  }
  console.log(`✓ Deleted ${deleted} archive slot(s).`);
}

// ─── Main ────────────────────────────────────────────────────────────────────

async function main() {
  const args = parseArgs(process.argv.slice(2));
  const forgeDir = resolve(args.cwd, ".forge");

  if (!existsSync(forgeDir)) {
    console.log(`✓ No .forge/ directory found at ${args.cwd} — nothing to clean.`);
    return;
  }

  if (args.dryRun) {
    console.log("⚡ DRY RUN — no files will be moved or deleted.\n");
  }

  // ── Phase 1: collect candidates ─────────────────────────────────────────
  const candidates = collectArchiveCandidates(forgeDir);

  if (candidates.length === 0) {
    console.log("✓ No ephemeral files found — .forge/ looks clean.");
  } else {
    logArchiveCandidates(candidates);
    const proceed =
      args.dryRun ||
      args.noConfirm ||
      (await confirm(`Move ${candidates.length} file(s) to .forge/archive/?`));

    if (proceed && !args.dryRun) {
      archiveCandidates(candidates, buildArchiveSlot(forgeDir));
    } else if (!proceed) {
      console.log("⏭  Skipped archiving.\n");
    }
  }

  // ── Phase 2: prune old archive entries ──────────────────────────────────
  if (args.maxAgeDays <= 0) {
    console.log("ℹ️  --max-age-days=0; skipping archive pruning.");
    return;
  }

  const archiveDir = join(forgeDir, "archive");
  if (!existsSync(archiveDir)) {
    console.log("✓ No archive directory — pruning skipped.");
    return;
  }

  const cutoff = new Date(Date.now() - args.maxAgeDays * 24 * 60 * 60 * 1000);
  const old = collectOldArchiveSlots(archiveDir, cutoff);

  if (old.length === 0) {
    console.log(`✓ No archive entries older than ${args.maxAgeDays} days.`);
    return;
  }

  logOldArchiveSlots(old, args.maxAgeDays);

  if (args.dryRun) {
    console.log("⚡ DRY RUN — would delete the above slots.");
    return;
  }

  const deleteProceed =
    args.noConfirm || (await confirm(`Permanently delete ${old.length} archive slot(s)?`));

  if (deleteProceed) {
    deleteArchiveSlots(old);
  } else {
    console.log("⏭  Skipped deletion.");
  }
}

main().catch((err) => {
  console.error("forge-home-cleanup failed:", err.message);
  process.exit(1);
});

#!/usr/bin/env node
/**
 * pforge graph — Knowledge graph CLI helper.
 * Usage: node scripts/graph.mjs rebuild|stats|query [type]
 */
import { resolve } from "node:path";
import { existsSync, readFileSync } from "node:fs";
import { fileURLToPath, pathToFileURL } from "node:url";
import { join, dirname } from "node:path";

const __dirname = dirname(fileURLToPath(import.meta.url));
const repoRoot = resolve(__dirname, "..");
const mcpDir = join(repoRoot, "pforge-mcp");

const [,, subcommand, ...rest] = process.argv;

async function main() {
  if (!subcommand || subcommand === "help") {
    console.log("Usage: node scripts/graph.mjs rebuild|stats|query [type]");
    console.log("  rebuild   Rebuild the knowledge graph snapshot");
    console.log("  stats     Print node count by type");
    console.log("  query     Query the graph by type (phase, file, recent-changes, neighbors)");
    process.exit(0);
  }
  if (subcommand === "rebuild") {
    const { buildGraph } = await import(pathToFileURL(join(mcpDir, "graph", "builder.mjs")).href);
    const graph = buildGraph(repoRoot);
    const typeCounts = {};
    for (const node of graph.nodes) {
      typeCounts[node.type] = (typeCounts[node.type] || 0) + 1;
    }
    console.log(`Graph rebuilt: ${graph.nodes.length} nodes, ${graph.edges.length} edges`);
    for (const [type, count] of Object.entries(typeCounts)) {
      console.log(`  ${type}: ${count}`);
    }
  } else if (subcommand === "stats") {
    const snapshotPath = join(repoRoot, ".forge", "graph", "snapshot.json");
    if (!existsSync(snapshotPath)) {
      console.log("No snapshot found. Run: node scripts/graph.mjs rebuild");
      process.exit(0);
    }
    const graph = JSON.parse(readFileSync(snapshotPath, "utf8"));
    const typeCounts = {};
    for (const node of graph.nodes) {
      typeCounts[node.type] = (typeCounts[node.type] || 0) + 1;
    }
    console.log(`Snapshot stats: ${graph.nodes.length} nodes, ${graph.edges.length} edges`);
    for (const [type, count] of Object.entries(typeCounts)) {
      console.log(`  ${type}: ${count}`);
    }
  } else if (subcommand === "query") {
    const queryType = rest[0] || "recent-changes";
    const { queryRecentChanges, queryByPhase, queryByFile, neighbors } = await import(pathToFileURL(join(mcpDir, "graph", "query.mjs")).href);
    let result;
    if (queryType === "phase") {
      result = queryByPhase(rest[1] || "", { projectDir: repoRoot });
    } else if (queryType === "file") {
      result = queryByFile(rest[1] || "", { projectDir: repoRoot });
    } else if (queryType === "neighbors") {
      result = neighbors(rest[1] || "", { projectDir: repoRoot });
    } else {
      result = queryRecentChanges({ type: rest[1] }, { projectDir: repoRoot });
    }
    console.log(JSON.stringify(result, null, 2));
  } else {
    console.error(`Unknown subcommand: ${subcommand}`);
    process.exit(1);
  }
}

main().catch(err => { console.error(err.message); process.exit(1); });

import { ESLint } from 'eslint';
import path from 'node:path';

const root = process.cwd();

const eslint = new ESLint({
  overrideConfigFile: path.join(root, 'scripts/audit/eslint-clean-code.config.mjs'),
  cwd: root
});

const results = await eslint.lintFiles([
  'pforge-mcp/**/*.mjs',
  'pforge-master/**/*.mjs'
]);

let totalErrors = 0;
const fileErrors = {};

for (const r of results) {
  const errors = r.messages.filter(m => m.severity === 2);
  if (errors.length > 0) {
    totalErrors += errors.length;
    const rel = r.filePath.replace(root + path.sep, '').replace(root + '/', '');
    fileErrors[rel] = errors.map(e => ({ rule: e.ruleId, line: e.line, msg: e.message.slice(0, 120) }));
  }
}

const summary = {
  totalErrors,
  fileCount: Object.keys(fileErrors).length,
  files: Object.entries(fileErrors).map(([f, errs]) => ({ file: f, count: errs.length, errors: errs }))
};

console.log(JSON.stringify(summary, null, 2));

#!/usr/bin/env node
/**
 * Plan Forge — timeline CLI helper.
 *
 * Offline-first unified chronological view across all forge event sources.
 * Reads directly from .forge/ files — no running server required.
 *
 * Usage:
 *   node scripts/timeline.mjs [options]
 *
 * Options:
 *   --window <15m|1h|6h|24h|7d|30d>   Time window relative to now (default: 24h)
 *   --from <iso>                        Start of window (ISO timestamp)
 *   --to <iso>                          End of window (ISO timestamp)
 *   --source <name,...>                 Comma-separated source filter
 *   --correlation <id>                  Filter to a single correlationId thread
 *   --group-by <time|correlation>       Group mode (default: time)
 *   --limit <n>                         Max events (default: 100, max: 2000)
 *   --json                              Output raw JSON
 *
 * Sources: hub-event, run, memory, openbrain, watch, tempering, bug, incident, forge-master
 */

import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const repoRoot = join(__dirname, "..");

const { timeline } = await import(join(repoRoot, "pforge-mcp", "timeline", "core.mjs"));

// ─── Arg parsing ──────────────────────────────────────────────────────

const WINDOW_MS = { "15m": 15 * 60_000, "1h": 3_600_000, "6h": 6 * 3_600_000, "24h": 24 * 3_600_000, "7d": 7 * 86_400_000, "30d": 30 * 86_400_000 };
const VALID_WINDOWS = Object.keys(WINDOW_MS);

const args = process.argv.slice(2);
const opts = {};

for (let i = 0; i < args.length; i++) {
  const a = args[i];
  if (a === "--json") { opts.json = true; continue; }
  if (a === "--help" || a === "-h") { opts.help = true; continue; }
  const m = a.match(/^--(window|from|to|source|correlation|group-by|limit)(?:=(.+))?$/);
  if (m) {
    opts[m[1]] = m[2] ?? args[++i];
  }
}

if (opts.help) {
  console.log(`Usage: pforge timeline [options]

Options:
  --window <${VALID_WINDOWS.join("|")}>   Time window (default: 24h)
  --from <iso>                  Window start (ISO timestamp)
  --to <iso>                    Window end (ISO timestamp)
  --source <name,...>           Comma-separated source filter
  --correlation <id>            Filter to a single correlationId
  --group-by <time|correlation> Group mode (default: time)
  --limit <n>                   Max events (default: 100)
  --json                        Output raw JSON

Sources: hub-event, run, memory, openbrain, watch, tempering, bug, incident, forge-master
`);
  process.exit(0);
}

// ─── Build params ─────────────────────────────────────────────────────

const params = {};

if (opts.from) {
  params.from = opts.from;
} else if (opts.window) {
  if (!WINDOW_MS[opts.window]) {
    console.error(`Unknown window '${opts.window}'. Valid: ${VALID_WINDOWS.join(", ")}`);
    process.exit(1);
  }
  params.from = new Date(Date.now() - WINDOW_MS[opts.window]).toISOString();
}

if (opts.to) params.to = opts.to;
if (opts.correlation) params.correlationId = opts.correlation;
if (opts["group-by"]) params.groupBy = opts["group-by"];
if (opts.source) params.sources = opts.source.split(",").map((s) => s.trim()).filter(Boolean);

const rawLimit = opts.limit ? parseInt(opts.limit, 10) : 100;
params.limit = isNaN(rawLimit) ? 100 : rawLimit;

// ─── Run timeline ─────────────────────────────────────────────────────

const projectDir = process.cwd();

try {
  const result = await timeline(params, { cwd: projectDir });

  if (opts.json) {
    console.log(JSON.stringify(result, null, 2));
    process.exit(0);
  }

  // Human-readable output
  const window = `${result.windowFrom ? new Date(result.windowFrom).toLocaleString() : "?"} → ${result.windowTo ? new Date(result.windowTo).toLocaleString() : "?"}`;
  console.log(`\n📅 Timeline  ${window}  (${result.durationMs}ms)`);
  if (result.sourcesQueried?.length) {
    console.log(`   Sources: ${result.sourcesQueried.join(", ")}`);
  }
  console.log("");

  if (result.groupBy === "correlation" || params.groupBy === "correlation") {
    const threads = result.threads || [];
    if (threads.length === 0) {
      console.log("  No threads found. Try widening the time window.");
    } else {
      for (const thread of threads) {
        const cid = thread.correlationId === "__ungrouped__" ? "(ungrouped)" : thread.correlationId;
        const count = thread.events?.length ?? 0;
        console.log(`  [${cid}]  ${count} event(s)  ${thread.sources?.join(",") ?? ""}`);
        if (thread.events) {
          for (const evt of thread.events.slice(0, 5)) {
            const ts = evt.ts ? new Date(evt.ts).toLocaleTimeString() : "?";
            console.log(`    ${ts}  ${evt.source}  ${evt.event}`);
          }
          if (count > 5) console.log(`    … and ${count - 5} more`);
        }
      }
    }
  } else {
    const events = result.events || [];
    if (events.length === 0) {
      console.log("  No events found. Try widening the time window.");
    } else {
      for (const evt of events) {
        const ts = evt.ts ? new Date(evt.ts).toLocaleString() : "?";
        const src = (evt.source || "?").padEnd(14);
        const ev = (evt.event || "?").padEnd(20);
        const cid = evt.correlationId ? `[${evt.correlationId.slice(0, 16)}]` : "";
        console.log(`  ${ts}  ${src}  ${ev}  ${cid}`);
      }
    }
  }

  if (result.truncated) {
    console.log(`\n  ⚠ Truncated to ${params.limit} results. Use --limit to raise the cap.`);
  }
  console.log(`\n  Total: ${result.total} event(s)`);
} catch (err) {
  console.error(`Timeline error: ${err.message}`);
  process.exit(1);
}
